function _normalizePatCard(card, idx) {
  if (!card || typeof card.prompt !== "string") return null;
  const id = String(card.id || `pat_${idx + 1}`);
  const prompt = card.prompt.trim();
  if (!prompt) return null;
  const rawDecision = String(card.decision || "").toLowerCase();
  const rawBucket = String(card.bucket || "").toLowerCase();
  const decision = rawDecision === "sick" || rawDecision === "not_sick"
    ? rawDecision
    : (rawBucket === "not_pat" ? "not_sick" : "sick");
  const mode = String(card.mode || "").toLowerCase() === "image" ? "image" : "text";
  return {
    id,
    mode,
    prompt,
    decision,
    bucket: rawBucket || (decision === "not_sick" ? "not_pat" : "appearance"),
    ticls: String(card.ticls || "").trim(),
    image_url: typeof card.image_url === "string" ? card.image_url : null,
    alt_text: typeof card.alt_text === "string" && card.alt_text.trim() ? card.alt_text.trim() : prompt,
    explanation: typeof card.explanation === "string" ? card.explanation : "",
    socratic_feedback: typeof card.socratic_feedback === "string" ? card.socratic_feedback : "",
    hint: typeof card.hint === "string" ? card.hint : "",
    follow_up: card.follow_up || null,
  };
}
