let _lexiMenuPool = null; // built once from LEXI_INTROS_GENERIC + EMS facts

async function _buildLexiMenuPool(personalLines = []) {
  let facts = [];
  try {
    const res = await fetch("/static/data/ems_facts.json");
    if (res.ok) facts = (await res.json()).map(f => f.text);
  } catch { /* non-fatal — pool falls back to Lexi-only */ }

  // Personal intro lines always lead, then interleave: fact, fact, Lexi quote, repeating
  const lexi = [...LEXI_INTROS_GENERIC];
  const pool = [...personalLines];
  let li = 0, fi = 0;
  while (li < lexi.length || fi < facts.length) {
    if (fi < facts.length) pool.push(facts[fi++]);
    if (fi < facts.length) pool.push(facts[fi++]);
    if (li < lexi.length) pool.push(lexi[li++]);
  }
  return pool.length ? pool : [...personalLines, ...lexi];
}
const _lexiMotionQuery = window.matchMedia ? window.matchMedia("(prefers-reduced-motion: reduce)") : null;

function _lexiPrefersReducedMotion() {
  return !!(_lexiMotionQuery && _lexiMotionQuery.matches);
}

function _lexiClearAvatarMotionClasses(avatar) {
  if (!avatar) return;
  avatar.classList.remove("excited", "thinking", "lexi-celebrating", "lexi-encouraging", "lexi-concerned");
}

function _lexiSetAvatarState(stateName, opts = {}) {
  const avatar = el("lexi-login-avatar");
  if (!avatar) return;
  const autoResetMs = opts.autoResetMs || 0;
  if (_lexiAvatarResetTimer) {
    clearTimeout(_lexiAvatarResetTimer);
    _lexiAvatarResetTimer = null;
  }
  _lexiClearAvatarMotionClasses(avatar);

  if (!_lexiPrefersReducedMotion()) {
    if (stateName === "thinking") avatar.classList.add("thinking");
    if (stateName === "celebrating") avatar.classList.add("lexi-celebrating");
    if (stateName === "encouraging") avatar.classList.add("lexi-encouraging");
    if (stateName === "concerned") avatar.classList.add("lexi-concerned");
  }

  if (autoResetMs > 0) {
    _lexiAvatarResetTimer = setTimeout(() => {
      _lexiSetAvatarState("idle");
    }, autoResetMs);
  }
}

const _LEXI_AVATAR_BASE_IDS = {
  155: "lexi-avatar-base-155",
  120: "lexi-avatar-base-120",
};

const _LEXI_AVATAR_PRESETS = {
  menu: {
    base: 155,
    viewBox: "0 0 155 145",
  },
  compact: {
    base: 120,
    viewBox: "0 0 120 132",
  },
  ticker: {
    base: 120,
    viewBox: "0 0 120 132",
    width: 18,
    height: 18,
    style: "display:inline-block;vertical-align:middle;",
  },
};

function _lexiEscAttr(v) {
  return String(v).replace(/"/g, "&quot;");
}

function _renderLexiAvatarSvg(presetName = "compact", overrides = {}) {
  const preset = _LEXI_AVATAR_PRESETS[presetName] || _LEXI_AVATAR_PRESETS.compact;
  const cfg = { ...preset, ...overrides };
  const baseId = _LEXI_AVATAR_BASE_IDS[cfg.base] || _LEXI_AVATAR_BASE_IDS[120];
  const attrs = [
    `viewBox="${cfg.viewBox}"`,
    `xmlns="http://www.w3.org/2000/svg"`,
  ];
  if (cfg.id) attrs.push(`id="${_lexiEscAttr(cfg.id)}"`);
  if (cfg.className) attrs.push(`class="${_lexiEscAttr(cfg.className)}"`);
  const styleBits = [];
  if (cfg.width) styleBits.push(`width:${cfg.width}px`);
  if (cfg.height) styleBits.push(`height:${cfg.height}px`);
  if (cfg.style) styleBits.push(cfg.style);
  if (styleBits.length) attrs.push(`style="${_lexiEscAttr(styleBits.join(";"))}"`);
  return `<svg ${attrs.join(" ")}><use href="#${baseId}"></use></svg>`;
}

// --- SPEECH-TO-TEXT (MICROPHONE) LOGIC ---
const SpeechRecognition = (/** @type {any} */ (window)).SpeechRecognition || window.webkitSpeechRecognition;
let recognition;
let isListening = false;
let synth = window.speechSynthesis;
let speechStartAttemptId = 0;
let speechStoppedByUser = false;

// TTS queue for popups
let isPopupOpen = false;
let _ttsAudioQueue = [];
let _ttsAudioPlaying = false;
let _ttsCurrentAudio = null;
let _ttsCurrentCleanup = null;
let _ttsPausedSpeechRecognition = false;
let _ttsResumeSpeechTarget = null;
let _ttsResumeSpeechBtn = null;
let isTtsEnabled = false;

// Track which input is currently receiving speech
let currentSpeechTarget = 'chat-input';
let currentSpeechBtn = 'btn-voice-input';

const _STT_MIC_BUTTON_IDS = ['btn-voice-input', 'btn-voice-dmist', 'btn-voice-narrative', 'btn-mc-stt'];
const _STT_BLOCKING_CHALLENGE_MODAL_IDS = ['modal-challenge', 'modal-lung-sound'];

function _isChallengeModalOpenForStt() {
    return _STT_BLOCKING_CHALLENGE_MODAL_IDS.some(id => {
        const node = document.getElementById(id);
        return Boolean(node && !node.classList.contains('hidden'));
    });
}

function _setMicButtonsDisabledForChallenge(disabled) {
    _STT_MIC_BUTTON_IDS.forEach(id => {
        const btn = document.getElementById(id);
        if (!btn) return;
        if (!btn.dataset.defaultTitle) btn.dataset.defaultTitle = btn.getAttribute('title') || '';
        btn.disabled = Boolean(disabled);
        btn.setAttribute('aria-disabled', disabled ? 'true' : 'false');
        btn.classList.toggle('opacity-40', Boolean(disabled));
        btn.classList.toggle('cursor-not-allowed', Boolean(disabled));
        btn.title = disabled ? 'Voice input is disabled while a challenge is open.' : btn.dataset.defaultTitle;
    });
}

function _stopSpeechRecognitionForChallenge() {
    _ttsPausedSpeechRecognition = false;
    _ttsResumeSpeechTarget = null;
    _ttsResumeSpeechBtn = null;
    if (!recognition || !isListening) return;
    speechStoppedByUser = true;
    try { recognition.stop(); } catch (err) { console.warn("Unable to stop speech recognition for challenge:", err); }
}

function _syncChallengeMicState() {
    const blocked = _isChallengeModalOpenForStt();
    if (blocked) _stopSpeechRecognitionForChallenge();
    _setMicButtonsDisabledForChallenge(blocked);
}

function _focusSpeechTarget(targetInputId) {
    const inputField = document.getElementById(targetInputId);
    if (!inputField) return;
    inputField.focus();
    if (typeof inputField.setSelectionRange === 'function') {
        const end = String(inputField.value || '').length;
        inputField.setSelectionRange(end, end);
    }
}

// 1. Check if the browser actually supports it
if (SpeechRecognition) {
    console.log('Speech Recognition supported');
    recognition = new SpeechRecognition();
    recognition.continuous = true; // Keeps listening even when the user pauses
    recognition.interimResults = false; // Only returns final text
    recognition.lang = 'en-US';

    // 2. Handle the visual state when recording starts
    recognition.onstart = () => {
        if (_isChallengeModalOpenForStt()) {
            _stopSpeechRecognitionForChallenge();
            _syncChallengeMicState();
            return;
        }
        isListening = true;
        speechStoppedByUser = false;
        const btn = document.getElementById(currentSpeechBtn);
        if (btn) btn.textContent = '🔴'; // Turns red to show it's active
    };

    // 3. Handle the text when the user stops talking
    recognition.onresult = (event) => {
        const inputField = document.getElementById(currentSpeechTarget);
        
        if (inputField) {
            let newText = "";
            for (let i = event.resultIndex; i < event.results.length; i++) {
                if (event.results[i].isFinal) {
                    newText += event.results[i][0].transcript;
                }
            }
            if (newText) {
                inputField.value = (inputField.value + ' ' + newText).trim();
            }
        }
    };

    // 4. Handle errors (like denying microphone permission)
    recognition.onerror = (event) => {
        console.error('Microphone error:', event.error);
        isListening = false;
        const btn = document.getElementById(currentSpeechBtn);
        if (btn) btn.textContent = '🎤';
        if (event.error === 'not-allowed') {
            showToast('Microphone access denied. Check your browser settings and allow microphone access. In Brave, try disabling Shields or use Chrome.', 'error');
        }
    };

    // 5. Reset the button when recording ends natively
    recognition.onend = () => {
        isListening = false;
        const btn = document.getElementById(currentSpeechBtn);
        if (btn) btn.textContent = '🎤';
    };

    // 6. Bind the logic to multiple HTML buttons
    window.bindMicButton = function(btnId, targetInputId) {
        const btn = document.getElementById(btnId);
        if (!btn) return;
        btn.addEventListener('click', (e) => {
            e.preventDefault();
            if (_isChallengeModalOpenForStt()) {
                _syncChallengeMicState();
                showToast('Voice input is disabled while a challenge is open.', 'info');
                return;
            }
            console.log('Mic button clicked, isListening:', isListening);
            _focusSpeechTarget(targetInputId);
            
            // If we're already listening but on a DIFFERENT button, stop first
            if (isListening && currentSpeechBtn !== btnId) {
                recognition.stop();
                setTimeout(() => {
                    currentSpeechTarget = targetInputId;
                    currentSpeechBtn = btnId;
                    _focusSpeechTarget(targetInputId);
                    try { recognition.start(); } catch(err) {}
                }, 300);
                return;
            }

            currentSpeechTarget = targetInputId;
            currentSpeechBtn = btnId;

            if (isListening) {
                speechStoppedByUser = true;
                recognition.stop();
            } else {
                try {
                    const attemptId = ++speechStartAttemptId;
                    speechStoppedByUser = false;
                    recognition.start();
                    
                    // --- THE BRAVE BROWSER FAILSAFE ---
                    setTimeout(() => {
                        if (!isListening && !speechStoppedByUser && attemptId === speechStartAttemptId) {
                            showToast("Speech-to-Text isn't supported in this browser. Try Chrome, or type your message instead.", 'error');
                            recognition.stop();
                        }
                    }, 1500);

                } catch (error) {
                    console.error("Speech recognition failed to start:", error);
                }
            }
        });
    };

    // Bind all speech-to-text targets used in the sim flow
    bindMicButton('btn-voice-input', 'chat-input');
    bindMicButton('btn-voice-dmist', 'dmist-input');
    bindMicButton('btn-voice-narrative', 'narrative-input');
    _syncChallengeMicState();

} else {
    console.warn("Speech Recognition API is not supported in this browser.");
    // Hide the button so students don't click a dead feature
    ['btn-voice-input', 'btn-voice-dmist', 'btn-voice-narrative'].forEach(id => {
        const btn = document.getElementById(id);
        if (btn) btn.style.display = 'none';
    });
}

// --- CHARACTER COUNTER WIRING ---
// Keeps the "N chars remaining" display in sync for long-form text inputs.
// Turns red when the user is within 10% of the limit.
(function _wireCharCounters() {
    const fields = [
        { inputId: 'dmist-input',     counterId: 'dmist-chars',   max: 1500 },
        { inputId: 'narrative-input', counterId: 'narrative-chars', max: 2000 },
    ];
    fields.forEach(({ inputId, counterId, max }) => {
        const input   = document.getElementById(inputId);
        const counter = document.getElementById(counterId);
        if (!input || !counter) return;
        input.addEventListener('input', () => {
            const remaining = max - input.value.length;
            counter.textContent = remaining;
            counter.style.color = remaining <= Math.ceil(max * 0.1) ? '#f87171' : '';
        });
    });
})();

// --- TTS TOGGLE SETUP ---
const voiceBtn = document.getElementById('btn-voice-input');
if (voiceBtn && voiceBtn.parentNode) {
    const ttsBtn = document.createElement('button');
    ttsBtn.id = 'btn-tts-toggle';
    ttsBtn.className = voiceBtn.className;
    ttsBtn.classList.add('sim-chat-tts-btn');
    ttsBtn.textContent = '🔇';
    ttsBtn.title = 'Toggle Text-to-Speech (currently OFF)';
    ttsBtn.addEventListener('click', () => {
        isTtsEnabled = !isTtsEnabled;
        ttsBtn.textContent = isTtsEnabled ? '🔊' : '🔇';
        ttsBtn.title = isTtsEnabled ? 'Toggle Text-to-Speech (currently ON)' : 'Toggle Text-to-Speech (currently OFF)';
        if (!isTtsEnabled) _clearTtsAudioQueue();
        if (isTtsEnabled) _scheduleTtsPrewarm();
    });
    voiceBtn.parentNode.insertBefore(ttsBtn, voiceBtn.nextSibling);
}

/* ── Voice preference lists — ordered best-to-fallback ── */
const _VOICE_PREFS_FEMALE = [
  "Samantha", "Karen", "Moira", "Fiona", "Victoria",    // macOS / Safari
  "Microsoft Aria Online", "Microsoft Jenny Online",     // Windows Edge
  "Microsoft Zira",                                       // Windows legacy
  "Google US English",                                    // Chrome (often female)
];
const _VOICE_PREFS_MALE = [
  "Daniel", "Aaron", "Fred", "Rishi",                    // macOS / Safari
  "Microsoft Guy Online", "Microsoft Christopher Online", // Windows Edge
  "Microsoft David",                                      // Windows legacy
];
// macOS has "Junior" (child male); no universal child female voice exists,
// so for female children we fall back to the female adult list + pitch boost.
const _VOICE_PREFS_CHILD = [
  "Junior",                                               // macOS
];

/**
 * Return the best available SpeechSynthesisVoice for the given gender.
 * For age="child", tries dedicated child voices first then falls back to
 * the gender list. Falls back to any English voice as last resort.
 */
function _pickVoice(gender, age) {
  const voices = synth ? synth.getVoices() : [];
  if (!voices.length) return null;

  // Try a dedicated child voice first (regardless of gender — "Junior" is male
  // but pitch adjustments will feminise it for female children)
  if (age === "child") {
    for (const name of _VOICE_PREFS_CHILD) {
      const v = voices.find(v => v.name.startsWith(name));
      if (v) return v;
    }
  }

  const prefs = gender === "male" ? _VOICE_PREFS_MALE : _VOICE_PREFS_FEMALE;
  for (const name of prefs) {
    const v = voices.find(v => v.name.startsWith(name));
    if (v) return v;
  }
  // Fallback: name-hint matching
  const genderHints = gender === "male"
    ? ["Aaron", "Daniel", "Fred", "Guy", "David", "Christopher", "Rishi", "James"]
    : ["Samantha", "Karen", "Moira", "Victoria", "Aria", "Jenny", "Zira", "Susan"];
  for (const hint of genderHints) {
    const v = voices.find(v => v.name.includes(hint));
    if (v) return v;
  }
  return voices.find(v => v.lang.startsWith("en")) || null;
}

/**
 * Voice profile per scene character.
 * gender: "male" | "female" | null (browser default)
 * age:    "child" | "elderly" | null (adult)
 */
const _CHAR_PROFILES = {
  // EMS partner
  alex:    { gender: "male",   age: null    },
  jake:    { gender: "male",   age: null    },
  // Common pediatric patient names
  lily:    { gender: "female", age: "child" },
  emma:    { gender: "female", age: "child" },
  noah:    { gender: "male",   age: "child" },
  liam:    { gender: "male",   age: "child" },
  // Common adult patient / family names
  sarah:   { gender: "female", age: null    },
  kate:    { gender: "female", age: null    },
  mike:    { gender: "male",   age: null    },
  tom:     { gender: "male",   age: null    },
  david:   { gender: "male",   age: null    },
  james:   { gender: "male",   age: null    },
  // Relational labels that may appear in chat
  mom:     { gender: "female", age: null    },
  mother:  { gender: "female", age: null    },
  dad:     { gender: "male",   age: null    },
  father:  { gender: "male",   age: null    },
  // Generic elderly labels
  grandma: { gender: "female", age: "elderly" },
  grandpa: { gender: "male",   age: "elderly" },
  patient: { gender: null,     age: null    },
};

function _ageBandForTts(age) {
  const n = Number(age);
  if (!Number.isFinite(n)) return null;
  if (n < 18) return "child";
  if (n >= 65) return "elderly";
  return null;
}

function _genderForTts(value = "") {
  const v = String(value || "").toLowerCase();
  if (v.startsWith("f")) return "female";
  if (v.startsWith("m")) return "male";
  return null;
}

function _profileForKnownName(name = "") {
  return _CHAR_PROFILES[_normalizeSpeakerKey(name)] || null;
}

/**
 * Parse a leading character tag like "*Alex:*" from text and return
 * { gender, age } for that character.
 */
function _profileFromText(text) {
  const parsed = _parseLeadingSpeakerLine(text);
  if (!parsed) return { gender: null, age: null };
  return _speakerProfileForTts(parsed.speaker);
}

function _speakerRoleForTts(name = "") {
  const normalized = _normalizeSpeakerName(name).toLowerCase();
  const profile = _speakerProfileForTts(name);
  if (profile.voiceRole) return profile.voiceRole;
  const roleHint = _speakerRoleHint(name);
  if (normalized.includes("alex") || roleHint === "partner") return "alex";
  if (normalized.includes("lexi")) return "lexi";
  if (normalized.includes("physician") || normalized.includes("doctor")) return "physician";
  if (roleHint === "patient") return "patient";
  if (["mom", "dad", "mother", "father", "parent", "guardian", "family"].includes(roleHint)) return "bystander";
  if (/(^|\b)(mom|mother|dad|father|parent|guardian|family)(\b|$)/i.test(normalized)) return "bystander";
  return "bystander";
}

/**
 * Pitch and rate adjustments by age group.
 * Children: slightly higher pitch without cartooning the fallback voice.
 * Elderly:  lower pitch, noticeably slower.
 */
const _AGE_TUNING = {
  child:   { pitch: 1.16, rate: 1.04 },
  elderly: { pitch: 0.82, rate: 0.82 },
  null:    { pitch: 1.0,  rate: 1.0  },
};

function _makeUtterance(text, gender, age, speed = null) {
  const utt   = new SpeechSynthesisUtterance(text);
  const tuning = _AGE_TUNING[age] || _AGE_TUNING[null];
  const authoredSpeed = Number(speed);
  utt.rate   = Number.isFinite(authoredSpeed) ? Math.max(0.5, Math.min(2, authoredSpeed)) : tuning.rate;
  utt.pitch  = tuning.pitch;
  utt.volume = 1;
  const v = _pickVoice(gender, age);
  if (v) utt.voice = v;
  return utt;
}

function _pauseSpeechRecognitionForTts() {
  if (!recognition || !isListening) return false;
  _ttsPausedSpeechRecognition = true;
  _ttsResumeSpeechTarget = currentSpeechTarget;
  _ttsResumeSpeechBtn = currentSpeechBtn;
  speechStoppedByUser = true;
  try { recognition.stop(); } catch (err) { console.warn("Unable to pause speech recognition for TTS:", err); }
  return true;
}

function _resumeSpeechRecognitionAfterTts() {
  if (!_ttsPausedSpeechRecognition || !recognition || _ttsAudioQueue.length > 0 || _ttsAudioPlaying) return;
  const target = _ttsResumeSpeechTarget;
  const btnId = _ttsResumeSpeechBtn;
  _ttsPausedSpeechRecognition = false;
  _ttsResumeSpeechTarget = null;
  _ttsResumeSpeechBtn = null;
  if (!target || !btnId) return;
  setTimeout(() => {
    if (_isChallengeModalOpenForStt()) {
      _syncChallengeMicState();
      return;
    }
    if (isListening || _ttsAudioPlaying || _ttsAudioQueue.length > 0) return;
    currentSpeechTarget = target;
    currentSpeechBtn = btnId;
    _focusSpeechTarget(target);
    try {
      speechStoppedByUser = false;
      recognition.start();
    } catch (err) {
      console.warn("Unable to resume speech recognition after TTS:", err);
    }
  }, 150);
}

function _clearTtsAudioQueue() {
  _ttsAudioQueue.forEach(slot => slot.cleanup?.());
  _ttsAudioQueue = [];
  _ttsAudioPlaying = false;
  if (_ttsCurrentAudio) {
    _ttsCurrentAudio.pause();
    _ttsCurrentAudio.src = "";
    _ttsCurrentAudio = null;
  }
  _ttsCurrentCleanup?.();
  _ttsCurrentCleanup = null;
  if (synth) synth.cancel();
  _ttsPausedSpeechRecognition = false;
  _ttsResumeSpeechTarget = null;
  _ttsResumeSpeechBtn = null;
}

function _playNextTts() {
  if (_ttsAudioPlaying || isPopupOpen) return;
  if (_ttsAudioQueue.length === 0 || !_ttsAudioQueue[0].ready) return;

  _ttsAudioPlaying = true;
  const slot = _ttsAudioQueue.shift();
  const micWasPaused = _pauseSpeechRecognitionForTts();
  const playbackDelayMs = micWasPaused ? 200 : 0;

  if (slot.url === "__skip__") {
    _ttsAudioPlaying = false;
    _playNextTts();
    _resumeSpeechRecognitionAfterTts();
    return;
  }

  if (slot.url === "__native__") {
    if (!synth || synth.getVoices().length === 0) {
      _ttsAudioPlaying = false;
      _playNextTts();
      return;
    }
    const utt = _makeUtterance(slot._text, slot._gender, slot._age, slot._speed);
    utt.onend = utt.onerror = () => {
      _ttsAudioPlaying = false;
      _playNextTts();
      _resumeSpeechRecognitionAfterTts();
    };
    setTimeout(() => synth.speak(utt), playbackDelayMs);
    return;
  }

  const audio = new Audio(slot.url);
  _ttsCurrentAudio = audio;
  _ttsCurrentCleanup = slot.cleanup;
  let settled = false;
  const finish = () => {
    if (settled) return;
    settled = true;
    if (_ttsCurrentAudio === audio) _ttsCurrentAudio = null;
    if (_ttsCurrentCleanup === slot.cleanup) _ttsCurrentCleanup = null;
    _ttsAudioPlaying = false;
    slot.cleanup?.();
    _playNextTts();
    _resumeSpeechRecognitionAfterTts();
  };
  audio.onended = finish;
  audio.onerror = finish;
  setTimeout(() => {
    audio.play().catch((err) => {
      console.warn("Cloud TTS playback blocked or failed:", err);
      finish();
    });
  }, playbackDelayMs);
}

function _ttsPayloadFromText(text) {
  const speakerChunks = _parseAiDialogueChunks(text)
    .filter(chunk => chunk.type === "speaker" && chunk.text?.trim())
    .filter(chunk => !_shouldSkipTtsForNonverbalPatient(chunk.speaker, chunk.text));
  if (speakerChunks.length !== 1) {
    if (speakerChunks.length > 1) return null;
  }

  const leadingSpeaker = _parseLeadingSpeakerLine(text);
  const activeSpeaker = speakerChunks[0]?.speaker || leadingSpeaker?.speaker || "";
  const activeText = speakerChunks[0]?.text || leadingSpeaker?.content || text;
  if (_shouldSkipTtsForNonverbalPatient(activeSpeaker, activeText)) return null;
  const profile = activeSpeaker ? _speakerProfileForTts(activeSpeaker) : _profileFromText(text);
  const { gender, age, providerVoice, demeanor, delivery, avoid, speed } = profile;
  const role = activeSpeaker ? _speakerRoleForTts(activeSpeaker) : "bystander";
  const cleanText = _cleanSpeakerText(activeText);
  if (cleanText.length === 0) return null;
  return {
    activeSpeaker,
    cleanText,
    gender,
    age,
    providerVoice,
    payload: {
      text: cleanText,
      scenario_id: state.scenarioId || null,
      speaker_role: role,
      gender,
      age,
      provider_voice: providerVoice,
      demeanor,
      delivery,
      avoid,
      speed,
      spo2: Number(state.currentVitals?.spo2 ?? 98),
      rr: Number(state.currentVitals?.rr ?? 16),
    },
  };
}

function _splitLongTtsText(text, maxChars = 135) {
  const clean = String(text || "").trim();
  if (clean.length <= maxChars) return [clean];
  const sentences = clean.match(/[^.!?]+[.!?]+(?:["')\]]+)?|[^.!?]+$/g)
    ?.map(part => part.trim())
    .filter(Boolean) || [clean];
  const chunks = [];
  let current = "";
  for (const sentence of sentences) {
    if (!current) {
      current = sentence;
    } else if (`${current} ${sentence}`.length <= maxChars) {
      current = `${current} ${sentence}`;
    } else {
      chunks.push(current);
      current = sentence;
    }
  }
  if (current) chunks.push(current);
  return chunks;
}

async function speakText(text, opts = {}) {
  if (!isTtsEnabled) return;
  const speakerChunks = _parseAiDialogueChunks(text)
    .filter(chunk => chunk.type === "speaker" && chunk.text?.trim())
    .filter(chunk => !_shouldSkipTtsForNonverbalPatient(chunk.speaker, chunk.text));
  if (speakerChunks.length > 1) {
    for (const chunk of speakerChunks) {
      speakText(`*${chunk.speaker}:* ${chunk.text}`, opts);
    }
    return;
  }

  const tts = _ttsPayloadFromText(text);
  if (!tts) return;
  const textChunks = opts.skipLongSplit ? [tts.cleanText] : _splitLongTtsText(tts.cleanText);
  if (tts.activeSpeaker && textChunks.length > 1) {
    for (const chunk of textChunks) {
      speakText(`*${tts.activeSpeaker}:* ${chunk}`, { ...opts, skipLongSplit: true });
    }
    return;
  }
  let cleanText = tts.cleanText;
  const slot = { url: null, ready: false, cleanup: null };
  _ttsAudioQueue.push(slot);
  const controller = new AbortController();
  const timeoutMs = tts.payload.speaker_role === "alex" ? 6500 : 12000;
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const res = await authFetch(`${API}/api/tts`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(tts.payload),
      signal: controller.signal,
      authRedirectOn401: false,
    });
    clearTimeout(timeoutId);
    if (!res.ok) {
      const err = new Error(`TTS ${res.status}`);
      err.allowNativeFallback = res.status === 503;
      throw err;
    }
    console.debug("Cloud TTS voice", {
      speaker: tts.activeSpeaker || "(untagged)",
      role: tts.payload.speaker_role,
      gender: tts.gender,
      age: tts.age,
      providerVoice: tts.providerVoice,
      responseVoice: res.headers.get("X-TTS-Voice"),
      responseModel: res.headers.get("X-TTS-Model"),
      responseRole: res.headers.get("X-TTS-Role"),
      responseSpeed: res.headers.get("X-TTS-Speed"),
      responseScenario: res.headers.get("X-TTS-Scenario"),
    });
    const blob = await res.blob();
    const url = URL.createObjectURL(blob);
    slot.url = url;
    slot.ready = true;
    slot.cleanup = () => URL.revokeObjectURL(url);
    _playNextTts();
    return;
  } catch (err) {
    clearTimeout(timeoutId);
    const reason = err?.allowNativeFallback ? "not configured" : "failed";
    console.warn(`Cloud TTS ${reason}; falling back to browser synthesis:`, err);
  }

  if (!synth || synth.getVoices().length === 0) {
    slot.url = "__skip__";
    slot.ready = true;
    _playNextTts();
    return;
  }

  // Expand common medical acronyms for better native TTS pronunciation
  cleanText = cleanText
    .replace(/\bSpO2\b/gi, "S P O 2")
    .replace(/\bEtCO2\b/gi, "E T C O 2")
    .replace(/\bBVM\b/gi, "B V M")
    .replace(/\bSVN\b/gi, "S V N")
    .replace(/\bNRB\b/gi, "N R B")
    .replace(/\bLPM\b/gi, "liters per minute")
    .replace(/\bbpm\b/gi, "beats per minute")
    .replace(/\bmg\/dL\b/gi, "milligrams per deciliter");

  slot.url = "__native__";
  slot.ready = true;
  slot.cleanup = null;
  slot._text = cleanText;
  slot._gender = tts.gender;
  slot._age = tts.age;
  slot._speed = tts.payload.speed;
  _playNextTts();
}

const _ttsPrewarmSeen = new Set();
let _ttsPrewarmTimer = null;
const _TTS_PREWARM_MAX_REQUESTS = 24;

function _scenarioTtsPrewarmTexts() {
  const s = state.scenarioData || {};
  const out = [];
  const initial = s.initial_complaint;
  if (initial?.speaker && initial?.lay_summary) out.push(`*${initial.speaker}:* ${initial.lay_summary}`);
  const responseMap = s.history_response_map && typeof s.history_response_map === "object"
    ? Object.values(s.history_response_map)
    : [];
  for (const entry of responseMap) {
    if (!entry?.answer) continue;
    const speaker = _historyResponseMapSpeaker(entry);
    out.push(`*${speaker}:* ${entry.answer}`);
  }
  out.push(
    "*Alex:* Medication setup is ready. Complete the medication check in the popup.",
    "*Alex:* Oxygen setup is ready. Confirm the delivery method in the popup.",
    "*Alex:* I have multiple treatments ready. Choose which one to complete next in the popup.",
  );
  return [...new Set(out)];
}

function _ttsPayloadsForPrewarmText(text) {
  const speakerChunks = _parseAiDialogueChunks(text)
    .filter(chunk => chunk.type === "speaker" && chunk.text?.trim())
    .filter(chunk => !_shouldSkipTtsForNonverbalPatient(chunk.speaker, chunk.text));
  if (speakerChunks.length > 1) {
    return speakerChunks.flatMap(chunk => _ttsPayloadsForPrewarmText(`*${chunk.speaker}:* ${chunk.text}`));
  }

  const tts = _ttsPayloadFromText(text);
  if (!tts) return [];
  const chunks = _splitLongTtsText(tts.cleanText);
  if (!tts.activeSpeaker || chunks.length <= 1) return [tts.payload];
  return chunks
    .map(chunk => _ttsPayloadFromText(`*${tts.activeSpeaker}:* ${chunk}`)?.payload)
    .filter(Boolean);
}

function _scenarioTtsPrewarmPayloads() {
  const payloads = [];
  for (const text of _scenarioTtsPrewarmTexts()) {
    payloads.push(..._ttsPayloadsForPrewarmText(text));
    if (payloads.length >= _TTS_PREWARM_MAX_REQUESTS) break;
  }
  return payloads.slice(0, _TTS_PREWARM_MAX_REQUESTS);
}

function _scheduleTtsPrewarm() {
  if (!isTtsEnabled || !state.scenarioId || !state.scenarioData) return;
  if (_ttsPrewarmTimer) clearTimeout(_ttsPrewarmTimer);
  _ttsPrewarmTimer = setTimeout(async () => {
    let warmed = 0;
    let skipped = 0;
    for (const payload of _scenarioTtsPrewarmPayloads()) {
      if (!isTtsEnabled) return;
      const key = JSON.stringify(payload);
      if (_ttsPrewarmSeen.has(key)) {
        skipped += 1;
        continue;
      }
      _ttsPrewarmSeen.add(key);
      try {
        const res = await authFetch(`${API}/api/tts`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
          authRedirectOn401: false,
        });
        if (res.ok) {
          await res.blob();
          warmed += 1;
        }
      } catch (err) {
        console.debug("TTS prewarm skipped:", err);
      }
      await new Promise(resolve => setTimeout(resolve, 150));
    }
    if (warmed || skipped) {
      console.debug("TTS prewarm complete", {
        scenario: state.scenarioId,
        warmed,
        skipped,
        max: _TTS_PREWARM_MAX_REQUESTS,
      });
    }
  }, 500);
}

function speakPendingIfAny() {
  if (!isTtsEnabled) return;
  if (!isPopupOpen) _playNextTts();
}

function _typeLexiText(text, spanEl, onDone) {
  if (_lexiTypingTimer) clearTimeout(_lexiTypingTimer);
  spanEl.textContent = "";
  let i = 0;
  function next() {
    if (i < text.length) {
      spanEl.textContent += text[i++];
      _lexiTypingTimer = setTimeout(next, 22 + Math.random() * 18);
    } else if (onDone) {
      onDone();
    }
  }
  next();
}

function _runLexiIntro() {
  const textEl = el("lexi-login-text");
  if (!textEl) return;
  const pool = _lexiMenuPool || LEXI_INTROS_GENERIC;
  const msg = pool[_lexiIntroIdx % pool.length];
  _lexiSetAvatarState("thinking");
  _typeLexiText(msg, textEl, () => {
    _lexiSetAvatarState("idle");
    // EMS facts get a longer pause so there's time to read them
    const pause = msg.startsWith("📡") ? 8500 : 6500;
    _lexiPauseTimer = setTimeout(() => {
      _lexiIntroIdx++;
      _runLexiIntro();
    }, pause);
  });
}

function _lexiMenuExcited() {
  const avatar = el("lexi-login-avatar");
  if (!avatar) return;
  _lexiSetAvatarState("celebrating", { autoResetMs: 1200 });
  const sound = el("lexi-sound");
  if (sound) { sound.currentTime = 0; sound.play().catch(e => console.log("Sound play failed:", e)); }
  if (_lexiTypingTimer) clearTimeout(_lexiTypingTimer);
  if (_lexiPauseTimer) clearTimeout(_lexiPauseTimer);
  const reactions = [
    "Oh hi!! Pet me more!! 🐾 Then go pick a scenario!",
    "Wag wag wag!! That's the spot! 🎉",
    "AH! Best responder ever!! Now GO TRAIN! 🚒",
    "WOOF! Okay okay, I'm excited — let's do this! 💪",
    "YAY! ...okay focus. Give me a treat and then pick a scenario. 🩺",
  ];
  const textEl = el("lexi-login-text");
  if (textEl) {
    _typeLexiText(reactions[Math.floor(Math.random() * reactions.length)], textEl, () => {
      _lexiPauseTimer = setTimeout(() => {
        _lexiIntroIdx++;
        _runLexiIntro();
      }, 3000);
    });
  }
}

function startLexiMenu(studentName, game) {
  // Stop any running intro cycle
  if (_lexiTypingTimer) clearTimeout(_lexiTypingTimer);
  if (_lexiPauseTimer) clearTimeout(_lexiPauseTimer);
  _lexiIntroIdx = 0;

  // Build 2 personalized intro lines — these always play before the ratio cycle starts
  const level = getCurrentLevel(game.xp);
  const firstName = studentName.split(" ")[0];
  const personalLines = [
    game.sessions > 0
      ? `Welcome back, ${firstName}! You're a ${level.name}${state.agency ? ` from ${state.agency}` : ""} — let's keep earning those badges! 💪`
      : `Hey ${firstName}! I'm Lexi — ${state.agency ? `${state.agency}'s` : "your"} official training companion! Pick a scenario to begin! 🐾`,
    game.sessions > 0
      ? `You've completed ${game.sessions} session${game.sessions !== 1 ? "s" : ""} so far. Every rep builds real skill — let's add another one. 🐾`
      : `Pick any scenario below and I'll guide you through the whole call — assessment, treatment, and handoff. Ready when you are! 🩺`,
  ];

  // Build interleaved pool (Lexi : EMS facts = 2:1), then start
  _buildLexiMenuPool(personalLines).then(pool => {
    _lexiMenuPool = pool;
    _runLexiIntro();
  });

  // Bind click only once
  if (!_lexiAvatarBound) {
    const avatar = el("lexi-login-avatar");
    if (avatar) {
      avatar.addEventListener("click", _lexiMenuExcited);
      _lexiAvatarBound = true;
    }
  }
}

