// ── Server-backed gamification cache ─────────────────────────────────────────
// Populated from the server at login; written back on state changes.
// Falls back to safe defaults if the server hasn't responded yet.
let _progressCache = null;
let _historyCache  = null;
let _historyCacheLoaded = false;
let _historyRefreshPromise = null;
let _historyLoadError = "";
let _menuRankCache = { agencyId: null, data: null, fetchedAt: 0, loading: false };
let _leaderboardModalCache = { agencyId: null, data: null, fetchedAt: 0 };
let _historyDebriefActiveEntry = null;
let _lastResultsActiveEntry = null;
let _orientationCompleteEntry = null;
let _historyReturnTarget = "menu";
let _debriefCoach = {
  source: "current", // current | history
  entry: null,
  pcrSnapshotHtml: "",
  lexiHistory: [],
  mobileTab: "feedback",
  contextPrimed: false,
};
let _lastDebriefEntry = null;

// ── Active review timer ───────────────────────────────────────────────────────
// Tracks foreground time on debrief/feedback review screens.
// Pauses after 90 s of inactivity or when the document is hidden.
// Backend caps the reported seconds at the per-phase CE constants.
const _activeReviewTimer = (() => {
  let _sessionId   = null;
  let _isDrill     = false;
  let _startedAt   = null;   // Date.now() when current segment started
  let _accumulated = 0;      // seconds from completed segments
  let _idleHandle  = null;
  const IDLE_MS    = 90_000; // 90 s no activity → pause

  function _elapsed() {
    return _startedAt ? (Date.now() - _startedAt) / 1000 : 0;
  }
  function _pause() {
    if (!_startedAt) return;
    _accumulated += _elapsed();
    _startedAt = null;
    if (_idleHandle) { clearTimeout(_idleHandle); _idleHandle = null; }
  }
  function _resume() {
    if (_startedAt || _sessionId === null) return;
    _startedAt = Date.now();
    _resetIdle();
  }
  function _resetIdle() {
    if (_idleHandle) clearTimeout(_idleHandle);
    _idleHandle = setTimeout(_pause, IDLE_MS);
  }
  function _onActivity() {
    if (_sessionId === null) return;
    if (!_startedAt) _resume(); else _resetIdle();
  }
  document.addEventListener("visibilitychange", () => {
    document.hidden ? _pause() : _resume();
  });
  document.addEventListener("pointermove", _onActivity, { passive: true });
  document.addEventListener("keydown",     _onActivity, { passive: true });

  return {
    start(sessionId, isDrill) {
      _pause();
      _sessionId   = sessionId;
      _isDrill     = Boolean(isDrill);
      _accumulated = 0;
      _startedAt   = null;
      _resume();
    },
    stop() {
      _pause();
      const out = { seconds: Math.round(_accumulated), sessionId: _sessionId, isDrill: _isDrill };
      _sessionId = null; _isDrill = false; _accumulated = 0;
      return out;
    },
  };
})();

// Tracks total active session time from scenario launch to debrief close.
// 5-minute idle threshold; resets on each new session start.
const _sessionActiveTimer = (() => {
  let _startedAt   = null;
  let _accumulated = 0;
  let _idleHandle  = null;
  const IDLE_MS    = 300_000; // 5 min inactivity → pause

  function _elapsed() { return _startedAt ? (Date.now() - _startedAt) / 1000 : 0; }
  function _pause() {
    if (!_startedAt) return;
    _accumulated += _elapsed();
    _startedAt = null;
    if (_idleHandle) { clearTimeout(_idleHandle); _idleHandle = null; }
  }
  function _resume() {
    if (_startedAt) return;
    _startedAt = Date.now();
    _resetIdle();
  }
  function _resetIdle() {
    if (_idleHandle) clearTimeout(_idleHandle);
    _idleHandle = setTimeout(_pause, IDLE_MS);
  }
  function _onActivity() {
    if (!_startedAt) _resume(); else _resetIdle();
  }
  document.addEventListener("visibilitychange", () => { document.hidden ? _pause() : _resume(); });
  document.addEventListener("pointermove", _onActivity, { passive: true });
  document.addEventListener("keydown",     _onActivity, { passive: true });

  return {
    start() { _accumulated = 0; _startedAt = null; _resume(); },
    stop()  { _pause(); const s = Math.round(_accumulated); _accumulated = 0; return s; },
  };
})();

// Tracks active launch-to-submit time for drill/minigame activities.
// Same 5-minute idle pause behavior as scenario challenge time.
const _drillLapTimer = (() => {
  let _running     = false;
  let _startedAt   = null;
  let _accumulated = 0;
  let _idleHandle  = null;
  const IDLE_MS    = 300_000; // 5 min inactivity → pause

  function _elapsed() { return _startedAt ? (Date.now() - _startedAt) / 1000 : 0; }
  function _clearIdle() {
    if (_idleHandle) { clearTimeout(_idleHandle); _idleHandle = null; }
  }
  function _pause() {
    if (!_startedAt) return;
    _accumulated += _elapsed();
    _startedAt = null;
    _clearIdle();
  }
  function _resume() {
    if (!_running || _startedAt || document.hidden) return;
    _startedAt = Date.now();
    _resetIdle();
  }
  function _resetIdle() {
    if (!_running) return;
    _clearIdle();
    _idleHandle = setTimeout(_pause, IDLE_MS);
  }
  function _onActivity() {
    if (!_running || document.hidden) return;
    if (!_startedAt) _resume(); else _resetIdle();
  }
  document.addEventListener("visibilitychange", () => {
    if (!_running) return;
    document.hidden ? _pause() : _resume();
  });
  document.addEventListener("pointermove", _onActivity, { passive: true });
  document.addEventListener("keydown",     _onActivity, { passive: true });

  return {
    start() {
      _running = true;
      _accumulated = 0;
      _startedAt = null;
      _resume();
    },
    stop() {
      if (!_running) return 0;
      _pause();
      const s = Math.round(_accumulated);
      _running = false;
      _accumulated = 0;
      _startedAt = null;
      _clearIdle();
      return s;
    },
    peek() {
      if (!_running) return 0;
      return Math.round(_accumulated + _elapsed());
    },
  };
})();

// Client-side run ID for drill :session CE dedup. Regenerated each drill open.
let _drillRunId = null;
function _newDrillRun() { _drillRunId = crypto.randomUUID(); _drillLapTimer.start(); }

async function _submitDebriefCe(seconds, sessionId, isDrill, sessionActiveSec = 0) {
  if (!sessionId || (seconds <= 0 && sessionActiveSec <= 0)) return;
  try {
    const res = await authFetch(`${API}/api/me/progress`, {
      method:  "POST",
      headers: { "Content-Type": "application/json" },
      body:    JSON.stringify({
        session_id:          sessionId,
        is_drill:            Boolean(isDrill),
        debrief_only:        true,
        debrief_elapsed_sec: seconds,
        session_active_sec:  sessionActiveSec,
      }),
    });
    if (res.ok) await _loadChallenges().then(_buildChallengesSection).catch(() => {});
  } catch { /* non-fatal — CE credit missed; main awards already recorded */ }
}

const _PROGRESS_DEFAULTS = () => ({
  xp: 0, sessions: 0, badges: [], pedsCount: 0, pedsTraumaCount: 0, treats: 3,
  pedsMapCompleted: [], pedsKeys: [],
});

async function _loadProgressFromServer(options = {}) {
  try {
    const minXp = Number.isFinite(Number(options.minXp)) ? Math.max(0, Number(options.minXp)) : null;
    const minTreats = Number.isFinite(Number(options.minTreats)) ? Math.max(0, Number(options.minTreats)) : null;
    const [progResult, histResult] = await Promise.allSettled([
      authFetch(`${API}/api/me/progress`),
      authFetch(`${API}/api/me/sessions?limit=50`),
    ]);
    const progRes = progResult.status === "fulfilled" ? progResult.value : null;
    const histRes = histResult.status === "fulfilled" ? histResult.value : null;
    _progressCache = progRes?.ok ? await progRes.json() : (_progressCache || _PROGRESS_DEFAULTS());
    if (minXp !== null) _progressCache.xp = Math.max(Number(_progressCache.xp || 0), minXp);
    if (minTreats !== null) _progressCache.treats = Math.max(Number(_progressCache.treats || 0), minTreats);
    _progressCache = { ...(_progressCache || _PROGRESS_DEFAULTS()) };
    if (histRes?.ok) {
      const historyData = await histRes.json();
      if (Array.isArray(historyData)) {
        _historyCache = historyData;
        _historyCacheLoaded = true;
        _historyLoadError = "";
        _refreshHistoryDependentViews();
      }
    } else if (!_historyCache) {
      _historyCache = [];
    }
    _writeProgressHistoryCache();
  } catch {
    _readProgressHistoryCache();
    _progressCache = _progressCache || _PROGRESS_DEFAULTS();
    _historyCache  = _historyCache || [];
  }
}

function _progressHistoryCacheKey() {
  return `ems_progress_history:${state.userId || "anon"}:${state.agency_id || "none"}`;
}

function _writeProgressHistoryCache() {
  try {
    localStorage.setItem(_progressHistoryCacheKey(), JSON.stringify({
      fetchedAt: Date.now(),
      progress: _progressCache || null,
      history: Array.isArray(_historyCache) ? _historyCache : [],
    }));
  } catch { /* storage may be unavailable */ }
}

function _readProgressHistoryCache() {
  try {
    const cached = JSON.parse(localStorage.getItem(_progressHistoryCacheKey()) || "null");
    if (cached?.progress && !_progressCache) _progressCache = cached.progress;
    if (Array.isArray(cached?.history) && !_historyCache) {
      _historyCache = cached.history;
      _historyCacheLoaded = true;
      _historyLoadError = "";
    }
    return !!cached;
  } catch {
    return false;
  }
}

function loadGamification() {
  return _progressCache || _PROGRESS_DEFAULTS();
}

function _applyGamificationAward({ xpEarned = 0, treatsEarned = 0, newBadges = [], challengeBadges = [] } = {}) {
  const game = { ...loadGamification() };
  const badges = Array.isArray(game.badges) ? [...game.badges] : [];
  game.xp = Math.max(0, Number(game.xp || 0)) + Math.max(0, Number(xpEarned || 0));
  game.treats = Math.max(0, Number(game.treats ?? 0)) + Math.max(0, Number(treatsEarned || 0));
  [...(newBadges || []), ...(challengeBadges || [])].forEach(id => {
    if (id && !badges.includes(id)) badges.push(id);
  });
  game.badges = badges;
  _progressCache = game;
  _writeProgressHistoryCache();
  _refreshGamificationChrome();
  return game;
}

