/* ═══════════════════════════════════════════════════════════════════
   HISTORY — server-backed session history cache
   Each entry: { key, scenarioId, title, date, score, xpGross,
                 xpEarned, treatsEarned, newBadges, debrief, elapsedMin }
   Award logic is computed server-side and cached here for display.
   ═══════════════════════════════════════════════════════════════════ */

function loadHistory() {
  return _historyCache || [];
}

function addHistoryEntry(entry) {
  if (!_historyCache) _historyCache = [];
  _historyCache.unshift(entry);  // newest first — local cache update for immediate display
  _writeProgressHistoryCache();
}

async function _refreshHistoryCache() {
  if (_historyRefreshPromise) return _historyRefreshPromise;
  _historyRefreshPromise = (async () => {
    try {
      const r = await authFetch(`${API}/api/me/sessions`);
      if (r.ok) {
        const data = await r.json();
        if (Array.isArray(data)) {
          _historyCache = data;
          _historyCacheLoaded = true;
          _historyLoadError = "";
          _refreshHistoryDependentViews();
        }
        _writeProgressHistoryCache();
      } else {
        _historyLoadError = `History could not load (${r.status}).`;
      }
    } catch {
      _historyLoadError = "History could not load. Check your connection and try again.";
    }
    if (!_historyCache) _historyCache = [];
    return _historyCache;
  })();
  try {
    return await _historyRefreshPromise;
  } finally {
    _historyRefreshPromise = null;
  }
}

function _refreshHistoryDependentViews() {
  _renderRightHistory();
  if (!el("screen-history")?.classList.contains("hidden")) {
    buildHistoryPage(false);
  }
}

function _findHistoryEntryByKey(key) {
  if (!key) return null;
  return (_historyCache || []).find(e => String(e.key) === String(key)) || null;
}

// Level display helpers (read-only on client; progression is server-authoritative).
function getCurrentLevel(xp) {
  let level = LEVELS[0];
  for (const l of LEVELS) { if (xp >= l.xp) level = l; else break; }
  return level;
}

function getNextLevel(xp) {
  for (const l of LEVELS) { if (xp < l.xp) return l; }
  return null;
}

function _ordinal(n) {
  const s = ["th", "st", "nd", "rd"];
  const v = n % 100;
  return `${n}${s[(v - 20) % 10] || s[v] || s[0]}`;
}

function _renderMenuRank(rankSummary) {
  const titleEl = el("menu-rank-title");
  const subEl = el("menu-rank-subtext");
  if (!titleEl || !subEl) return;

  if (!state.agency_id || state._isSuper) {
    titleEl.textContent = "";
    subEl.textContent = "";
    return;
  }

  const agencyName = rankSummary?.agency_name || state.agency || "your agency";
  const rank = rankSummary?.my_rank;
  if (!Number.isFinite(rank) || rank <= 0) {
    titleEl.textContent = `Agency standings: ${agencyName}`;
    subEl.textContent = "Play more to climb the ranks.";
    return;
  }

  if (rank === 1) {
    titleEl.textContent = `You're in 1st place at ${agencyName}!`;
    subEl.textContent = "Keep earning XP to defend the lead.";
    return;
  }

  const xpToNext = Math.max(0, rankSummary?.xp_to_next_rank || 0);
  titleEl.textContent = `You're ${_ordinal(rank)} at ${agencyName}.`;
  subEl.textContent = xpToNext > 0
    ? `${xpToNext.toLocaleString()} XP to pass ${_ordinal(rank - 1)} place.`
    : "You're tied for the rank above. One more XP to move up.";
}

async function _loadMenuRankSummary(force = false) {
  if (!state.agency_id || state._isSuper) return;
  const now = Date.now();
  if (!force &&
      _menuRankCache.agencyId === state.agency_id &&
      (now - _menuRankCache.fetchedAt) < 60000 &&
      _menuRankCache.data) {
    _renderMenuRank(_menuRankCache.data);
    return;
  }
  if (_menuRankCache.loading) return;

  _menuRankCache.loading = true;
  try {
    const r = await authFetch(`${API}/api/agency/leaderboard`);
    if (!r.ok) return;
    const data = await r.json();
    _menuRankCache = {
      agencyId: state.agency_id,
      data: data.rank_summary || null,
      fetchedAt: Date.now(),
      loading: false,
    };
    _renderMenuRank(_menuRankCache.data);
  } catch {
    // no-op; menu keeps current content
  } finally {
    _menuRankCache.loading = false;
  }
}

