function formatTime(secs) {
  const m = Math.floor(secs / 60).toString().padStart(2, "0");
  const s = (secs % 60).toString().padStart(2, "0");
  return `${m}:${s}`;
}

function _toEpochMs(value, fallback = Date.now()) {
  if (typeof value === "number" && Number.isFinite(value)) return value;
  if (value == null) return fallback;
  let s = String(value).trim();
  if (!s) return fallback;
  // Normalize a common malformed shape: "...+00:00Z" -> "...+00:00"
  s = s.replace(/([+\-]\d{2}:\d{2})Z$/, "$1");
  // If no timezone is present, treat as UTC.
  if (!/(Z|[+\-]\d{2}:\d{2})$/.test(s)) s += "Z";
  const ms = Date.parse(s);
  return Number.isFinite(ms) ? ms : fallback;
}

function showError(elId, msg) {
  const e = el(elId); if (e) { e.textContent = msg; e.classList.remove("hidden"); }
}
function clearError(elId) { const e = el(elId); if (e) e.classList.add("hidden"); }

/**
 * Show a non-blocking toast notification at the top of the screen.
 * type: "error" (red) | "warning" (amber) | "info" (gray) | "success" (green)
 * Auto-dismisses after 4 seconds.
 */
function showToast(message, type = "error") {
  const colors = {
    error:   "bg-red-900/90 border-red-700 text-red-100",
    warning: "bg-amber-900/90 border-amber-700 text-amber-100",
    info:    "bg-gray-800/90 border-gray-600 text-gray-100",
    success: "bg-emerald-900/90 border-emerald-700 text-emerald-100",
  };
  const toast = document.createElement("div");
  toast.className = `fixed top-4 left-1/2 -translate-x-1/2 z-[300] px-5 py-3 rounded-xl border shadow-2xl text-sm max-w-sm text-center transition-all duration-300 ${colors[type] || colors.error}`;
  toast.textContent = message;
  document.body.appendChild(toast);
  // Fade out then remove
  setTimeout(() => { toast.style.opacity = "0"; toast.style.transform = "translateX(-50%) translateY(-8px)"; }, 3600);
  setTimeout(() => toast.remove(), 4000);
}

function escapeHTML(str) {
  return String(str ?? "")
    .replace(/&/g,  "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;").replace(/\n/g, "<br>");
}

function _normalizeDebriefText(input) {
  let text = input;

  if (text && typeof text === "object") {
    text = text.debrief || text.feedback || JSON.stringify(text, null, 2);
  }

  text = String(text || "").trim();
  if (!text) return "";

  // If the payload is a JSON envelope string, extract the debrief body.
  for (let i = 0; i < 2; i += 1) {
    const trimmed = text.trim();
    if (!(trimmed.startsWith("{") || trimmed.startsWith("\"{"))) break;
    try {
      const parsed = JSON.parse(trimmed);
      if (typeof parsed === "string") {
        text = parsed;
        continue;
      }
      if (parsed && typeof parsed === "object") {
        text = parsed.debrief || parsed.feedback || text;
      }
    } catch {
      break;
    }
  }

  // If the model wrapped the JSON object in extra text, pull out the largest
  // object-looking slice and try one more time.
  const firstBrace = text.indexOf("{");
  const lastBrace = text.lastIndexOf("}");
  if (firstBrace !== -1 && lastBrace > firstBrace) {
    const candidate = text.slice(firstBrace, lastBrace + 1);
    try {
      const parsed = JSON.parse(candidate);
      if (parsed && typeof parsed === "object") {
        text = parsed.debrief || parsed.feedback || text;
      }
    } catch {
      // Leave text as-is if the slice was not parseable JSON.
    }
  }

  // Unescape common transport artifacts when a JSON string slips through.
  text = text
    .replace(/^"+|"+$/g, "")
    .replace(/\\n/g, "\n")
    .replace(/\\"/g, '"')
    .replace(/\\t/g, "  ")
    .replace(/\r/g, "")
    .trim();

  return _demoteCaseLearningSubsectionNumbers(
    _normalizeDebriefInlineListsForDisplay(
      _normalizeDebriefSectionHeadersForDisplay(text)
    )
  );
}

function _normalizeDebriefSectionHeadersForDisplay(markdown = "") {
  let text = String(markdown || "");
  if (!text) return "";

  const unnumberedHeadings = [
    "FTO\\s+Summary",
    "What\\s+Went\\s+Well",
    "What\\s+Could\\s+Be\\s+Better",
    "Protocols?\\s*&\\s*Treatments?",
    "Handoff\\s*&\\s*Communication",
    "Patient\\s+Communication",
    "Narrative",
    "Case\\s+Study",
    "Rubric\\s+Detail(?:\\s+—[^\\n]*)?",
  ];
  unnumberedHeadings.forEach((titlePattern) => {
    const inlineRe = new RegExp(`([^\\n])\\s+(?:#{1,3}\\s*)(${titlePattern})(?=\\s|$)`, "gi");
    const lineRe = new RegExp(`^[ \\t]*(?:#{1,3}\\s*)?(${titlePattern})[ \\t]*$`, "gim");
    text = text
      .replace(inlineRe, "$1\n\n## $2")
      .replace(lineRe, "## $1");
  });

  const headings = [
    [1, "(?:Clinical\\s+Performance(?:\\s*\\(Assessment\\))?|Patient\\s+Overview)"],
    [2, "(?:Protocols\\s*&\\s*Treatment|What\\s+Was\\s+Done\\s+Well)"],
    [3, "(?:Scope\\s+of\\s+Practice|What\\s+Could\\s+Be\\s+Done\\s+Better)"],
    [4, "(?:DMIST\\s+Quality(?:\\s+—[^\\n]*)?|DMIST\\s+Turnover\\s+Evaluation|Hospital\\s+Turnover|Patient\\s+Turnover|Clinical\\s+Performance\\s*\\(Assessment\\))"],
    [5, "(?:Professionalism\\s*&\\s*Bedside\\s+Manner|DMIST\\s+Turnover\\s+Evaluation|Hospital\\s+Turnover|Patient\\s+Turnover)"],
    [6, "(?:Case\\s+Summary|Professionalism\\s*&\\s*Bedside\\s+Manner)"],
    [7, "(?:Key\\s+Takeaways|Protocols\\s*&\\s*Treatment|Scope\\s+of\\s+Practice)"],
    [8, "Condition\\s+—[^\\n]*"],
    [9, "Treatment\\s*&\\s*Protocol\\s+Reference"],
    [10, "Patient\\s+Care\\s+Narrative\\s+Evaluation"],
    [11, "Key\\s+Takeaways"],
  ];

  headings.forEach(([num, titlePattern]) => {
    const headingPattern = `(${num}\\.\\s+${titlePattern})`;
    const inlineRe = new RegExp(`([^\\n])\\s+(?:\\*\\*)?(?:#{1,3}\\s*)?${headingPattern}(?:\\*\\*)?`, "gi");
    const lineRe = new RegExp(`^[ \\t]*(?:\\*\\*)?(?:#{1,3}\\s*)?${headingPattern}(?:\\*\\*)?[ \\t]*$`, "gim");
    text = text
      .replace(inlineRe, "$1\n\n**$2**")
      .replace(lineRe, "**$1**");
  });

  const caseSubheadings = [
    "Key\\s+Takeaways",
    "Condition\\s+—[^\\n]*",
    "Treatment\\s*&\\s*Protocol\\s+Reference",
    "Patient\\s+Care\\s+Narrative\\s+Evaluation",
  ];
  caseSubheadings.forEach((titlePattern) => {
    const inlineRe = new RegExp(`([^\\n])\\s+(?:\\*\\*)?(?:#{1,3}\\s*)?(${titlePattern})(?:\\*\\*)?`, "gi");
    const lineRe = new RegExp(`^[ \\t]*(?:\\*\\*)?(?:#{1,3}\\s*)?(${titlePattern})(?:\\*\\*)?[ \\t]*$`, "gim");
    text = text
      .replace(inlineRe, "$1\n\n**$2**")
      .replace(lineRe, "**$1**");
  });

  return text.replace(/\n{3,}/g, "\n\n").trim();
}

function _normalizeDebriefInlineListsForDisplay(markdown = "") {
  const lines = String(markdown || "").split("\n");
  const out = [];
  let activeListSection = "";
  const looksLikeGap = (part = "") => /\b(not|missed|missing|incomplete|not completed|not assessed|not documented|no credit)\b/i.test(String(part || ""));
  const listSectionRe = /^#{1,3}\s+(What Went Well|What Could Be Better)\b/i;
  const anyHeadingRe = /^#{1,3}\s+/;
  lines.forEach((rawLine) => {
    const line = String(rawLine || "");
    const trimmed = line.trim();
    const headingMatch = trimmed.match(listSectionRe);
    if (headingMatch) {
      activeListSection = headingMatch[1].toLowerCase();
      out.push(line);
      return;
    }
    if (anyHeadingRe.test(trimmed)) {
      activeListSection = "";
      out.push(line);
      return;
    }
    if (!activeListSection || /^[-•*]\s+/.test(trimmed) || !/\s-\s/.test(trimmed)) {
      out.push(line);
      return;
    }

    const parts = trimmed.split(/\s+-\s+(?=[A-Z0-9])/).map(part => part.trim()).filter(Boolean);
    if (parts.length < 2) {
      out.push(line);
      return;
    }
    let movedToGaps = activeListSection === "what could be better";
    parts.forEach(part => {
      if (activeListSection === "what went well" && !movedToGaps && looksLikeGap(part)) {
        out.push("");
        out.push("## What Could Be Better");
        movedToGaps = true;
      }
      out.push(`- ${part}`);
    });
    if (movedToGaps) activeListSection = "what could be better";
  });
  return out.join("\n").replace(/\n{3,}/g, "\n\n").trim();
}

function _splitDebriefForModal(input) {
  const normalized = _stripGeneratedDebriefAuxiliarySections(_normalizeDebriefText(input));
  if (!normalized) {
    return { mainMarkdown: "", referenceMarkdown: "" };
  }

  const lines = normalized.split("\n");
  const sections = [];
  let current = { number: null, lines: [] };

  const pushCurrent = () => {
    if (current.lines.length) sections.push(current);
  };

  lines.forEach((line) => {
    const trimmed = line.trim();
    const numberedMatch = trimmed.match(/^(?:\*\*|#{1,3}\s*)(\d+)\.\s+/);
    if (numberedMatch) {
      pushCurrent();
      current = {
        number: Number(numberedMatch[1]),
        lines: [line],
      };
    } else {
      current.lines.push(line);
    }
  });
  pushCurrent();

  if (!sections.length) {
    return { mainMarkdown: normalized, referenceMarkdown: "" };
  }

  const mainSections = [];
  const referenceSections = [];
  const isReferenceSection = (section) => section.number >= 8 && section.number <= 10;
  const referenceExtracted = sections.some(isReferenceSection);
  let nextVisibleMainNumber = 1;
  sections.forEach((section) => {
    const sectionMarkdown = section.lines.join("\n").trimEnd();
    if (isReferenceSection(section)) {
      referenceSections.push(sectionMarkdown);
      return;
    }

    if (referenceExtracted && section.number !== null) {
      mainSections.push(_renumberDebriefSectionHeading(sectionMarkdown, nextVisibleMainNumber));
      nextVisibleMainNumber += 1;
      return;
    }

    mainSections.push(sectionMarkdown);
  });

  return {
    mainMarkdown: mainSections.filter(Boolean).join("\n\n").trim(),
    referenceMarkdown: referenceSections.filter(Boolean).join("\n\n").trim(),
  };
}

function _stripGeneratedDebriefAuxiliarySections(markdown = "") {
  let text = String(markdown || "");
  if (!text) return "";

  const nextSectionPattern = [
    "Clinical\\s+Impression\\s+Review",
    "FTO\\s+Summary",
    "What\\s+Went\\s+Well",
    "What\\s+Could\\s+Be\\s+Better",
    "Protocols?\\s*&\\s*Treatments?",
    "Handoff\\s*&\\s*Communication",
    "Patient\\s+Communication",
    "Narrative",
    "Case\\s+Study",
    "What\\s+happened",
    "What\\s+it\\s+means\\s+clinically",
  ].join("|");

  const auxSectionRe = new RegExp(
    String.raw`(?:^|\n)[ \t]*(?:\*\*|#{1,3}\s*)?(?:\d+\.\s*)?(?:Key\s+Takeaways|Reflection\s+Prompts)(?:\*\*)?[ \t]*\n[\s\S]*?(?=\n[ \t]*(?:\*\*|#{1,3}\s*)?(?:\d+\.\s*)?(?:${nextSectionPattern})\b|$)`,
    "gi",
  );

  return text.replace(auxSectionRe, "\n").replace(/\n{3,}/g, "\n\n").trim();
}

function _demoteCaseLearningSubsectionNumbers(markdown = "") {
  return String(markdown || "")
    .replace(/^(\s*(?:\*\*|#{1,3}\s*)?)7\.\s+(Key\s+Takeaways.*)$/gim, "$1$2")
    .replace(/^(\s*(?:\*\*|#{1,3}\s*)?)8\.\s+(Condition\s+—.*)$/gim, "$1$2")
    .replace(/^(\s*(?:\*\*|#{1,3}\s*)?)9\.\s+(Treatment\s*&\s*Protocol\s*Reference.*)$/gim, "$1$2")
    .replace(/^(\s*(?:\*\*|#{1,3}\s*)?)10\.\s+(Patient\s+Care\s+Narrative\s+Evaluation.*)$/gim, "$1$2");
}

function _renumberDebriefSectionHeading(markdown = "", visibleNumber) {
  if (!Number.isFinite(visibleNumber)) return String(markdown || "");
  return String(markdown || "").replace(
    /^(\s*(?:\*\*|#{1,3}\s*)?)(\d+)(\.\s+)/,
    `$1${visibleNumber}$3`,
  );
}

function _stripReferenceSectionNumbers(markdown = "") {
  return String(markdown || "")
    .replace(/^(\s*(?:\*\*|#{1,3}\s*)?)8\.\s+(Condition\s+—.*)$/gim, "$1$2")
    .replace(/^(\s*(?:\*\*|#{1,3}\s*)?)9\.\s+(Treatment\s*&\s*Protocol\s*Reference.*)$/gim, "$1$2")
    .replace(/^(\s*(?:\*\*|#{1,3}\s*)?)10\.\s+(Patient\s+Care\s+Narrative\s+Evaluation.*)$/gim, "$1$2");
}

function _isConditionLocked(ic) {
  // No IC object means the challenge isn't enabled for this scenario — never lock.
  // If IC is present but result is anything other than correct/acceptable (including
  // null, unknown, or a malformed value), treat as locked. Fail closed.
  if (!ic) return false;
  return ic.result !== "correct" && ic.result !== "acceptable";
}

function _buildConditionLockedFeedbackBanner(ic) {
  const givenAnswer = ic?.student_answer || "No impression recorded";
  return `<div class="condition-lock-block">
    <div class="condition-lock-icon">🔒</div>
    <div class="condition-lock-title">Full Debrief Locked</div>
    <div class="condition-lock-body">Your working impression was <strong>${escapeHTML(givenAnswer)}</strong> — the primary condition was not correctly identified.</div>
    <div class="condition-lock-body">The full feedback, condition reference, and treatment protocol are unlocked when you correctly identify the condition on a retry.</div>
    <div class="condition-lock-prompt">Return to the scene, review the clinical findings — vitals, presentation, history — and form your impression before you act.</div>
  </div>`;
}

function _buildConditionLockedRefBanner() {
  return `<div class="condition-lock-block condition-lock-block--compact">
    <span class="condition-lock-icon">🔒</span>
    <span class="condition-lock-body">Condition and treatment reference unlock when you correctly identify the primary impression on a retry.</span>
  </div>`;
}

function _isTransientSubmitStatus(status) {
  return [408, 409, 425, 429, 500, 502, 503, 504].includes(Number(status));
}

async function _submitNarrativeWithRetry(payload, btn) {
  const url = `${API}/api/sessions/${state.sessionId}/narrative`;
  const attempt = async () => authFetch(url, {
    method: "POST",
    body: JSON.stringify(payload),
  });

  try {
    const first = await attempt();
    if (first.ok || !_isTransientSubmitStatus(first.status)) return first;
    if (btn) btn.textContent = "Retrying debrief…";
    await new Promise(resolve => setTimeout(resolve, 700));
    return await attempt();
  } catch (_err) {
    if (btn) btn.textContent = "Retrying debrief…";
    await new Promise(resolve => setTimeout(resolve, 700));
    return await attempt();
  }
}

function renderMarkdown(text) {
  const normalized = _normalizeDebriefText(text);
  if (!normalized) return "<p>No debrief feedback available.</p>";

  const formatInline = (value = "") => {
    let html = escapeHTML(value);
    html = html.replace(/\*\*([^*\n]+)\*\*/g, "<strong>$1</strong>");
    html = html.replace(/\*([^*\n]+)\*/g, '<em class="debrief-score">$1</em>');
    return html;
  };

  const imageLineHtml = (line = "") => {
    const imageMatch = line.match(/^!\[([^\]]*)\]\(([^)\s]+)\)$/);
    if (!imageMatch) return null;
    const alt = imageMatch[1] || "Learning reference image";
    const src = imageMatch[2] || "";
    if (!/^\/static\/[A-Za-z0-9._~:/?#\[\]@!$&'()*+,;=%-]+$/.test(src)) return null;
    return `<figure class="markdown-image-card"><img src="${escapeHTML(src)}" alt="${escapeHTML(alt)}" loading="lazy" /></figure>`;
  };

  const lines = normalized
    .split("\n")
    .map(line => line.replace(/\r/g, ""))
    // Strip markdown table rows and flatten simple pipe rows into plain text.
    .filter(line => !/^\|[-| :]+\|?\s*$/.test(line.trim()))
    .map(line => /^\|.*\|?\s*$/.test(line.trim())
      ? line.replace(/\|/g, " ").replace(/\s+/g, " ").trim()
      : line);

  const out = [];
  let paragraph = [];
  let listItems = [];

  const flushParagraph = () => {
    if (!paragraph.length) return;
    out.push(`<p>${paragraph.map(part => formatInline(part)).join("<br>")}</p>`);
    paragraph = [];
  };
  const flushList = () => {
    if (!listItems.length) return;
    out.push(`<ul>${listItems.map(item => `<li>${formatInline(item)}</li>`).join("")}</ul>`);
    listItems = [];
  };

  lines.forEach((rawLine) => {
    const line = rawLine.trim();
    if (!line) {
      flushParagraph();
      flushList();
      return;
    }

    const h3Match = line.match(/^###\s+(.+)$/);
    const h2Match = line.match(/^(?:##|#)\s+(.+)$/);
    const numberedSectionMatch = line.match(/^(?:\*\*)?(\d+\.\s+.+?)(?:\*\*)?$/);
    const bulletMatch = line.match(/^[-•*]\s+(.+)$/);
    const labelLine = line.match(/^([A-Za-z][A-Za-z &/()-]{2,40}:)\s*(.*)$/);
    const imageHtml = imageLineHtml(line);

    if (imageHtml) {
      flushParagraph();
      flushList();
      out.push(imageHtml);
      return;
    }

    if (h3Match) {
      flushParagraph();
      flushList();
      out.push(`<h3>${formatInline(h3Match[1])}</h3>`);
      return;
    }

    if (h2Match) {
      flushParagraph();
      flushList();
      out.push(`<h2>${formatInline(h2Match[1])}</h2>`);
      return;
    }

    if (numberedSectionMatch && /^\d+\.\s+/.test(numberedSectionMatch[1])) {
      flushParagraph();
      flushList();
      out.push(`<h2>${formatInline(numberedSectionMatch[1])}</h2>`);
      return;
    }

    if (bulletMatch) {
      flushParagraph();
      listItems.push(bulletMatch[1]);
      return;
    }

    if (labelLine && !line.includes("score:") && labelLine[2]) {
      flushParagraph();
      flushList();
      out.push(`<p><strong>${formatInline(labelLine[1])}</strong> ${formatInline(labelLine[2])}</p>`);
      return;
    }

    flushList();
    paragraph.push(line);
  });

  flushParagraph();
  flushList();

  return out.join("")
    .replace(/SCORE:\s*\d+\/100\s*$/im, "")
    .replace(/<p>\s*<\/p>/g, "");
}

function _hideNavigationOverlays() {
  const selectors = [
    "[id^='modal-']",
    ".mg-results-backdrop",
    ".mg-results",
    ".mg-intro-overlay",
    ".sort-learn-backdrop",
    "#mg-education-modal",
    "#badge-toast",
    "#emoji-picker-grid",
  ];
  document.querySelectorAll(selectors.join(",")).forEach(node => {
    node.classList.add("hidden");
  });
}

function showScreen(name) {
  if (_isScormRuntimeUi() && name === "login") name = "menu";
  document.querySelectorAll("[id^='screen-']").forEach(node => hide(node.id));
  _hideNavigationOverlays();
  show(`screen-${name}`);
  if (name === "menu") _syncHv2MobileMode();
  if (name === "category") _syncCategoryMobileMode();
  if (name === "menu") _renderRightDistrictList();
  _applyScormSaasUiTrim();
  _queueViewportSync(0);
  _maybeShowTourTip(name);
}

function _hideScreenTransitionModals() {
  const preserve = new Set([
    // These are active workflow surfaces opened after the target screen is already visible.
    "modal-agency-picker",
  ]);
  document.querySelectorAll("[id^='modal-']").forEach(node => {
    if (!preserve.has(node.id)) hide(node.id);
  });
  isPopupOpen = false;
}

function _isScormEmbeddedFrame() {
  if (!state.scormEnabled && !document.documentElement.classList.contains("scorm-runtime")) return false;
  try {
    return window.self !== window.top;
  } catch {
    return true;
  }
}

function _isSimMobileTarget() {
  const compact = window.matchMedia
    ? window.matchMedia("(max-width: 1024px)").matches
    : (window.innerWidth <= 1024);
  if (_isScormEmbeddedFrame()) return compact;
  const coarse = window.matchMedia ? window.matchMedia("(pointer: coarse)").matches : false;
  const touch = coarse || (navigator.maxTouchPoints || 0) > 0;
  return !!(compact && touch);
}

function _isHv2MobileTarget() {
  return window.matchMedia
    ? window.matchMedia("(max-width: 1024px)").matches
    : (window.innerWidth <= 1024);
}

function _setHv2MobileTab(tab = "map") {
  const screen = el("screen-menu");
  const left = el("hv2-left-nav");
  const main = el("hv2-main");
  const right = el("hv2-call-board");
  if (!screen || !left || !main || !right) return;

  const mobile = _isHv2MobileTarget();
  const activeTab = ["menu", "map", "calls"].includes(tab) ? tab : "map";
  screen.dataset.hv2MobileTab = activeTab;

  if (!mobile) {
    left.classList.remove("hidden", "hv2-mobile-pane-active");
    main.classList.remove("hidden", "hv2-mobile-pane-active");
    right.classList.remove("hidden", "hv2-mobile-pane-active");
    left.style.display = "";
    main.style.display = "";
    right.style.display = "";
  } else {
    left.classList.toggle("hidden", activeTab !== "menu");
    main.classList.toggle("hidden", activeTab !== "map");
    right.classList.toggle("hidden", activeTab !== "calls");
    left.classList.toggle("hv2-mobile-pane-active", activeTab === "menu");
    main.classList.toggle("hv2-mobile-pane-active", activeTab === "map");
    right.classList.toggle("hv2-mobile-pane-active", activeTab === "calls");
    left.style.display = activeTab === "menu" ? "flex" : "none";
    main.style.display = activeTab === "map" ? "flex" : "none";
    right.style.display = activeTab === "calls" ? "flex" : "none";
  }

  el("btn-hv2-tab-menu")?.classList.toggle("hv2-mobile-tab--active", mobile && activeTab === "menu");
  el("btn-hv2-tab-map")?.classList.toggle("hv2-mobile-tab--active", mobile && activeTab === "map");
  el("btn-hv2-tab-calls")?.classList.toggle("hv2-mobile-tab--active", mobile && activeTab === "calls");
}

function _syncHv2MobileMode() {
  const screen = el("screen-menu");
  const tabs = el("hv2-mobile-tabs");
  if (!screen || !tabs) return;
  const mobile = _isHv2MobileTarget();
  tabs.classList.toggle("hidden", !mobile);
  const active = screen.dataset.hv2MobileTab || "map";
  _setHv2MobileTab(mobile ? active : "map");
}

