function _setSimMobileTab(tab = "chat") {
  const left = el("sim-panel-left");
  const center = el("sim-panel-center");
  const right = el("sim-panel-right");
  if (!left || !center || !right) return;
  left.classList.toggle("hidden", tab !== "notes");
  center.classList.toggle("hidden", tab !== "chat");
  right.classList.toggle("hidden", tab !== "lexi");
  el("btn-sim-tab-notes")?.classList.toggle("active", tab === "notes");
  el("btn-sim-tab-chat")?.classList.toggle("active", tab === "chat");
  el("btn-sim-tab-lexi")?.classList.toggle("active", tab === "lexi");
  _syncSimMobileOffsets();
}

function _syncSimMobileOffsets() {
  const sim = el("screen-sim");
  if (!sim || !sim.classList.contains("sim-mobile-active")) return;
  const tabsH = Math.ceil(el("sim-mobile-tabs")?.offsetHeight || 50);
  const chatInputH = Math.ceil(el("sim-panel-center")?.querySelector(".sim-chat-input-wrap")?.offsetHeight || 116);
  const lexiInputH = Math.ceil(el("sim-panel-right")?.querySelector(".sim-lexi-controls")?.offsetHeight || 152);
  sim.style.setProperty("--sim-mobile-tabs-h", `${tabsH}px`);
  sim.style.setProperty("--sim-mobile-input-h", `${chatInputH}px`);
  sim.style.setProperty("--sim-mobile-lexi-input-h", `${lexiInputH}px`);
}

function _syncSimMobileMode() {
  const sim = el("screen-sim");
  const tabs = el("sim-mobile-tabs");
  if (!sim || !tabs) return;
  const mobileMode = _isSimMobileTarget();
  sim.classList.toggle("sim-mobile-active", mobileMode);
  tabs.classList.toggle("hidden", !mobileMode);
  if (mobileMode) {
    _setSimMobileTab("chat");
    _syncSimMobileOffsets();
  }
  else {
    sim.style.removeProperty("--sim-mobile-tabs-h");
    sim.style.removeProperty("--sim-mobile-input-h");
    sim.style.removeProperty("--sim-mobile-lexi-input-h");
    el("sim-panel-left")?.classList.remove("hidden");
    el("sim-panel-center")?.classList.remove("hidden");
    el("sim-panel-right")?.classList.remove("hidden");
    el("btn-sim-tab-notes")?.classList.remove("active");
    el("btn-sim-tab-chat")?.classList.remove("active");
    el("btn-sim-tab-lexi")?.classList.remove("active");
	  }
}

function _resetSimComposerInputs() {
  const chatInput = el("chat-input");
  if (chatInput) {
    chatInput.value = "";
    chatInput.style.height = "";
  }
  const lexiInput = el("lexi-input");
  if (lexiInput) {
    lexiInput.value = "";
    lexiInput.style.height = "";
  }
  _syncSimMobileOffsets();
}

const _LEFT_NAV_PREF_KEY = "ems:left_nav_expanded";

function _readLeftNavExpandedPref() {
  try {
    return localStorage.getItem(_LEFT_NAV_PREF_KEY) === "1";
  } catch {
    return false;
  }
}

function _writeLeftNavExpandedPref(open) {
  try {
    localStorage.setItem(_LEFT_NAV_PREF_KEY, open ? "1" : "0");
  } catch { /* storage may be unavailable */ }
}

function _setSharedLeftNavExpanded(open, { persist = true } = {}) {
  const expanded = !!open;
  const mainNav = el("hv2-left-nav");
  const mainBody = el("hv2-body");
  const mainToggleWrap = el("hv2-nav-toggle")?.closest(".hv2-toggle-wrap");
  const categoryNav = el("category-v2-left");
  const categoryBody = document.querySelector("#screen-category .category-v2-body");
  const categoryScreen = el("screen-category");
  const categoryToggleWrap = el("category-v2-nav-toggle")?.closest(".hv2-toggle-wrap");

  mainNav?.classList.toggle("expanded", expanded);
  mainBody?.classList.toggle("nav-open", expanded);
  categoryNav?.classList.toggle("expanded", expanded);
  categoryBody?.classList.toggle("nav-open", expanded);
  categoryScreen?.classList.toggle("nav-open", expanded);

  const width = expanded ? "var(--hv2-nav-w)" : "var(--hv2-nav-col-w)";
  if (mainToggleWrap) mainToggleWrap.style.width = width;
  if (mainNav) mainNav.style.width = width;
  if (categoryToggleWrap) categoryToggleWrap.style.width = width;
  if (categoryNav) categoryNav.style.width = width;

  if (persist) _writeLeftNavExpandedPref(expanded);
}

function _toggleSharedLeftNav() {
  const current = el("hv2-left-nav")?.classList.contains("expanded")
    || el("category-v2-left")?.classList.contains("expanded");
  _setSharedLeftNavExpanded(!current);
}

function _applySavedLeftNavPreference() {
  _setSharedLeftNavExpanded(_readLeftNavExpandedPref(), { persist: false });
}

/* ═══════════════════════════════════════════════════════════════════
   AUTH HELPERS
   ═══════════════════════════════════════════════════════════════════ */

function _getCsrfToken() {
  const match = document.cookie.match(/(?:^|;)\s*pfd_ems_csrf=([^;]+)/);
  return match ? decodeURIComponent(match[1]) : null;
}

// Wrapper around fetch() that injects the CSRF token for mutating requests.
// Cookies are sent automatically by the browser (same-origin, httpOnly session).
let _silentRefreshPromise = null;

async function _silentRefresh() {
  if (_silentRefreshPromise) return _silentRefreshPromise;
  _silentRefreshPromise = (async () => {
    try {
      const r = await fetch(`${API}/api/token/refresh`, {
        method: "POST",
        credentials: "same-origin",
      });
      return r.ok;
    } catch {
      return false;
    } finally {
      _silentRefreshPromise = null;
    }
  })();
  return _silentRefreshPromise;
}

function _responseNeedsActiveAgencyContext(response, detail = "") {
  if (!response || response.status !== 403) return false;
  return /active agency context required/i.test(String(detail || ""));
}

async function _restoreActiveAgencyContext() {
  const refreshed = await _silentRefresh();
  if (refreshed) return true;
  if (!state.agency_id) return false;
  const headers = { "Content-Type": "application/json" };
  const csrf = _getCsrfToken();
  if (csrf) headers["X-CSRF-Token"] = csrf;
  try {
    const res = await fetch(`${API}/api/token/switch`, {
      method: "POST",
      credentials: "same-origin",
      headers,
      body: JSON.stringify({ agency_id: state.agency_id }),
    });
    if (!res.ok) return false;
    const data = await res.json().catch(() => null);
    if (data) _storeAuthFromContext(data);
    return true;
  } catch {
    return false;
  }
}

async function authFetch(url, options = {}, _retry = true) {
  const { authRedirectOn401 = true, timeoutMs = 0, ...fetchOptions } = options || {};
  const method = String(fetchOptions.method || "GET").toUpperCase();
  const headers = { "Content-Type": "application/json", ...(fetchOptions.headers || {}) };
  const scormToken = _getScormAccessToken();
  if (scormToken && !headers.Authorization && !headers.authorization) {
    headers.Authorization = `Bearer ${scormToken}`;
  }
  if (method !== "GET" && method !== "HEAD") {
    const csrf = _getCsrfToken();
    if (csrf) headers["X-CSRF-Token"] = csrf;
  }
  const isRead = method === "GET" || method === "HEAD";
  let timeoutId = null;
  let signal = fetchOptions.signal;
  if (timeoutMs && !signal) {
    const controller = new AbortController();
    signal = controller.signal;
    timeoutId = window.setTimeout(() => controller.abort(), timeoutMs);
  }
  const res = await fetch(url, { ...fetchOptions, signal, headers, credentials: "same-origin", cache: isRead ? "no-store" : fetchOptions.cache })
    .finally(() => { if (timeoutId) window.clearTimeout(timeoutId); });
  if (res.status === 401 && _retry) {
    const refreshed = await _silentRefresh();
    if (refreshed) {
      // Retry once with the fresh session and CSRF cookies
      return authFetch(url, options, false);
    }
    if (authRedirectOn401) {
      if (_handleScormAuthExpired()) return res;
      _clearAuth();
      showScreen("login");
    }
  }
  if (res.status === 403 && _retry && !String(url || "").includes("/api/token/switch")) {
    let detail = "";
    try {
      const err = await res.clone().json();
      detail = err?.detail || "";
    } catch {}
    if (_responseNeedsActiveAgencyContext(res, detail)) {
      const restored = await _restoreActiveAgencyContext();
      if (restored) return authFetch(url, options, false);
    }
  }
  return res;
}

function _isScormLaunch() {
  return !!window.RescueTrails?.["scormAdapter"]?.isLaunch?.();
}

function _showScormLaunchStatus(message, tone = "info") {
  const box = el("scorm-launch-status");
  if (!box) return;
  box.textContent = message;
  box.classList.remove("hidden", "is-error", "is-info");
  box.classList.add(tone === "error" ? "is-error" : "is-info");
}

function _hideScormLaunchStatus() {
  const box = el("scorm-launch-status");
  if (!box) return;
  box.textContent = "";
  box.classList.add("hidden");
  box.classList.remove("is-error", "is-info");
}

function _releaseScormPreboot() {
  document.documentElement.classList.remove("scorm-preboot");
}

function _scormAssetUrl(url) {
  const value = String(url || "");
  if (!state.scormEnabled || !value) return value;
  const staticPrefix = `/${"static"}/`;
  if (value.startsWith(staticPrefix)) return value.slice(staticPrefix.length);
  return value.startsWith("static/") ? value.slice("static/".length) : value;
}

const _scenarioImagePreloads = new Map();

function _preloadImage(url, { priority = "high" } = {}) {
  const resolved = _scormAssetUrl(url);
  if (typeof Image === "undefined" || !resolved || _scenarioImagePreloads.has(resolved)) return resolved;
  const img = new Image();
  img.decoding = "async";
  if ("fetchPriority" in img) img.fetchPriority = priority;
  img.onload = () => _scenarioImagePreloads.set(resolved, "loaded");
  img.onerror = () => _scenarioImagePreloads.delete(resolved);
  _scenarioImagePreloads.set(resolved, img);
  img.src = resolved;
  return resolved;
}

function _preloadScenarioImages(scenario = {}) {
  const patientImage = scenario?.patient?.image || "";
  const sceneImage = scenario?.scene?.image || "";
  _preloadImage(sceneImage || patientImage, { priority: "high" });
  if (patientImage && patientImage !== sceneImage) _preloadImage(patientImage, { priority: "high" });
}

function _showScormLaunchError(err) {
  const message = err?.message || "SCORM launch failed. Please relaunch this activity from Moodle.";
  console.error("SCORM launch failed", err);
  _releaseScormPreboot();
  showScreen("scorm-station1");
  _showScormLaunchStatus(message, "error");
  ["scorm-map0-nodes", "scorm-pm1-nodes", "scorm-pt1-nodes", "scorm-map3-nodes", "scorm-optional-nodes"].forEach(id => {
    const list = el(id);
    if (list) list.innerHTML = "";
  });
}

function _getScormAccessToken() {
  if (!state.scormEnabled) return "";
  try {
    return window.RescueTrails?.["scormAdapter"]?.getAccessToken?.() || "";
  } catch {
    return "";
  }
}

