const _PEDS_MAP_BY_ID = new Map(PEDS_MAP_DATA.map(m => [m.id, m]));

const _pedsMapPriorityImages = new Map();
const _pedsMapPrefetchedImages = new Set();

function _prioritizePedsMapImage(url) {
  if (typeof Image === "undefined" || !url || _pedsMapPriorityImages.has(url)) return;
  const img = new Image();
  img.decoding = "async";
  if ("fetchPriority" in img) img.fetchPriority = "high";
  img.onload = () => {
    _pedsMapPriorityImages.delete(url);
    _prefetchAdjacentPedsMapImages();
  };
  img.onerror = () => _pedsMapPriorityImages.delete(url);
  _pedsMapPriorityImages.set(url, img);
  img.src = url;
}

function _pedsAdjacentMapIds(mapDef) {
  if (!mapDef) return [];
  return [
    mapDef.parent,
    ...(Array.isArray(mapDef.parents) ? mapDef.parents.map(parent => parent.to) : []),
    ...(Array.isArray(mapDef.exits) ? mapDef.exits.map(exit => exit.to) : []),
  ].filter(Boolean);
}

function _prefetchAdjacentPedsMapImages() {
  if (typeof Image === "undefined") return;
  const currentMap = _PEDS_MAP_BY_ID.get(_pedsJourneyState?.currentMap || "map_0") || PEDS_MAP_DATA[0];
  const maps = _pedsAdjacentMapIds(currentMap)
    .map(mapId => _PEDS_MAP_BY_ID.get(mapId))
    .filter(mapDef => mapDef?.image && !_pedsMapPrefetchedImages.has(mapDef.image));
  if (!maps.length) return;

  const prefetch = () => {
    maps.forEach(mapDef => {
      _pedsMapPrefetchedImages.add(mapDef.image);
      const img = new Image();
      img.decoding = "async";
      if ("fetchPriority" in img) img.fetchPriority = "low";
      img.src = mapDef.image;
    });
  };

  if (typeof window !== "undefined" && typeof window.requestIdleCallback === "function") {
    window.requestIdleCallback(prefetch, { timeout: 2500 });
  } else {
    setTimeout(prefetch, 1000);
  }
}

// ── Topology helpers ──────────────────────────────────────────────────────────

// Returns true if mapId is "complete" for unlock purposes (§10.2 completion rules).
// Gateway/convergence nodes: server-authoritative pedsMapCompleted set.
// Scenario maps: the final real (non-placeholder) scenario in ordered list must be cleared.
//   Maps with no real scenarios cannot be completed until content is implemented.
function _mapHasCompletion(mapId, completedIds, pedsMapCompleted = new Set()) {
  if (pedsMapCompleted.has(mapId)) return true;
  const mapDef = _PEDS_MAP_BY_ID.get(mapId);
  if (!mapDef) return false;
  const realScenarios = mapDef.scenarios.filter(s => !s.id.startsWith("_ph"));
  if (!realScenarios.length) return false;
  const finalScenario = realScenarios[realScenarios.length - 1];
  return completedIds.has(finalScenario.id);
}

// Returns Map<mapId, {unlocked: bool, partial: bool}>.
// pedsMapCompleted: Set of map IDs the server has recorded as gateway/convergence-complete.
function _computeMapUnlockState(completedIds, topology = MAP_TOPOLOGY, pedsMapCompleted = new Set()) {
  const fullyUnlocked = new Map();

  function isFullyUnlocked(mapId) {
    if (fullyUnlocked.has(mapId)) return fullyUnlocked.get(mapId);
    const topo = topology[mapId];
    if (!topo) { fullyUnlocked.set(mapId, false); return false; }
    if (topo.requires.length === 0) { fullyUnlocked.set(mapId, true); return true; }
    const result = topo.requires.every(reqId => isFullyUnlocked(reqId) && _mapHasCompletion(reqId, completedIds, pedsMapCompleted));
    fullyUnlocked.set(mapId, result);
    return result;
  }

  for (const mapId of Object.keys(topology)) isFullyUnlocked(mapId);

  const state = new Map();
  for (const [mapId, topo] of Object.entries(topology)) {
    const unlocked = fullyUnlocked.get(mapId) || false;
    let partial = false;
    if (!unlocked && topo.partial_requires) {
      partial = topo.partial_requires.some(reqId => isFullyUnlocked(reqId) && _mapHasCompletion(reqId, completedIds, pedsMapCompleted));
    }
    state.set(mapId, { unlocked, partial });
  }
  return state;
}

