let _pedsAssignmentsCache = null;
let _pedsAssignmentsLoading = false;
let _pedsAssignmentsAttempted = false;
let _patStatusCache = null;
let _patStatusLoading = false;
let _patStatusAttempted = false;
let _devSortStatusCache = null;
let _devSortStatusLoading = false;
let _devSortStatusAttempted = false;
