function _districtForCategory(categoryKey = "") {
  const direct = ADVENTURE_DISTRICTS.find(d => d.id === categoryKey);
  if (direct) return direct.id;
  const mapped = ADVENTURE_DISTRICTS.find(d => (d.legacy || []).includes(categoryKey));
  return mapped ? mapped.id : null;
}

function _scenarioCategoryLabelFromNode(node) {
  if (!node) return "General Activity";
  const c = node.scenario?.category || "";
  if (c === "pediatric_medical") return "Pediatric Medical Activity";
  if (c === "pediatric_trauma") return "Pediatric Trauma Activity";
  if (node.lane === "medical") return "Medical Activity";
  if (node.lane === "trauma") return "Trauma Activity";
  return "General Activity";
}

function _unlockRequirementForDistrict(districtId = "", totalPriorScenarios = 0) {
  if (!totalPriorScenarios || totalPriorScenarios <= 0) return 0;
  const district = ADVENTURE_DISTRICTS.find(d => d.id === districtId);
  const ratio = Number(district?.unlock_ratio);
  const unlockRatio = Number.isFinite(ratio) && ratio > 0 ? Math.min(1, ratio) : 0.8;
  const minRaw = Number(district?.unlock_min);
  const unlockMin = Number.isFinite(minRaw) && minRaw >= 0 ? Math.floor(minRaw) : 1;
  const ratioReq = Math.ceil(totalPriorScenarios * unlockRatio);
  return Math.min(totalPriorScenarios, Math.max(unlockMin, ratioReq));
}

function _normalizePedsAssignments(payload) {
  const src = payload?.scenario_assignments || payload;
  const fallback = PEDS_FIXED_SCENARIO_ASSIGNMENTS_FALLBACK;
  if (!src || typeof src !== "object") return fallback;
  const normLane = (laneKey) => {
    const lane = src[laneKey];
    if (!lane || typeof lane !== "object") return fallback[laneKey];
    const out = {};
    Object.keys(lane).forEach((k) => {
      const n = Number(k);
      if (!Number.isFinite(n) || n < 1) return;
      const list = Array.isArray(lane[k]) ? lane[k].filter((v) => typeof v === "string" && v.trim()) : [];
      out[n] = list;
    });
    return Object.keys(out).length ? out : fallback[laneKey];
  };
  return {
    medical: normLane("medical"),
    trauma: normLane("trauma"),
  };
}

async function _loadPedsAssignmentsConfig() {
  try {
    const res = await fetch(PEDS_ASSIGNMENTS_URL);
    if (!res.ok) return null;
    const data = await res.json().catch(() => null);
    _pedsAssignmentsCache = _normalizePedsAssignments(data);
    _pedsAssignmentsAttempted = true;
    return _pedsAssignmentsCache;
  } catch {
    return null;
  }
}

function _savePedsJourneyState() {
  try {
    localStorage.setItem(_pedsJourneyStorageKey(), JSON.stringify({
      selectedMedicalTrail: _pedsJourneyState.selectedMedicalTrail,
      selectedTraumaTrail:  _pedsJourneyState.selectedTraumaTrail,
      view:                 _pedsJourneyState.view,
      currentMap:           _pedsJourneyState.currentMap,
    }));
  } catch {}
}

function _restorePedsJourneyState() {
  try {
    const raw = localStorage.getItem(_pedsJourneyStorageKey());
    if (!raw) return;
    const saved = JSON.parse(raw);
    if (!saved || typeof saved !== "object") return;
    _pedsJourneyState.selectedMedicalTrail = Math.max(1, Number(saved.selectedMedicalTrail) || 1);
    _pedsJourneyState.selectedTraumaTrail  = Math.max(1, Number(saved.selectedTraumaTrail)  || 1);
    _pedsJourneyState.view = ["entrance", "medical", "trauma"].includes(saved.view) ? saved.view : "entrance";
    if (saved.currentMap && _PEDS_MAP_BY_ID.has(saved.currentMap)) {
      _pedsJourneyState.currentMap = saved.currentMap;
    }
  } catch {}
}

function _openScenarioPreview(node) {
  if (!node?.scenarioId || !node.available) return;
  _scenarioPreviewSelection = { type: "scenario", scenarioId: node.scenarioId, lastEntry: node.lastEntry || null };
  setText("scenario-preview-kicker", "Scenario Status");
  setText("scenario-preview-title", _scenarioRevealedTitle(node.scenario, node.completed) || node.label || "Ready to Play?");
  const categoryEl = el("scenario-preview-category");
  if (categoryEl) {
    categoryEl.textContent = `Category: ${_scenarioCategoryLabelFromNode(node)}`;
    categoryEl.classList.remove("hidden");
  }
  const detailEl = el("scenario-preview-detail");
  if (detailEl) {
    detailEl.innerHTML = "";
    detailEl.classList.add("hidden");
  }

  // Completion status with narrative detail
  let statusText = "Status: Not completed yet";
  if (node.completed && node.lastEntry) {
    const skipped = node.lastEntry.narrativeSkipped || (node.lastEntry.narrativeScore == null && !node.lastEntry.drillMode);
    statusText = skipped ? "Status: Completed without Narrative" : "Status: Completed with Narrative";
  } else if (node.completed) {
    statusText = "Status: Completed";
  }
  setText("scenario-preview-status", statusText);

  const playBtn = el("btn-scenario-preview-play");
  if (playBtn) {
    playBtn.disabled = false;
    playBtn.textContent = node.completed ? "Retake Scenario" : "Play Activity";
    playBtn.className = node.completed
      ? "flex-1 bg-amber-700 hover:bg-amber-600 text-white font-semibold py-2.5 rounded-lg transition-colors modal-btn modal-btn--amber ui-btn ui-btn--amber"
      : "flex-1 bg-amber-600 hover:bg-amber-500 text-white font-semibold py-2.5 rounded-lg transition-colors modal-btn modal-btn--amber ui-btn ui-btn--amber";
  }

	  const lastResultsBtn = el("btn-scenario-preview-last-results");
	  const notesBtn = el("btn-scenario-preview-notes");
	  if (lastResultsBtn) {
	    if (node.completed && node.lastEntry?.key) lastResultsBtn.classList.remove("hidden");
	    else lastResultsBtn.classList.add("hidden");
	  }
	  if (notesBtn) {
	    if (node.lastEntry?.key) notesBtn.classList.remove("hidden");
	    else notesBtn.classList.add("hidden");
	  }

  show("modal-scenario-preview");
  _prefetchScenarioData(node.scenarioId);
}

function _scenarioDisplayTitle(scenario = {}) {
  return scenario?.display_title || scenario?.title || scenario?.name || scenario?.scenario_title || "";
}

function _scenarioRevealedTitle(scenario = {}, completed = false) {
  if (completed) {
    return scenario?.title || scenario?.display_title || scenario?.name || scenario?.scenario_title || "";
  }
  return _scenarioDisplayTitle(scenario);
}

function _mapGameCompletionId(mapGameId = "") {
  return mapGameId === "pat_dash" ? "pat" : mapGameId;
}

function _completedLearningGameIds() {
  const scope = _notebookCacheScope();
  const cachedLearning = _notebookLearningCache.scope === scope && Array.isArray(_notebookLearningCache.data)
    ? _notebookLearningCache.data
    : [];
  const learningRows = cachedLearning.length
    ? cachedLearning
    : (Array.isArray(_notebookState.learning) ? _notebookState.learning : []);
  return new Set(learningRows.map(row => row?.game_id).filter(Boolean));
}

function _prefetchScenarioData(scenarioId) {
  if (!scenarioId) return;
  _scenarioPreviewDataCache = null;
  const promise = authFetch(`${API}/api/scenarios/${scenarioId}`)
    .then(r => r.ok ? r.json() : null)
    .then(data => {
      if (data) _preloadScenarioImages(data);
      if (data && _scenarioPreviewSelection?.scenarioId === scenarioId) {
        _scenarioPreviewDataCache = { scenarioId, data };
      }
      return data;
    })
    .catch(() => null)
    .finally(() => {
      if (_scenarioPreviewDataPromise?.scenarioId === scenarioId) _scenarioPreviewDataPromise = null;
    });
  _scenarioPreviewDataPromise = { scenarioId, promise };
}

function _mapNodeStatusText(selection) {
  if (selection.type === "scenario") {
    if (!selection.completed) return "Ready to start";
    return selection.lastEntry?.narrativeSkipped || (selection.lastEntry?.narrativeScore == null && !selection.lastEntry?.drillMode)
      ? "Completed without narrative"
      : "Completed with narrative";
  }
  if (selection.type === "station_intro" || selection.type === "station_wrapup" || selection.type === "station_challenges") {
    return selection.statusText || "";
  }
  if (selection.type === "station_locked") {
    return selection.statusText || "Complete the previous Station 1 step first.";
  }
  return selection.statusText || "Ready to play";
}

function _mapNodeKicker(selection = {}) {
  if (selection.kicker) return selection.kicker;
  if (selection.type === "map_requirements") {
    return selection.statusKind === "district" ? "District Status" : "Map Status";
  }
  if (selection.type === "lexi_message" || selection.type === "station_intro" || selection.type === "station_wrapup" || selection.type === "station_challenges") {
    return "Message";
  }
  if (selection.type === "scenario") return "Scenario Status";
  if (selection.type === "station_locked") {
    return "District Status";
  }
  return "Activity Status";
}

function _mapNodeCategory(selection = {}) {
  if (selection.categoryLabel) return selection.categoryLabel;
  if (selection.type === "scenario") return "Scenario";
  if (selection.type === "map_requirements") {
    return selection.statusKind === "district" ? "District" : "Map";
  }
  if (selection.type === "lexi_message") return "Lexi";
  if (selection.type === "station_intro" || selection.type === "station_wrapup" || selection.type === "station_challenges" || selection.type === "station_locked") {
    return "Station 1";
  }
  return "Training Drill";
}

