function _openMgEducation(selection, returnMode = "preview") {
  if (!_hasMgEducation(selection)) return;
  _mgEducationSelection = selection;
  _mgEducationReturnMode = returnMode;
  const cfg = _MG_EDUCATION[selection.type];
  setText("mg-education-title", cfg.title);
  setText("mg-education-subtitle", cfg.subtitle);
  const body = el("mg-education-body");
  if (body) {
    const imageHtml = cfg.imageUrl
      ? `<figure class="mg-education-image-card"><img src="${escapeHTML(cfg.imageUrl)}" alt="${escapeHTML(cfg.imageAlt || cfg.title)}" /></figure>`
      : "";
    body.innerHTML = imageHtml + cfg.sections.map(section => `
      <section class="mg-education-section">
        <h3>${escapeHTML(section.title)}</h3>
        <ul>
          ${section.bullets.map(bullet => `<li>${escapeHTML(bullet)}</li>`).join("")}
        </ul>
      </section>
    `).join("");
  }
  show("mg-education-modal");
}

function _openMapNodeModal(selection) {
  if (!selection) return;
  _scenarioPreviewSelection = selection;
  setText("scenario-preview-kicker", _mapNodeKicker(selection));
  const modalTitle = selection.type === "scenario"
    ? (_scenarioRevealedTitle(selection.scenario, selection.completed) || selection.label || "Ready to Play?")
    : (selection.label || "Ready to Play?");
  setText("scenario-preview-title", modalTitle);
  const categoryEl = el("scenario-preview-category");
  const categoryText = _mapNodeCategory(selection);
  if (categoryEl) {
    if (categoryText) {
      categoryEl.textContent = categoryText;
      categoryEl.classList.remove("hidden");
    } else {
      categoryEl.textContent = "";
      categoryEl.classList.add("hidden");
    }
  }
  setText("scenario-preview-status", _mapNodeStatusText(selection));
  const detailEl = el("scenario-preview-detail");
  if (detailEl) {
    if (selection.detailHtml) {
      detailEl.innerHTML = selection.detailHtml;
      detailEl.classList.remove("hidden");
    } else {
      detailEl.innerHTML = "";
      detailEl.classList.add("hidden");
    }
  }

  const playBtn = el("btn-scenario-preview-play");
  if (playBtn) {
    playBtn.disabled = false;
    playBtn.classList.remove("opacity-60", "opacity-70", "cursor-not-allowed", "scenario-preview-play--repeat");
    if (selection.type === "map_requirements") {
      playBtn.textContent = selection.reportDistrictId && selection.canReport ? "Report to District" : "Close";
      playBtn.disabled = false;
    } else if (selection.type === "station_locked") {
      playBtn.textContent = "Locked";
      playBtn.disabled = true;
      playBtn.classList.add("opacity-60", "cursor-not-allowed");
    } else if (selection.type === "station_intro") {
      playBtn.textContent = "Got It";
    } else if (selection.type === "lexi_message") {
      playBtn.textContent = "Got It";
    } else if (selection.type === "station_challenges") {
      playBtn.textContent = "Continue";
    } else if (selection.type === "station_wrapup") {
      playBtn.textContent = "Complete Station 1";
    } else if (selection.type === "scenario") {
      playBtn.textContent = selection.completed ? "Retake Scenario" : "Take Scenario";
    } else {
      playBtn.textContent = selection.completed ? "Play Again" : "Play Activity";
      playBtn.classList.toggle("scenario-preview-play--repeat", Boolean(selection.completed));
    }
  }

  const notesBtn = el("btn-scenario-preview-notes");
  const lastResultsBtn = el("btn-scenario-preview-last-results");
  if (lastResultsBtn) {
    if (selection.type === "scenario" && selection.lastEntry?.key) {
      lastResultsBtn.classList.remove("hidden");
    } else {
      lastResultsBtn.classList.add("hidden");
    }
  }
  if (notesBtn) {
    if (selection.type === "scenario" && selection.lastEntry?.key) {
      notesBtn.classList.remove("hidden");
    } else {
      notesBtn.classList.add("hidden");
    }
  }
  show("modal-scenario-preview");
  if (selection.type === "scenario" && selection.scenarioId) _prefetchScenarioData(selection.scenarioId);
}

function _presentMapNodeSelection(selection) {
  if (!selection) return;
  _openMapNodeModal(selection);
}

async function _loadPatStatus() {
  try {
    const res = await authFetch(`${API}/api/me/minigames/pat/status`);
    _patStatusAttempted = true;
    if (!res.ok) return null;
    const data = await res.json().catch(() => null);
    _patStatusCache = data || null;
    return _patStatusCache;
  } catch {
    _patStatusAttempted = true;
    return null;
  }
}

async function _loadDevSortStatus() {
  try {
    const res = await authFetch(`${API}/api/me/minigames/dev-sort/status`);
    _devSortStatusAttempted = true;
    if (!res.ok) return null;
    const data = await res.json().catch(() => null);
    _devSortStatusCache = data || null;
    return _devSortStatusCache;
  } catch {
    _devSortStatusAttempted = true;
    return null;
  }
}

async function _openPatPreview(launchMapId = null) {
  const cachedStatus = _patStatusCache;
  const render = (status) => {
    const runs = Number(status?.runs_today || 0);
    const xpToday = Number(status?.xp_today || 0);
    const remaining = Number(status?.remaining_xp ?? PAT_DAILY_CAP_XP);
    const totalRuns = Number(status?.total_cards > 0 ? Math.ceil(status.total_cards / 10) : 0);
    const bestAcc = Number(status?.best_accuracy || 0);
    let statusLine = `${runs} run${runs !== 1 ? "s" : ""} today · ${xpToday} XP earned · ${remaining} XP remaining`;
    if (bestAcc > 0) statusLine += ` · Best accuracy: ${bestAcc}%`;
    _presentMapNodeSelection({
      type: "pat",
      label: "Doorway Dash",
      completed: !!status?.ever_completed,
      statusText: statusLine,
      launchMapId,
    });
  };
  render(cachedStatus);
  const status = await _loadPatStatus();
  if (status && _scenarioPreviewSelection?.type === "pat") render(status);
}

function _patGamesSummary() {
  return { completed: _patStatusCache?.ever_completed ? 1 : 0 };
}

function _devSortCompletedOnce() {
  try { return localStorage.getItem(DEV_SORT_COMPLETED_KEY) === "1"; }
  catch { return false; }
}

function _devSortGamesSummary() {
  if (_devSortStatusCache) {
    return { completed: _devSortStatusCache?.ever_completed ? 1 : 0 };
  }
  return { completed: _devSortCompletedOnce() ? 1 : 0 };
}

async function _openDevSortPreview(launchMapId = null) {
  const cachedStatus = _devSortStatusCache;
  const render = (status) => {
    const runs = Number(status?.runs_today || 0);
    const xpToday = Number(status?.xp_today || 0);
    const remaining = Number(status?.remaining_xp ?? DEV_SORT_DAILY_CAP_XP);
    const bestAcc = Number(status?.best_accuracy || 0);
    let statusLine = `${runs} run${runs !== 1 ? "s" : ""} today · ${xpToday} XP earned · ${remaining} XP remaining`;
    if (bestAcc > 0) statusLine += ` · Best accuracy: ${bestAcc}%`;
    _presentMapNodeSelection({
      type: "dev_sort",
      label: "Pediatric Stages of Development",
      completed: !!status?.ever_completed || _devSortCompletedOnce(),
      statusText: statusLine,
      launchMapId,
    });
  };
  render(cachedStatus);
  const status = await _loadDevSortStatus();
  if (status && _scenarioPreviewSelection?.type === "dev_sort") render(status);
}

function _openMgPreview(gameId, label, launchMapId = null) {
  _presentMapNodeSelection({
    type:       gameId,
    label:      label,
    completed:  false,
    statusText: "Ready to play",
    launchMapId,
  });
}

