function _dogParkGameCatalog() {
  return DOG_PARK_GAME_GROUPS.flatMap(group => group.games.map(game => ({ ...game, groupId: group.id })));
}

function _dogParkVisibleGroups(unlockedGameIds = new Set()) {
  return DOG_PARK_GAME_GROUPS
    .map(group => ({
      ...group,
      games: group.games.filter(game => game.alwaysAvailable || unlockedGameIds.has(game.type)),
    }))
    .filter(group => group.games.length > 0);
}

async function _openDogParkGamePreview(game) {
  if (!game?.type) return;
  if (game.type === "pat") {
    const render = (status) => {
      const runs = Number(status?.runs_today || 0);
      const xpToday = Number(status?.xp_today || 0);
      const remaining = Number(status?.remaining_xp ?? PAT_DAILY_CAP_XP);
      const bestAcc = Number(status?.best_accuracy || 0);
      let statusLine = `${runs} run${runs !== 1 ? "s" : ""} today · ${xpToday} XP earned · ${remaining} XP remaining`;
      if (bestAcc > 0) statusLine += ` · Best accuracy: ${bestAcc}%`;
      _openMapNodeModal({
        type: "pat",
        label: game.label || "Doorway Dash",
        completed: !!status?.ever_completed,
        statusText: statusLine,
      });
    };
    render(_patStatusCache);
    const status = await _loadPatStatus();
    if (status && _scenarioPreviewSelection?.type === "pat") render(status);
    return;
  }
  if (game.type === "dev_sort") {
    const render = (status) => {
      const runs = Number(status?.runs_today || 0);
      const xpToday = Number(status?.xp_today || 0);
      const remaining = Number(status?.remaining_xp ?? DEV_SORT_DAILY_CAP_XP);
      const bestAcc = Number(status?.best_accuracy || 0);
      let statusLine = `${runs} run${runs !== 1 ? "s" : ""} today · ${xpToday} XP earned · ${remaining} XP remaining`;
      if (bestAcc > 0) statusLine += ` · Best accuracy: ${bestAcc}%`;
      _openMapNodeModal({
        type: "dev_sort",
        label: game.label || "Pediatric Stages of Development",
        completed: !!status?.ever_completed || _devSortCompletedOnce(),
        statusText: statusLine,
      });
    };
    render(_devSortStatusCache);
    const status = await _loadDevSortStatus();
    if (status && _scenarioPreviewSelection?.type === "dev_sort") render(status);
    return;
  }
  _openMapNodeModal({
    type: game.type,
    label: game.label || "Training Drill",
    completed: true,
    statusText: "Unlocked for replay",
  });
}

/* ═══════════════════════════════════════════════════════════════════
   PAT SWIPE GAME — engine instance + topic-specific config
   ═══════════════════════════════════════════════════════════════════ */
const _patEngine = new SwipeGameEngine({
  prefix:       "pat",
  gameId:       "pat",
  adaptiveMode: true,
  durationSec:  PAT_GAME_DURATION_SEC,
  swipeMinPx:   PAT_SWIPE_MIN_PX,
  previewMinPx: PAT_PREVIEW_MIN_PX,
  choices:      { right: "sick", left: "not_sick" },
  decisionLabels: { sick: "Sick", not_sick: "Not Sick" },
  cardsUrl:     PAT_CARDS_URL,
  fallbackCards: PAT_CARD_FALLBACK,
  normalizeCard: _normalizePatCard,

  getExpectedDecision(card) {
    const explicit = String(card.decision || "").toLowerCase();
    if (explicit === "sick" || explicit === "not_sick") return explicit;
    const bucket = String(card.bucket || "").toLowerCase();
    return bucket === "not_pat" ? "not_sick" : "sick";
  },

  getSignalLabel(card) {
    const explicit = String(card.ticls || "").trim();
    if (explicit) return explicit;
    const prompt = String(card.prompt || "").toLowerCase();
    if (prompt.includes("consol"))   return "TICLS: Consolability";
    if (prompt.includes("interact") || prompt.includes("eye contact") || prompt.includes("track")) return "TICLS: Interactiveness";
    if (prompt.includes("cry"))      return "TICLS: Speech/Cry";
    if (prompt.includes("tone") || prompt.includes("limp")) return "TICLS: Tone";
    if (prompt.includes("gaze") || prompt.includes("look")) return "TICLS: Look/Gaze";
    const bucket = String(card.bucket || "").toLowerCase();
    if (bucket === "appearance")  return "TICLS Appearance";
    if (bucket === "breathing")   return "PAT Breathing";
    if (bucket === "circulation") return "PAT Circulation";
    return "Doorway Hands-Off Rule";
  },

  feedback: {
    active:      "Swipe right if this doorway cue suggests SICK. Swipe left if NOT SICK.",
    nudge:       "Swipe left for Not Sick, right for Sick. Or tap left/right half of the card.",
    onCorrect:   (signal)         => `It's a Match: ${signal}`,
    onIncorrect: (expected, card) => card.explanation || `No match: this doorway cue is ${expected === "sick" ? "SICK" : "NOT SICK"} by PAT.`,
  },

  toastError: "Could not load PAT game cards.",

  async onRoundComplete({ total, correct, bestStreak, elapsedSec, mode, mistakeTags, hintCount }) {
    if (mode === "ce_adaptive") {
      await _mgSubmitResult("pat", { total, correct, bestStreak, elapsedSec, mode, mistakeTags, hintCount }, "pat-r-xp", "pat-server-cap-note");
      return;
    }
    try {
      const res = await authFetch(`${API}/api/me/minigames/pat/submit`, {
        method: "POST",
        body: JSON.stringify({ total_cards: total, correct, best_streak: bestStreak, elapsed_sec: elapsedSec, run_id: _drillRunId, session_elapsed_sec: _drillLapTimer.stop() }),
      });
      const data = await res.json().catch(() => ({}));
      if (res.ok) {
        const score = Number(data.score ?? (total > 0 ? Math.round((correct / total) * 100) : 0));
        setText("pat-r-xp", `+${Number(data.xp_earned || 0)} XP`);
        setText("pat-server-cap-note", data.xp_capped
          ? "Daily limit reached — come back tomorrow for more XP."
          : `${Number(data.remaining_xp || 0)} XP remaining today.`);
        _patStatusCache = {
          ...(_patStatusCache || {}),
          xp_today:       Number(data.xp_today    || 0),
          runs_today:     Number(data.runs_today   || 0),
          remaining_xp:   Number(data.remaining_xp || 0),
          ever_completed: !!data.ever_completed,
        };
        _applyGamificationAward({ xpEarned: Number(data.xp_earned || 0) });
        if (score >= 70) await _saveMgLearningPage("pat");
        await _onScormNodeComplete("pat", score, true, Array.isArray(mistakeTags) ? mistakeTags : []);
        await _loadProgressFromServer().catch(() => {});
        _refreshGamificationChrome();
        await _refreshScormSummary().catch(() => {});
        if (!el("screen-menu")?.classList.contains("hidden")) buildMenu();
      } else {
        setText("pat-server-cap-note", data.detail || "Could not record PAT results.");
      }
    } catch {
      setText("pat-server-cap-note", "Connection issue recording PAT results.");
    }
  },
});

function _openPatGameScreen() {
  _newDrillRun();
  _patEngine.stop();
  _patEngine.resetUi();
  _patEngine.bindGestures();
  el("pat-swipe-hint")?.classList.remove("hidden");
  const status  = _patStatusCache || {};
  const runs    = Number(status.runs_today  || 0);
  const xpToday = Number(status.xp_today   || 0);
  const remain  = Number(status.remaining_xp ?? PAT_DAILY_CAP_XP);
  setText("pat-subtitle", `Classify doorway cues as Sick or Not Sick before time runs out. Today: ${runs} run${runs !== 1 ? "s" : ""}, ${xpToday} XP, ${remain} XP remaining.`);
  show("pat-intro-overlay");
  hide("pat-learn-modal");
  showScreen("pat-game");
}

/* ═══════════════════════════════════════════════════════════════════
   SORT GAME — Lexi avatar helpers (expressions + motion states)
   ═══════════════════════════════════════════════════════════════════ */
let _sortLexiResetTimer = null;

function _sortLexiSetExpression(mood) {
  const expr = _LEXI_EXPRESSIONS[mood] || _LEXI_EXPRESSIONS.neutral;
  const eyeL  = document.getElementById("sort-lexi-eye-l");
  const eyeR  = document.getElementById("sort-lexi-eye-r");
  const mouth = document.getElementById("sort-lexi-mouth");
  if (eyeL)  eyeL.setAttribute("ry",  String(expr.eyeRy));
  if (eyeR)  eyeR.setAttribute("ry",  String(expr.eyeRy));
  if (mouth) mouth.setAttribute("d",  expr.mouth);
}

function _sortLexiSetState(stateName, opts = {}) {
  const avatar = el("sort-lexi-avatar");
  if (!avatar) return;
  if (_sortLexiResetTimer) { clearTimeout(_sortLexiResetTimer); _sortLexiResetTimer = null; }
  avatar.classList.remove("lexi-celebrating", "lexi-encouraging", "lexi-concerned", "thinking");
  if (!_lexiPrefersReducedMotion()) {
    if (stateName === "celebrating") avatar.classList.add("lexi-celebrating");
    if (stateName === "encouraging") avatar.classList.add("lexi-encouraging");
    if (stateName === "concerned")   avatar.classList.add("lexi-concerned");
    if (stateName === "thinking")    avatar.classList.add("thinking");
  }
  if ((opts.autoResetMs || 0) > 0) {
    _sortLexiResetTimer = setTimeout(() => _sortLexiSetState("idle"), opts.autoResetMs);
  }
}

const _SORT_LEXI_CORRECT_MSGS = ["Nice sort! 🐾", "That's right!", "Pawsome! 🐾", "Great job! ✅", "Spot on!"];
const _SORT_LEXI_WRONG_MSGS   = (label) => [`Not quite — that's ${label}!`, `Hmm, that one's ${label}.`, `Almost! Try ${label} next time.`];

/* ═══════════════════════════════════════════════════════════════════
   DEVELOPMENT SORT GAME — engine instance + content config
   ═══════════════════════════════════════════════════════════════════ */
const _devSortEngine = new DragSortGameEngine({
  prefix: "sort",
  gameUrl: DEV_SORT_GAME_URL,
  fallbackGame: DEV_SORT_GAME_FALLBACK,
  onCardResult({ correct, correctLabel }) {
    if (correct) {
      const msg = _SORT_LEXI_CORRECT_MSGS[Math.floor(Math.random() * _SORT_LEXI_CORRECT_MSGS.length)];
      setText("sort-lexi-msg", msg);
      _sortLexiSetExpression("happy");
      _sortLexiSetState("celebrating", { autoResetMs: 900 });
    } else {
      const msgs = _SORT_LEXI_WRONG_MSGS(correctLabel);
      setText("sort-lexi-msg", msgs[Math.floor(Math.random() * msgs.length)]);
      _sortLexiSetExpression("sad");
      _sortLexiSetState("concerned", { autoResetMs: 1000 });
    }
  },
  async onRoundComplete({ total, correct }) {
    const accuracy = total > 0 ? Math.round((correct / total) * 100) : 0;
    // Lexi reacts to round results
    if (accuracy === 100) {
      setText("sort-lexi-msg", `Perfect score! ${correct}/${total} — Lexi is impressed! 🎉`);
      _sortLexiSetExpression("happy");
      _sortLexiSetState("celebrating", { autoResetMs: 2000 });
    } else if (accuracy >= 70) {
      setText("sort-lexi-msg", `Nice work! ${correct}/${total} sorted correctly! 🐾`);
      _sortLexiSetExpression("happy");
      _sortLexiSetState("encouraging", { autoResetMs: 1500 });
    } else {
      setText("sort-lexi-msg", `${correct}/${total} correct — let's review those stages! 📚`);
      _sortLexiSetExpression("sad");
      _sortLexiSetState("concerned", { autoResetMs: 1500 });
    }
    try {
      const _devSortSessionSec = _drillLapTimer.stop();
      const res = await authFetch(`${API}/api/me/minigames/dev-sort/submit`, {
        method: "POST",
        body: JSON.stringify({ total_cards: total, correct, elapsed_sec: _devSortSessionSec, session_elapsed_sec: _devSortSessionSec, run_id: _drillRunId }),
      });
      const data = await res.json().catch(() => ({}));
      if (res.ok) {
        const score = Number(data.score ?? accuracy);
        setText("sort-r-xp", `+${Number(data.xp_earned || 0)} XP`);
        setText("sort-server-cap-note", data.xp_capped
          ? "Daily limit reached — come back tomorrow for more XP."
          : `${Number(data.remaining_xp || 0)} XP remaining today.`);
        _devSortStatusCache = {
          ...(_devSortStatusCache || {}),
          xp_today: Number(data.xp_today || 0),
          runs_today: Number(data.runs_today || 0),
          remaining_xp: Number(data.remaining_xp || 0),
          ever_completed: !!data.ever_completed,
        };
        _applyGamificationAward({ xpEarned: Number(data.xp_earned || 0) });
        if (score >= 70) {
          await _saveMgLearningPage("dev_sort");
          el("btn-sort-continue-red-flags")?.classList.remove("hidden");
        } else {
          el("btn-sort-continue-red-flags")?.classList.add("hidden");
        }
        await _onScormNodeComplete("dev_sort", score, true, []);
        await _loadProgressFromServer().catch(() => {});
        _refreshGamificationChrome();
        await _refreshScormSummary().catch(() => {});
        if (!el("screen-menu")?.classList.contains("hidden")) buildMenu();
      } else {
        setText("sort-server-cap-note", data.detail || "Could not record drill results.");
      }
    } catch {
      setText("sort-server-cap-note", "Connection issue recording drill results.");
    }
    // NOTE: Do NOT call _renderPediatricsJourney here — it unconditionally calls
    // showScreen("category"), which hides the sort game screen and closes the
    // results before the user can see them. The map refreshes when the user
    // exits via "Back to Map" which calls _exitSortGameToMap → _renderPediatricsJourney.
  },
});

async function _openDevSortGameScreen() {
  _newDrillRun();
  const renderIntro = (game, status = _devSortStatusCache || {}) => {
    const runs = Number(status?.runs_today || 0);
    const xpToday = Number(status?.xp_today || 0);
    const remain = Number(status?.remaining_xp ?? DEV_SORT_DAILY_CAP_XP);
    setText("sort-title", game?.subtitle ? "Pediatric Stages of Development" : (game?.title || "Pediatric Stages of Development"));
    setText("sort-subtitle", `${game?.subtitle || "Sort characteristics into age groups."} Today: ${runs} run${runs !== 1 ? "s" : ""}, ${xpToday} XP, ${remain} XP remaining.`);
    const learnWrap = el("sort-learn-stages");
    if (!learnWrap) return;
    const buckets = Array.isArray(game?.buckets) ? game.buckets : [];
    // Desktop: always "med" for uniform card height across all stages.
    // Mobile: each card picks its own adaptive size.
    const cardSizeFor = (n) => n >= 4 ? "large" : n <= 2 ? "small" : "med";
    const uniformSize = "med";

    learnWrap.innerHTML = buckets.map((b) => {
      const noteCount  = (b.stage_notes || []).length;
      const mobileSize = cardSizeFor(noteCount);
      const desktopUrl = `/static/img/minigames/sorting/intro_card_${uniformSize}.png`;
      const mobileUrl  = `/static/img/minigames/sorting/intro_card_${mobileSize}.png`;
      return `
        <div class="sort-stage-learn-card"
             style="--card-bg-desktop:url('${escapeHTML(desktopUrl)}');--card-bg-mobile:url('${escapeHTML(mobileUrl)}')">
          <div class="sort-stage-learn-content">
            <p class="sort-stage-learn-label">${escapeHTML(b.label || b.id)}</p>
            <p class="sort-stage-learn-age">${escapeHTML(b.age_range || "")} yrs</p>
            <ul class="sort-stage-learn-notes">
              ${(b.stage_notes || []).map((n) => `<li>${escapeHTML(String(n))}</li>`).join("")}
            </ul>
          </div>
        </div>`;
    }).join("");
  };
  renderIntro(_devSortEngine._game || _devSortEngine._cfg.fallbackGame, _devSortStatusCache || {});
  _devSortEngine.resetUi();
  setText("sort-r-xp", "+0 XP");
  setText("sort-server-cap-note", "");
  // Reset Lexi to a welcoming state
  setText("sort-lexi-msg", "Sort the milestones into the right toy boxes! 🐾");
  _sortLexiSetExpression("neutral");
  _sortLexiSetState("encouraging", { autoResetMs: 1000 });
  show("sort-intro-overlay");
  hide("sort-learn-modal");
  showScreen("sort-game");
  const game = await _devSortEngine._loadGame();
  const status = (await _loadDevSortStatus()) || _devSortStatusCache || {};
  renderIntro(game, status);
}

/* ═══════════════════════════════════════════════════════════════════
   SHARED MINI-GAME HELPERS — result submit, status tracking
   ═══════════════════════════════════════════════════════════════════ */
function _mgRunId(gameId) {
  return `${gameId}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

function _mgEnsureHintControls(prefix, anchorSuffix = "feedback") {
  const anchor = el(`${prefix}-${anchorSuffix}`) || el(`${prefix}-feedback`) || el(`${prefix}-explanation`);
  if (!anchor?.parentNode) return null;
  const existing = el(`${prefix}-hint-wrap`);
  if (existing) return existing;
  const wrap = document.createElement("div");
  wrap.id = `${prefix}-hint-wrap`;
  wrap.className = "mg-hint-wrap hidden";
  wrap.innerHTML = `
    <button id="btn-${prefix}-hint" class="mg-hint-btn" type="button">Hint</button>
    <p id="${prefix}-hint-text" class="mg-hint-text hidden"></p>
  `;
  anchor.parentNode.insertBefore(wrap, anchor);
  return wrap;
}

function _mgResetHint(prefix, hint = "", onUse = null, anchorSuffix = "feedback") {
  const wrap = _mgEnsureHintControls(prefix, anchorSuffix);
  const btn = el(`btn-${prefix}-hint`);
  const text = el(`${prefix}-hint-text`);
  if (!wrap || !btn || !text) return;
  text.textContent = "";
  text.classList.add("hidden");
  const available = Boolean(hint);
  wrap.classList.toggle("hidden", !available);
  btn.disabled = !available;
  btn.onclick = available ? () => {
    text.textContent = hint;
    text.classList.remove("hidden");
    onUse?.();
  } : null;
}

let _mgProficiencyCache = null;

async function _mgLoadProficiency() {
  if (_mgProficiencyCache) return _mgProficiencyCache;
  try {
    const res = await authFetch(`${API}/api/me/minigames/proficiency`, { timeoutMs: 800 });
    if (!res.ok) throw new Error("proficiency unavailable");
    _mgProficiencyCache = await res.json();
  } catch {
    _mgProficiencyCache = {};
  }
  return _mgProficiencyCache;
}

async function _mgShouldUseAdaptiveMode(gameId) {
  const prof = await _mgLoadProficiency();
  const row = prof?.[gameId] || {};
  return Number(row.runs_30d || 0) >= 3 && Number(row.avg_score_30d || 0) >= 80;
}

async function _mgSubmitResult(gameId, { total, correct, bestStreak, elapsedSec, mistakeTags, mode, hintCount, sequenceData, caseEvidence, sessionElapsedSec }, xpEl, capNoteEl) {
  try {
    const score   = total > 0 ? Math.round((correct / total) * 100) : 0;
    const runId   = _mgRunId(gameId);
    const payload = { game_id: gameId, run_id: runId, score, total, correct, elapsed_sec: elapsedSec, session_elapsed_sec: sessionElapsedSec || 0 };
    if (mistakeTags?.length) payload.mistake_tags = mistakeTags;
    if (mode)               payload.mode          = mode;
    if (hintCount != null)  payload.hint_count    = Math.max(0, Number(hintCount) || 0);
    if (sequenceData && typeof sequenceData === "object") payload.sequence_data = sequenceData;
    if (Array.isArray(caseEvidence) && caseEvidence.length) payload.case_evidence = caseEvidence;
    const res   = await authFetch(`${API}/api/me/minigames/result`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    const data = await res.json().catch(() => ({}));
    if (res.ok) {
      _mgProficiencyCache = null;
      const xpEarned = Number(data.xp_earned || 0);
      const remainingXp = Number(data.remaining_xp || 0);
      if (xpEl) setText(xpEl, `+${xpEarned} XP`);
      if (capNoteEl) setText(capNoteEl, data.xp_capped
        ? `Saved +${xpEarned} XP. Daily drill XP limit reached for this game.`
        : `Saved +${xpEarned} XP. ${remainingXp} XP remaining for this game today.`);
      if (!_progressCache) _progressCache = _PROGRESS_DEFAULTS();
      _applyGamificationAward({ xpEarned });
      const bestScores = {
        ...(_progressCache.minigameBestScores || {}),
        [gameId]: Math.max(Number(_progressCache.minigameBestScores?.[gameId] || 0), score),
      };
      _progressCache = { ..._progressCache, minigameBestScores: bestScores };
      _writeProgressHistoryCache();

      window.dispatchEvent(new CustomEvent("rt:drillComplete", {
        detail: {
          gameId,
          score,
          passed:      score >= 70,
          mistakeTags: Array.isArray(mistakeTags) ? mistakeTags : [],
        },
      }));
      // Save learning page to notebook for passing runs; backend verifies the score
      // from stored MinigameResult rows and reads content server-side.
      if (score >= 70 && _MG_LEARNING_PAGES[gameId]) {
        await _saveMgLearningPage(gameId);
      }
      const unlockedCards = Array.isArray(data.newly_unlocked_reference_cards)
        ? data.newly_unlocked_reference_cards
        : [];
      if (unlockedCards.length) {
        const firstCard = unlockedCards[0];
        const title = firstCard?.title || firstCard?.card_id || "Reference card";
        showToast(`Reference card unlocked: ${title}`, "success");
      }
      await _loadProgressFromServer().catch(() => {});
      _refreshGamificationChrome();
      await _refreshScormSummary().catch(() => {});
      await _loadChallenges().then(_buildChallengesSection).catch(() => {});
    } else {
      if (capNoteEl) setText(capNoteEl, data.detail || "Could not save results.");
    }
  } catch {
    if (capNoteEl) setText(capNoteEl, "Connection issue saving results.");
  }
}

function _exitMgToMap(gameId) {
  document.getElementById(`${gameId}-engine`)?.stop?.();
  if (_categoryView?.mode === "district" && _categoryView?.districtId === "pediatrics") {
    _renderPediatricsJourney({ preserveTrail: true });
  }
  showScreen("category");
}

