/* ═══════════════════════════════════════════════════════════════════
   RULE OF NINES GAME — body-region accumulator + implication follow-up
   ═══════════════════════════════════════════════════════════════════ */
class BodyMapGame {
  constructor(cfg) {
    this._cfg = cfg;
    this._data = null;
    this._state = {
      deck: [],
      idx: 0,
      regionValues: {},
      correct: 0,
      total: 0,
      startTs: 0,
      mistakeTags: [],
      hintCount: 0,
      hintedCases: new Set(),
      bsaSubmitted: false,
      bsaAttempts: 0,
    };
  }

  _el(suffix) { return el(`${this._cfg.prefix}-${suffix}`); }

  async _loadData() {
    if (this._data) return this._data;
    const res = await _fetchWithTimeout(this._cfg.dataUrl, {}, 2500);
    if (!res.ok) throw new Error("rule_of_nines data unavailable");
    this._data = await res.json();
    return this._data;
  }

  resetUi() {
    hide(`${this._cfg.prefix}-results`);
    hide(`${this._cfg.prefix}-results-backdrop`);
    hide(`${this._cfg.prefix}-followup`);
    hide(`${this._cfg.prefix}-explanation`);
    hide(`btn-${this._cfg.prefix}-next`);
    setText(`${this._cfg.prefix}-progress`, "0/0");
    setText(`${this._cfg.prefix}-score`, "0");
    setText(`${this._cfg.prefix}-percent`, "0%");
    setText(`${this._cfg.prefix}-percent-bottom`, "0%");
    setText(`${this._cfg.prefix}-prompt`, "Tap Play Now to begin.");
    setHTML(`${this._cfg.prefix}-region-grid`, "");
    this._updateBodyMap({});
    setHTML(`${this._cfg.prefix}-followup-choices`, "");
    setText(`${this._cfg.prefix}-feedback`, "");
  }

  async startRound() {
    _setMiniGameStartLoading(this._cfg.prefix, true);
    setText(`${this._cfg.prefix}-feedback`, "Loading cases...");
    try {
      const data = await this._loadData();
      const cards = (data.vignettes || []).slice();
      for (let i = cards.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [cards[i], cards[j]] = [cards[j], cards[i]];
      }
      this._state = {
        deck: cards.slice(0, Math.min(cards.length, this._cfg.maxDeckSize || 6)),
        idx: 0,
        regionValues: {},
        correct: 0,
        total: 0,
        startTs: Date.now(),
        mistakeTags: [],
        hintCount: 0,
        hintedCases: new Set(),
        bsaSubmitted: false,
        bsaAttempts: 0,
      };
      hide(`${this._cfg.prefix}-intro-overlay`);
      hide(`${this._cfg.prefix}-results`);
      hide(`${this._cfg.prefix}-results-backdrop`);
      _setMiniGameStartLoading(this._cfg.prefix, false);
      this._renderCase();
    } catch {
      showToast("Could not load Rule of Nines cases.", "error");
      _setMiniGameStartLoading(this._cfg.prefix, false);
      setText(`${this._cfg.prefix}-feedback`, "");
    }
  }

  _currentCase() { return this._state.deck[this._state.idx]; }

  _selectedPercent() {
    return Object.values(this._state.regionValues || {}).reduce((sum, value) => sum + Number(value || 0), 0);
  }

  _expectedRegionValues(c) {
    const answerRegions = new Set(c?.answer_regions || []);
    const expected = {};
    (this._data?.regions || []).forEach(region => {
      expected[region.id] = answerRegions.has(region.id) ? Number(region.percent || 0) : 0;
    });
    return expected;
  }

  _allowedRegionValues() { return [0, 1, 9, 18]; }

  _regionValue(regionId) {
    return Number(this._state.regionValues?.[regionId] || 0);
  }

  _isBsaCorrect(c) {
    const expected = this._expectedRegionValues(c);
    return Object.entries(expected).every(([regionId, value]) => this._regionValue(regionId) === value);
  }

  _renderCase() {
    const c = this._currentCase();
    if (!c) return this._finish();
    this._state.regionValues = {};
    this._state.bsaSubmitted = false;
    this._state.bsaAttempts = 0;
    setText(`${this._cfg.prefix}-progress`, `${this._state.idx + 1}/${this._state.deck.length}`);
    setText(`${this._cfg.prefix}-score`, `${this._state.correct}/${Math.max(1, this._state.total || 0)}`);
    setText(`${this._cfg.prefix}-prompt`, c.prompt || "");
    setText(`${this._cfg.prefix}-percent`, "0%");
    setText(`${this._cfg.prefix}-percent-bottom`, "0%");
    setText(`${this._cfg.prefix}-feedback`, "Use +/- to mark each burned region as 0%, 1%, 9%, or 18%. Submit when the total looks right.");
    hide(`${this._cfg.prefix}-followup`);
    hide(`${this._cfg.prefix}-explanation`);
    hide(`btn-${this._cfg.prefix}-next`);
    el(`btn-${this._cfg.prefix}-submit-bsa`)?.removeAttribute("disabled");
    el(`btn-${this._cfg.prefix}-reset`)?.removeAttribute("disabled");
    _mgResetHint(this._cfg.prefix, c.hint || "", () => {
      const key = c.id || String(this._state.idx);
      if (!this._state.hintedCases.has(key)) {
        this._state.hintedCases.add(key);
        this._state.hintCount += 1;
      }
    });

    setHTML(`${this._cfg.prefix}-region-grid`, (this._data?.regions || []).map(r => `
      <div class="rule9-region-control" data-rule9-control="${escapeHTML(r.id)}">
        <div>
          <div class="rule9-region-label">${escapeHTML(r.label)}</div>
          <div class="rule9-region-help">Set burned area for this region</div>
        </div>
        <div class="rule9-stepper">
          <button type="button" data-rule9-step="${escapeHTML(r.id)}" data-delta="-1" aria-label="Decrease ${escapeHTML(r.label)}">−</button>
          <span class="rule9-value-pill" data-rule9-value="${escapeHTML(r.id)}">0%</span>
          <button type="button" data-rule9-step="${escapeHTML(r.id)}" data-delta="1" aria-label="Increase ${escapeHTML(r.label)}">+</button>
        </div>
      </div>
    `).join(""));
    this._el("region-grid")?.querySelectorAll("[data-rule9-step]").forEach(btn => {
      btn.addEventListener("click", () => this._stepRegion(btn.getAttribute("data-rule9-step"), Number(btn.getAttribute("data-delta")) || 0));
    });
    document.querySelectorAll("[data-rule9-region-shape]").forEach(shape => {
      shape.onclick = () => this._stepRegion(shape.getAttribute("data-rule9-region-shape"), 1);
    });
    this._updateBodyMap();
  }

  _stepRegion(regionId, delta) {
    if (!regionId || this._state.bsaSubmitted) return;
    const values = this._allowedRegionValues();
    const current = this._regionValue(regionId);
    const idx = Math.max(0, values.indexOf(current));
    const nextIdx = Math.min(values.length - 1, Math.max(0, idx + delta));
    this._state.regionValues[regionId] = values[nextIdx];
    this._updateBodyMap();
  }

  _updateBodyMap(values = this._state.regionValues || {}) {
    const percent = Object.values(values || {}).reduce((sum, value) => sum + Number(value || 0), 0);
    setText(`${this._cfg.prefix}-percent`, `${percent}%`);
    setText(`${this._cfg.prefix}-percent-bottom`, `${percent}%`);
    document.querySelectorAll("[data-rule9-region-shape]").forEach(shape => {
      const regionId = shape.getAttribute("data-rule9-region-shape");
      shape.classList.toggle("is-burned", Number(values?.[regionId] || 0) > 0);
    });
    this._el("region-grid")?.querySelectorAll("[data-rule9-control]").forEach(control => {
      const regionId = control.getAttribute("data-rule9-control");
      const value = Number(values?.[regionId] || 0);
      control.classList.toggle("is-burned", value > 0);
      const pill = control.querySelector("[data-rule9-value]");
      if (pill) pill.textContent = `${value}%`;
    });
  }

  resetSelection() {
    if (this._state.bsaSubmitted) return;
    this._state.regionValues = {};
    this._updateBodyMap();
    setText(`${this._cfg.prefix}-feedback`, "Selection cleared. Use the body map and +/- controls to estimate TBSA.");
  }

  submitBsa() {
    const c = this._currentCase();
    if (!c || this._state.bsaSubmitted) return;
    const bsaCorrect = this._isBsaCorrect(c);
    this._state.bsaAttempts += 1;
    if (!bsaCorrect) {
      if (c.mistake_tag) this._state.mistakeTags.push(c.mistake_tag);
      setText(`${this._cfg.prefix}-feedback`, "Not quite. Try again — adjust the burned regions or percentage values before submitting.");
      return;
    }
    this._state.total += 1;
    this._state.correct += 1;
    this._state.bsaSubmitted = true;
    el(`btn-${this._cfg.prefix}-submit-bsa`)?.setAttribute("disabled", "disabled");
    el(`btn-${this._cfg.prefix}-reset`)?.setAttribute("disabled", "disabled");
    this._el("region-grid")?.querySelectorAll("[data-rule9-step]").forEach(btn => { btn.disabled = true; });
    setText(`${this._cfg.prefix}-feedback`, `Correct BSA estimate: ${this._selectedPercent()}%.`);
    this._renderFollowup(c);
  }

  _renderFollowup(c) {
    const fu = c.follow_up || {};
    const choices = [fu.correct, ...(fu.distractors || [])].filter(Boolean);
    for (let i = choices.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [choices[i], choices[j]] = [choices[j], choices[i]];
    }
    setText(`${this._cfg.prefix}-followup-prompt`, fu.prompt || "What is the safest implication?");
    setHTML(`${this._cfg.prefix}-followup-choices`, choices.map(choice =>
      `<button type="button" class="mg-choice-btn" data-rule9-followup="${escapeHTML(choice)}">${escapeHTML(choice)}</button>`
    ).join(""));
    show(`${this._cfg.prefix}-followup`);
    this._el("followup-choices")?.querySelectorAll("[data-rule9-followup]").forEach(btn => {
      btn.addEventListener("click", () => this._submitFollowup(btn.getAttribute("data-rule9-followup")));
    });
  }

  _submitFollowup(choice) {
    const c = this._currentCase();
    if (!c || !choice) return;
    const correctChoice = c.follow_up?.correct || "";
    const correct = choice === correctChoice;
    this._state.total += 1;
    if (correct) this._state.correct += 1;
    else this._state.mistakeTags.push("missed_burn_implication");
    this._el("followup-choices")?.querySelectorAll("[data-rule9-followup]").forEach(btn => {
      btn.disabled = true;
      const value = btn.getAttribute("data-rule9-followup");
      btn.classList.toggle("mg-choice-correct", value === correctChoice);
      btn.classList.toggle("mg-choice-wrong", value === choice && !correct);
    });
    setText(`${this._cfg.prefix}-explanation`, c.follow_up?.explanation || c.explanation || "");
    show(`${this._cfg.prefix}-explanation`);
    show(`btn-${this._cfg.prefix}-next`);
    setText(`${this._cfg.prefix}-score`, `${this._state.correct}/${this._state.total}`);
  }

  advance() {
    hide(`btn-${this._cfg.prefix}-next`);
    this._state.idx += 1;
    this._renderCase();
  }

  async _finish() {
    const { total, correct, startTs, mistakeTags, hintCount } = this._state;
    const elapsedSec = Math.max(0, Math.round((Date.now() - startTs) / 1000));
    const score = total > 0 ? Math.round((correct / total) * 100) : 0;
    setText(`${this._cfg.prefix}-r-accuracy`, `${score}%`);
    setText(`${this._cfg.prefix}-r-correct`, `${correct}/${total}`);
    await _mgSubmitResult("rule_of_nines", { total, correct, bestStreak: 0, elapsedSec, mistakeTags: [...new Set(mistakeTags)], hintCount, sessionElapsedSec: _drillLapTimer.stop() }, "rule9-r-xp", "rule9-server-cap-note");
    show(`${this._cfg.prefix}-results-backdrop`);
    show(`${this._cfg.prefix}-results`);
  }
}

const _rule9Game = new BodyMapGame({
  prefix: "rule9",
  dataUrl: "/static/data/games/rule_of_nines/game.json",
  maxDeckSize: 6,
});

