/* ═══════════════════════════════════════════════════════════════════
   SCORED SEQUENCE GAME — shared full-order commit/reveal engine
   ═══════════════════════════════════════════════════════════════════ */
class SequenceOrderGame {
  constructor(cfg) {
    this._cfg = cfg;
    this._data = null;
    this._state = { deck: [], idx: 0, bank: [], order: [], correct: 0, total: 0, startTs: 0, mistakeTags: [], hintCount: 0, hintedCases: new Set(), submitted: false };
  }

  _el(suffix) { return el(`${this._cfg.prefix}-${suffix}`); }

  async _loadData() {
    if (this._data) return this._data;
    const res = await _fetchWithTimeout(this._cfg.dataUrl, {}, 2500);
    if (!res.ok) throw new Error(`${this._cfg.gameId} data unavailable`);
    this._data = await res.json();
    return this._data;
  }

  resetUi() {
    hide(`${this._cfg.prefix}-results`);
    hide(`${this._cfg.prefix}-results-backdrop`);
    hide(`${this._cfg.prefix}-reveal`);
    hide(`btn-${this._cfg.prefix}-next`);
    setText(`${this._cfg.prefix}-progress`, "0/0");
    setText(`${this._cfg.prefix}-score`, "0");
    setText(`${this._cfg.prefix}-prompt`, "Tap Play Now to begin.");
    setHTML(`${this._cfg.prefix}-bank`, "");
    setHTML(`${this._cfg.prefix}-order`, "");
    setHTML(`${this._cfg.prefix}-reveal`, "");
    setText(`${this._cfg.prefix}-feedback`, "");
  }

  async startRound() {
    _setMiniGameStartLoading(this._cfg.prefix, true);
    setText(`${this._cfg.prefix}-feedback`, "Loading cases...");
    try {
      const data = await this._loadData();
      const cases = (data.cases || []).slice();
      for (let i = cases.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [cases[i], cases[j]] = [cases[j], cases[i]];
      }
      this._state = {
        deck: cases.slice(0, Math.min(cases.length, this._cfg.maxDeckSize || 6)),
        idx: 0,
        bank: [],
        order: [],
        correct: 0,
        total: 0,
        startTs: Date.now(),
        mistakeTags: [],
        hintCount: 0,
        hintedCases: new Set(),
        submitted: false,
      };
      hide(`${this._cfg.prefix}-intro-overlay`);
      hide(`${this._cfg.prefix}-results`);
      hide(`${this._cfg.prefix}-results-backdrop`);
      _setMiniGameStartLoading(this._cfg.prefix, false);
      this._renderCase();
    } catch {
      showToast(`Could not load ${this._cfg.title || "sequence"} cases.`, "error");
      _setMiniGameStartLoading(this._cfg.prefix, false);
      setText(`${this._cfg.prefix}-feedback`, "");
    }
  }

  _currentCase() { return this._state.deck[this._state.idx]; }

  _shuffleSteps(steps) {
    const copy = steps.slice();
    for (let i = copy.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [copy[i], copy[j]] = [copy[j], copy[i]];
    }
    return copy;
  }

  _renderCase() {
    const c = this._currentCase();
    if (!c) return this._finish();
    this._state.bank = this._shuffleSteps(c.steps || []);
    this._state.order = [];
    this._state.submitted = false;
    setText(`${this._cfg.prefix}-progress`, `${this._state.idx + 1}/${this._state.deck.length}`);
    setText(`${this._cfg.prefix}-score`, `${this._state.correct}/${this._state.total || 0}`);
    setText(`${this._cfg.prefix}-prompt`, c.prompt || "");
    setText(`${this._cfg.prefix}-feedback`, "Build the full order, then submit. The answer is revealed only after you commit.");
    hide(`${this._cfg.prefix}-reveal`);
    hide(`btn-${this._cfg.prefix}-next`);
    _mgResetHint(this._cfg.prefix, c.hint || "", () => {
      const key = c.id || String(this._state.idx);
      if (!this._state.hintedCases.has(key)) {
        this._state.hintedCases.add(key);
        this._state.hintCount += 1;
      }
    });
    this._renderLists();
  }

  _renderLists() {
    const locked = this._state.submitted;
    setHTML(`${this._cfg.prefix}-bank`, this._state.bank.map(step => `
      <button type="button" class="mg-choice-btn text-left" data-seq-add="${escapeHTML(step.id)}" ${locked ? "disabled" : ""}>
        ${escapeHTML(step.label)}
      </button>
    `).join("") || `<p class="text-xs text-gray-500">All steps placed.</p>`);
    setHTML(`${this._cfg.prefix}-order`, this._state.order.map((step, i) => `
      <div class="rounded-lg border border-amber-800/50 bg-amber-950/20 p-2 flex items-center gap-2">
        <span class="text-xs font-bold text-amber-300 w-6">${i + 1}</span>
        <span class="flex-1 text-sm text-gray-100">${escapeHTML(step.label)}</span>
        <button type="button" class="text-xs text-gray-400 hover:text-white px-2" data-seq-up="${escapeHTML(step.id)}" ${locked || i === 0 ? "disabled" : ""}>↑</button>
        <button type="button" class="text-xs text-gray-400 hover:text-white px-2" data-seq-down="${escapeHTML(step.id)}" ${locked || i === this._state.order.length - 1 ? "disabled" : ""}>↓</button>
        <button type="button" class="text-xs text-red-300 hover:text-red-200 px-2" data-seq-remove="${escapeHTML(step.id)}" ${locked ? "disabled" : ""}>Remove</button>
      </div>
    `).join("") || `<p class="text-xs text-gray-500">Tap steps above to build your sequence.</p>`);
    this._el("bank")?.querySelectorAll("[data-seq-add]").forEach(btn => btn.addEventListener("click", () => this._addStep(btn.getAttribute("data-seq-add"))));
    this._el("order")?.querySelectorAll("[data-seq-remove]").forEach(btn => btn.addEventListener("click", () => this._removeStep(btn.getAttribute("data-seq-remove"))));
    this._el("order")?.querySelectorAll("[data-seq-up]").forEach(btn => btn.addEventListener("click", () => this._moveStep(btn.getAttribute("data-seq-up"), -1)));
    this._el("order")?.querySelectorAll("[data-seq-down]").forEach(btn => btn.addEventListener("click", () => this._moveStep(btn.getAttribute("data-seq-down"), 1)));
    const submit = el(`btn-${this._cfg.prefix}-submit`);
    if (submit) submit.disabled = locked || this._state.order.length !== (this._currentCase()?.steps || []).length;
  }

  _addStep(stepId) {
    if (this._state.submitted || !stepId) return;
    const idx = this._state.bank.findIndex(s => s.id === stepId);
    if (idx < 0) return;
    const [step] = this._state.bank.splice(idx, 1);
    this._state.order.push(step);
    this._renderLists();
  }

  _removeStep(stepId) {
    if (this._state.submitted || !stepId) return;
    const idx = this._state.order.findIndex(s => s.id === stepId);
    if (idx < 0) return;
    const [step] = this._state.order.splice(idx, 1);
    this._state.bank.push(step);
    this._renderLists();
  }

  _moveStep(stepId, delta) {
    if (this._state.submitted || !stepId) return;
    const idx = this._state.order.findIndex(s => s.id === stepId);
    const next = idx + delta;
    if (idx < 0 || next < 0 || next >= this._state.order.length) return;
    [this._state.order[idx], this._state.order[next]] = [this._state.order[next], this._state.order[idx]];
    this._renderLists();
  }

  submit() {
    const c = this._currentCase();
    if (!c || this._state.submitted) return;
    const expected = c.correct_order || [];
    if (this._state.order.length !== expected.length) {
      setText(`${this._cfg.prefix}-feedback`, "Place every step before submitting.");
      return;
    }
    this._state.submitted = true;
    let earned = 0;
    const actual = this._state.order.map(s => s.id);
    expected.forEach((id, idx) => { if (actual[idx] === id) earned += 1; });
    this._state.correct += earned;
    this._state.total += expected.length;
    if (earned < expected.length && c.mistake_tag) this._state.mistakeTags.push(c.mistake_tag);
    const stepById = new Map((c.steps || []).map(s => [s.id, s.label]));
    setHTML(`${this._cfg.prefix}-reveal`, `
      <h4 class="text-sm font-bold text-white mb-2">Sequence Reveal</h4>
      <div class="grid md:grid-cols-2 gap-3">
        <div>
          <p class="text-[10px] uppercase tracking-wide text-gray-500 mb-2">Your order</p>
          ${actual.map((id, idx) => `<div class="text-xs py-1 border-b border-gray-800 ${id === expected[idx] ? "text-green-300" : "text-red-300"}">${idx + 1}. ${escapeHTML(stepById.get(id) || id)}</div>`).join("")}
        </div>
        <div>
          <p class="text-[10px] uppercase tracking-wide text-gray-500 mb-2">Recommended order</p>
          ${expected.map((id, idx) => `<div class="text-xs py-1 border-b border-gray-800 text-blue-200">${idx + 1}. ${escapeHTML(stepById.get(id) || id)}</div>`).join("")}
        </div>
      </div>
      <p class="mt-3 text-sm text-gray-300">${escapeHTML(c.explanation || "")}</p>
    `);
    setText(`${this._cfg.prefix}-feedback`, `${earned}/${expected.length} steps in the recommended position.`);
    setText(`${this._cfg.prefix}-score`, `${this._state.correct}/${this._state.total}`);
    show(`${this._cfg.prefix}-reveal`);
    show(`btn-${this._cfg.prefix}-next`);
    this._renderLists();
  }

  advance() {
    hide(`btn-${this._cfg.prefix}-next`);
    this._state.idx += 1;
    this._renderCase();
  }

  async _finish() {
    const { total, correct, startTs, mistakeTags, hintCount } = this._state;
    const elapsedSec = Math.max(0, Math.round((Date.now() - startTs) / 1000));
    const score = total > 0 ? Math.round((correct / total) * 100) : 0;
    setText(`${this._cfg.prefix}-r-accuracy`, `${score}%`);
    setText(`${this._cfg.prefix}-r-correct`, `${correct}/${total}`);
    await _mgSubmitResult(this._cfg.gameId, { total, correct, bestStreak: 0, elapsedSec, mistakeTags: [...new Set(mistakeTags)], hintCount, sessionElapsedSec: _drillLapTimer.stop() }, `${this._cfg.prefix}-r-xp`, `${this._cfg.prefix}-server-cap-note`);
    show(`${this._cfg.prefix}-results-backdrop`);
    show(`${this._cfg.prefix}-results`);
    if (typeof this._cfg.onFinish === "function") {
      this._cfg.onFinish({ score, total, correct, elapsedSec });
    }
  }
}

function _makeSequenceGame(cfg) {
  const game = new SequenceOrderGame(cfg);
  return game;
}

