let _cprBlsConceptsGame = null;
let _cprBlsReturnDistrictId = null;
let _sessionReturnDistrictId = null;

function _makeCprBlsConceptsGame() {
  return new PairMatchGame({
    prefix: "cprconcepts",
    gameId: "cpr_bls_concepts",
    dataUrl: "/static/data/games/cpr_bls_concepts/game.json",
    loadError: "CPR Concepts data unavailable",
    toastError: "Could not load CPR Concepts data.",
    defaultRoundText: "MCQ",
    defaultProgressText: "0 / 5",
    forceActionMode: true,
    actionQuestionCount: 5,
    onFinish({ correct, total }) {
      const required = 4;
      const questionTotal = Math.max(5, Number(total) || 5);
      const passed = Number(correct) >= required;
      const playAgainBtn = el("btn-cprconcepts-play-again");
      const gateNote = el("cprconcepts-gate-note");

      if (playAgainBtn) playAgainBtn.textContent = passed ? "Play Again" : "Retry CPR Drill";
      if (gateNote) {
        gateNote.textContent = passed
          ? `CPR drill complete: ${correct}/${questionTotal} correct.`
          : `Score at least ${required}/${questionTotal} correct to complete the CPR drill.`;
        gateNote.classList.toggle("text-green-400", passed);
        gateNote.classList.toggle("text-amber-400", !passed);
      }
    },
  });
}

function _ensureCprBlsConceptsGame() {
  if (!_cprBlsConceptsGame || _cprBlsConceptsGame._cfg?.gameId !== "cpr_bls_concepts") {
    _cprBlsConceptsGame = _makeCprBlsConceptsGame();
  }
  return _cprBlsConceptsGame;
}

