/* ═══════════════════════════════════════════════════════════════════
   AMS AEIOUTIPS DIFFERENTIAL MAPPER — engine
   ═══════════════════════════════════════════════════════════════════ */
class PairMatchGame {
  constructor(cfg = {}) {
    this._cfg = {
      prefix: "aeiou",
      gameId: "ams_aeioutips",
      dataUrl: "/static/data/games/ams_aeioutips/game.json",
      loadError: "AMS game data unavailable",
      toastError: "Could not load game data.",
      defaultRoundText: "1 / 3",
      defaultProgressText: "0 / 3",
      resultMode: null,
      onFinish: null,
      ...cfg,
    };
    this._data         = null;
    this._state        = null;
    this._explainTimer = null;
  }

  _el(suffix) { return el(`${this._cfg.prefix}-${suffix}`); }
  _set(suffix, value) { setText(`${this._cfg.prefix}-${suffix}`, value); }
  _btn(suffix) { return el(`btn-${this._cfg.prefix}-${suffix}`); }

  async _loadData() {
    if (this._data) return this._data;
    const res = await _fetchWithTimeout(this._cfg.dataUrl, {}, 2500);
    if (!res.ok) throw new Error(this._cfg.loadError);
    this._data = await res.json();
    return this._data;
  }

	  async startRound() {
	    let data;
    _setMiniGameStartLoading(this._cfg.prefix, true);
    try {
      data = await this._loadData();
    } catch (e) {
      console.error("[PairMatchGame]", e);
      showToast(this._cfg.toastError, "error");
      _setMiniGameStartLoading(this._cfg.prefix, false);
      return;
    }
    if (!data?.pairs?.length) {
      showToast("Could not load game pairs.", "warning");
      _setMiniGameStartLoading(this._cfg.prefix, false);
      return;
    }
    let useActionCases = Boolean(data.action_cases?.length && this._cfg.forceActionMode);
    if (!useActionCases && data.action_cases?.length) {
      useActionCases = await _mgShouldUseAdaptiveMode(this._cfg.gameId);
    }
    if (useActionCases) {
      _setMiniGameStartLoading(this._cfg.prefix, false);
      this._startActionPriorityRound(data);
      return;
    }

    const shuffled = [...data.pairs].sort(() => Math.random() - 0.5);
    const rounds        = data.rounds || 3;
    const pairsPerRound = data.pairs_per_round || 3;
    const totalPairs    = rounds * pairsPerRound;

    this._state = {
      active:         true,
      mode:           "pair_match",
      rounds,
      pairsPerRound,
      totalPairs,
      roundIdx:       0,
      allPairs:       shuffled,
      roundNudges:    data.round_nudges || [],
      usedCount:      0,
      roundPairs:     [],
      roundCleared:   new Set(),
      sel1:           null,
      locked:         false,
      totalAttempts:  0,
      totalCleared:   0,
      firstTryCleared: 0,
      pairAttemptMap: {},
      mistakeTags:    [],
      hintCount:      0,
      hintedPairs:    new Set(),
      startTs:        Date.now(),
    };
    _setMiniGameStartLoading(this._cfg.prefix, false);

    this._el("results")?.classList.add("hidden");
    this._el("results-backdrop")?.classList.add("hidden");
    this._el("nudge-overlay")?.classList.add("hidden");
    this._btn("start")?.classList.add("hidden");
    this._el("explanation")?.classList.add("hidden");

    this._startCurrentRound();
  }

  _buildActionQuestionPool(data) {
    const defaultHint = "Focus on the AHA variables in the stem: patient age, rescuer count, airway status, rhythm/shock state, compression quality, and pause time.";
    const authored = Array.isArray(data.action_cases)
      ? data.action_cases.map((item, idx) => ({
          ...item,
          id: item.id || `action_${idx}`,
          hint: item.hint || defaultHint,
          mistake_tag: item.mistake_tag || "cpr_metric_confusion",
        }))
      : [];
    const pairCards = Array.isArray(data.pairs) ? data.pairs : [];
    const generated = pairCards.map((pair, idx) => {
      const correct = pair.category_label || "";
      if (!correct) return null;
      const distractors = pairCards
        .filter(p => p && p.id !== pair.id && p.category_label && p.category_label !== correct)
        .map(p => p.category_label);
      const choices = [correct, ...distractors]
        .filter((choice, i, arr) => choice && arr.indexOf(choice) === i)
        .slice(0, 4);
      if (choices.length < 2) return null;
      return {
        id: `generated_${pair.id || idx}`,
        presentation: `Which AHA CPR target matches this field situation?\n\n${pair.finding || ""}`,
        choices,
        correct,
        feedback: pair.explanation || "",
        hint: pair.hint || defaultHint,
        mistake_tag: pair.mistake_tag || "cpr_metric_confusion",
      };
    }).filter(Boolean);
    return [...authored, ...generated];
  }

  _startActionPriorityRound(data) {
    const pool = this._buildActionQuestionPool(data);
    const targetCount = Math.max(1, Number(this._cfg.actionQuestionCount || 6));
    const cases = [...pool].sort(() => Math.random() - 0.5).slice(0, Math.min(targetCount, pool.length));
    this._state = {
      active:         true,
      mode:           "ce_adaptive",
      deck:           cases,
      idx:            0,
      correct:        0,
      bestStreak:     0,
      streak:         0,
      mistakeTags:    [],
      hintCount:      0,
      hintedCases:    new Set(),
      answered:       false,
      startTs:        Date.now(),
    };
    this._el("results")?.classList.add("hidden");
    this._el("results-backdrop")?.classList.add("hidden");
    this._el("nudge-overlay")?.classList.add("hidden");
    this._btn("start")?.classList.add("hidden");
    this._btn("next-action")?.classList.add("hidden");
    this._renderActionCase();
  }

  _renderActionCase() {
    const card = this._state?.deck?.[this._state.idx];
    if (!card) { this._finishActionPriority(); return; }
    this._state.answered = false;
    this._set("round", "Adaptive");
    this._set("progress", `${this._state.idx + 1} / ${this._state.deck.length}`);
    this._set("score", `${this._state.correct}`);
    const grid = this._el("pair-grid");
    if (!grid) return;
    const choices = [card.correct, ...((card.choices || []).filter(c => c !== card.correct))].sort(() => Math.random() - 0.5);
    const labels = ["A", "B", "C", "D"];
    grid.innerHTML = `
      <article class="aeiou-action-case">
        <p class="aeiou-action-case-kicker">First priority</p>
        <h3>${escapeHTML(card.presentation || "")}</h3>
      </article>
      <div class="cprconcepts-mcq-answers">
        ${choices.map((choice, i) => `<button class="mg-tap-btn lexi-ans-btn cprconcepts-ans-btn text-left w-full border border-gray-700 text-sm rounded-xl px-4 py-3 transition-colors"
           data-choice="${escapeHTML(choice)}" type="button">
           <span class="lexi-ans-label font-bold mr-2">${labels[i]}.</span>${escapeHTML(choice)}
         </button>`).join("")}
      </div>
    `;
    grid.querySelectorAll(".mg-tap-btn").forEach(btn => {
      btn.addEventListener("click", () => this._submitActionPriority(btn.getAttribute("data-choice") || ""));
    });
    const ex = this._el("explanation");
    if (ex) {
      ex.textContent = "";
      ex.classList.add("hidden");
    }
    this._btn("next-action")?.classList.add("hidden");
    _mgResetHint(this._cfg.prefix, card.hint || "", () => {
      const key = card.id || `${this._state.idx}`;
      if (!this._state.hintedCases.has(key)) {
        this._state.hintedCases.add(key);
        this._state.hintCount += 1;
      }
    }, "explanation");
  }

  _submitActionPriority(choice = "") {
    if (!this._state?.active || this._state.answered || this._state.mode !== "ce_adaptive") return;
    const card = this._state.deck[this._state.idx];
    if (!card) return;
    this._state.answered = true;
    const correct = choice === card.correct;
    const grid = this._el("pair-grid");
    grid?.querySelectorAll(".mg-tap-btn").forEach(btn => {
      btn.disabled = true;
      const val = btn.getAttribute("data-choice") || "";
      if (val === card.correct) btn.classList.add("is-correct");
      if (val === choice && !correct) btn.classList.add("is-wrong");
    });
    if (correct) {
      this._state.correct += 1;
      this._state.streak += 1;
      this._state.bestStreak = Math.max(this._state.bestStreak, this._state.streak);
    } else {
      this._state.streak = 0;
      if (card.mistake_tag) this._state.mistakeTags.push(card.mistake_tag);
    }
    const ex = this._el("explanation");
    if (ex) {
      ex.textContent = correct ? `Correct. ${card.feedback || ""}` : `${card.correct} — ${card.feedback || ""}`;
      ex.classList.remove("hidden");
    }
    this._set("score", `${this._state.correct}`);
    const nextBtn = this._btn("next-action");
    if (nextBtn) {
      nextBtn.textContent = this._state.idx >= this._state.deck.length - 1 ? "Show Results →" : "Next Question →";
      nextBtn.classList.remove("hidden");
      nextBtn.onclick = () => this._advanceActionPriority();
    }
  }

  _advanceActionPriority() {
    if (!this._state?.active || this._state.mode !== "ce_adaptive" || !this._state.answered) return;
    this._btn("next-action")?.classList.add("hidden");
    this._state.idx += 1;
    this._renderActionCase();
  }

  async _finishActionPriority() {
    this._state.active = false;
    const total = Math.max(1, this._state.deck.length);
    const correct = this._state.correct;
    const score = Math.round((correct / total) * 100);
    const elapsedSec = Math.round((Date.now() - this._state.startTs) / 1000);
    this._set("r-score", `${score}%`);
    this._set("r-correct", `${correct}/${total}`);
    this._set("r-xp", "+0");
    this._set("gate-note", "");
    this._set("server-cap-note", "Saving results…");
    this._el("results-backdrop")?.classList.remove("hidden");
    this._el("results")?.classList.remove("hidden");
    this._btn("start")?.classList.remove("hidden");
    this._btn("next-action")?.classList.add("hidden");
    await _mgSubmitResult(this._cfg.gameId,
      { total, correct, bestStreak: this._state.bestStreak, elapsedSec,
        mistakeTags: [...new Set(this._state.mistakeTags)], hintCount: this._state.hintCount || 0, mode: "ce_adaptive", sessionElapsedSec: _drillLapTimer.stop() },
      `${this._cfg.prefix}-r-xp`, `${this._cfg.prefix}-server-cap-note`);
    if (typeof this._cfg.onFinish === "function") {
      this._cfg.onFinish({ score, total, correct, elapsedSec, mode: "ce_adaptive" });
    }
  }

  _startCurrentRound() {
    const { allPairs, usedCount, pairsPerRound, roundIdx, rounds } = this._state;
    const roundPairs = allPairs.slice(usedCount, usedCount + pairsPerRound);
    this._state.usedCount  += pairsPerRound;
    this._state.roundPairs  = roundPairs;
    this._state.roundCleared = new Set();
    this._state.sel1        = null;
    this._state.locked      = false;

    this._set("round",    `${roundIdx + 1} / ${rounds}`);
    this._set("progress", `0 / ${pairsPerRound}`);
    this._set("score",    "—");

    this._renderGrid(roundPairs);
    this._refreshHint();
  }

  _currentHintPair() {
    if (!this._state) return null;
    const selectedPairId = this._state.sel1?.pairId;
    if (selectedPairId) return this._state.roundPairs.find(p => p.id === selectedPairId) || null;
    return this._state.roundPairs.find(p => !this._state.roundCleared.has(p.id)) || null;
  }

  _refreshHint() {
    const pair = this._currentHintPair();
    _mgResetHint(this._cfg.prefix, pair?.hint || "", () => {
      const key = pair?.id || `round_${this._state?.roundIdx || 0}`;
      if (!this._state.hintedPairs.has(key)) {
        this._state.hintedPairs.add(key);
        this._state.hintCount += 1;
      }
    }, "explanation");
  }

  _renderGrid(pairs) {
    const grid = this._el("pair-grid");
    if (!grid) return;

    const cards = [];
    for (const pair of pairs) {
      cards.push({ id: `cat_${pair.id}`, type: "category", pair_id: pair.id,
                   letter: pair.category_letter, label: pair.category_label });
      cards.push({ id: `fnd_${pair.id}`, type: "finding",  pair_id: pair.id,
                   text: pair.finding });
    }
    for (let i = cards.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [cards[i], cards[j]] = [cards[j], cards[i]];
    }

    grid.innerHTML = cards.map(c => {
      if (c.type === "category") {
        return `<button class="aeiou-pair-card aeiou-pair-card--category"
                  data-card-id="${escapeHTML(c.id)}" data-pair-id="${escapeHTML(c.pair_id)}"
                  data-card-type="category" type="button">
                  <span class="aeiou-pair-letter">${escapeHTML(c.letter)}</span>
                  <span class="aeiou-pair-text">${escapeHTML(c.label)}</span>
                </button>`;
      }
      return `<button class="aeiou-pair-card aeiou-pair-card--finding"
                data-card-id="${escapeHTML(c.id)}" data-pair-id="${escapeHTML(c.pair_id)}"
                data-card-type="finding" type="button">
                <span class="aeiou-pair-text">${escapeHTML(c.text)}</span>
              </button>`;
    }).join("");

    grid.querySelectorAll(".aeiou-pair-card").forEach(btn => {
      btn.addEventListener("click", () => this._onTap(btn));
    });
  }

  _onTap(btn) {
    if (!this._state?.active || this._state.locked) return;
    if (btn.dataset.cleared) return;

    const { cardId, pairId, cardType } = {
      cardId:   btn.dataset.cardId,
      pairId:   btn.dataset.pairId,
      cardType: btn.dataset.cardType,
    };

    if (!this._state.sel1) {
      this._state.sel1 = { cardId, pairId, cardType, btn };
      btn.classList.add("is-selected");
      this._refreshHint();
      return;
    }

    const s1 = this._state.sel1;
    this._state.sel1 = null;

    if (cardId === s1.cardId) {
      s1.btn.classList.remove("is-selected");
      this._refreshHint();
      return;
    }

    this._state.locked = true;
    this._state.totalAttempts++;

    const isMatch = s1.pairId === pairId && s1.cardType !== cardType;

    if (isMatch) {
      const prevAttempts = this._state.pairAttemptMap[pairId] || 0;
      this._state.pairAttemptMap[pairId] = prevAttempts + 1;

      s1.btn.classList.remove("is-selected");
      s1.btn.classList.add("is-matched");
      btn.classList.add("is-matched");

      setTimeout(() => {
        s1.btn.dataset.cleared = "1";
        btn.dataset.cleared    = "1";

        if (prevAttempts === 0) this._state.firstTryCleared++;
        this._state.totalCleared++;
        this._state.roundCleared.add(pairId);

        const pair = this._state.roundPairs.find(p => p.id === pairId);
        if (pair?.explanation) this._showExplanation(pair.explanation);

        const cleared = this._state.roundCleared.size;
        this._set("progress", `${cleared} / ${this._state.pairsPerRound}`);
        const sc = Math.round(this._state.totalCleared / this._state.totalAttempts * 100);
        this._set("score", `${sc}%`);

        if (cleared >= this._state.pairsPerRound) {
          setTimeout(() => this._onRoundComplete(), 600);
        } else {
          this._state.locked = false;
          this._refreshHint();
        }
      }, 450);

    } else {
      // Mismatch — emit letter-based mistake tags when a category card was involved
      const catCard = s1.cardType === "category" ? s1 : (cardType === "category" ? { cardId, pairId, cardType, btn } : null);
      const fndCard = s1.cardType === "finding"  ? s1 : (cardType === "finding"  ? { cardId, pairId, cardType, btn } : null);

      if (catCard && fndCard) {
        const correctPair   = this._state.roundPairs.find(p => p.id === fndCard.pairId);
        const wrongCatPair  = this._state.roundPairs.find(p => p.id === catCard.pairId);
        if (correctPair)  this._state.mistakeTags.push(`missed_${correctPair.category_letter}`);
        if (wrongCatPair) this._state.mistakeTags.push(`false_positive_${wrongCatPair.category_letter}`);
      } else {
        // Two cards of the same type (cat+cat or finding+finding) — no letter signal available
        this._state.mistakeTags.push("invalid_pair_selection");
      }
      if (fndCard) {
        const fp = fndCard.pairId;
        this._state.pairAttemptMap[fp] = (this._state.pairAttemptMap[fp] || 0) + 1;
      }

      s1.btn.classList.remove("is-selected");
      s1.btn.classList.add("is-wrong");
      btn.classList.add("is-wrong");

      setTimeout(() => {
        s1.btn.classList.remove("is-wrong");
        btn.classList.remove("is-wrong");
        this._state.locked = false;
        this._refreshHint();
      }, 1000);
    }
  }

  _showExplanation(text) {
    clearTimeout(this._explainTimer);
    const exEl = this._el("explanation");
    if (!exEl) return;
    exEl.textContent = text;
    exEl.classList.remove("hidden");
    this._explainTimer = setTimeout(() => exEl.classList.add("hidden"), 4000);
  }

  _onRoundComplete() {
    const { roundIdx, rounds, roundNudges } = this._state;
    if (roundIdx < rounds - 1) {
      const nudge = roundNudges[roundIdx];
      if (nudge) {
        this._set("nudge-prompt", nudge.prompt);
        this._set("nudge-text",   nudge.text);
        this._el("nudge-overlay")?.classList.remove("hidden");
      } else {
        this._advanceRound();
      }
    } else {
      this._finish();
    }
  }

  continueRound() {
    this._el("nudge-overlay")?.classList.add("hidden");
    this._advanceRound();
  }

  _advanceRound() {
    this._state.roundIdx++;
    this._state.active = true;
    this._startCurrentRound();
  }

  async _finish() {
    this._state.active = false;
    const { totalAttempts, totalCleared, firstTryCleared, totalPairs, startTs, mistakeTags, hintCount } = this._state;
    const score      = totalAttempts > 0 ? Math.round(totalCleared / totalAttempts * 100) : 100;
    const elapsedSec = Math.round((Date.now() - startTs) / 1000);

    this._set("r-score",   `${score}%`);
    this._set("r-correct", `${firstTryCleared}/${totalPairs}`);
    this._set("r-xp",      "+0");
    this._set("server-cap-note", "Saving results…");

    this._el("results-backdrop")?.classList.remove("hidden");
    this._el("results")?.classList.remove("hidden");
    this._btn("start")?.classList.remove("hidden");

    const payload = { total: totalAttempts, correct: totalCleared, bestStreak: firstTryCleared, elapsedSec,
      mistakeTags: [...new Set(mistakeTags)], hintCount, sessionElapsedSec: _drillLapTimer.stop() };
    if (this._cfg.resultMode) payload.mode = this._cfg.resultMode;
    await _mgSubmitResult(this._cfg.gameId, payload, `${this._cfg.prefix}-r-xp`, `${this._cfg.prefix}-server-cap-note`);
    if (typeof this._cfg.onFinish === "function") {
      this._cfg.onFinish({ score, totalAttempts, totalCleared, firstTryCleared, totalPairs, elapsedSec });
    }
  }

  resetUi() {
    this._state = null;
    clearTimeout(this._explainTimer);
    const grid = this._el("pair-grid");
    if (grid) grid.innerHTML = "";
    this._set("round",    this._cfg.defaultRoundText);
    this._set("progress", this._cfg.defaultProgressText);
    this._set("score",    "—");
    this._el("explanation")?.classList.add("hidden");
    _mgResetHint(this._cfg.prefix, "", null, "explanation");
    this._el("nudge-overlay")?.classList.add("hidden");
    this._el("results")?.classList.add("hidden");
    this._el("results-backdrop")?.classList.add("hidden");
    this._btn("start")?.classList.remove("hidden");
  }

  stop() { if (this._state) this._state.active = false; }
}

