let _mapDragMoved = false;
let _categoryMapDragBound = false;
let _categoryMapDragMoved = false;
let _categoryMapSuppressClickUntil = 0;

function _initDistrictMapPan(container) {
  const svg = container.querySelector('#hv2-district-map');
  if (!svg) return;

  let isDown = false, startX = 0, startY = 0, downX = 0, downY = 0, tx = 0, ty = 0;
  let maxX = 0, maxY = 0;

  const sizeMapToViewport = () => {
    const cw = container.clientWidth || 1;
    const ch = container.clientHeight || 1;
    const mapRatio = 800 / 500;
    const containerRatio = cw / ch;

    let width, height;
    if (containerRatio > mapRatio) {
      width = cw;
      height = cw / mapRatio;
    } else {
      height = ch;
      width = ch * mapRatio;
    }

    svg.style.width = `${Math.ceil(width)}px`;
    svg.style.height = `${Math.ceil(height)}px`;
    maxX = Math.max(0, (width - cw) / 2);
    maxY = Math.max(0, (height - ch) / 2);
    clamp();
    apply();
  };

  const clamp = () => {
    tx = Math.min(maxX, Math.max(-maxX, tx));
    ty = Math.min(maxY, Math.max(-maxY, ty));
  };

  const apply = () => { svg.style.transform = `translate(${tx}px,${ty}px)`; };

  sizeMapToViewport();
  new ResizeObserver(sizeMapToViewport).observe(container);

  container.addEventListener('mousedown', e => {
    _mapDragMoved = false;
    isDown = true;
    downX = e.clientX; downY = e.clientY;
    startX = e.clientX - tx; startY = e.clientY - ty;
  });

  window.addEventListener('mousemove', e => {
    if (!isDown) return;
    if (!_mapDragMoved && Math.hypot(e.clientX - downX, e.clientY - downY) > 4) {
      _mapDragMoved = true;
      container.classList.add('dragging');
    }
    if (_mapDragMoved) {
      tx = e.clientX - startX; ty = e.clientY - startY;
      clamp(); apply();
    }
  });

  window.addEventListener('mouseup', () => {
    isDown = false;
    container.classList.remove('dragging');
  });

  // Touch support
  let touchStartX = 0, touchStartY = 0;
  container.addEventListener('touchstart', e => {
    _mapDragMoved = false;
    const t = e.touches[0];
    touchStartX = t.clientX; touchStartY = t.clientY;
    startX = t.clientX - tx; startY = t.clientY - ty;
  }, { passive: true });

  container.addEventListener('touchmove', e => {
    const t = e.touches[0];
    if (!_mapDragMoved && Math.hypot(t.clientX - touchStartX, t.clientY - touchStartY) > 4)
      _mapDragMoved = true;
    if (_mapDragMoved) {
      tx = t.clientX - startX; ty = t.clientY - startY;
      clamp(); apply();
      e.preventDefault();
    }
  }, { passive: false });
}

function _initCategoryMapDragPan() {
  const pane = el("category-district-view");
  if (!pane || _categoryMapDragBound) return;
  _categoryMapDragBound = true;

  let isDown = false;
  let pointerId = null;
  let downX = 0;
  let downY = 0;
  let startScrollLeft = 0;
  let startScrollTop = 0;

  const isInteractiveMapTarget = (target) => Boolean(target?.closest?.(
    "button, a, input, textarea, select, [role='button'], [data-peds-scenario], [data-peds-game], [data-peds-shop], [data-s1-node], [data-s1-scenario], [data-s1-cpr], [data-category-map-nav], [data-station1-step]"
  ));

  const stopDrag = () => {
    if (_categoryMapDragMoved) _categoryMapSuppressClickUntil = Date.now() + 250;
    isDown = false;
    pointerId = null;
    pane.classList.remove("dragging");
    window.setTimeout(() => { _categoryMapDragMoved = false; }, 250);
    window.setTimeout(() => { _mapDragMoved = false; }, 0);
  };

  pane.addEventListener("pointerdown", (e) => {
    if (e.button !== undefined && e.button !== 0) return;
    if (isInteractiveMapTarget(e.target)) {
      _categoryMapDragMoved = false;
      _mapDragMoved = false;
      return;
    }
    isDown = true;
    pointerId = e.pointerId;
    downX = e.clientX;
    downY = e.clientY;
    startScrollLeft = pane.scrollLeft;
    startScrollTop = pane.scrollTop;
    _categoryMapDragMoved = false;
    _mapDragMoved = false;
    try { pane.setPointerCapture(e.pointerId); } catch {}
  });

  pane.addEventListener("pointermove", (e) => {
    if (!isDown || (pointerId !== null && e.pointerId !== pointerId)) return;
    const dx = e.clientX - downX;
    const dy = e.clientY - downY;
    if (!_categoryMapDragMoved && Math.hypot(dx, dy) > 4) {
      _categoryMapDragMoved = true;
      _mapDragMoved = true;
      pane.classList.add("dragging");
    }
    if (_categoryMapDragMoved) {
      pane.scrollLeft = startScrollLeft - dx;
      pane.scrollTop = startScrollTop - dy;
      e.preventDefault();
    }
  });

  pane.addEventListener("pointerup", stopDrag);
  pane.addEventListener("pointercancel", stopDrag);
  pane.addEventListener("click", (e) => {
    if (!_categoryMapDragMoved && Date.now() > _categoryMapSuppressClickUntil) return;
    e.preventDefault();
    e.stopPropagation();
  }, true);
}

function _genDistrictMapSVG(history) {
  const defs = `<defs>
    <pattern id="hv2-city-grid" width="28" height="28" patternUnits="userSpaceOnUse">
      <path d="M 28 0 L 0 0 0 28" fill="none" stroke="white" stroke-width="0.5"/>
    </pattern>
  </defs>`;

  const stationComplete = _station1IsComplete(_station1RequirementsState(history));

  // Render station circle nodes. Station 1 is active; future stations are locked markers.
  const homeNodeSvg = ADVENTURE_DISTRICTS.filter(d => d.mapNode).map(d => {
    const { x, y } = d.mapNode;
    const done = d.id === "station_1" && stationComplete;
    const active = d.status === "active";
    const nodeLabel = d.mapNode.label || d.title;
    const statusText = done ? "✓ Cleared" : d.mapNode.plannedText || (active ? "Start here" : "Planned");
    return `<g class="hv2-dz hv2-home-node${done ? " done" : ""}${active ? "" : " locked"}" data-district="${d.id}"${active ? ' role="button" tabindex="0"' : ""} aria-label="${escapeHTML(d.title)}">
      <circle cx="${x}" cy="${y}" r="38" class="hv2-station-node-mask"/>
      <circle cx="${x}" cy="${y}" r="36" class="hv2-dz-color" style="fill:none;stroke-width:2;opacity:0.8;"/>
      <text x="${x}" y="${y - 6}" class="hv2-dz-icon" text-anchor="middle" font-size="18">${d.icon}</text>
      <text x="${x}" y="${y + 10}" class="hv2-dz-name" text-anchor="middle" font-size="8">${escapeHTML(nodeLabel)}</text>
      <text x="${x}" y="${y + 22}" class="${done ? "hv2-dz-prog" : "hv2-dz-planned"}" text-anchor="middle" font-size="7">${escapeHTML(statusText)}</text>
    </g>`;
  }).join("\n");

  const zones = ADVENTURE_DISTRICTS.filter(d => d.mapZone).map(d => {
    const progress  = _districtProgress(d.id);
    const pct       = progress.pct;
    const prereqMet = !d.prereq || stationComplete;
    const active    = d.status === "active" && prereqMet;
    const { points, lx, ly, label, rot } = d.mapZone;
    const halfH     = ((label.length - 1) * 14) / 2;

    const nameLines = label.map((ln, i) =>
      `<tspan x="${lx}" dy="${i === 0 ? 0 : 14}">${escapeHTML(ln)}</tspan>`
    ).join("");

    const nameEl = rot !== undefined
      ? `<text x="${lx}" y="${ly}" class="hv2-dz-name" text-anchor="middle" transform="rotate(${rot} ${lx} ${ly})">${escapeHTML(label[0])}</text>`
      : `<text x="${lx}" y="${ly - halfH}" class="hv2-dz-name" text-anchor="middle">${nameLines}</text>`;

    const progEl = rot !== undefined ? "" : active
      ? `<text x="${lx}" y="${ly + halfH + 14}" class="hv2-dz-prog" text-anchor="middle">${pct}% covered</text>`
      : d.prereq && !prereqMet
        ? `<text x="${lx}" y="${ly + halfH + 14}" class="hv2-dz-planned" text-anchor="middle">🔒 Complete Station 1</text>`
        : `<text x="${lx}" y="${ly + halfH + 14}" class="hv2-dz-planned" text-anchor="middle">Planned</text>`;

    const iconEl = rot !== undefined ? ""
      : `<text x="${lx}" y="${ly - halfH - 8}" class="hv2-dz-icon" text-anchor="middle">${d.icon}</text>`;

    return `<g class="hv2-dz${active ? "" : " locked"}" data-district="${d.id}"${active ? ' role="button" tabindex="0"' : ''} aria-label="${escapeHTML(d.title)}">
      <polygon points="${points}" class="hv2-dz-base"/>
      <polygon points="${points}" class="hv2-dz-grid"/>
      <polygon points="${points}" class="hv2-dz-color"/>
      ${iconEl}
      ${nameEl}
      ${progEl}
    </g>`;
  }).join("\n");

  const stationNode = ADVENTURE_DISTRICTS.find(d => d.id === "station_1")?.mapNode || { x: 295, y: 165 };
  const stationRadius = 36;
  const stationLeft = stationNode.x - stationRadius;
  const stationRight = stationNode.x + stationRadius;
  const stationBottom = stationNode.y + stationRadius;

  const roads = `<g class="hv2-roads" pointer-events="none">
    <line x1="0" y1="165" x2="${stationLeft}" y2="165"/>
    <line x1="${stationRight}" y1="165" x2="800" y2="165"/>
    <line x1="0" y1="400" x2="800" y2="400"/>
    <line x1="185" y1="0" x2="190" y2="165"/>
    <line x1="590" y1="0" x2="595" y2="165"/>
    <line x1="88" y1="165" x2="90" y2="400"/>
    <line x1="${stationNode.x}" y1="${stationBottom}" x2="295" y2="400"/>
    <line x1="638" y1="165" x2="640" y2="400"/>
    <line x1="468" y1="400" x2="470" y2="500"/>
  </g>`;

  const mapImg = `<image href="/static/img/district-map-1600.jpg" x="0" y="0" width="800" height="500" preserveAspectRatio="xMidYMid meet" opacity="0.45"/>`;
  return `<svg id="hv2-district-map" viewBox="0 0 800 500" class="hv2-district-map" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid meet">${defs}${mapImg}${zones}${roads}${homeNodeSvg}</svg>`;
}

function buildMenu() {
  const game = loadGamification();
  setText("menu-student-name", `Welcome, ${state.firstName || state.studentName}`);

  // Provider level, MCA, and agency badges — driven by decoded JWT state
  const levelDisplay = LEVEL_DISPLAY[state.providerLevel] || state.providerLevel || "EMT-Basic (BLS)";
  const mcaDisplay   = MCA_DISPLAY[state.mca]             || state.mca           || "WMRMCC";
  const agencyDisplay = state._isSuper ? "Global Superuser" : (state.agency || "");
  setText("menu-provider-badge", levelDisplay);
  setText("menu-mca-badge",      mcaDisplay);
  const agencyBadge = el("menu-agency-badge");
  if (agencyBadge) {
    if (agencyDisplay) { agencyBadge.textContent = agencyDisplay; agencyBadge.classList.remove("hidden"); }
    else               { agencyBadge.classList.add("hidden"); }
  }

  // Switch Agency button visibility
  const switchBtn = el("btn-switch-agency");
  if (switchBtn) {
    if (!state.scormEnabled && (state._membershipCount ?? 1) > 1) switchBtn.classList.remove("hidden");
    else                                                          switchBtn.classList.add("hidden");
  }

  const level = getCurrentLevel(game.xp);
  const nextLevel = getNextLevel(game.xp);
  setText("menu-level-name", `${level.icon} ${level.name}`);
  setText("menu-xp-text", nextLevel ? `${game.xp} / ${nextLevel.xp} XP` : `${game.xp} XP — MAX`);
  const pct = nextLevel ? Math.min(100, ((game.xp - level.xp) / (nextLevel.xp - level.xp)) * 100) : 100;
  el("menu-xp-fill").style.width = pct + "%";
  setText("map-xp-level", `${level.icon} ${level.name}`);
  setText("map-xp-text", nextLevel ? `${game.xp} / ${nextLevel.xp} XP` : `${game.xp} XP — MAX`);
  const mapXpFill = el("map-xp-fill");
  if (mapXpFill) mapXpFill.style.width = pct + "%";

  setText("menu-treat-count", `🦴 ${game.treats ?? 0} treats`);
  const cachedLeaderboard = _readLeaderboardModalCache();
  if (cachedLeaderboard?.rank_summary) {
    _menuRankCache = {
      agencyId: state.agency_id,
      data: cachedLeaderboard.rank_summary,
      fetchedAt: Date.now(),
      loading: false,
    };
  }
  _renderMenuRank(
    _menuRankCache.agencyId === state.agency_id ? _menuRankCache.data : null
  );
  _loadMenuRankSummary();

  startLexiMenu(state.firstName || state.studentName, game);
  
  _updateLoginStreak();
  _renderRightHistory();
  _renderRightCurrentMap();

  // Set nav avatar initial
  const ava = el("hv2-nav-ava");
  if (ava) ava.textContent = (state.firstName || state.studentName || "?")[0].toUpperCase();

  const container = el("menu-categories");
  const history = loadHistory().filter(h => !h.agencyId || h.agencyId === state.agency_id);
  container.innerHTML = _genDistrictMapSVG(history);

  container.querySelectorAll(".hv2-dz[data-district]").forEach(zone => {
    zone.addEventListener("click", () => {
      if (_mapDragMoved) return;
      const district = zone.getAttribute("data-district");
      const districtDef = ADVENTURE_DISTRICTS.find(d => d.id === district);
      if (districtDef?.prereq === "station_1" && !_station1IsComplete()) {
        showToast("Complete Station 1 orientation first — tap the firehouse marker.", "info");
        return;
      }
      if (zone.classList.contains("locked")) return;
      if (district === "pediatrics") {
        _pedsJourneyState.selectedMedicalTrail = 1;
        _pedsJourneyState.selectedTraumaTrail = 1;
      }
      if (district) showCategoryScreen(district);
    });
    zone.addEventListener("keydown", e => {
      if (e.key === "Enter" || e.key === " ") { e.preventDefault(); zone.click(); }
    });
  });

  _initDistrictMapPan(container);

  buildBadgesSection(game);
  _buildChallengesSection();
  // Refresh challenge cache in background so active challenges always surface if available.
  _loadChallenges().then(() => {
    _buildChallengesSection();
    buildBadgesSection(game);
  });
  _loadLexiStatus();
  _loadDrillStatus();
  _loadRcStatus();
  _updateRandomDrillCard();
  _updateRandomCallCard();
  // Show XP action row (Badges / Toy Chest / Leaderboard) — leaderboard only when in agency
  const xpRow = el("xp-action-row");
  const lbBtn = el("btn-open-leaderboard");
  if (xpRow) xpRow.classList.remove("hidden");
  if (lbBtn) {
    if (state.agency_id && !state._isSuper) lbBtn.classList.remove("hidden");
    else lbBtn.classList.add("hidden");
  }
  // Initialize tour for first-time users (students only)
  const isPrivilegedUser = state._role === "admin" || state._role === "instructor" || state._isSuper;
  _syncDashboardMobileVisibility();
  _applyScormSaasUiTrim();
  if (!isPrivilegedUser) _initTour();
}

function _refreshGamificationChrome() {
  const game = loadGamification();
  const level = getCurrentLevel(game.xp);
  const nextLevel = getNextLevel(game.xp);
  const xpText = nextLevel ? `${game.xp} / ${nextLevel.xp} XP` : `${game.xp} XP — MAX`;
  const pct = nextLevel ? Math.min(100, ((game.xp - level.xp) / (nextLevel.xp - level.xp)) * 100) : 100;
  setText("menu-level-name", `${level.icon} ${level.name}`);
  setText("menu-xp-text", xpText);
  setText("map-xp-level", `${level.icon} ${level.name}`);
  setText("map-xp-text", xpText);
  const menuXpFill = el("menu-xp-fill");
  if (menuXpFill) menuXpFill.style.width = pct + "%";
  const mapXpFill = el("map-xp-fill");
  if (mapXpFill) mapXpFill.style.width = pct + "%";
  setText("menu-treat-count", `🦴 ${game.treats ?? 0} treats`);
  setText("category-treat-count", `🦴 ${game.treats ?? 0} treats`);
}

function _updateLoginStreak() {
  const lastDate = localStorage.getItem("pfd_last_login_date");
  let streak = parseInt(localStorage.getItem("pfd_login_streak") || "0", 10);
  const today = new Date().toDateString();

  if (lastDate !== today) {
    const yesterday = new Date();
    yesterday.setDate(yesterday.getDate() - 1);
    if (lastDate === yesterday.toDateString()) {
      streak += 1;
    } else if (lastDate) {
      streak = 1;
    } else {
      streak = 1;
    }
    localStorage.setItem("pfd_last_login_date", today);
    localStorage.setItem("pfd_login_streak", streak.toString());
  }
  
  const streakEl = el("hv2-streak-label");
  if (streakEl) streakEl.textContent = `${streak} Day Streak`;
}

function _renderRightHistory() {
  const listEl = el("right-history-list");
  if (!listEl) return;
  const moreBtn = el("btn-right-more-calls");
  const maxVisible = 5;
  const allHistory = loadHistory().filter(h => !h.agencyId || h.agencyId === state.agency_id);
  const history = allHistory.slice(0, maxVisible);
  if (moreBtn) moreBtn.classList.toggle("hidden", allHistory.length <= history.length);
  if (!history.length) {
    listEl.innerHTML = '<p class="text-gray-500 text-xs">No recent calls.</p>';
    return;
  }
  listEl.innerHTML = history.map(h => {
    const isPass = (_assessmentPctFromEntry(h) ?? 0) >= 70 && !h.criticalFailure;
    const resClass = isPass ? "hv2-result-pass" : "hv2-result-fail";
    const resText = isPass ? "PASS" : "REVIEW";
    const date = new Date(h.date).toLocaleDateString(undefined, {month:'short', day:'numeric'});
    return `<div class="hv2-call-item cursor-pointer hover:bg-white/5 transition-colors rounded px-2 -mx-2" data-history-debrief-key="${escapeHTML(String(h.key))}">
        <div class="hv2-call-accent ${isPass ? 'bg-green-500' : 'bg-red-500'}"></div>
        <div class="hv2-call-info">
            <div class="hv2-call-name">${escapeHTML(h.title)}</div>
            <div class="hv2-call-meta">
                <span class="hv2-call-tag">${escapeHTML(h.providerLevel)}</span>
                <span class="hv2-call-when">${date}</span>
            </div>
        </div>
        <div class="hv2-call-result ${resClass}">${resText}</div>
    </div>`;
  }).join("");
}

function _openHistoryScreen(returnTarget = "menu") {
  _historyReturnTarget = returnTarget || "menu";
  buildHistoryPage();
  showScreen("history");
}

el("btn-right-more-calls")?.addEventListener("click", () => _openHistoryScreen("menu"));

function _renderRightCurrentMap() {
  _renderRightDistrictList();
}

function _syncCategoryShell(districtId = null) {
  const districtDef = ADVENTURE_DISTRICTS.find(d => d.id === districtId);
  const mapDef = districtId === "pediatrics"
    ? (_PEDS_MAP_BY_ID.get(_pedsJourneyState.currentMap || "map_0") || null)
    : null;
  const categoryLabel = districtId === "pediatrics"
    ? "Pediatrics"
    : (districtId === "other" ? "Training Center" : (districtDef?.title || "Map"));
  const label = mapDef?.label || districtDef?.title || el("category-screen-title")?.textContent || "Map";
  const sub = mapDef?.theme || districtDef?.subtitle || districtDef?.blurb || "Active assignment";
  const icon = districtId === "pediatrics" ? "🏫" : (districtDef?.icon || "📍");

  setText("category-topbar-mark", districtId === "pediatrics" ? "PED" : (districtId === "other" ? "TC" : "MAP"));
  setText("category-screen-title", categoryLabel);
  el("btn-category-home")?.classList.toggle("hidden", districtId === "other");
  el("btn-category-training-back")?.classList.toggle("hidden", districtId !== "other");
  setText("category-nav-ava", (state.firstName || state.studentName || "?")[0].toUpperCase());
  setText("category-nav-title", `Welcome, ${state.firstName || state.studentName}`);
  const agencyDisplay = state._isSuper ? "Global Superuser" : (state.agency || "");
  const agencyBadge = el("category-agency-badge");
  if (agencyBadge) {
    if (agencyDisplay) { agencyBadge.textContent = agencyDisplay; agencyBadge.classList.remove("hidden"); }
    else agencyBadge.classList.add("hidden");
  }
  setText("category-mca-badge", MCA_DISPLAY[state.mca] || state.mca || "WMRMCC");
  setText("category-provider-badge", LEVEL_DISPLAY[state.providerLevel] || state.providerLevel || "EMT-Basic (BLS)");
  setText("category-streak-label", el("hv2-streak-label")?.textContent || `${localStorage.getItem("pfd_login_streak") || 0} Day Streak`);
  setText("category-rank-title", el("menu-rank-title")?.textContent || "");
  setText("category-rank-subtext", el("menu-rank-subtext")?.textContent || "");
  el("category-open-leaderboard")?.classList.toggle("hidden", !(state.agency_id && !state._isSuper));
  setText("category-nav-lexi-status", el("nav-lexi-status")?.textContent || "Loading...");
  setText("category-treat-count", el("menu-treat-count")?.textContent || `🦴 ${loadGamification().treats ?? 0} treats`);

  el("category-nav-training")?.classList.toggle("hv2-active", districtId === "other");
  el("category-admin-dashboard")?.classList.toggle("hidden", !_canShowDashboardButtonForRole());
  const iconEl = el("category-screen-icon");
  if (iconEl) iconEl.textContent = icon;
  _applyScormSaasUiTrim();
}

function _pedsMapCompletionSets() {
  const passedIds = _scenarioPassedHistorySet();
  const pedsMapCompleted = new Set(loadGamification().pedsMapCompleted || []);
  return { passedIds, pedsMapCompleted };
}

function _renderCategoryMapNav(mode = "district", districtId = null) {
  const list = el("category-map-nav-list");
  const subtitle = el("category-map-nav-subtitle");
  if (!list) return;
  _syncCategoryShell(districtId);

  if (districtId === "pediatrics") {
    const currentMapId = _pedsJourneyState.currentMap || "map_0";
    const { passedIds, pedsMapCompleted } = _pedsMapCompletionSets();
    const baseUnlockState = _computeMapUnlockState(passedIds, MAP_TOPOLOGY, pedsMapCompleted);
    const unlockState = PEDS_MAP_DEV_UNLOCKED ? null : baseUnlockState;
    const navMaps = state.scormEnabled
      ? PEDS_MAP_DATA.filter(mapDef => _scormPedsMapAllowed(mapDef.id))
      : PEDS_MAP_DATA;
    if (subtitle) subtitle.textContent = state.scormEnabled
      ? "Station 1 maps only."
      : "Jump between available pediatric maps.";

    const orientationButton = state.scormEnabled
      ? `<button type="button" class="category-map-nav-btn" data-scorm-map-nav="orientation">
          <span class="category-map-nav-ico">🚒</span>
          <span class="category-map-nav-body">
            <span class="category-map-nav-title">Orientation</span>
            <span class="category-map-nav-meta">Station 1 orientation map</span>
            <span class="category-map-nav-status category-map-nav-status--available">Available</span>
          </span>
        </button>`
      : "";

    list.innerHTML = orientationButton + navMaps.map(mapDef => {
      const scormProgress = state.scormEnabled ? _scormPedsSidebarProgress(mapDef.id) : null;
      const unlock = unlockState?.get(mapDef.id);
      const locked = state.scormEnabled
        ? !scormProgress?.unlocked
        : (!!unlockState && !unlock?.unlocked && !unlock?.partial);
      const current = mapDef.id === currentMapId;
      const complete = state.scormEnabled
        ? !!scormProgress?.complete
        : _mapHasCompletion(mapDef.id, passedIds, pedsMapCompleted);
      const statusText = current ? "Current" : locked ? "Locked" : complete ? "Complete" : "Available";
      const statusCls = current ? "current" : locked ? "locked" : complete ? "complete" : "available";
      const icon = mapDef.id === "map_0" ? "🏠" : mapDef.id.startsWith("pm") ? "🩺" : mapDef.id.startsWith("pt") ? "🦴" : "🚨";
      return `<button type="button" class="category-map-nav-btn${current ? " active" : ""}${locked ? " locked" : ""}"
          data-category-map-nav="${escapeHTML(mapDef.id)}" ${locked ? "disabled" : ""}>
        <span class="category-map-nav-ico">${icon}</span>
        <span class="category-map-nav-body">
          <span class="category-map-nav-title">${escapeHTML(mapDef.label || mapDef.id)}</span>
          <span class="category-map-nav-meta">${escapeHTML(mapDef.theme || "Pediatric map")}</span>
          <span class="category-map-nav-status category-map-nav-status--${statusCls}">${statusText}</span>
        </span>
      </button>`;
    }).join("");

    list.querySelector("[data-scorm-map-nav='orientation']")?.addEventListener("click", () => {
      _setCategoryMobileTab("map");
      _enterScormOrientationMap();
    });
    list.querySelectorAll("[data-category-map-nav]:not([disabled])").forEach(btn => {
      btn.addEventListener("click", () => {
        const mapId = btn.getAttribute("data-category-map-nav");
        _setCategoryMobileTab("map");
        if (mapId === currentMapId) return;
        _renderPedsMap(mapId);
      });
    });
    return;
  }

  if (districtId === "other") {
    if (subtitle) subtitle.textContent = "Training Center replay areas.";
    list.innerHTML = DOG_PARK_GAME_GROUPS.map(group => `
      <button type="button" class="category-map-nav-btn" data-dog-park-nav="${escapeHTML(group.title)}">
        <span class="category-map-nav-ico">📚</span>
        <span class="category-map-nav-body">
          <span class="category-map-nav-title">${escapeHTML(group.title)}</span>
          <span class="category-map-nav-meta">${escapeHTML(group.subtitle || "Drill practice")}</span>
          <span class="category-map-nav-status category-map-nav-status--available">Replay</span>
        </span>
      </button>
    `).join("");
    list.querySelectorAll("[data-dog-park-nav]").forEach(btn => {
      btn.addEventListener("click", () => _setCategoryMobileTab("map"));
    });
    return;
  }

  if (subtitle) subtitle.textContent = "Select another district.";
  list.innerHTML = ADVENTURE_DISTRICTS.map(d => {
    const active = d.id === districtId;
    const available = d.status === "active";
    return `<button type="button" class="category-map-nav-btn${active ? " active" : ""}${available ? "" : " locked"}"
        data-district-nav="${escapeHTML(d.id)}" ${available ? "" : "disabled"}>
      <span class="category-map-nav-ico">${escapeHTML(d.icon || "📍")}</span>
      <span class="category-map-nav-body">
        <span class="category-map-nav-title">${escapeHTML(d.title)}</span>
        <span class="category-map-nav-meta">${escapeHTML(d.subtitle || d.blurb || "")}</span>
        <span class="category-map-nav-status category-map-nav-status--${available ? "available" : "locked"}">${available ? "Available" : "Planned"}</span>
      </span>
    </button>`;
  }).join("");
  list.querySelectorAll("[data-district-nav]:not([disabled])").forEach(btn => {
    btn.addEventListener("click", () => {
      _setCategoryMobileTab("map");
      showCategoryScreen(btn.getAttribute("data-district-nav"));
    });
  });
}

function _clearDistrictJourneySummary() {
  const summary = el("district-journey-summary");
  if (summary) {
    summary.innerHTML = "";
    summary.classList.add("hidden");
  }
}

function _mapTrackForId(mapId) {
  if (mapId === "map_0") return "entrance";
  if (String(mapId || "").startsWith("pm")) return "medical";
  if (String(mapId || "").startsWith("pt")) return "trauma";
  if (String(mapId || "").startsWith("pe")) return "emergency";
  return "district";
}

function _mapTrackLabel(track) {
  return {
    entrance: "Entrance",
    medical: "Medical Trail",
    trauma: "Trauma Trail",
    emergency: "Emergencies",
    station_1: "Station 1",
  }[track] || "District";
}

function _pedsMapProgress(mapId, passedIds, pedsMapCompleted, unlockState) {
  const topology = MAP_TOPOLOGY[mapId] || { requires: [] };
  const requirements = Array.isArray(topology.requires) ? topology.requires : [];
  const met = requirements.filter(req => _mapHasCompletion(req, passedIds, pedsMapCompleted));
  const unlock = unlockState?.get(mapId);
  const unlocked = mapId === "map_0" || !!unlock?.unlocked;
  const partial = !!unlock?.partial && !unlocked;
  const pct = requirements.length ? Math.round((met.length / requirements.length) * 100) : 100;
  return {
    unlocked,
    partial,
    pct: unlocked ? 100 : pct,
    metCount: requirements.length ? met.length : 1,
    totalCount: requirements.length || 1,
    requirements,
    metRequirements: new Set(met),
  };
}

function _scenarioPassedHistorySet() {
  const history = loadHistory().filter(h => !h.agencyId || h.agencyId === state.agency_id);
  const passedIds = new Set(history.filter(_scenarioHistoryEntryPassed).map(h => h.scenarioId));
  if (state.scormEnabled) {
    Object.entries(_SCORM_NODE_BY_APP_ID).forEach(([appId, node]) => {
      if (node?.type === "scenario" && _scormNodeCompleteByNodeId(node.nodeId)) {
        passedIds.add(appId);
      }
    });
  }
  return passedIds;
}

function _pedsMapActivityCounts(mapIds = [], passedIds = new Set()) {
  const maps = mapIds.map(id => _PEDS_MAP_BY_ID.get(id)).filter(Boolean);
  const scenarios = maps.flatMap(m => (m.scenarios || []).filter(s => !String(s.id || "").startsWith("_ph")));
  const games = maps.flatMap(m => {
    if (Array.isArray(m.games)) return m.games.filter(g => !String(g.id || "").startsWith("_ph"));
    if (m.game && !String(m.game.id || "").startsWith("_ph")) return [m.game];
    return [];
  });
  return {
    callsComplete: scenarios.filter(s => passedIds.has(s.id)).length,
    callsTotal: scenarios.length,
    drillsComplete: 0,
    drillsTotal: games.length,
  };
}

function _scormPediatricDistrictActivityCounts() {
  const passedIds = _scenarioPassedHistorySet();
  const scenarioIds = PEDS_MAP_DATA
    .filter(m => _scormPedsMapAllowed(m.id))
    .flatMap(m => (m.scenarios || []).filter(s => !String(s.id || "").startsWith("_ph")).map(s => s.id));
  return {
    callsComplete: scenarioIds.filter(appId => _scormVisibleScenarioComplete(appId, passedIds)).length,
    callsTotal: scenarioIds.length,
    drillsComplete: 0,
    drillsTotal: 0,
  };
}

function _districtActivityCounts(districtId, unlockedOnly = true) {
  if (state.scormEnabled && districtId === "pediatrics") {
    return _scormPediatricDistrictActivityCounts();
  }
  const { passedIds, pedsMapCompleted } = _pedsMapCompletionSets();
  if (districtId === "pediatrics") {
    const unlockState = _computeMapUnlockState(passedIds, MAP_TOPOLOGY, pedsMapCompleted);
    const mapIds = PEDS_MAP_DATA
      .filter(m => !state.scormEnabled || _scormPedsMapAllowed(m.id))
      .filter(m => !unlockedOnly || m.id === "map_0" || !!unlockState.get(m.id)?.unlocked)
      .map(m => m.id);
    return _pedsMapActivityCounts(mapIds, passedIds);
  }
  const district = ADVENTURE_DISTRICTS.find(d => d.id === districtId);
  const scenarios = (state.allScenarios || []).filter(s => (district?.legacy || []).includes(s.category));
  return {
    callsComplete: scenarios.filter(s => passedIds.has(s.id)).length,
    callsTotal: scenarios.length,
    drillsComplete: 0,
    drillsTotal: 0,
  };
}

function _formatActivityCounts(counts) {
  return `Calls ${counts.callsComplete}/${counts.callsTotal} · Drills ${counts.drillsComplete}/${counts.drillsTotal}`;
}

function _pedsMapCompletionNode(mapId) {
  const mapDef = _PEDS_MAP_BY_ID.get(mapId);
  if (!mapDef) return { label: mapId, mapLabel: mapId, kind: "map" };
  const realScenarios = (mapDef.scenarios || []).filter(s => !String(s.id || "").startsWith("_ph"));
  const finalScenario = realScenarios[realScenarios.length - 1];
  return {
    id: finalScenario?.id || mapId,
    label: finalScenario?.label || finalScenario?.id || mapDef.label || mapId,
    mapLabel: mapDef.label || mapId,
    kind: finalScenario ? "scenario" : "map",
  };
}

function _pedsRequirementHtml(mapDef, progress, counts = null) {
  const rows = progress.requirements.length
    ? progress.requirements.map(req => {
        const node = _pedsMapCompletionNode(req);
        const done = progress.metRequirements?.has(req);
        return `<li class="map-req-row ${done ? "done" : "locked"}">
          <span>${done ? "✓" : "○"}</span>
          <strong>${escapeHTML(node.label)}</strong>
          <em>${escapeHTML(node.mapLabel)}</em>
        </li>`;
      }).join("")
    : `<li class="map-req-row done"><span>✓</span><strong>No prerequisite map.</strong></li>`;
  return `<div class="map-req-panel">
    <div class="map-req-progress">
      <span>${progress.pct}% unlocked</span>
      <div class="map-nav-progress"><i style="width:${progress.pct}%"></i></div>
    </div>
    ${counts ? `<div class="map-req-counts">${escapeHTML(_formatActivityCounts(counts))}</div>` : ""}
    <p class="map-req-copy">Complete the required call${progress.requirements.length === 1 ? "" : "s"} below to unlock ${escapeHTML(mapDef?.label || "this map")}.</p>
    <ul>${rows}</ul>
  </div>`;
}

function _openMapRequirementsPopup(mapId, progress) {
  const mapDef = _PEDS_MAP_BY_ID.get(mapId);
  _presentMapNodeSelection({
    type: "map_requirements",
    statusKind: "map",
    kicker: "Map Status",
    label: mapDef?.label || "Map Requirements",
    statusText: progress.unlocked
      ? "This map is unlocked."
      : progress.partial
        ? "Partially unlocked. Complete the remaining feeder maps to fully unlock it."
        : "Locked. Complete the requirements below to unlock this map.",
    detailHtml: _pedsRequirementHtml(
      mapDef,
      progress,
      _pedsMapActivityCounts(progress.unlocked ? [mapId] : [], _scenarioPassedHistorySet())
    ),
  });
}

function _renderPedsMapSidebar(currentMapId, unlockState, passedIds, pedsMapCompleted) {
  const list = el("category-map-nav-list");
  const subtitle = el("category-map-nav-subtitle");
  if (!list) return;
  if (subtitle) subtitle.textContent = state.scormEnabled
    ? "Station 1 trails and available maps."
    : "Trails, unlock progress, and available maps.";

  const current = _PEDS_MAP_BY_ID.get(currentMapId) || PEDS_MAP_DATA[0];
  const pathIds = [
    ...(current.parent ? [current.parent] : []),
    ...(current.parents || []).map(p => p.to),
    ...(current.exits || []).map(e => e.to),
  ].filter(mapId => mapId && (!state.scormEnabled || _scormPedsMapAllowed(mapId)));
  const uniquePathIds = [...new Set(pathIds)];
  const allPedsMaps = state.scormEnabled
    ? PEDS_MAP_DATA.filter(m => _scormPedsMapAllowed(m.id))
    : PEDS_MAP_DATA;
  const unlockedPedsMaps = allPedsMaps.filter(m => {
    const progress = state.scormEnabled
      ? _scormPedsSidebarProgress(m.id)
      : _pedsMapProgress(m.id, passedIds, pedsMapCompleted, unlockState);
    return progress.unlocked || m.id === currentMapId;
  });

  const pathRows = uniquePathIds.length
    ? uniquePathIds.map(mapId => _pedsSidebarMapButton(mapId, currentMapId, passedIds, pedsMapCompleted, unlockState, "path")).join("")
    : `<div class="map-nav-empty">No connected trails from this map.</div>`;
  const unlockedRows = unlockedPedsMaps.length
    ? unlockedPedsMaps.map(m => _pedsSidebarMapButton(m.id, currentMapId, passedIds, pedsMapCompleted, unlockState, "map")).join("")
    : `<div class="map-nav-empty">No unlocked pediatric maps yet.</div>`;

  list.innerHTML = `
    <section class="category-map-nav-section">
      <div class="category-map-nav-section-head">
        <span>Trails To / From Current</span>
        <small>${escapeHTML(current.label || currentMapId)}</small>
      </div>
      <div class="category-map-nav-section-body">${pathRows}</div>
    </section>
    <section class="category-map-nav-section">
      <div class="category-map-nav-section-head">
        <span>Unlocked Pediatric Maps</span>
        <small>${unlockedPedsMaps.length}/${allPedsMaps.length}</small>
      </div>
      <div class="category-map-nav-section-body">${unlockedRows}</div>
    </section>
  `;

  list.querySelectorAll("[data-category-map-nav]").forEach(btn => {
    btn.addEventListener("click", () => {
      const mapId = btn.getAttribute("data-category-map-nav");
      const progress = state.scormEnabled
        ? _scormPedsSidebarProgress(mapId)
        : _pedsMapProgress(mapId, passedIds, pedsMapCompleted, unlockState);
      if (!progress.unlocked && !progress.partial) {
        _openMapRequirementsPopup(mapId, progress);
        return;
      }
      _setCategoryMobileTab("map");
      if (mapId === currentMapId) return;
      _renderPedsMap(mapId);
    });
  });
}

function _pedsSidebarMapButton(mapId, currentMapId, passedIds, pedsMapCompleted, unlockState, kind = "map") {
  const mapDef = _PEDS_MAP_BY_ID.get(mapId);
  const progress = state.scormEnabled
    ? _scormPedsSidebarProgress(mapId)
    : _pedsMapProgress(mapId, passedIds, pedsMapCompleted, unlockState);
  const current = mapId === currentMapId;
  const locked = !progress.unlocked && !progress.partial;
  const complete = state.scormEnabled
    ? !!progress.complete
    : _mapHasCompletion(mapId, passedIds, pedsMapCompleted);
  const statusText = current ? "Current" : locked ? "Locked" : complete ? "Complete" : progress.partial ? "Partial" : "Available";
  const statusCls = current ? "current" : locked ? "locked" : complete ? "complete" : "available";
  const icon = mapId === "map_0" ? "🏠" : mapId.startsWith("pm") ? "🩺" : mapId.startsWith("pt") ? "🦴" : "🚨";
  return `<button type="button" class="category-map-nav-btn${current ? " active" : ""}${locked ? " locked" : ""}"
      data-category-map-nav="${escapeHTML(mapId)}" data-map-nav-kind="${escapeHTML(kind)}">
    <span class="category-map-nav-ico">${icon}</span>
    <span class="category-map-nav-body">
      <span class="category-map-nav-title">${escapeHTML(mapDef?.label || mapId)}</span>
      <span class="category-map-nav-meta">${escapeHTML(mapDef?.theme || "Pediatric map")}</span>
      <span class="map-nav-progress" aria-hidden="true"><i style="width:${progress.pct}%"></i></span>
      <span class="category-map-nav-status category-map-nav-status--${statusCls}">
        ${statusText} · ${progress.pct}%
      </span>
    </span>
  </button>`;
}

function _renderStation1Sidebar({ introSeen, completed, cprComplete, challengesSeen }) {
  const list = el("category-map-nav-list");
  const subtitle = el("category-map-nav-subtitle");
  if (!list) return;
  if (subtitle) subtitle.textContent = "Orientation progress and Station 1 access.";
  const stationComplete = _station1IsComplete({
    introSeen,
    completed,
    cprComplete,
    challengesSeen,
    ready: introSeen && completed && cprComplete && challengesSeen,
  });
  const requirements = [
    { label: "Lexi Intro", done: introSeen },
    { label: "Orientation Tour", done: completed },
    { label: "CPR Drill", done: cprComplete },
    { label: "Challenges Briefing", done: challengesSeen },
    { label: "Lexi Wrap-up", done: stationComplete },
  ];
  const doneCount = requirements.filter(r => r.done).length;
  const orientationStep = {
    id: "orientation",
    label: "Orientation",
    unlocked: true,
    complete: stationComplete,
    pct: Math.round((doneCount / requirements.length) * 100),
    requirement: `${doneCount}/${requirements.length} steps complete`,
    requirements,
  };
  const stationStep = {
    id: "station_1",
    label: "Station 1",
    unlocked: true,
    complete: stationComplete,
    pct: orientationStep.pct,
    requirement: stationComplete ? "Complete" : "Complete Orientation to unlock other districts.",
    requirements,
  };
  list.innerHTML = `
    <section class="category-map-nav-section">
      <div class="category-map-nav-section-head">
        <span>Trails To / From Current</span>
        <small>Orientation progress</small>
      </div>
      <div class="category-map-nav-section-body">
        ${_station1SidebarButton(orientationStep)}
      </div>
    </section>
    <section class="category-map-nav-section">
      <div class="category-map-nav-section-head">
        <span>Station 1</span>
        <small>Home base</small>
      </div>
      <div class="category-map-nav-section-body">
        ${_station1SidebarButton(stationStep)}
      </div>
    </section>
  `;
  list.querySelectorAll("[data-station1-step]").forEach(btn => {
    btn.addEventListener("click", () => {
      const stepId = btn.getAttribute("data-station1-step");
      const step = stepId === "station_1" ? stationStep : orientationStep;
      if (!step) return;
      _presentMapNodeSelection({
        type: "map_requirements",
        statusKind: "district",
        kicker: "District Status",
        label: step.label,
        statusText: step.complete ? "Complete." : step.requirement,
        detailHtml: _station1RequirementHtml(step),
      });
    });
  });
}

function _station1SidebarButton(step) {
  const locked = !step.unlocked;
  const statusText = locked ? "Locked" : step.complete ? "Complete" : "Available";
  const statusCls = locked ? "locked" : step.complete ? "complete" : "available";
  return `<button type="button" class="category-map-nav-btn${locked ? " locked" : ""}"
      data-station1-step="${escapeHTML(step.id)}">
    <span class="category-map-nav-ico">${locked ? "🔒" : step.complete ? "✓" : "🚒"}</span>
    <span class="category-map-nav-body">
      <span class="category-map-nav-title">${escapeHTML(step.label)}</span>
      <span class="category-map-nav-meta">${escapeHTML(step.requirement)}</span>
      <span class="map-nav-progress" aria-hidden="true"><i style="width:${step.pct}%"></i></span>
      <span class="category-map-nav-status category-map-nav-status--${statusCls}">${statusText} · ${step.pct}%</span>
    </span>
  </button>`;
}

function _station1RequirementHtml(step) {
  const rows = (step.requirements || []).map(req => `<li class="map-req-row ${req.done ? "done" : "locked"}">
    <span>${req.done ? "✓" : "○"}</span>
    <strong>${escapeHTML(req.label)}</strong>
  </li>`).join("");
  const counts = _districtActivityCounts("station_1", true);
  return `<div class="map-req-panel">
    <div class="map-req-progress">
      <span>${step.pct}% complete</span>
      <div class="map-nav-progress"><i style="width:${step.pct}%"></i></div>
    </div>
    <div class="map-req-counts">${escapeHTML(_formatActivityCounts(counts))}</div>
    <p class="map-req-copy">${escapeHTML(step.requirement)}</p>
    <ul>${rows}</ul>
  </div>`;
}

function _districtProgress(districtId) {
  const district = ADVENTURE_DISTRICTS.find(d => d.id === districtId);
  const stationDone = _station1IsComplete();
  const prereqMet = !district?.prereq || stationDone;
  const counts = _districtActivityCounts(districtId, true);
  const total = counts.callsTotal;
  const done = counts.callsComplete;
  const stationStarted = stationDone || _station1IntroSeen();
  const pct = state.scormEnabled && districtId === "pediatrics"
    ? (total > 0 ? Math.round((done / total) * 100) : 0)
    : districtId === "station_1"
    ? (stationDone ? 100 : stationStarted ? 25 : 0)
    : !prereqMet
      ? 0
      : total > 0
        ? Math.round((done / total) * 100)
        : 0;
  return {
    unlocked: prereqMet && district?.status === "active",
    planned: district?.status !== "active",
    pct,
    counts,
    requirement: !prereqMet
      ? "Complete Station 1 orientation first."
      : district?.status !== "active"
        ? "This district is planned for a later phase."
        : "Available.",
  };
}

function _districtRequirementHtml(district, progress) {
  const rows = [];
  if (district?.prereq === "station_1") {
    const stationComplete = _station1IsComplete();
    rows.push(`<li class="map-req-row ${stationComplete ? "done" : "locked"}">
      <span>${stationComplete ? "✓" : "○"}</span>
      <strong>Station 1 Orientation</strong>
    </li>`);
  } else {
    rows.push(`<li class="map-req-row done"><span>✓</span><strong>No prerequisite district.</strong></li>`);
  }
  return `<div class="map-req-panel">
    <div class="map-req-progress">
      <span>${progress.pct}% unlocked</span>
      <div class="map-nav-progress"><i style="width:${progress.pct}%"></i></div>
    </div>
    <div class="map-req-counts">${escapeHTML(_formatActivityCounts(progress.counts))}</div>
    <p class="map-req-copy">${escapeHTML(progress.requirement)}</p>
    <ul>${rows.join("")}</ul>
  </div>`;
}

function _openDistrictRequirementsPopup(districtId) {
  const district = ADVENTURE_DISTRICTS.find(d => d.id === districtId);
  if (!district) return;
  const progress = _districtProgress(districtId);
  _presentMapNodeSelection({
    type: "map_requirements",
    statusKind: "district",
    kicker: "District Status",
    label: district.title,
    statusText: progress.requirement,
    reportDistrictId: districtId,
    canReport: progress.unlocked,
    detailHtml: _districtRequirementHtml(district, progress),
  });
}

function _renderRightDistrictList() {
  const list = el("right-district-list");
  if (!list) return;
  list.innerHTML = ADVENTURE_DISTRICTS
    .filter(d => d.id !== "other" || d.status === "active")
    .map(d => {
      const progress = _districtProgress(d.id);
      const locked = !progress.unlocked;
      const statusText = progress.planned ? "Planned" : locked ? "Locked" : "Available";
      const statusCls = progress.planned || locked ? "locked" : "available";
      return `<button type="button" class="category-map-nav-btn${locked ? " locked" : ""}" data-right-district="${escapeHTML(d.id)}">
        <span class="category-map-nav-ico">${escapeHTML(d.icon || "📍")}</span>
        <span class="category-map-nav-body">
          <span class="category-map-nav-title">${escapeHTML(d.title)}</span>
          <span class="category-map-nav-meta">${escapeHTML(_formatActivityCounts(progress.counts))}</span>
          <span class="map-nav-progress" aria-hidden="true"><i style="width:${progress.pct}%"></i></span>
          <span class="category-map-nav-status category-map-nav-status--${statusCls}">${statusText} · ${progress.pct}%</span>
        </span>
      </button>`;
    }).join("");
  list.querySelectorAll("[data-right-district]").forEach(btn => {
    btn.addEventListener("click", () => {
      const districtId = btn.getAttribute("data-right-district");
      _openDistrictRequirementsPopup(districtId);
    });
  });
}

function buildBadgesSection(game) {
  const section = el("badges-section");
  const display = el("all-badges-display");
  const summary = el("badges-summary");
  const modalSummary = el("badges-modal-summary");
  const isPrivileged = state._role === "admin" || state._role === "instructor" || state._isSuper;
  const drillUnlocked = !!(_drillStatus?.random_available);
  const isDrillFeatureBadge = (id = "", name = "", desc = "") => {
    const t = `${id} ${name} ${desc}`.toLowerCase();
    return /quick\s*drill|random\s*drill|drill\s*mode|\bdrill\b/.test(t);
  };
  const canShowLockedBadge = (id = "", name = "", desc = "") => {
    if (isDrillFeatureBadge(id, name, desc)) return drillUnlocked;
    return true;
  };

  const visibleSystem = BADGE_DEFS
    .filter(b => {
      const earned = game.badges.includes(b.id);
      return earned || canShowLockedBadge(b.id, b.name, b.desc);
    })
    .map(b => ({
      earned: game.badges.includes(b.id),
      html: `<div class="badge-card ${game.badges.includes(b.id) ? "earned" : ""}">
        <div class="badge-card-icon">${game.badges.includes(b.id) ? b.icon : "🔒"}</div>
        <div><div class="badge-card-name">${escapeHTML(b.name)}</div>
             <div class="badge-card-desc">${escapeHTML(b.desc)}</div></div>
      </div>`,
    }));

  const visibleChallenges = (_challengesCache || [])
    .filter(ch => {
      const earned = game.badges.includes(ch.badge_id);
      return earned || canShowLockedBadge(ch.badge_id, ch.name || "", ch.description || "");
    })
    .map(ch => ({
      earned: game.badges.includes(ch.badge_id),
      html: `<div class="badge-card ${game.badges.includes(ch.badge_id) ? "earned" : ""}">
        <div class="badge-card-icon">${game.badges.includes(ch.badge_id) ? (ch.icon || "🏅") : "🔒"}</div>
        <div><div class="badge-card-name">${escapeHTML(ch.name)}</div>
             <div class="badge-card-desc">${escapeHTML(ch.description || "Agency challenge")}</div></div>
      </div>`,
    }));

  const allVisible = [...visibleSystem, ...visibleChallenges];
  const earnedCards = allVisible.filter(b => b.earned).map(b => b.html).join("");
  const availableCards = allVisible.filter(b => !b.earned).map(b => b.html).join("");

  const sectionHtml = [];
  if (earnedCards) {
    sectionHtml.push(`
      <section>
        <h3 class="text-xs font-semibold text-green-300 uppercase tracking-widest mb-2">Earned</h3>
        <div class="grid grid-cols-1 md:grid-cols-2 gap-3">${earnedCards}</div>
      </section>
    `);
  }
  if (availableCards) {
    sectionHtml.push(`
      <section>
        <h3 class="text-xs font-semibold text-amber-300 uppercase tracking-widest mb-2">Available</h3>
        <div class="grid grid-cols-1 md:grid-cols-2 gap-3">${availableCards}</div>
      </section>
    `);
  }
  display.innerHTML = sectionHtml.join("") || '<p class="text-sm text-gray-500">No badges available yet.</p>';

  const totalVisible = allVisible.length;
  const earnedVisible = allVisible.filter(b => b.earned).length;
  const summaryText = totalVisible > 0
    ? `${earnedVisible} earned · ${Math.max(0, totalVisible - earnedVisible)} available`
    : "No badges available yet";
  if (summary) summary.textContent = summaryText;
  if (modalSummary) modalSummary.textContent = summaryText;

  if (isPrivileged || totalVisible > 0 || game.badges.length > 0 || game.sessions > 0) {
    section.classList.remove("hidden");
  } else {
    section.classList.add("hidden");
  }
}

// ── Leaderboard ───────────────────────────────────────────────────────────────

const MEDALS = ["🥇", "🥈", "🥉"];
const MEDAL_BG = [
  "border rounded-xl",  // gold — inline style applied below
  "border rounded-xl",
  "border rounded-xl",
];
const MEDAL_BG_STYLE = [
  "background:rgba(180,120,0,0.12);border-color:rgba(180,120,0,0.4);",
  "background:rgba(100,60,5,0.08);border-color:rgba(100,60,5,0.25);",
  "background:rgba(130,70,10,0.10);border-color:rgba(130,70,10,0.3);",
];

async function _loadLeaderboard() {
  // Leaderboard button only visible in agency context
  const btn = el("btn-open-leaderboard");
  if (!state.agency_id || state._isSuper) { btn?.classList.add("hidden"); return; }
  btn?.classList.remove("hidden");

  try {
    const r = await authFetch(`${API}/api/agency/leaderboard`);
    if (!r.ok) return;
    const data = await r.json();
    _leaderboardModalCache = { agencyId: state.agency_id, data, fetchedAt: Date.now() };
    _writeLeaderboardModalCache(data);
    _renderLeaderboardModalData(data);
  } catch { /* silently ignore */ }
}

function _leaderboardCacheKey() {
  return `ems_leaderboard_modal:${state.agency_id || "none"}`;
}

function _writeLeaderboardModalCache(data) {
  if (!state.agency_id || !data) return;
  try {
    localStorage.setItem(_leaderboardCacheKey(), JSON.stringify({ fetchedAt: Date.now(), data }));
  } catch { /* storage may be unavailable */ }
}

function _readLeaderboardModalCache() {
  if (!state.agency_id) return null;
  if (_leaderboardModalCache.agencyId === state.agency_id && _leaderboardModalCache.data) {
    return _leaderboardModalCache.data;
  }
  try {
    const cached = JSON.parse(localStorage.getItem(_leaderboardCacheKey()) || "null");
    if (cached?.data) {
      _leaderboardModalCache = {
        agencyId: state.agency_id,
        data: cached.data,
        fetchedAt: Number(cached.fetchedAt || 0),
      };
      return cached.data;
    }
  } catch { /* ignore corrupt cache */ }
  return null;
}

function _renderLeaderboardModalData(data = {}) {
  const { leaderboard, rising_star, feed, rank_summary } = data || {};
  if (rank_summary !== undefined) {
    _menuRankCache = {
      agencyId: state.agency_id,
      data: rank_summary || null,
      fetchedAt: Date.now(),
      loading: false,
    };
    _renderMenuRank(_menuRankCache.data);
  }

  // Agency name in modal header
  setText("lb-agency-name", state.agency || "");

  // Top 3
  const top3 = el("lb-top3");
  if (top3) {
    top3.innerHTML = (leaderboard || []).map((entry, i) => {
      const bgStyle = entry.is_me
        ? "background:rgba(37,99,235,0.10);border-color:rgba(37,99,235,0.3);"
        : (MEDAL_BG_STYLE[i] || "background:rgba(100,60,5,0.07);border-color:rgba(100,60,5,0.22);");
      const nameColor = entry.is_me ? "color:#1d4ed8;font-weight:700;" : "color:var(--ui-text-primary);font-weight:600;";
      const lvl = getCurrentLevel(entry.xp);
      return `<div class="flex items-center gap-3 border rounded-xl px-4 py-2.5" style="${bgStyle}">
        <span class="text-2xl leading-none shrink-0">${MEDALS[i]}</span>
        <div class="flex-1 min-w-0">
          <div class="text-sm truncate" style="${nameColor}">${escapeHTML(entry.display)}${entry.is_me ? " <span style='color:var(--ui-text-muted);font-size:0.7rem;font-weight:400;'>(you)</span>" : ""}</div>
          <div class="text-xs mt-0.5" style="color:var(--ui-text-muted);">${lvl.icon} ${lvl.name}</div>
        </div>
        <span class="font-bold text-sm tabular-nums shrink-0" style="color:#1d4ed8;">${entry.xp.toLocaleString()} XP</span>
      </div>`;
    }).join("") || `<p class="text-sm text-center py-4" style="color:var(--ui-text-muted);">No data yet.</p>`;
  }

  // Rising star
  const rsSection  = el("lb-rising-star");
  const rsNoData   = el("lb-no-rising");
  if (rising_star) {
    setText("lb-rising-name", rising_star.display + (rising_star.is_me ? " (you)" : ""));
    setText("lb-rising-xp", `+${rising_star.xp_recent.toLocaleString()} XP`);
    rsSection?.classList.remove("hidden");
    rsNoData?.classList.add("hidden");
  } else {
    rsSection?.classList.add("hidden");
    rsNoData?.classList.remove("hidden");
  }

  // Ticker
  _renderLeaderboardTicker(feed || []);
}

const _LEXI_TICKER_GAGS = [
  "Lexi chased a squirrel 🐿️",
  "Lexi ate someone's lunch 🥪",
  "Lexi got into the dayroom trash 🗑️",
  "Lexi demands more treats 🦴",
  "Lexi is not sorry about getting into the trash 🐾",
  "Lexi chewed the radio cord again 📻",
  "Lexi is being very professional right now 🎖️",
  "Lexi found a tennis ball in a gear bag 🎾",
  "Lexi stole a glove from the supply room 🧤",
  "Lexi is supervising from the couch 🛋️",
  "Lexi has declared herself incident commander 🦺",
];

// Reusable Lexi avatar render helper powers ticker (and future dynamic avatar inserts).
const _LEXI_TICKER_SVG = _renderLexiAvatarSvg("ticker");
const _LEXI_BONUS_TICKER_SVG = _renderLexiAvatarSvg("ticker", {
  className: "lexi-bonus-icon",
  style: "display:inline-block;vertical-align:middle;",
});

let _tickerAnim = null;

function _renderLeaderboardTicker(feed) {
  const ticker = el("lb-ticker");
  if (!ticker) return;

  // Cancel previous animation
  if (_tickerAnim) { cancelAnimationFrame(_tickerAnim); _tickerAnim = null; }

  // Build feed items
  const feedItems = (feed || []).map(e => {
    const who  = e.is_me ? "You" : escapeHTML(e.display);
    const text = e.event_type === "level_up"
      ? `${e.icon} ${who} made ${escapeHTML(e.label)}`
      : `${e.icon} ${who} earned ${escapeHTML(e.label)}`;
    const color = e.is_me ? "color:#1d4ed8;" : "color:#64748b;";
    return `<span style="${color}padding:0 20px;">${text}</span>`;
  });

  // Shuffle gags so each run through the ticker shows different ones
  const shuffledGags = [..._LEXI_TICKER_GAGS].sort(() => Math.random() - 0.5);

  const makeGagSpan = gag =>
    `<span style="color:#1d4ed8;padding:0 20px;">${_LEXI_TICKER_SVG} ${gag}</span>`;
  const dot = `<span style="color:#64748b;padding:0 8px;">·</span>`;

  // Interleave one unique gag between each feed item (and after the last)
  // e.g. [feed1 · GAG_A · feed2 · GAG_B · feed3 · GAG_C ...]
  let segment;
  if (feedItems.length) {
    const parts = [];
    feedItems.forEach((item, i) => {
      parts.push(item);
      parts.push(dot);
      parts.push(makeGagSpan(shuffledGags[i % shuffledGags.length]));
      if (i < feedItems.length - 1) parts.push(dot);
    });
    segment = parts.join("");
  } else {
    // No feed events — rotate through all gags
    segment = shuffledGags.map(makeGagSpan).join(dot);
  }

  // Duplicate segment for seamless looping
  ticker.innerHTML = segment + segment;

  // Wait a frame for the DOM to paint so scrollWidth is accurate
  requestAnimationFrame(() => {
    const halfWidth = ticker.scrollWidth / 2;
    if (halfWidth <= 0) return;

    let pos = 0;
    const speedPxPerSec = 48;
    let lastTs = null;

    function step(ts) {
      if (lastTs == null) lastTs = ts;
      const dtSec = Math.min((ts - lastTs) / 1000, 0.1);
      lastTs = ts;
      pos += speedPxPerSec * dtSec;
      if (pos >= halfWidth) pos = 0;
      ticker.style.transform = `translateX(${-pos}px)`;
      _tickerAnim = requestAnimationFrame(step);
    }
    _tickerAnim = requestAnimationFrame(step);
  });
}

function _openLeaderboard() {
  show("modal-leaderboard");
  const cached = _readLeaderboardModalCache();
  if (cached) _renderLeaderboardModalData(cached);
  else {
    setText("lb-agency-name", state.agency || "");
    const top3 = el("lb-top3");
    if (top3) top3.innerHTML = `<p class="text-sm text-center py-4" style="color:var(--ui-text-muted);">Loading leaderboard…</p>`;
    _renderLeaderboardTicker([]); // start Lexi immediately while data loads
  }
  _loadLeaderboard();
}

function _closeLeaderboardModal() {
  hide("modal-leaderboard");
  if (_tickerAnim) {
    cancelAnimationFrame(_tickerAnim);
    _tickerAnim = null;
  }
}

el("btn-open-leaderboard")?.addEventListener("click", _openLeaderboard);
el("btn-leaderboard-close")?.addEventListener("click", _closeLeaderboardModal);
el("btn-leaderboard-refresh")?.addEventListener("click", _loadLeaderboard);

// ── Challenges ────────────────────────────────────────────────────────────────

async function _loadChallenges() {
  try {
    const r = await authFetch(`${API}/api/challenges`);
    if (!r.ok) throw new Error(`${r.status} ${r.statusText}`);
    const payload = await r.json();
    _challengesCache = Array.isArray(payload)
      ? payload
      : Array.isArray(payload?.challenges)
        ? payload.challenges
        : [];
    _writeChallengesCache(_challengesCache);
  } catch (err) {
    if (!Array.isArray(_challengesCache)) _challengesCache = [];
    throw err;
  }
}

function _challengesCacheKey() {
  return `ems_active_challenges:${state.agency_id || "none"}`;
}

function _writeChallengesCache(challenges) {
  if (!state.agency_id || !Array.isArray(challenges)) return;
  try {
    localStorage.setItem(_challengesCacheKey(), JSON.stringify({ fetchedAt: Date.now(), challenges }));
  } catch { /* storage may be unavailable */ }
}

const _CHALLENGES_CACHE_TTL_MS = 5 * 60 * 1000;

function _readChallengesCache() {
  if (!state.agency_id) return false;
  if (Array.isArray(_challengesCache)) return true;
  try {
    const cached = JSON.parse(localStorage.getItem(_challengesCacheKey()) || "null");
    const age = Date.now() - (cached?.fetchedAt || 0);
    if (Array.isArray(cached?.challenges) && age < _CHALLENGES_CACHE_TTL_MS) {
      _challengesCache = cached.challenges;
      return true;
    }
  } catch { /* ignore corrupt cache */ }
  return false;
}

function _buildChallengesSection() {
  const active = _activeChallengesForDisplay();
  const openCount = active.filter(ch => !ch?.earned).length;
  const summary = !active.length
    ? "No active challenges"
    : openCount
      ? `${openCount} active challenge${openCount === 1 ? "" : "s"}`
      : "All active challenges earned";

  setText("challenges-nav-sub", summary);
  setText("category-challenges-nav-sub", summary);
  ["challenges-nav-dot", "category-challenges-nav-dot"].forEach(id => {
    const node = el(id);
    if (node) node.classList.toggle("hidden", openCount <= 0);
  });
}

function _scormPassChallengeForDisplay() {
  if (!state.scormEnabled) return null;
  const summary = _normalizeScormState(state.scormLatestSummary || state.scormResumeState || {});
  const ce = summary.peds_ce_challenge || {};
  const pm1Required = Number(ce.pm1_required || 2);
  const pt1Required = Number(ce.pt1_required || 2);
  const pm1Done = Math.min(Math.max(0, Number(ce.pm1_completed || 0)), pm1Required);
  const pt1Done = Math.min(Math.max(0, Number(ce.pt1_completed || 0)), pt1Required);
  const ceSeconds = Math.max(0, Number(ce.ce_seconds || 0));
  const ceMinutes = Math.min(Math.floor(ceSeconds / 60), 60);
  const xpRequired = Number(ce.xp_required || 1200);
  const xpDone = Math.max(0, Number(ce.xp || 0));
  const timeDone = !!ce.training_time_done;
  const xpOk = !!ce.xp_ok;
  const progressDone = pm1Done + pt1Done + (timeDone ? 1 : 0) + (xpOk ? 1 : 0);
  const progressTotal = pm1Required + pt1Required + 2;

  return {
    id: "scorm-peds-ce-challenge",
    scorm_pass: true,
    is_active: true,
    earned: !!ce.complete,
    icon: "🎯",
    name: "Pediatric Patient Assessment",
    description: "Moodle course completion requirement: finish the required scenario mix, training time, and XP target.",
    scenarios_total: progressTotal,
    scenarios_completed: progressDone,
    time_goal_minutes: 60,
    challenge_ce_seconds: ceSeconds,
    requirements_progress: [
      {
        label: "Complete 2 Pediatric Medical scenarios with on-track scores or higher",
        completed: pm1Done,
        needed: pm1Required,
        progress_text: `${pm1Done}/${pm1Required}`,
        custom_items: [{
          label: "Pediatric Medical scenarios",
          status: `${pm1Done} of ${pm1Required} passing scenarios complete`,
          complete: pm1Done >= pm1Required,
        }],
      },
      {
        label: "Complete 2 Pediatric Trauma scenarios with on-track scores or higher",
        completed: pt1Done,
        needed: pt1Required,
        progress_text: `${pt1Done}/${pt1Required}`,
        custom_items: [{
          label: "Pediatric Trauma scenarios",
          status: `${pt1Done} of ${pt1Required} passing scenarios complete`,
          complete: pt1Done >= pt1Required,
        }],
      },
      {
        label: "Spend at least 1 hour training",
        completed: ceMinutes,
        needed: 60,
        progress_text: `${_fmtMinutes(ceMinutes)} of 1h${timeDone ? "" : ` · ${_fmtMinutes(60 - ceMinutes)} remaining`}`,
        custom_items: [{
          label: "Training time",
          status: timeDone
            ? "1 hour logged from orientation, drills, and scenarios"
            : `${_fmtMinutes(ceMinutes)} logged from orientation, drills, and scenarios · ${_fmtMinutes(60 - ceMinutes)} remaining`,
          complete: timeDone,
        }],
      },
      {
        label: `Earn at least ${xpRequired} XP`,
        completed: Math.min(xpDone, xpRequired),
        needed: xpRequired,
        progress_text: `${xpDone.toLocaleString()} of ${xpRequired.toLocaleString()} XP`,
        custom_items: [{
          label: "XP",
          status: `${xpDone.toLocaleString()} of ${xpRequired.toLocaleString()} XP earned`,
          complete: xpOk,
        }],
      },
    ],
  };
}

function _activeChallengesForDisplay() {
  const agencyChallenges = (_challengesCache || []).filter(ch => ch?.is_active !== false);
  const scormChallenge = _scormPassChallengeForDisplay();
  return scormChallenge ? [scormChallenge, ...agencyChallenges] : agencyChallenges;
}

function _fmtMinutes(mins) {
  if (mins < 60) return `${mins}m`;
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  return m ? `${h}h ${m}m` : `${h}h`;
}

function _challengeRequirementText(req = {}) {
  if (req.label && req.progress_text) return `${req.label} · ${req.progress_text}`;
  const label = req.label || "";
  const done = Number(req.completed || 0);
  const needed = Math.max(0, Number(req.needed || 0));
  const prefix = req.type === "any_n" ? `Complete any ${needed}` : "Complete all";
  const scenarioCount = Array.isArray(req.scenario_ids) ? req.scenario_ids.length : 0;
  const drillCount = Array.isArray(req.drill_ids) ? req.drill_ids.length : 0;
  const noun = scenarioCount && drillCount
    ? "items"
    : drillCount
      ? `drill${needed === 1 ? "" : "s"}`
      : `scenario${needed === 1 ? "" : "s"}`;
  const fallback = `${prefix} ${noun}`;
  return `${label || fallback} · ${Math.min(done, needed)}/${needed}`;
}

function _challengeScenarioTitle(scenarioId = "", req = {}, completed = false) {
  const serverTitles = req?.scenario_titles || req?.scenarioTitles || {};
  const serverTitle = serverTitles[String(scenarioId)] || serverTitles[scenarioId];
  if (serverTitle) return serverTitle;
  const scenario = (state.allScenarios || []).find(s => String(s.id) === String(scenarioId));
  if (!completed) {
    return scenario?.display_title || scenario?.default_title || scenario?.name || scenario?.scenario_title || scenarioId;
  }
  return scenario?.title || scenario?.display_title || scenario?.name || scenario?.scenario_title || scenarioId;
}

function _challengeDrillTitle(drillId = "") {
  const raw = String(drillId || "");
  const aliases = {
    drill_pat: "pat",
    pat_dash: "pat",
    drill_dev: "dev_sort",
  };
  const canonical = aliases[raw] || raw;
  const game = _dogParkGameCatalog().find(g => String(g.type) === canonical || String(g.type) === raw);
  if (game?.label) return game.label;
  const dashboardDrill = Array.isArray(CHALLENGE_DRILLS)
    ? CHALLENGE_DRILLS.find(d => String(d.id) === canonical || String(d.id) === raw)
    : null;
  return dashboardDrill?.label || canonical || raw || "Training Drill";
}

function _challengeAttemptStatusText(ch = {}) {
  if (!ch.repeatable) return "";
  const count = Number(ch.completion_count || 0);
  const attempt = ch.attempt || null;
  if (attempt?.status === "active") return `Attempt ${attempt.attempt_number || 1} active`;
  if (attempt?.status === "completed") {
    return `${count || 1} completion${(count || 1) === 1 ? "" : "s"} · ready to repeat`;
  }
  return "Not started";
}

function _renderActiveChallengeCard(ch = {}) {
  const total = Math.max(0, Number(ch.scenarios_total || 0));
  const done = Math.max(0, Number(ch.scenarios_completed || 0));
  const pct = total ? Math.min(100, Math.round((done / total) * 100)) : (ch.earned ? 100 : 0);
  const earned = !!ch.earned;

  const timeGoal = Number(ch.time_goal_minutes || 0);
  const timeDone = timeGoal ? Math.min(Math.round((ch.challenge_ce_seconds || 0) / 60), timeGoal) : 0;
  const timePct  = timeGoal ? Math.min(100, Math.round((timeDone / timeGoal) * 100)) : 0;
  const timeRemaining = timeGoal ? Math.max(0, timeGoal - timeDone) : 0;
  const timeBar = timeGoal ? `
    <div class="mt-3">
      <div class="flex items-center justify-between text-[0.7rem] text-gray-500 mb-1">
        <span>Time</span>
        <span>${_fmtMinutes(Math.min(timeDone, timeGoal))} of ${_fmtMinutes(timeGoal)}${timeRemaining > 0 ? ` · ${_fmtMinutes(timeRemaining)} remaining` : " · Goal reached"}</span>
      </div>
      <div class="h-1.5 rounded-full bg-gray-200 overflow-hidden border border-gray-200">
        <div class="h-full ${earned ? "bg-green-400" : "bg-blue-400"} rounded-full transition-all" style="width:${timePct}%"></div>
      </div>
    </div>` : "";
  const repeatBadge = ch.repeatable
    ? `<span class="shrink-0 text-[0.68rem] font-bold uppercase tracking-wider px-2 py-1 rounded-full bg-sky-100 text-sky-800 border border-sky-200">Repeatable</span>`
    : "";
  const attemptText = _challengeAttemptStatusText(ch);

  return `
    <button type="button" data-challenge-detail-id="${escapeHTML(ch.id)}" class="block w-full text-left rounded-2xl border ${earned ? "border-green-300 bg-green-50 hover:border-green-500" : "border-gray-200 bg-white hover:border-amber-400"} p-4 shadow-sm transition-colors focus:outline-none focus:ring-2 focus:ring-amber-500/40">
      <div class="flex items-start gap-3">
        <div class="w-12 h-12 rounded-2xl ${earned ? "bg-green-100 border-green-200" : "bg-amber-100 border-amber-200"} border flex items-center justify-center text-2xl shrink-0">
          ${escapeHTML(ch.icon || "🏅")}
        </div>
        <div class="min-w-0 flex-1">
          <div class="flex items-start justify-between gap-3">
            <div class="min-w-0">
              <h3 class="text-gray-950 font-bold text-sm leading-tight">${escapeHTML(ch.name || "Agency Challenge")}</h3>
              ${ch.description ? `<p class="text-gray-600 text-xs mt-1 leading-relaxed">${escapeHTML(ch.description)}</p>` : ""}
            </div>
            <span class="shrink-0 text-[0.68rem] font-bold uppercase tracking-wider px-2 py-1 rounded-full ${earned ? "bg-green-100 text-green-800 border border-green-200" : "bg-amber-100 text-amber-800 border border-amber-200"}">
              ${earned ? "Earned" : "Active"}
            </span>
            ${repeatBadge}
          </div>

          <div class="mt-4">
            <div class="flex items-center justify-between text-[0.7rem] text-gray-500 mb-1">
              <span>Progress</span>
              <span>${done}/${total || 0} · ${pct}%</span>
            </div>
            <div class="h-2 rounded-full bg-gray-200 overflow-hidden border border-gray-200">
              <div class="h-full ${earned ? "bg-green-500" : "bg-amber-500"} rounded-full transition-all" style="width:${pct}%"></div>
            </div>
          </div>

          ${timeBar}

          <div class="mt-4 flex items-center justify-between gap-3 text-xs">
            <span class="text-gray-500">${attemptText || (total ? `${Math.min(done, total)} done · ${Math.max(0, total - done)} remaining` : "Open details for requirements")}</span>
            <span class="text-amber-700 font-semibold">View requirements -></span>
          </div>
        </div>
      </div>
    </button>
  `;
}

function _renderActiveChallengesModal() {
  const body = el("active-challenges-body");
  const summary = el("active-challenges-summary");
  if (!body) return;
  const active = _activeChallengesForDisplay();
  const open = active.filter(ch => !ch?.earned).length;
  if (summary) {
    summary.textContent = !active.length
      ? "No active agency challenges are available right now."
      : `${active.length} active · ${open} not yet earned`;
  }
  if (!active.length) {
    body.innerHTML = `
      <div class="rounded-2xl border border-gray-200 bg-white p-5 text-center shadow-sm">
        <div class="text-3xl mb-2">🎯</div>
        <h3 class="text-gray-950 font-bold text-sm">No active challenges right now</h3>
        <p class="text-gray-600 text-sm mt-2 leading-relaxed">When your agency publishes a challenge, it will show up here with your progress.</p>
      </div>
    `;
    return;
  }
  body.innerHTML = `<div class="space-y-3">${active.map(_renderActiveChallengeCard).join("")}</div>`;
}

function _renderChallengeDetail(ch = {}) {
  const body = el("active-challenges-body");
  const summary = el("active-challenges-summary");
  if (!body) return;
  const total = Math.max(0, Number(ch.scenarios_total || 0));
  const done = Math.max(0, Number(ch.scenarios_completed || 0));
  const pct = total ? Math.min(100, Math.round((done / total) * 100)) : (ch.earned ? 100 : 0);
  if (summary) summary.textContent = `${done}/${total || 0} complete · ${pct}%`;
  const repeatBadge = ch.repeatable
    ? `<span class="shrink-0 text-[0.68rem] font-bold uppercase tracking-wider px-2 py-1 rounded-full bg-sky-100 text-sky-800 border border-sky-200">Repeatable</span>`
    : "";
  const canStartRepeat = ch.repeatable && (!ch.attempt || ch.attempt.status === "completed" || ch.attempt.status === "cancelled");
  const startLabel = ch.attempt?.status === "completed" ? "Start Again" : "Start Challenge";
  const attemptText = _challengeAttemptStatusText(ch);
  const repeatAction = ch.repeatable ? `
    <div class="mt-4 flex flex-wrap items-center justify-between gap-3 rounded-xl border border-sky-200 bg-sky-50 px-3 py-3">
      <div>
        <div class="text-sky-950 text-sm font-semibold">${escapeHTML(attemptText)}</div>
        <div class="text-sky-700 text-xs mt-0.5">Only work completed after an attempt starts counts for that run.</div>
      </div>
      ${canStartRepeat ? `<button type="button" data-challenge-start="${escapeHTML(ch.id)}" class="text-xs font-bold text-white bg-sky-700 hover:bg-sky-600 rounded-lg px-3 py-2 transition-colors">${startLabel}</button>` : ""}
    </div>` : "";
  const reqs = Array.isArray(ch.requirements_progress) ? ch.requirements_progress : [];
  const reqHtml = reqs.length
    ? reqs.map((req, idx) => {
      const scenarioIds = Array.isArray(req.scenario_ids) ? req.scenario_ids : [];
      const drillIds = Array.isArray(req.drill_ids) ? req.drill_ids : [];
      const customItems = Array.isArray(req.custom_items) ? req.custom_items : [];
      const completedIds = new Set(Array.isArray(req.completed_ids) ? req.completed_ids.map(String) : []);
      const completedDrillIds = new Set(Array.isArray(req.completed_drill_ids) ? req.completed_drill_ids.map(String) : []);
      const needed = Math.max(0, Number(req.needed || 0));
      const completed = Math.min(Math.max(0, Number(req.completed || 0)), needed);
      const groupComplete = needed > 0 && completed >= needed;
      const itemHtml = [
        ...customItems.map(item => {
          const complete = !!item.complete;
          return `<li class="flex items-start gap-3 rounded-xl border ${complete ? "border-green-300 bg-green-50" : "border-gray-200 bg-white"} px-3 py-2">
            <span class="mt-0.5 text-sm ${complete ? "text-green-700" : "text-gray-400"}">${complete ? "✓" : "○"}</span>
            <span class="min-w-0 flex-1">
              <span class="block text-sm ${complete ? "text-green-950" : "text-gray-800"}">${escapeHTML(item.label || "Requirement")}</span>
              <span class="block text-[0.68rem] uppercase tracking-wider ${complete ? "text-green-700" : "text-gray-500"}">${escapeHTML(item.status || (complete ? "Complete" : "Not complete"))}</span>
            </span>
          </li>`;
        }),
        ...scenarioIds.map(id => {
          const complete = completedIds.has(String(id));
	          return `<li class="flex items-start gap-3 rounded-xl border ${complete ? "border-green-300 bg-green-50" : "border-gray-200 bg-white"} px-3 py-2">
	            <span class="mt-0.5 text-sm ${complete ? "text-green-700" : "text-gray-400"}">${complete ? "✓" : "○"}</span>
	            <span class="min-w-0 flex-1">
	              <span class="block text-sm ${complete ? "text-green-950" : "text-gray-800"}">${escapeHTML(_challengeScenarioTitle(id, req, complete))}</span>
	              <span class="block text-[0.68rem] uppercase tracking-wider ${complete ? "text-green-700" : "text-gray-500"}">${complete ? "Completed" : "Not completed"}</span>
	            </span>
	          </li>`;
	        }),
        ...drillIds.map(id => {
          const complete = completedDrillIds.has(String(id));
          return `<li class="flex items-start gap-3 rounded-xl border ${complete ? "border-green-300 bg-green-50" : "border-gray-200 bg-white"} px-3 py-2">
            <span class="mt-0.5 text-sm ${complete ? "text-green-700" : "text-gray-400"}">${complete ? "✓" : "○"}</span>
            <span class="min-w-0 flex-1">
              <span class="block text-sm ${complete ? "text-green-950" : "text-gray-800"}">${escapeHTML(_challengeDrillTitle(id))}</span>
              <span class="block text-[0.68rem] uppercase tracking-wider ${complete ? "text-green-700" : "text-gray-500"}">${complete ? "Completed drill" : "Not completed"}</span>
            </span>
          </li>`;
        }),
      ].join("") || `<li class="text-sm text-gray-500">No scenarios or drills listed for this requirement.</li>`;

	      return `
	        <section class="rounded-2xl border ${groupComplete ? "border-green-300 bg-green-50/70" : "border-gray-200 bg-white"} p-4 shadow-sm">
	          <div class="flex items-start justify-between gap-3 mb-3">
	            <div>
	              <h4 class="text-gray-950 font-bold text-sm">Requirement ${idx + 1}</h4>
	              <p class="text-gray-600 text-xs mt-1">${escapeHTML(_challengeRequirementText(req))}</p>
	            </div>
	            <span class="shrink-0 text-[0.68rem] font-bold uppercase tracking-wider px-2 py-1 rounded-full ${groupComplete ? "bg-green-100 text-green-800 border border-green-200" : "bg-gray-100 text-gray-700 border border-gray-200"}">
	              ${groupComplete ? "Done" : `${completed}/${needed}`}
	            </span>
	          </div>
          <ul class="space-y-2">${itemHtml}</ul>
        </section>
      `;
    }).join("")
	    : `<div class="rounded-2xl border border-gray-200 bg-white p-4 text-sm text-gray-600">No requirements were listed for this challenge.</div>`;

	  body.innerHTML = `
	    <div class="space-y-4">
	      <button type="button" data-challenge-back class="text-xs text-gray-700 hover:text-gray-950 border border-gray-300 hover:border-gray-500 rounded-lg px-3 py-1.5 transition-colors bg-white">← All challenges</button>
	      <div class="rounded-2xl border ${ch.earned ? "border-green-300 bg-green-50" : "border-amber-300 bg-white"} p-5 shadow-sm">
	        <div class="flex items-start gap-3">
	          <div class="w-12 h-12 rounded-2xl ${ch.earned ? "bg-green-100 border-green-200" : "bg-amber-100 border-amber-200"} border flex items-center justify-center text-2xl shrink-0">${escapeHTML(ch.icon || "🏅")}</div>
	          <div class="min-w-0 flex-1">
	            <div class="flex items-start justify-between gap-3">
	              <div>
	                <h3 class="text-gray-950 font-bold text-base leading-tight">${escapeHTML(ch.name || "Agency Challenge")}</h3>
	                ${ch.description ? `<p class="text-gray-600 text-sm mt-1 leading-relaxed">${escapeHTML(ch.description)}</p>` : ""}
	              </div>
	              <span class="shrink-0 text-[0.68rem] font-bold uppercase tracking-wider px-2 py-1 rounded-full ${ch.earned ? "bg-green-100 text-green-800 border border-green-200" : "bg-amber-100 text-amber-800 border border-amber-200"}">
	                ${ch.earned ? "Earned" : "Active"}
	              </span>
                ${repeatBadge}
	            </div>
	            <div class="mt-4">
	              <div class="flex items-center justify-between text-[0.72rem] text-gray-500 mb-1">
	                <span>Overall progress</span>
	                <span>${done}/${total || 0} · ${pct}%</span>
	              </div>
	              <div class="h-2 rounded-full bg-gray-200 overflow-hidden border border-gray-200">
	                <div class="h-full ${ch.earned ? "bg-green-500" : "bg-amber-500"} rounded-full transition-all" style="width:${pct}%"></div>
	              </div>
            </div>
            ${(() => {
              const tg = Number(ch.time_goal_minutes || 0);
              if (!tg) return "";
              const td = Math.min(Math.round((ch.challenge_ce_seconds || 0) / 60), tg);
              const tp = Math.min(100, Math.round((td / tg) * 100));
              const tr = Math.max(0, tg - td);
              return `<div class="mt-3">
                <div class="flex items-center justify-between text-[0.72rem] text-gray-500 mb-1">
                  <span>Time goal</span>
                  <span>${_fmtMinutes(Math.min(td, tg))} of ${_fmtMinutes(tg)}${tr > 0 ? ` · ${_fmtMinutes(tr)} remaining` : " · Goal reached"}</span>
                </div>
                <div class="h-2 rounded-full bg-gray-200 overflow-hidden border border-gray-200">
                  <div class="h-full ${ch.earned ? "bg-green-400" : "bg-blue-400"} rounded-full transition-all" style="width:${tp}%"></div>
                </div>
              </div>`;
            })()}
            ${repeatAction}
          </div>
        </div>
      </div>
      <div class="space-y-3">${reqHtml}</div>
    </div>
  `;
}

async function _openActiveChallengesModal() {
  show("modal-active-challenges");
  const body = el("active-challenges-body");
  const summary = el("active-challenges-summary");
  _readChallengesCache();
  const hadCache = Array.isArray(_challengesCache);
  if (hadCache) {
    _renderActiveChallengesModal();
    if (summary) summary.textContent += " · refreshing...";
  } else {
    if (body) body.innerHTML = `<div class="rounded-2xl border border-gray-200 bg-white p-5 text-gray-700 text-sm shadow-sm">Loading active challenges…</div>`;
    if (summary) summary.textContent = "Loading agency challenges…";
  }
  try {
    await _loadChallenges();
    _buildChallengesSection();
    _renderActiveChallengesModal();
  } catch (err) {
    if (state.scormEnabled && _scormPassChallengeForDisplay()) {
      _renderActiveChallengesModal();
      if (summary) summary.textContent += " · agency challenges unavailable";
      return;
    }
    if (summary) summary.textContent = "Could not load challenges.";
    if (body) {
      body.innerHTML = `
        <div class="rounded-2xl border border-red-800 bg-red-950/40 p-5">
          <h3 class="text-red-100 font-bold text-sm">Challenges could not load</h3>
          <p class="text-red-200/80 text-sm mt-2">${escapeHTML(err?.message || err || "Unknown error")}</p>
        </div>
      `;
    }
  }
}

async function _startRepeatableChallenge(challengeId, btn = null) {
  if (!challengeId) return;
  const original = btn?.textContent;
  if (btn) {
    btn.disabled = true;
    btn.textContent = "Starting...";
  }
  try {
    const r = await authFetch(`${API}/api/challenges/${encodeURIComponent(challengeId)}/attempts`, {
      method: "POST",
    });
    if (!r.ok) {
      const err = await r.json().catch(() => ({}));
      throw new Error(err.detail || r.statusText || "Could not start challenge.");
    }
    await _loadChallenges();
    _buildChallengesSection();
    const challenge = (_challengesCache || []).find(ch => String(ch.id) === String(challengeId));
    if (challenge) _renderChallengeDetail(challenge);
    showToast("Challenge attempt started.", "success");
  } catch (err) {
    showToast(err?.message || String(err), "error");
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.textContent = original || "Start Challenge";
    }
  }
}

el("btn-nav-lexi-challenge")?.addEventListener("click", _openLexiChallenge);

// Right-panel recent-call cards route through the history debrief modal without
// using capture-phase click interception, which can swallow unrelated controls.
document.addEventListener("click", (e) => {
  const historyCard = e.target.closest?.("[data-history-debrief-key]");
  if (!historyCard) return;
  if (e.target.closest?.("button, a, input, select, textarea, [role='button']")) return;
  const key = historyCard.dataset.historyDebriefKey;
  if (!key) return;
  e.preventDefault();
  _openLastResultsByKey(key);
});

