function _lexiPick(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

// ── Lexi status ───────────────────────────────────────────────────────────────

async function _loadDrillStatus() {
  try {
    const r = await authFetch(`${API}/api/me/drills/status`);
    _drillStatus = r.ok ? await r.json() : null;
  } catch {
    _drillStatus = null;
  }
  _updateRandomDrillCard();
  buildBadgesSection(loadGamification());
}

async function _loadRcStatus() {
  try {
    const r = await authFetch(`${API}/api/me/random-call/status`);
    _rcStatus = r.ok ? await r.json() : null;
  } catch {
    _rcStatus = null;
  }
  _updateRandomCallCard();
}

async function _loadLexiStatus() {
  try {
    const r = await authFetch(`${API}/api/me/lexi-status`);
    _lexiStatus = r.ok ? await r.json() : null;
  } catch {
    _lexiStatus = null;
  }
  _updateLexiCard();
}

function _updateLexiCard() {
  const statusEl = el("nav-lexi-status");
  if (!statusEl) return;
  if (!_lexiStatus) { statusEl.textContent = ""; return; }
  const cap       = _lexiStatus.daily_cap ?? 3;
  const remaining = Math.max(0, cap - (_lexiStatus.rounds_today || 0));
  const best      = _lexiStatus.best_score ?? 0;
  const parts     = [];
  if (remaining > 0) parts.push(`${remaining} round${remaining !== 1 ? "s" : ""} remaining today`);
  else               parts.push("Come back tomorrow for more XP");
  if (_lexiStatus.total_rounds > 0) parts.push(`Best: ${best}/5`);
  statusEl.textContent = parts.join(" · ");
}

function _updateRandomDrillCard() {
  const btn = el("btn-random-drill");
  const statusEl = el("random-drill-card-status");
  if (!btn || !statusEl) return;

  if (!_drillStatus) {
    btn.disabled = true;
    statusEl.textContent = "Loading drill status…";
    return;
  }

  const unlocked = _drillStatus.unlocked_count || 0;
  const minReq = _drillStatus.min_required || 5;
  const xpToday = _drillStatus.xp_today || 0;
  const cap = _drillStatus.daily_cap_xp || 0;
  const available = !!_drillStatus.random_available;

  btn.disabled = !available;
  if (available) {
    btn.classList.remove("opacity-70");
    statusEl.textContent = `${unlocked} unlocked · ${xpToday}/${cap} XP today`;
  } else {
    btn.classList.add("opacity-70");
    statusEl.textContent = `Unlock ${Math.max(0, minReq - unlocked)} more scenarios to play (${unlocked}/${minReq})`;
  }
}

function _updateRandomCallCard() {
  const btn = el("btn-random-call");
  const statusEl = el("random-call-card-status");
  if (!btn || !statusEl) return;

  if (!_rcStatus) {
    btn.disabled = true;
    statusEl.textContent = "Loading…";
    return;
  }

  const completed = _rcStatus.completed_count || 0;
  const minReq    = _rcStatus.min_required    || 5;
  const xpToday   = _rcStatus.xp_today        || 0;
  const cap       = _rcStatus.daily_cap_xp    || 600;
  const eligible  = !!_rcStatus.eligible;

  btn.disabled = !eligible;
  if (eligible) {
    btn.classList.remove("opacity-70");
    statusEl.textContent = `${completed} scenarios · ${xpToday}/${cap} XP today`;
  } else {
    btn.classList.add("opacity-70");
    statusEl.textContent = `Complete ${Math.max(0, minReq - completed)} more scenarios to unlock (${completed}/${minReq})`;
  }
}

async function startRandomQuickDrill() {
  try {
    const res = await authFetch(`${API}/api/me/drills/random/start`, { method: "POST" });
    if (!res.ok) {
      let msg = "Quick drill unavailable right now.";
      try {
        const err = await res.json();
        if (err?.detail) msg = err.detail;
      } catch {}
      showToast(msg, "warning");
      await _loadDrillStatus();
      return;
    }
    const data = await res.json();
    const scenRes = await authFetch(`${API}/api/scenarios/${data.scenario_id}`);
    if (!scenRes.ok) {
      showToast("Couldn't load the selected drill scenario.", "error");
      return;
    }
    state.sessionId = data.session_id;
    state.startTime = new Date(_toEpochMs(data.started_at, Date.now()));
    state.simTimersStarted = false;
    state.scenarioId = data.scenario_id;
    state.scenarioData = _prepareScenarioDataForRuntime(await scenRes.json());
    state.dispatchQuickDrillOnly = true;
    _sessionActiveTimer.start();
    showDispatch();
  } catch {
    showToast("Connection error starting quick drill.", "error");
  }
}

async function startRandomCall(forcedScenarioId = null) {
  try {
    const body = forcedScenarioId ? JSON.stringify({ forced_scenario_id: forcedScenarioId }) : undefined;
    const res = await authFetch(`${API}/api/me/random-call/start`, {
      method: "POST",
      ...(body ? { headers: { "Content-Type": "application/json" }, body } : {}),
    });
    if (!res.ok) {
      let msg = "Random Call unavailable right now.";
      try {
        const err = await res.json();
        if (err?.detail) msg = err.detail;
      } catch {}
      showToast(msg, "warning");
      await _loadRcStatus();
      return;
    }
    const data = await res.json();
    const scenRes = await authFetch(`${API}/api/scenarios/${data.scenario_id}`);
    if (!scenRes.ok) {
      showToast("Couldn't load the selected scenario.", "error");
      return;
    }
    state.sessionId    = data.session_id;
    state.startTime    = new Date(_toEpochMs(data.started_at, Date.now()));
    state.simTimersStarted = false;
    state.scenarioId   = data.scenario_id;
    state.scenarioData = _prepareScenarioDataForRuntime(await scenRes.json());
    state.isRandomCall = true;
    _sessionActiveTimer.start();
    showDispatch();
  } catch {
    showToast("Connection error starting Random Call.", "error");
  }
}

// ── Game state ────────────────────────────────────────────────────────────────

let _lexiGame = {
  questions:    [],
  currentIdx:   0,
  score:        0,
  results:      [],   // true/false/'timeout' per question
  timerHandle:  null,
  answered:     false,
};

function _lexiQuestionKey(q = {}) {
  const question = String(q.question || "").trim().toLowerCase();
  const options = Array.isArray(q.options) ? q.options.map(o => String(o || "").trim().toLowerCase()).join(" | ") : "";
  return `${question} || ${options}`;
}

let _lexiGroup = {
  active: false,
  sessionId: null,
  roomCode: "",
  ws: null,
  pollTimer: null,
  state: null,
  answeredCurrent: false,
  pendingFeedbackReady: false,
  pendingNextRoundReady: false,
  feedbackCountdown: null,
  renderedQuestionKey: null,
  renderedFeedbackKey: null,
  resultsCountdown: null,
  creating: false,
  joining: false,
  starting: false,
  lastStateAt: 0,
  lastStateSource: "",
  lastStateVersionMs: 0,
  syncHintTimer: null,
  removedNotified: false,
  isTeamChallenge: false,
};

let _lexiTeam = {
  // Default visible until explicitly disabled by server feature flag.
  enabled: true,
  checkedFeature: false,
  featureCheckedAt: 0,
  teamId: null,
  teamData: null,
  matchId: null,
  liveTeams: [],
  incomingInvites: [],
  myMatch: null,
  selectedTargets: new Set(),
  pollTimer: null,
  lastIncomingSweepSig: "",
  lastPresenceSentAt: 0,
  presenceInFlight: false,
  refreshInFlight: false,
};

const _LEXI_TEAM_FEATURE_TTL_MS = 5 * 60 * 1000;

const _LEXI_GROUP_DEBUG = (() => {
  try {
    const qs = new URLSearchParams(window.location.search);
    if (qs.get("debug") === "1") return true;
    const stored = localStorage.getItem("lexi_group_debug");
    return stored === "1" || stored === "true";
  } catch {
    return false;
  }
})();

function _lexiStopGroupSyncHintTimer() {
  if (_lexiGroup.syncHintTimer) {
    clearInterval(_lexiGroup.syncHintTimer);
    _lexiGroup.syncHintTimer = null;
  }
}

function _lexiRenderGroupSyncHint(stateData = _lexiGroup.state) {
  const lobbyEl = el("lexi-group-sync-hint-lobby");
  const resultsEl = el("lexi-group-sync-hint-results");
  if (!_LEXI_GROUP_DEBUG) {
    if (lobbyEl) lobbyEl.textContent = "";
    if (resultsEl) resultsEl.textContent = "";
    return;
  }
  const ts = _lexiGroup.lastStateAt || 0;
  const source = _lexiGroup.lastStateSource || "unknown";
  const phase = stateData?.phase || "—";
  const ageSec = ts > 0 ? Math.max(0, Math.floor((Date.now() - ts) / 1000)) : null;
  const text = ts > 0
    ? `Sync: ${phase} · ${ageSec}s ago via ${source}`
    : `Sync: ${phase} · waiting for updates…`;
  if (lobbyEl) lobbyEl.textContent = text;
  if (resultsEl) resultsEl.textContent = text;
}

function _lexiPhaseRank(phase = "") {
  const p = String(phase || "").toLowerCase();
  if (p === "lobby") return 0;
  if (p === "question") return 1;
  if (p === "feedback") return 2;
  if (p === "round_results") return 3;
  if (p === "final_results") return 4;
  return -1;
}

function _isLikelyStaleGroupState(nextState, prevState) {
  if (!nextState || !prevState) return false;
  const nextVersion = Number(nextState.state_version_ms || 0);
  const prevVersion = Number(prevState.state_version_ms || 0);
  if (nextVersion > 0 && prevVersion > 0) {
    if (nextVersion < prevVersion) return true;
    // Equal versions are safe to accept; can arrive via different channels.
  }

  const nextPhase = _lexiPhaseRank(nextState.phase);
  const prevPhase = _lexiPhaseRank(prevState.phase);
  const nextRound = Number(nextState.round_index || 0);
  const prevRound = Number(prevState.round_index || 0);
  const nextQ = Number(nextState.current_question_index || 0);
  const prevQ = Number(prevState.current_question_index || 0);
  const nextPhaseStart = Number(nextState.phase_started_epoch_ms || 0);
  const prevPhaseStart = Number(prevState.phase_started_epoch_ms || 0);
  const isLegitFeedbackAdvance =
    nextRound === prevRound &&
    prevPhase === 2 && nextPhase === 1 &&
    nextQ > prevQ;

  if (nextRound < prevRound) return true;
  if (nextRound === prevRound && nextPhase < prevPhase && !isLegitFeedbackAdvance) return true;
  if (nextRound === prevRound && nextPhase === prevPhase && nextQ < prevQ) return true;
  if (nextRound === prevRound && nextPhase === prevPhase && nextPhaseStart > 0 && prevPhaseStart > 0 && nextPhaseStart < prevPhaseStart) {
    return true;
  }

  const nextParticipants = Array.isArray(nextState.participants) ? nextState.participants.length : 0;
  const prevParticipants = Array.isArray(prevState.participants) ? prevState.participants.length : 0;
  const sameCohortSize = nextParticipants === prevParticipants;

  if (sameCohortSize && nextRound === prevRound && nextPhase === prevPhase && nextQ === prevQ) {
    if (nextPhase === 1 && (Number(nextState.answer_count || 0) < Number(prevState.answer_count || 0))) return true;
    if (nextPhase === 2 && (Number(nextState.feedback_ready_count || 0) < Number(prevState.feedback_ready_count || 0))) return true;
    if (nextPhase === 3 && (Number(nextState.next_round_ready_count || 0) < Number(prevState.next_round_ready_count || 0))) return true;
  }

  return false;
}

let _lexiStatusRefreshAt = 0;

function _refreshLexiStatusAndMenu(force = false) {
  const now = Date.now();
  if (!force && (now - _lexiStatusRefreshAt) < 2500) return;
  _lexiStatusRefreshAt = now;
  _loadLexiStatus();
  _loadProgressFromServer().then(() => {
    if (!el("screen-menu")?.classList.contains("hidden")) buildMenu();
    _refreshScormSummary().catch(() => {});
  }).catch(() => {});
}

function _lexiScreen(name) {
  ["intro", "group-lobby", "team-lobby", "loading", "question", "feedback", "outro", "group-results"].forEach(s => {
    const el2 = el(`lexi-screen-${s}`);
    if (el2) el2.classList.toggle("hidden", s !== name);
  });
}

function _showLexiNoticeModal(message, title = "Group Challenge Update") {
  const existing = document.getElementById("lexi-notice-modal");
  if (existing) existing.remove();
  const wrap = document.createElement("div");
  wrap.id = "lexi-notice-modal";
  wrap.className = "fixed inset-0 bg-black/80 flex items-center justify-center p-4 z-[95]";
  wrap.innerHTML = `
    <div class="w-full max-w-sm bg-gray-900 border border-gray-700 rounded-xl p-4 shadow-2xl">
      <div class="text-white font-semibold text-base mb-2">${escapeHTML(title)}</div>
      <div class="text-gray-300 text-sm leading-relaxed mb-4">${escapeHTML(message)}</div>
      <button id="btn-lexi-notice-ok" class="w-full bg-amber-600 hover:bg-amber-500 text-white font-semibold py-2 rounded-lg transition-colors ui-btn ui-btn--amber">OK</button>
    </div>
  `;
  document.body.appendChild(wrap);
  wrap.querySelector("#btn-lexi-notice-ok")?.addEventListener("click", () => wrap.remove());
}

function _lexiHandleGroupRemoval(message = "You were removed from this group challenge by the host.") {
  if (_lexiGroup.removedNotified) return;
  _lexiGroup.removedNotified = true;
  _lexiGroupCleanupWs();
  _lexiGroup.active = false;
  _lexiGroup.sessionId = null;
  _lexiGroup.roomCode = "";
  _lexiGroup.state = null;
  _lexiGroup.answeredCurrent = false;
  _lexiGroup.pendingFeedbackReady = false;
  _lexiGroup.pendingNextRoundReady = false;
  _lexiGroup.renderedQuestionKey = null;
  _lexiGroup.renderedFeedbackKey = null;
  if (_lexiGroup.feedbackCountdown) clearInterval(_lexiGroup.feedbackCountdown);
  _lexiGroup.feedbackCountdown = null;
  if (_lexiGroup.resultsCountdown) clearInterval(_lexiGroup.resultsCountdown);
  _lexiGroup.resultsCountdown = null;
  _lexiResetGroupLobbyUi();
  _lexiScreen("intro");
  const introStatus = el("lexi-intro-status");
  if (introStatus) {
    introStatus.innerHTML = `<span class="text-amber-400">${escapeHTML(message)}</span>`;
  }
  _showLexiNoticeModal(message, "You Left the Group");
  showToast(message, "warning");
}

async function _loadTeamChallengeFeatureFlag(opts = {}) {
  const force = !!opts.force;
  const fresh = _lexiTeam.checkedFeature && (Date.now() - Number(_lexiTeam.featureCheckedAt || 0)) < _LEXI_TEAM_FEATURE_TTL_MS;
  if (fresh && !force) return _lexiTeam.enabled;
  try {
    const r = await authFetch(`${API}/api/me`);
    if (r.ok) {
      const me = await r.json();
      state.features = me?.features || state.features || {};
      _lexiTeam.enabled = !!(me?.features?.team_challenge_enabled);
      _lexiTeam.checkedFeature = true;
      _lexiTeam.featureCheckedAt = Date.now();
    } else {
      // Keep prior visible state on transient auth/API issues.
      _lexiTeam.checkedFeature = false;
    }
  } catch {
    // Don't stick in "disabled" on transient network/auth hiccups (Safari is more sensitive here).
    _lexiTeam.checkedFeature = false;
  }
  return _lexiTeam.enabled;
}

function _seedTeamChallengeFeatureFlagFromState() {
  if (!state.features || !Object.prototype.hasOwnProperty.call(state.features, "team_challenge_enabled")) return;
  _lexiTeam.enabled = !!state.features.team_challenge_enabled;
  _lexiTeam.checkedFeature = true;
  _lexiTeam.featureCheckedAt = Date.now();
}

function _renderTeamModeAvailability() {
  const btn = _ensureTeamModeButton();
  if (!btn) return;
  btn.classList.toggle("hidden", !_lexiTeam.enabled);
}

function _ensureTeamModeButton() {
  let btn = el("btn-lexi-team-mode");
  if (!btn) {
    const actions = document.querySelector("#modal-lexi-challenge .lexi-intro-actions");
    if (!actions) return null;
    btn = document.createElement("button");
    btn.id = "btn-lexi-team-mode";
    btn.className = "hidden w-full bg-violet-700 hover:bg-violet-600 text-white font-bold py-3 rounded-xl text-sm transition-colors lexi-btn ui-btn ui-btn--full";
    btn.innerHTML = "👥 Team Challenge";
    const cancelBtn = el("btn-lexi-cancel");
    if (cancelBtn && cancelBtn.parentElement === actions) actions.insertBefore(btn, cancelBtn);
    else actions.appendChild(btn);
  }
  if (!btn.dataset.teamModeBound) {
    btn.addEventListener("click", _openTeamChallengeLobby);
    btn.dataset.teamModeBound = "1";
  }
  return btn;
}

function _renderTeamMyTeam(teamData = null) {
  const box = el("lexi-team-my-team");
  if (!box) return;
  if (!teamData) {
    box.innerHTML = "No active team yet.";
    return;
  }
  const status = teamData.status ? ` · ${escapeHTML(teamData.status)}` : "";
  const code = teamData.join_code ? `<span class="text-violet-300 ml-2">${escapeHTML(teamData.join_code)}</span>` : "";
  const crown = teamData.is_creator ? `<span class="text-amber-400 ml-1" title="Team Captain">👑</span>` : "";
  box.innerHTML = `<span class="font-semibold">${escapeHTML(teamData.name || "Team")}${crown}</span>${status}${code}`;
}

function _renderTeamRoster(teamDetail = null) {
  const list = el("team-roster-list");
  if (!list) return;
  if (!teamDetail || !Array.isArray(teamDetail.members) || !teamDetail.members.length) {
    list.innerHTML = `<p class="text-gray-500">No active team roster.</p>`;
    return;
  }
  const isCreator = teamDetail.created_by_user_id === state.userId;
  const isForming = teamDetail.status === "forming";
  list.innerHTML = teamDetail.members.map((m) => {
    const captainTag = m.user_id === teamDetail.created_by_user_id ? `<span class="text-amber-300 text-[10px] ml-1" title="Team Captain">👑</span>` : "";
    const repTag = m.is_representative ? `<span class="text-violet-300 text-[10px] ml-1" title="Representative">REP</span>` : "";
    const meTag = m.user_id === state.userId ? `<span class="text-blue-300 text-[10px] ml-1">(you)</span>` : "";
    const canRemove = isCreator && isForming && m.user_id !== state.userId;
    const removeBtn = canRemove
      ? `<button class="team-member-remove text-[10px] px-1.5 py-0.5 rounded bg-red-900/70 hover:bg-red-800 text-red-100" data-user-id="${escapeHTML(m.user_id || "")}" data-display="${escapeHTML(m.display || m.user_id || "Member")}">Remove</button>`
      : "";
    return `<div class="flex items-center justify-between gap-2">
      <span class="truncate">${escapeHTML(m.display || m.user_id)}${captainTag}${repTag}${meTag}</span>
      ${removeBtn}
    </div>`;
  }).join("");
  list.querySelectorAll(".team-member-remove").forEach((btn) => {
    btn.addEventListener("click", () => {
      const uid = btn.getAttribute("data-user-id");
      const display = btn.getAttribute("data-display") || "Member";
      _teamRemoveMember(uid, display);
    });
  });
}

function _teamStopPolling() {
  if (_lexiTeam.pollTimer) {
    clearInterval(_lexiTeam.pollTimer);
    _lexiTeam.pollTimer = null;
  }
}

function _teamStartPolling() {
  _teamStopPolling();
  _lexiTeam.pollTimer = setInterval(() => {
    const teamLobbyVisible = !el("lexi-screen-team-lobby")?.classList.contains("hidden");
    const modalVisible = !el("modal-lexi-challenge")?.classList.contains("hidden");
    if (teamLobbyVisible && modalVisible) _teamRefreshPanels();
  }, 5000);
}

async function _teamRefreshPanels() {
  if (!_lexiTeam.enabled) return;
  if (_lexiTeam.refreshInFlight) return;
  _lexiTeam.refreshInFlight = true;
  const createBtn = el("btn-team-create");
  const joinBtn = el("btn-team-join");
  const lockBtn = el("btn-team-lock");
  const disbandBtn = el("btn-team-disband");
  const leaveBtn = el("btn-team-leave");
  const presenceBtn = el("btn-team-presence");
  const joinMatchBtn = el("btn-team-start-match");

  const liveEl = el("lexi-team-live-list");
  if (liveEl && !liveEl.innerHTML.trim()) liveEl.innerHTML = `<p class="text-gray-500 text-xs">Loading teams…</p>`;
  const incomingEl = el("lexi-team-incoming-list");
  if (incomingEl && !incomingEl.innerHTML.trim()) incomingEl.innerHTML = `<p class="text-gray-500 text-xs">Loading invites…</p>`;
  const hostedEl = el("team-hosted-match-status");
  if (hostedEl && !String(hostedEl.textContent || "").trim()) hostedEl.textContent = "Checking hosted match…";

  try {
    const lobbyRes = await authFetch(`${API}/api/me/team-lobby-state`);
    if (!lobbyRes.ok) {
      if (liveEl) liveEl.innerHTML = `<p class="text-amber-400 text-xs">Could not load team lobby state.</p>`;
      if (incomingEl) incomingEl.innerHTML = `<p class="text-amber-400 text-xs">Could not load team lobby state.</p>`;
      if (hostedEl) hostedEl.textContent = "Could not load hosted match status.";
      return;
    }
    const lobby = await lobbyRes.json().catch(() => ({}));
    const myTeam = lobby?.my_team || null;
    const myTeamDetail = lobby?.my_team_detail || null;
    const myMatch = lobby?.my_match || null;
    _lexiTeam.teamId = myTeam?.id || null;
    _lexiTeam.teamData = myTeamDetail || null;
    _lexiTeam.myMatch = myMatch;

    _renderTeamMyTeam(myTeam);
    _renderTeamRoster(myTeamDetail);

    const hasTeam = !!myTeam?.id;
    const isCreator = !!myTeam?.is_creator;
    const isForming = myTeam?.status === "forming";
    if (createBtn) createBtn.disabled = hasTeam;
    if (joinBtn) joinBtn.disabled = hasTeam;
    if (lockBtn) lockBtn.disabled = !(hasTeam && isCreator && isForming);
    if (disbandBtn) disbandBtn.disabled = !(hasTeam && isCreator);
    if (leaveBtn) leaveBtn.disabled = !(hasTeam && !isCreator && isForming);
    if (presenceBtn) presenceBtn.disabled = !hasTeam;
    const nowMs = Date.now();
    if (
      hasTeam &&
      myTeam?.status === "locked" &&
      !_lexiTeam.presenceInFlight &&
      (nowMs - Number(_lexiTeam.lastPresenceSentAt || 0) >= 15000)
    ) {
      _teamPresence({ silent: true, refresh: false });
    }

    const rows = Array.isArray(lobby?.live_teams) ? lobby.live_teams : [];
    _lexiTeam.liveTeams = rows;
    if (liveEl) {
      const items = rows
        .filter(t => !t.is_my_team)
        .map(t => {
          const checked = _lexiTeam.selectedTargets.has(t.id) ? "checked" : "";
          const unavailable = !t.is_online || !!t.is_busy;
          const disabled = unavailable ? "disabled" : "";
          const statusText = t.is_busy
            ? "<span class='text-amber-400'>in match</span>"
            : (t.is_online ? "<span class='text-emerald-400'>online</span>" : "<span class='text-gray-500'>offline</span>");
          const captain = t.representative_user_id ? `<span class="text-amber-400" title="Team Captain">👑</span>` : "";
          return `<label class="flex items-center justify-between gap-2 bg-gray-900/50 border border-gray-700 rounded-lg px-2 py-1.5">
            <span class="flex items-center gap-2 min-w-0">
              <input type="checkbox" class="team-target-checkbox" data-team-id="${escapeHTML(t.id)}" ${checked} ${disabled} />
              <span class="truncate">${escapeHTML(t.name || "Team")} ${captain} (${t.member_count || 0})</span>
            </span>
            <span class="text-xs">${statusText}</span>
          </label>`;
        });
      liveEl.innerHTML = items.join("") || `<p class="text-gray-500 text-xs">No challenge-ready teams online.</p>`;
      liveEl.querySelectorAll(".team-target-checkbox").forEach((cb) => {
        cb.addEventListener("change", () => {
          const teamId = cb.getAttribute("data-team-id");
          if (!teamId) return;
          if (cb.checked) _lexiTeam.selectedTargets.add(teamId);
          else _lexiTeam.selectedTargets.delete(teamId);
        });
      });
    }

    const invites = Array.isArray(lobby?.incoming_invites) ? lobby.incoming_invites : [];
    const sweep = lobby?.incoming_sweep || {};
    const expiredCount = Number(sweep?.expired_count || 0);
    const canceledCount = Number(sweep?.canceled_count || 0);
    if ((expiredCount > 0 || canceledCount > 0)) {
      const sig = `${expiredCount}:${canceledCount}`;
      if (_lexiTeam.lastIncomingSweepSig !== sig) {
        _lexiTeam.lastIncomingSweepSig = sig;
        const bits = [];
        if (expiredCount > 0) bits.push(`${expiredCount} invite${expiredCount !== 1 ? "s" : ""} expired`);
        if (canceledCount > 0) bits.push(`${canceledCount} invite${canceledCount !== 1 ? "s" : ""} canceled`);
        showToast(`Team updates: ${bits.join(", ")}.`, "info");
      }
    } else {
      _lexiTeam.lastIncomingSweepSig = "";
    }
    _lexiTeam.incomingInvites = invites;
    if (incomingEl) {
      incomingEl.innerHTML = invites.map(inv => {
        const status = String(inv.status || "pending");
        const isPending = status === "pending";
        const statusBadge = isPending
          ? `<span class="text-[10px] uppercase tracking-wide text-amber-300">Pending</span>`
          : `<span class="text-[10px] uppercase tracking-wide text-emerald-300">Accepted</span>`;
        const actions = isPending
          ? `<div class="flex gap-2">
              <button class="team-invite-accept bg-emerald-700 hover:bg-emerald-600 text-white text-xs font-semibold px-2 py-1 rounded" data-invite-id="${escapeHTML(inv.invite_id)}">Accept</button>
              <button class="team-invite-decline bg-gray-700 hover:bg-gray-600 text-gray-200 text-xs font-semibold px-2 py-1 rounded" data-invite-id="${escapeHTML(inv.invite_id)}">Decline</button>
            </div>`
          : `<div class="flex items-center justify-between gap-2">
              <div class="text-xs text-emerald-300">Accepted · waiting for match join/start.</div>
              <button class="team-invite-leave bg-gray-700 hover:bg-gray-600 text-gray-200 text-xs font-semibold px-2 py-1 rounded" data-match-id="${escapeHTML(inv.match_id || "")}">Leave Challenge</button>
            </div>`;
        return `
        <div class="bg-gray-900/50 border border-gray-700 rounded-lg px-2 py-1.5 space-y-1">
          <div class="flex items-center justify-between gap-2">
            <div class="text-sm">${escapeHTML(inv.source_team_name || "Team")} challenged you.</div>
            ${statusBadge}
          </div>
          ${actions}
        </div>
      `;
      }).join("") || `<p class="text-gray-500 text-xs">No active challenges.</p>`;
      incomingEl.querySelectorAll(".team-invite-accept").forEach((btn) => {
        btn.addEventListener("click", () => _teamRespondInvite(btn.getAttribute("data-invite-id"), true));
      });
      incomingEl.querySelectorAll(".team-invite-decline").forEach((btn) => {
        btn.addEventListener("click", () => _teamRespondInvite(btn.getAttribute("data-invite-id"), false));
      });
      incomingEl.querySelectorAll(".team-invite-leave").forEach((btn) => {
        btn.addEventListener("click", () => _teamLeaveAcceptedMatch(btn.getAttribute("data-match-id")));
      });
    }

    const hostedMatch = lobby?.hosted_match || null;
    const match = myMatch || hostedMatch || null;
    const recentNotice = lobby?.recent_notice?.message || "";
    _lexiTeam.matchId = match?.id || null;
    if (hostedEl) {
      if (!match) {
        hostedEl.textContent = recentNotice || "No pending team match yet.";
      } else {
        const joinedCount = Number(match.joined_team_count || 0);
        const acceptedCount = Number(match.accepted_team_count || 0);
        hostedEl.innerHTML = `Match <span class="text-blue-300">${escapeHTML(match.id.slice(0, 8))}</span> · ${escapeHTML(match.status)} · joined <span class="text-emerald-300">${joinedCount}/${acceptedCount}</span>`;
      }
    }
    if (joinMatchBtn) {
      joinMatchBtn.disabled = !match;
      joinMatchBtn.classList.toggle("opacity-60", !match);
      joinMatchBtn.textContent = "Join Live Match";
    }
  } catch {
    if (liveEl) liveEl.innerHTML = `<p class="text-amber-400 text-xs">Connection issue loading teams.</p>`;
    if (incomingEl) incomingEl.innerHTML = `<p class="text-amber-400 text-xs">Connection issue loading invites.</p>`;
    if (hostedEl) hostedEl.textContent = "Connection issue loading hosted match.";
  } finally {
    _lexiTeam.refreshInFlight = false;
  }
}

async function _openTeamChallengeLobby() {
  if (!_lexiTeam.enabled) {
    showToast("Team Challenge mode is disabled right now.", "info");
    return;
  }
  _lexiTeam.selectedTargets = new Set();
  _lexiScreen("team-lobby");
  await _teamRefreshPanels();
  _teamStartPolling();
}

async function _teamCreate() {
  const nameInput = el("team-create-name");
  const name = (nameInput?.value || "").trim();
  if (!name) return;
  try {
    const r = await authFetch(`${API}/api/me/challenge-teams`, {
      method: "POST",
      body: JSON.stringify({ name, challenge_type: "lexi_group", min_members: 2, max_members: 5 }),
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not create team.", "warning");
      return;
    }
    showToast("Team created.", "success");
    _lexiTeam.teamId = data?.team?.id || null;
    if (nameInput) nameInput.value = "";
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue creating team.", "error");
  }
}

async function _teamJoin() {
  const codeInput = el("team-join-code");
  const code = (codeInput?.value || "").trim().toUpperCase();
  if (!code) return;
  try {
    const r = await authFetch(`${API}/api/me/challenge-teams/join`, {
      method: "POST",
      body: JSON.stringify({ join_code: code }),
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not join team.", "warning");
      return;
    }
    if (codeInput) codeInput.value = "";
    showToast("Joined team.", "success");
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue joining team.", "error");
  }
}

async function _teamLock() {
  if (!_lexiTeam.teamId) {
    showToast("Join or create a team first.", "info");
    return;
  }
  try {
    const r = await authFetch(`${API}/api/me/challenge-teams/${encodeURIComponent(_lexiTeam.teamId)}/lock`, {
      method: "POST",
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not lock team.", "warning");
      return;
    }
    showToast("Team locked and challenge-ready.", "success");
    _lexiTeam.lastPresenceSentAt = Date.now();
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue locking team.", "error");
  }
}

async function _teamPresence(opts = {}) {
  const silent = !!opts.silent;
  const shouldRefresh = opts.refresh !== false;
  if (!_lexiTeam.teamId) {
    if (!silent) showToast("No active team.", "info");
    return;
  }
  if (_lexiTeam.presenceInFlight) return;
  _lexiTeam.presenceInFlight = true;
  try {
    const r = await authFetch(`${API}/api/me/challenge-teams/${encodeURIComponent(_lexiTeam.teamId)}/presence`, {
      method: "POST",
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      if (!silent) showToast(data.detail || "Could not update presence.", "warning");
      return;
    }
    _lexiTeam.lastPresenceSentAt = Date.now();
    if (!silent) showToast("Team marked online.", "info");
    if (shouldRefresh) _teamRefreshPanels();
  } catch {
    if (!silent) showToast("Connection issue updating presence.", "error");
  } finally {
    _lexiTeam.presenceInFlight = false;
  }
}

async function _teamDisband() {
  if (!_lexiTeam.teamId) {
    showToast("No active team to disband.", "info");
    return;
  }
  if (!confirm("Disband your current team?")) return;
  try {
    const r = await authFetch(`${API}/api/me/challenge-teams/${encodeURIComponent(_lexiTeam.teamId)}/disband`, { method: "POST" });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not disband team.", "warning");
      return;
    }
    _lexiTeam.teamId = null;
    _lexiTeam.lastPresenceSentAt = 0;
    showToast("Team disbanded.", "info");
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue disbanding team.", "error");
  }
}

async function _teamLeave() {
  if (!_lexiTeam.teamId) {
    showToast("No active team to leave.", "info");
    return;
  }
  if (!confirm("Leave your current team?")) return;
  try {
    const r = await authFetch(`${API}/api/me/challenge-teams/${encodeURIComponent(_lexiTeam.teamId)}/leave`, { method: "POST" });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not leave team.", "warning");
      return;
    }
    _lexiTeam.teamId = null;
    _lexiTeam.teamData = null;
    _lexiTeam.lastPresenceSentAt = 0;
    showToast("Left team.", "info");
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue leaving team.", "error");
  }
}

async function _teamRemoveMember(userId, displayName = "Member") {
  if (!_lexiTeam.teamId || !userId) return;
  if (!confirm(`Remove ${displayName} from your team?`)) return;
  try {
    const r = await authFetch(`${API}/api/me/challenge-teams/${encodeURIComponent(_lexiTeam.teamId)}/remove`, {
      method: "POST",
      body: JSON.stringify({ user_id: userId }),
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not remove member.", "warning");
      return;
    }
    showToast(`${displayName} removed.`, "info");
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue removing member.", "error");
  }
}

async function _teamChallengeSelected() {
  if (!_lexiTeam.teamId) {
    showToast("Create or join a team first.", "info");
    return;
  }
  const targets = Array.from(_lexiTeam.selectedTargets || []);
  if (!targets.length) {
    showToast("Select at least one online team.", "info");
    return;
  }
  const eligible = targets.filter((id) => {
    const t = (_lexiTeam.liveTeams || []).find(x => x.id === id);
    return t && t.is_online && !t.is_busy;
  });
  if (!eligible.length) {
    showToast("Selected teams are no longer available.", "warning");
    return;
  }
  try {
    const r = await authFetch(`${API}/api/me/team-invites`, {
      method: "POST",
      body: JSON.stringify({
        source_team_id: _lexiTeam.teamId,
        target_team_ids: eligible,
        challenge_type: "lexi_group",
        timeout_sec: 60,
      }),
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not send team challenge.", "warning");
      return;
    }
    _lexiTeam.matchId = data.match_id || null;
    showToast(`Challenge sent to ${data.invite_count || eligible.length} team(s).`, "success");
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue sending challenge.", "error");
  }
}

async function _teamRespondInvite(inviteId, accept) {
  if (!inviteId) return;
  try {
    const r = await authFetch(`${API}/api/me/team-invites/${encodeURIComponent(inviteId)}/respond`, {
      method: "POST",
      body: JSON.stringify({ accept: !!accept }),
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not respond to challenge.", "warning");
      return;
    }
    if (accept && data.match_id) _lexiTeam.matchId = data.match_id;
    showToast(accept ? "Challenge accepted." : "Challenge declined.", "info");
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue responding to challenge.", "error");
  }
}

async function _teamLeaveAcceptedMatch(matchId) {
  const id = String(matchId || "").trim();
  if (!id) {
    showToast("No active challenge to leave.", "info");
    return;
  }
  if (!confirm("Leave this accepted challenge?")) return;
  try {
    const r = await authFetch(`${API}/api/me/team-matches/${encodeURIComponent(id)}/leave`, {
      method: "POST",
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not leave challenge.", "warning");
      return;
    }
    showToast("You left the challenge.", "info");
    await _teamRefreshPanels();
  } catch {
    showToast("Connection issue leaving challenge.", "error");
  }
}

async function _teamStartMatch() {
  const matchId = _lexiTeam.matchId || _lexiTeam.myMatch?.id || null;
  if (!matchId) {
    showToast("No active match to join.", "info");
    return;
  }
  try {
    const r = await authFetch(`${API}/api/me/team-matches/${encodeURIComponent(matchId)}/start`, {
      method: "POST",
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok) {
      showToast(data.detail || "Could not join team match.", "warning");
      return;
    }
    if (data?.state) {
      _teamStopPolling();
      _lexiGroup.active = true;
      _lexiGroup.isTeamChallenge = true;
      _lexiGroup.sessionId = data.session_id;
      _lexiGroup.roomCode = data.room_code || "";
      _connectLexiGroupSocket(data.session_id);
      _lexiHandleGroupState(data.state, "http");
      showToast("Joined team match.", "success");
      return;
    }
    if (data?.waiting_team_count > 0) {
      const names = Array.isArray(data.waiting_team_names) ? data.waiting_team_names.filter(Boolean) : [];
      const suffix = names.length ? ` Waiting on: ${names.join(", ")}.` : "";
      showToast(`Joined match queue.${suffix}`, "info");
      _teamRefreshPanels();
      return;
    }
    showToast("Joined match. Waiting for live state…", "info");
    _teamRefreshPanels();
  } catch {
    showToast("Connection issue joining team match.", "error");
  }
}

// ── Open / start ──────────────────────────────────────────────────────────────

function _openLexiChallenge() {
  _teamStopPolling();
  _lexiGroupCleanupWs();
  _lexiGroup.active = false;
  _lexiGroup.sessionId = null;
  _lexiGroup.roomCode = "";
  _lexiGroup.state = null;
  _lexiGroup.removedNotified = false;
  _lexiGroup.answeredCurrent = false;
  _lexiGroup.renderedQuestionKey = null;
  _lexiGroup.renderedFeedbackKey = null;
  if (_lexiGroup.feedbackCountdown) clearInterval(_lexiGroup.feedbackCountdown);
  _lexiGroup.feedbackCountdown = null;
  if (_lexiGroup.resultsCountdown) clearInterval(_lexiGroup.resultsCountdown);
  _lexiGroup.resultsCountdown = null;
  _lexiResetGroupLobbyUi();
  _lexiRenderGroupSyncHint({ phase: "lobby" });
  _lexiScreen("intro");

  // Populate intro status
  const statusEl = el("lexi-intro-status");
  if (statusEl && _lexiStatus) {
    const cap       = _lexiStatus.daily_cap ?? 3;
    const remaining = Math.max(0, cap - (_lexiStatus.rounds_today || 0));
    const perfect   = _lexiStatus.perfect_rounds ?? 0;
    const lines     = [];
    if (remaining > 0)
      lines.push(`<span class="text-amber-700">${remaining} round${remaining !== 1 ? "s" : ""} remaining today</span>`);
    else
      lines.push(`<span class="text-gray-600">XP cap reached — play for practice</span>`);
    if (_lexiStatus.total_rounds > 0)
      lines.push(`<span>${_lexiStatus.total_rounds} total rounds · ${perfect} perfect</span>`);
    statusEl.innerHTML = lines.join("<br>");
  } else if (statusEl) {
    statusEl.innerHTML = "";
  }

  const startBtn = el("btn-lexi-start");
  if (startBtn) startBtn.disabled = false;

  _ensureTeamModeButton();
  _seedTeamChallengeFeatureFlagFromState();
  _renderTeamModeAvailability();
  show("modal-lexi-challenge");
  _loadTeamChallengeFeatureFlag({ force: false }).then(() => _renderTeamModeAvailability());
  _lexiSetAvatarState("encouraging", { autoResetMs: 1200 });
}

function _lexiLeaveGroupSilently() {
  const leavingSessionId = (_lexiGroup.active && _lexiGroup.sessionId) ? _lexiGroup.sessionId : null;
  if (!leavingSessionId) return;
  authFetch(`${API}/api/me/lexi-group/leave`, {
    method: "POST",
    keepalive: true,
    body: JSON.stringify({ session_id: leavingSessionId }),
  }).catch(() => {});
}

function _closeLexiChallengeModal() {
  hide("modal-lexi-challenge");
  if (_lexiGame.timerHandle) {
    clearTimeout(_lexiGame.timerHandle);
    _lexiGame.timerHandle = null;
  }
  _teamStopPolling();
  _lexiLeaveGroupSilently();
  _lexiGroup.active = false;
  _lexiGroup.sessionId = null;
  _lexiGroup.roomCode = "";
  _lexiGroup.state = null;
  _lexiGroup.answeredCurrent = false;
  _lexiGroup.pendingFeedbackReady = false;
  _lexiGroup.pendingNextRoundReady = false;
  _lexiGroup.renderedQuestionKey = null;
  _lexiGroup.renderedFeedbackKey = null;
  _lexiGroup.removedNotified = false;
  if (_lexiGroup.feedbackCountdown) clearInterval(_lexiGroup.feedbackCountdown);
  _lexiGroup.feedbackCountdown = null;
  if (_lexiGroup.resultsCountdown) clearInterval(_lexiGroup.resultsCountdown);
  _lexiGroup.resultsCountdown = null;
  _lexiGroupCleanupWs();
  _refreshLexiStatusAndMenu(true);
  // Safari/network race guard: retry once shortly after close so rounds remaining/XP stay in sync.
  setTimeout(() => _refreshLexiStatusAndMenu(true), 900);
}
window._closeLexiChallengeModal = _closeLexiChallengeModal;

function _lexiGroupCleanupWs() {
  if (_lexiGroup.ws) {
    try { _lexiGroup.ws.close(); } catch {}
  }
  _lexiGroup.ws = null;
  if (_lexiGroup.pollTimer) {
    clearInterval(_lexiGroup.pollTimer);
    _lexiGroup.pollTimer = null;
  }
  _lexiStopGroupSyncHintTimer();
}

function _lexiGroupStartPolling() {
  if (_lexiGroup.pollTimer) {
    clearInterval(_lexiGroup.pollTimer);
    _lexiGroup.pollTimer = null;
  }
  _lexiGroup.pollTimer = setInterval(async () => {
    if (!_lexiGroup.active || !_lexiGroup.sessionId) return;
    try {
      const r = await authFetch(`${API}/api/me/lexi-group/${_lexiGroup.sessionId}`);
      if (!r.ok) {
        if (r.status === 403) {
          _lexiHandleGroupRemoval("You were removed from this group challenge.");
        }
        return;
      }
      const data = await r.json();
      if (data?.state) _lexiHandleGroupState(data.state, "poll");
    } catch { /* ignore polling issues */ }
  }, 1500);
}

function _lexiResetGroupLobbyUi() {
  _lexiGroup.creating = false;
  _lexiGroup.joining = false;
  _lexiGroup.starting = false;
  _lexiGroup.lastStateAt = 0;
  _lexiGroup.lastStateSource = "";
  _lexiGroup.lastStateVersionMs = 0;
  _lexiGroup.removedNotified = false;
  _lexiGroup.isTeamChallenge = false;
  _lexiRenderGroupSyncHint({ phase: "lobby" });
  setText("lexi-group-room-display", "");
  const roster = el("lexi-group-participants");
  if (roster) roster.innerHTML = `<p class="text-gray-500 text-xs">Create a room or enter a code to join.</p>`;
  setText("lexi-group-lobby-note", "Need at least 2 participants to start.");
  const startBtn = el("btn-lexi-group-start");
  if (startBtn) {
    startBtn.disabled = true;
    startBtn.classList.add("opacity-60");
    startBtn.textContent = "Waiting for host…";
  }
  const endBtn = el("btn-lexi-group-end");
  if (endBtn) {
    endBtn.classList.add("hidden");
    endBtn.disabled = false;
    endBtn.classList.remove("opacity-60");
  }
  const roomActions = el("lexi-group-room-actions");
  if (roomActions) roomActions.classList.remove("hidden");
}

function _lexiRenderGroupLobby(stateData) {
  const roomEl = el("lexi-group-room-display");
  if (roomEl) roomEl.textContent = stateData?.room_code || "";
  const roster = el("lexi-group-participants");
  const isHost = !!(stateData?.host_user_id && stateData.host_user_id === state.userId);
  if (roster) {
    const me = state.userId;
    roster.innerHTML = (stateData?.participants || []).map((p, idx) => {
      const meTag = p.user_id === me ? " <span class='text-blue-400'>(you)</span>" : "";
      const hostTag = p.user_id === stateData?.host_user_id ? " <span class='text-amber-500 text-xs ml-1' title='Host'>👑</span>" : "";
      const canKick = isHost && p.user_id !== me;
      const kickBtn = canKick
        ? `<button class="lexi-kick-user text-[11px] text-red-300 hover:text-red-200 border border-red-900/70 hover:border-red-700 rounded px-1.5 py-0.5 transition-colors" data-user-id="${escapeHTML(p.user_id || "")}" data-user-name="${escapeHTML(p.display || p.user_id || "Responder")}">Remove</button>`
        : "";
      return `<div class="flex items-center justify-between">
        <span>${idx + 1}. ${escapeHTML(p.display || p.user_id)}${meTag}${hostTag}</span>
        <span class="flex items-center gap-2">
          <span class="text-gray-500 text-xs">${escapeHTML(p.provider_level || "")}</span>
          ${kickBtn}
        </span>
      </div>`;
    }).join("") || `<p class="text-gray-500 text-xs">No participants yet.</p>`;
    roster.querySelectorAll(".lexi-kick-user").forEach((btn) => {
      btn.addEventListener("click", () => {
        const uid = btn.getAttribute("data-user-id") || "";
        const name = btn.getAttribute("data-user-name") || "Responder";
        _lexiGroupKick(uid, name);
      });
    });
  }
  const note = el("lexi-group-lobby-note");
  const isTeamChallenge = !!_lexiGroup.isTeamChallenge;
  _lexiGroup.isTeamChallenge = isTeamChallenge;
  const roomActions = el("lexi-group-room-actions");
  if (roomActions) roomActions.classList.toggle("hidden", isTeamChallenge);
  if (note) {
    const count = (stateData?.participants || []).length;
    if (isTeamChallenge) {
      note.textContent = count < 2
        ? "Waiting for teams to join this shared match lobby."
        : isHost
          ? `${count} team reps connected. Start when ready.`
          : `${count} team reps connected. Waiting for challenger to start.`;
    } else {
      note.textContent = count < 2
        ? "Need at least 2 participants to start."
        : isHost
          ? `${count} participants ready. You can remove participants or end session from here.`
          : `${count} participants ready.`;
    }
  }
  const startBtn = el("btn-lexi-group-start");
  if (startBtn) {
    startBtn.disabled = _lexiGroup.starting || !isHost || (stateData?.participants || []).length < 2;
    startBtn.classList.toggle("opacity-60", startBtn.disabled);
    if (_lexiGroup.starting) startBtn.textContent = "Starting…";
    else startBtn.textContent = isHost ? "Start Group Challenge" : "Waiting for host…";
  }
  const endBtn = el("btn-lexi-group-end");
  if (endBtn) {
    endBtn.classList.toggle("hidden", !isHost);
    endBtn.disabled = _lexiGroup.starting;
    endBtn.classList.toggle("opacity-60", endBtn.disabled);
  }
  _lexiScreen("group-lobby");
}

async function _lexiGroupKick(userId, displayName = "Responder") {
  if (!_lexiGroup.sessionId || !userId) return;
  if (!confirm(`Remove ${displayName} from this live challenge? They can rejoin with the room code if the host allows it.`)) return;
  try {
    const r = await authFetch(`${API}/api/me/lexi-group/kick`, {
      method: "POST",
      body: JSON.stringify({ session_id: _lexiGroup.sessionId, user_id: userId }),
    });
    if (!r.ok) {
      const err = await r.json().catch(() => ({}));
      showToast(err.detail || "Could not remove participant.", "warning");
      return;
    }
    showToast(`${displayName} was removed from this session.`, "info");
  } catch {
    showToast("Connection error removing participant.", "error");
  }
}

async function _lexiGroupEnd() {
  if (!_lexiGroup.sessionId) return;
  if (!confirm("End this live group challenge for everyone now?")) return;
  const endBtn = el("btn-lexi-group-end");
  if (endBtn) {
    endBtn.disabled = true;
    endBtn.classList.add("opacity-60");
  }
  try {
    const r = await authFetch(`${API}/api/me/lexi-group/end`, {
      method: "POST",
      body: JSON.stringify({ session_id: _lexiGroup.sessionId }),
    });
    if (!r.ok) {
      const err = await r.json().catch(() => ({}));
      showToast(err.detail || "Could not end session.", "warning");
      return;
    }
    showToast("Group challenge session ended.", "info");
  } catch {
    showToast("Connection error ending session.", "error");
  } finally {
    if (endBtn) {
      endBtn.disabled = false;
      endBtn.classList.remove("opacity-60");
    }
  }
}

function _lexiGroupStartTimerBar(endsAtIso) {
  const bar = el("lexi-timer-bar");
  if (!bar) return;
  const now = Date.now();
  const endTs = _toEpochMs(endsAtIso, now + 30000);
  const total = 30000;
  const remainingRaw = endTs - now;
  const remaining = Number.isFinite(remainingRaw) ? Math.max(0, Math.min(total, remainingRaw)) : total;
  const pct = (remaining / total) * 100;
  bar.style.transition = "none";
  bar.style.width = `${pct}%`;
  bar.style.background = "rgb(217,119,6)";
  bar.offsetWidth; // eslint-disable-line
  bar.style.transition = `width ${remaining}ms linear, background ${Math.max(0, remaining - 9000)}ms linear 9000ms`;
  bar.style.width = "0%";
  bar.style.background = "rgb(220,38,38)";
}

function _lexiGroupStartFeedbackBar(endsAtIso) {
  const wrap = el("lexi-feedback-timer-wrap");
  const bar = el("lexi-feedback-timer-bar");
  if (!wrap || !bar) return;
  wrap.classList.remove("hidden");
  const now = Date.now();
  const endTs = _toEpochMs(endsAtIso, now + 30000);
  const total = 30000;
  const remainingRaw = endTs - now;
  const remaining = Number.isFinite(remainingRaw) ? Math.max(0, Math.min(total, remainingRaw)) : total;
  const pct = (remaining / total) * 100;
  bar.style.transition = "none";
  bar.style.width = `${pct}%`;
  bar.style.background = "rgb(59,130,246)";
  bar.offsetWidth; // eslint-disable-line
  bar.style.transition = `width ${remaining}ms linear`;
  bar.style.width = "0%";
}

function _lexiShowGroupQuestion(stateData) {
  const round = stateData.round_index || 1;
  const qIdx = stateData.current_question_index || 0;
  const qKey = `${round}:${qIdx}`;
  const isSameQuestion = _lexiGroup.renderedQuestionKey === qKey && !el("lexi-screen-question")?.classList.contains("hidden");
  const answeredIds = stateData.answered_user_ids || [];
  const myAnswered = answeredIds.includes(state.userId);
  _lexiGroup.answeredCurrent = myAnswered;
  setText("lexi-q-counter", `Round ${round}/${stateData.max_rounds || 3} · Question ${qIdx + 1} of 5`);
  const pipsEl = el("lexi-score-pips");
  if (pipsEl) {
    pipsEl.innerHTML = `<span class="text-gray-500 text-xs">${(stateData.answer_count || 0)} / ${(stateData.participants || []).length} answered</span>`;
  }
  if (isSameQuestion) {
    return;
  }

  _lexiGroup.renderedQuestionKey = qKey;
  _lexiGroup.renderedFeedbackKey = null;
  setText("lexi-question-text", stateData.question?.question || "");
  const answersEl = el("lexi-answers");
  const labels = ["A", "B", "C", "D"];
  const opts = stateData.question?.options || [];
  answersEl.innerHTML = opts.map((opt, i) =>
    `<button class="lexi-ans-btn text-left w-full border text-gray-200 text-sm rounded-xl px-4 py-3 transition-colors"
      onclick="_lexiGroupAnswerSelected(${i})">
      <span class="lexi-ans-label font-bold mr-2">${labels[i]}.</span>${escapeHTML(opt)}
    </button>`
  ).join("");
  if (myAnswered) {
    document.querySelectorAll(".lexi-ans-btn").forEach(btn => { btn.disabled = true; });
  }
  const nextBtn = el("btn-lexi-next");
  if (nextBtn) nextBtn.classList.add("hidden");
  const cd = el("lexi-feedback-countdown");
  if (cd) cd.classList.add("hidden");
  const fbWrap = el("lexi-feedback-timer-wrap");
  if (fbWrap) fbWrap.classList.add("hidden");
  _lexiScreen("question");
  _lexiGroupStartTimerBar(stateData.phase_ends_epoch_ms ?? stateData.phase_ends_at);
}

async function _lexiGroupAnswerSelected(choiceIdx) {
  if (!_lexiGroup.active || !_lexiGroup.sessionId || _lexiGroup.answeredCurrent) return;
  _lexiGroup.answeredCurrent = true;
  document.querySelectorAll(".lexi-ans-btn").forEach((btn, i) => {
    btn.disabled = true;
    if (i === choiceIdx) btn.className = btn.className.replace("border-gray-700", "border-blue-500") + " bg-blue-950/30 text-blue-200";
  });
  try {
    const res = await authFetch(`${API}/api/me/lexi-group/answer`, {
      method: "POST",
      body: JSON.stringify({ session_id: _lexiGroup.sessionId, choice: choiceIdx }),
    });
    if (!res.ok) {
      if (res.status === 403) {
        _lexiHandleGroupRemoval("You were removed from this group challenge.");
        return;
      }
      const err = await res.json().catch(() => ({}));
      _lexiGroup.answeredCurrent = false;
      document.querySelectorAll(".lexi-ans-btn").forEach((btn, i) => {
        btn.disabled = false;
        if (i === choiceIdx) {
          btn.className = btn.className
            .replace("border-blue-500", "border-gray-700")
            .replace(" bg-blue-950/30 text-blue-200", "");
        }
      });
      if (res.status !== 409) {
        showToast(err.detail || "Answer was not accepted. Please try again.", "warning");
      }
    }
  } catch {
    _lexiGroup.answeredCurrent = false;
    document.querySelectorAll(".lexi-ans-btn").forEach((btn, i) => {
      btn.disabled = false;
      if (i === choiceIdx) {
        btn.className = btn.className
          .replace("border-blue-500", "border-gray-700")
          .replace(" bg-blue-950/30 text-blue-200", "");
      }
    });
    showToast("Connection issue submitting answer. Please try again.", "warning");
  }
}
window._lexiGroupAnswerSelected = _lexiGroupAnswerSelected;

function _lexiShowGroupFeedback(stateData) {
  const round = stateData.round_index || 1;
  const qIdx = stateData.current_question_index || 0;
  const feedbackKey = `${round}:${qIdx}`;
  const isSameFeedback = _lexiGroup.renderedFeedbackKey === feedbackKey && !el("lexi-screen-feedback")?.classList.contains("hidden");
  _lexiGroup.renderedFeedbackKey = feedbackKey;
  const myAnswered = (stateData.answered_user_ids || []).includes(state.userId);
  const myCorrect = myAnswered && !!stateData.my_answer_correct;
  const myReadyServer = (stateData.feedback_ready_user_ids || []).includes(state.userId);
  const myReady = myReadyServer || _lexiGroup.pendingFeedbackReady;
  if (myReadyServer) _lexiGroup.pendingFeedbackReady = false;
  const resultEl = el("lexi-feedback-result");
  if (resultEl) {
    if (myCorrect) {
      resultEl.textContent = "✓ Correct!";
      resultEl.className = "text-center font-bold text-2xl text-emerald-400";
    } else if (myAnswered) {
      resultEl.textContent = "✗ Incorrect";
      resultEl.className = "text-center font-bold text-2xl text-red-400";
    } else {
      resultEl.textContent = "⏱ Unanswered";
      resultEl.className = "text-center font-bold text-2xl text-amber-500";
    }
  }
  _lexiSetExpression(myCorrect ? "happy" : (myAnswered ? "sad" : "shocked"));
  if (myCorrect) _lexiSetAvatarState("celebrating", { autoResetMs: 1100 });
  else if (myAnswered) _lexiSetAvatarState("concerned", { autoResetMs: 1100 });
  else _lexiSetAvatarState("concerned", { autoResetMs: 1300 });
  setText(
    "lexi-feedback-msg",
    `Round score so far: ${stateData.my_round_score ?? 0}/5`
  );
  setText("lexi-feedback-explanation", stateData.question?.explanation || "");
  const nextBtn = el("btn-lexi-next");
  if (nextBtn) {
    nextBtn.classList.remove("hidden");
    const ready = stateData.feedback_ready_count || 0;
    const total = (stateData.participants || []).length;
    nextBtn.textContent = myReady
      ? `Waiting (${ready}/${total})`
      : `I'm Ready (${ready}/${total}) →`;
    nextBtn.disabled = !!myReady;
    nextBtn.classList.toggle("opacity-60", !!myReady);
  }
  const cd = el("lexi-feedback-countdown");
  if (cd) {
    cd.classList.remove("hidden");
    const tick = () => {
      const end = _toEpochMs(stateData.phase_ends_epoch_ms ?? stateData.phase_ends_at, Date.now());
      const secs = Math.max(0, Math.ceil((end - Date.now()) / 1000));
      cd.textContent = `Auto-advance in ${secs}s`;
      if (secs <= 0) clearInterval(_lexiGroup.feedbackCountdown);
    };
    if (!isSameFeedback) {
      if (_lexiGroup.feedbackCountdown) clearInterval(_lexiGroup.feedbackCountdown);
      tick();
      _lexiGroup.feedbackCountdown = setInterval(tick, 500);
    } else {
      tick();
    }
  }
  _lexiScreen("feedback");
  if (!isSameFeedback) _lexiGroupStartFeedbackBar(stateData.phase_ends_epoch_ms ?? stateData.phase_ends_at);
}

function _lexiRenderGroupResults(stateData) {
  const isFinal = stateData.phase === "final_results";
  if (_lexiGroup.resultsCountdown) {
    clearInterval(_lexiGroup.resultsCountdown);
    _lexiGroup.resultsCountdown = null;
  }
  setText("lexi-group-results-title", isFinal ? "Final Group Results" : `Round ${stateData.round_index} Results`);
  setText("lexi-group-results-sub", `Room ${stateData.room_code} · Level ${stateData.effective_provider_level || "EMT"}`);
  setText("lexi-group-standings-title", "Your Results");
  const top3El = el("lexi-group-top3");
  if (top3El) {
    top3El.innerHTML = (stateData.top3 || []).map((row, i) => {
      const medal = ["🥇", "🥈", "🥉"][i] || "🏅";
      return `<div class="flex items-center justify-between ${row.is_me ? "text-blue-300" : "text-white"}">
        <span>${medal} ${escapeHTML(row.display || "")}${row.is_me ? " (you)" : ""}</span>
        <span class="text-amber-300">${row.score} pts</span>
      </div>`;
    }).join("") || `<p class="text-gray-500 text-xs">No results yet.</p>`;
  }
  const allEl = el("lexi-group-standings");
  if (allEl) {
    const meStanding = (stateData.standings || []).find(row => row.is_me);
    const meRound = (stateData.round_results || []).find(row => row.is_me);
    const rank = meStanding?.rank ?? "—";
    const label = escapeHTML(meStanding?.display || "You");
    const scoreText = isFinal
      ? `${meStanding?.score ?? 0} pts total`
      : `${meRound?.score ?? 0} pts this round`;
    const xpText = isFinal
      ? `+${stateData.my_xp_earned_total || 0} XP total`
      : `+${stateData.my_xp_earned_round || 0} XP this round`;

    allEl.innerHTML = meStanding
      ? `<div class="bg-gray-900/70 border border-gray-700 rounded-lg px-3 py-2 space-y-1">
          <div class="flex items-center justify-between text-blue-300">
            <span>#${rank} ${label} (you)</span>
            <span>${scoreText}</span>
          </div>
          <div class="flex items-center justify-between text-gray-300 text-xs">
            <span>Your Group XP</span>
            <span class="text-amber-300">${xpText}</span>
          </div>
        </div>`
      : `<p class="text-gray-500 text-xs">No personal results available.</p>`;
  }
  const bonusEl = el("lexi-group-bonus");
  if (bonusEl) {
    const bonus = stateData.bonus || {};
    const lines = [];
    const pushBonusLine = (text, toneClass = "text-gray-300") => {
      lines.push(
        `<div class="flex items-start gap-2 ${toneClass}">
          <span class="shrink-0 mt-0.5">${_LEXI_BONUS_TICKER_SVG}</span>
          <span class="leading-relaxed">${text}</span>
        </div>`
      );
    };
    if (!isFinal && !stateData.round_winner_user_id) {
      pushBonusLine("No round winner: no submitted answers.", "text-gray-400");
    }
    if (!isFinal && stateData.round_winner_user_id) {
      const winner = (stateData.participants || []).find(p => p.user_id === stateData.round_winner_user_id);
      pushBonusLine(`${escapeHTML(winner?.display || "Winner")} earned +10XP for placing 1st this round!`, "text-emerald-300");
    }
    if (!isFinal && stateData.my_round_xp_capped) {
      pushBonusLine("You reached today's Lexi XP cap, so base round XP was not awarded.", "text-amber-300");
    }
    const treatEarned = Array.isArray(bonus.treat_earned) ? bonus.treat_earned : [];
    if (treatEarned.length > 0) {
      const seenTreatMsgs = new Set();
      treatEarned.forEach((entry) => {
        const uid = entry?.user_id;
        const reason = entry?.reason;
        const t = (stateData.standings || []).find(s => s.user_id === uid);
        const name = escapeHTML(t?.display || "User");
        const msg = reason === "won_all_3_rounds"
          ? `${name} earned a treat for winning all 3 rounds!`
          : `${name} earned a treat for having 3 perfect rounds!`;
        if (!seenTreatMsgs.has(msg)) {
          seenTreatMsgs.add(msg);
          pushBonusLine(msg, "text-amber-300");
        }
      });
    } else {
      const treatEarners = Array.isArray(bonus.treat_earned_user_ids) ? bonus.treat_earned_user_ids : [];
      treatEarners.forEach((uid) => {
        const t = (stateData.standings || []).find(s => s.user_id === uid);
        pushBonusLine(`${escapeHTML(t?.display || "User")} earned a treat for having 3 perfect rounds!`, "text-amber-300");
      });
    }
    if (bonus.treat_award_capped) {
      pushBonusLine("3-perfect-round treat not awarded for at least one player: daily group treat cap reached.", "text-amber-300");
    }
    if (isFinal) {
      const myTreatCaps = Array.isArray(stateData.my_treat_capped_reasons) ? stateData.my_treat_capped_reasons : [];
      if (myTreatCaps.length > 0) {
        pushBonusLine("You met treat criteria, but your daily group-challenge treat cap has been reached.", "text-amber-300");
      }
    }
    bonusEl.innerHTML = lines.join("");
    bonusEl.classList.toggle("hidden", lines.length === 0);
  }
  const facilitatorSummaryWrap = el("lexi-group-facilitator-summary");
  const facilitatorSummaryBody = el("lexi-group-facilitator-summary-body");
  if (facilitatorSummaryWrap && facilitatorSummaryBody) {
    const isFacilitatorView = !!(state._isSuper || state._role === "admin" || state._role === "instructor" || stateData.host_user_id === state.userId);
    const fs = stateData.facilitator_summary || null;
    if (isFinal && isFacilitatorView && fs) {
      const items = [
        { label: "Rounds Completed", value: fs.rounds_completed ?? 0 },
        { label: "Participants", value: fs.participants ?? 0 },
        { label: "Answer Completion", value: `${fs.completion_rate_pct ?? 0}%` },
        { label: "Team Accuracy", value: `${fs.team_accuracy_pct ?? 0}%` },
        { label: "Avg Pts / Responder / Round", value: fs.avg_points_per_responder_per_round ?? 0 },
        { label: "No-Answer Rounds", value: fs.rounds_with_no_answers ?? 0 },
      ];
      facilitatorSummaryBody.innerHTML = items.map((item) => `
        <div class="bg-gray-900/60 border border-gray-700 rounded-lg px-2.5 py-2">
          <div class="text-[11px] text-gray-500 uppercase tracking-wide">${escapeHTML(String(item.label))}</div>
          <div class="text-sm text-gray-200 font-semibold mt-0.5">${escapeHTML(String(item.value))}</div>
        </div>
      `).join("");
      facilitatorSummaryWrap.classList.remove("hidden");
    } else {
      facilitatorSummaryWrap.classList.add("hidden");
      facilitatorSummaryBody.innerHTML = "";
    }
  }
  const playAgainBtn = el("btn-lexi-group-play-again");
  const updateRoundResultsSub = () => {
    if (isFinal || !stateData.phase_ends_epoch_ms) return -1;
    const end = stateData.phase_ends_epoch_ms;
    const secs = Math.max(0, Math.ceil((end - Date.now()) / 1000));
    setText("lexi-group-results-sub", `Room ${stateData.room_code} · Level ${stateData.effective_provider_level || "EMT"} · Advance in ${secs}s (non-ready removed)`);
    return secs;
  };
  if (playAgainBtn) {
    if (isFinal) {
      playAgainBtn.classList.add("hidden");
    } else {
      const ready = stateData.next_round_ready_count || 0;
      const total = (stateData.participants || []).length;
      const myReadyServer = (stateData.next_round_ready_user_ids || []).includes(state.userId);
      const myReady = myReadyServer || _lexiGroup.pendingNextRoundReady;
      if (myReadyServer) _lexiGroup.pendingNextRoundReady = false;
      playAgainBtn.classList.remove("hidden");
      const base = myReady ? `Waiting (${ready}/${total})` : `Play Again (${ready}/${total})`;
      const setPlayAgainText = () => {
        const end = _toEpochMs(stateData.phase_ends_epoch_ms ?? stateData.phase_ends_at, 0);
        if (end > 0) {
          const secs = Math.max(0, Math.ceil((end - Date.now()) / 1000));
          playAgainBtn.textContent = `${base} · ${secs}s`;
          updateRoundResultsSub();
          return secs;
        }
        playAgainBtn.textContent = base;
        return -1;
      };
      const initialSecs = setPlayAgainText();
      if (initialSecs > 0) {
        _lexiGroup.resultsCountdown = setInterval(() => {
          const secs = setPlayAgainText();
          if (secs <= 0 && _lexiGroup.resultsCountdown) {
            clearInterval(_lexiGroup.resultsCountdown);
            _lexiGroup.resultsCountdown = null;
          }
        }, 500);
      }
      playAgainBtn.disabled = myReady;
      playAgainBtn.classList.toggle("opacity-60", myReady);
    }
  }
  updateRoundResultsSub();
  _lexiScreen("group-results");
}

function _lexiHandleGroupState(stateData, source = "state") {
  const participantIds = Array.isArray(stateData?.participants)
    ? stateData.participants.map(p => p?.user_id).filter(Boolean)
    : [];
  if (_lexiGroup.active && participantIds.length > 0 && !participantIds.includes(state.userId)) {
    _lexiHandleGroupRemoval("You were removed from this group challenge.");
    return;
  }
  if (_isLikelyStaleGroupState(stateData, _lexiGroup.state)) return;
  _lexiGroup.lastStateAt = Date.now();
  _lexiGroup.lastStateSource = source;
  _lexiGroup.lastStateVersionMs = Number(stateData?.state_version_ms || _lexiGroup.lastStateVersionMs || 0);
  _lexiRenderGroupSyncHint(stateData);
  if (!_lexiGroup.syncHintTimer) {
    _lexiGroup.syncHintTimer = setInterval(() => _lexiRenderGroupSyncHint(), 1000);
  }
  _lexiGroup.state = stateData;
  _lexiGroup.sessionId = stateData.session_id;
  _lexiGroup.roomCode = stateData.room_code;
  if (stateData.phase !== "feedback" && _lexiGroup.feedbackCountdown) {
    clearInterval(_lexiGroup.feedbackCountdown);
    _lexiGroup.feedbackCountdown = null;
  }
  if (stateData.phase !== "feedback") _lexiGroup.pendingFeedbackReady = false;
  if (stateData.phase !== "round_results" && _lexiGroup.resultsCountdown) {
    clearInterval(_lexiGroup.resultsCountdown);
    _lexiGroup.resultsCountdown = null;
  }
  if (stateData.phase !== "round_results") _lexiGroup.pendingNextRoundReady = false;
  if (stateData.phase !== "question") _lexiGroup.renderedQuestionKey = null;
  if (stateData.phase !== "feedback") _lexiGroup.renderedFeedbackKey = null;
  if (stateData.phase === "lobby") {
    _lexiRenderGroupLobby(stateData);
    return;
  }
  if (stateData.phase === "question") {
    _lexiShowGroupQuestion(stateData);
    return;
  }
  if (stateData.phase === "feedback") {
    _lexiShowGroupFeedback(stateData);
    return;
  }
  if (stateData.phase === "round_results" || stateData.phase === "final_results") {
    _refreshLexiStatusAndMenu(stateData.phase === "final_results");
    _lexiRenderGroupResults(stateData);
    return;
  }
}

async function _connectLexiGroupSocket(sessionId) {
  _lexiGroupCleanupWs();
  _lexiGroup.sessionId = sessionId;
  _lexiGroupStartPolling();
  let ticket = "";
  try {
    const tr = await authFetch(`${API}/api/ws-ticket`, { method: "POST" });
    if (tr.ok) { const td = await tr.json(); ticket = td.ticket || ""; }
  } catch {}
  if (!ticket) {
    // Ticket fetch failed — polling will keep state current; log and bail.
    console.warn("Lexi group WS: ticket fetch failed, falling back to polling.");
    return;
  }
  const wsProto = location.protocol === "https:" ? "wss:" : "ws:";
  const ws = new WebSocket(`${wsProto}//${location.host}/ws/lexi-group/${sessionId}?ticket=${encodeURIComponent(ticket)}`);
  _lexiGroup.ws = ws;
  ws.onmessage = (evt) => {
    try {
      const data = JSON.parse(evt.data);
      if (data?.type === "state" && data.state) _lexiHandleGroupState(data.state, "ws");
      if (data?.type === "kicked") {
        _lexiHandleGroupRemoval(data?.message || "You were removed from this group challenge.");
      }
    } catch {}
  };
  ws.onclose = async (evt) => {
    if (evt?.code === 4003) {
      _lexiHandleGroupRemoval("You were removed from this group challenge.");
      return;
    }
    // Safari fallback: verify membership via HTTP because WS close codes can be unreliable.
    if (_lexiGroup.active && _lexiGroup.sessionId) {
      try {
        const probe = await authFetch(`${API}/api/me/lexi-group/${_lexiGroup.sessionId}`);
        if (probe.status === 403) {
          _lexiHandleGroupRemoval("You were removed from this group challenge.");
          return;
        }
        if (probe.ok) {
          const data = await probe.json();
          if (data?.state) {
            _lexiHandleGroupState(data.state, "http");
            return;
          }
        }
      } catch {
        // Fall through to reconnect path.
      }
    }
    if (_lexiGroup.active) {
      setTimeout(() => {
        if (_lexiGroup.active && _lexiGroup.sessionId) _connectLexiGroupSocket(_lexiGroup.sessionId);
      }, 1500);
    }
  };
}

async function _lexiGroupCreate() {
  if (_lexiGroup.isTeamChallenge) {
    showToast("This lobby is team-managed. Use Join Live Match from Team Challenge.", "info");
    return;
  }
  if (_lexiGroup.creating || _lexiGroup.joining || _lexiGroup.starting) return;
  _lexiGroup.creating = true;
  const createBtn = el("btn-lexi-group-create");
  const joinBtn = el("btn-lexi-group-join");
  const codeInput = el("lexi-group-room-code");
  if (createBtn) { createBtn.disabled = true; createBtn.classList.add("opacity-60"); }
  if (joinBtn) joinBtn.disabled = true;
  if (codeInput) codeInput.disabled = true;
  try {
    const r = await authFetch(`${API}/api/me/lexi-group/create`, { method: "POST" });
    if (!r.ok) { showToast("Couldn't create group challenge.", "error"); return; }
    const data = await r.json();
    _lexiGroup.active = true;
    _lexiGroup.sessionId = data.session_id;
    _connectLexiGroupSocket(data.session_id);
    _lexiHandleGroupState(data.state, "http");
  } catch {
    showToast("Connection error creating group challenge.", "error");
  } finally {
    _lexiGroup.creating = false;
    if (createBtn) { createBtn.disabled = false; createBtn.classList.remove("opacity-60"); }
    if (joinBtn) joinBtn.disabled = false;
    if (codeInput) codeInput.disabled = false;
  }
}

async function _lexiGroupJoin() {
  if (_lexiGroup.isTeamChallenge) {
    showToast("This lobby is team-managed. Use Join Live Match from Team Challenge.", "info");
    return;
  }
  if (_lexiGroup.creating || _lexiGroup.joining || _lexiGroup.starting) return;
  const input = el("lexi-group-room-code");
  const code = (input?.value || "").trim().toUpperCase();
  if (!code) return;
  _lexiGroup.joining = true;
  const joinBtn = el("btn-lexi-group-join");
  const createBtn = el("btn-lexi-group-create");
  if (joinBtn) { joinBtn.disabled = true; joinBtn.classList.add("opacity-60"); }
  if (createBtn) createBtn.disabled = true;
  if (input) input.disabled = true;
  try {
    const r = await authFetch(`${API}/api/me/lexi-group/join`, {
      method: "POST",
      body: JSON.stringify({ room_code: code }),
    });
    if (!r.ok) {
      // Duplicate taps/race can cause a late non-OK while state sync still succeeds.
      // Prefer specific messaging and avoid noisy false-negative toasts.
      if (r.status === 429) {
        showToast("Join request already in progress. Please wait…", "info");
      } else {
        const err = await r.json().catch(() => ({}));
        showToast(err.detail || "Could not join room. Check code and try again.", "warning");
      }
      return;
    }
    const data = await r.json();
    _lexiGroup.active = true;
    _lexiGroup.sessionId = data.session_id;
    if (input) input.value = "";
    _connectLexiGroupSocket(data.session_id);
    _lexiHandleGroupState(data.state, "http");
  } catch {
    showToast("Connection error joining room.", "error");
  } finally {
    _lexiGroup.joining = false;
    if (joinBtn) { joinBtn.disabled = false; joinBtn.classList.remove("opacity-60"); }
    if (createBtn) createBtn.disabled = false;
    if (input) input.disabled = false;
  }
}

async function _lexiGroupStart() {
  if (_lexiGroup.creating || _lexiGroup.joining || _lexiGroup.starting) return;
  if (!_lexiGroup.sessionId) return;
  _lexiGroup.starting = true;
  const startBtn = el("btn-lexi-group-start");
  if (startBtn) {
    startBtn.disabled = true;
    startBtn.classList.add("opacity-60");
  }
  try {
    const r = await authFetch(`${API}/api/me/lexi-group/start`, {
      method: "POST",
      body: JSON.stringify({ session_id: _lexiGroup.sessionId }),
    });
    if (!r.ok) {
      const err = await r.json().catch(() => ({}));
      showToast(err.detail || "Could not start group challenge.", "warning");
    }
  } catch {
    showToast("Connection error starting group challenge.", "error");
  } finally {
    _lexiGroup.starting = false;
    if (startBtn) {
      startBtn.disabled = false;
      startBtn.classList.remove("opacity-60");
    }
  }
}

async function _lexiGroupNextRound() {
  if (!_lexiGroup.sessionId) return;
  _lexiGroup.pendingNextRoundReady = true;
  const btn = el("btn-lexi-group-play-again");
  if (btn) {
    btn.disabled = true;
    btn.classList.add("opacity-60");
    if (!btn.textContent.includes("Waiting")) btn.textContent = "Waiting…";
  }
  try {
    const r = await authFetch(`${API}/api/me/lexi-group/next-round`, {
      method: "POST",
      body: JSON.stringify({ session_id: _lexiGroup.sessionId }),
    });
    if (!r.ok) {
      if (r.status === 403) {
        _lexiHandleGroupRemoval("You were removed from this group challenge.");
        return;
      }
      if (r.status !== 409) showToast("Couldn't advance to next round yet.", "warning");
    }
    // Force a state refresh so Safari stays synced even if WS lags.
    const sr = await authFetch(`${API}/api/me/lexi-group/${_lexiGroup.sessionId}`);
    if (sr.status === 403) {
      _lexiHandleGroupRemoval("You were removed from this group challenge.");
      return;
    }
    if (sr.ok) {
      const data = await sr.json();
      if (data?.state) _lexiHandleGroupState(data.state, "http");
    }
  } catch {
    _lexiGroup.pendingNextRoundReady = false;
    if (btn) {
      btn.disabled = false;
      btn.classList.remove("opacity-60");
    }
  }
}

async function _lexiGroupFeedbackReady() {
  if (!_lexiGroup.sessionId) return;
  _lexiGroup.pendingFeedbackReady = true;
  const btn = el("btn-lexi-next");
  if (btn) {
    btn.disabled = true;
    btn.classList.add("opacity-60");
    if (!btn.textContent.includes("Waiting")) btn.textContent = "Waiting…";
  }
  try {
    const r = await authFetch(`${API}/api/me/lexi-group/feedback-ready`, {
      method: "POST",
      body: JSON.stringify({ session_id: _lexiGroup.sessionId }),
    });
    if (!r.ok) {
      if (r.status === 403) {
        _lexiHandleGroupRemoval("You were removed from this group challenge.");
        return;
      }
      const err = await r.json().catch(() => ({}));
      if (r.status !== 409) {
        showToast(err.detail || "Couldn't mark ready right now.", "warning");
      }
    }
    // Force a state refresh so Safari stays synced even if WS lags.
    const sr = await authFetch(`${API}/api/me/lexi-group/${_lexiGroup.sessionId}`);
    if (sr.status === 403) {
      _lexiHandleGroupRemoval("You were removed from this group challenge.");
      return;
    }
    if (sr.ok) {
      const data = await sr.json();
      if (data?.state) _lexiHandleGroupState(data.state, "http");
    }
  } catch {
    _lexiGroup.pendingFeedbackReady = false;
    showToast("Connection issue marking ready.", "warning");
    if (btn) {
      btn.disabled = false;
      btn.classList.remove("opacity-60");
    }
  }
}

async function _startLexiRound() {
  _lexiScreen("loading");
  _lexiSetAvatarState("thinking");
  _lexiGame = { questions: [], currentIdx: 0, score: 0, results: [], timerHandle: null, answered: false };

  try {
    const r = await authFetch(`${API}/api/me/lexi-questions`, {
      method:  "POST",
      headers: { "Content-Type": "application/json" },
      body:    JSON.stringify({ provider_level: state.providerLevel || "EMT", mca: state.mca || "mi_wmrmcc_kent" }),
    });
    if (!r.ok) throw new Error();
    const data = await r.json();
    _lexiGame.questions = data.questions || [];
  } catch {
    // Will fall back to backend's static questions — nothing to do here;
    // if the fetch itself failed entirely, show error
    _lexiSetAvatarState("concerned", { autoResetMs: 1400 });
    _lexiScreen("intro");
    return;
  }

  _lexiSetAvatarState("encouraging", { autoResetMs: 1000 });
  _lexiShowQuestion(0);
}

// ── Question display ──────────────────────────────────────────────────────────

function _lexiShowQuestion(idx) {
  _lexiGame.currentIdx = idx;
  _lexiGame.answered   = false;
  const q = _lexiGame.questions[idx];

  setText("lexi-q-counter", `Question ${idx + 1} of 5`);

  // Score pips
  const pipsEl = el("lexi-score-pips");
  if (pipsEl) {
    pipsEl.innerHTML = _lexiGame.results.map(r =>
      `<span class="w-2 h-2 rounded-full ${r === true ? "bg-emerald-500" : "bg-red-600"}"></span>`
    ).join("") + `<span class="w-2 h-2 rounded-full bg-gray-700"></span>`.repeat(5 - _lexiGame.results.length);
  }

  setText("lexi-question-text", q.question);

  const answersEl = el("lexi-answers");
  const labels    = ["A", "B", "C", "D"];
  answersEl.innerHTML = q.options.map((opt, i) =>
    `<button class="lexi-ans-btn text-left w-full border text-gray-200 text-sm rounded-xl px-4 py-3 transition-colors"
       onclick="_lexiAnswerSelected(${i})">
       <span class="lexi-ans-label font-bold mr-2">${labels[i]}.</span>${escapeHTML(opt)}
     </button>`
  ).join("");

  _lexiScreen("question");

  // Start timer bar animation
  const bar = el("lexi-timer-bar");
  if (bar) {
    bar.style.transition = "none";
    bar.style.width      = "100%";
    bar.style.background = "rgb(217,119,6)"; // amber-600
    // Force reflow so the reset is visible before the animation starts
    bar.offsetWidth; // eslint-disable-line
    bar.style.transition = "width 30s linear, background 21s linear 9s";
    bar.style.width      = "0%";
    bar.style.background = "rgb(220,38,38)"; // red-600
  }

  // Expiry handle
  _lexiGame.timerHandle = setTimeout(_lexiTimerExpired, 30000);
}

// ── Answer handling ───────────────────────────────────────────────────────────

function _lexiAnswerSelected(choiceIdx) {
  if (_lexiGame.answered) return;
  _lexiGame.answered = true;
  clearTimeout(_lexiGame.timerHandle);

  // Stop timer bar
  const bar = el("lexi-timer-bar");
  if (bar) {
    const computed = window.getComputedStyle(bar).width;
    bar.style.transition = "none";
    bar.style.width      = computed;
  }

  const q       = _lexiGame.questions[_lexiGame.currentIdx];
  const correct = choiceIdx === q.correct;

  // Highlight the answer buttons
  document.querySelectorAll(".lexi-ans-btn").forEach((btn, i) => {
    btn.disabled = true;
    if (i === q.correct)  btn.className = btn.className.replace("border-gray-700", "border-emerald-500") + " bg-emerald-900/40 text-emerald-300";
    if (i === choiceIdx && !correct) btn.className = btn.className.replace("border-gray-700", "border-red-600") + " bg-red-900/30 text-red-300";
  });

  if (correct) _lexiGame.score++;
  _lexiGame.results.push(correct);

  const lexiMsg = correct ? _lexiPick(LEXI_CORRECT) : _lexiPick(LEXI_WRONG);
  setTimeout(() => _lexiShowFeedback(correct, false, lexiMsg, q.explanation), 600);
}

function _lexiTimerExpired() {
  if (_lexiGame.answered) return;
  _lexiGame.answered = true;

  // Show correct answer
  const q = _lexiGame.questions[_lexiGame.currentIdx];
  document.querySelectorAll(".lexi-ans-btn").forEach((btn, i) => {
    btn.disabled = true;
    if (i === q.correct) btn.className = btn.className.replace("border-gray-700", "border-amber-500") + " bg-amber-900/30 text-amber-300";
  });

  _lexiGame.results.push("timeout");
  _lexiShowFeedback(false, true, _lexiPick(LEXI_TIMEOUT), q.explanation);
}

// ── Expression engine ─────────────────────────────────────────────────────────

const _LEXI_EXPRESSIONS = {
  neutral: { mouth: "M70,91 Q80,99 90,91",  eyeRy: 8.5 },
  happy:   { mouth: "M67,90 Q80,104 93,90", eyeRy: 6.0 },  // big smile, squinted
  sad:     { mouth: "M70,94 Q80,86 90,94",  eyeRy: 8.5 },  // frown
  shocked: { mouth: "M73,91 Q80,97 87,91",  eyeRy: 10.5 }, // wide eyes, small surprised mouth
};

function _lexiSetExpression(mood) {
  const expr    = _LEXI_EXPRESSIONS[mood] || _LEXI_EXPRESSIONS.neutral;
  const mouthEl = document.getElementById("lexi-fb-mouth");
  const eyeL    = document.getElementById("lexi-fb-eye-l");
  const eyeR    = document.getElementById("lexi-fb-eye-r");
  if (mouthEl) mouthEl.setAttribute("d",  expr.mouth);
  if (eyeL)    eyeL.setAttribute("ry",    expr.eyeRy);
  if (eyeR)    eyeR.setAttribute("ry",    expr.eyeRy);
}

// ── Feedback ──────────────────────────────────────────────────────────────────

function _lexiShowFeedback(correct, timedOut, lexiMsg, explanation) {
  const resultEl = el("lexi-feedback-result");
  if (resultEl) {
    if (correct)       { resultEl.textContent = "✓ Correct!";   resultEl.className = "text-center font-bold text-2xl text-emerald-400"; }
    else if (timedOut) { resultEl.textContent = "⏱ Time's Up!"; resultEl.className = "text-center font-bold text-2xl text-amber-500"; }
    else               { resultEl.textContent = "✗ Incorrect";   resultEl.className = "text-center font-bold text-2xl text-red-400"; }
  }

  // Set Lexi's expression based on outcome
  _lexiSetExpression(correct ? "happy" : timedOut ? "shocked" : "sad");
  if (correct) _lexiSetAvatarState("celebrating", { autoResetMs: 1200 });
  else if (timedOut) _lexiSetAvatarState("concerned", { autoResetMs: 1400 });
  else _lexiSetAvatarState("concerned", { autoResetMs: 1200 });

  setText("lexi-feedback-msg",         lexiMsg);
  setText("lexi-feedback-explanation", explanation);

  // Update the Next button label — last question gets "See Results"
  const nextBtn = el("btn-lexi-next");
  const isLast  = _lexiGame.currentIdx >= 4;
  if (nextBtn) {
    nextBtn.classList.remove("hidden");
    nextBtn.textContent = isLast ? "See Results 🐾" : "Next Question →";
  }
  const cd = el("lexi-feedback-countdown");
  if (cd) cd.classList.add("hidden");

  _lexiScreen("feedback");
}

// ── Outro ─────────────────────────────────────────────────────────────────────

async function _lexiShowOutro() {
  _lexiScreen("loading"); // brief loading while we submit
  _lexiSetAvatarState("thinking");

  let result;
  try {
    const r = await authFetch(`${API}/api/me/lexi-challenge`, {
      method:  "POST",
      headers: { "Content-Type": "application/json" },
      body:    JSON.stringify({
        score:          _lexiGame.score,
        provider_level: state.providerLevel || "EMT",
        mca:            state.mca           || "mi_wmrmcc_kent",
        question_keys: _lexiGame.questions.map(q => q?.qid || _lexiQuestionKey(q)),
        missed_question_keys: _lexiGame.questions
          .map((q, i) => ({ q, r: _lexiGame.results[i] }))
          .filter(item => item.r !== true)
          .map(item => item.q?.qid || _lexiQuestionKey(item.q)),
      }),
    });
    result = r.ok ? await r.json() : null;
  } catch {
    result = null;
  }

  const score   = _lexiGame.score;
  const xp      = result?.xp_earned  ?? 0;
  const capped  = result?.xp_capped  ?? false;
  const badges  = result?.new_badges ?? [];

  // Pick outro content
  let outroIcon, outroTitle, outroLexi;
  if (score === 5) {
    outroIcon  = "🏆";
    outroTitle = "Perfect Round!";
    outroLexi  = _lexiPick(LEXI_PERFECT);
  } else if (score >= 3) {
    outroIcon  = "🐾";
    outroTitle = `${score} / 5 Correct`;
    outroLexi  = _lexiPick(LEXI_OUTRO_GOOD);
  } else {
    outroIcon  = "📋";
    outroTitle = `${score} / 5 Correct`;
    outroLexi  = _lexiPick(LEXI_OUTRO_BAD);
  }

  if (score === 5) _lexiSetAvatarState("celebrating", { autoResetMs: 1500 });
  else if (score >= 3) _lexiSetAvatarState("encouraging", { autoResetMs: 1300 });
  else _lexiSetAvatarState("concerned", { autoResetMs: 1300 });

  setText("lexi-outro-icon",     outroIcon);
  setText("lexi-outro-title",    outroTitle);
  setText("lexi-outro-lexi-msg", outroLexi);
  setText("lexi-outro-score",    `${score} / 5`);
  setText("lexi-outro-xp",       xp > 0 ? `+${xp} XP` : "—");

  const capNote = el("lexi-outro-cap-note");
  if (capNote) capNote.classList.toggle("hidden", !capped || xp > 0);

  // Badge display
  const badgesSection = el("lexi-outro-badges");
  const badgeItems    = el("lexi-badge-items");
  if (badgesSection && badgeItems && badges.length) {
    badgeItems.innerHTML = badges.map(id => {
      const def = BADGE_DEFS.find(b => b.id === id);
      return def
        ? `<div class="flex items-center gap-2 bg-amber-950/40 border border-amber-800/40 rounded-lg px-3 py-2">
             <span class="text-xl">${def.icon}</span>
             <div class="text-left">
               <p class="text-amber-200 text-xs font-semibold">${escapeHTML(def.name)}</p>
               <p class="text-gray-500 text-xs">${escapeHTML(def.desc)}</p>
             </div>
           </div>`
        : "";
    }).join("");
    badgesSection.classList.toggle("hidden", !badges.length);
  } else if (badgesSection) {
    badgesSection.classList.add("hidden");
  }

  // Play again button visibility — always show but label changes
  const playAgainBtn = el("btn-lexi-play-again");
  if (playAgainBtn && result) {
    const remaining = Math.max(0, (result.rounds_today ? (_lexiStatus?.daily_cap ?? 3) - result.rounds_today : 0));
    playAgainBtn.textContent = remaining > 0 ? "Play Again 🐾" : "Practice Again 🐾";
  }

  // Refresh local status and menu card
  if (result) {
    _lexiStatus = {
      ...(_lexiStatus || {}),
      rounds_today:   result.rounds_today,
      total_rounds:   result.total_rounds,
      perfect_rounds: result.perfect_rounds,
    };
    _updateLexiCard();
  }

  // Refresh progress from server so post-round XP/badges stay authoritative.
  if (result) {
    _applyGamificationAward({ xpEarned: xp, newBadges: badges });
    await _loadProgressFromServer().catch(() => {});
    _refreshGamificationChrome();
    await _refreshScormSummary().catch(() => {});
    const g = loadGamification();
    buildBadgesSection(g);
    if (!el("screen-menu")?.classList.contains("hidden")) buildMenu();
  }

  _lexiScreen("outro");
}

