/* ═══════════════════════════════════════════════════════════════════
   CATEGORY SCREEN
   ═══════════════════════════════════════════════════════════════════ */

el("btn-category-back")?.addEventListener("click", () => {
  buildMenu();
  showScreen("menu");
});

function _showLegacyCategoryList(categoryKey) {
  const cat = CATEGORY_DEFS.find(c => c.key === categoryKey);
  if (!cat) return false;
  const trailChip = el("category-trail-chip");
  trailChip?.classList.add("hidden");
  const trailNav = el("district-trail-nav");
  if (trailNav) {
    trailNav.classList.add("hidden");
    trailNav.innerHTML = "";
  }
  setText("category-screen-icon",  cat.icon);
  setText("category-screen-title", cat.title);
  setText("category-screen-desc",  cat.desc);
  _renderCategoryMapNav("legacy", _districtForCategory(categoryKey) || categoryKey);
  hide("category-district-view");
  show("category-scenario-list");

  const scenarios = state.allScenarios
    .filter(s => s.category === categoryKey)
    .sort((a, b) => (a.scenario_number ?? 999) - (b.scenario_number ?? 999));
  const history = loadHistory();
  // Completion and prerequisites are scoped to the current agency context
  const contextHistory = history.filter(h => !h.agencyId || h.agencyId === state.agency_id);
  const completedIds = new Set(contextHistory.filter(_scenarioHistoryEntryPassed).map(h => h.scenarioId));

  const container = el("category-scenario-list");
  container.innerHTML = "";

  if (scenarios.length === 0) {
    container.innerHTML = `<div class="text-center text-gray-500 py-16">
      <div class="text-4xl mb-3">🔒</div>
      <p class="text-base font-semibold">No scenarios available yet.</p>
      <p class="text-xs mt-1">Check back soon!</p>
    </div>`;
    showScreen("category");
    return true;
  }

  scenarios.forEach(scenario => {
    const num = scenario.scenario_number ?? "?";
    const attempts = contextHistory.filter(h => h.scenarioId === scenario.id);
    const attempted = attempts.length > 0;
    const bestAttempt = attempted
      ? attempts.reduce((best, attempt) => {
          const pct = _assessmentPctFromEntry(attempt) ?? 0;
          const bestPct = best ? (_assessmentPctFromEntry(best) ?? 0) : -1;
          return pct > bestPct ? attempt : best;
        }, null)
      : null;
    const completed = attempts.some(_scenarioHistoryEntryPassed);
    const bestScore = bestAttempt ? (bestAttempt.assessmentScore ?? bestAttempt.score ?? null) : null;
    const bestDenom = bestAttempt ? _assessmentMaxFromEntry(bestAttempt) : 100;
    const bestPct = bestAttempt ? _assessmentPctFromEntry(bestAttempt) : null;
    const lastAttempt = attempted ? attempts[0] : null;

    // Check prerequisites
    const prereqs = scenario.prerequisites ?? [];
    const unmetPrereqs = prereqs.filter(pid => !completedIds.has(pid));
    const prereqBlocked = unmetPrereqs.length > 0;

    // Resolve unmet prereq scenario numbers for display
    const unmetTitles = unmetPrereqs.map(pid => {
      const ps = state.allScenarios.find(s => s.id === pid);
      return ps ? `Scenario #${ps.scenario_number ?? "?"}` : `Scenario #?`;
    });

    const diffBadge = scenario.difficulty
      ? `<span class="text-xs px-2 py-0.5 rounded bg-gray-800 border border-gray-700 text-gray-400 font-medium">${escapeHTML(scenario.difficulty)}</span>`
      : "";

    const numBadge = `<span class="text-xs px-2 py-0.5 rounded bg-gray-800 border border-gray-600 text-gray-400 font-mono font-semibold">#${num}</span>`;

    const card = document.createElement("div");

    if (prereqBlocked) {
      // ── Prerequisite-blocked card — cannot start ─────────────────────
      const prereqText = unmetTitles.map(t => `<div class="text-gray-600 text-xs">• ${escapeHTML(t)}</div>`).join("");
      card.className = "bg-gray-900 border border-gray-800 rounded-xl p-5 opacity-60";
      card.innerHTML = `
        <div class="flex items-center justify-between gap-4">
          <div class="flex items-center gap-3">
            <div class="text-2xl text-gray-700">🔒</div>
            <div>
              <div class="flex items-center gap-2 flex-wrap mb-1">
                ${numBadge}
                ${diffBadge}
              </div>
              <p class="text-gray-500 text-xs font-semibold">Complete first:</p>
              ${prereqText}
            </div>
          </div>
        </div>`;
    } else if (completed) {
      // ── Completed scenario card ──────────────────────────────────────
      const statusMeta = _assessmentStatusMeta(bestPct, { criticalFailure: bestAttempt?.criticalFailure });
      const scoreColor = statusMeta.cls;
      const scoreLabel = statusMeta.label;

      const lastDate = lastAttempt
        ? new Date(lastAttempt.date).toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric" })
        : "";
      const lastModeTag = lastAttempt?.drillMode
        ? ` <span class="text-yellow-600 text-xs font-semibold">⚡ Drill</span>`
        : (lastAttempt ? ` <span class="text-gray-600 text-xs">Full</span>` : "");
      const attemptLine = attempts.length === 1
        ? `1 attempt · Last: ${lastDate}${lastModeTag}`
        : `${attempts.length} attempts · Last: ${lastDate}${lastModeTag}`;
      const lastCtxParts = lastAttempt ? [
        lastAttempt.agencyName,
        MCA_DISPLAY[lastAttempt.mca] || lastAttempt.mca,
        LEVEL_DISPLAY[lastAttempt.providerLevel] || lastAttempt.providerLevel,
      ].filter(Boolean) : [];
      const lastCtxLine = lastCtxParts.length
        ? `<p class="text-gray-600 text-xs mt-0.5">${lastCtxParts.map(escapeHTML).join(" · ")}</p>`
        : "";

      card.className = "bg-gray-900 border border-gray-700 rounded-xl p-5";
      card.innerHTML = `
        <div class="flex items-start justify-between gap-4">
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-2 flex-wrap mb-1">
              ${numBadge}
              <h3 class="text-white font-bold text-sm">${escapeHTML(_scenarioDisplayTitle(scenario))}</h3>
              ${diffBadge}
            </div>
            ${scenario.subtitle ? `<p class="text-gray-500 text-xs mb-1">${escapeHTML(scenario.subtitle)}</p>` : ""}
            <p class="text-gray-600 text-xs">${attemptLine}</p>
            ${lastCtxLine}
          </div>
          <div class="text-right shrink-0">
            <div class="text-2xl font-bold font-mono ${scoreColor}">${bestScore !== null ? bestScore + "/" + bestDenom : "—"}</div>
            <div class="text-xs ${scoreColor}">${scoreLabel}</div>
          </div>
        </div>
        <div class="flex gap-2 mt-4">
          <button class="btn-cat-start flex-1 bg-red-700 hover:bg-red-600 text-white text-xs font-semibold py-2 rounded-lg transition-colors" data-scenario="${scenario.id}">
            🔄 Retake Scenario
          </button>
          <button class="btn-cat-debrief bg-gray-800 hover:bg-gray-700 border border-gray-700 text-gray-300 text-xs font-semibold py-2 px-3 rounded-lg transition-colors" data-key="${lastAttempt?.key}">
            📄 Last Debrief
          </button>
        </div>`;
    } else {
      // ── Not yet attempted — available to start ───────────────────────
      card.className = "bg-gray-900 border border-gray-700 rounded-xl p-5";
      card.innerHTML = `
        <div class="flex items-center justify-between gap-4">
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-2 flex-wrap mb-1">
              ${numBadge}
              ${diffBadge}
            </div>
            <p class="text-gray-600 text-xs mt-0.5">Complete to unlock full details</p>
          </div>
          <button class="btn-cat-start bg-red-700 hover:bg-red-600 text-white text-xs font-semibold py-2 px-4 rounded-lg transition-colors whitespace-nowrap" data-scenario="${scenario.id}">
            ▶ Start
          </button>
        </div>`;
    }

    container.appendChild(card);
  });

  // Wire start buttons
  container.querySelectorAll(".btn-cat-start").forEach(btn => {
    btn.addEventListener("click", () => {
      resetSessionState();
      startScenario(btn.dataset.scenario);
    });
  });

  // Wire debrief buttons
  container.querySelectorAll(".btn-cat-debrief").forEach(btn => {
    btn.addEventListener("click", () => {
      _openLastResultsByKey(btn.dataset.key);
    });
  });

  showScreen("category");
  return true;
}

function _renderDistrictComingSoon(districtId) {
  const districtDef = ADVENTURE_DISTRICTS.find(d => d.id === districtId);
  const trailChip = el("category-trail-chip");
  trailChip?.classList.add("hidden");
  const trailNav = el("district-trail-nav");
  if (trailNav) {
    trailNav.classList.add("hidden");
    trailNav.innerHTML = "";
  }
  setText("category-screen-icon", districtDef?.icon || "🐾");
  setText("category-screen-title", districtDef?.title || "District");
  setText("category-screen-desc", "Coming Soon • This map is under construction.");
  _renderCategoryMapNav("district", districtId);
  show("category-district-view");
  hide("category-scenario-list");
  el("category-district-view")?.classList.remove("station1-map-pane");
  const mapWrap = document.querySelector("#category-district-view .adventure-map-wrap");
  if (mapWrap) {
    mapWrap.classList.remove("puppy-park-map", "puppy-park-map-medical-trail-2", "puppy-park-map-trauma-trail-2", "dog-park-game-map", "station1-map-wrap");
    mapWrap.style.backgroundImage = "";
    mapWrap.style.backgroundSize = "";
    mapWrap.style.backgroundPosition = "";
    mapWrap.style.backgroundRepeat = "";
  }
  const overlay = el("district-park-overlay");
  if (overlay) overlay.innerHTML = "";
  const layer = el("district-node-layer");
  if (layer) {
    layer.innerHTML = `<div class="journey-empty-card">New trails are under construction in this district.</div>`;
  }
  _clearDistrictJourneySummary();
  showScreen("category");
}

// ─── Station 1 Map renderer ─────────────────────────────────────────────────
function _station1StorageScope() {
  if (!state.scormEnabled) return "";
  try {
    return window.RescueTrails?.["scormAdapter"]?.getAttemptId?.() || "current";
  } catch {
    return "current";
  }
}

function _station1IntroKey() {
  const scope = _station1StorageScope();
  const scopePart = scope ? `scorm:${scope}:` : "";
  return `station1_intro_seen:${scopePart}${state.userId || "anon"}:${state.agency_id || "none"}`;
}

function _station1IntroSeen() {
  try {
    return localStorage.getItem(_station1IntroKey()) === "1";
  } catch {
    return false;
  }
}

function _station1MarkIntroSeen() {
  try {
    localStorage.setItem(_station1IntroKey(), "1");
  } catch { /* storage may be unavailable */ }
}

function _pedsLexiNodeSeenKey(mapId, nodeId) {
  const scope = _station1StorageScope();
  const scopePart = scope ? `scorm:${scope}:` : "";
  return `peds_lexi_node_seen:${scopePart}${state.userId || "anon"}:${state.agency_id || "none"}:${mapId || "map"}:${nodeId || "node"}`;
}

function _pedsLexiNodeSeen(mapId, nodeId) {
  try {
    return localStorage.getItem(_pedsLexiNodeSeenKey(mapId, nodeId)) === "1";
  } catch {
    return false;
  }
}

function _pedsMarkLexiNodeSeen(mapId, nodeId) {
  try {
    localStorage.setItem(_pedsLexiNodeSeenKey(mapId, nodeId), "1");
  } catch { /* visual-only state; non-fatal */ }
}

function _station1LexiGlyph(done = false) {
  return `
    <svg viewBox="0 0 155 145" xmlns="http://www.w3.org/2000/svg" class="station1-lexi-node-avatar" aria-hidden="true">
      <use href="#lexi-avatar-face-155-neutral"></use>
    </svg>
    ${done ? `<span class="journey-node-complete" aria-hidden="true">✓</span>` : ""}`;
}

function _station1DotGlyph(done = false) {
  return done
    ? `<span class="journey-node-dot"></span><span class="journey-node-complete" aria-hidden="true">✓</span>`
    : `<span class="journey-node-dot"></span>`;
}

function _station1LockSelection(label, statusText) {
  return {
    type: "station_locked",
    label,
    statusText,
  };
}

function _station1GuideBubble({ x, y, text, messages, align = "center", animate = true }) {
  const bubbleMessages = Array.isArray(messages) && messages.length ? messages : [text];
  const safeText = escapeHTML(bubbleMessages[0]);
  const attrText = safeText.replace(/<br>/g, " ");
  const attrMessages = escapeHTML(JSON.stringify(bubbleMessages.map(message => String(message ?? ""))));
  return `<div class="station1-guide-bubble station1-guide-bubble--${align}${animate ? " station1-guide-bubble--typing" : ""}"
    data-guide-bubble-text="${attrText}" data-guide-bubble-animate="${animate ? "1" : "0"}"
    data-guide-bubble-messages="${attrMessages}"
    style="left:${x}%; top:${y}%;">
    <span class="station1-guide-bubble__name">Lexi</span>
    <span class="station1-guide-bubble__text">${animate ? "" : safeText}</span>
  </div>`;
}

function _animateGuideBubbles(container) {
  if (!container) return;
  const bubbles = Array.from(container.querySelectorAll('[data-guide-bubble-animate="1"]'));
  bubbles.forEach((bubble, index) => {
    const textEl = bubble.querySelector(".station1-guide-bubble__text");
    const fallbackText = bubble.getAttribute("data-guide-bubble-text") || "";
    let messages = [fallbackText];
    try {
      const parsed = JSON.parse(bubble.getAttribute("data-guide-bubble-messages") || "[]");
      if (Array.isArray(parsed) && parsed.length) messages = parsed.map(message => String(message ?? ""));
    } catch { /* use fallback text */ }
    if (!textEl || !messages.some(Boolean)) return;

    const typeMessage = (messageIndex = 0) => {
      const fullText = messages[messageIndex] || "";
      let charIndex = 0;
      textEl.textContent = "";
      bubble.classList.add("is-typing");
      const typeNext = () => {
        charIndex += 1;
        textEl.textContent = fullText.slice(0, charIndex);
        if (charIndex < fullText.length) {
          setTimeout(typeNext, fullText[charIndex - 1] === " " ? 18 : 32);
        } else if (messageIndex < messages.length - 1) {
          setTimeout(() => typeMessage(messageIndex + 1), 950);
        } else {
          bubble.classList.remove("is-typing");
        }
      };
      typeNext();
    };

    setTimeout(() => typeMessage(0), 220 + (index * 120));
  });
}

function _scrollCurrentMapToBottom() {
  const pane = el("category-district-view");
  const mapWrap = pane?.querySelector(".adventure-map-wrap");
  if (!pane || !mapWrap) return;
  _initCategoryMapDragPan();
  requestAnimationFrame(() => {
    pane.scrollLeft = 0;
    pane.scrollTop = Math.max(0, mapWrap.offsetTop + mapWrap.offsetHeight - pane.clientHeight);
  });
}

function _openStation1IntroNode() {
  _presentMapNodeSelection({
    type: "station_intro",
    label: "Lexi Intro",
    statusText: "Lexi will walk you through Station 1: practice the scenario controls, complete a CPR drill, then return to the main map.",
  });
}

function _openStation1CompletionNode() {
  _presentMapNodeSelection({
    type: "station_wrapup",
    label: "Lexi Wrap-up",
    statusText: "Nice work completing Station 1. Head back to the main map when you're ready to start your course work.",
  });
}

function _openStation1ChallengesNode() {
  _presentMapNodeSelection({
    type: "station_challenges",
    label: "Challenges",
    statusText: "Click on Challenges in the left sidebar menu to view the requirements to complete the course and your progress.",
  });
}

const STATION1_CPR_SCENARIO_ID = "adult_cardiac_arrest_01_bls";
const STATION1_CPR_COMPLETION_IDS = new Set([
  "adult_cardiac_arrest_01_bls",
  "peds_cardiac_arrest_01_bls",
]);
const STATION1_CPR_IMAGE = "/static/images/cpr_mannequin.jpeg";
const STATION1_WRAP_NODE_ID = "wrapup";
const STATION1_CHALLENGES_NODE_ID = "challenges";
const STATION1_GUIDE_BUBBLE_POS = { x: 57.8, y: 76 };

function _station1IntroBubbleText() {
  const firstName = String(state.firstName || state.studentName || "").trim() || "there";
  const agencyName = String(state.agency || "").trim() || "your agency";
  return `Hi ${firstName}! Welcome to ${agencyName} Station 1! I'm Lexi, the station dog and your personal training companion. Click the Intro Node below to begin training.`;
}

function _station1CprDrillBestScore() {
  const scores = loadGamification().minigameBestScores || {};
  return Number(scores.cpr_bls_concepts || 0);
}

function _station1CprDrillComplete() {
  return _station1CprDrillBestScore() >= 70;
}

function _station1WrapSeen() {
  return _station1IsComplete() || _pedsLexiNodeSeen("station_1", STATION1_WRAP_NODE_ID);
}

function _station1MarkWrapSeen() {
  _pedsMarkLexiNodeSeen("station_1", STATION1_WRAP_NODE_ID);
}

function _station1ChallengesSeen() {
  return _pedsLexiNodeSeen("station_1", STATION1_CHALLENGES_NODE_ID);
}

function _station1MarkChallengesSeen() {
  _pedsMarkLexiNodeSeen("station_1", STATION1_CHALLENGES_NODE_ID);
}

function _station1RequirementsState(history = null) {
  const scopedHistory = history || loadHistory().filter(h => !h.agencyId || h.agencyId === state.agency_id);
  const completedIds = new Set(scopedHistory.map(h => h.scenarioId));
  const persistedComplete = _station1PersistedComplete();
  const introSeen = persistedComplete || _station1IntroSeen();
  const completed = persistedComplete || completedIds.has("orientation_01");
  const cprComplete = persistedComplete || _station1CprDrillComplete();
  const challengesSeen = persistedComplete || (cprComplete && _station1ChallengesSeen());
  const ready = introSeen && completed && cprComplete && challengesSeen;
  return { history: scopedHistory, completedIds, introSeen, completed, cprComplete, challengesSeen, ready };
}

function _station1ScormOrientationComplete() {
  if (!state.scormEnabled) return false;
  return _getScormUiState()?.orientationComplete === true && !!state.orientationCompletedAt;
}

function _station1PersistedComplete() {
  return !!state.orientationCompletedAt;
}

function _station1IsComplete(requirements = null) {
  if (_station1PersistedComplete()) return true;
  const req = requirements || _station1RequirementsState();
  return !!state.orientationCompletedAt && !!req.ready;
}

function _station1IncompleteMessage(requirements) {
  if (!requirements.introSeen) return "Start with the Lexi Intro node before completing Station 1.";
  if (!requirements.completed) return "Finish the Orientation Tour before completing Station 1.";
  if (!requirements.cprComplete) return "Complete the Station 1 CPR drill before completing Station 1.";
  if (!requirements.challengesSeen) return "Open the Challenges Briefing before completing Station 1.";
  return "Complete all Station 1 requirements before continuing.";
}

function _latestOrientationSessionId() {
  return _orientationCompleteEntry?.key
    || loadHistory().find(h => h.scenarioId === "orientation_01" && (!h.agencyId || h.agencyId === state.agency_id))?.key
    || null;
}

async function _completeStation1FromWrapupNode() {
  const requirements = _station1RequirementsState();
  if (!requirements.ready) {
    showToast(_station1IncompleteMessage(requirements), "error");
    return false;
  }
  const sessionId = _latestOrientationSessionId();
  if (!sessionId) {
    showToast("Finish the Orientation Tour before completing Station 1.", "error");
    return false;
  }
  const res = await authFetch(`${API}/api/me/orientation/complete`, {
    method: "POST",
    body: JSON.stringify({ session_id: sessionId }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.detail || "Could not complete Station 1.");
  }
  state.orientationCompletedAt = new Date().toISOString();
  if (state.scormEnabled) _setScormUiState({ location: "home", map: "map_0", orientationComplete: true });
  const meRes = await authFetch(`${API}/api/me`).catch(() => null);
  if (meRes?.ok) {
    const me = await meRes.json().catch(() => null);
    state.orientationCompletedAt = me?.orientation_completed_at || state.orientationCompletedAt;
  }
  await _loadProgressFromServer().catch(() => {});
  _refreshGamificationChrome();
  await _refreshScormSummary().catch(() => {});
  _refreshScormChallengeDisplays();
  showToast("Station 1 complete. Check Challenges any time from the sidebar.", "success");
  return true;
}

function _renderStation1Map() {
  const history = loadHistory().filter(h => !h.agencyId || h.agencyId === state.agency_id);
  const requirements = _station1RequirementsState(history);
  const { completedIds, introSeen, completed, cprComplete, challengesSeen } = requirements;

  setText("category-screen-icon", "🚒");
  setText("category-screen-title", "Station 1");
  setText("category-screen-desc", "Firehouse orientation and assessment foundations.");
  _renderCategoryMapNav("district", "station_1");

  el("category-trail-chip")?.classList.add("hidden");
  const trailNav = el("district-trail-nav");
  if (trailNav) { trailNav.classList.add("hidden"); trailNav.innerHTML = ""; }

  show("category-district-view");
  hide("category-scenario-list");
  el("category-district-view")?.classList.add("station1-map-pane");

  const mapWrap = document.querySelector("#category-district-view .adventure-map-wrap");
  if (mapWrap) {
    PEDS_MAP_DATA.forEach(m => { if (m.bgClass) mapWrap.classList.remove(m.bgClass); });
    mapWrap.classList.remove("puppy-park-map", "puppy-park-map-medical-trail-2", "puppy-park-map-trauma-trail-2", "dog-park-game-map", "station1-map-wrap");
    mapWrap.classList.add("station1-map-wrap");
    mapWrap.style.backgroundImage = "url('/static/img/maps/orientation/station.jpeg?v=20260510')";
    mapWrap.style.backgroundSize = "contain";
    mapWrap.style.backgroundPosition = "center";
    mapWrap.style.backgroundRepeat = "no-repeat";
  }

  const overlay = el("district-park-overlay");
  if (overlay) overlay.innerHTML = "";

  const layer = el("district-node-layer");
  if (!layer) { showScreen("category"); return; }

  const scenario = state.allScenarios.find(s => s.id === "orientation_01");
  const cprScenario = state.allScenarios.find(s => s.id === STATION1_CPR_SCENARIO_ID);
  const cprLastEntry = history
    .filter(h => h.scenarioId === STATION1_CPR_SCENARIO_ID)
    .sort((a, b) => (b.key || 0) - (a.key || 0))[0] || null;
  const lastEntry = history
    .filter(h => h.scenarioId === "orientation_01")
    .sort((a, b) => (b.key || 0) - (a.key || 0))[0] || null;
  const label = scenario?.display_title || "Station Skills Drill";

  const orientationLocked = !introSeen;
  const cprLocked = !completed;
  const challengesLocked = !cprComplete;
  const completionLocked = !introSeen || !completed || !cprComplete || !challengesSeen;
  const station1Guide = text => _station1GuideBubble({ ...STATION1_GUIDE_BUBBLE_POS, text, align: "center" });
  const guide = !introSeen
    ? station1Guide(_station1IntroBubbleText())
    : !completed
      ? station1Guide("Next: complete the Station Skills Drill.")
      : !cprComplete
        ? station1Guide("Next: complete the CPR Drill.")
        : !challengesSeen
          ? station1Guide("Next: check the Challenges Briefing.")
          : !_station1IsComplete(requirements)
            ? station1Guide("Final step: click on the Wrap-up to complete your orientation.")
            : station1Guide("Station 1 complete. Now go do some hero stuff!");

  layer.innerHTML = `
    ${guide}
    <button class="journey-node journey-node--lexi ${introSeen ? "done" : "open"}"
      data-s1-node="intro"
      title="Lexi Intro" aria-label="Lexi Intro"
      style="left:51%; top:90%;">
      ${_station1LexiGlyph(introSeen)}
    </button>
    <button class="journey-node ${orientationLocked ? "locked" : completed ? "done" : "open"}"
      data-s1-scenario="orientation_01"
      title="${escapeHTML(label)}" aria-label="${escapeHTML(label)}"
      style="left:23%; top:52%;">
      ${orientationLocked ? `<span class="journey-node-lock" aria-hidden="true">🔒</span>` : _station1DotGlyph(completed)}
    </button>
    <button class="journey-node ${cprLocked ? "locked" : cprComplete ? "done" : "open"}"
      data-s1-cpr="${escapeHTML(STATION1_CPR_SCENARIO_ID)}"
      title="CPR Training Drill" aria-label="CPR Training Drill"
      style="left:76%; top:69%;">
      ${cprLocked ? `<span class="journey-node-lock" aria-hidden="true">🔒</span>` : `📚${cprComplete ? `<span class="journey-node-complete" aria-hidden="true">✓</span>` : ""}`}
    </button>
    <button class="journey-node journey-node--lexi ${completionLocked ? "locked" : _station1IsComplete(requirements) ? "done" : "open"}"
      data-s1-node="complete"
      title="Lexi Wrap-up" aria-label="Lexi Wrap-up"
      style="left:49%; top:44%;">
      ${completionLocked ? `<span class="journey-node-lock" aria-hidden="true">🔒</span>` : _station1LexiGlyph(_station1IsComplete(requirements))}
    </button>
    <button class="journey-node journey-node--lexi ${challengesLocked ? "locked" : challengesSeen ? "done" : "open"}"
      data-s1-node="challenges"
      title="Challenges Briefing" aria-label="Challenges Briefing"
      style="left:14%; top:52%;">
      ${challengesLocked ? `<span class="journey-node-lock" aria-hidden="true">🔒</span>` : _station1LexiGlyph(challengesSeen)}
    </button>`;
  _animateGuideBubbles(layer);

  layer.querySelector('[data-s1-node="intro"]')?.addEventListener("click", _openStation1IntroNode);
  layer.querySelector('[data-s1-node="complete"]')?.addEventListener("click", () => {
    if (completionLocked) {
      _presentMapNodeSelection(_station1LockSelection("Lexi Wrap-up Locked", "Complete the Orientation Tour, CPR drill, and Challenges briefing before the final Station 1 message."));
      return;
    }
    _openStation1CompletionNode();
  });
  layer.querySelector('[data-s1-node="challenges"]')?.addEventListener("click", () => {
    if (challengesLocked) {
      _presentMapNodeSelection(_station1LockSelection("Challenges Briefing Locked", "Complete the CPR drill before the Challenges briefing."));
      return;
    }
    _openStation1ChallengesNode();
  });

  layer.querySelector("[data-s1-scenario]")?.addEventListener("click", () => {
    if (orientationLocked) {
      _presentMapNodeSelection(_station1LockSelection("Orientation Tour Locked", "Start with the Lexi Intro node first."));
      return;
    }
    _openScenarioPreview({
      scenarioId: "orientation_01",
      available: true,
      label,
      completed,
      lastEntry,
      scenario,
      lane: null,
    });
  });
  layer.querySelector("[data-s1-cpr]")?.addEventListener("click", () => {
    if (cprLocked) {
      _presentMapNodeSelection(_station1LockSelection("CPR Drill Locked", "Complete the Orientation Tour before starting the CPR drill."));
      return;
    }
    _presentMapNodeSelection({
      type: "cpr_bls_concepts",
      label: "CPR Mastery Drill",
      completed: cprComplete,
      statusText: cprComplete
        ? "CPR training drill completed. Replay the CPR metrics drill any time."
        : "Answer the CPR metric questions. Score at least 4 out of 5 to complete the drill.",
      detailHtml: `
        <figure class="scenario-preview-image-card">
          <img src="${STATION1_CPR_IMAGE}" alt="CPR training mannequin" loading="lazy" />
        </figure>
      `,
      returnDistrictId: "station_1",
    });
  });

  _renderStation1Sidebar({ introSeen, completed, cprComplete, challengesSeen });
  _clearDistrictJourneySummary();

  showScreen("category");
  _scrollCurrentMapToBottom();
}

// ─── Pediatric Map v2 renderer ───────────────────────────────────────────────
function _renderPedsMap(mapId = null) {
  if (mapId && _PEDS_MAP_BY_ID.has(mapId)) {
    _pedsJourneyState.currentMap = mapId;
    _savePedsJourneyState();
  } else {
    _restorePedsJourneyState();
  }
  let currentMapId = _pedsJourneyState.currentMap || "map_0";

  // Unlock state (normally null when dev-unlocked)
  const _history = loadHistory().filter(h => !h.agencyId || h.agencyId === state.agency_id);
  const { passedIds: _passedIds, pedsMapCompleted: _pedsMapCompleted } = _pedsMapCompletionSets();
  const _baseUnlockState = _computeMapUnlockState(_passedIds, MAP_TOPOLOGY, _pedsMapCompleted);
  const unlockState = (() => {
    if (!PEDS_MAP_DEV_UNLOCKED) return _baseUnlockState;
    return null;
  })();

  const currentUnlock = unlockState?.get(currentMapId);
  const currentLocked = state.scormEnabled
    ? !_scormPedsMapAllowed(currentMapId) || !_scormMapRouteUnlocked(currentMapId)
    : (!!unlockState && currentMapId !== "map_0" && !currentUnlock?.unlocked && !currentUnlock?.partial);
  if (currentLocked) {
    currentMapId = "map_0";
    _pedsJourneyState.currentMap = currentMapId;
    _savePedsJourneyState();
  }
  if (state.scormEnabled) _setScormUiState({ location: "peds", map: currentMapId });

  const mapDef = _PEDS_MAP_BY_ID.get(currentMapId) || PEDS_MAP_DATA[0];

  // Detect newly-unlocked maps for reveal animation (per-session, sessionStorage)
  const _prevSnapshotKey = `peds_unlock_snapshot_${state.userId || "anon"}`;
  const _prevSnapshot = (() => { try { return JSON.parse(sessionStorage.getItem(_prevSnapshotKey) || "{}"); } catch { return {}; } })();
  const _newlyUnlocked = new Set();
  if (unlockState) {
    for (const [mid, s] of unlockState) {
      if (s.unlocked && !_prevSnapshot[mid]) _newlyUnlocked.add(mid);
    }
    const snap = {};
    for (const [mid, s] of unlockState) if (s.unlocked) snap[mid] = true;
    try { sessionStorage.setItem(_prevSnapshotKey, JSON.stringify(snap)); } catch { /* non-fatal */ }
  }

  // Header
  setText("category-screen-icon", "🏫");
  setText("category-screen-title", "Pediatrics");
  setText("category-screen-desc", mapDef.theme);
  _renderCategoryMapNav("district", "pediatrics");
  show("category-district-view");
  hide("category-scenario-list");
  el("category-district-view")?.classList.remove("station1-map-pane");

  const trailChip = el("category-trail-chip");
  if (trailChip) { trailChip.textContent = mapDef.label; trailChip.classList.remove("hidden"); }

  // Map background
  const mapWrap = document.querySelector("#category-district-view .adventure-map-wrap");
  if (mapWrap) {
    PEDS_MAP_DATA.forEach(m => {
      if (m.bgClass) mapWrap.classList.remove(m.bgClass);
    });
    mapWrap.classList.remove("puppy-park-map", "puppy-park-map-medical-trail-2", "puppy-park-map-trauma-trail-2", "dog-park-game-map");
    if (mapDef.bgClass) mapWrap.classList.add(mapDef.bgClass);
    if (mapDef.image) {
      _prioritizePedsMapImage(mapDef.image);
      mapWrap.style.backgroundImage = `url('${mapDef.image}')`;
      mapWrap.style.backgroundSize = "cover";
      mapWrap.style.backgroundPosition = "center";
      mapWrap.style.backgroundRepeat = "";
    } else {
      mapWrap.style.backgroundImage = "";
    }
  }

  // Navigation overlay: back + exits
  const overlay = el("district-park-overlay");
  if (overlay) {
    const _navStyle = (pos, defaultX, defaultY) => {
      const p = pos || { x: defaultX, y: defaultY, r: 0 };
      return `left:${p.x}%; top:${p.y}%;`;
    };
    let html = "";
    // Single parent back button
    if (mapDef.parent) {
      const parentLabel = _PEDS_MAP_BY_ID.get(mapDef.parent)?.label || "Back";
      html += `<button class="trail-map-btn trail-map-btn--back" data-peds-nav="${mapDef.parent}"
        title="Back to ${parentLabel}" style="${_navStyle(mapDef.backPos, 8, 85)}">Back</button>`;
    }

    // Multi-parent back buttons (convergence maps)
    (mapDef.parents || []).forEach(p => {
      html += `<button class="trail-map-btn trail-map-btn--back" data-peds-nav="${p.to}"
        title="${escapeHTML(p.label)}" style="${_navStyle(p.pos, 8, 85)}">Back</button>`;
    });

    // Forward exits — apply lock state when unlock enforcement is active
    const exits = state.scormEnabled
      ? mapDef.exits.filter(exit => _scormPedsMapAllowed(exit.to))
      : mapDef.exits;
    exits.forEach(exit => {
      const destState = unlockState?.get(exit.to);
      const isLocked  = state.scormEnabled
        ? !_scormMapRouteUnlocked(exit.to)
        : (unlockState && !destState?.unlocked && !destState?.partial);
      const isPartial = state.scormEnabled
        ? false
        : (unlockState && !destState?.unlocked && destState?.partial);
      const lockCls   = isLocked ? " trail-map-btn--locked" : isPartial ? " trail-map-btn--future" : "";
      const destLabel = _PEDS_MAP_BY_ID.get(exit.to)?.label || exit.label || "Next";
      const label = isLocked ? "🔒" : destLabel;
      html += `<button class="trail-map-btn trail-map-btn--next${lockCls}"
        data-peds-nav="${exit.to}" ${isLocked ? "disabled aria-disabled='true'" : ""}
        title="${escapeHTML(exit.label)}" style="${_navStyle(exit.pos, 88, 15)}">${label}</button>`;
    });

    overlay.innerHTML = html;
    overlay.querySelectorAll("[data-peds-nav]").forEach(btn => {
      btn.addEventListener("click", () => _renderPedsMap(btn.getAttribute("data-peds-nav")));
    });
  }

  // Scenario & game nodes
  const layer = el("district-node-layer");
  if (layer) {
    const history = loadHistory().filter(h => !h.agencyId || h.agencyId === state.agency_id);
    const completedIds = new Set(history.filter(_scenarioHistoryEntryPassed).map(h => h.scenarioId));
    if (state.scormEnabled) {
      Object.entries(_SCORM_NODE_BY_APP_ID).forEach(([appId, node]) => {
        if (node?.type === "scenario" && _scormNodeCompleteByNodeId(node.nodeId)) {
          completedIds.add(appId);
        }
      });
    }
    const histByScenario = new Map();
    history.forEach(h => { if (!histByScenario.has(h.scenarioId)) histByScenario.set(h.scenarioId, h); });
    const scenarioLookup = new Map(state.allScenarios.map(s => [s.id, s]));
    const completedGameIds = _completedLearningGameIds();

    const nodeBtns = mapDef.scenarios.map(s => {
      const isPh = s.id.startsWith("_ph");
      const scenario = isPh ? null : scenarioLookup.get(s.id);
      const scormLocked = !isPh && _scormScenarioLocked(s.id, currentMapId);
      const completed = !isPh && completedIds.has(s.id);
      const available = PEDS_MAP_DEV_UNLOCKED || (!isPh && !!scenario);
      const statusClass = (isPh || scormLocked) ? "locked" : completed ? "done" : "open";
      const glyph = isPh
        ? `<span class="journey-node-lock" aria-hidden="true">🔒</span>`
        : scormLocked
          ? `<span class="journey-node-lock" aria-hidden="true">🔒</span>`
          : completed
          ? `<span class="journey-node-dot"></span><span class="journey-node-complete" aria-hidden="true">✓</span>`
          : `<span class="journey-node-dot"></span>`;
      const scenarioTitle = _scenarioRevealedTitle(scenario, completed) || s.label;
      const tip = isPh
        ? `${s.label} — Coming Soon`
        : scormLocked
          ? `${scenarioTitle} — Complete the Map 0 route scenario to unlock`
          : completed ? `${scenarioTitle} — Cleared` : `${scenarioTitle} — Available`;
      return `<button class="journey-node ${statusClass}" data-peds-scenario="${s.id}"
        ${isPh ? "disabled" : ""}
        title="${escapeHTML(tip)}" aria-label="${escapeHTML(tip)}"
        style="left:${s.x}%; top:${s.y}%;">${glyph}</button>`;
    });

    const _renderGameNode = (g) => {
      const isPh = g.id.startsWith("_ph");
      const glyph = "📚";
      const completionId = _mapGameCompletionId(g.id);
      const patCompleted = completionId === "pat" ? !!_patStatusCache?.ever_completed : false;
      const devCompleted = completionId === "dev_sort" ? _devSortGamesSummary().completed === 1 : false;
      const completed = patCompleted || devCompleted || completedGameIds.has(completionId) || _scormAppComplete(completionId);
      const completeMark = completed ? `<span class="journey-node-complete" aria-hidden="true">✓</span>` : "";
      const statusClass = isPh ? "locked" : completed ? "done" : "open";
      const tip = isPh ? `${g.label} — Coming Soon` : completed ? `${g.label} — Complete` : `${g.label}`;
      nodeBtns.push(`<button class="journey-node ${statusClass}" data-peds-game="${g.id}"
        ${isPh ? "disabled" : ""}
        title="${escapeHTML(tip)}" aria-label="${escapeHTML(tip)}"
        style="left:${g.x}%; top:${g.y}%;">${glyph}${completeMark}</button>`);
    };
    if (mapDef.games) { mapDef.games.forEach(_renderGameNode); }
    else if (mapDef.game) { _renderGameNode(mapDef.game); }

    if (Array.isArray(mapDef.lexiNodes)) {
      mapDef.lexiNodes.forEach(node => {
        const seen = _pedsLexiNodeSeen(currentMapId, node.id);
        nodeBtns.push(`<button class="journey-node journey-node--lexi ${seen ? "done" : "open"}" data-peds-lexi="${escapeHTML(node.id)}"
          title="${escapeHTML(node.label || "Lexi Message")}" aria-label="${escapeHTML(node.label || "Lexi Message")}"
          style="left:${node.x}%; top:${node.y}%;">${_station1LexiGlyph(seen)}</button>`);
      });
    }

    if (mapDef.shop) {
      const s = mapDef.shop;
      nodeBtns.push(`<button class="journey-node open scout-shop-node" data-peds-shop="${s.district}"
        title="${escapeHTML(s.label)}" aria-label="${escapeHTML(s.label)}"
        style="left:${s.x}%; top:${s.y}%;"><span class="scout-shop-node-icon">🧸</span></button>`);
    }

    const chatBubbles = Array.isArray(mapDef.chatBubbles)
      ? mapDef.chatBubbles.map(bubble => _station1GuideBubble({
          x: bubble.x,
          y: bubble.y,
          text: bubble.text || "TBD",
          messages: bubble.messages,
          align: bubble.align || "center",
        }))
      : [];

    layer.innerHTML = [...chatBubbles, ...nodeBtns].join("");
    _animateGuideBubbles(layer);

    layer.querySelectorAll("[data-peds-scenario]").forEach(btn => {
      btn.addEventListener("click", () => {
        const sid = btn.getAttribute("data-peds-scenario");
        if (!sid || sid.startsWith("_ph")) return;
        const scenario = scenarioLookup.get(sid);
        if (!scenario) return;
        if (_scormScenarioLocked(sid, currentMapId)) {
          _presentMapNodeSelection(_station1LockSelection(
            "Scenario Locked",
            "Complete the required Map 0 route scenario before starting this trail.",
          ));
          return;
        }
        _presentMapNodeSelection({
          type: "scenario",
          scenarioId: sid,
          label: _scenarioRevealedTitle(scenario, completedIds.has(sid)) || sid,
          scenario,
          categoryLabel: _scenarioCategoryLabelFromNode({ scenario }),
          completed: completedIds.has(sid),
          available: true,
          lastEntry: histByScenario.get(sid) || null,
        });
      });
    });

    layer.querySelectorAll("[data-peds-lexi]").forEach(btn => {
      btn.addEventListener("click", () => {
        const nodeId = btn.getAttribute("data-peds-lexi");
        const node = (mapDef.lexiNodes || []).find(item => item.id === nodeId);
        if (!node) return;
        _pedsMarkLexiNodeSeen(currentMapId, nodeId);
        btn.classList.remove("open");
        btn.classList.add("done");
        btn.innerHTML = _station1LexiGlyph(true);
        _presentMapNodeSelection({
          type: "lexi_message",
          label: node.label || "Lexi Message",
          statusText: node.message || "Keep scanning the patient from the doorway first.",
        });
      });
    });

    layer.querySelectorAll("[data-peds-game]").forEach(btn => {
      btn.addEventListener("click", () => {
        const gid = btn.getAttribute("data-peds-game");
        const g = mapDef.games ? mapDef.games.find(x => x.id === gid) : mapDef.game;
        if (gid === "pat_dash")           { _openPatPreview(currentMapId);       return; }
        if (gid === "dev_sort")           { _openDevSortPreview(currentMapId);   return; }
        if (gid === "ten4_facesp")        { _openMgPreview(gid, g?.label || "TEN-4 FACESp", currentMapId);        return; }
        if (gid === "shock_spotter_med")  { _openMgPreview(gid, g?.label || "Shock Spotter Med", currentMapId);   return; }
        if (gid === "adult_child_ap_swipe") { _openMgPreview(gid, g?.label || "Adult vs. Child A&P", currentMapId); return; }
        if (gid === "lung_sounds_matcher") { _openMgPreview(gid, g?.label || "Lung Sounds Matcher", currentMapId); return; }
        if (gid === "sound_check")          { _openMgPreview(gid, g?.label || "Sound Check", currentMapId);         return; }
        if (gid === "history_maker")      { _openMgPreview(gid, g?.label || "History Maker", currentMapId);       return; }
        if (gid === "peds_gcs_calculator") { _openMgPreview(gid, g?.label || "Peds GCS Calculator", currentMapId); return; }
        if (gid === "ams_aeioutips")      { _openMgPreview(gid, g?.label || "AMS Differential", currentMapId);    return; }
        if (gid === "diff_dash_ams")      { _openMgPreview(gid, g?.label || "Differential Dash AMS", currentMapId); return; }
        if (gid === "diff_dash_resp")     { _openMgPreview(gid, g?.label || "Differential Dash Respiratory", currentMapId); return; }
        if (gid === "rule_of_nines")      { _openMgPreview(gid, g?.label || "Rule of Nines", currentMapId); return; }
        if (gid === "stop_the_bleed")     { _openMgPreview(gid, g?.label || "Stop the Bleed", currentMapId); return; }
        if (gid === "bls_sequence")       { _openMgPreview(gid, g?.label || "BLS Sequence", currentMapId); return; }
        if (gid === "priority_stack")     { _openMgPreview(gid, g?.label || "Priority Stack", currentMapId); return; }
        if (gid === "moi_mapper")         { _openMgPreview(gid, g?.label || "MOI Mapper", currentMapId); return; }
        if (gid === "shock_spotter_trauma") { _openMgPreview(gid, g?.label || "Shock Spotter Trauma", currentMapId); return; }
        if (gid === "temp_check")         { _openMgPreview(gid, g?.label || "Temp Check", currentMapId); return; }
        if (gid && !gid.startsWith("_ph")) { _openMgPreview(gid, g?.label || "Training Drill", currentMapId); return; }
      });
    });

  }

  // Trail nav — breadcrumb with home + track shortcuts
  const trailNav = el("district-trail-nav");
  if (trailNav) {
    const isEntrance  = currentMapId === "map_0";
    const isMedical   = ["pm1","pm2","pm3","pm4","pm5","pm6","pm7"].includes(currentMapId);
    const isTrauma    = ["pt1","pt2","pt3","pt4","pt5","pt6","pt7","pt8"].includes(currentMapId);
    const isEmergency = ["pe1","pe2"].includes(currentMapId);

    // Lock state for trail shortcuts
    const pm1Locked = unlockState && !unlockState.get("pm1")?.unlocked && !unlockState.get("pm1")?.partial;
    const pt1Locked = unlockState && !unlockState.get("pt1")?.unlocked && !unlockState.get("pt1")?.partial;
    const pe1Locked = unlockState && !unlockState.get("pe1")?.unlocked && !unlockState.get("pe1")?.partial;

    // PE1 two-key gate: count how many of pm7/pt8 are fully satisfied
    const pe1KeyCount = unlockState
      ? ["pm7", "pt8"].filter(mid =>
          unlockState.get(mid)?.unlocked && _mapHasCompletion(mid, _passedIds, _pedsMapCompleted)
        ).length
      : 2;
    const pe1Label = (unlockState && !unlockState.get("pe1")?.unlocked)
      ? `🚨 Emergencies <span class="pe1-key-counter">${pe1KeyCount}/2 🔑</span>`
      : "🚨 Emergencies";

    if (state.scormEnabled) {
      const pm1Locked = !_scormMapRouteUnlocked("pm1");
      const pt1Locked = !_scormMapRouteUnlocked("pt1");
      trailNav.innerHTML = [
        `<button class="district-trail-btn district-trail-home" data-scorm-nav="orientation">🚒 Orientation</button>`,
        `<button class="district-trail-btn${isEntrance ? " active" : ""}" data-peds-nav="map_0">🏠 Map 0</button>`,
        `<button class="district-trail-btn${currentMapId === "pm1" ? " active" : ""}${pm1Locked ? " locked" : ""}"
          data-peds-nav="pm1" ${pm1Locked ? "disabled" : ""}>🩺 PM1${pm1Locked ? " 🔒" : ""}</button>`,
        `<button class="district-trail-btn${currentMapId === "pt1" ? " active" : ""}${pt1Locked ? " locked" : ""}"
          data-peds-nav="pt1" ${pt1Locked ? "disabled" : ""}>🦴 PT1${pt1Locked ? " 🔒" : ""}</button>`,
      ].join("");
    } else {
      trailNav.innerHTML = [
        `<button class="district-trail-btn district-trail-home${isEntrance ? " active" : ""}" data-peds-nav="map_0">🏠 Entrance</button>`,
        `<button class="district-trail-btn${isMedical ? " active" : ""}${pm1Locked ? " locked" : ""}"
          data-peds-nav="pm1" ${pm1Locked ? "disabled" : ""}>🩺 Medical${pm1Locked ? " 🔒" : ""}</button>`,
        `<button class="district-trail-btn${isTrauma ? " active" : ""}${pt1Locked ? " locked" : ""}"
          data-peds-nav="pt1" ${pt1Locked ? "disabled" : ""}>🦴 Trauma${pt1Locked ? " 🔒" : ""}</button>`,
        `<button class="district-trail-btn${isEmergency ? " active" : ""}${pe1Locked ? " locked" : ""}"
          data-peds-nav="pe1" ${pe1Locked ? "disabled" : ""}>${pe1Label}</button>`,
      ].join("");
    }
    trailNav.classList.remove("hidden");
    trailNav.querySelector("[data-scorm-nav='orientation']")?.addEventListener("click", () => {
      _enterScormOrientationMap();
    });
    trailNav.querySelectorAll("[data-peds-nav]:not([disabled])").forEach(btn => {
      btn.addEventListener("click", () => _renderPedsMap(btn.getAttribute("data-peds-nav")));
    });
  }

  _renderPedsMapSidebar(currentMapId, _baseUnlockState, _passedIds, _pedsMapCompleted);
  _clearDistrictJourneySummary();

  // Lazy-load PAT/devSort status and re-render if needed
  const _reRender = () => {
    if (_categoryView?.mode === "district" && _categoryView?.districtId === "pediatrics"
        && !el("screen-category")?.classList.contains("hidden")) {
      _renderPedsMap();
    }
  };
  if (!_patStatusAttempted && !_patStatusLoading) {
    _patStatusLoading = true;
    _loadPatStatus().finally(() => { _patStatusLoading = false; _reRender(); });
  }
  if (!_devSortStatusAttempted && !_devSortStatusLoading) {
    _devSortStatusLoading = true;
    _loadDevSortStatus().finally(() => { _devSortStatusLoading = false; _reRender(); });
  }
  const learningFresh = _notebookLearningCache.scope === _notebookCacheScope() &&
    Array.isArray(_notebookLearningCache.data) &&
    (Date.now() - Number(_notebookLearningCache.fetchedAt || 0)) <= _NOTEBOOK_CACHE_TTL_MS;
  if (!learningFresh && !_pedsLearningStatusLoading) {
    _pedsLearningStatusLoading = true;
    _fetchNotebookLearningData(false)
      .catch(() => [])
      .finally(() => { _pedsLearningStatusLoading = false; _reRender(); });
  }

  showScreen("category");
  _scrollCurrentMapToBottom();
}

function _renderPediatricsJourney(opts = {}) {
  _renderPedsMap();
}

async function _renderDogPark() {
  const districtDef = ADVENTURE_DISTRICTS.find(d => d.id === "other");
  const trailChip = el("category-trail-chip");
  trailChip?.classList.add("hidden");
  const trailNav = el("district-trail-nav");
  if (trailNav) {
    trailNav.classList.add("hidden");
    trailNav.innerHTML = "";
  }

  setText("category-screen-icon", districtDef?.icon || "📚");
  setText("category-screen-title", districtDef?.title || "Training Center");
  setText("category-screen-desc", "Replay unlocked drills by skill category.");
  _renderCategoryMapNav("district", "other");
  show("category-district-view");
  hide("category-scenario-list");
  el("category-district-view")?.classList.remove("station1-map-pane");

  const mapWrap = document.querySelector("#category-district-view .adventure-map-wrap");
  if (mapWrap) {
    PEDS_MAP_DATA.forEach(m => {
      if (m.bgClass) mapWrap.classList.remove(m.bgClass);
    });
    mapWrap.classList.remove("puppy-park-map", "puppy-park-map-medical-trail-2", "puppy-park-map-trauma-trail-2", "station1-map-wrap");
    mapWrap.classList.add("dog-park-game-map");
    mapWrap.style.backgroundImage = "";
    mapWrap.style.backgroundSize = "";
    mapWrap.style.backgroundPosition = "";
    mapWrap.style.backgroundRepeat = "";
  }
  const overlay = el("district-park-overlay");
  if (overlay) overlay.innerHTML = "";
  const layer = el("district-node-layer");
  if (layer) {
    layer.innerHTML = `<div class="dog-park-game-panel"><p class="text-amber-900/70 text-xs text-center py-6">Loading unlocked drills...</p></div>`;
  }
  _clearDistrictJourneySummary();
  showScreen("category");

  try {
    const learning = await _fetchNotebookLearningData(false);
    const dogParkLearning = (Array.isArray(learning) ? learning : [])
      .filter(l => (l.category_id || "dog_park") === "dog_park");
    const unlockedGameIds = new Set(dogParkLearning.map(l => l.game_id).filter(Boolean));
    const visibleGroups = _dogParkVisibleGroups(unlockedGameIds);
    const unlockedCount = visibleGroups.reduce((sum, group) => sum + group.games.length, 0);

    if (!layer) return;
    if (unlockedCount === 0) {
      layer.innerHTML = `<div class="dog-park-game-panel dog-park-game-panel--empty">
        <div class="dog-park-game-empty-icon">📚</div>
        <h3>No replay drills unlocked yet.</h3>
        <p>Pass a drill with a score of 70% or higher to unlock it here for replay.</p>
      </div>`;
    } else {
      layer.innerHTML = `<div class="dog-park-game-panel">
        <div class="dog-park-game-heading">
          <div>
            <p class="dog-park-game-kicker">Training Center</p>
            <h3>Unlocked Replay Drills</h3>
          </div>
          <span>${unlockedCount}</span>
        </div>
        <div class="dog-park-game-groups">
          ${visibleGroups.map(group => `
            <section class="dog-park-game-group">
              <div class="dog-park-game-group-head">
                <div>
                  <h4>${escapeHTML(group.title)}</h4>
                  <p>${escapeHTML(group.subtitle)}</p>
                </div>
                <span>${group.games.length}</span>
              </div>
              <div class="dog-park-game-grid">
                ${group.games.map(game => `
                  <button type="button" class="dog-park-game-card" data-dog-park-game="${escapeHTML(game.type)}">
                    <span class="dog-park-game-card__icon">${escapeHTML(game.icon || "MG")}</span>
                    <span class="dog-park-game-card__text">
                      <span class="dog-park-game-card__title">${escapeHTML(game.label)}</span>
                      <span class="dog-park-game-card__subtitle">${escapeHTML(game.subtitle || "Replay this drill.")}</span>
                    </span>
                    <span class="dog-park-game-card__cta">${escapeHTML(game.cta || "Play Again")}</span>
                  </button>
                `).join("")}
              </div>
            </section>
          `).join("")}
        </div>
      </div>`;
      const catalog = _dogParkGameCatalog();
      layer.querySelectorAll("[data-dog-park-game]").forEach(btn => {
        btn.addEventListener("click", () => {
          const type = btn.getAttribute("data-dog-park-game");
          const game = catalog.find(g => g.type === type);
          _openDogParkGamePreview(game);
        });
      });
    }
    _clearDistrictJourneySummary();
  } catch {
    const visibleGroups = _dogParkVisibleGroups(new Set());
    const unlockedCount = visibleGroups.reduce((sum, group) => sum + group.games.length, 0);
    if (layer) {
      layer.innerHTML = `<div class="dog-park-game-panel">
        <div class="dog-park-game-heading">
          <div>
            <p class="dog-park-game-kicker">Training Center</p>
            <h3>Training Center</h3>
          </div>
          <span>${unlockedCount}</span>
        </div>
        <div class="dog-park-game-groups">
          ${visibleGroups.map(group => `
            <section class="dog-park-game-group">
              <div class="dog-park-game-group-head">
                <div>
                  <h4>${escapeHTML(group.title)}</h4>
                  <p>${escapeHTML(group.subtitle)}</p>
                </div>
                <span>${group.games.length}</span>
              </div>
              <div class="dog-park-game-grid">
                ${group.games.map(game => `
                  <button type="button" class="dog-park-game-card" data-dog-park-game="${escapeHTML(game.type)}">
                    <span class="dog-park-game-card__icon">${escapeHTML(game.icon || "MG")}</span>
                    <span class="dog-park-game-card__text">
                      <span class="dog-park-game-card__title">${escapeHTML(game.label)}</span>
                      <span class="dog-park-game-card__subtitle">${escapeHTML(game.subtitle || "Replay this drill.")}</span>
                    </span>
                    <span class="dog-park-game-card__cta">${escapeHTML(game.cta || "Play Again")}</span>
                  </button>
                `).join("")}
              </div>
            </section>
          `).join("")}
          <p class="text-xs text-amber-900/70">Could not refresh unlocked drills. Station 1 remains available from the main map.</p>
        </div>
      </div>`;
      const catalog = _dogParkGameCatalog();
      layer.querySelectorAll("[data-dog-park-game]").forEach(btn => {
        btn.addEventListener("click", () => {
          const type = btn.getAttribute("data-dog-park-game");
          const game = catalog.find(g => g.type === type);
          _openDogParkGamePreview(game);
        });
      });
    }
    _clearDistrictJourneySummary();
  }
}

function _openTrainingCenter(returnTarget = null) {
  if (returnTarget) {
    _trainingCenterReturnTarget = returnTarget;
  } else if (_categoryView?.mode === "district" && _categoryView?.districtId && _categoryView.districtId !== "other") {
    _trainingCenterReturnTarget = { type: "district", districtId: _categoryView.districtId };
  } else {
    _trainingCenterReturnTarget = { type: "menu" };
  }
  _renderTrainingCenter();
}

// ─── Training Center — map accessibility ─────────────────────────────────────

function _buildAccessibleTrainingCenterMaps() {
  const accessible = new Set(["station_1"]);
  if (!_station1IsComplete()) return accessible;

  accessible.add("map_0");
  if (state.scormEnabled) {
    PEDS_MAP_DATA.forEach(mapDef => {
      if (_scormMapRouteUnlocked(mapDef.id)) accessible.add(mapDef.id);
    });
    return accessible;
  }

  const { passedIds, pedsMapCompleted } = _pedsMapCompletionSets();
  const unlockState = _computeMapUnlockState(passedIds, MAP_TOPOLOGY, pedsMapCompleted);
  PEDS_MAP_DATA.forEach(mapDef => {
    if (unlockState.get(mapDef.id)?.unlocked) accessible.add(mapDef.id);
  });
  return accessible;
}

function _trainingCenterDrillMapUnlocked(game, accessibleMaps = new Set()) {
  const mapId = game?.mapId || null;
  if (!mapId) return _station1IsComplete();
  return !!accessibleMaps?.has?.(mapId);
}

// ─── Training Center domain metadata ─────────────────────────────────────────

const _TC_DOMAIN_META = {
  pediatrics: { label: "Pediatrics",   chipClass: "tc-domain--pediatrics", shelfTitle: "Pediatric Foundations" },
  assessment:  { label: "Assessment",   chipClass: "tc-domain--assessment",  shelfTitle: "Assessment Skills"     },
  airway:      { label: "Airway",       chipClass: "tc-domain--airway",      shelfTitle: "Airway & Breathing"    },
  cardiac:     { label: "Cardiac/CPR",  chipClass: "tc-domain--cardiac",     shelfTitle: "Cardiac / CPR"         },
  trauma:      { label: "Trauma",       chipClass: "tc-domain--trauma",      shelfTitle: "Trauma Screens"        },
  handoff:     { label: "Handoff",      chipClass: "tc-domain--handoff",     shelfTitle: "Handoff & Communication"},
};

// Ordered domain display sequence for the default "All" view.
const _TC_DOMAIN_ORDER = ["pediatrics", "airway", "assessment", "cardiac", "trauma", "handoff"];

let _tcActiveFilter = "all";
let _tcSearchQuery  = "";
let _tcLearningMap  = null; // { unlockedIds, unlockedDates }
let _tcWired        = false;

async function _renderTrainingCenter() {
  // Reset filter/search state on each open
  _tcActiveFilter = "all";
  _tcSearchQuery  = "";

  showScreen("training-center");

  // Sync filter chip active state
  el("tc-filter-chips")?.querySelectorAll("[data-tc-filter]").forEach(c => {
    c.classList.toggle("tc-chip--active", c.getAttribute("data-tc-filter") === "all");
  });

  const body = el("tc-body");
  const countBadge = el("tc-count-badge");
  if (body) body.innerHTML = `<p class="text-sm text-center py-10" style="color:var(--ui-text-muted)">Loading…</p>`;

  // Clear search box on every open
  const searchInput = el("tc-search");
  if (searchInput) searchInput.value = "";

  // Wire events once; subsequent opens reuse the same listeners
  if (!_tcWired) {
    _tcWireFilterChips();
    _tcWireSearch();
    _tcWired = true;
  }

  // Determine which maps are accessible from authoritative campaign unlock state.
  const accessibleMaps = _buildAccessibleTrainingCenterMaps();

  // Fetch unlock state (drills the user has passed at least once)
  let unlockedIds = new Set();
  let unlockedDates = {};
  try {
    const learning = await _fetchNotebookLearningData(false);
    const dogParkEntries = (Array.isArray(learning) ? learning : []).filter(l => (l.category_id || "dog_park") === "dog_park");
    unlockedIds = new Set(dogParkEntries.map(l => l.game_id).filter(Boolean));
    dogParkEntries.forEach(l => { if (l.game_id) unlockedDates[l.game_id] = l.unlocked_at; });
  } catch { /* show drills in available-but-not-passed state on error */ }
  _tcLearningMap = { unlockedIds, unlockedDates, accessibleMaps };

  // Catalog filtered to drills on accessible maps. A passed drill stays hidden
  // until its campaign map is unlocked, so replay access cannot bypass pacing.
  const catalog = _dogParkGameCatalog();
  const visibleDrills = catalog.filter(g => _trainingCenterDrillMapUnlocked(g, accessibleMaps));
  const unlockedCount = visibleDrills.filter(g => unlockedIds.has(g.type)).length;
  if (countBadge) countBadge.textContent = `${unlockedCount} of ${visibleDrills.length} drills completed`;

  _tcRenderBody();
}

function _tcRenderBody() {
  const body = el("tc-body");
  if (!body || !_tcLearningMap) return;

  const { unlockedIds, unlockedDates, accessibleMaps } = _tcLearningMap;
  const q = _tcSearchQuery.toLowerCase().trim();
  const filter = _tcActiveFilter;

  // Drills visible in TC: only when the campaign map they live on is unlocked.
  const fullCatalog = _dogParkGameCatalog();
  const accessibleDrills = fullCatalog.filter(g => _trainingCenterDrillMapUnlocked(g, accessibleMaps));

  // Apply active filter + search
  const visible = accessibleDrills.filter(game => {
    if (filter === "unlocked" && !unlockedIds.has(game.type)) return false;
    if (filter === "available" && unlockedIds.has(game.type)) return false;
    if (filter !== "all" && filter !== "unlocked" && filter !== "available" && game.domain !== filter) return false;
    if (q && !game.label.toLowerCase().includes(q) && !game.subtitle.toLowerCase().includes(q)) return false;
    return true;
  });

  if (visible.length === 0) {
    body.innerHTML = `<div class="tc-empty">
      <div class="tc-empty-icon">🔍</div>
      <h3>No drills found</h3>
      <p>${q ? "Try a different search term." : "Progress further in the campaign to discover more drills."}</p>
    </div>`;
    return;
  }

  // Flat grid when searching or domain-filtering
  const useShelf = filter === "all" && !q;

  if (!useShelf) {
    body.innerHTML = `<div class="tc-game-grid">${visible.map(g => _tcGameCardHtml(g, unlockedIds, unlockedDates)).join("")}</div>`;
    _tcWireCards(body, fullCatalog);
    return;
  }

  // Shelf view: Recommended (top 3) + domain shelves
  const recommended = _tcBuildRecommended(accessibleDrills, unlockedIds, unlockedDates);
  const byDomain = {};
  visible.forEach(g => {
    (byDomain[g.domain] = byDomain[g.domain] || []).push(g);
  });

  const recommendedHtml = recommended.length > 0 ? `
    <div class="tc-shelf tc-shelf--recommended">
      <div class="tc-shelf-head">
        <span class="tc-shelf-title tc-shelf-title--recommended">⭐ Recommended For You</span>
        <span class="tc-shelf-count">${recommended.length}</span>
      </div>
      <div class="tc-game-grid">${recommended.map(g => _tcGameCardHtml(g, unlockedIds, unlockedDates, true)).join("")}</div>
    </div>` : "";

  body.innerHTML = recommendedHtml + _TC_DOMAIN_ORDER
    .filter(d => byDomain[d])
    .map(d => {
      const meta = _TC_DOMAIN_META[d] || { shelfTitle: d, chipClass: "" };
      const games = byDomain[d];
      return `<div class="tc-shelf">
        <div class="tc-shelf-head">
          <span class="tc-shelf-title">${escapeHTML(meta.shelfTitle)}</span>
          <span class="tc-shelf-count">${games.length}</span>
        </div>
        <div class="tc-game-grid">${games.map(g => _tcGameCardHtml(g, unlockedIds, unlockedDates)).join("")}</div>
      </div>`;
    })
    .join("");

  _tcWireCards(body, fullCatalog);
}

// Build top-3 recommendations from accessible drills.
// Priority: (1) available-but-not-yet-passed, (2) recently unlocked (stale reps)
function _tcBuildRecommended(accessibleDrills, unlockedIds, unlockedDates) {
  // Drills on accessible maps that have never been passed — user should try them
  const notPassed = accessibleDrills.filter(g => !unlockedIds.has(g.type));
  if (notPassed.length >= 3) return notPassed.slice(0, 3);

  // Fill remaining slots with the most recently unlocked (oldest unlock date = needs refreshing)
  const passed = accessibleDrills
    .filter(g => unlockedIds.has(g.type))
    .sort((a, b) => {
      const da = unlockedDates[a.type] ? new Date(unlockedDates[a.type]).getTime() : 0;
      const db = unlockedDates[b.type] ? new Date(unlockedDates[b.type]).getTime() : 0;
      return da - db; // oldest first → most likely needs a refresh
    });

  return [...notPassed, ...passed].slice(0, 3);
}

function _tcGameCardHtml(game, unlockedIds, unlockedDates, isRecommended = false) {
  const unlocked = unlockedIds.has(game.type);
  const meta = _TC_DOMAIN_META[game.domain] || {};
  const domainChip = meta.label
    ? `<span class="tc-domain-chip ${escapeHTML(meta.chipClass || "")}">${escapeHTML(meta.label)}</span>`
    : "";
  let footerLeft, ctaText, cardClass;
  if (unlocked) {
    const dateStr = unlockedDates[game.type] ? `Passed ${_formatShortDate(unlockedDates[game.type])}` : "Passed";
    footerLeft = `<span class="tc-game-card__unlock-date">${dateStr}</span>`;
    ctaText = "Play Again →";
    cardClass = "tc-game-card";
  } else {
    footerLeft = `<span class="tc-game-card__unlock-date tc-game-card__unlock-date--new">New — try it!</span>`;
    ctaText = "Practice →";
    cardClass = "tc-game-card tc-game-card--available";
  }
  return `<button type="button" class="${cardClass}${isRecommended ? " tc-game-card--rec" : ""}" data-tc-game="${escapeHTML(game.type)}">
    ${domainChip}
    <span class="tc-game-card__title">${escapeHTML(game.label)}</span>
    <span class="tc-game-card__subtitle">${escapeHTML(game.subtitle || "")}</span>
    <div class="tc-game-card__footer">${footerLeft}<span class="tc-game-card__cta">${ctaText}</span></div>
  </button>`;
}

function _tcWireCards(container, catalog) {
  container.querySelectorAll("[data-tc-game]:not([disabled])").forEach(btn => {
    btn.addEventListener("click", () => {
      const type = btn.getAttribute("data-tc-game");
      const game = catalog.find(g => g.type === type);
      if (game) _openDogParkGamePreview(game);
    });
  });
}

function _tcWireFilterChips() {
  const row = el("tc-filter-chips");
  if (!row) return;
  row.querySelectorAll("[data-tc-filter]").forEach(chip => {
    chip.addEventListener("click", () => {
      _tcActiveFilter = chip.getAttribute("data-tc-filter") || "all";
      row.querySelectorAll("[data-tc-filter]").forEach(c => c.classList.toggle("tc-chip--active", c === chip));
      _tcRenderBody();
    });
  });
}

function _tcWireSearch() {
  const input = el("tc-search");
  if (!input) return;
  input.addEventListener("input", () => {
    _tcSearchQuery = input.value;
    _tcRenderBody();
  });
}

function _formatShortDate(isoString) {
  if (!isoString) return "";
  try {
    return new Date(isoString).toLocaleDateString(undefined, { month: "short", day: "numeric" });
  } catch { return ""; }
}

function _returnFromTrainingCenter() {
  const target = _trainingCenterReturnTarget || { type: "menu" };
  if (target.type === "district" && target.districtId) {
    showCategoryScreen(target.districtId);
    return;
  }
  buildMenu();
  showScreen("menu");
}

// ─── Practice Insights dashboard ──────────────────────────────────────────────

let _progressReturnScreen = "menu";
let _practiceTab = "scenarios";
let _practicePerfCache = null;
let _practiceDrillPerfCache = null;
let _practiceCoachHistory = [];
let _practiceCoachFocusTitle = "";
let _practiceCoachSessionIds = [];
let _practiceCoachSending = false;
let _practiceCoachConversationId = "";

const _PRACTICE_CATEGORY_LABELS = {
  clinical_performance: "Clinical Performance",
  protocols_treatment: "Protocol / Treatment",
  scope_adherence: "Scope of Practice",
  documentation: "Communication / Handoff",
  professionalism: "Professionalism",
};

const _PRACTICE_FOCUS_GROUPS = [
  { key: "history_structure", label: "History structure", match: /\b(sample|opqrst|onset|provocation|quality|radiation|severity|time|allerg|medication|past|last|event)\b/i },
];

const _PRACTICE_PROTOCOL_RECS = [
  { key: "airway", title: "Airway and respiratory distress", match: /(airway|breath|resp|oxygen|ventilat|lung|stridor|wheez|cpap|bvm)/i },
  { key: "shock", title: "Shock recognition and reassessment", match: /(shock|circulation|perfusion|blood pressure|hypotension|pulse|capillary|hemorrhage)/i },
  { key: "cardiac", title: "Cardiac arrest and CPR/AED", match: /(cpr|aed|cardiac|arrest|pulse check|compression|rosc)/i },
  { key: "trauma", title: "Trauma assessment and bleeding control", match: /(trauma|bleed|hemorrhage|moi|burn|fracture|injury)/i },
  { key: "handoff", title: "DMIST, handoff, and documentation", match: /(dmist|handoff|documentation|narrative|communication|report)/i },
  { key: "peds", title: "Pediatric assessment and PAT", match: /(pediatric|peds|infant|child|pat|caregiver|development)/i },
];

function _openProgress() {
  _progressReturnScreen = el("screen-menu")?.classList.contains("hidden") ? "category" : "menu";
  _practiceTab = "scenarios";
  _renderProgress();
}

async function _renderProgress() {
  showScreen("progress");
  const body = el("progress-body");
  const xpBadge = el("progress-xp-badge");
  if (body) body.innerHTML = `<p class="text-sm text-center py-10" style="color:var(--ui-text-muted)">Loading practice insights…</p>`;
  if (xpBadge) xpBadge.textContent = "Coaching view";

  const history = _historyCache || [];
  const [perfResult, drillResult] = await Promise.allSettled([
    _fetchPracticePerformance(),
    _fetchPracticeDrillPerformance(),
  ]);
  if (perfResult.status === "fulfilled") {
    _practicePerfCache = perfResult.value;
  } else {
    _practicePerfCache = _practicePerfCache || null;
  }
  if (drillResult.status === "fulfilled") {
    _practiceDrillPerfCache = drillResult.value;
  } else {
    _practiceDrillPerfCache = _practiceDrillPerfCache || [];
  }

  _renderPracticeBody(history);
}

function _renderPracticeBody(history = _historyCache || []) {
  const body = el("progress-body");
  if (!body) return;
  const perf = _practicePerfCache || {};
  const drillPerf = Array.isArray(_practiceDrillPerfCache) ? _practiceDrillPerfCache : [];
  const trend = Array.isArray(perf.score_trend) ? perf.score_trend : [];
  const scoredHistory = history.filter(h => h && h.score != null);
  const scenarioCount = perf.completed_sessions ?? scoredHistory.length;
  const avgScore = _practiceAverageScore(trend, scoredHistory);
  const strongest = _practiceStrongestArea(perf);
  const recommendations = _practiceRecommendations(perf, drillPerf);
  const scenarioPanel = _practiceTab === "scenarios" ? _practiceScenarioPanel(perf, trend) : "";
  const drillPanel = _practiceTab === "drills" ? _practiceDrillPanel(drillPerf) : "";

  body.innerHTML = `
    <div class="progress-dashboard practice-dashboard">
      <section class="practice-coach-note">
        <div class="practice-coach-avatar">🐾</div>
        <div>
          <strong>Practice guide</strong>
          <p>These insights are here to guide your next practice rep. They are based on recent calls and drills, not a permanent grade.</p>
        </div>
        <div class="practice-coach-note-actions">
          <button type="button" class="practice-coach-open-btn" data-practice-coach-open>Coach with Lexi</button>
        </div>
      </section>

      <div class="progress-stat-row">
        <div class="progress-stat-card"><span class="progress-stat-val">${scenarioCount}</span><span class="progress-stat-lbl">Scenarios run</span></div>
        <div class="progress-stat-card"><span class="progress-stat-val">${avgScore == null ? "—" : `${avgScore}%`}</span><span class="progress-stat-lbl">Recent form</span></div>
        <div class="progress-stat-card"><span class="progress-stat-val progress-stat-val--text">${escapeHTML(strongest || "Building")}</span><span class="progress-stat-lbl">Strongest area</span></div>
      </div>

      <section class="progress-section progress-section--recommended">
        <h3 class="progress-section-title flex items-center gap-2 text-amber-600">🐾 Lexi's Recommended Next Reps</h3>
        <div class="practice-rec-grid">
          ${recommendations.map(r => _practiceRecommendationHtml(r)).join("")}
        </div>
      </section>

      <div class="practice-tabs" role="tablist" aria-label="Practice Insights tabs">
        <button class="practice-tab ${_practiceTab === "scenarios" ? "practice-tab--active" : ""}" data-practice-tab="scenarios">Scenarios</button>
        <button class="practice-tab ${_practiceTab === "drills" ? "practice-tab--active" : ""}" data-practice-tab="drills">Drills</button>
      </div>

      ${scenarioPanel}
      ${drillPanel}
    </div>`;

  _practiceWireBody();
}

async function _fetchPracticePerformance() {
  const res = await authFetch(`${API}/api/me/performance`);
  if (!res.ok) throw new Error("performance_fetch_failed");
  return await res.json();
}

async function _fetchPracticeDrillPerformance() {
  const res = await authFetch(`${API}/api/me/drill-performance`);
  if (!res.ok) return [];
  const data = await res.json();
  return Array.isArray(data) ? data : [];
}

function _practiceAverageScore(trend, fallbackHistory) {
  const scores = (Array.isArray(trend) && trend.length ? trend : fallbackHistory)
    .slice(0, 3)
    .map(s => Number(s.score))
    .filter(Number.isFinite);
  if (!scores.length) return null;
  return Math.round(scores.reduce((sum, score) => sum + score, 0) / scores.length);
}

function _practiceCategoryRows(perf) {
  const details = perf?.category_details || {};
  if (Object.keys(details).length) {
    return Object.entries(details).map(([key, row]) => ({
      key,
      label: _PRACTICE_CATEGORY_LABELS[key] || key,
      pct: Math.round(Number(row.avg_pct) || 0),
      count: Number(row.count) || 0,
      method: row.method || "deterministic",
    })).sort((a, b) => a.pct - b.pct);
  }
  return Object.entries(perf?.category_averages || {}).map(([key, pct]) => ({
    key,
    label: _PRACTICE_CATEGORY_LABELS[key] || key,
    pct: Math.round(Number(pct) || 0),
    count: 0,
    method: "deterministic",
  })).sort((a, b) => a.pct - b.pct);
}

function _practiceStrongestArea(perf) {
  const rows = _practiceCategoryRows(perf).filter(r => r.method === "deterministic" && r.pct > 0);
  if (!rows.length) return null;
  return rows.sort((a, b) => b.pct - a.pct)[0].label.replace(" / ", " ");
}

function _practiceTier(score) {
  if (score >= 85) return { cls: "strong", label: "Strong pattern" };
  if (score >= 70) return { cls: "developing", label: "Developing" };
  return { cls: "needs-rep", label: "Needs another rep" };
}

function _practiceRecommendations(perf, drillPerf) {
  const recs = [];
  const focus = (perf?.most_missed_items || []).filter(i => Number(i.times_seen) >= 2)[0];
  if (focus) {
    recs.push({
      type: "Debrief With Lexi",
      title: _practiceFocusLabel(focus),
      reason: `Recent calls show this action still needs reps in ${focus.times_missed || 0}/${focus.times_seen || 0} times seen.`,
      action: "Review calls",
    });
  }
  const lowCategory = _practiceCategoryRows(perf).find(r => r.method === "deterministic" && r.pct < 70);
  if (lowCategory) {
    recs.push({
      type: "Retake Similar Call",
      title: `${lowCategory.label} practice`,
      reason: `${lowCategory.label} is still building across recent scored sessions.`,
      action: "Run a call",
    });
  }
  const catalog = _dogParkGameCatalog();
  const lowDrill = (drillPerf || []).find(d => Number(d.last_score) < 70);
  if (lowDrill) {
    const game = catalog.find(g => g.type === lowDrill.game_id);
    recs.push({
      type: "Practice Drill",
      title: game?.label || lowDrill.game_id,
      reason: `Last drill score was ${lowDrill.last_score}%. A quick rep can sharpen it.`,
      action: "Open Training Center",
      openTrainingCenter: true,
    });
  }
  if (!recs.length) {
    recs.push({
      type: "Next Best Rep",
      title: "Run a few calls or drills",
      reason: "Lexi will start picking more precise next reps once there are a few recent data points.",
      action: "Open Training Center",
      openTrainingCenter: true,
    });
  }
  return recs.slice(0, 3);
}

function _practiceRecommendationHtml(rec) {
  return `<article class="practice-rec-card">
    <span class="practice-rec-type">${escapeHTML(rec.type)}</span>
    <h4>${escapeHTML(rec.title)}</h4>
    <p>${escapeHTML(rec.reason)}</p>
    <button class="practice-rec-btn" ${rec.openTrainingCenter ? "data-practice-open-training" : "data-practice-open-history"}>${escapeHTML(rec.action)}</button>
  </article>`;
}

function _practiceScenarioPanel(perf, trend) {
  const rows = _practiceCategoryRows(perf);
  const focus = _practiceGroupedFocusItems(perf?.most_missed_items || []).slice(0, 5);
  const strengths = (perf?.consistent_strengths || []).slice(0, 5);
  const protocolRecs = _practiceProtocolRecommendations(rows, focus);
  return `
    ${rows.length ? `<section class="progress-section">
      <h3 class="progress-section-title">Skill Patterns</h3>
      <div class="progress-domain-list">${rows.map(_practiceCategoryRowHtml).join("")}</div>
    </section>` : _practiceEmpty("Run scored scenarios to see skill patterns.")}

    <section class="progress-section">
      <h3 class="progress-section-title">Recent Trend</h3>
      ${_practiceTrendHtml(trend)}
    </section>

    <div class="practice-two-col">
      <section class="progress-section">
        <h3 class="progress-section-title">Focus Areas From Recent Calls</h3>
        ${focus.length ? `<div class="practice-list">${focus.map(_practiceFocusHtml).join("")}</div>` : `<p class="practice-muted">More scenario data needed to identify patterns.</p>`}
      </section>
      <section class="progress-section">
        <h3 class="progress-section-title">Strengths You're Building</h3>
        ${strengths.length ? `<div class="practice-list">${strengths.map(_practiceStrengthHtml).join("")}</div>` : `<p class="practice-muted">Strength patterns will appear as you complete more scored calls.</p>`}
      </section>
    </div>

    <section class="progress-section">
      <h3 class="progress-section-title">Recommended Protocol Review</h3>
      ${protocolRecs.length ? `<div class="practice-protocol-list">${protocolRecs.map(r => `<span>${escapeHTML(r.title)}</span>`).join("")}</div>` : `<p class="practice-muted">Protocol review suggestions will appear when recent patterns point to a topic.</p>`}
    </section>`;
}

function _practiceCategoryRowHtml(row) {
  const tier = _practiceTier(row.pct);
  const legacy = row.method === "legacy_ai";
  return `<div class="progress-domain-row practice-domain-row">
    <span class="progress-domain-name">${escapeHTML(row.label)}</span>
    <div class="progress-domain-bar-wrap"><div class="progress-domain-bar progress-domain-bar--${tier.cls}" style="width:${Math.max(2, Math.min(100, row.pct))}%"></div></div>
    <span class="progress-domain-score">${row.pct}%</span>
    <span class="progress-domain-count">${legacy ? "Legacy scoring" : (row.count ? `${row.count} call${row.count === 1 ? "" : "s"}` : "")}</span>
    <span class="practice-tier practice-tier--${tier.cls}">${legacy ? "Score not yet deterministic" : tier.label}</span>
  </div>`;
}

function _practiceTrendHtml(trend) {
  const points = (Array.isArray(trend) ? trend : []).slice(0, 10).reverse();
  if (points.length < 3) return `<p class="practice-muted">Run at least 3 scenarios to see your score trend.</p>`;
  const max = Math.max(...points.map(p => Number(p.score) || 0), 100);
  return `<div class="practice-trend-wrap">
    <div class="practice-trend-caption">Last ${points.length} scored calls · taller bars mean higher score</div>
    <div class="practice-sparkline" aria-label="Recent scenario score trend">
      ${points.map(p => {
        const score = Number(p.score) || 0;
        const tier = _practiceTier(score);
        const date = p.ended_at ? _formatShortDate(p.ended_at) : "";
        return `<span class="practice-spark-item">
          <span class="practice-spark-score">${score}%</span>
          <span class="practice-spark-dot practice-spark-dot--${tier.cls}" title="${escapeHTML(p.scenario_id || "Scenario")} · ${score}%" style="height:${Math.max(12, Math.round((score / max) * 54))}px">${p.critical_failure ? "×" : ""}</span>
          <span class="practice-spark-date">${escapeHTML(date)}</span>
        </span>`;
      }).join("")}
    </div>
    <div class="practice-trend-legend">
      <span><i class="practice-dot practice-dot--strong"></i> Strong</span>
      <span><i class="practice-dot practice-dot--developing"></i> Developing</span>
      <span><i class="practice-dot practice-dot--needs-rep"></i> Needs another rep</span>
    </div>
  </div>`;
}

function _practiceFocusLabel(item) {
  return item.title || _humanizePracticeItemLabel(item.label || item.item_id || "Practice opportunity");
}

function _practiceFocusHtml(item) {
  const label = _practiceFocusLabel(item);
  const seen = Number(item.times_seen) || 0;
  const missed = Number(item.times_missed) || 0;
  const elements = Array.isArray(item.elements) ? item.elements : [];
  const ids = Array.from(new Set(item.missed_session_ids || [])).join(",");
  return `<div class="practice-list-row practice-list-row--action">
    <div>
      <strong>${escapeHTML(label)}</strong>
      <span>${seen ? `Needs reps in ${missed} of ${seen} recent calls` : "Practice signal"} · <em>${escapeHTML(_PRACTICE_CATEGORY_LABELS[item.category] || item.category || "Scenario")}</em></span>
      ${elements.length ? `<small>Commonly missed: ${elements.map(escapeHTML).join(", ")}</small>` : ""}
      <small>${escapeHTML(_practiceFocusWhy(item))}</small>
    </div>
    <div class="practice-row-actions">
      <button class="practice-row-btn" data-practice-focus-title="${escapeHTML(label)}" data-practice-session-ids="${escapeHTML(ids)}">Review Calls</button>
      <button class="practice-row-btn" data-practice-coach-open data-practice-focus-title="${escapeHTML(label)}" data-practice-session-ids="${escapeHTML(ids)}">Ask Lexi</button>
    </div>
  </div>`;
}

function _practiceStrengthHtml(item) {
  const seen = Number(item.times_seen) || 0;
  const satisfied = Number(item.times_satisfied) || 0;
  return `<div class="practice-list-row practice-list-row--strength">
    <div>
      <strong>${escapeHTML(_humanizePracticeItemLabel(item.label || item.item_id || "Strong pattern"))}</strong>
      <span>${seen ? `Satisfied in ${satisfied} of last ${seen} calls` : "Consistent evidence"} · <em>${escapeHTML(_PRACTICE_CATEGORY_LABELS[item.category] || item.category || "Scenario")}</em></span>
    </div>
  </div>`;
}

function _practiceFocusWhy(item) {
  const haystack = `${item.title || ""} ${item.label || ""} ${item.item_id || ""} ${(item.elements || []).join(" ")}`.toLowerCase();
  if (/sample|opqrst|history|onset|allerg|medication|event/.test(haystack)) {
    return "Why focus here: cleaner history structure makes your differential, handoff, and narrative easier to defend.";
  }
  if (/airway|breath|oxygen|lung|resp/.test(haystack)) {
    return "Why focus here: airway and breathing reassessment drives the next intervention and escalation decision.";
  }
  if (/shock|circulation|pulse|pressure|perfusion/.test(haystack)) {
    return "Why focus here: early shock recognition prevents delayed transport or under-treatment.";
  }
  if (/trauma|bleed|injury|burn/.test(haystack)) {
    return "Why focus here: trauma misses often change priority, destination, or immediate intervention.";
  }
  if (/handoff|dmist|documentation|narrative|communication/.test(haystack)) {
    return "Why focus here: clear communication preserves the clinical picture for the next crew or receiving team.";
  }
  return "Why focus here: this pattern showed up repeatedly in recent scored calls, so one targeted rep should pay off.";
}

function _practiceDrillPanel(drillPerf) {
  const catalog = _dogParkGameCatalog();
  const byId = new Map(catalog.map(g => [g.type, g]));
  if (!drillPerf.length) return _practiceEmpty("Play a few drills and this tab will show score patterns, common tags, and refresh opportunities.");
  const rows = drillPerf.map(d => ({ ...d, game: byId.get(d.game_id) })).sort((a, b) => (a.game?.domain || "").localeCompare(b.game?.domain || ""));
  return `<section class="progress-section">
    <h3 class="progress-section-title">Drill Performance</h3>
    <div class="practice-drill-list">${rows.map(_practiceDrillRowHtml).join("")}</div>
  </section>`;
}

function _practiceDrillRowHtml(row) {
  const game = row.game || {};
  const tier = _practiceTier(Number(row.last_score) || 0);
  const meta = _TC_DOMAIN_META[game.domain] || {};
  const scores = Array.isArray(row.scores) ? row.scores.slice(-3) : [];
  return `<div class="practice-drill-row">
    <div class="practice-drill-main">
      <strong>${escapeHTML(game.label || row.game_id)}</strong>
      <span>${escapeHTML(meta.label || "Drill")} · ${row.play_count || 0} play${row.play_count === 1 ? "" : "s"}</span>
      ${(row.top_mistake_tags || []).length ? `<small>Common error patterns: ${(row.top_mistake_tags || []).map(t => escapeHTML(_humanizePracticeItemLabel(String(t)))).join(", ")}</small>` : `<small>No recurring error pattern yet.</small>`}
    </div>
    <div class="practice-drill-recent">
      <span>Last 3 scores</span>
      <div class="practice-drill-dots">${scores.map(s => `<i class="practice-dot practice-dot--${_practiceTier(Number(s) || 0).cls}" title="${s}%"></i>`).join("")}</div>
    </div>
    <span class="practice-tier practice-tier--${tier.cls}">${row.last_score ?? 0}% · ${tier.label}</span>
  </div>`;
}

function _humanizePracticeItemLabel(raw) {
  let text = String(raw || "").trim();
  if (!text) return "Practice opportunity";
  text = text
    .replace(/^ems[._-]/i, "")
    .replace(/^(medical|trauma|pediatric|adult)[._-]/i, "")
    .replace(/[._-]+/g, " ")
    .replace(/\bopqrst\b/gi, "OPQRST")
    .replace(/\bsample\b/gi, "SAMPLE")
    .replace(/\bdmist\b/gi, "DMIST")
    .replace(/\bcpr\b/gi, "CPR")
    .replace(/\baed\b/gi, "AED")
    .replace(/\bgcs\b/gi, "GCS")
    .replace(/\bpat\b/gi, "PAT")
    .replace(/\bals\b/gi, "ALS")
    .replace(/\bbls\b/gi, "BLS");
  return text.charAt(0).toUpperCase() + text.slice(1);
}

function _practiceFocusGroupKey(item) {
  const haystack = `${item.item_id || ""} ${item.label || ""}`.toLowerCase();
  const group = _PRACTICE_FOCUS_GROUPS.find(g => g.match.test(haystack));
  return group?.key || null;
}

function _practiceGroupedFocusItems(items) {
  const grouped = new Map();
  const standalone = [];
  for (const item of items) {
    const key = _practiceFocusGroupKey(item);
    if (!key) {
      standalone.push({ ...item, title: _humanizePracticeItemLabel(item.label || item.item_id) });
      continue;
    }
    const def = _PRACTICE_FOCUS_GROUPS.find(g => g.key === key);
    if (!grouped.has(key)) {
      grouped.set(key, {
        ...item,
        title: def?.label || "Related focus area",
        elements: [],
        times_seen: 0,
        times_missed: 0,
        missed_session_ids: [],
      });
    }
    const row = grouped.get(key);
    row.times_seen += Number(item.times_seen) || 0;
    row.times_missed += Number(item.times_missed) || 0;
    row.missed_session_ids.push(...(item.missed_session_ids || []));
    row.elements.push(_humanizePracticeItemLabel(item.label || item.item_id));
  }
  const combined = [...grouped.values(), ...standalone].map(row => ({
    ...row,
    elements: Array.from(new Set(row.elements || [])).slice(0, 5),
    missed_session_ids: Array.from(new Set(row.missed_session_ids || [])).slice(0, 10),
  }));
  return combined.sort((a, b) => (Number(b.times_missed) || 0) - (Number(a.times_missed) || 0));
}

function _practiceProtocolRecommendations(rows, focusItems) {
  const haystack = [
    ...rows.map(r => `${r.label} ${r.key}`),
    ...focusItems.map(f => `${f.title || ""} ${f.label || ""} ${(f.elements || []).join(" ")}`),
  ].join(" ");
  const recs = _PRACTICE_PROTOCOL_RECS.filter(r => r.match.test(haystack)).slice(0, 4);
  if (recs.length) return recs;
  return rows.some(r => r.pct < 70)
    ? [{ key: "general", title: "Primary assessment and reassessment" }]
    : [];
}

function _openPracticeCallsModal(title, sessionIds) {
  const ids = new Set((sessionIds || []).map(String).filter(Boolean));
  const entries = (_historyCache || []).filter(entry => ids.has(String(entry.key)));
  setText("practice-calls-title", title || "Relevant Calls");
  setText("practice-calls-subtitle", entries.length ? `${entries.length} related call${entries.length === 1 ? "" : "s"}` : "No matching call records found");
  const body = el("practice-calls-body");
  if (body) {
    body.innerHTML = entries.length ? `
      <div class="practice-call-list">
        ${entries.map(entry => `<button type="button" class="practice-call-card" data-practice-call-key="${escapeHTML(entry.key)}">
          <strong>${escapeHTML(entry.title || entry.scenarioId || "Scenario")}</strong>
          <span>${entry.score != null ? `${entry.score}%` : "Score unavailable"} · ${entry.date ? _formatShortDate(entry.date) : ""}</span>
        </button>`).join("")}
      </div>` : `<p class="practice-muted">This focus area is based on recent scoring data, but the matching history records are not loaded locally yet. Try reopening Practice Insights after History finishes syncing.</p>`;
  }
  show("modal-practice-calls");
}

function _practiceCoachAppend(role, text) {
  const wrap = el("practice-coach-messages");
  if (!wrap) return null;
  const div = document.createElement("div");
  div.className = `practice-coach-msg practice-coach-msg--${role === "user" ? "user" : "lexi"}`;
  div.textContent = text || "";
  wrap.appendChild(div);
  wrap.scrollTop = wrap.scrollHeight;
  return div;
}

function _practiceCoachSetQuota(quota = {}) {
  const remaining = quota.remaining_today;
  const cap = quota.daily_cap;
  const sessionRemaining = quota.remaining_this_session;
  const sessionCap = quota.session_cap;
  const label = remaining === undefined
    ? "Coaching turns left today: —"
    : `Coaching turns: ${sessionRemaining ?? "—"}/${sessionCap ?? "?"} this chat · ${remaining}/${cap ?? "?"} today`;
  setText("practice-coach-quota", label);
}

async function _openPracticeCoachModal(opts = {}) {
  _practiceCoachFocusTitle = opts.focusTitle || "";
  _practiceCoachSessionIds = Array.isArray(opts.sessionIds) ? opts.sessionIds.filter(Boolean).map(String) : [];
  _practiceCoachHistory = [];
  _practiceCoachConversationId = `${Date.now()}-${Math.random().toString(16).slice(2)}`;
  setText("practice-coach-title", _practiceCoachFocusTitle ? `Coach with Lexi — ${_practiceCoachFocusTitle}` : "Coach with Lexi");
  setText("practice-coach-subtitle", "Evidence-based coaching from recent calls and drills");
  setText("practice-coach-context-line", "Lexi uses recent scored calls, drill results, unlocked practice options, and agency context.");
  _practiceCoachSetQuota();
  const messages = el("practice-coach-messages");
  if (messages) messages.innerHTML = "";
  const input = el("practice-coach-input");
  if (input) {
    input.value = "";
    input.style.height = "2.75rem";
  }
  show("modal-practice-coach");
  _practiceCoachAppend("lexi", "Give me a second to review your recent practice data. I’ll keep it encouraging, honest, and focused on the next useful rep.");
  try {
    const res = await authFetch(`${API}/api/me/practice-coach/context`);
    if (!res.ok) throw new Error("context_fetch_failed");
    const ctx = await res.json();
    _practiceCoachSetQuota(ctx.quota || {});
    if (messages) messages.innerHTML = "";
    const focus = _practiceCoachFocusTitle ? ` I’m already looking at “${_practiceCoachFocusTitle}.”` : "";
    _practiceCoachAppend("lexi", `I’m ready.${focus} Ask what to practice next, why this pattern matters, or which protocols to review.`);
  } catch {
    if (messages) messages.innerHTML = "";
    _practiceCoachAppend("lexi", "I couldn’t load your coaching context yet. You can still ask, but if the response is thin, reopen Practice Insights after your records finish syncing.");
  }
  input?.focus();
}

async function _sendPracticeCoachMessage(message) {
  const text = String(message || el("practice-coach-input")?.value || "").trim();
  if (!text || _practiceCoachSending) return;
  _practiceCoachSending = true;
  const input = el("practice-coach-input");
  const sendBtn = el("btn-practice-coach-send");
  if (input) {
    input.value = "";
    input.style.height = "2.75rem";
  }
  if (sendBtn) sendBtn.disabled = true;
  _practiceCoachAppend("user", text);
  const typing = _practiceCoachAppend("lexi", "Thinking through your recent reps…");
  const historySnapshot = _practiceCoachHistory.slice(-6);
  _practiceCoachHistory.push({ role: "user", content: text });
  try {
    const res = await authFetch(`${API}/api/me/practice-coach/chat`, {
      method: "POST",
      body: JSON.stringify({
        message: text,
        history: historySnapshot,
        focus_title: _practiceCoachFocusTitle,
        session_ids: _practiceCoachSessionIds,
        conversation_id: _practiceCoachConversationId,
      }),
    });
    if (!res.ok) {
      let detail = null;
      try { detail = await res.json(); } catch {}
      const msg = detail?.detail?.message || detail?.message || "I couldn’t start that coaching response. Try again in a bit.";
      if (typing) typing.textContent = msg;
      return;
    }
    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    let responseText = "";
    let doneSeen = false;
    while (true) {
      const { done, value } = await reader.read();
      buffer += done ? decoder.decode() : decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = done ? "" : lines.pop();
      const dataLines = lines.map(line => line.trim()).filter(line => line.startsWith("data: ")).map(line => line.slice(6));
      for (const data of dataLines) {
        if (data === "[DONE]") { doneSeen = true; break; }
        try {
          const parsed = JSON.parse(data);
          if (parsed.type === "provider_error") {
            if (typing) typing.textContent = "AI is temporarily at capacity — your progress is saved. Try again in a moment.";
            doneSeen = true; break;
          } else if (parsed.text) {
            responseText += parsed.text;
            if (typing) typing.textContent = responseText;
            const wrap = el("practice-coach-messages");
            if (wrap) wrap.scrollTop = wrap.scrollHeight;
          }
        } catch {}
      }
      if (done || doneSeen) break;
    }
    if (!responseText && typing) typing.textContent = "I lost that response on the way over. Ask again and I’ll try once more.";
    _practiceCoachHistory.push({ role: "assistant", content: responseText });
    const ctxRes = await authFetch(`${API}/api/me/practice-coach/context`);
    if (ctxRes.ok) {
      const ctx = await ctxRes.json();
      _practiceCoachSetQuota(ctx.quota || {});
    }
  } catch {
    if (typing) typing.textContent = "Connection hiccup. Ask again and I’ll coach you through it.";
  } finally {
    _practiceCoachSending = false;
    if (sendBtn) sendBtn.disabled = false;
  }
}

function _practiceEmpty(message) {
  return `<section class="progress-section"><p class="practice-muted">${escapeHTML(message)}</p></section>`;
}

function _practiceWireBody() {
  el("progress-body")?.querySelectorAll("[data-practice-tab]").forEach(btn => {
    btn.addEventListener("click", () => {
      _practiceTab = btn.getAttribute("data-practice-tab") || "scenarios";
      _renderPracticeBody();
    });
  });
  el("progress-body")?.querySelectorAll("[data-practice-open-training]").forEach(btn => {
    btn.addEventListener("click", _openTrainingCenter);
  });
  el("progress-body")?.querySelectorAll("[data-practice-open-history]").forEach(btn => {
    btn.addEventListener("click", () => _openHistoryScreen("progress"));
  });
  el("progress-body")?.querySelectorAll("[data-practice-coach-open]").forEach(btn => {
    btn.addEventListener("click", () => {
      const ids = (btn.getAttribute("data-practice-session-ids") || "").split(",").filter(Boolean);
      _openPracticeCoachModal({
        focusTitle: btn.getAttribute("data-practice-focus-title") || "",
        sessionIds: ids,
      });
    });
  });
  el("progress-body")?.querySelectorAll("[data-practice-session-ids]").forEach(btn => {
    btn.addEventListener("click", () => {
      if (btn.hasAttribute("data-practice-coach-open")) return;
      const ids = (btn.getAttribute("data-practice-session-ids") || "").split(",");
      _openPracticeCallsModal(btn.getAttribute("data-practice-focus-title") || "Relevant Calls", ids);
    });
  });
}

