el("btn-scenario-preview-cancel")?.addEventListener("click", () => {
  _scenarioPreviewSelection = null;
  hide("modal-scenario-preview");
});

el("btn-scenario-preview-play")?.addEventListener("click", async () => {
  const selection = _scenarioPreviewSelection;
  if (!selection) return;

  const playBtn = el("btn-scenario-preview-play");
  const originalText = playBtn?.textContent || "Play Activity";

  if (typeof selection === "string") {
    if (playBtn) { playBtn.disabled = true; playBtn.textContent = "Launching…"; playBtn.classList.add("opacity-70"); }
    setText("scenario-preview-status", "Loading scenario…");
    const ok = await startScenario(selection);
    if (ok) {
      _scenarioPreviewSelection = null;
      // showDispatch → showScreen → _hideNavigationOverlays closes the modal automatically
    } else {
      if (playBtn) { playBtn.disabled = false; playBtn.textContent = originalText; playBtn.classList.remove("opacity-70"); }
      setText("scenario-preview-status", _mapNodeStatusText(selection));
    }
    return;
  }
  if (selection.type === "station_intro") {
    _scenarioPreviewSelection = null;
    hide("modal-scenario-preview");
    _station1MarkIntroSeen();
    _renderStation1Map();
    return;
  }
  if (selection.type === "station_wrapup") {
    if (playBtn) { playBtn.disabled = true; playBtn.textContent = "Completing..."; }
    try {
      const ok = await _completeStation1FromWrapupNode();
      if (!ok) return;
      _station1MarkWrapSeen();
      _scenarioPreviewSelection = null;
      hide("modal-scenario-preview");
      _cprBlsReturnDistrictId = null;
      if (state.scormEnabled) _setScormUiState({ location: "home", map: "map_0", orientationComplete: true });
      buildMenu();
      showScreen("menu");
    } catch (err) {
      showToast(err?.message || String(err), "error");
      if (playBtn) { playBtn.disabled = false; playBtn.textContent = originalText; }
    }
    return;
  }
  if (selection.type === "station_challenges") {
    _scenarioPreviewSelection = null;
    hide("modal-scenario-preview");
    _station1MarkChallengesSeen();
    _renderStation1Map();
    return;
  }
  if (selection.type === "lexi_message") {
    _scenarioPreviewSelection = null;
    hide("modal-scenario-preview");
    return;
  }
  if (selection.type === "map_requirements") {
    if (selection.reportDistrictId && selection.canReport) {
      _scenarioPreviewSelection = null;
      hide("modal-scenario-preview");
      showCategoryScreen(selection.reportDistrictId);
      return;
    }
    _scenarioPreviewSelection = null;
    hide("modal-scenario-preview");
    return;
  }
  if (_playMinigameSelection(selection)) {
    _scenarioPreviewSelection = null;
    hide("modal-scenario-preview");
    return;
  }
  if (selection.type === "scenario" && selection.scenarioId) {
    if (playBtn) { playBtn.disabled = true; playBtn.textContent = "Launching…"; playBtn.classList.add("opacity-70"); }
    setText("scenario-preview-status", "Loading scenario…");
    const ok = await startScenario(selection.scenarioId);
    if (ok) {
      _scenarioPreviewSelection = null;
      // showDispatch → showScreen → _hideNavigationOverlays closes the modal automatically
    } else {
      if (playBtn) { playBtn.disabled = false; playBtn.textContent = originalText; playBtn.classList.remove("opacity-70"); }
      setText("scenario-preview-status", _mapNodeStatusText(selection));
    }
  }
});

