el("btn-join-agency").addEventListener("click", handleJoinAgency);

function openEditProfileModal() {
  if (_isScormRuntimeUi()) {
    _applyScormSaasUiTrim();
    return;
  }
  el("edit-first-name").value = state.firstName || "";
  el("edit-last-name").value  = "";
  el("edit-email").value      = "";
  el("edit-password").value   = "";
  setText("edit-current-agency", state.agency || "Not set");
  el("edit-profile-error").classList.add("hidden");
  el("edit-profile-success").classList.add("hidden");
  el("join-agency-error").classList.add("hidden");
  el("join-agency-success").classList.add("hidden");
  el("join-code-input").value = "";

  // Fetch full profile: personal info + full membership list
  authFetch(`${API}/api/me`).then(r => r.json()).then(data => {
    el("edit-first-name").value = data.first_name || state.firstName || "";
    el("edit-last-name").value  = data.last_name  || "";
    el("edit-email").value      = data.email       || "";
    _renderMembershipsList(data.memberships);
  }).catch(() => {
    el("edit-memberships-list").innerHTML = '<p class="text-red-400 text-sm">Could not load memberships.</p>';
  });

  // Populate join-agency dropdown from public API (split into open/private groups)
  fetch(`${API}/api/agencies/public`)
    .then(r => r.json())
    .then(agencies => {
      const sel = el("join-agency-select");
      sel.innerHTML = '<option value="">— Select agency —</option>';
      const openGroup    = document.createElement("optgroup");
      openGroup.label    = "Open Access";
      const privateGroup = document.createElement("optgroup");
      privateGroup.label = "Requires Join Code";
      agencies.forEach(a => {
        _agencyOpenMap[a.id] = a.is_open_join;
        const opt = document.createElement("option");
        opt.value = a.id;
        opt.textContent = a.name;
        (a.is_open_join ? openGroup : privateGroup).appendChild(opt);
      });
      if (openGroup.children.length)    sel.appendChild(openGroup);
      if (privateGroup.children.length) sel.appendChild(privateGroup);
    }).catch(() => {});

  // Show/hide join code row based on selected agency type
  el("join-agency-select").onchange = function() {
    const isOpen = _agencyOpenMap[this.value] === true;
    el("join-code-row").classList.toggle("hidden", isOpen);
    el("join-agency-hint").classList.toggle("hidden", !isOpen);
    if (isOpen) el("join-code-input").value = "";
  };

  // Reset join code visibility to default (visible, no hint)
  el("join-code-row").classList.remove("hidden");
  el("join-agency-hint").classList.add("hidden");

  show("modal-edit-profile");
}

function _renderMembershipsList(memberships) {
  const container = el("edit-memberships-list");
  if (!memberships || memberships.length === 0) {
    container.innerHTML = '<p class="text-gray-500 text-sm">No agency memberships.</p>';
    return;
  }
  const onlyOne = memberships.length === 1;
  container.innerHTML = memberships.map(m => `
    <div class="bg-gray-800 border border-gray-700 rounded-lg p-3">
      <div class="flex items-center justify-between mb-2">
        <span class="text-white text-sm font-semibold">${escapeHTML(m.agency_name || m.agency_id)}</span>
        <div class="flex items-center gap-2">
          <span class="text-xs text-gray-400 capitalize">${escapeHTML(m.role)}</span>
          ${onlyOne
            ? `<span class="text-xs text-gray-600 italic">only agency</span>`
            : `<button class="btn-leave-agency text-xs text-red-500 hover:text-red-400 border border-red-900 hover:border-red-700 px-2 py-0.5 rounded transition-colors"
                 data-agency-id="${escapeHTML(m.agency_id)}" data-agency-name="${escapeHTML(m.agency_name || m.agency_id)}">Leave</button>`
          }
        </div>
      </div>
      <div class="grid grid-cols-2 gap-2">
        <div>
          <label class="block text-xs text-gray-500 mb-1">MCA</label>
          <select class="membership-mca w-full bg-gray-700 border border-gray-600 rounded px-2 py-1.5 text-white text-xs focus:outline-none focus:border-blue-500"
            data-agency-id="${escapeHTML(m.agency_id)}">
            <option value="mi_wmrmcc_kent"${m.mca === "mi_wmrmcc_kent" ? " selected" : ""}>WMRMCC</option>
          </select>
        </div>
        <div>
          <label class="block text-xs text-gray-500 mb-1">Provider Level</label>
          <select class="membership-level w-full bg-gray-700 border border-gray-600 rounded px-2 py-1.5 text-white text-xs focus:outline-none focus:border-blue-500"
            data-agency-id="${escapeHTML(m.agency_id)}">
            <option value="MFR"${m.provider_level === "MFR" ? " selected" : ""}>MFR</option>
            <option value="EMT"${m.provider_level === "EMT" ? " selected" : ""}>EMT</option>
            <option value="AEMT"${m.provider_level === "AEMT" ? " selected" : ""}>AEMT</option>
            <option value="Paramedic"${m.provider_level === "Paramedic" ? " selected" : ""}>Paramedic</option>
          </select>
        </div>
      </div>
      <button class="btn-save-membership mt-2 w-full text-xs bg-amber-600 hover:bg-amber-500 text-white py-1.5 rounded transition-colors ui-btn ui-btn--amber"
        data-agency-id="${escapeHTML(m.agency_id)}">Save Level / MCA</button>
      <div class="membership-feedback text-xs mt-1 text-center hidden" data-agency-id="${escapeHTML(m.agency_id)}"></div>
    </div>
  `).join("");

  // Wire Save buttons for active membership
  container.querySelectorAll(".btn-save-membership").forEach(btn => {
    btn.addEventListener("click", async () => {
      const agencyId  = btn.dataset.agencyId;
      const levelSel  = container.querySelector(`.membership-level[data-agency-id="${agencyId}"]`);
      const mcaSel    = container.querySelector(`.membership-mca[data-agency-id="${agencyId}"]`);
      const feedbackEl = container.querySelector(`.membership-feedback[data-agency-id="${agencyId}"]`);
      btn.disabled = true;
      btn.textContent = "Saving…";
      feedbackEl.classList.add("hidden");
      try {
        const res = await authFetch(`${API}/api/me/membership`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ agency_id: agencyId, provider_level: levelSel.value, mca: mcaSel.value }),
        });
        if (!res.ok) {
          const err = await res.json().catch(() => ({}));
          feedbackEl.textContent = err.detail || "Save failed.";
          feedbackEl.className = "membership-feedback text-xs mt-1 text-center text-red-400";
          feedbackEl.classList.remove("hidden");
          return;
        }
        const data = await res.json();
        _storeAuthFromContext(data);
        buildMenu();
        feedbackEl.textContent = "Saved!";
        feedbackEl.className = "membership-feedback text-xs mt-1 text-center text-green-400";
        feedbackEl.classList.remove("hidden");
      } catch {
        feedbackEl.textContent = "Connection error.";
        feedbackEl.className = "membership-feedback text-xs mt-1 text-center text-red-400";
        feedbackEl.classList.remove("hidden");
      } finally {
        btn.disabled = false;
        btn.textContent = "Save Level / MCA";
      }
    });
  });

  // Wire Leave buttons — modal confirm/cancel are wired once at module scope below
  container.querySelectorAll(".btn-leave-agency").forEach(btn => {
    btn.addEventListener("click", () => {
      _leavePendingAgencyId = btn.dataset.agencyId;
      const name = btn.dataset.agencyName;
      const msgEl = el("leave-agency-msg");
      if (msgEl) msgEl.textContent = `Remove yourself from "${name}"?`;
      show("modal-leave-agency");
    });
  });
}

async function saveEditProfile() {
  const errorEl   = el("edit-profile-error");
  const successEl = el("edit-profile-success");
  errorEl.classList.add("hidden");
  successEl.classList.add("hidden");

  const firstName = el("edit-first-name").value.trim();
  const lastName  = el("edit-last-name").value.trim();
  const email     = el("edit-email").value.trim();
  const password  = el("edit-password").value;

  if (password && password.length < 8) {
    errorEl.textContent = "Password must be at least 8 characters.";
    errorEl.classList.remove("hidden");
    return;
  }

  const body = {
    first_name: firstName || null,
    last_name:  lastName  || null,
    email:      email     || null,
  };
  if (password) body.password = password;

  el("btn-edit-profile-save").disabled = true;
  el("btn-edit-profile-save").textContent = "Saving…";

  try {
    const res = await authFetch(`${API}/api/me`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      errorEl.textContent = err.detail || "Could not save changes.";
      errorEl.classList.remove("hidden");
      return;
    }
    const data = await res.json();
    _storeAuthFromContext(data);
    buildMenu();
    successEl.textContent = "Profile updated!";
    successEl.classList.remove("hidden");
    setTimeout(() => hide("modal-edit-profile"), 1200);
  } catch {
    errorEl.textContent = "Connection error.";
    errorEl.classList.remove("hidden");
  } finally {
    el("btn-edit-profile-save").disabled = false;
    el("btn-edit-profile-save").textContent = "Save Personal Info";
  }
}

async function handleJoinAgency() {
  if (_isScormRuntimeUi()) {
    _applyScormSaasUiTrim();
    return;
  }
  const errEl     = el("join-agency-error");
  const successEl = el("join-agency-success");
  errEl.classList.add("hidden");
  successEl.classList.add("hidden");

  const agencyId = el("join-agency-select").value;
  const joinCode = el("join-code-input").value.trim();
  const level    = el("join-level").value;
  const mca      = el("join-mca").value;

  const isOpen = _agencyOpenMap[agencyId] === true;

  if (!agencyId) { errEl.textContent = "Please select an agency."; errEl.classList.remove("hidden"); return; }
  if (!isOpen && !joinCode) { errEl.textContent = "Please enter the join code."; errEl.classList.remove("hidden"); return; }

  el("btn-join-agency").disabled = true;
  el("btn-join-agency").textContent = "Joining…";

  const joinPayload = isOpen ? { agency_id: agencyId } : { agency_id: agencyId, agency_join_code: joinCode };

  try {
    const res = await authFetch(`${API}/api/agencies/join`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...joinPayload,
        provider_level: level,
        mca,
      }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      errEl.textContent = err.detail || "Could not join agency.";
      errEl.classList.remove("hidden");
      return;
    }
    const data = await res.json();

    // Update in-memory membership count so Switch button appears immediately
    state._membershipCount = data.membership_count;
    const switchBtn = el("btn-switch-agency");
    if (switchBtn && data.membership_count > 1) switchBtn.classList.remove("hidden");

    // Re-render memberships list with updated data
    _renderMembershipsList(data.memberships);

    successEl.textContent = "Joined! Use 'Switch Agency' to activate this context.";
    successEl.classList.remove("hidden");
    el("join-code-input").value = "";
  } catch {
    errEl.textContent = "Connection error.";
    errEl.classList.remove("hidden");
  } finally {
    el("btn-join-agency").disabled = false;
    el("btn-join-agency").textContent = "Join Agency";
  }
}

