function _assessmentMaxFromSubscores(subscores) {
  const maxes = subscores?._maxes;
  if (maxes && typeof maxes === "object") {
    return ["clinical_performance", "protocols_treatment", "scope_adherence", "dmist", "professionalism"]
      .reduce((sum, key) => sum + (Number(maxes[key]) || 0), 0) || (subscores.protocols_treatment !== undefined ? 100 : 80);
  }
  return (subscores && subscores.protocols_treatment !== undefined) ? 100 : 80;
}

function _assessmentMaxFromEntry(entry) {
  return entry?.assessmentMax || _assessmentMaxFromSubscores(entry?.subscores);
}

function _assessmentPctFromScore(score, denom = 100) {
  if (score === null || score === undefined) return null;
  const max = Number(denom) || 100;
  return Math.round((Number(score) / max) * 100);
}

function _assessmentPctFromEntry(entry) {
  if (!entry) return null;
  const raw = entry.assessmentScore ?? entry.score;
  return _assessmentPctFromScore(raw, _assessmentMaxFromEntry(entry));
}

function _scenarioHistoryEntryPassed(entry) {
  if (!entry || entry.criticalFailure?.triggered) return false;
  const pct = _assessmentPctFromEntry(entry);
  return pct !== null && pct >= 70;
}

function _assessmentStatusMeta(pct, { assessmentOnly = false, criticalFailure = null } = {}) {
  if (criticalFailure?.triggered) {
    return { cls: "text-red-500", label: criticalFailure.display_label || "Critical Misses", tone: "critical" };
  }
  if (pct === null || pct === undefined || Number.isNaN(Number(pct))) {
    return { cls: "text-gray-400", label: "No Score", tone: "none" };
  }
  const score = Number(pct);
  if (score >= 92) return { cls: "text-green-400", label: "Excellent Rep", tone: "excellent" };
  if (score >= 85) return { cls: "text-blue-400", label: "Strong Rep", tone: "strong" };
  if (score >= 70) return { cls: "text-yellow-400", label: assessmentOnly ? "On Track (Assessment only)" : "On Track", tone: "on_track" };
  if (score >= 60) return { cls: "text-orange-400", label: "Needs Work", tone: "needs_work" };
  return { cls: "text-red-400", label: "Growth Opportunity", tone: "growth" };
}

function _subscoreDefsForDisplay(subscores) {
  const maxes = subscores?._maxes || {};
  if (subscores && subscores.protocols_treatment !== undefined) {
    const defs = [
      { key: "clinical_performance", label: "Clinical Performance", max: Number(maxes.clinical_performance) || 50 },
      { key: "protocols_treatment", label: "Protocols & Treatment", max: Number(maxes.protocols_treatment) || 30 },
    ];
    if (subscores.scope_adherence !== undefined) {
      defs.push({ key: "scope_adherence", label: "Scope Adherence", max: Number(maxes.scope_adherence) || 20 });
    }
    defs.push(
      { key: "dmist", label: "DMIST Quality", max: Number(maxes.dmist) || 10 },
      { key: "professionalism", label: "Professionalism", max: Number(maxes.professionalism) || 10 },
    );
    return defs;
  }
  return [
    { key: "clinical_performance", label: "Clinical Performance", max: Number(maxes.clinical_performance) || 40 },
    { key: "scope_adherence", label: "Scope Adherence", max: Number(maxes.scope_adherence) || 20 },
    { key: "dmist", label: "DMIST Quality", max: Number(maxes.dmist) || 10 },
    { key: "professionalism", label: "Professionalism", max: Number(maxes.professionalism) || 10 },
  ];
}

function _renderHistoryDebriefError(message) {
  setText("modal-history-debrief-title", "FTO Evaluation");
  setText("modal-history-debrief-subtitle", "Could not load feedback");
  const content = el("modal-history-debrief-content");
  if (content) {
    content.innerHTML = `
      <div class="rounded-2xl border border-red-800 bg-red-950/40 p-5">
        <h3 class="text-red-100 font-bold text-sm">Feedback could not load</h3>
        <p class="text-red-200/80 text-sm mt-2">${escapeHTML(message || "Unknown error")}</p>
      </div>
    `;
  }
  el("btn-history-debrief-retake")?.classList.add("hidden");
  el("btn-history-debrief-with-lexi")?.classList.add("hidden");
  show("modal-history-debrief");
}

function _historyDebriefText(entry = {}) {
  return String(
    entry.debrief
    || entry.feedback
    || entry.debriefMarkdown
    || entry.debrief_markdown
    || entry.feedback_markdown
    || ""
  ).trim();
}

function _normalizeHistoryEntryForDisplay(entry = {}) {
  if (!entry || typeof entry !== "object") return {};
  return {
    ...entry,
    debrief: _historyDebriefText(entry),
    timeline: Array.isArray(entry.timeline) ? entry.timeline : [],
    rubricDetail: Array.isArray(entry.rubricDetail)
      ? entry.rubricDetail
      : Array.isArray(entry.rubric_detail)
        ? entry.rubric_detail
        : [],
    scoreNotes: entry.scoreNotes || entry.score_notes || {},
    pcrSnapshotHtml: entry.pcrSnapshotHtml || entry.pcr_snapshot_html || "",
    pcrNotes: entry.pcrNotes || entry.pcr_notes || null,
    topTakeaways: Array.isArray(entry.topTakeaways)
      ? entry.topTakeaways
      : Array.isArray(entry.top_takeaways)
        ? entry.top_takeaways
        : [],
    reflectionPrompts: Array.isArray(entry.reflectionPrompts)
      ? entry.reflectionPrompts
      : Array.isArray(entry.reflection_prompts)
        ? entry.reflection_prompts
        : [],
    nextAction: entry.nextAction || entry.next_action || "",
    nextActionTargetType: entry.nextActionTargetType || entry.next_action_target_type || "none",
    nextActionTargetId: entry.nextActionTargetId || entry.next_action_target_id || null,
    debriefLexiHints: Array.isArray(entry.debriefLexiHints)
      ? entry.debriefLexiHints
      : Array.isArray(entry.debrief_lexi_hints)
        ? entry.debrief_lexi_hints
        : [],
  };
}

function _historyDebriefHtml(text = "") {
  const raw = String(text || "").trim();
  if (!raw) return "";
  return raw
    .split(/\n{2,}/)
    .map(block => `<p style="margin:0 0 0.9rem;color:#f3f4f6;line-height:1.6;">${escapeHTML(block).replace(/\n/g, "<br>")}</p>`)
    .join("");
}

function _historyDebriefSubtitle(entry = {}) {
  const parts = [];
  if (entry.drillMode) parts.push("Quick Drill");
  else parts.push("Full Scenario");
  if (entry.date) {
    const d = new Date(entry.date);
    if (!Number.isNaN(d.getTime())) {
      parts.push(d.toLocaleString(undefined, { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" }));
    }
  }
  if (entry.elapsedMin !== undefined && entry.elapsedMin !== null) parts.push(`${entry.elapsedMin}m on scene`);
  return parts.filter(Boolean).join(" · ") || "Scenario feedback";
}

function _historySubscoresHtml(entry = {}) {
  const subscores = entry.subscores || {};
  const defs = _subscoreDefsForDisplay(subscores)
    .filter(def => subscores[def.key] !== undefined && subscores[def.key] !== null);
  if (!defs.length) return "";
  return `
    <div class="rounded-2xl border border-gray-700 bg-gray-900 p-4 mb-4">
      <div class="text-xs uppercase tracking-widest text-gray-400 font-bold mb-3">Score Breakdown</div>
      <div class="grid grid-cols-1 sm:grid-cols-2 gap-2">
        ${defs.map(def => `
          <div class="rounded-xl border border-gray-800 bg-gray-950/50 px-3 py-2">
            <div class="text-gray-300 text-xs">${escapeHTML(def.label)}</div>
            <div class="text-white font-bold font-mono text-sm mt-0.5">${escapeHTML(subscores[def.key])}/${escapeHTML(def.max)}</div>
          </div>
        `).join("")}
      </div>
    </div>
  `;
}

function _historyInlineTimelineHtml(timeline) {
  const rows = Array.isArray(timeline) ? timeline : [];
  if (!rows.length) return "";
  return `
    <section style="margin-top:1rem;border:1px solid #374151;background:#111827;border-radius:16px;padding:16px;">
      <div style="color:#9ca3af;font-size:11px;text-transform:uppercase;letter-spacing:.12em;font-weight:800;margin-bottom:10px;">Intervention Timeline</div>
      <div style="display:grid;gap:8px;">
        ${rows.map(row => {
          const status = String(row.status || "");
          const color = status === "applied" ? "#bbf7d0" : status === "informational" ? "#bfdbfe" : status === "out_of_order" ? "#fde68a" : "#fecaca";
          const icon = status === "applied" ? "✓" : status === "informational" ? "i" : status === "out_of_order" ? "!" : "×";
          const time = row.elapsed_min !== null && row.elapsed_min !== undefined ? `+${row.elapsed_min}m` : "";
          return `<div style="display:flex;gap:10px;align-items:flex-start;border-bottom:1px solid #1f2937;padding-bottom:8px;">
            <span style="color:${color};font-weight:900;width:16px;">${icon}</span>
            <span style="color:#6b7280;font-size:12px;width:42px;">${escapeHTML(time)}</span>
            <span style="color:${color};font-size:13px;line-height:1.4;">${escapeHTML(row.action || "")}</span>
          </div>`;
        }).join("")}
      </div>
    </section>
  `;
}

function _historyInlineRubricHtml(rubricDetail) {
  const groups = Array.isArray(rubricDetail) ? rubricDetail : [];
  if (!groups.length) return "";
  return `
    <section style="margin-top:1rem;border:1px solid #374151;background:#111827;border-radius:16px;padding:16px;">
      <div style="color:#9ca3af;font-size:11px;text-transform:uppercase;letter-spacing:.12em;font-weight:800;margin-bottom:10px;">Rubric Detail - Done / Not Done</div>
      <div style="display:grid;gap:12px;">
        ${groups.map(group => {
          const rows = Array.isArray(group.items) ? group.items : [];
          return `<div style="border:1px solid #1f2937;border-radius:12px;overflow:hidden;">
            <div style="display:flex;justify-content:space-between;gap:12px;background:#0f172a;padding:10px 12px;border-bottom:1px solid #1f2937;">
              <span style="color:#e5e7eb;font-size:12px;font-weight:800;text-transform:uppercase;letter-spacing:.08em;">${escapeHTML(group.label || group.category || "Rubric")}</span>
              <span style="color:#9ca3af;font-size:12px;font-family:ui-monospace,Menlo,monospace;">${group.score ?? ""}${group.max !== undefined ? `/${group.max}` : ""}</span>
            </div>
            <div style="display:grid;">
              ${rows.map(item => {
                const status = String(item.status || "");
                const done = status === "satisfied";
                const partial = status === "partial";
                const color = done ? "#bbf7d0" : partial ? "#fde68a" : "#fecaca";
                const icon = done ? "✓" : partial ? "◐" : "×";
                return `<div style="display:flex;gap:10px;align-items:flex-start;padding:9px 12px;border-bottom:1px solid #1f2937;">
                  <span style="color:${color};font-weight:900;width:16px;">${icon}</span>
                  <span style="color:#e5e7eb;font-size:13px;line-height:1.4;flex:1;">${escapeHTML(item.label || item.id || "Rubric item")}</span>
                  <span style="color:${color};font-size:12px;font-weight:800;">${escapeHTML(item.earned ?? 0)}/${escapeHTML(item.points ?? 0)}</span>
                </div>`;
              }).join("") || `<div style="padding:10px 12px;color:#9ca3af;font-size:13px;">No rubric items stored.</div>`}
            </div>
          </div>`;
        }).join("")}
      </div>
    </section>
  `;
}

function _lastResultsBodyHtml(entry = {}) {
  return `<div class="last-results-report">${_buildCoachFeedbackHtml(_normalizeHistoryEntryForDisplay(entry))}</div>`;
}

function _renderLastResultsModal(entry = {}) {
  entry = _normalizeHistoryEntryForDisplay(entry);
  _lastResultsActiveEntry = entry;
  setText("last-results-title", entry.title || "Scenario Feedback");
  setText("last-results-subtitle", _historyDebriefSubtitle(entry));
  const content = el("last-results-content");
  if (content) content.innerHTML = _lastResultsBodyHtml(entry);
  el("btn-last-results-retake")?.classList.toggle("hidden", !entry.scenarioId);
  el("btn-last-results-lexi")?.classList.toggle("hidden", !_historyDebriefText(entry));
  show("modal-last-results");
}

async function _openLastResultsByKey(key) {
  if (!key) return;
  let entry = _findHistoryEntryByKey(key);
  if (!entry) {
    // Show immediately with a loading shell so the click feels instant
    setText("last-results-title", "Loading…");
    setText("last-results-subtitle", "Fetching call record");
    const loadingContent = el("last-results-content");
    if (loadingContent) loadingContent.innerHTML = `<div class="rounded-2xl border border-gray-200 bg-white p-5 text-gray-500 text-sm shadow-sm">Loading results…</div>`;
    el("btn-last-results-retake")?.classList.add("hidden");
    el("btn-last-results-lexi")?.classList.add("hidden");
    show("modal-last-results");
    await _refreshHistoryCache();
    entry = _findHistoryEntryByKey(key);
  }
  if (!entry) {
    _lastResultsActiveEntry = null;
    setText("last-results-title", "Scenario Feedback");
    setText("last-results-subtitle", "Could not load last results");
    const content = el("last-results-content");
    if (content) {
      content.innerHTML = `<div class="rounded-2xl border border-red-800 bg-red-950/40 p-5 text-red-100">That previous run could not be found. Try reopening the map and selecting the scenario again.</div>`;
    }
    el("btn-last-results-retake")?.classList.add("hidden");
    el("btn-last-results-lexi")?.classList.add("hidden");
    show("modal-last-results");
    return;
  }
  _renderLastResultsModal(entry);

  const normalized = _normalizeHistoryEntryForDisplay(entry);
  const hasDetails = Boolean(
    _historyDebriefText(normalized) ||
    (Array.isArray(normalized.timeline) && normalized.timeline.length) ||
    (Array.isArray(normalized.rubricDetail) && normalized.rubricDetail.length)
  );
  if (!hasDetails) {
    await _refreshHistoryCache();
    const fresh = _findHistoryEntryByKey(key);
    if (fresh) _renderLastResultsModal(fresh);
  }
}

function _openHistoryDebriefModal(entry) {
  if (!entry) return;
  const fullEntry = entry.key
    ? ((_historyCache || []).find(e => String(e.key) === String(entry.key)) || entry)
    : entry;
  entry = _normalizeHistoryEntryForDisplay(fullEntry);
  const debriefText = _historyDebriefText(entry);

  _historyDebriefActiveEntry = entry;
  const titleEl = el("modal-history-debrief-title");
  const subtitleEl = el("modal-history-debrief-subtitle");
  const contentEl = el("modal-history-debrief-content");
  if (!titleEl || !contentEl) {
    showToast("Debrief popup is missing from the page.", "error");
    return;
  }

  titleEl.textContent = entry.title ? `FTO Evaluation - ${entry.title}` : "FTO Evaluation";
  if (subtitleEl) subtitleEl.textContent = _historyDebriefSubtitle(entry);
  contentEl.innerHTML = `<div class="last-results-report">${_buildCoachFeedbackHtml(entry)}</div>`;

  el("btn-history-debrief-with-lexi")?.classList.toggle("hidden", !debriefText);
  const retakeBtn = el("btn-history-debrief-retake");
  if (retakeBtn) {
    const canRetake = Boolean(entry?.scenarioId);
    retakeBtn.classList.toggle("hidden", !canRetake);
    retakeBtn.dataset.scenario = canRetake ? entry.scenarioId : "";
  }
  show("modal-history-debrief");
  return;
}

el("btn-history-debrief-close").addEventListener("click", () => hide("modal-history-debrief"));
el("modal-history-debrief")?.addEventListener("click", (event) => {
  if (event.target === el("modal-history-debrief")) hide("modal-history-debrief");
});
el("btn-history-debrief-retake")?.addEventListener("click", () => {
  const scenarioId = _historyDebriefActiveEntry?.scenarioId || el("btn-history-debrief-retake")?.dataset.scenario;
  if (!scenarioId) return;
  hide("modal-history-debrief");
  resetSessionState();
  startScenario(scenarioId);
});
el("btn-history-debrief-with-lexi")?.addEventListener("click", () => {
  if (!_historyDebriefActiveEntry) return;
  hide("modal-history-debrief");
  _openDebriefWithLexi(_historyDebriefActiveEntry, "history");
});

el("btn-last-results-close")?.addEventListener("click", () => hide("modal-last-results"));
el("modal-last-results")?.addEventListener("click", (event) => {
  if (event.target === el("modal-last-results")) hide("modal-last-results");
});
el("btn-last-results-retake")?.addEventListener("click", () => {
  const scenarioId = _lastResultsActiveEntry?.scenarioId;
  if (!scenarioId) return;
  hide("modal-last-results");
  resetSessionState();
  startScenario(scenarioId);
});
el("btn-last-results-lexi")?.addEventListener("click", () => {
  if (!_lastResultsActiveEntry) return;
  hide("modal-last-results");
  _openDebriefWithLexi(_lastResultsActiveEntry, "history");
});

el("btn-orientation-complete-close")?.addEventListener("click", _closeOrientationCompletionModal);
el("btn-orientation-complete-continue")?.addEventListener("click", _closeOrientationCompletionModal);
el("modal-orientation-complete")?.addEventListener("click", (event) => {
  if (event.target === el("modal-orientation-complete")) _closeOrientationCompletionModal();
});
el("btn-orientation-complete-lexi")?.addEventListener("click", () => {
  if (!_orientationCompleteEntry) return;
  _closeOrientationCompletionModal();
  _openDebriefWithLexi(_orientationCompleteEntry, "orientation");
});

function _buildCurrentPcrSnapshotHtml() {
  const notes = el("tab-notes");
  if (!notes) {
    return `<div class="text-sm text-gray-400">No live PCR snapshot available for this run.</div>`;
  }
  const clone = notes.cloneNode(true);
  clone.id = "";
  clone.className = "coach-full-pcr-notes";
  clone.querySelectorAll("[id]").forEach(node => node.removeAttribute("id"));
  return clone.outerHTML;
}

function _buildHistoryPcrSnapshotHtml(entry) {
  const html = String(entry?.pcrSnapshotHtml || entry?.pcr_snapshot_html || "").trim();
  if (html) return html;
  const notesHtml = _renderSavedPcrNotesHtml(entry?.pcrNotes || entry?.pcr_notes);
  if (notesHtml) return notesHtml;
  return `<div class="text-sm text-gray-400">PCR notes are not available for this saved run. Complete a new run to capture the full PCR Notes snapshot.</div>`;
}

function _pcrSavedItemsHtml(items = [], { treatment = false } = {}) {
  const rows = Array.isArray(items) ? items : [];
  return rows.map(item => {
    if (treatment) {
      const label = typeof item === "string" ? item : item?.label;
      if (!String(label || "").trim()) return "";
      return `<div class="pcr-item"><span class="pcr-treat-val">✓ ${escapeHTML(label)}</span></div>`;
    }
    const key = typeof item === "string" ? "" : item?.key;
    const value = typeof item === "string" ? item : item?.value;
    if (!String(value || key || "").trim()) return "";
    return `<div class="pcr-item"><span class="pcr-item-key">${escapeHTML(key || "Finding")}:</span><span class="pcr-item-val">${escapeHTML(value || "")}</span></div>`;
  }).join("");
}

function _renderSavedPcrNotesHtml(notes) {
  if (!notes || typeof notes !== "object") return "";
  const sections = [
    { label: "📡 Dispatch", html: escapeHTML(notes.dispatch || "") },
    { label: "👁 Presentation", html: escapeHTML(notes.presentation || "") },
    { label: "🔍 Exam / OPQRST", html: _pcrSavedItemsHtml(notes.exam) },
    { label: "📋 History", html: _pcrSavedItemsHtml(notes.history) },
    { label: "📊 Vital Signs", html: _pcrSavedItemsHtml(notes.vitals) },
    { label: "💊 Treatments", html: _pcrSavedItemsHtml(notes.treatments, { treatment: true }) },
  ];
  const header = [
    notes.patientId ? `<div class="text-white font-bold text-xs mb-1">${escapeHTML(notes.patientId)}</div>` : "",
    notes.complaint ? `<div class="text-red-400 text-xs mb-2">${escapeHTML(notes.complaint)}</div>` : "",
  ].join("");
  const body = sections.map(section => {
    const content = String(section.html || "").trim() || "&nbsp;";
    return `<div class="pcr-section">
      <div class="pcr-label">${section.label}</div>
      <div class="pcr-value">${content}</div>
    </div>`;
  }).join("");
  return body ? `${header}${body}` : "";
}

function _renderTimelinePanel(timeline, heading = "📋 Intervention Timeline", extraClasses = "") {
  const rowsSrc = Array.isArray(timeline) ? timeline : [];
  if (!rowsSrc.length) return "";
  const rows = rowsSrc.map(t => {
    const isApplied = t.status === "applied";
    const isInfo = t.status === "informational";
    const isOutOfOrder = t.status === "out_of_order";
    const icon = isApplied ? "✅" : isInfo ? "ℹ️" : isOutOfOrder ? "⚠️" : "❌";
    const timeStr = t.elapsed_min !== null && t.elapsed_min !== undefined
      ? `+${t.elapsed_min}m`
      : isInfo ? "auto" : isOutOfOrder ? "order" : isApplied ? "scene" : "missed";
    const labelClass = isApplied ? "text-gray-200" : isInfo ? "text-blue-400" : isOutOfOrder ? "text-amber-400" : "text-red-400";
    return `<div class="flex items-center gap-2 text-xs py-1 border-b border-gray-800">
      <span class="w-4 shrink-0">${icon}</span>
      <span class="text-gray-500 w-12 shrink-0">${timeStr}</span>
      <span class="${labelClass}">${escapeHTML(t.action || "")}</span>
    </div>`;
  }).join("");
  return `<div class="${extraClasses} border border-gray-700 rounded-lg p-3">
    <div class="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">${heading}</div>
    ${rows}
  </div>`;
}

function _renderRubricDetailContent(rubricDetail) {
  const groups = Array.isArray(rubricDetail) ? rubricDetail : [];
  if (!groups.length) return "";
  const statusMeta = {
    satisfied: { icon: "✅", cls: "text-green-400", label: "Done" },
    partial: { icon: "◐", cls: "text-amber-400", label: "Partial" },
    not_satisfied: { icon: "❌", cls: "text-red-400", label: "Not done" },
    contradicted: { icon: "⚠️", cls: "text-red-400", label: "Contradicted" },
    unsupported_by_run: { icon: "⚠️", cls: "text-amber-400", label: "Unsupported" },
    ambiguous: { icon: "?", cls: "text-gray-400", label: "Review" },
  };
  return groups.map(group => {
    const scoreText = group.score !== null && group.score !== undefined && group.max !== null && group.max !== undefined
      ? `${group.score}/${group.max}`
      : "";
    const items = Array.isArray(group.items) ? group.items : [];
    const rows = items.map(item => {
      const meta = statusMeta[item.status] || { icon: "•", cls: "text-gray-400", label: item.status || "Unknown" };
      const req = item.required === "bonus" ? "bonus" : item.required === "optional" ? "optional" : "required";
      const points = item.required === "bonus"
        ? `+${item.earned || 0}/${item.points || 0}`
        : `${item.earned || 0}/${item.points || 0}`;
      const note = item.timing_violation ? " · timing/order issue" : item.notes ? ` · ${item.notes}` : "";
      return `<div class="flex items-start gap-2 text-xs py-1.5 border-b border-gray-800 last:border-b-0">
        <span class="w-5 shrink-0">${meta.icon}</span>
        <div class="flex-1 min-w-0">
          <div class="text-gray-200">${escapeHTML(item.label || item.id || "Rubric item")}</div>
          <div class="text-[11px] text-gray-500">${escapeHTML(req)} · ${escapeHTML(meta.label)}${escapeHTML(note)}</div>
        </div>
        <span class="${meta.cls} font-semibold shrink-0">${escapeHTML(points)}</span>
      </div>`;
    }).join("");
    return `<div class="rounded-lg border border-gray-800 bg-gray-950/40 overflow-hidden">
      <div class="flex items-center justify-between gap-3 px-3 py-2 bg-gray-900/70 border-b border-gray-800">
        <span class="text-xs font-bold text-gray-300 uppercase tracking-widest">${escapeHTML(group.label || group.category || "Rubric")}</span>
        <span class="text-xs text-gray-400 font-mono">${escapeHTML(scoreText)}</span>
      </div>
      <div class="px-3 py-1">${rows}</div>
    </div>`;
  }).join("");
}

function _renderRubricDetailPanel(rubricDetail, heading = "✅ Rubric Detail", extraClasses = "") {
  const content = _renderRubricDetailContent(rubricDetail);
  if (!content) return "";
  return `<div class="${extraClasses} border border-gray-700 rounded-lg p-3">
    <div class="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">${heading}</div>
    <div class="space-y-3">${content}</div>
  </div>`;
}

function _scoreNoteLabel(key = "") {
  const labels = {
    clinical_performance: "Clinical Performance",
    protocols_treatment: "Protocols & Treatment",
    scope_adherence: "Scope Adherence",
    dmist: "DMIST / Handoff",
    professionalism: "Professionalism",
    narrative: "Narrative Bonus",
  };
  return labels[key] || String(key || "Scoring").replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase());
}

function _scoreNoteRows(scoreNotes = {}) {
  if (!scoreNotes || typeof scoreNotes !== "object") return [];
  return Object.entries(scoreNotes)
    .filter(([, note]) => String(note || "").trim())
    .map(([key, note]) => ({
      label: _scoreNoteLabel(key),
      detail: String(note || "").trim(),
      source: "score_note",
    }));
}

function _missedTimelineRows(timeline = []) {
  return (Array.isArray(timeline) ? timeline : [])
    .filter(row => ["missed", "out_of_order", "contradicted"].includes(String(row?.status || "")) && String(row?.action || "").trim())
    .slice(0, 8)
    .map(row => ({
      label: row.status === "out_of_order" ? "Timing / Sequence" : "Missed Action",
      detail: row.action,
      source: "timeline",
    }));
}

function _missedRubricRows(rubricDetail = []) {
  const rows = [];
  (Array.isArray(rubricDetail) ? rubricDetail : []).forEach(group => {
    (Array.isArray(group?.items) ? group.items : []).forEach(item => {
      const status = String(item?.status || "");
      const points = Number(item?.points || 0);
      const earned = Number(item?.earned || 0);
      if (status === "satisfied" || earned >= points || points <= 0) return;
      rows.push({
        label: group?.label || group?.category || "Rubric",
        detail: `${item?.label || item?.id || "Rubric item"} (${earned}/${points})${item?.notes ? ` - ${item.notes}` : ""}`,
        source: "rubric",
      });
    });
  });
  return rows.slice(0, 10);
}

function _renderMissedPointsHtml({ scoreNotes = {}, timeline = [], rubricDetail = [] } = {}) {
  const noteRows = _scoreNoteRows(scoreNotes);
  const timelineRows = _missedTimelineRows(timeline);
  const rubricRows = _missedRubricRows(rubricDetail);
  const seen = new Set();
  const rows = [...noteRows, ...timelineRows, ...rubricRows].filter(row => {
    const key = `${row.label}|${row.detail}`.toLowerCase();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
  if (!rows.length) return "";
  return rows.map(row => {
    const sourceLabel = row.source === "score_note" ? "Score note" : row.source === "timeline" ? "Timeline" : "Rubric";
    return `<div class="debrief-missed-point-card rounded-lg border border-gray-300 bg-white p-2.5">
      <div class="flex items-center justify-between gap-3">
        <div class="debrief-missed-point-label text-xs font-bold uppercase tracking-widest text-gray-800">${escapeHTML(row.label)}</div>
        <div class="debrief-missed-point-source text-[10px] uppercase tracking-widest text-slate-600">${escapeHTML(sourceLabel)}</div>
      </div>
      <div class="debrief-missed-point-detail mt-1 text-sm text-gray-950 leading-relaxed">${escapeHTML(row.detail)}</div>
    </div>`;
  }).join("");
}

function _buildCoachFeedbackHtml(entry) {
  const score = entry?.assessmentScore ?? entry?.score;
  const denom = _assessmentMaxFromEntry(entry);
  const pct = _assessmentPctFromScore(score, denom);
  const scoreClass = _assessmentStatusMeta(pct, { criticalFailure: entry?.criticalFailure }).cls;
  const scoreRow = score === null || score === undefined
    ? ""
    : `<div class="mb-3 text-sm"><span class="text-gray-400">Score:</span> <span class="${scoreClass} font-bold">${score}/${denom || 100}</span></div>`;
  const timeline = Array.isArray(entry?.timeline) ? entry.timeline : [];
  const timelineHtml = _renderTimelinePanel(timeline, "📋 Intervention Timeline", "mt-4");
  const rubricHtml = _renderRubricDetailPanel(entry?.rubricDetail, "✅ Rubric Detail — Done / Not Done", "mt-4");
  // Strip sections 8 & 9 when condition is locked — defense-in-depth against cached
  // pre-fix entries that may still carry the full debrief text client-side.
  const locked = _isConditionLocked(entry?.impressionChallenge);
  const missedHtml = _renderMissedPointsHtml({
    scoreNotes: entry?.scoreNotes,
    timeline,
    rubricDetail: entry?.rubricDetail,
  });
  const missedPanel = missedHtml && !locked
    ? `<div class="mt-4 border border-amber-900/60 bg-amber-950/20 rounded-lg p-3">
      <div class="text-xs font-bold text-amber-300 uppercase tracking-widest mb-2">Missed Points & Deduction Reasons</div>
      <div class="space-y-2">${missedHtml}</div>
    </div>`
    : "";
  const rawDebrief = entry?.debrief || "";
  const debriefText = locked
    ? (_splitDebriefForModal(rawDebrief).mainMarkdown || "No debrief feedback available.")
    : (rawDebrief || "No debrief feedback available.");
  return `${scoreRow}<div class="debrief-prose">${renderMarkdown(debriefText)}</div>${missedPanel}${timelineHtml}${rubricHtml}`;
}

function _isCoachMobileTarget() {
  const compact = window.matchMedia ? window.matchMedia("(max-width: 1024px)").matches : (window.innerWidth <= 1024);
  const coarse = window.matchMedia ? window.matchMedia("(pointer: coarse)").matches : false;
  const touch = coarse || (navigator.maxTouchPoints || 0) > 0;
  return !!(compact && touch);
}

function _setCoachMobileTab(tab = "feedback") {
  const screen = el("screen-debrief-lexi");
  if (!screen) return;
  const safe = (tab === "notes" || tab === "feedback" || tab === "lexi") ? tab : "feedback";
  _debriefCoach.mobileTab = safe;
  screen.classList.remove("coach-mobile-notes", "coach-mobile-feedback", "coach-mobile-lexi");
  screen.classList.add(`coach-mobile-${safe}`);
  el("btn-coach-tab-notes")?.classList.toggle("active", safe === "notes");
  el("btn-coach-tab-feedback")?.classList.toggle("active", safe === "feedback");
  el("btn-coach-tab-lexi")?.classList.toggle("active", safe === "lexi");
}

function _syncCoachMobileMode() {
  const tabs = el("coach-mobile-tabs");
  const screen = el("screen-debrief-lexi");
  if (!tabs || !screen) return;
  const mobile = _isCoachMobileTarget();
  tabs.classList.toggle("hidden", !mobile);
  if (mobile) _setCoachMobileTab(_debriefCoach.mobileTab || "feedback");
  else screen.classList.remove("coach-mobile-notes", "coach-mobile-feedback", "coach-mobile-lexi");
}

function _coachLexiAppendUser(text) {
  const container = el("coach-lexi-messages");
  const div = document.createElement("div");
  div.className = "lexi-msg-user";
  div.textContent = text;
  container?.appendChild(div);
  if (container) container.scrollTop = container.scrollHeight;
}

function _coachLexiAppendBot(text) {
  const container = el("coach-lexi-messages");
  const div = document.createElement("div");
  div.className = "lexi-msg-bot";
  div.textContent = text;
  container?.appendChild(div);
  if (container) container.scrollTop = container.scrollHeight;
  return div;
}

function _coachLexiAppendTyping() {
  const container = el("coach-lexi-messages");
  const div = document.createElement("div");
  div.className = "lexi-msg-bot";
  div.innerHTML = `<div class="typing-dots"><span></span><span></span><span></span></div>`;
  container?.appendChild(div);
  if (container) container.scrollTop = container.scrollHeight;
  return div;
}

const COACH_LEXI_DEFAULT_QUICK_ACTIONS = [
  { label: "Top 2 Fixes", msg: "What are my top 2 improvement priorities from this run?" },
  { label: "DMIST Coach", msg: "Help me improve my DMIST for this case in 60 seconds." },
  { label: "Next Replay Plan", msg: "Give me a 3-step plan for my next replay of this scenario." },
];

function _coachLexiQuickActions(entry = {}) {
  const scenarioHints = Array.isArray(entry.debriefLexiHints)
    ? entry.debriefLexiHints
    : Array.isArray(entry.debrief_lexi_hints)
      ? entry.debrief_lexi_hints
      : [];
  const all = [...COACH_LEXI_DEFAULT_QUICK_ACTIONS, ...scenarioHints];
  const seen = new Set();
  return all
    .map(h => ({
      label: String(h?.label || "").trim(),
      msg: String(h?.msg || "").trim(),
    }))
    .filter(h => {
      const key = `${h.label.toLowerCase()}|${h.msg.toLowerCase()}`;
      if (!h.label || !h.msg || seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .slice(0, 8);
}

function _renderCoachQuickActions(entry = {}) {
  const container = el("coach-quick-actions");
  if (!container) return;
  const actions = _coachLexiQuickActions(entry);
  container.innerHTML = actions.map(action =>
    `<button class="coach-quick-btn ui-btn ui-btn--slate" data-msg="${escapeHTML(action.msg)}">${escapeHTML(action.label)}</button>`
  ).join("");
  container.querySelectorAll(".coach-quick-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
      const msg = btn.dataset.msg || "";
      if (msg) _sendCoachLexiMessage(msg);
    });
  });
}

function _resizeCoachLexiInput() {
  const input = el("coach-lexi-input");
  if (!input) return;
  const MIN_H = 44;
  const MAX_H = 132;
  if (input.offsetParent === null) {
    input.style.height = `${MIN_H}px`;
    return;
  }
  input.style.height = "auto";
  input.style.height = `${Math.max(MIN_H, Math.min(input.scrollHeight, MAX_H))}px`;
}

function _coachLexiContextPrompt() {
  const e = _debriefCoach.entry || {};
  const timeline = Array.isArray(e.timeline) ? e.timeline : [];
  const appliedText = timeline.filter(t => t.status === "applied").slice(0, 10).map(t => t.action || "").filter(Boolean).join("; ");
  const missedText = timeline.filter(t => t.status === "missed").slice(0, 10).map(t => t.action || "").filter(Boolean).join("; ");
  const informationalText = timeline.filter(t => t.status === "informational").slice(0, 10).map(t => t.action || "").filter(Boolean).join("; ");
  const locked = _isConditionLocked(e.impressionChallenge);
  const feedbackLine = locked
    ? "CONDITION LOCK ACTIVE: The learner did not correctly identify the primary clinical impression. Do NOT name, describe, hint at, or discuss the specific condition, diagnosis, pathophysiology, or treatment protocol in any response. You may reference what actions the learner took or missed from the timeline, but do not explain WHY those actions were needed in a way that reveals the condition. If asked directly about the condition, the correct answer, or the treatment: tell the learner the condition reference is locked until they correctly identify the impression on a retry, and encourage them to return to the scene and use the clinical findings to form their impression."
    : `Feedback summary: ${(e.debrief || "").slice(0, 900)}`;
  return [
    "You are Lexi, coaching after an EMS training debrief.",
    "Use a supportive, non-judgmental tone focused on actionable improvement.",
    "Ground every answer in the stored debrief feedback and timeline below. Do not invent missed steps that are not supported there.",
    "Never recommend an action already listed under APPLIED ACTIONS.",
    "Never recommend explicitly requesting ALS if the context says ALS was co-dispatched or already en route.",
    "Do not recommend changing the oxygen device, route, or flow if oxygen delivery is already listed under APPLIED ACTIONS unless the stored debrief explicitly criticized that oxygen choice.",
    "If the learner asks for improvement priorities, choose the highest-impact items from MISSED ACTIONS or explicit debrief criticisms first.",
    `Scenario: ${e.title || "Unknown scenario"}`,
    `Mode: ${e.drillMode ? "Quick Drill" : "Full Scenario"}`,
    `Score: ${e.score ?? "N/A"}/100`,
    feedbackLine,
    appliedText ? `APPLIED ACTIONS: ${appliedText}` : "",
    missedText ? `MISSED ACTIONS: ${missedText}` : "",
    informationalText ? `INFORMATIONAL / GRACE ITEMS: ${informationalText}` : "",
  ].filter(Boolean).join("\n");
}

function _extractSseDataLines(buffer = "") {
  return String(buffer || "")
    .split("\n")
    .map(line => line.trim())
    .filter(line => line.startsWith("data: "))
    .map(line => line.slice(6));
}

async function _sendCoachLexiMessage(message) {
  const text = String(message || "").trim();
  if (!text) return;
  const sessionId = _debriefCoach.entry?.key || state.sessionId;
  if (!sessionId) {
    _coachLexiAppendBot("I need a session context to coach this debrief.");
    return;
  }
  _coachLexiAppendUser(text);
  const typingEl = _coachLexiAppendTyping();

  const historySnapshot = [...(_debriefCoach.lexiHistory || [])];
  _debriefCoach.lexiHistory.push({ role: "user", content: text });
  const contextualMessage = !_debriefCoach.contextPrimed
    ? `${_coachLexiContextPrompt()}\n\nInstruction: Answer only the learner's latest question. Do not repeat the full scenario recap unless specifically asked.\n\nLearner question: ${text}`
    : text;
  _debriefCoach.contextPrimed = true;

  try {
    const res = await authFetch(`${API}/api/lexi`, {
      method: "POST",
      body: JSON.stringify({
        session_id: sessionId,
        message: contextualMessage,
        history: historySnapshot,
        mode: "debrief",
      }),
    });
    if (!res.ok) {
      typingEl.remove();
      _coachLexiAppendBot("I hit a snag fetching that coaching response. Try again.");
      return;
    }
    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "", responseText = "", botEl = null;
    let doneSeen = false;
    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        buffer += decoder.decode();
      } else {
        buffer += decoder.decode(value, { stream: true });
      }
      const lines = buffer.split("\n");
      buffer = done ? "" : lines.pop();
      const dataLines = done ? _extractSseDataLines(lines.join("\n")) : lines.map(line => line.trim()).filter(line => line.startsWith("data: ")).map(line => line.slice(6));
      for (const data of dataLines) {
        if (data === "[DONE]") { doneSeen = true; break; }
        try {
          const parsed = JSON.parse(data);
          if (parsed.text) {
            responseText += parsed.text;
            if (!botEl) { typingEl.remove(); botEl = _coachLexiAppendBot(""); }
            botEl.textContent = responseText;
            const container = el("coach-lexi-messages");
            if (container) container.scrollTop = container.scrollHeight;
          }
        } catch {}
      }
      if (done || doneSeen) break;
    }
    if (!botEl) {
      typingEl.remove();
      botEl = _coachLexiAppendBot(responseText || "I lost that coaching response on the way over. Ask again and I'll try once more.");
    }
    _debriefCoach.lexiHistory.push({ role: "assistant", content: responseText });
  } catch {
    typingEl.remove();
    _coachLexiAppendBot("Connection hiccup. Ask me again and I’ll coach you through it.");
  }
}

function _openDebriefWithLexi(entry, source = "current") {
  if (!entry) return;
  _debriefCoach = {
    source,
    entry,
    pcrSnapshotHtml: source === "current" ? _buildCurrentPcrSnapshotHtml() : _buildHistoryPcrSnapshotHtml(entry),
    lexiHistory: [],
    mobileTab: "feedback",
    contextPrimed: false,
  };
  setText("coach-subtitle", `${entry.title || "Scenario"} · ${entry.drillMode ? "Quick Drill" : "Full Scenario"} · Score ${entry.score ?? "—"}/100`);
  setHTML("coach-notes-content", _debriefCoach.pcrSnapshotHtml);
  setHTML("coach-feedback-content", _buildCoachFeedbackHtml(entry));
  el("coach-lexi-messages").innerHTML = "";
  if (el("coach-lexi-input")) {
    el("coach-lexi-input").value = "";
    el("coach-lexi-input").style.height = "44px";
  }
  _renderCoachQuickActions(entry);
  _coachLexiAppendBot("Nice work completing that run. Ask me any follow-up question and I’ll coach you through improvements.");
  showScreen("debrief-lexi");
  _syncCoachMobileMode();
  requestAnimationFrame(() => _resizeCoachLexiInput());
}

/* ── History page ─────────────────────────────────────────────────── */

async function buildHistoryPage(refresh = true) {
  const container = el("history-list");
  setText("history-student-name", state.firstName || state.studentName || "");
  if (!_historyCache) _readProgressHistoryCache();
  const showLoading = () => {
    if (!container) return;
    container.innerHTML = `<div class="text-center text-gray-500 py-16">
      <div class="text-5xl mb-4">📋</div>
      <p class="text-lg font-semibold">Loading recent calls…</p>
    </div>`;
  };
  const showLoadError = () => {
    if (!container) return;
    container.innerHTML = `<div class="text-center text-red-300 py-16">
      <div class="text-5xl mb-4">⚠️</div>
      <p class="text-lg font-semibold">Could not load scenario history.</p>
      <p class="text-sm mt-1 text-red-200/80">${escapeHTML(_historyLoadError || "Try again in a moment.")}</p>
      <button class="mt-4 text-xs bg-red-700 hover:bg-red-600 text-white px-3 py-1.5 rounded-lg transition-colors" data-history-retry>Retry</button>
    </div>`;
    container.querySelector("[data-history-retry]")?.addEventListener("click", () => {
      _historyLoadError = "";
      buildHistoryPage(true);
    });
  };
  if (_historyLoadError && !loadHistory().length) {
    showLoadError();
    return;
  }
  if ((!_historyCache || (!_historyCacheLoaded && !loadHistory().length)) && container) {
    showLoading();
    if (refresh) {
      _refreshHistoryCache()
        .then(() => buildHistoryPage(false))
        .catch(() => {});
    }
    return;
  }
  const h = loadHistory();

  if (h.length === 0) {
    if (_historyLoadError) {
      showLoadError();
      return;
    }
    if (refresh && !_historyCacheLoaded) {
      showLoading();
      _refreshHistoryCache()
        .then(() => buildHistoryPage(false))
        .catch(() => buildHistoryPage(false));
      return;
    }
    container.innerHTML = `<div class="text-center text-gray-500 py-16">
      <div class="text-5xl mb-4">📋</div>
      <p class="text-lg font-semibold">No completed scenarios yet.</p>
      <p class="text-sm mt-1">Finish a scenario to see your history here.</p>
    </div>`;
    if (refresh) {
      _refreshHistoryCache()
        .then(() => buildHistoryPage(false))
        .catch(() => {});
    }
    return;
  }

  container.innerHTML = h.map(entry => {
    const date = new Date(entry.date);
    const dateStr = date.toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric" });
    const timeStr = date.toLocaleTimeString(undefined, { hour: "numeric", minute: "2-digit" });

    const score = entry.assessmentScore ?? entry.score ?? null;
    const denom = _assessmentMaxFromEntry(entry);
    const pct = _assessmentPctFromScore(score, denom);
    const statusMeta = _assessmentStatusMeta(pct, {
      assessmentOnly: entry.narrativeSkipped,
      criticalFailure: entry.criticalFailure,
    });
    const scoreClass = statusMeta.cls;
    const gradeLabel = statusMeta.label;

    const badgeChips = (entry.newBadges || []).map(id => {
      const b = BADGE_DEFS.find(d => d.id === id);
      return b ? `<span class="badge-chip text-xs">${b.icon} ${b.name}</span>` : "";
    }).join("");

    const xpNote = entry.xpEarned > 0
      ? `<span class="text-yellow-400 text-xs font-semibold">+${entry.xpEarned} XP</span>`
      : `<span class="text-gray-600 text-xs">No XP earned</span>`;

    const levelLabel  = LEVEL_DISPLAY[entry.providerLevel]  || entry.providerLevel  || "";
    const mcaLabel    = MCA_DISPLAY[entry.mca]              || entry.mca            || "";
    const agencyLabel = entry.agencyName || "";
    const contextParts = [agencyLabel, mcaLabel, levelLabel].filter(Boolean);
    const contextLine = contextParts.length
      ? `<div class="text-xs text-gray-500 mt-0.5">${contextParts.map(escapeHTML).join(" · ")}</div>`
      : "";

    const drillTag = entry.drillMode
      ? `<span class="ml-1.5 text-xs bg-yellow-900/60 border border-yellow-700/50 text-yellow-400 px-1.5 py-0.5 rounded font-semibold">⚡ Drill</span>`
      : "";
    const retakeButton = state.scormEnabled
      ? ""
      : `<button class="btn-history-retake text-xs bg-red-700 hover:bg-red-600 text-white px-3 py-1.5 rounded-lg transition-colors" data-scenario="${entry.scenarioId}">
          🔄 Retake
        </button>`;

    return `<div class="history-card">
      <div class="history-card-header">
        <div>
          <div class="history-card-title">${escapeHTML(entry.title)}${drillTag}</div>
          <div class="history-card-meta">${dateStr} · ${timeStr} · ${entry.elapsedMin ?? "?"}m on scene</div>
          ${contextLine}
        </div>
        <div class="text-right">
          <div class="text-2xl font-bold font-mono ${scoreClass}">${score !== null ? score + "/" + denom : "—"}</div>
          <div class="text-xs ${scoreClass}">${gradeLabel}</div>
        </div>
      </div>
      <div class="history-card-stats">
        ${xpNote}
        ${entry.treatsEarned > 0 ? `<span class="text-amber-400 text-xs font-semibold">+${entry.treatsEarned} 🦴</span>` : ""}
        ${badgeChips}
      </div>
      <div class="history-card-actions">
        <button class="btn-history-debrief text-xs bg-gray-700 hover:bg-gray-600 text-white px-3 py-1.5 rounded-lg transition-colors" data-key="${escapeHTML(String(entry.key))}">
          📄 View Debrief
        </button>
        ${retakeButton}
      </div>
    </div>`;
  }).join("");

  // Retake buttons wired per-render (safe: no closure over stale data)
  container.querySelectorAll(".btn-history-retake").forEach(btn => {
    btn.addEventListener("click", () => {
      resetSessionState();
      startScenario(btn.dataset.scenario);
    });
  });
  // Debrief buttons use delegated listener — see _initHistoryDelegation()
  if (refresh) {
    _refreshHistoryCache()
      .then(() => buildHistoryPage(false))
      .catch(() => {});
  }
}

function _scenarioJurisdictionWarning(scenario) {
  const jurisdiction = String(
    scenario?.jurisdiction ||
    scenario?.clinical_context?.jurisdiction ||
    ""
  ).trim();
  if (!jurisdiction || /^national$/i.test(jurisdiction)) return null;
  const activeMca = String(state.mca || "").trim();
  const normJur = jurisdiction.toLowerCase();
  const normMca = activeMca.toLowerCase();
  const scenarioBase = normJur.startsWith("mi") || normJur === "pfd" ? "MI"
    : normJur.startsWith("nasemso") ? "NASEMSO"
    : jurisdiction;
  const activeBase = normMca.startsWith("mi") ? "MI"
    : normMca.startsWith("nasemso") ? "NASEMSO"
    : activeMca;
  if (!scenarioBase || !activeBase || scenarioBase === activeBase) return null;
  return {
    jurisdiction,
    activeMca: activeMca || "not set",
    message: `This scenario is tagged for ${jurisdiction}, but your active profile/MCA appears to be ${activeMca || "not set"}. You can continue for practice, but treat protocol-specific details as potentially mismatched.`,
  };
}

function _confirmJurisdictionWarning(warning) {
  if (!warning) return Promise.resolve(true);
  const modal = el("modal-jurisdiction-warning");
  const body = el("jurisdiction-warning-body");
  const btnContinue = el("btn-jurisdiction-warning-continue");
  const btnCancel = el("btn-jurisdiction-warning-cancel");
  const btnClose = el("btn-jurisdiction-warning-close");
  if (!modal || !btnContinue || !btnCancel) {
    return Promise.resolve(window.confirm(warning.message));
  }
  if (body) body.textContent = warning.message;
  show("modal-jurisdiction-warning");
  return new Promise(resolve => {
    const cleanup = (value) => {
      hide("modal-jurisdiction-warning");
      btnContinue.removeEventListener("click", onContinue);
      btnCancel.removeEventListener("click", onCancel);
      btnClose?.removeEventListener("click", onCancel);
      resolve(value);
    };
    const onContinue = () => cleanup(true);
    const onCancel = () => cleanup(false);
    btnContinue.addEventListener("click", onContinue);
    btnCancel.addEventListener("click", onCancel);
    btnClose?.addEventListener("click", onCancel);
  });
}

async function startScenario(scenarioId) {
  return startScenarioWithOptions(scenarioId);
}

async function startScenarioWithOptions(scenarioId, options = {}) {
  const t0 = performance.now();
  const _lap = (label) => console.log(`[startScenario] ${label}: ${(performance.now() - t0).toFixed(0)}ms`);
  const startDrill = Boolean(options.startDrill);
  const drillSource = options.drillSource || null;
  try {
    let scenarioData = null;
    if (_scenarioPreviewDataCache?.scenarioId === scenarioId) {
      scenarioData = _scenarioPreviewDataCache.data;
      _scenarioPreviewDataCache = null;
      _lap("scenario data from prefetch cache");
    } else if (_scenarioPreviewDataPromise?.scenarioId === scenarioId) {
      _lap("awaiting in-flight scenario prefetch");
      scenarioData = await _scenarioPreviewDataPromise.promise;
      _lap("in-flight scenario prefetch complete");
      _scenarioPreviewDataCache = null;
      if (!scenarioData) {
        showToast("Could not load this scenario. Try again.", "error");
        return false;
      }
    } else {
      _lap("prefetch cache miss — fetching scenario");
      const scenRes = await authFetch(`${API}/api/scenarios/${scenarioId}`);
      _lap("scenario GET complete");
      if (!scenRes.ok) {
        showToast("Could not load this scenario. Try again.", "error");
        return false;
      }
      scenarioData = _prepareScenarioDataForRuntime(await scenRes.json());
      _lap("scenario JSON parsed");
    }
    _preloadScenarioImages(scenarioData);
    const warning = _scenarioJurisdictionWarning(scenarioData);
    if (warning && !(await _confirmJurisdictionWarning(warning))) return false;

    _lap("posting session");
    const res = await authFetch(`${API}/api/sessions`, {
      method: "POST",
      body: JSON.stringify({
        scenario_id: scenarioId,
        provider_level: state.providerLevel,
        mca: state.mca,
        start_drill: startDrill,
        ...(drillSource ? { drill_source: drillSource } : {}),
      }),
    });
    _lap("session POST complete");

    if (!res.ok) {
      if (res.status === 401) {
        if (_handleScormAuthExpired()) return false;
        _clearAuth(); switchAuthTab("login");
        showScreen("login"); showError("login-error", "Session expired — please sign in again."); return false;
      }
      showToast("🐾 Lexi couldn't load this scenario — check your connection and try again.", "error"); return false;
    }

    const data = await res.json();
    state.sessionId  = data.session_id;
    state.startTime  = new Date(_toEpochMs(data.started_at, Date.now()));
    state.simTimersStarted = false;
    state.scenarioId = scenarioId;
    state.scenarioData = _prepareScenarioDataForRuntime(scenarioData);
    state.drillMode = startDrill;
    state.dispatchQuickDrillOnly = false;
    _sessionActiveTimer.start();

    _lap("calling showDispatch");
    showDispatch();
    _lap("done");
    return true;
  } catch (err) {
    console.error("[startScenario] error:", err);
    showToast("Connection error. Please try again.", "error");
    return false;
  }
}

