function showDispatch() {
  const d = state.scenarioData.dispatch;
  setText("dispatch-unit", d.unit);
  setText("dispatch-priority", d.priority);
  setText("dispatch-time", `Time of call: ${d.time}`);
  setText("dispatch-text", d.text);
  setText("dispatch-location", d.cross_streets || "");
  setText("dispatch-eta", `ETA ${d.response_time_minutes} min`);

  const modeNote = el("dispatch-mode-note");
  if (modeNote) {
    if (state.isRandomCall) {
      modeNote.textContent = "🚨 Random Call — replaying a completed call. Full XP rules apply (capped daily).";
      modeNote.classList.remove("hidden");
    } else {
      modeNote.classList.add("hidden");
    }
  }

  showScreen("dispatch");
}

el("btn-respond").addEventListener("click", () => {
  // Initialize (and iOS-unlock) AudioContext on the first user gesture
  window._immAudio?.init();
  startSim();
});

el("btn-dispatch-back")?.addEventListener("click", () => {
  state.drillMode = false;
  state.dispatchQuickDrillOnly = false;
  state.isRandomCall = false;
  state.sessionId = null;
  const lastScenarioId = state.scenarioId;
  const scenarioCategory = state.scenarioData?.category
    || state.allScenarios.find(s => s.id === lastScenarioId)?.category
    || "";
  state.scenarioId = null;
  state.scenarioData = null;
  if (scenarioCategory) {
    showCategoryScreen(scenarioCategory);
  } else {
    buildMenu();
    showScreen("menu");
  }
});


/* ═══════════════════════════════════════════════════════════════════
   SIMULATION SCREEN
   ═══════════════════════════════════════════════════════════════════ */

function _scenarioAgeDisplay(scenario = state.scenarioData) {
  const patient = scenario?.patient || {};
  if (patient.age_display) return patient.age_display;
  const months = Number(patient.age_months);
  const days = Number(patient.age_days);
  if (Number.isFinite(days) && days >= 0 && days < 31) {
    return `${days}-day-old ${patient.sex || "patient"}`;
  }
  if (Number.isFinite(months) && months > 0 && months < 24) {
    return `${months}-month-old ${patient.sex || "patient"}`;
  }
  if (Number.isFinite(months) && months >= 24) {
    const years = Math.floor(months / 12);
    return `${years}-year-old ${patient.sex || "patient"}`;
  }
  if (Number(patient.age) > 0 && patient.sex) return `${patient.age}-year-old ${patient.sex}`;
  return patient.sex || "Patient";
}

function _scenarioPatientDobDisplay(scenario = state.scenarioData, options = {}) {
  const { includeAge = false } = options;
  const dob = _scenarioPatientDobDate(scenario);
  const ageText = includeAge ? _scenarioPatientAgeParenthetical(scenario) : "";
  if (!dob) return "";
  const dateText = dob.toLocaleDateString([], { month: "short", day: "numeric", year: "numeric" });
  return ageText ? `${dateText} (${ageText})` : dateText;
}

function _scenarioPatientAgeParenthetical(scenario = state.scenarioData) {
  const patient = scenario?.patient || {};
  const days = Number(patient.age_days);
  if (Number.isFinite(days) && days >= 0 && days < 31) {
    return `${days} day${days === 1 ? "" : "s"}`;
  }
  const months = Number(patient.age_months);
  if (Number.isFinite(months) && months >= 0) {
    if (months < 12) return `${months} month${months === 1 ? "" : "s"}`;
    const years = Math.floor(months / 12);
    const remMonths = months % 12;
    const parts = [`${years} year${years === 1 ? "" : "s"}`];
    if (remMonths) parts.push(`${remMonths} month${remMonths === 1 ? "" : "s"}`);
    return parts.join(" ");
  }
  const years = Number(patient.age);
  if (Number.isFinite(years) && years >= 0) return `${years} year${years === 1 ? "" : "s"}`;
  return "";
}

function _scenarioPatientAgeYears(scenario = state.scenarioData) {
  const patient = scenario?.patient || {};
  const directYears = Number(patient.age);
  if (Number.isFinite(directYears) && directYears >= 0) return directYears;
  const displayMatch = String(patient.age_display || "").match(/\b(\d+(?:\.\d+)?)\s*-\s*year-old\b/i)
    || String(patient.age_display || "").match(/\b(\d+(?:\.\d+)?)\s+years?\s+old\b/i);
  if (displayMatch) {
    const displayYears = Number(displayMatch[1]);
    if (Number.isFinite(displayYears) && displayYears >= 0) return displayYears;
  }
  return NaN;
}

function _scenarioPatientDobDate(scenario = state.scenarioData) {
  const patient = scenario?.patient || {};
  const authoredDob = String(patient.dob || patient.dob_display || "").trim();
  if (authoredDob) {
    const parsed = Date.parse(authoredDob);
    if (Number.isFinite(parsed)) return new Date(parsed);
  }
  const relativeDob = String(patient.dob_relative || "").trim().toLowerCase();
  const days = Number(patient.age_days);
  const months = Number(patient.age_months);
  const years = _scenarioPatientAgeYears(scenario);
  const dob = new Date();
  const relativeParsed = _relativeDobDateFromText(relativeDob);
  if (relativeParsed) return relativeParsed;
  if (relativeDob === "today") {
    return dob;
  }
  const dobMonthDay = String(patient.dob_month_day || "").trim();
  if (dobMonthDay) {
    const match = dobMonthDay.match(/^([A-Za-z]+\.?)\s+(\d{1,2})$/);
    if (match) {
      const derived = _derivePatientDobFromMonthDay(match[1], Number(match[2]), { fallback: false });
      if (derived) return derived;
    }
  }
  if (Number.isFinite(days) && days >= 0) {
    dob.setDate(dob.getDate() - days);
    return dob;
  }
  if (Number.isFinite(months) && months >= 0) {
    dob.setMonth(dob.getMonth() - months);
    return dob;
  }
  if (Number.isFinite(years) && years >= 0) {
    dob.setFullYear(dob.getFullYear() - years);
    return dob;
  }
  return null;
}

function _relativeDobDateFromText(value = "") {
  const text = String(value || "").toLowerCase();
  const now = new Date();
  const monthMatch = text.match(/\b(?:about\s+|approximately\s+|approx\.?\s*)?(\d+)\s*months?\b/);
  if (monthMatch) {
    const months = Number(monthMatch[1]);
    if (Number.isFinite(months) && months >= 0) {
      const dob = new Date(now);
      dob.setMonth(dob.getMonth() - months);
      return dob;
    }
  }
  const dayMatch = text.match(/\b(?:about\s+|approximately\s+|approx\.?\s*)?(\d+)\s*days?\b/);
  if (dayMatch) {
    const days = Number(dayMatch[1]);
    if (Number.isFinite(days) && days >= 0) {
      const dob = new Date(now);
      dob.setDate(dob.getDate() - days);
      return dob;
    }
  }
  return null;
}

function _scenarioConcreteDobDisplay(scenario = state.scenarioData) {
  const dob = _scenarioPatientDobDate(scenario);
  if (!dob) return "";
  return dob.toLocaleDateString([], { month: "short", day: "numeric", year: "numeric" });
}

function _replacePatientDobTagsWithConcreteDate(scenario = {}, dobText = "") {
  if (!scenario || !dobText || !scenario.history_response_map || typeof scenario.history_response_map !== "object") return;
  Object.values(scenario.history_response_map).forEach(entry => {
    if (!entry || typeof entry !== "object") return;
    const rewrite = tag => String(tag || "").replace(
      /\[\[\s*HISTORY:\s*Patient\s+Date\s+of\s+Birth\s*=\s*[^\]]+\]\]/i,
      `[[HISTORY: Patient Date of Birth=${dobText}]]`
    );
    if (typeof entry.tag === "string") entry.tag = rewrite(entry.tag);
    if (Array.isArray(entry.tags)) entry.tags = entry.tags.map(rewrite);
  });
}

function _prepareScenarioDataForRuntime(scenario) {
  if (!scenario || typeof scenario !== "object") return scenario;
  const patient = scenario.patient || {};
  const dobText = _scenarioConcreteDobDisplay(scenario);
  if (dobText) {
    patient.dob = dobText;
    patient.dob_display = dobText;
    scenario.patient = patient;
    _replacePatientDobTagsWithConcreteDate(scenario, dobText);
  }
  return scenario;
}

function _pcrDemographicsDeferred() {
  return Boolean(state.scenarioData?.patient?.pcr_demographics_deferred);
}

function _renderPcrHeader() {
  const s = state.scenarioData || {};
  const pt = s.patient || {};
  const h = state.pcrHeader || {};
  if (!_pcrDemographicsDeferred()) {
    setText("pcr-patient-id", `${pt.name || ""} · ${_scenarioAgeDisplay(s)} · ${pt.weight_display || ""}`.replace(/\s+·\s+$/g, ""));
    setText("pcr-complaint", pt.chief_complaint || "");
    return;
  }

  const idParts = [];
  if (h.name) idParts.unshift(h.name);
  if (h.age) idParts.push(h.age);
  if (h.dob) idParts.push(`DOB ${h.dob}`);
  if (h.weight) idParts.push(h.weight);
  setText("pcr-patient-id", idParts.filter(Boolean).join(" · ") || "Patient");

  const complaintParts = [];
  if (h.chiefComplaint) complaintParts.push(`Chief complaint: ${h.chiefComplaint}`);
  if (h.primaryImpression) complaintParts.push(`Primary impression: ${h.primaryImpression}`);
  setText("pcr-complaint", complaintParts.join(" · "));
}

function _scenarioHeaderTitle() {
  const s = state.scenarioData || {};
  if (!_pcrDemographicsDeferred()) return s.display_title || s.title || "Scenario";
  if (s.category_display) return s.category_display;
  const category = String(s.category || "");
  if (category.includes("trauma")) return "Pediatric Trauma";
  if (category.includes("medical")) return "Pediatric Medical";
  return "Scenario";
}

function _scenarioHeaderSubtitle() {
  const s = state.scenarioData || {};
  if (!_pcrDemographicsDeferred()) return s.subtitle || "";
  return s.dispatch?.text || "";
}

function _deferredPatientInfoParts(options = {}) {
  const { includeDob = true, includeWeight = true, fallback = "Patient" } = options;
  const s = state.scenarioData || {};
  const pt = s.patient || {};
  if (!_pcrDemographicsDeferred()) {
    return [pt.name || fallback, _scenarioAgeDisplay(s), includeWeight ? pt.weight_display : ""].filter(Boolean);
  }

  const h = state.pcrHeader || {};
  const parts = [];
  if (h.name) parts.push(h.name);
  if (h.age) parts.push(h.age);
  if (includeDob && h.dob) parts.push(`DOB ${h.dob}`);
  if (includeWeight && h.weight) parts.push(h.weight);
  if (!parts.length && fallback) parts.push(fallback);
  return parts.filter(Boolean);
}

function _normalizePcrHeaderValue(key = "", value = "") {
  const k = String(key || "").toLowerCase();
  const v = String(value || "").trim();
  if (!/date\s+of\s+birth|dob|birth\s*date/.test(k)) return v;
  const relativeDob = _relativeDobDateFromText(v);
  if (relativeDob) {
    return relativeDob.toLocaleDateString([], { month: "short", day: "numeric", year: "numeric" });
  }
  if (/today|actual date|current date|\b\d+\s*(?:years?|months?|days?)\b/i.test(v)) {
    return _scenarioPatientDobDisplay() || v;
  }
  const monthDayYearMatch = v.match(/^([A-Za-z]+\.?)\s+(\d{1,2})(?:,?\s+(\d{4}))?$/);
  if (monthDayYearMatch) {
    const monthName = monthDayYearMatch[1];
    const day = Number(monthDayYearMatch[2]);
    const derivedDob = _derivePatientDobFromMonthDay(monthName, day);
    if (derivedDob) {
      const suppliedYear = monthDayYearMatch[3] ? Number(monthDayYearMatch[3]) : null;
      const currentYear = new Date().getFullYear();
      const patientAge = Number(state.scenarioData?.patient?.age);
      if (suppliedYear && suppliedYear !== currentYear && Number.isFinite(patientAge) && patientAge > 0) {
        return v;
      }
      return derivedDob.toLocaleDateString([], { month: "short", day: "numeric", year: "numeric" });
    }
  }
  return v;
}

function _derivePatientDobFromMonthDay(monthName = "", day = NaN, options = {}) {
  const fallback = options.fallback !== false;
  const patientAge = _scenarioPatientAgeYears();
  // patientAge === 0 means under 1 year old; birth year cannot be reliably derived from
  // month/day alone (2026 - 0 = 2026 = today's year), so always fall back to age_months/age_days.
  if (!Number.isFinite(patientAge) || patientAge < 0 || patientAge === 0 || !Number.isFinite(day)) {
    return fallback ? _scenarioPatientDobDate() : null;
  }
  const parsed = Date.parse(`${monthName} ${day}, 2000`);
  if (!Number.isFinite(parsed)) return fallback ? _scenarioPatientDobDate() : null;
  const month = new Date(parsed).getMonth();
  const now = new Date();
  const birthdayThisYear = new Date(now.getFullYear(), month, day);
  const birthYear = now.getFullYear() - patientAge - (birthdayThisYear > now ? 1 : 0);
  return new Date(birthYear, month, day);
}

function _pcrHeaderKeyIsFamilyOrBystander(key = "") {
  return /\b(?:family|bystander|caregiver|parent|mother|mom|father|dad|guardian|witness|caller|reporting\s+party|sarah|mike)\b/i.test(String(key || ""));
}

function _pcrHeaderKeyIsPatientScoped(key = "") {
  const k = String(key || "");
  if (_pcrHeaderKeyIsFamilyOrBystander(k)) return false;
  return /\b(?:patient|pt|infant|child)\b/i.test(k);
}

function _pcrHeaderValueMatchesPatientName(value = "") {
  const expected = String(state.scenarioData?.patient?.name || "").trim().toLowerCase();
  return Boolean(expected && String(value || "").trim().toLowerCase() === expected);
}

function _pcrHeaderValueMatchesPatientWeight(value = "") {
  const pt = state.scenarioData?.patient || {};
  const v = String(value || "").toLowerCase();
  const kg = Number(pt.weight_kg);
  if (Number.isFinite(kg) && new RegExp(`\\b${kg}\\s*kg\\b`, "i").test(v)) return true;
  const display = String(pt.weight_display || "").toLowerCase();
  const lbMatch = display.match(/\b(\d+(?:\.\d+)?)\s*(?:lb|lbs|pound|pounds)\b/i);
  if (lbMatch && new RegExp(`\\b${lbMatch[1]}\\s*(?:lb|lbs|pound|pounds)\\b`, "i").test(v)) {
    return true;
  }
  const colorMatch = display.match(/\bbroselow\s+([a-z]+)/i);
  if (colorMatch) {
    const color = colorMatch[1].replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    if (new RegExp(`\\bbroselow\\s+${color}\\b`, "i").test(v)) return true;
  }
  return false;
}

function _capturePcrHeaderFinding(key = "", value = "") {
  if (!_pcrDemographicsDeferred()) return false;
  state.pcrHeader = state.pcrHeader || { name: null, age: null, dob: null, weight: null, chiefComplaint: null, primaryImpression: null };
  const k = String(key || "").trim();
  const v = _normalizePcrHeaderValue(k, value);
  if (!v) return false;
  let captured = false;
  const patientScoped = _pcrHeaderKeyIsPatientScoped(k);
  if (/^(?:patient\s+|pt\s+)?name$/i.test(k) && patientScoped && _pcrHeaderValueMatchesPatientName(v)) {
    state.pcrHeader.name = v;
    _markSceneNameKnown(v);
    _postFinding("history", "Patient Name", v, "ai_roleplay_tag");
    captured = true;
  }
  if (/^(?:patient\s+|pt\s+)?age$/i.test(k) && patientScoped && _lastUserMessageRequestsPatientAge()) {
    state.pcrHeader.age = v;
    captured = true;
  }
  if (/(?:date\s+of\s+birth|dob|birth\s*date)/i.test(k) && patientScoped && _lastUserMessageRequestsPatientDob()) {
    state.pcrHeader.dob = v;
    captured = true;
  }
  if (/weight|broselow|broslow/i.test(k) && patientScoped && _lastUserMessageRequestsPatientWeight() && _pcrHeaderValueMatchesPatientWeight(v)) {
    state.pcrHeader.weight = v;
    captured = true;
  }
  if (/chief\s+complaint|chief\s+concern|complaint/i.test(k) && patientScoped) {
    state.pcrHeader.chiefComplaint = v;
    captured = true;
  }
  _renderPcrHeader();
  return captured;
}

function _pcrFindingShouldRenderOnlyInHeader(key = "") {
  const k = String(key || "").trim();
  return /^(?:patient\s+|pt\s+)?name$/i.test(k)
    || /^(?:patient\s+|pt\s+)?(?:age|date\s+of\s+birth|dob|birth\s*date)$/i.test(k)
    || /^(?:patient\s+|pt\s+)?(?:chief\s+complaint|chief\s+concern|complaint)$/i.test(k);
}

function _pcrHeaderOnlyFieldRequestedForCurrentMessage(key = "") {
  const k = String(key || "").trim();
  if (/^(?:patient\s+|pt\s+)?name$/i.test(k)) return _lastUserMessageRequestsPatientName();
  if (/^(?:patient\s+|pt\s+)?age$/i.test(k)) return _lastUserMessageRequestsPatientAge();
  if (/(?:date\s+of\s+birth|dob|birth\s*date)/i.test(k)) return _lastUserMessageRequestsPatientDob();
  if (/weight|broselow|broslow/i.test(k)) return _lastUserMessageRequestsPatientWeight();
  return true;
}

function _pcrDataKeyForDisplayKey(key = "") {
  return String(key || "").toLowerCase().replace(/[\s/]+/g, "_");
}

let _pcrItemInsertSeq = 0;

function _pcrCanonicalMnemonicRank(key = "") {
  const k = String(key || "")
    .toLowerCase()
    .replace(/[*_:]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (!k) return null;

  const opqrst = [
    [/^(?:seizure\s+)?onset\b|\bonset\b/, 10],
    [/provocation|palliation|provokes?|palliates?|better|worse/, 20],
    [/\bquality\b|character|description/, 30],
    [/region|radiation|radiates?/, 40],
    [/severity/, 50],
    [/^time\b|time\s*\/\s*course|\bcourse\b|duration|seizure\s+duration|seizure\s+status/, 60],
  ];
  for (const [pattern, rank] of opqrst) {
    if (pattern.test(k)) return rank;
  }

  const sample = [
    [/signs?\s*(?:and|&)?\s*symptoms?|associated\s+symptoms?/, 110],
    [/allerg/, 120],
    [/med(?:ication)?s?\b|medications?/, 130],
    [/pmh|past\s*(?:medical\s*)?history|pertinent\s+history|medical\s+problems?/, 140],
    [/last\s+oral|last\s+intake|oral\s+intake|loi|food|formula|ate|drink/, 150],
    [/^events?\b|events?\s+leading|what\s+happened|mechanism/, 160],
  ];
  for (const [pattern, rank] of sample) {
    if (pattern.test(k)) return rank;
  }
  return null;
}

function _pcrCanonicalHistoryLabel(key = "") {
  const k = String(key || "")
    .toLowerCase()
    .replace(/[*_:]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (!k) return { label: key, canonical: false };

  const aliases = [
    [/^(?:seizure\s+)?onset\b|\bonset\b/, "Onset"],
    [/provocation|palliation|provokes?|palliates?|better|worse/, "Provocation"],
    [/\bquality\b|character|description/, "Quality"],
    [/region|radiation|radiates?/, "Radiation"],
    [/severity/, "Severity"],
    [/^time\b|time\s*\/\s*course|\bcourse\b|duration|seizure\s+duration|seizure\s+status/, "Time"],
    [/signs?\s*(?:and|&)?\s*symptoms?|associated\s+symptoms?/, "Signs and Symptoms"],
    [/allerg/, "Allergies"],
    [/med(?:ication)?s?\b|medications?/, "Medications"],
    [/pmh|past\s*(?:medical\s*)?history|pertinent\s+history|medical\s+problems?/, "PMH"],
    [/last\s+oral|last\s+intake|oral\s+intake|loi|food|formula|ate|drink/, "LOI"],
    [/^events?\b|events?\s+leading|what\s+happened|mechanism/, "Events"],
  ];
  for (const [pattern, label] of aliases) {
    if (pattern.test(k)) return { label, canonical: String(key || "").trim() === label };
  }
  return { label: key, canonical: false };
}

function _sortPcrMnemonicItems(containerId = "") {
  const container = el(containerId);
  if (!container) return;
  const items = Array.from(container.querySelectorAll(":scope > .pcr-item"));
  if (items.length < 2) return;
  items.forEach((item) => {
    if (!item.dataset.pcrInsertSeq) {
      _pcrItemInsertSeq += 1;
      item.dataset.pcrInsertSeq = String(_pcrItemInsertSeq);
    }
  });
  items
    .sort((a, b) => {
      const aLabel = a.querySelector(".pcr-item-key")?.textContent?.replace(/:\s*$/, "") || a.dataset.key || "";
      const bLabel = b.querySelector(".pcr-item-key")?.textContent?.replace(/:\s*$/, "") || b.dataset.key || "";
      const aRank = _pcrCanonicalMnemonicRank(aLabel);
      const bRank = _pcrCanonicalMnemonicRank(bLabel);
      const aSort = aRank ?? 1000;
      const bSort = bRank ?? 1000;
      if (aSort !== bSort) return aSort - bSort;
      return Number(a.dataset.pcrInsertSeq || 0) - Number(b.dataset.pcrInsertSeq || 0);
    })
    .forEach(item => container.appendChild(item));
}

function _removePcrHeaderOnlyRows(containerId, key = "") {
  const container = el(containerId);
  if (!container) return;
  const dkey = _pcrDataKeyForDisplayKey(key);
  container.querySelectorAll(".pcr-item").forEach((item) => {
    const itemKey = item.dataset?.key || "";
    const label = item.querySelector(".pcr-item-key")?.textContent || "";
    const labelKey = _pcrDataKeyForDisplayKey(label.replace(/:\s*$/, ""));
    if (itemKey === dkey || labelKey === dkey) item.remove();
  });
  if (!container.querySelector(".pcr-item")) show(`${containerId}-empty`);
}

function _capturePcrPrimaryImpression(value = "") {
  if (!_pcrDemographicsDeferred()) return;
  const clean = String(value || "").trim();
  if (!clean || clean === "__skipped__") return;
  state.pcrHeader = state.pcrHeader || { name: null, age: null, dob: null, weight: null, chiefComplaint: null, primaryImpression: null };
  state.pcrHeader.primaryImpression = clean;
  _renderPcrHeader();
}

function _sceneRosterCandidateKey(name = "") {
  return _normalizeSpeakerKey(name);
}

function _sceneRosterRoleDisplay(role = "", relation = "") {
  const label = _roleLabelFromActor(role, relation) || String(relation || role || "").trim();
  if (!label) return "";
  if (label === "mom") return "mother";
  if (label === "dad") return "father";
  return label;
}

function _personaSceneRoleDisplay(persona = {}) {
  const relation = persona?.relation || persona?.relationship || "";
  const direct = _sceneRosterRoleDisplay(persona?.role, relation);
  if (direct && direct !== "bystander") return direct;
  const aliasText = Array.isArray(persona?.aliases) ? persona.aliases.join(" ") : "";
  const combined = `${persona?.name || ""} ${persona?.description || ""} ${aliasText}`.toLowerCase();
  if (/\bteacher|school aide|school staff|aide\b/.test(combined)) return "teacher";
  if (/\bclassmate|friend|student witness\b/.test(combined)) return "classmate";
  if (/\bnurse\b/.test(combined)) return "nurse";
  if (/\bwitness\b/.test(combined)) return "witness";
  if (direct) return direct;
  if (String(persona?.role || "").toLowerCase().includes("bystander")) return "bystander";
  return "";
}

function _sceneRosterShouldExclude(name = "", role = "", relation = "") {
  const key = _sceneRosterCandidateKey(name);
  const label = _roleLabelFromActor(role, relation);
  return !key || label === "als" || label === "ed physician";
}

function _sceneRosterRoleRank(role = "") {
  const r = String(role || "").toLowerCase();
  if (r === "partner") return 0;
  if (r === "patient") return 1;
  if (/\b(?:mom|mother|dad|father|parent|caregiver|guardian|family)\b/.test(r)) return 2;
  return 3;
}

function _sceneRosterCandidates(s = state.scenarioData || {}) {
  const candidates = [];
  const seen = new Set();
  let order = 0;
  const add = (name, role = "", relation = "") => {
    const cleanName = String(name || "").trim();
    if (!cleanName || _sceneRosterShouldExclude(cleanName, role, relation)) return;
    const key = _sceneRosterCandidateKey(cleanName);
    if (!key || seen.has(key)) return;
    const displayRole = _sceneRosterRoleDisplay(role, relation);
    seen.add(key);
    candidates.push({
      key,
      name: cleanName,
      role: displayRole,
      _order: order++,
    });
  };

  if (s.patient?.name) add(s.patient.name, "patient", "patient");

  const personas = s.personas && typeof s.personas === "object" ? Object.values(s.personas) : [];
  personas.forEach(persona => {
    if (!persona?.name) return;
    add(persona.name, persona.role, persona.relation || persona.relationship || _personaSceneRoleDisplay(persona));
  });

  if (Array.isArray(s.scene?.bystanders)) {
    s.scene.bystanders.forEach(bystander => {
      add(bystander?.name, "family", bystander?.relation);
    });
  }

  return candidates.sort((a, b) => {
    const rankDelta = _sceneRosterRoleRank(a.role) - _sceneRosterRoleRank(b.role);
    if (rankDelta) return rankDelta;
    return a._order - b._order;
  });
}

function _orderedKnownSceneNames() {
  if (!(state._knownSceneNames instanceof Map) || state._knownSceneNames.size === 0) return [];
  const known = state._knownSceneNames;
  const ordered = _sceneRosterCandidates().filter(candidate => known.has(candidate.key));
  const orderedKeys = new Set(ordered.map(candidate => candidate.key));
  known.forEach((value, key) => {
    if (!orderedKeys.has(key)) ordered.push(value);
  });
  return ordered;
}

function _seedKnownScenePartners() {
  if (!(state._knownSceneNames instanceof Map)) state._knownSceneNames = new Map();
  _sceneRosterCandidates().forEach(candidate => {
    if (candidate.role === "partner") state._knownSceneNames.set(candidate.key, candidate);
  });
}

function _renderChatOnSceneRoster() {
  const container = el("chat-on-scene-roster");
  if (!container) return;
  const candidates = _sceneRosterCandidates();
  if (!candidates.length) {
    container.innerHTML = `
      <div class="sim-on-scene-roster__head">
        <span class="sim-on-scene-roster__label">On Scene</span>
      </div>
      <div class="sim-on-scene-roster__empty">Scene contacts appear here.</div>`;
    setTimeout(_syncSimMobileOffsets, 0);
    return;
  }
  const known = state._knownSceneNames instanceof Map ? state._knownSceneNames : new Map();

  container.innerHTML = `
    <div class="sim-on-scene-roster__head">
      <span class="sim-on-scene-roster__label">On Scene</span>
    </div>
    <div class="sim-on-scene-roster__list">
      ${candidates.map(person => {
        const nameKnown = person.role === "partner" || known.has(person.key);
        const primary = nameKnown ? person.name : (person.role || "on scene");
        const secondary = nameKnown && person.role && person.role !== primary ? person.role : "";
        return `
        <span class="sim-on-scene-roster__chip${person.role === "partner" ? " sim-on-scene-roster__chip--partner" : ""}${nameKnown ? "" : " sim-on-scene-roster__chip--placeholder"}">
          <span>${escapeHTML(primary)}</span>
          ${secondary ? `<span class="sim-on-scene-roster__role">${escapeHTML(secondary)}</span>` : ""}
        </span>`;
      }).join("")}
    </div>`;
  setTimeout(_syncSimMobileOffsets, 0);
}

function _markSceneNameKnown(name = "") {
  const key = _sceneRosterCandidateKey(name);
  if (!key || key === "alex") return false;
  const candidate = _sceneRosterCandidates().find(person => person.key === key);
  if (!candidate) return false;
  if (!(state._knownSceneNames instanceof Map)) state._knownSceneNames = new Map();
  const existed = state._knownSceneNames.has(key);
  state._knownSceneNames.set(key, candidate);
  if (candidate.role === "patient" && _pcrDemographicsDeferred() && _pcrHeaderValueMatchesPatientName(candidate.name)) {
    state.pcrHeader = state.pcrHeader || { name: null, age: null, dob: null, weight: null, chiefComplaint: null, primaryImpression: null };
    if (!state.pcrHeader.name) {
      state.pcrHeader.name = candidate.name;
      _renderPcrHeader();
    }
  }
  if (!existed) _renderChatOnSceneRoster();
  return !existed;
}

function _sceneSpeakerNameIsKnown(name = "", role = "") {
  const roleKey = String(role || "").toLowerCase();
  if (roleKey === "partner") return true;
  const key = _sceneRosterCandidateKey(name);
  return Boolean(key && state._knownSceneNames instanceof Map && state._knownSceneNames.has(key));
}

function _messageRequestsAnySceneName(message = "") {
  const msg = _normalizeHistoryMapText(message);
  if (!msg) return false;
  return _messageRequestsPatientName(message)
    || /\bwho\s+(?:are|r)\s+(?:you|u)\b/.test(msg)
    || /\b(?:what is|whats|who is|identify|tell me)\b.{0,50}\b(?:your name|name)\b/.test(msg)
    || /\b(?:your name|name and age|name dob|name date of birth)\b/.test(msg);
}

function _sceneNameRegex(name = "") {
  const normalized = _normalizeHistoryMapText(name);
  if (!normalized) return null;
  const parts = normalized.split(/\s+/).filter(Boolean).map(part => part.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"));
  if (!parts.length) return null;
  return new RegExp(`\\b${parts.join("\\s+")}\\b`, "i");
}

function _stripSpeakerLabelsForRosterNameCapture(text = "") {
  return String(text || "")
    .split("\n")
    .map(line => line.replace(/^\s*\*?[^:\n*]{1,80}\*?\s*:\s*/, ""))
    .join("\n");
}

function _captureKnownSceneNamesFromExchange(message = "", responseText = "") {
  const msg = _normalizeHistoryMapText(message);
  const response = _normalizeHistoryMapText(_stripSpeakerLabelsForRosterNameCapture(responseText));
  if (!msg && !response) return;
  const askedName = _messageRequestsAnySceneName(message);
  _sceneRosterCandidates().forEach(candidate => {
    const candidateNameRe = _sceneNameRegex(candidate.name);
    if (!candidateNameRe) return;
    const learnerUsedName = Boolean(msg && candidateNameRe.test(msg));
    const responseGaveName = Boolean(askedName && response && candidateNameRe.test(response));
    if (learnerUsedName || responseGaveName) _markSceneNameKnown(candidate.name);
  });
}

function _chatSpeakerLabelForDisplay(speaker = "", role = "") {
  const speakerName = _canonicalSpeakerDisplayName(speaker);
  const displayRole = _speakerDisplayRole(speaker, role);
  const roleSuffix = displayRole ? ` (${displayRole})` : "";
  if (_sceneSpeakerNameIsKnown(speakerName, displayRole)) {
    return `${speakerName}${roleSuffix}`;
  }
  if (displayRole) return `(${displayRole})`;
  return speakerName || "On scene";
}

function startSim(opts = {}) {
  const s = state.scenarioData;
  _seedScenarioSpeakerAliases(s);
  _lastNonPartnerSceneSpeaker = "";
  setText("sim-title", _scenarioHeaderTitle());
  setText("sim-subtitle", _scenarioHeaderSubtitle());
  const studentEl = el("sim-student");
  if (studentEl) studentEl.querySelector("div").textContent = state.firstName || state.studentName;

  // PCR Notes — patient identity + dispatch
  state.pcrHeader = { name: null, age: null, dob: null, weight: null, chiefComplaint: null, primaryImpression: null };
  state._knownSceneNames = new Map();
  _seedKnownScenePartners();
  _renderPcrHeader();
  _renderChatOnSceneRoster();
  setText("pcr-dispatch", s.dispatch.text);
  setText("pcr-presentation", s.patient.general_impression);

  // Reset PCR dynamic sections
  el("pcr-history").innerHTML = "";
  el("pcr-vitals").innerHTML = "";
  el("pcr-treatments").innerHTML = "";
  show("pcr-history-empty");
  show("pcr-vitals-empty");
  show("pcr-treatments-empty");

  // Scene tab — patient photo
  if (s.patient.image) {
    el("pt-photo").loading = "eager";
    el("pt-photo").decoding = "async";
    if ("fetchPriority" in el("pt-photo")) el("pt-photo").fetchPriority = "high";
    el("pt-photo").src = _scormAssetUrl(s.patient.image);
    el("pt-photo").classList.remove("hidden");
    el("pt-photo-placeholder").classList.add("hidden");
  }
  setText("scene-description", s.scene.description);
  // Keep the notes panel compact: the small patient/scene thumbnail above opens
  // the full image in the lightbox. Do not render the full-size image inline.
  hide("scene-image-container");
  if (el("scene-image")) el("scene-image").src = _scormAssetUrl(s.scene.image || s.patient.image || "");
  setText("scene-bystanders", "");

  // Reset state
  state.interventionsApplied = [];
  state.detectedTreatmentIds = [];
  state.detectedTreatmentLabels = [];
  state.alsArrived = false;
  state.lexiHistory = [];
  state._o2Early = false;
  state._lexiGuidedMode = false;
  state._lexiAssistedTreatments = [];
  state._lexiActionFeedbackShown = new Set();
  state._lastSimLearnerActivityAt = Date.now();
  state._lexiIdleCheckinShown = false;
  _clearLexiIdleCheckinTimer();
  state._sceneEntryPpe = [];
  state._sceneEntryApproach = null;
  _ttsPrewarmSeen.clear();
  _lungSoundUsed = false;
  _lungSoundPendingFinding = null;
  _suctionReadyConfirmationPending = false;
  state.simTimersStarted = false;
  _historyCaptureUnlocked = false;
  msgCount = 0;
  o2Applied = false;

  // Reset chat — keep composer guidance generic so authored names are not revealed.
  el("chat-messages").innerHTML = "";
  _resetSimComposerInputs();
  el("chat-input").placeholder = "Ask questions or give EMS instructions...";
  const addrHint = el("chat-address-hint");
  if (addrHint) addrHint.textContent = "Use roles like patient, parent/caregiver, bystander, or partner until names are known.";
  appendSystemMessage("Scene arrived. You step out of the rig and approach the scene.");

  // Lexi hint buttons — render from scenario data
  const hintContainer = el("lexi-hint-buttons");
  if (hintContainer && s.lexi_hints?.length) {
    hintContainer.innerHTML = s.lexi_hints.map(h =>
      `<button class="lexi-hint-btn" data-msg="${h.msg.replace(/"/g, "&quot;")}">${h.label}</button>`
    ).join("");
    hintContainer.querySelectorAll(".lexi-hint-btn").forEach(btn => {
      btn.addEventListener("click", () => { if (btn.dataset.msg) sendLexiMessage(btn.dataset.msg); });
    });
  }

  // Lexi panel — welcome message + treat count
  el("lexi-messages").innerHTML = "";
  updateTreatDisplay();
  appendLexiBot("I'm here to help! Ask me EMS questions, protocol guidance, or type \"what can you do?\" to see everything I can help with. 🐾");

  buildInterventionIndex();

  // Phase 4: reset body map for new scenario — clear prior SVG, reset to Briefing tab
  const _bmc = el("body-map-container");
  if (_bmc) {
    const _svgWrap = el("body-map-svg-wrap");
    if (_svgWrap) _svgWrap.innerHTML = "";               // force re-fetch on next tab switch
    _bmc.dataset.variant = getPatientSilhouetteType(s.patient.age);
    _bmc.classList.add("hidden");
  }
  _setLeftPanelTab("briefing");                           // always start on Briefing tab

  // Show/hide drill mode UI
  const drillBadge = el("drill-mode-badge");
  const btnDrillFb = el("btn-drill-feedback");
  const btnTreatment = el("btn-open-treatment");
  if (state.drillMode) {
    if (drillBadge) drillBadge.classList.remove("hidden");
    if (btnDrillFb) btnDrillFb.classList.remove("hidden");
    if (btnTreatment) btnTreatment.classList.add("hidden");
  } else {
    if (drillBadge) drillBadge.classList.add("hidden");
    if (btnDrillFb) btnDrillFb.classList.add("hidden");
    if (btnTreatment) btnTreatment.classList.remove("hidden");
  }

  showScreen("sim");
  _syncSimMobileMode();

  // Populate and show the scene arrival modal
  const arrImgContainer = el("arrival-image-container");
  const arrImg = el("arrival-image");
  const arrivalImage = s.scene.image || s.patient.image;
  if (arrivalImage) {
    arrImg.loading = "eager";
    arrImg.decoding = "async";
    if ("fetchPriority" in arrImg) arrImg.fetchPriority = "high";
    arrImg.src = _scormAssetUrl(arrivalImage);
    arrImgContainer.classList.remove("hidden");
  } else {
    arrImgContainer.classList.add("hidden");
    arrImg.src = "";
  }
  setText("arrival-scene-desc", s.scene.description);
  setText("arrival-patient-presentation", s.patient.general_impression);
  _resetPpeButtons();
  show("modal-scene-arrival");
  _scheduleTtsPrewarm();
}

