function _setLeftPanelTab(tab) {
  const isBriefing = tab === "briefing";
  const isExam     = tab === "exam";
  const isRef      = tab === "ref";

  el("tab-notes")?.classList.toggle("hidden", !isBriefing);

  const bmc = el("body-map-container");
  if (bmc) bmc.classList.toggle("hidden", !isExam);
  if (isExam) _loadBodyMapSvg();

  const refPanel = el("ref-panel");
  if (refPanel) {
    refPanel.classList.toggle("hidden",  !isRef);
    refPanel.classList.toggle("visible", isRef);
    if (isRef) _loadRefPanel();
  }

  el("btn-left-tab-briefing")?.classList.toggle("left-panel-tab--active", isBriefing);
  el("btn-left-tab-exam")?.classList.toggle("left-panel-tab--active",     isExam);
  el("btn-left-tab-ref")?.classList.toggle("left-panel-tab--active",      isRef);
}

el("btn-left-tab-briefing")?.addEventListener("click", () => _setLeftPanelTab("briefing"));
el("btn-left-tab-exam")?.addEventListener("click",     () => _setLeftPanelTab("exam"));
el("btn-left-tab-ref")?.addEventListener("click",      () => _setLeftPanelTab("ref"));

