let _refActiveSubtab = "conditions";
let _refNotesSearch = "";
let _refNotesFilter = "all";

function _setRefSubtab(name) {
  _refActiveSubtab = name;
  ["conditions", "learning", "notes"].forEach(tab => {
    const pane = el(`ref-pane-${tab}`);
    const btn  = el(`btn-ref-subtab-${tab}`);
    const active = tab === name;
    pane?.classList.toggle("hidden", !active);
    btn?.classList.toggle("ref-subtab--active", active);
  });
}

["conditions", "learning", "notes"].forEach(tab => {
  el(`btn-ref-subtab-${tab}`)?.addEventListener("click", () => _setRefSubtab(tab));
});

function _wireRefAccordions(pane) {
  pane.querySelectorAll(".ref-panel-section__header").forEach(header => {
    header.addEventListener("click", () => {
      const body = el(header.dataset.body);
      const chev = el(`chev-${header.dataset.body}`);
      if (!body) return;
      const open = body.classList.toggle("open");
      if (open) _syncRefAccordionBodyHeight(header, body);
      else body.style.removeProperty("max-height");
      chev?.classList.toggle("ref-panel-section__chevron--open", open);
    });
  });
}

function _syncRefAccordionBodyHeight(header, body) {
  const pane = header?.closest(".ref-pane") || body?.closest(".ref-pane");
  if (!pane || !header || !body) return;
  const paneRect = pane.getBoundingClientRect();
  const headerRect = header.getBoundingClientRect();
  const available = Math.floor(paneRect.bottom - headerRect.bottom - 12);
  body.style.maxHeight = `${Math.max(140, available)}px`;
}

function _syncOpenRefAccordions() {
  document.querySelectorAll(".ref-pane:not(.hidden) .ref-panel-section__body.open").forEach(body => {
    const header = body.previousElementSibling;
    if (header?.classList.contains("ref-panel-section__header")) {
      _syncRefAccordionBodyHeight(header, body);
    }
  });
}

window.addEventListener("resize", _syncOpenRefAccordions);

function _refEmptyPane(msg) {
  return `<p class="text-gray-500 text-xs text-center py-6">${msg}</p>`;
}

function _refScenarioRelevantTerms() {
  const sc = state.scenarioData || {};
  const parts = [
    state.scenarioId || "",
    sc.id || "",
    sc.title || "",
    sc.subtitle || "",
    sc.category || "",
    sc.type || "",
    sc.dispatch?.text || sc.dispatch || "",
    sc.patient?.chief_complaint || "",
    sc.patient?.age_display || "",
    sc.patient?.sex || "",
  ].join(" ").toLowerCase();

  const terms = new Set();
  const add = (...items) => items.forEach(item => {
    const value = String(item || "").trim().toLowerCase();
    if (value) terms.add(value);
  });

  if (/pediatric|peds|child|infant|toddler|school|adolescent|baby/.test(parts)) add("pediatric", "pediatrics", "child", "children");
  if (/adult/.test(parts)) add("adult");
  if (/trauma|mvc|mva|fall|burn|laceration|bleeding|hemorrhage|fracture|injury|choking/.test(parts)) add("trauma", "injury", "bleeding");
  if (/medical|fever|seizure|diabetic|tox|overdose|asthma|croup|anaphylaxis|respiratory|cardiac/.test(parts)) add("medical");
  if (/airway|choking|stridor|snoring|obstruct|epiglottitis|croup/.test(parts)) add("airway");
  if (/breath|respiratory|wheeze|wheezing|stridor|crackles|lung|asthma|spo2|oxygen|hypoxia/.test(parts)) add("breathing", "respiratory", "lung sounds", "oxygen", "spo2");
  if (/shock|perfusion|pale|mottled|cyanosis|cap refill|pulse|heart|bleeding|hemorrhage/.test(parts)) add("circulation", "perfusion", "pulse", "shock");
  if (/gcs|altered|ams|unresponsive|seizure|loc|mental|neuro|pupil/.test(parts)) add("gcs", "neuro", "loc", "assessment");
  if (/vital|bp|blood pressure|heart rate|pulse|resp|spo2|temperature|bgl|glucose/.test(parts)) add("vitals", "assessment");
  if (/sample|opqrst|history|allerg|medication|last oral|events|pain/.test(parts)) add("history", "sample", "opqrst", "assessment");
  if (/medication|albuterol|epinephrine|epi|dextrose|naloxone|oxygen|treatment|intervention/.test(parts)) add("meds", "medications", "treatment");

  String(sc.category || "").split(/[_\s-]+/).forEach(token => {
    if (token.length >= 4) add(token);
  });

  return [...terms];
}

function _refNoteHaystack(note = "") {
  return [
    note.title || "",
    note.body || "",
    note.scenario_display_name || "",
    note.scenario_id || "",
    ...(note.tags || []),
  ].join(" ").toLowerCase();
}

function _renderRefNotesPane(pane, notes = []) {
  if (!pane) return;
  const allNotes = Array.isArray(notes) ? notes : [];
  const currentScenarioId = state.scenarioId || "";
  const relevantTerms = _refScenarioRelevantTerms();
  const filterLabels = [
    ["all", "All"],
    ["current", "This Call"],
    ["relevant", "Relevant"],
    ["recent", "Recent"],
  ];
  pane.innerHTML = `
    <div class="ref-notes-tools">
      <input id="ref-notes-search" class="ref-notes-search" type="search" maxlength="120"
        placeholder="Search notes..." value="${escapeHTML(_refNotesSearch)}" autocomplete="off">
      <div class="ref-notes-filters">
        ${filterLabels.map(([id, label]) => `
          <button type="button" class="ref-notes-filter${_refNotesFilter === id ? " active" : ""}" data-ref-notes-filter="${id}">
            ${escapeHTML(label)}
          </button>
        `).join("")}
      </div>
    </div>
    <div id="ref-notes-list" class="ref-notes-list"></div>
  `;

  const list = el("ref-notes-list");
  const apply = () => {
	  const term = (_refNotesSearch || "").trim().toLowerCase();
	  const now = Date.now();
	  const filtered = allNotes.filter(n => {
      const haystack = _refNoteHaystack(n);
	      if (_refNotesFilter === "current" && (!currentScenarioId || n.scenario_id !== currentScenarioId)) return false;
	      if (_refNotesFilter === "relevant" && !relevantTerms.some(relevant => haystack.includes(relevant))) return false;
	      if (_refNotesFilter === "recent") {
	        const updated = n.updated_at ? new Date(n.updated_at).getTime() : 0;
	        if (!updated || now - updated > 7 * 24 * 60 * 60 * 1000) return false;
	      }
	      if (!term) return true;
	      return haystack.includes(term);
	    });

    if (!list) return;
    if (filtered.length === 0) {
      list.innerHTML = _refEmptyPane(allNotes.length
        ? "No notes match the current search or filter."
        : "No notes yet. Use the notebook to create notes during scenarios.");
      return;
    }
    list.innerHTML = filtered.map((n, i) => {
      const bid = `ref-note-body-${i}`;
      const subtitle = n.scenario_display_name
        ? `<span class="text-gray-600 font-normal ml-1 text-xs">— ${escapeHTML(n.scenario_display_name)}</span>`
        : "";
      const tags = (n.tags || []).map(t => `<span class="ref-note-tag">${escapeHTML(t)}</span>`).join("");
      const meta = [
        n.updated_at ? _relativeTime(n.updated_at) : "",
        tags ? `<span class="ref-note-tags">${tags}</span>` : "",
      ].filter(Boolean).join(" ");
      return `<div class="ref-panel-section">
        <div class="ref-panel-section__header" data-body="${bid}">
          <span>${escapeHTML(n.title || "Untitled note")}${subtitle}${meta ? `<span class="ref-note-meta">${meta}</span>` : ""}</span>
          <span class="ref-panel-section__chevron" id="chev-${bid}">▼</span>
        </div>
        <div class="ref-panel-section__body" id="${bid}">${renderMarkdown(n.body || "")}</div>
      </div>`;
    }).join("");
    _wireRefAccordions(pane);
  };

  el("ref-notes-search")?.addEventListener("input", (event) => {
    _refNotesSearch = event.target.value || "";
    apply();
  });
  pane.querySelectorAll("[data-ref-notes-filter]").forEach(btn => {
    btn.addEventListener("click", () => {
      _refNotesFilter = btn.getAttribute("data-ref-notes-filter") || "all";
      pane.querySelectorAll("[data-ref-notes-filter]").forEach(b => {
        b.classList.toggle("active", b === btn);
      });
      apply();
    });
  });
  apply();
}

async function _loadRefPanel() {
  const panes = {
    conditions: el("ref-pane-conditions"),
    learning:   el("ref-pane-learning"),
    notes:      el("ref-pane-notes"),
  };
  if (!panes.conditions) return;

  panes[_refActiveSubtab].innerHTML = '<p class="text-gray-500 text-xs text-center py-4">Loading…</p>';

  try {
    const [condRes, learnRes, notesRes] = await Promise.all([
      authFetch(`${API}/api/me/notebook/conditions`),
      authFetch(`${API}/api/me/notebook/learning`),
      authFetch(`${API}/api/notes?limit=50`),
    ]);
    const conditions = condRes.ok  ? await condRes.json()  : [];
    const learning   = learnRes.ok ? await learnRes.json() : [];
    const notes      = notesRes.ok ? await notesRes.json() : [];

    // Conditions pane
    if (conditions.length > 0) {
      panes.conditions.innerHTML = conditions.map((c, i) => {
        const bid = `ref-cond-body-${i}`;
        return `<div class="ref-panel-section">
          <div class="ref-panel-section__header" data-body="${bid}">
            <span>${escapeHTML(c.condition_name)}<span class="text-gray-600 font-normal ml-1 text-xs">— ${escapeHTML(c.scenario_title)}</span></span>
            <span class="ref-panel-section__chevron" id="chev-${bid}">▼</span>
          </div>
          <div class="ref-panel-section__body" id="${bid}">${renderMarkdown(_stripReferenceSectionNumbers(c.reference_md))}</div>
        </div>`;
      }).join("");
      _wireRefAccordions(panes.conditions);
    } else {
      panes.conditions.innerHTML = _refEmptyPane("No conditions unlocked yet. Complete scenarios to earn condition references.");
    }

    // Learning pane
    if (learning.length > 0) {
      panes.learning.innerHTML = learning.map((l, i) => {
        const bid = `ref-learn-body-${i}`;
        return `<div class="ref-panel-section">
          <div class="ref-panel-section__header" data-body="${bid}">
            <span>${escapeHTML(l.game_title)}<span class="text-gray-600 font-normal ml-1 text-xs">— ${escapeHTML(l.category_title || "Training Center")}</span></span>
            <span class="ref-panel-section__chevron" id="chev-${bid}">▼</span>
          </div>
          <div class="ref-panel-section__body" id="${bid}">${renderMarkdown(l.content_md)}</div>
        </div>`;
      }).join("");
      _wireRefAccordions(panes.learning);
    } else {
      panes.learning.innerHTML = _refEmptyPane("No learning pages yet. Complete drills to unlock references.");
    }

    // Notes pane
    _renderRefNotesPane(panes.notes, notes);

  } catch {
    panes[_refActiveSubtab].innerHTML = `<p class="text-red-400 text-xs text-center py-4">Failed to load references.</p>`;
  }
}

