function _formatReferenceRequirement(req = "") {
  const [gameId, mode] = String(req || "").split(":");
  const title = _MG_LEARNING_PAGES[gameId]?.title || gameId.replace(/_/g, " ");
  if (!mode) return title;
  return `${title} (${mode.replace(/_/g, " ")})`;
}

function _renderReferenceCardSections(card = {}) {
  const section = (title, items = []) => {
    if (!Array.isArray(items) || !items.length) return "";
    return `
      <h4 class="nb-reference-card__section-title">${escapeHTML(title)}</h4>
      <ul class="nb-reference-card__list">
        ${items.map(item => `<li>${escapeHTML(item)}</li>`).join("")}
      </ul>
    `;
  };
  return [
    section("Framework", card.framework_summary),
    section("Common traps", card.common_traps),
    section("Field examples", card.field_examples),
  ].join("");
}

async function _loadReferenceCardsForNotebook() {
  const list = el("nb-reference-card-list");
  const empty = el("nb-reference-card-empty");
  if (!list) return;
  list.innerHTML = `<p class="text-gray-500 text-xs py-3">Loading reference cards…</p>`;
  empty?.classList.add("hidden");
  try {
    const res = await authFetch(`${API}/api/me/minigames/reference-cards`);
    if (!res.ok) throw new Error("reference cards unavailable");
    const payload = await res.json();
    const unlocked = Array.isArray(payload.cards) ? payload.cards : [];
    const locked = Array.isArray(payload.locked_cards) ? payload.locked_cards : [];
    if (!unlocked.length && !locked.length) {
      list.innerHTML = "";
      empty?.classList.remove("hidden");
      return;
    }
    const unlockedHtml = unlocked.map((card, i) => {
      const bodyId = `nb-ref-card-body-${i}`;
      const date = card.unlocked_at ? new Date(card.unlocked_at).toLocaleDateString() : "";
      return `
        <article class="nb-reference-card">
          <div class="nb-reference-card__header" data-ref-body="${bodyId}">
            <div>
              <div class="nb-reference-card__title">${escapeHTML(card.title || card.card_id)}</div>
              <div class="nb-reference-card__meta">${date ? `Unlocked ${escapeHTML(date)}` : "Unlocked reference"} · ${escapeHTML((card.related_game_ids || []).join(", ") || "Drill")}</div>
            </div>
            <span class="nb-reference-card__badge">Earned</span>
          </div>
          <div id="${bodyId}" class="nb-reference-card__body">${_renderReferenceCardSections(card)}</div>
        </article>
      `;
    }).join("");
    const lockedHtml = locked.map((card, i) => {
      const bodyId = `nb-ref-locked-body-${i}`;
      const reqs = card.unlock_condition?.all_passed || [];
      return `
        <article class="nb-reference-card nb-reference-card--locked">
          <div class="nb-reference-card__header" data-ref-body="${bodyId}">
            <div>
              <div class="nb-reference-card__title">${escapeHTML(card.title || card.card_id)}</div>
              <div class="nb-reference-card__meta">Locked · ${escapeHTML((card.related_game_ids || []).join(", ") || "Drill")}</div>
            </div>
            <span class="nb-reference-card__badge">Locked</span>
          </div>
          <div id="${bodyId}" class="nb-reference-card__body">
            <h4 class="nb-reference-card__section-title">Unlock condition</h4>
            <ul class="nb-reference-card__list">
              ${reqs.length ? reqs.map(req => `<li>Pass ${escapeHTML(_formatReferenceRequirement(req))}</li>`).join("") : "<li>Complete the associated mastery flow.</li>"}
            </ul>
          </div>
        </article>
      `;
    }).join("");
    list.innerHTML = unlockedHtml + lockedHtml;
    list.querySelectorAll("[data-ref-body]").forEach(header => {
      header.addEventListener("click", () => {
        const body = el(header.getAttribute("data-ref-body") || "");
        body?.classList.toggle("open");
      });
    });
  } catch {
    list.innerHTML = `<p class="text-red-400 text-xs py-3">Could not load reference cards.</p>`;
  }
}

async function _saveMgLearningPage(gameId) {
  try {
    const res = await authFetch(`${API}/api/me/notebook/learning`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ game_id: gameId }),
    });
    if (!res.ok) return null;
    const entry = await res.json().catch(() => null);
    if (entry?.game_id) {
      const existing = (_notebookState.learning || []).filter(l => l.game_id !== entry.game_id);
      _notebookState.learning = [entry, ...existing];
      const cached = _notebookLearningCache.scope === _notebookCacheScope() && Array.isArray(_notebookLearningCache.data)
        ? _notebookLearningCache.data
        : [];
      _notebookLearningCache = {
        scope: _notebookCacheScope(),
        fetchedAt: Date.now(),
        data: [entry, ...cached.filter(l => l?.game_id !== entry.game_id)],
        promise: null,
      };
      if (!el("screen-notebook")?.classList.contains("hidden") && _notebookState.activeTab === "learning") {
        _renderNotebookLearning();
      }
      if (!el("ref-panel")?.classList.contains("hidden")) {
        _loadRefPanel().catch(() => {});
      }
    }
    return entry;
  } catch { /* fire and forget */ }
  return null;
}

