async function _loadBodyMapSvg() {
  const svgWrap = el("body-map-svg-wrap");
  if (!svgWrap) return;
  if (svgWrap.querySelector("svg")) return; // already loaded
  const variant = el("body-map-container")?.dataset.variant || "adult";
  try {
    const r = await fetch(`/static/img/body-map/body-map-${variant}.svg?v=patient-anatomical-lr-20260605`, {
      cache: "no-store",
    });
    if (!r.ok) return;
    svgWrap.innerHTML = await r.text();
    svgWrap.querySelectorAll(".bm-region").forEach(regionEl => {
      regionEl.addEventListener("click", _onBmRegionClick);
    });
  } catch (e) { /* SVG unavailable — body map stays empty */ }
}

function _onBmRegionClick(e) {
  const regionEl = e.currentTarget;
  const region = regionEl.dataset.region;
  if (!region || !state.sessionId) return;

  // Amber flash on the tapped region
  regionEl.classList.add("bm-region--flash");
  regionEl.addEventListener("animationend", () => regionEl.classList.remove("bm-region--flash"), { once: true });

  // Open exam options popup for this region
  _openExamRegionModal(region);
}

function _openExamRegionModal(region) {
  const def = BM_REGION_EXAMS[region];
  if (!def) return;
  const title = el("exam-modal-title");
  const body  = el("exam-modal-body");
  if (!title || !body) return;

  title.textContent = def.label;
  body.innerHTML = "";

  function makeItemBtn(item) {
    const btn = document.createElement("button");
    btn.className = "action-sheet-item";
    btn.textContent = item.label;
    btn.addEventListener("click", async () => {
      if (item.action === "o2_modal") {
        hide("modal-exam-region");
        show("modal-o2-admin");
        isPopupOpen = true;
      } else if (item.action === "lung_sound_challenge") {
        hide("modal-exam-region");
        _openScenarioLungSoundChallenge(item.payload);
        if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
      } else if (item.action === "cpr_challenge") {
        hide("modal-exam-region");
        if (_scenarioHasCprChallenge()) _openCprChallengeHud(item.cprTrigger || "cpr_started");
        else sendMessage(item.payload || "I am starting CPR.", { isAction: true });
        if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
      } else if (item.payload) {
        hide("modal-exam-region");
        const handledAuthoredExam = await _handleAuthoredStandardExamAction(item.payload, "body-map-exam", true);
        if (handledAuthoredExam) {
          if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
          return;
        }
        const handledIntervention = await _handleActionMenuInterventionItem(item, "body-map-procedure");
        if (handledIntervention) {
          if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
          return;
        }
        sendMessage(item.payload, { isAction: true });
        if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
      }
    });
    return btn;
  }

  // Exams section
  if (def.items?.length) {
    const examHeader = document.createElement("p");
    examHeader.className = "exam-section-header";
    examHeader.textContent = "Exams";
    body.appendChild(examHeader);
    def.items.forEach(item => body.appendChild(makeItemBtn(item)));
  }

  // Procedures section
  if (def.procedures?.length) {
    const procHeader = document.createElement("p");
    procHeader.className = "exam-section-header exam-section-header--procedures";
    procHeader.textContent = "Procedures";
    body.appendChild(procHeader);
    def.procedures.forEach(item => body.appendChild(makeItemBtn(item)));
  }

  show("modal-exam-region");
}

el("btn-exam-close")?.addEventListener("click", () => hide("modal-exam-region"));
// Close on backdrop click
el("modal-exam-region")?.addEventListener("click", e => {
  if (e.target === el("modal-exam-region")) hide("modal-exam-region");
});

