// Navigation stack for multi-level modal
let _actionStack = [];

function _renderActionModal() {
  const view = _actionStack[_actionStack.length - 1];
  if (!view) return;
  setText("action-modal-title", view.title);
  const backBtn = el("btn-action-back");
  if (backBtn) backBtn.classList.toggle("hidden", _actionStack.length <= 1);
  const body = el("action-modal-body");
  if (!body) return;
  body.innerHTML = "";

  // ── Vitals: multi-select checkboxes ──────────────────────────────
  if (view.type === "vitals") {
    if (!view.items.length) {
      const empty = document.createElement("p");
      empty.className = "action-sheet-empty";
      empty.textContent = "No vitals available.";
      body.appendChild(empty);
      return;
    }
    const selections = view.selections || (view.selections = new Set());

    view.items.forEach(item => {
      const row = document.createElement("label");
      row.className = "vital-check-row";
      const cb = document.createElement("input");
      cb.type = "checkbox";
      cb.className = "vital-check-input";
      cb.checked = selections.has(item.payload);
      cb.addEventListener("change", () => {
        if (cb.checked) selections.add(item.payload); else selections.delete(item.payload);
        updateConfirmBtn();
      });
      const span = document.createElement("span");
      span.textContent = item.label;
      row.appendChild(cb);
      row.appendChild(span);
      body.appendChild(row);
    });

    // Sticky confirm button
    const confirmWrap = document.createElement("div");
    confirmWrap.className = "vital-confirm-wrap";
    const confirmBtn = document.createElement("button");
    confirmBtn.className = "vital-confirm-btn";
    confirmBtn.disabled = true;
    confirmBtn.textContent = "Take Vitals";
    confirmBtn.addEventListener("click", async () => {
      if (!selections.size) return;
      const selectedPayloads = [...selections];
      const selectedItems = view.items.filter(item => selectedPayloads.includes(item.payload));
      const gcsPayload = ACTION_VITALS.find(item => item.action === "gcs_modal")?.payload;
      const avpuPayload = ACTION_VITALS.find(item => item.label === "AVPU")?.payload;
      const shouldOpenGcs = !!gcsPayload && selectedPayloads.includes(gcsPayload);
      const shouldAssessAvpu = !!avpuPayload && selectedPayloads.includes(avpuPayload);
      const reportPayloads = selectedPayloads.filter(payload => payload !== gcsPayload);
      const nonGcsPayloads = selectedPayloads.filter(payload => payload !== gcsPayload && payload !== avpuPayload);
      const nonGcsItems = selectedItems.filter(item => item.payload !== gcsPayload && item.payload !== avpuPayload);
      hide("modal-action");
      _actionStack = [];
      let avpuAssessment = null;
      if (shouldAssessAvpu && nonGcsPayloads.length) {
        avpuAssessment = await _recordAvpuAssessment(avpuPayload, {
          isAction: true,
          chipId: "action-vitals-avpu",
          appendUser: false,
          appendResponse: true,
          source: "authored_vitals",
        });
      }
      if (nonGcsPayloads.length) {
        const msg = `Alex, please report these vitals: ${reportPayloads.join(", ")}.`;
        const handled = await _recordAuthoredVitalsRequest(msg, {
          isAction: true,
          chipId: "action-vitals",
          requestedDefs: _actionVitalsRequestedDefs(nonGcsItems),
          extraResponseLines: [],
        });
        if (!handled) await sendMessage(msg, { isAction: true, suppressGcsChallenge: true });
      }
      if (shouldAssessAvpu && !nonGcsPayloads.length) {
        await _recordAvpuAssessment(avpuPayload, { isAction: true, chipId: "action-vitals-avpu", source: "authored_vitals" });
      }
      if (shouldOpenGcs) _openGcsAssessmentModal({ suppressAlexEcho: !!nonGcsPayloads.length });
      if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
    });
    confirmWrap.appendChild(confirmBtn);
    body.appendChild(confirmWrap);

    function updateConfirmBtn() {
      confirmBtn.disabled = selections.size === 0;
      confirmBtn.textContent = selections.size
        ? `Take Vitals (${selections.size} selected)`
        : "Take Vitals";
    }
    return;
  }

  // ── Standard list ─────────────────────────────────────────────────
  if (!view.items.length) {
    const empty = document.createElement("p");
    empty.className = "action-sheet-empty";
    empty.textContent = "No options available for this scenario.";
    body.appendChild(empty);
    return;
  }
  view.items.forEach(item => {
    if (item.isNote) {
      const note = document.createElement("p");
      note.className = item.isUnavailable ? "action-sheet-note action-sheet-note--unavailable" : "action-sheet-note";
      note.textContent = item.label;
      body.appendChild(note);
      return;
    }
    const btn = document.createElement("button");
    btn.className = "action-sheet-item" + (item.children ? " action-sheet-item--has-children" : "");
    btn.innerHTML = escapeHTML(item.label) + (item.children ? `<span class="action-sheet-item-chevron">›</span>` : "");
    btn.addEventListener("click", async () => {
      if (item.children) {
        _actionStack.push({ title: item.label, items: item.children });
        _renderActionModal();
      } else if (item.action === "o2_modal") {
        hide("modal-action");
        _actionStack = [];
        show("modal-o2-admin");
        isPopupOpen = true;
      } else if (item.action === "gcs_modal") {
        hide("modal-action");
        _actionStack = [];
        _openGcsAssessmentModal();
      } else if (item.action === "lung_sound_challenge") {
        hide("modal-action");
        _actionStack = [];
        _openScenarioLungSoundChallenge(item.payload);
      } else if (item.action === "cpr_challenge" && _scenarioHasCprChallenge()) {
        hide("modal-action");
        _actionStack = [];
        _openCprChallengeHud(item.cprTrigger || "cpr_started");
      } else if (item.action === "cpr_challenge") {
        hide("modal-action");
        _actionStack = [];
        sendMessage(item.payload || "I am starting CPR.", { isAction: true });
      } else if (item.action === "med_popup" && item.intervention) {
        hide("modal-action");
        _actionStack = [];
        showMedPopup(item.intervention);
      } else if (item.payload) {
        hide("modal-action");
        _actionStack = [];
        if (await _handleAuthoredStandardExamAction(item.payload, "action-menu-exam", true)) {
          if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
          return;
        }
        if (await _handleActionMenuInterventionItem(item, "action_menu")) {
          if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
          return;
        }
        sendMessage(item.payload, { isAction: true });
        if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
      }
    });
    body.appendChild(btn);
  });
}

function _inventoryHasAny(ids = [], kind = "any") {
  if (!ids.length) return true;
  const equipment = state.availableEquipmentIds || new Set();
  const meds = state.availableMedicationIds || new Set();
  return ids.some(id => {
    if (kind === "equipment") return equipment.has(id);
    if (kind === "medication") return meds.has(id);
    return equipment.has(id) || meds.has(id);
  });
}

function _inventoryHasCustomKeyword(keywords = []) {
  if (!keywords.length) return false;
  const labels = state.availableCustomInventoryLabels || [];
  return keywords.some(k => labels.some(label => label.includes(String(k || "").toLowerCase())));
}

function _inventorySatisfiesAllGroups(groups = [], kind = "any") {
  if (!groups.length) return true;
  return groups.every(group => {
    const ids = Array.isArray(group) ? group : [group];
    return _inventoryHasAny(ids, kind);
  });
}

function _isActionItemAvailable(item, kind = "any") {
  if (!state.agencyEquipmentConfigured) return true;
  if (item.requiresAll?.length) return _inventorySatisfiesAllGroups(item.requiresAll, kind);
  const ids = item.requiresAny || (kind === "medication" ? item.matchIds : []);
  const keywords = item.customKeywords || (kind === "medication" ? [item.key, item.label].filter(Boolean) : []);
  if (!ids.length && !keywords.length) return true;
  return _inventoryHasAny(ids, kind) || _inventoryHasCustomKeyword(keywords);
}

function _filterActionItems(items = [], kind = "any", mapper = null) {
  return items
    .map(raw => {
      const item = mapper ? mapper(raw) : raw;
      if (!item) return null;
      if (item.children) {
        const children = _filterActionItems(item.children, kind, mapper);
        return children.length ? { ...item, children } : null;
      }
      if (item.isNote) return item;
      return _isActionItemAvailable(item, kind) ? item : null;
    })
    .filter(Boolean);
}

function _openActionModal(category) {
  if (!state.sessionId) return;
  _actionStack = [];
  let title, items, type;

  function mapMedicationMenuItem(med) {
    if (med.children) {
      return { ...med, children: med.children.map(mapMedicationMenuItem) };
    }
    if (med.isNote) return med;
    const scenarioIv = Object.values(_interventionById)
      .find(iv => {
        const matchIds = new Set([med.key, ...(med.matchIds || [])].filter(Boolean));
        return matchIds.has(iv.id) || iv.label?.toLowerCase().includes(String(med.key || "").replace(/_/g, " "));
      });

    if (scenarioIv?.popup_config && (scenarioIv.popup_config.drug || scenarioIv.popup_config.dose)) {
      return { ...med, label: med.label, action: "med_popup", intervention: scenarioIv };
    }
    return { ...med, label: med.label, payload: `I am administering ${med.label} per protocol.` };
  }

  if (category === "vitals") {
    title = "Vitals";
    type  = "vitals";
    items = _filterActionItems(ACTION_VITALS, "equipment");
  } else if (category === "equipment") {
    title = "Equipment";
    items = _filterActionItems(ACTION_EQUIPMENT, "equipment");
  } else if (category === "meds") {
    title = "Medications";
    // Keep the displayed formulary stable across scenarios. Scenario data is only used
    // behind the scenes to attach an existing dose/effect popup when the shared item matches.
    items = _filterActionItems(BASE_MEDICATIONS, "medication", mapMedicationMenuItem);
  } else if (category === "procedures") {
    title = "Quick Procedures";
    items = _filterActionItems(ACTION_PROCEDURES, "any");
  }

  _actionStack.push({ title, type, items });
  _renderActionModal();
  show("modal-action");
}

// Action bar category buttons
document.querySelectorAll(".action-cat-btn").forEach(btn => {
  btn.addEventListener("click", () => _openActionModal(btn.dataset.category));
});

// Modal navigation
el("btn-action-back")?.addEventListener("click", () => {
  _actionStack.pop();
  if (_actionStack.length === 0) { hide("modal-action"); } else { _renderActionModal(); }
});
el("btn-action-close")?.addEventListener("click", () => { hide("modal-action"); _actionStack = []; });
el("modal-action")?.addEventListener("click", e => {
  if (e.target === el("modal-action")) { hide("modal-action"); _actionStack = []; }
});

/* ═══════════════════════════════════════════════════════════════════
   IN-SCENARIO GCS MODAL
   ═══════════════════════════════════════════════════════════════════ */

let _gcsAssessmentSelection = { e: null, v: null, m: null };
let _gcsAssessmentPending = null;
let _gcsAssessmentOptions = {};

function _scenarioGcsPatientPresentation() {
  const scen = state.scenarioData || {};
  const patient = scen.patient || {};
  const scene = scen.scene || {};
  const pieces = [];
  const demo = _deferredPatientInfoParts({ includeDob: true, includeWeight: true }).join(" · ");
  if (demo) pieces.push(demo);
  const gcsDescription = _scenarioGcsChallengeDescription();
  if (gcsDescription) {
    pieces.push(gcsDescription);
  } else if (patient.general_impression) {
    pieces.push(patient.general_impression);
  } else if (scene.description) {
    pieces.push(scene.description);
  } else if (patient.chief_complaint) {
    pieces.push(patient.chief_complaint);
  }
  return pieces.join("\n\n") || "Use your current patient presentation to calculate eye, verbal, and motor response.";
}

function _scenarioGcsChallengeDescription() {
  const authoredGcs = state.scenarioData?.gcs_assessment || state.scenarioData?.gcs_challenge?.expected || state.scenarioData?.patient?.gcs_assessment;
  if (!authoredGcs || typeof authoredGcs !== "object") return "";

  const postIntervention = _assessmentAfterAppliedIntervention(authoredGcs);
  if (postIntervention?.challenge_description) return postIntervention.challenge_description;
  if (postIntervention?.description) return postIntervention.description;

  const currentGcs = Number(state.currentVitals?.gcs ?? state.currentVitals?.GCS);
  const deteriorationDescriptions = authoredGcs.deterioration_descriptions || authoredGcs.deteriorationDescriptions || [];
  if (Number.isFinite(currentGcs) && Array.isArray(deteriorationDescriptions)) {
    const match = deteriorationDescriptions.find(item => {
      if (!item || typeof item !== "object") return false;
      if (Number.isFinite(Number(item.gcs_below)) && currentGcs < Number(item.gcs_below)) return true;
      if (Number.isFinite(Number(item.gcs_above)) && currentGcs > Number(item.gcs_above)) return true;
      return false;
    });
    if (match?.description) return match.description;
  }

  return authoredGcs.challenge_description || authoredGcs.description || "";
}

function _scenarioExpectedGcs() {
  const authoredGcs = state.scenarioData?.gcs_assessment || state.scenarioData?.gcs_challenge?.expected || state.scenarioData?.patient?.gcs_assessment;
  const postInterventionGcs = _assessmentAfterAppliedIntervention(authoredGcs);
  if (postInterventionGcs) {
    const explicitPost = _coerceExpectedGcs(postInterventionGcs);
    if (explicitPost) return explicitPost;
  }
  const explicit = _coerceExpectedGcs(
    authoredGcs
  );
  if (explicit) return explicit;

  const gcs = _findScenarioGcsVital();
  if (!gcs) {
    const presentation = _scenarioGcsPatientPresentation().toLowerCase();
    if (/\b(alert|interactive|oriented|appropriate|follows commands|good tone)\b/.test(presentation)) {
      return { e: 4, v: 5, m: 6, total: 15, exact: true };
    }
    return null;
  }

  if (typeof gcs === "number" && Number.isFinite(gcs)) {
    if (gcs === 15) return { e: 4, v: 5, m: 6, total: 15, exact: true };
    return { total: gcs, exact: false };
  }

  if (typeof gcs === "string") {
    const primitiveMatch = gcs.match(/\bE\s*(\d)\s*V\s*(\d)\s*M\s*(\d)\b/i);
    if (primitiveMatch) {
      const e = Number(primitiveMatch[1]);
      const v = Number(primitiveMatch[2]);
      const m = Number(primitiveMatch[3]);
      return { e, v, m, total: e + v + m, exact: true };
    }
    const primitiveTotal = Number(gcs.match(/\b(\d{1,2})\b/)?.[1]);
    if (Number.isFinite(primitiveTotal)) {
      if (primitiveTotal === 15) return { e: 4, v: 5, m: 6, total: 15, exact: true };
      return { total: primitiveTotal, exact: false };
    }
  }

  const text = [
    gcs.detail,
    gcs.display,
    gcs.label,
    typeof gcs.value === "string" ? gcs.value : "",
  ].filter(Boolean).join(" ");
  const componentMatch = text.match(/\bE\s*(\d)\s*V\s*(\d)\s*M\s*(\d)\b/i);
  if (componentMatch) {
    const e = Number(componentMatch[1]);
    const v = Number(componentMatch[2]);
    const m = Number(componentMatch[3]);
    return { e, v, m, total: e + v + m, exact: true };
  }

  const numericValue = Number(gcs.value);
  if (Number.isFinite(numericValue)) {
    // A normal GCS is unambiguous even when scenario text omits E/V/M detail.
    if (numericValue === 15) return { e: 4, v: 5, m: 6, total: 15, exact: true };
    return { total: numericValue, exact: false };
  }

  const totalMatch = text.match(/\b(\d{1,2})\s*(?:\/\s*15)?\b/);
  if (totalMatch) {
    const total = Number(totalMatch[1]);
    if (Number.isFinite(total)) return { total, exact: false };
  }
  return null;
}

function _assessmentAfterAppliedIntervention(raw) {
  if (!raw || typeof raw !== "object") return null;
  let postStates = raw.after_interventions || raw.afterInterventions || raw.post_intervention || raw.postIntervention || [];
  if (postStates && typeof postStates === "object" && !Array.isArray(postStates)) postStates = [postStates];
  if (!Array.isArray(postStates) || !postStates.length) return null;
  const applied = new Set(state.interventionsApplied || []);
  return postStates.find(item => {
    if (!item || typeof item !== "object") return false;
    const intervention = item.intervention || item.requires_intervention || item.requiresIntervention;
    return intervention && applied.has(intervention);
  }) || null;
}

function _coerceExpectedGcs(raw) {
  if (!raw) return null;
  const coerceAlternates = (source) => {
    const alternates = source?.acceptable || source?.alternates || source?.alternate_components || [];
    if (!Array.isArray(alternates)) return [];
    return alternates.map(item => {
      const copy = item && typeof item === "object" ? { ...item } : item;
      if (copy && typeof copy === "object") {
        delete copy.acceptable;
        delete copy.alternates;
        delete copy.alternate_components;
      }
      return _coerceExpectedGcs(copy);
    }).filter(Boolean);
  };
  if (typeof raw === "number" && Number.isFinite(raw)) {
    return raw === 15
      ? { e: 4, v: 5, m: 6, total: 15, exact: true }
      : { total: raw, exact: false };
  }
  if (typeof raw === "string") {
    const componentMatch = raw.match(/\bE\s*:?\s*(\d)\s*[\/,\s-]*V\s*:?\s*(\d)\s*[\/,\s-]*M\s*:?\s*(\d)\b/i);
    if (componentMatch) {
      const e = Number(componentMatch[1]);
      const v = Number(componentMatch[2]);
      const m = Number(componentMatch[3]);
      return { e, v, m, total: e + v + m, exact: true };
    }
    const total = Number(raw.match(/\b(\d{1,2})\s*(?:\/\s*15)?\b/)?.[1]);
    if (Number.isFinite(total)) {
      return total === 15
        ? { e: 4, v: 5, m: 6, total: 15, exact: true }
        : { total, exact: false };
    }
    return null;
  }
  if (typeof raw === "object") {
    const e = Number(raw.e ?? raw.eye);
    const v = Number(raw.v ?? raw.verbal);
    const m = Number(raw.m ?? raw.motor);
    if ([e, v, m].every(Number.isFinite)) {
      return {
        e,
        v,
        m,
        total: Number(raw.total) || e + v + m,
        exact: raw.exact === false ? false : true,
        rationale: raw.rationale || "",
        acceptable: coerceAlternates(raw),
      };
    }
    const total = Number(raw.total ?? raw.value);
    if (Number.isFinite(total)) {
      return total === 15
        ? { e: 4, v: 5, m: 6, total: 15, exact: true, rationale: raw.rationale || "", acceptable: coerceAlternates(raw) }
        : { total, exact: false, rationale: raw.rationale || "", acceptable: coerceAlternates(raw) };
    }
  }
  return null;
}

function _findScenarioGcsVital() {
  const scen = state.scenarioData || {};
  const direct = [
    scen.vitals?.baseline?.gcs,
    scen.initial_vitals?.gcs,
    scen.starting_vitals?.gcs,
    scen.patient?.vitals?.gcs,
  ].find(Boolean);
  if (direct) return direct;

  const seen = new Set();
  const stack = [scen];
  while (stack.length) {
    const obj = stack.pop();
    if (!obj || typeof obj !== "object" || seen.has(obj)) continue;
    seen.add(obj);
    for (const [key, value] of Object.entries(obj)) {
      if (!value || typeof value !== "object") continue;
      const label = String(value.label || "").toLowerCase();
      const hasGcsShape = "value" in value && (label.includes("gcs") || key.toLowerCase() === "gcs");
      if (hasGcsShape) return value;
      stack.push(value);
    }
  }
  return null;
}

function _setGcsAssessmentFeedback(message = "", kind = "wrong") {
  const feedbackEl = el("gcs-assessment-feedback");
  if (!feedbackEl) return;
  feedbackEl.textContent = message;
  feedbackEl.className = message ? `gcs-verdict ${kind}` : "gcs-verdict hidden";
}

function _resetGcsAssessmentConfirmation() {
  _gcsAssessmentPending = null;
  el("btn-gcs-assessment-submit")?.classList.remove("hidden");
  el("btn-gcs-assessment-continue")?.classList.add("hidden");
}

function _isGcsAssessmentCorrect(selection, expected) {
  if (!expected) return false;
  return !!_matchingExpectedGcs(selection, expected);
}

function _matchingExpectedGcs(selection, expected) {
  if (!expected) return null;
  const total = selection.e + selection.v + selection.m;
  const matches = (candidate) => {
    if (!candidate) return false;
    if (candidate.exact) {
      return selection.e === candidate.e && selection.v === candidate.v && selection.m === candidate.m;
    }
    return total === candidate.total;
  };
  if (matches(expected)) return expected;
  return (expected.acceptable || []).find(matches) || null;
}

function _gcsAssessmentScaleLabel(key, value) {
  const isInfant = _gcsAssessmentType() === "infant";
  const scale = key === "e"
    ? _GCS_SCALES.eye
    : key === "v"
      ? (isInfant ? _GCS_SCALES.verbal_infant : _GCS_SCALES.verbal_child)
      : (isInfant ? _GCS_SCALES.motor_infant : _GCS_SCALES.motor_child);
  const label = scale.find(opt => opt.v === value)?.label || String(value);
  return label.replace(/^\d+\s*—\s*/, "").toLowerCase();
}

function _gcsAssessmentCorrectFeedback(selection, expected) {
  const total = selection.e + selection.v + selection.m;
  const matched = _matchingExpectedGcs(selection, expected) || expected;
  if (matched?.rationale) {
    return `Correct. E${selection.e} V${selection.v} M${selection.m} = ${total}/15. ${matched.rationale}`;
  }
  if (matched?.exact) {
    const eye = _gcsAssessmentScaleLabel("e", selection.e);
    const verbal = _gcsAssessmentScaleLabel("v", selection.v);
    const motor = _gcsAssessmentScaleLabel("m", selection.m);
    return `Correct. E${selection.e} because eye opening is ${eye}; V${selection.v} because verbal response is ${verbal}; M${selection.m} because motor response is ${motor}. Together that gives ${total}/15, matching this patient presentation.`;
  }
  if (expected?.total) {
    return `Correct. Your selected eye, verbal, and motor components total ${total}/15, matching the expected GCS for this patient presentation.`;
  }
  return `GCS calculated as ${total}/15 from E${selection.e}, V${selection.v}, M${selection.m}.`;
}

function _gcsAssessmentType() {
  const age = Number(state.scenarioData?.patient?.age);
  return Number.isFinite(age) && age < 2 ? "infant" : "child";
}

function _updateGcsAssessmentTotal() {
  const totalEl = el("gcs-assessment-total");
  const submitBtn = el("btn-gcs-assessment-submit");
  const vals = [_gcsAssessmentSelection.e, _gcsAssessmentSelection.v, _gcsAssessmentSelection.m];
  const selected = vals.filter(v => v !== null);
  const complete = selected.length === 3;
  if (totalEl) totalEl.textContent = selected.length ? String(selected.reduce((sum, v) => sum + v, 0)) : "—";
  if (submitBtn) submitBtn.disabled = !complete;
}

function _renderGcsAssessmentSections() {
  const sectionsEl = el("gcs-assessment-sections");
  if (!sectionsEl) return;
  const isInfant = _gcsAssessmentType() === "infant";
  const sections = [
    { key: "e", label: "E — Eye Opening", scale: _GCS_SCALES.eye },
    { key: "v", label: isInfant ? "V — Infant Verbal" : "V — Verbal", scale: isInfant ? _GCS_SCALES.verbal_infant : _GCS_SCALES.verbal_child },
    { key: "m", label: "M — Motor", scale: isInfant ? _GCS_SCALES.motor_infant : _GCS_SCALES.motor_child },
  ];
  sectionsEl.innerHTML = sections.map(({ key, label, scale }) => `
    <div class="gcs-section">
      <div class="gcs-section-label">${escapeHTML(label)}</div>
      <div class="gcs-options" data-gcs-key="${key}">
        ${scale.map(opt => {
          const selected = _gcsAssessmentSelection[key] === opt.v;
          return `<button class="gcs-opt-btn ${selected ? "selected" : ""}" data-key="${key}" data-val="${opt.v}">${opt.v}</button>`;
        }).join("")}
      </div>
    </div>
  `).join("");
  sectionsEl.querySelectorAll(".gcs-opt-btn").forEach(btn => {
    btn.addEventListener("click", () => {
      const key = btn.getAttribute("data-key");
      const val = Number(btn.getAttribute("data-val"));
      _gcsAssessmentSelection[key] = val;
      _setGcsAssessmentFeedback("");
      _resetGcsAssessmentConfirmation();
      _renderGcsAssessmentSections();
      _updateGcsAssessmentTotal();
    });
  });
}

function _openGcsAssessmentModal(options = {}) {
  _gcsAssessmentSelection = { e: null, v: null, m: null };
  _gcsAssessmentOptions = {
    suppressAlexEcho: !!options.suppressAlexEcho,
  };
  _resetGcsAssessmentConfirmation();
  setText("gcs-assessment-presentation", _scenarioGcsPatientPresentation());
  _renderGcsAssessmentSections();
  _updateGcsAssessmentTotal();
  _setGcsAssessmentFeedback("");
  show("modal-gcs-assessment");
}

function _closeGcsAssessmentModal() {
  hide("modal-gcs-assessment");
  _gcsAssessmentPending = null;
  _gcsAssessmentOptions = {};
}

async function _submitGcsAssessment() {
  const { e, v, m } = _gcsAssessmentSelection;
  if (e === null || v === null || m === null) return;
  const total = e + v + m;
  const expected = _scenarioExpectedGcs();
  if (!expected) {
    _setGcsAssessmentFeedback("Incorrect, try again.", "wrong");
    return;
  }
  if (!_isGcsAssessmentCorrect({ e, v, m }, expected)) {
    _setGcsAssessmentFeedback("Incorrect, try again.", "wrong");
    return;
  }
  _gcsAssessmentPending = { e, v, m };
  _setGcsAssessmentFeedback(_gcsAssessmentCorrectFeedback(_gcsAssessmentPending, expected), "correct");
  el("btn-gcs-assessment-submit")?.classList.add("hidden");
  el("btn-gcs-assessment-continue")?.classList.remove("hidden");
}

async function _recordGcsAssessment(selection) {
  const { e, v, m } = selection;
  const total = e + v + m;
  _closeGcsAssessmentModal();
  const message = `I calculated GCS ${total}/15 (E${e} V${v} M${m}).`;
  appendUserAction(message, "gcs-assessment");
  _lastUserChatMessage = message;
  // GCS entered through the modal is challenge-gated structured evidence.
  // Source stamping keeps formal GCS credit separate from plain LOC/AVPU,
  // while display remains an exam/challenge finding rather than a vital-sign block.
  _postFinding("vital", "GCS", `${total}/15`, "gcs_modal");
  addPcrExam("GCS Components", `E${e} V${v} M${m}`, "gcs_modal");
  addPcrExam("GCS", `${total} (E${e} V${v} M${m})`, "gcs_modal");
  appendExamFindingInfo("Glasgow Coma Scale", `GCS ${total}/15 (E${e} V${v} M${m})`);
  appendLexiActionFeedback("gcs_calculated", LEXI_ACTION_FEEDBACK.gcs_calculated);
  checkReadiness();
  _orientationFlushQueuedCues();
}

function _userRequestedGcs(message = "") {
  return /\b(gcs|glasgow(?:\s+coma)?(?:\s+scale)?)\b/i.test(String(message || ""));
}

function _normalizeAvpuValue(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  if (/^(a|alert)$/.test(raw)) return "alert";
  if (/^(v|verbal|voice|responds?\s+to\s+voice)$/.test(raw)) return "verbal";
  if (/^(p|pain|painful|responds?\s+to\s+pain)$/.test(raw)) return "pain";
  if (/^(u|unresponsive|unconscious|unresponsive\s+to\s+pain)$/.test(raw)) return "unresponsive";
  return "";
}

function _scenarioExpectedAvpu() {
  const raw = state.scenarioData?.patient?.avpu_assessment || state.scenarioData?.avpu_assessment || null;
  if (raw) {
    const postIntervention = _assessmentAfterAppliedIntervention(raw);
    const source = postIntervention || raw;
    if (typeof source === "string") {
      const value = _normalizeAvpuValue(source);
      if (value) return { value, description: `Level of consciousness is ${value}.`, rationale: "" };
    } else if (typeof source === "object") {
      const value = _normalizeAvpuValue(source.value ?? source.avpu ?? source.loc);
      if (value) {
        return {
          value,
          description: source.description || source.detail || `Level of consciousness is ${value}.`,
          rationale: source.rationale || "",
        };
      }
    }
  }

  const expectedGcs = _scenarioExpectedGcs();
  const total = Number(expectedGcs?.total);
  if (Number.isFinite(total)) {
    if (total >= 15) return { value: "alert", description: "Patient is alert.", rationale: "" };
    if (total >= 9) return { value: "verbal", description: "Patient responds to verbal stimuli but is not fully alert.", rationale: "" };
    if (total >= 4) return { value: "pain", description: "Patient responds only to painful stimuli.", rationale: "" };
    return { value: "unresponsive", description: "Patient is unresponsive.", rationale: "" };
  }

  return { value: "alert", description: "Patient is alert.", rationale: "" };
}

function _userRequestedAvpuOnly(message = "") {
  const msg = String(message || "");
  if (!_userRequestedAvpu(msg)) return false;
  // Mixed requests like "blood glucose and AVPU" should still go through the
  // normal chat/vitals path unless the action modal split them for us.
  return !/\b(blood\s*glucose|bgl|glucose|blood\s*sugar|bp|blood pressure|spo2|pulse ox|heart rate|respiratory rate|temperature|skin|vitals?)\b/i.test(msg);
}

function _userRequestedAvpu(message = "") {
  const msg = String(message || "");
  if (_userRequestedGcs(msg)) return false;
  return /\b(avpu|level of consciousness|loc|responsive(?:ness)?|respond(?:ing|s)? to (?:voice|verbal|pain)|respond(?:ing|s)? (?:only )?to painful stimuli?|painful stimuli?|unresponsive|alert\s+and\s+orient|orient(?:ed|ation)?\s+(?:to\s+)?(?:person|place|time|event))\b/i.test(msg)
    || /\b(?:is|are|appears?|seems?|looks?|patient|pt)\b.{0,24}\b(?:alert|verbal|unresponsive)\b/i.test(msg)
    || /\ba\s*[&+]\s*o(?:\s*[×x]\s*[1-4])?\b/i.test(msg);
}

async function _recordAvpuAssessment(message, options = {}) {
  const {
    chipId = null,
    isAction = false,
    appendUser = true,
    appendResponse = true,
    source = null,
  } = options;
  const evidenceSource = source || (isAction ? "avpu_quick_action" : "authored_vitals");
  const assessment = _scenarioExpectedAvpu();
  if (appendUser) {
    if (isAction) appendUserAction(message, chipId);
    else appendUserMessage(message);
    _lastUserChatMessage = message;
  }
  addPcrExam("LOC", assessment.value, evidenceSource);
  if (assessment.description) addPcrExam("Mental Status", assessment.description, evidenceSource);
  // Persist AVPU as structured evidence for LOC/reassessment scoring, but do
  // not render it in the visible Vital Signs block. AVPU is a neuro/LOC check,
  // not a baseline vital-sign set.
  _postFinding("vital", "AVPU", assessment.value, evidenceSource);
  if (appendResponse) {
    appendExamFindingInfo("Level of Consciousness", assessment.description || assessment.value);
  }
  appendLexiActionFeedback("avpu_assessed", LEXI_ACTION_FEEDBACK.avpu_assessed);
  checkReadiness();
  if (appendUser && !isAction) _orientationFireCue("after_first_message");
  _orientationFlushQueuedCues();
  return assessment;
}

function _scenarioExpectedBreathingAssessment() {
  const s = state.scenarioData || {};
  const pat = s.patient?.pat || {};
  const baseline = s.vitals?.baseline || {};
  const authoredAirway = s.patient?.airway_assessment || s.airway_assessment || {};
  const wobSpec = baseline.work_of_breathing || baseline.wob || null;
  const wobValue = typeof wobSpec === "object" && wobSpec
    ? (wobSpec.value || wobSpec.display || wobSpec.detail || "")
    : (typeof wobSpec === "string" ? wobSpec : "");
  const patWob = typeof pat.work_of_breathing === "object" && pat.work_of_breathing
    ? (pat.work_of_breathing.value || pat.work_of_breathing.display || pat.work_of_breathing.detail || "")
    : (pat.work_of_breathing || "");
  let source = String(wobValue || patWob || "");
  const impression = String(pat.impression || s.patient?.general_impression || "");
  const textSource = `${source} ${impression}`.toLowerCase();

  let airway = "";
  if (authoredAirway && typeof authoredAirway === "object" && (authoredAirway.status || authoredAirway.description)) {
    const status = String(authoredAirway.status || "").trim();
    const description = String(authoredAirway.description || "").trim();
    airway = description || `Airway is ${status}.`;
  }
  if (!airway) airway = "Airway appears patent.";
  if (!authoredAirway?.status && /\b(partial|upper airway|obstruct|stridor|chok|foreign body|cough|not protected|unprotected|gurgling|secretions|saliva)\b/i.test(textSource)) {
    airway = "Airway is maintained — noisy airflow audible; partial upper-airway obstruction possible. Monitor closely.";
  }
  if (/\b(complete obstruction|silent chest|apneic|apnea|agonal|not breathing|no effective respiratory effort)\b/i.test(textSource)) {
    airway = "Airway and breathing are not adequate; immediate airway and ventilatory support are needed.";
  }

  if (!source && /\b(stridor|cough|chok|foreign body|partial|obstruct)\b/i.test(textSource)) {
    source = "Abnormal - forceful coughing with concern for partial upper-airway obstruction; air movement is present but must be monitored closely.";
  }
  const wob = source || "No increased work of breathing is documented.";
  return {
    airway,
    wob,
    description: `${airway} Work of breathing is ${wob}`,
  };
}

async function _recordBreathingAssessment(message, options = {}) {
  const { chipId = null, isAction = false, appendUser = true } = options;
  const assessment = _scenarioExpectedBreathingAssessment();
  if (appendUser) {
    if (isAction) appendUserAction(message, chipId);
    else appendUserMessage(message);
    _lastUserChatMessage = message;
  }
  addPcrExam("Airway", assessment.airway);
  addPcrExam("WOB", assessment.wob);
  appendExamFindingInfo("Airway / Breathing", assessment.description);
  appendLexiActionFeedback("airway_breathing_assessed", LEXI_ACTION_FEEDBACK.airway_breathing_assessed);
  checkReadiness();
  if (appendUser && !isAction) _orientationFireCue("after_first_message");
  _orientationFlushQueuedCues();
}

el("btn-gcs-assessment-close")?.addEventListener("click", _closeGcsAssessmentModal);
el("btn-gcs-assessment-submit")?.addEventListener("click", _submitGcsAssessment);
el("btn-gcs-assessment-continue")?.addEventListener("click", () => {
  if (_gcsAssessmentPending) _recordGcsAssessment(_gcsAssessmentPending);
});
el("modal-gcs-assessment")?.addEventListener("click", e => {
  if (e.target === el("modal-gcs-assessment")) _closeGcsAssessmentModal();
});

/* ═══════════════════════════════════════════════════════════════════
   LEXI PANEL (right column)
   ═══════════════════════════════════════════════════════════════════ */

function appendLexiBot(text) {
  const container = el("lexi-messages");
  const div = document.createElement("div");
  div.className = "lexi-msg-bot";
  div.textContent = text;
  container.appendChild(div);
  container.scrollTop = container.scrollHeight;
  return div;
}

function appendLexiActionFeedback(key = "", message = "") {
  if (!key || !message) return null;
  if (!(state._lexiActionFeedbackShown instanceof Set)) {
    state._lexiActionFeedbackShown = new Set();
  }
  if (state._lexiActionFeedbackShown.has(key)) return null;
  state._lexiActionFeedbackShown.add(key);
  return appendLexiBot(message);
}

function _clearLexiIdleCheckinTimer() {
  if (_lexiIdleCheckinTimer) {
    clearTimeout(_lexiIdleCheckinTimer);
    _lexiIdleCheckinTimer = null;
  }
}

function _lexiIdleCheckinActive() {
  return Boolean(
    state.sessionId &&
    state.simTimersStarted &&
    !el("screen-sim")?.classList.contains("hidden")
  );
}

function _scheduleLexiIdleCheckin() {
  _clearLexiIdleCheckinTimer();
  if (!_lexiIdleCheckinActive()) return;
  const lastActivityAt = Number(state._lastSimLearnerActivityAt || Date.now());
  const elapsed = Math.max(0, Date.now() - lastActivityAt);
  const delay = Math.max(1000, LEXI_IDLE_CHECKIN_MS - elapsed);
  _lexiIdleCheckinTimer = setTimeout(_maybeShowLexiIdleCheckin, delay);
}

function _markSimLearnerActivityForLexiIdle() {
  state._lastSimLearnerActivityAt = Date.now();
  state._lexiIdleCheckinShown = false;
  _scheduleLexiIdleCheckin();
}

function _maybeShowLexiIdleCheckin() {
  _lexiIdleCheckinTimer = null;
  if (!_lexiIdleCheckinActive()) return;
  const elapsed = Date.now() - Number(state._lastSimLearnerActivityAt || Date.now());
  if (elapsed < LEXI_IDLE_CHECKIN_MS) {
    _scheduleLexiIdleCheckin();
    return;
  }
  if (state._lexiIdleCheckinShown) return;
  state._lexiIdleCheckinShown = true;
  appendLexiBot("Still with you. When you're ready, continue with your next assessment, treatment, reassessment, or handoff.");
}

const LEXI_ACTION_FEEDBACK = Object.freeze({
  avpu_assessed: "Good LOC check. That anchors the rest of your primary survey.",
  airway_breathing_assessed: "Good airway and breathing assessment. Keep trending work of breathing after interventions.",
  pulse_assessed: "Good circulation check. Pulse quality helps frame how sick the patient is.",
  vitals_obtained: "Good baseline vitals. Those numbers give you something meaningful to reassess against.",
  gcs_calculated: "Nice GCS calculation. E/V/M components give the receiving crew a reproducible neuro baseline.",
  primary_survey: "Good primary survey. You identified immediate threats before getting pulled into details.",
  secondary_assessment: "Good secondary assessment. Now add focused detail on the affected area or abnormal findings.",
  focused_exam: "Good focused exam. That detail supports your clinical impression and handoff.",
  reassessment: "Good reassessment. Trending the patient after treatment tells you whether your plan is working.",
  intervention_airway: "Good airway intervention. Reassess breath sounds, SpO2, and work of breathing next.",
  intervention_oxygen: "Good oxygen support. Recheck SpO2 and respiratory effort to confirm response.",
  intervention_medication: "Good medication administration. Reassess the patient and document the response.",
  intervention_bleeding: "Good hemorrhage control. Reassess bleeding, perfusion, and mental status.",
  intervention_positioning: "Good positioning. That can immediately reduce airway or breathing risk.",
  intervention_general: "Good priority intervention. Reassess the patient and update your handoff.",
});

function _lexiFeedbackKeyForIntervention(interventionId = "", label = "") {
  const text = `${interventionId || ""} ${label || ""}`.toLowerCase();
  if (/\b(suction|airway|bvm|adjunct|opa|npa|ventilat)/.test(text)) return "intervention_airway";
  if (/\b(o2|oxygen|nrb|nasal\s+cannula|blow[-\s]?by|cpap)\b/.test(text)) return "intervention_oxygen";
  if (/\b(albuterol|epinephrine|epi\b|glucose|naloxone|medication|mg|mcg|ml)\b/.test(text)) return "intervention_medication";
  if (/\b(bleed|bleeding|hemorrhage|direct\s+pressure|pressure\s+dressing|tourniquet|wound)\b/.test(text)) return "intervention_bleeding";
  if (/\b(position|upright|recovery|lateral|comfort|calm|stimulation)\b/.test(text)) return "intervention_positioning";
  return "intervention_general";
}

function _appendLexiInterventionFeedback(interventionId = "", label = "") {
  const categoryKey = _lexiFeedbackKeyForIntervention(interventionId, label);
  const message = LEXI_ACTION_FEEDBACK[categoryKey] || LEXI_ACTION_FEEDBACK.intervention_general;
  const stableKey = `intervention:${interventionId || categoryKey}`;
  return appendLexiActionFeedback(stableKey, message);
}

function appendLexiUser(text) {
  const container = el("lexi-messages");
  const div = document.createElement("div");
  div.className = "lexi-msg-user";
  div.textContent = text;
  container.appendChild(div);
  container.scrollTop = container.scrollHeight;
  return div;
}

function appendLexiTyping() {
  const container = el("lexi-messages");
  const div = document.createElement("div");
  div.className = "lexi-msg-bot";
  div.innerHTML = `<div class="typing-dots"><span></span><span></span><span></span></div>`;
  container.appendChild(div);
  container.scrollTop = container.scrollHeight;
  return div;
}

async function sendLexiMessage(message) {
  if (!message.trim() || !state.sessionId) return;
  _markSimLearnerActivityForLexiIdle();
  appendLexiUser(message);
  const typingEl = appendLexiTyping();

  const historySnapshot = [...state.lexiHistory];
  state.lexiHistory.push({ role: "user", content: message });

  try {
    const res = await authFetch(`${API}/api/lexi`, {
      method: "POST",
      body: JSON.stringify({
        session_id: state.sessionId,
        message,
        history: historySnapshot,
      }),
    });

    if (!res.ok) { typingEl.remove(); appendLexiBot("I was off chasing squirrels and missed that one. Try again! 🐿️"); return; }

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "", responseText = "", botEl = null;

    let doneSeen = false;
    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        buffer += decoder.decode();
      } else {
        buffer += decoder.decode(value, { stream: true });
      }
      const lines = buffer.split("\n");
      buffer = done ? "" : lines.pop();
      const dataLines = done ? _extractSseDataLines(lines.join("\n")) : lines.map(line => line.trim()).filter(line => line.startsWith("data: ")).map(line => line.slice(6));
      for (const data of dataLines) {
        if (data === "[DONE]") { doneSeen = true; break; }
        try {
          const parsed = JSON.parse(data);
          if (parsed.text) {
            responseText += parsed.text;
            if (!botEl) { typingEl.remove(); botEl = appendLexiBot(""); }
            botEl.textContent = responseText;
            el("lexi-messages").scrollTop = el("lexi-messages").scrollHeight;
          }
        } catch { /* partial chunk */ }
      }
      if (done || doneSeen) break;
    }
    if (!botEl) {
      typingEl.remove();
      botEl = appendLexiBot(responseText || "Woof — I didn't get a usable response that time. Ask me again! 🐾");
    }

    state.lexiHistory.push({ role: "assistant", content: responseText });
    _orientationMarkLexiInteraction();
  } catch {
    typingEl.remove();
    appendLexiBot("Woof — lost my train of thought there. Ask me again! 🐾");
  }
}

// ── Treats system ────────────────────────────────────────────
function updateTreatDisplay() {
  const game = loadGamification();
  const count = game.treats ?? 0;
  setText("lexi-treat-count", count);
  const btn = el("btn-give-treat");
  if (btn) {
    btn.disabled = count < 1;
    btn.className = count < 1
      ? "bg-gray-700 text-gray-500 px-2 py-1 rounded text-xs font-semibold cursor-not-allowed"
      : "bg-amber-700 hover:bg-amber-600 text-white px-2 py-1 rounded text-xs font-semibold transition-colors";
  }
}

el("btn-give-treat").addEventListener("click", () => {
  const game = loadGamification();
  if ((game.treats ?? 0) < 1) return;
  isPopupOpen = true;  // Prevent TTS while popup is open
  show("modal-treat-confirm");
});

el("btn-treat-cancel").addEventListener("click", () => {
  hide("modal-treat-confirm");
  isPopupOpen = false;  // Allow TTS now that popup is closed
  speakPendingIfAny();  // Speak any queued response
});

el("btn-treat-confirm").addEventListener("click", () => {
  hide("modal-treat-confirm");
  isPopupOpen = false;  // Allow TTS now that popup is closed
  speakPendingIfAny();  // Speak any queued response
  sendLexiTreatHint();
});

async function sendLexiTreatHint() {
  if (!state.sessionId) return;

  // Deduct treat server-side first; server issues a single-use refund token
  const game = loadGamification();
  if ((game.treats ?? 0) < 1) return;
  let spendToken = null;
  try {
    const spendRes = await authFetch(`${API}/api/me/treats/spend`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ session_id: state.sessionId }),
    });
    if (!spendRes.ok) {
      const errData = await spendRes.json().catch(() => ({}));
      showToast(errData.detail || "Could not use treat — session may be inactive.", "error");
      return;
    }
    const spendData = await spendRes.json();
    game.treats = spendData.treats;
    spendToken = spendData.token;
  } catch { appendLexiBot("Couldn't connect — try again in a moment. 🐾"); return; }
  _progressCache = game;
  updateTreatDisplay();

  appendLexiUser("Here's a treat, Lexi! What should I do next?");
  const typingEl = appendLexiTyping();
  const historySnapshot = [...state.lexiHistory];
  state.lexiHistory.push({ role: "user", content: "Here's a treat, Lexi! What should I do next?" });

  try {
    const res = await authFetch(`${API}/api/lexi`, {
      method: "POST",
      body: JSON.stringify({
        session_id: state.sessionId,
        message: "What should I do right now in this scenario? Give me your best scenario-specific hint.",
        history: historySnapshot,
        treat_hint: true,
      }),
    });

    if (!res.ok) {
      typingEl.remove();
      if (spendToken) {
        authFetch(`${API}/api/me/treats/refund`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ token: spendToken }),
        }).then(r => r.json()).then(d => {
          const g = loadGamification(); g.treats = d.treats; _progressCache = g; updateTreatDisplay();
        }).catch(() => {});
      }
      appendLexiBot("Lexi is busy right now — treat refunded! Try again in a moment. 🐾");
      return;
    }

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "", responseText = "", botEl = null;

    let doneSeen = false;
    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        buffer += decoder.decode();
      } else {
        buffer += decoder.decode(value, { stream: true });
      }
      const lines = buffer.split("\n");
      buffer = done ? "" : lines.pop();
      const dataLines = done ? _extractSseDataLines(lines.join("\n")) : lines.map(line => line.trim()).filter(line => line.startsWith("data: ")).map(line => line.slice(6));
      for (const data of dataLines) {
        if (data === "[DONE]") { doneSeen = true; break; }
        try {
          const parsed = JSON.parse(data);
          if (parsed.text) {
            responseText += parsed.text;
            if (!botEl) { typingEl.remove(); botEl = appendLexiBot(""); }
            botEl.textContent = responseText;
            el("lexi-messages").scrollTop = el("lexi-messages").scrollHeight;
          }
        } catch { /* partial chunk */ }
      }
      if (done || doneSeen) break;
    }
    if (!botEl) {
      typingEl.remove();
      botEl = appendLexiBot(responseText || "I didn't get the whole hint out that time, but your treat still counts. Ask me again if you want another try. 🐾");
    }
    state.lexiHistory.push({ role: "assistant", content: responseText });
    state._lexiGuidedMode = true;  // treat hint given — next actions are Lexi-directed
    _orientationMarkLexiInteraction();
  } catch {
    typingEl.remove();
    if (spendToken) {
      authFetch(`${API}/api/me/treats/refund`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ token: spendToken }),
      }).then(r => r.json()).then(d => {
        const g = loadGamification(); g.treats = d.treats; _progressCache = g; updateTreatDisplay();
      }).catch(() => {});
    }
    appendLexiBot("*drops treat, chases squirrel* Sorry — Lexi is busy right now. Your treat was refunded! Try again in a moment. 🐾");
  }
}

// Lexi text input
function _resizeLexiInput() {
  const input = el("lexi-input");
  if (!input) return;
  input.style.height = "auto";
  input.style.height = `${Math.min(input.scrollHeight, 112)}px`;
  _syncSimMobileOffsets();
}

el("btn-lexi-send").addEventListener("click", () => {
  const input = el("lexi-input");
  const msg = input.value.trim();
  if (msg) { input.value = ""; _resizeLexiInput(); sendLexiMessage(msg); }
});

el("lexi-input").addEventListener("input", _resizeLexiInput);
el("lexi-input").addEventListener("focus", () => setTimeout(_syncSimMobileOffsets, 0));
el("lexi-input").addEventListener("blur", () => setTimeout(_syncSimMobileOffsets, 0));

el("lexi-input").addEventListener("keydown", e => {
  if (e.key === "Enter" && !e.shiftKey) {
    e.preventDefault();
    const msg = e.target.value.trim();
    if (msg) { e.target.value = ""; _resizeLexiInput(); sendLexiMessage(msg); }
  }
});

