// Built from scenario data at startSim time: id → {label, popup_type, popup_default, popup_config, ...}
let _interventionById = {};
// Queue of popup interventions detected in one AI response — worked through one at a time
let _pendingPopupQueue = [];
// Impression challenge is backend-triggered after primary survey. It should open
// as soon as the triggering response finishes unless another clinical modal is active.
let _pendingImpChallenge = null;
let _impressionChallengeCompleted = false;
let _turnoverTreatmentPromise = null;
// Currently selected O2 device button
let _o2SelectedDevice = "nrb";

function buildInterventionIndex() {
  _interventionById = {};

  const avail = state.scenarioData?.available_interventions || [];
  for (const iv of avail) {
    _interventionById[iv.id] = iv;
  }
}

// Returns "infant" / "pediatric" / "adult" for body map variant selection (Phase 4)
function getPatientSilhouetteType(age) {
  const n = parseInt(age, 10);
  if (isNaN(n) || n < 2) return "infant";
  if (n <= 12) return "pediatric";
  return "adult";
}

// buildJumpBag and buildChipRow removed — replaced by action bar + action modal

// Find a scenario intervention by label (exact match first, then pattern match from scenario data)
function findInterventionByLabel(label) {
  const lower = label.toLowerCase();

  // Exact label match
  for (const iv of Object.values(_interventionById)) {
    if (iv.label.toLowerCase() === lower) return iv;
  }

  // Pattern match using each intervention's own detection_patterns from scenario data
  // This avoids hardcoding drug names — any scenario's interventions will work automatically
  const avail = state.scenarioData?.available_interventions || [];
  for (const iv of avail) {
    const full = _interventionById[iv.id];
    if (!full) continue;
    const patterns = full.detection_patterns || [];
    for (const pat of patterns) {
      try {
        if (new RegExp(pat, "i").test(lower)) return full;
      } catch { /* invalid regex — skip */ }
    }
  }
  return null;
}

function _actionMenuInterventionCandidate(item = {}) {
  const itemText = `${item.label || ""} ${item.payload || ""}`;
  if (_cspineExamRequested(itemText)) return null;
  if (/\bprimary\s+survey\b/i.test(itemText)) return null;

  const id = item.interventionId || item.intervention_id;
  if (id && _interventionById[id]) return _interventionById[id];

  const direct = [
    item.label,
    item.payload,
    `${item.label || ""} ${item.payload || ""}`,
  ].filter(Boolean)
    .map(text => findInterventionByLabel(String(text)))
    .find(Boolean);
  if (direct) return direct;

  const text = itemText.toLowerCase();
  const fallbackIds = [];
  if (/\bdry\s+sterile\s+dress|dry.*dressing|sterile.*dressing\b/.test(text)) {
    fallbackIds.push("dry_dressing", "direct_pressure");
  }
  if (/\bwet\s+(?:or\s+moist\s+)?dress|moist\s+dress|saline\s+dress/.test(text)) {
    fallbackIds.push("wet_dressing");
  }
  if (/\bpressure\s+(?:dressing|bandage)|direct\s+(?:manual\s+)?pressure|bleeding\s+control|control\s+bleed/.test(text)) {
    fallbackIds.push("direct_pressure");
  }
  if (/\bprevent\s+hypothermia|cover(?:ing)?\s+the\s+patient|blanket/.test(text)) {
    fallbackIds.push("prevent_hypothermia");
  }

  return fallbackIds.map(candidateId => _interventionById[candidateId]).find(Boolean) || null;
}

async function _handleActionMenuInterventionItem(item = {}, source = "action_menu") {
  if (!item?.payload || _isOrientationScenarioActive()) return false;
  const intervention = _actionMenuInterventionCandidate(item);
  if (!intervention || intervention.requires_popup || intervention.popup_type) return false;
  appendUserAction(item.payload, source);
  _lastUserChatMessage = item.payload;
  await applyInterventionAndRecord(intervention.id, intervention.label || item.label || item.payload, { source });
  return true;
}

// O2 device → intervention ID mapping
const O2_DEVICE_INTERVENTION = {
  nc:   "o2_nc",
  nrb:  "o2_nrb",
  bvm:  "bvm",
  cpap: "cpap",
};

function showO2Popup(intervention) {
  const rawDefaultDevice = intervention?.popup_default?.device || "nrb";
  const defaultDevice = rawDefaultDevice === "blowby" ? "nrb" : rawDefaultDevice;
  _o2SelectedDevice = defaultDevice;

  // Set patient context line
  const vitals = state.scenarioData?.vitals?.baseline || {};
  const spo2Val = vitals.spo2?.value ?? "—";
  const patientInfo = _deferredPatientInfoParts({ includeDob: false, includeWeight: false }).join(" · ") || "Patient";
  setText("o2-popup-patient-info", `${patientInfo} · SpO₂ ${spo2Val}% · Target ≥ 94%`);

  // Reset blow-by on each open; learners explicitly opt into blow-by.
  const blowbyEl = el("o2-blowby");
  if (blowbyEl) blowbyEl.checked = false;

  // Highlight default device button
  document.querySelectorAll(".o2-device-btn").forEach(btn => {
    const selected = btn.dataset.device === defaultDevice;
    btn.classList.toggle("border-blue-600", selected);
    btn.classList.toggle("bg-blue-900/30", selected);
    btn.classList.toggle("border-gray-700", !selected);
    btn.classList.toggle("bg-gray-800", !selected);
  });

  // Set flow rate
  const btn = document.querySelector(`.o2-device-btn[data-device="${defaultDevice}"]`);
  if (btn) updateO2FlowForDevice(btn);

  isPopupOpen = true;  // Prevent TTS while popup is open
  show("modal-o2-admin");
}

function updateO2FlowForDevice(btn) {
  const min = parseInt(btn.dataset.flowMin) || 0;
  const max = parseInt(btn.dataset.flowMax) || 0;
  const def = parseInt(btn.dataset.flowDefault) || 0;
  const device = btn.dataset.device;

  const flowRow = el("o2-flow-row");
  const flowInput = el("o2-flow-input");
  const flowRange = el("o2-flow-range");

  const blowbyLabel = el("o2-blowby-label");
  const blowby      = el("o2-blowby");
  if (blowbyLabel) blowbyLabel.classList.remove("hidden");

  if (device === "cpap" || device === "bvm" || device === "nc") {
    // CPAP uses pressure / BVM is assisted ventilation. MI pediatric blow-by
    // uses mask hardware held near the face, not nasal cannula tubing.
    if (flowRow) flowRow.classList.toggle("hidden", device === "cpap");
    if (blowby) blowby.checked = false;
  } else {
    if (flowRow) flowRow.classList.remove("hidden");
    const isBlowby = !!blowby?.checked;
    const flowMin = isBlowby ? 10 : min;
    const flowMax = isBlowby ? 15 : max;
    const flowDefault = isBlowby ? 15 : def;
    if (flowInput) {
      flowInput.min = flowMin;
      flowInput.max = flowMax;
      const current = parseInt(flowInput.value, 10);
      flowInput.value = Number.isFinite(current) && current >= flowMin && current <= flowMax
        ? current
        : flowDefault;
    }
    if (flowRange) {
      const deliveryLabel = isBlowby ? "blow-by" : "standard";
      flowRange.textContent = flowMin === flowMax ? `${flowMin} LPM · ${deliveryLabel}` : `(${flowMin}–${flowMax} LPM · ${deliveryLabel})`;
    }
  }
}

// Wire O2 device buttons
document.querySelectorAll(".o2-device-btn").forEach(btn => {
  btn.addEventListener("click", () => {
    _o2SelectedDevice = btn.dataset.device;
    document.querySelectorAll(".o2-device-btn").forEach(b => {
      const sel = b === btn;
      b.classList.toggle("border-blue-600", sel);
      b.classList.toggle("bg-blue-900/30", sel);
      b.classList.toggle("border-gray-700", !sel);
      b.classList.toggle("bg-gray-800", !sel);
    });
    updateO2FlowForDevice(btn);
  });
});

el("o2-blowby")?.addEventListener("change", () => {
  if (el("o2-blowby")?.checked && _o2SelectedDevice !== "nrb") {
    const nrbBtn = document.querySelector('.o2-device-btn[data-device="nrb"]');
    nrbBtn?.click();
    return;
  }
  const btn = document.querySelector(`.o2-device-btn[data-device="${_o2SelectedDevice || "nrb"}"]`);
  if (btn) updateO2FlowForDevice(btn);
});

el("btn-o2-cancel").addEventListener("click", () => {
  hide("modal-o2-admin");
  isPopupOpen = false;  // Allow TTS now that popup is closed
  speakPendingIfAny();  // Speak any queued response
  setTimeout(advanceInterventionQueue, 200);
});

el("btn-o2-confirm").addEventListener("click", async () => {
  const device = _o2SelectedDevice;
  const blowby = el("o2-blowby")?.checked;
  const isBlowby = blowby && device === "nrb";
  const interventionId = isBlowby
    ? "o2_blowby"
    : (O2_DEVICE_INTERVENTION[device] || "o2_nrb");
  let pcrLabel;
  if (device === "cpap") {
    pcrLabel = "O₂ via CPAP — 5 cmH₂O PEEP";
  } else {
    const flow = el("o2-flow-input")?.value || "?";
    const deviceNames = { nc: "Nasal Cannula (NC)", nrb: "Non-Rebreather Mask (NRB)", bvm: "BVM with O₂" };
    if (isBlowby && device === "nrb") {
      pcrLabel = `Blow-by O₂ held near face — ${flow} LPM`;
    } else {
      pcrLabel = `O₂ via ${deviceNames[device] || device.toUpperCase()} — ${flow} LPM`;
    }
  }

  hide("modal-o2-admin");
  isPopupOpen = false;  // Allow TTS now that popup is closed
  speakPendingIfAny();  // Speak any queued response
  await applyInterventionAndRecord(interventionId, pcrLabel);
  setTimeout(advanceInterventionQueue, 200);
});

function _showPendingIcThen(onDone) {
  if (!_pendingImpChallenge) { onDone(); return; }
  const _ca = _pendingImpChallenge;
  _pendingImpChallenge = null;
  _openChallengeModal(
    _ca.type, _ca.data, _ca.challenge_id || "default",
    (result) => {
      _capturePcrPrimaryImpression(result?.student_answer);
      _impressionChallengeCompleted = true;
      onDone();
    },
    () => { _pendingImpChallenge = _ca; _pendingPopupQueue = []; }  // deferred: restore challenge, drop stale queue items
  );
}

function _openOrQueueImpressionChallenge(challenge) {
  if (!challenge || _impressionChallengeCompleted) return;
  _pendingImpChallenge = challenge;
}

function _resumePendingImpressionChallengeAfterModal() {
  if (!_pendingImpChallenge || _impressionChallengeCompleted) return false;
  setTimeout(() => {
    if (!isPopupOpen) _showPendingIcThen(() => setTimeout(advanceInterventionQueue, 50));
  }, 150);
  return true;
}

function _scenarioImpressionChallengePayload() {
  if (_pendingImpChallenge) return _pendingImpChallenge;
  if (_impressionChallengeCompleted) return null;
  const ic = state.scenarioData?.impression_challenge || {};
  if (!ic.enabled) return null;
  return {
    type: "impression",
    challenge_id: "default",
    data: {
      title: "Clinical Impression",
      subtitle: "Based on your primary survey — choose your working impression.",
      prompt: ic.prompt || "Based on your initial assessment, what is your primary clinical impression?",
      options: Array.isArray(ic.options) ? ic.options : [],
    },
  };
}

function _ensureImpressionChallengeBeforeHandoff(onDone) {
  const challenge = _scenarioImpressionChallengePayload();
  if (!challenge) { onDone(); return; }
  _pendingImpChallenge = null;
  _openChallengeModal(
    challenge.type,
    challenge.data,
    challenge.challenge_id || "default",
    (result) => {
      _capturePcrPrimaryImpression(result?.student_answer);
      _impressionChallengeCompleted = true;
      onDone();
    },
    () => { _pendingImpChallenge = challenge; _pendingPopupQueue = []; }
  );
}

function _ensureImpressionChallengeBeforeMedication(onDone) {
  const challenge = _scenarioImpressionChallengePayload();
  if (!challenge) { onDone(); return; }
  _pendingImpChallenge = null;
  _openChallengeModal(
    challenge.type,
    challenge.data,
    challenge.challenge_id || "default",
    (result) => {
      _capturePcrPrimaryImpression(result?.student_answer);
      _impressionChallengeCompleted = true;
      onDone();
    },
    () => { _pendingImpChallenge = challenge; }
  );
}

function showMedPopup(intervention) {
  if (!_impressionChallengeCompleted && _scenarioImpressionChallengePayload()) {
    _ensureImpressionChallengeBeforeMedication(() => showMedPopup(intervention));
    return;
  }

  _activeMedIntervention = intervention;
  const cfg = intervention?.popup_config || {};

  setText("med-popup-patient-info", _deferredPatientInfoParts({ includeDob: true, includeWeight: true }).join(" · "));
  setText("med-drug-name",          cfg.drug  || intervention.label);
  setText("med-drug-concentration", cfg.concentration || cfg.dose || "—");
  setText("med-drug-route",         cfg.route || "—");
  setText("med-drug-dose",          cfg.dose  || "—");
  setText("med-drug-scope",         cfg.scope || "—");

  // Cross-check notice (WMRMCC 9-1S)
  const noticeEl   = el("med-crosscheck-notice");
  const noticeText = el("med-crosscheck-notice-text");
  if (cfg.cross_check_notice && noticeEl && noticeText) {
    noticeText.textContent = cfg.cross_check_notice;
    show("med-crosscheck-notice");
  } else if (noticeEl) {
    hide("med-crosscheck-notice");
  }

  // Pre-fill dose input
  const doseInput = el("med-dose-input");
  if (doseInput) doseInput.value = cfg.dose || "";

  // Build 6-Rights cross-check boxes (supports both string[] and {label, right}[])
  const container = el("med-cross-checks");
  container.innerHTML = "";
  const checks = cfg.cross_checks || [];
  checks.forEach((check, i) => {
    const label = typeof check === "string" ? check : check.label;
    const rightKey = typeof check === "object" ? check.right : null;
    const id = `check-${i}`;
    const item = document.createElement("label");
    item.className = "flex items-start gap-2.5 cursor-pointer select-none group";

    const badge = rightKey
      ? `<span class="shrink-0 text-xs px-1.5 py-0.5 rounded bg-gray-700 text-gray-400 uppercase tracking-wide font-semibold leading-none mt-0.5">${rightKey === "crosscheck" ? "✓ X-CHK" : rightKey}</span>`
      : "";

    item.innerHTML = `
      <input type="checkbox" id="${id}" class="med-check mt-0.5 w-4 h-4 rounded accent-green-500 shrink-0" />
      <span class="text-gray-300 text-sm leading-snug flex-1">${escapeHTML(label)}</span>
      ${badge}`;
    container.appendChild(item);
    item.querySelector("input").addEventListener("change", updateMedConfirmBtn);
  });

  // Procedure steps (collapsible)
  const stepsSection = el("med-procedure-section");
  const stepsList = el("med-steps-list");
  const steps = cfg.procedure_steps || [];
  if (steps.length && stepsSection && stepsList) {
    stepsList.innerHTML = steps.map(s => `<li>${escapeHTML(s)}</li>`).join("");
    show("med-procedure-section");
    hide("med-procedure-steps");  // collapsed by default
    setText("med-steps-arrow", "›");
  } else if (stepsSection) {
    hide("med-procedure-section");
  }

  updateMedConfirmBtn();
  isPopupOpen = true;  // Prevent TTS while popup is open
  show("modal-med-admin");
}

function updateMedConfirmBtn() {
  const allChecked = [...document.querySelectorAll(".med-check")].every(c => c.checked);
  const dose = el("med-dose-input")?.value?.trim();
  const btn = el("btn-med-confirm");
  if (!btn) return;

  const ready = allChecked && !!dose;
  btn.disabled = !ready;
  if (ready) {
    btn.className = "flex-1 bg-green-700 hover:bg-green-600 text-white font-semibold py-2.5 rounded-lg text-sm transition-colors cursor-pointer";
    btn.textContent = "Administer ✓";
  } else {
    btn.className = "flex-1 bg-gray-600 text-gray-400 font-semibold py-2.5 rounded-lg text-sm cursor-not-allowed transition-colors";
    btn.textContent = allChecked ? "Enter dose first" : "Confirm all checks first";
  }
}

el("med-dose-input").addEventListener("input", updateMedConfirmBtn);

el("btn-med-steps-toggle").addEventListener("click", () => {
  const stepsDiv = el("med-procedure-steps");
  const arrow = el("med-steps-arrow");
  if (!stepsDiv) return;
  const visible = !stepsDiv.classList.contains("hidden");
  stepsDiv.classList.toggle("hidden", visible);
  if (arrow) arrow.textContent = visible ? "›" : "⌄";
});

el("btn-med-cancel").addEventListener("click", () => {
  hide("modal-med-admin");
  isPopupOpen = false;  // Allow TTS now that popup is closed
  speakPendingIfAny();  // Speak any queued response
  if (!_resumePendingImpressionChallengeAfterModal()) setTimeout(advanceInterventionQueue, 200);
});

// _activeMedIntervention: the intervention currently shown in the med popup
let _activeMedIntervention = null;

el("btn-med-confirm").addEventListener("click", async () => {
  if (el("btn-med-confirm").disabled) return;
  const cfg = _activeMedIntervention?.popup_config || {};
  const dose = el("med-dose-input")?.value?.trim() || cfg.dose;
  const pcrLabel = `${cfg.drug || _activeMedIntervention?.label} — ${dose} (${cfg.route || "SVN"})`;
  const interventionId = _activeMedIntervention?.id;
  _activeMedIntervention = null;
  hide("modal-med-admin");
  isPopupOpen = false;  // Allow TTS now that popup is closed
  speakPendingIfAny();  // Speak any queued response
  await applyInterventionAndRecord(interventionId, pcrLabel);
  if (!_resumePendingImpressionChallengeAfterModal()) setTimeout(advanceInterventionQueue, 200);
});

el("btn-queue-skip").addEventListener("click", () => {
  _pendingPopupQueue = [];
  hide("modal-intervention-queue");
});

// Called after each popup resolves (confirm or cancel) to work through the queue
function advanceInterventionQueue() {
  if (!el("modal-challenge")?.classList.contains("hidden")) return;
  // Filter out already-applied items
  _pendingPopupQueue = _pendingPopupQueue.filter(iv => !state.interventionsApplied.includes(iv.id));

  if (_pendingPopupQueue.length === 0) return;

  if (_pendingPopupQueue.length === 1) {
    const iv = _pendingPopupQueue.shift();
    if (iv.popup_type === "oxygen") showO2Popup(iv);
    else if (iv.popup_type === "medication") showMedPopup(iv);
    return;
  }

  // Multiple remaining — ask which to do next
  showInterventionQueueModal();
}

function showInterventionQueueModal() {
  const container = el("intervention-queue-list");
  container.innerHTML = "";
  _pendingPopupQueue.forEach(iv => {
    const btn = document.createElement("button");
    btn.className = "w-full text-left px-4 py-3 bg-gray-800 hover:bg-gray-700 border border-gray-700 hover:border-yellow-600 rounded-lg text-white text-sm font-semibold transition-colors";
    btn.textContent = iv.popup_type === "oxygen" ? `💨 ${iv.label}` : `💊 ${iv.label}`;
    btn.addEventListener("click", () => {
      hide("modal-intervention-queue");
      _pendingPopupQueue = _pendingPopupQueue.filter(q => q.id !== iv.id);
      // Re-add remaining to front so they come after this one
      const remaining = [..._pendingPopupQueue];
      _pendingPopupQueue = remaining;
      if (iv.popup_type === "oxygen") showO2Popup(iv);
      else if (iv.popup_type === "medication") showMedPopup(iv);
    });
    container.appendChild(btn);
  });

  const countEl = el("intervention-queue-count");
  if (countEl) countEl.textContent = _pendingPopupQueue.length;
  show("modal-intervention-queue");
}

async function applyInterventionAndRecord(interventionId, pcrLabel, { source = "backend_auto" } = {}) {
  // Skip if already applied — do not add a second PCR entry with a different label
  if (state.interventionsApplied.includes(interventionId)) {
    return;
  }

  const interventionMeta = _interventionById[interventionId];
  if (_showFtoGuidanceForIntervention(interventionMeta, pcrLabel)) {
    return;
  }
  if (interventionMeta?.popup_type === "medication" && !_impressionChallengeCompleted && _scenarioImpressionChallengePayload()) {
    _ensureImpressionChallengeBeforeMedication(() => {
      applyInterventionAndRecord(interventionId, pcrLabel, { source });
    });
    return;
  }

  // Apply intervention effects via API
  if (state.sessionId && interventionId) {
    try {
      const canTriggerImpressionChallenge = interventionMeta?.popup_type === "medication";
      await authFetch(`${API}/api/sessions/${state.sessionId}/interventions`, {
        method: "POST",
        body: JSON.stringify({ intervention_name: interventionId, source }),
      }).then(async (res) => {
        const data = await res.json().catch(() => ({}));
        if (data?.vitals && typeof data.vitals === "object") {
          _applyCurrentVitalsSnapshot(data.vitals);
        }
        if (canTriggerImpressionChallenge && data?.challenge_available) {
          _openOrQueueImpressionChallenge(data.challenge_available);
        }
      });
      state.interventionsApplied.push(interventionId);
    } catch { /* non-fatal — still record in PCR */ }
  }

  addPcrTreatment(pcrLabel, interventionId);
  const structuredExamFindings = await _recordStructuredExamFindingsForIntervention(interventionId);
  (structuredExamFindings || []).forEach(({ key, value }) => {
    if (_examFindingShouldRenderChatCallout(key, value)) {
      appendExamFindingInfo(key, value);
    }
  });
  _appendLexiInterventionFeedback(interventionId, pcrLabel);
  checkReadiness();
}

async function _recordStructuredExamFindingsForIntervention(interventionId) {
  const id = String(interventionId || "");
  const writes = [];
  const displayFindings = [];
  const recordExam = (key, value, source = "student_stated_exam", { display = true } = {}) => {
    writes.push(addPcrExam(key, value, source));
    if (display) displayFindings.push({ key, value });
  };
  const authoredValue = (key, fallback = "") => {
    const def = _AUTHORED_VITAL_DEFS.find(d => d.key === key);
    const formatted = def ? _formatAuthoredVitalValue(def, { useDisplay: true }) : null;
    if (formatted && !formatted.unavailable && formatted.value) return formatted.value;
    return fallback;
  };

  if (id === "neuro_assessment") {
    const gcs = state.scenarioData?.patient?.gcs_assessment;
    const gcsText = gcs?.total
      ? `GCS ${gcs.total}/15 (E${gcs.e} V${gcs.v} M${gcs.m})`
      : "GCS/AVPU assessed";
    const gcsVitalText = gcs?.total ? `${gcs.total} (E${gcs.e} V${gcs.v} M${gcs.m})` : "Assessed";
    const locText = state.scenarioData?.patient?.avpu_assessment?.description || "Level of consciousness assessed.";
    const pupilsText = authoredValue("pupils", "Pupils assessed for size, equality, and reactivity.");
    const eventsText = state.scenarioData?.history?.events_leading_to_call || "LOC and vomiting history assessed.";
    _vitalsBatch = { GCS: gcsVitalText };
    writes.push(...(flushVitalsBlock({ GCS: "gcs_modal", default: "gcs_modal" }) || []));
    recordExam("Neurological Assessment", `${gcsText}; ${locText}; Pupils: ${pupilsText}`);
    recordExam("Pupils", pupilsText);
    recordExam("AVPU / LOC", locText, "student_stated_exam", { display: false });
    writes.push(addPcrHistory("LOC", eventsText, "ai_roleplay_tag"));
    writes.push(addPcrHistory("Vomiting", eventsText, "ai_roleplay_tag"));
  } else if (id === "dcap_btls_head_neck") {
    const headFinding = "Head/scalp DCAP-BTLS assessed for deformity, contusions, abrasions, punctures, burns, tenderness, lacerations, swelling, and skull step-off; no visible scalp laceration or external hemorrhage noted.";
    const faceFinding = "Face, mouth, and nose assessed for DCAP-BTLS and visible injury.";
    recordExam("DCAP-BTLS Head", headFinding);
    recordExam("Head Assessment", headFinding, "student_stated_exam", { display: false });
    recordExam("Scalp Assessment", headFinding, "student_stated_exam", { display: false });
    recordExam("Facial / Mouth / Nose Assessment", faceFinding, "student_stated_exam", { display: false });
  }

  await Promise.allSettled(writes.filter(Boolean));
  return displayFindings;
}

function appendSuggestionChips(suggestions, afterEl) {
  const lastMessage = String(_lastUserChatMessage || "");
  const vitalsOnlyRequest = _isLikelyAuthoredVitalsRequest(lastMessage)
    && !/\b(administer|apply|start|give|place|put\s+on|treat|therapy|nrb|nasal\s+cannula|blow[-\s]?by|15\s*lpm|lpm|oxygen(?:\s+therapy)?|o2(?:\s+(?:therapy|via|by|on|at))?)\b/i.test(lastMessage);

  if (vitalsOnlyRequest) return;

  // Filter out anything already applied or already queued for a popup
  const filtered = (suggestions || []).filter(s =>
    !state.interventionsApplied.includes(s.id) &&
    !_pendingPopupQueue.find(q => q.id === s.id)
  );
  if (!filtered.length) return;

  const wrap = document.createElement("div");
  wrap.className = "msg-suggestions";

  const dismiss = () => wrap.remove();
  const seenLabels = new Set();

  filtered.forEach(iv => {
    const displayLabel = iv.popup_type === "oxygen" ? "Administer O2?" : iv.label;
    const dedupeKey = iv.popup_type === "oxygen" ? "oxygen" : String(displayLabel || iv.id || "").toLowerCase();
    if (seenLabels.has(dedupeKey)) return;
    seenLabels.add(dedupeKey);
    const label = displayLabel.length > 34 ? displayLabel.substring(0, 32) + "…" : displayLabel;
    const btn = document.createElement("button");
    btn.className = "suggestion-chip";
    btn.textContent = label;
    btn.title = displayLabel;
    btn.addEventListener("click", async () => {
      dismiss();
      const ivData = _interventionById[iv.id];
      if (iv.popup_type === "medication" && ivData) {
        showMedPopup(ivData);
      } else if (iv.popup_type === "oxygen" && ivData) {
        showO2Popup(ivData);
      } else {
        await applyInterventionAndRecord(iv.id, iv.label, { source: "student_confirmed" });
        sendMessage(`Applied ${iv.label}.`, { isAction: true, suppressAuthoritativeTags: true });
      }
    });
    wrap.appendChild(btn);
  });

  const xBtn = document.createElement("button");
  xBtn.className = "suggestion-dismiss";
  xBtn.title = "Dismiss";
  xBtn.textContent = "✕";
  xBtn.addEventListener("click", dismiss);
  wrap.appendChild(xBtn);

  afterEl.insertAdjacentElement("afterend", wrap);
  scrollChat();
}

// Tags emitted by LLM:
//   [[VITAL: label=value unit]]      → timestamped vitals block
//   [[EXAM: key=value]]              → exam findings / OPQRST / SAMPLE
//   [[HISTORY: key=value]]           → additional history (PMH, etc.)
//   [[INTERVENTION: label]]          → treatments

let _vitalsBatch = {};
let _lastUserChatMessage = "";
let _historyCaptureUnlocked = false;

function _manualCspineCommandRequested(message = "") {
  const msg = String(message || "").toLowerCase();
  if (_cspineExamRequested(msg)) return false;
  return (
    /\b(hold|maintain|stabiliz(?:e|ing)|manual)\b.{0,30}\b(c[\s-]?spine|cervical spine|neck|head)\b/i.test(msg)
    || /\b(c[\s-]?spine|cervical spine|neck|head)\b.{0,30}\b(hold|maintain|stabiliz(?:e|ing)|manual)\b/i.test(msg)
    || /\bmanual\s+in[-\s]?line\s+stabilization\b/i.test(msg)
  ) && !/\b(c[-\s]?collar|cervical collar|collar)\b/i.test(msg);
}

function _cspineExamRequested(message = "") {
  const msg = String(message || "");
  return /\b(?:palpat(?:e|ing)|assess(?:ing)?|check(?:ing)?|examin(?:e|ing)|evaluat(?:e|ing))\b.{0,50}\b(?:c[\s-]?spine|cervical spine|neck)\b/i.test(msg)
    || /\b(?:c[\s-]?spine|cervical spine|neck)\b.{0,50}\b(?:tenderness|pain|deformity|step[-\s]?off|palpat(?:e|ing)|assess(?:ing)?|check(?:ing)?|exam)\b/i.test(msg);
}

async function _handleCspineExamAction(message = "", chipId = null, isAction = false) {
  if (!_cspineExamRequested(message)) return false;
  const match = _authoredStandardExamFindingForMessage(message)
    || _authoredStandardExamFindingForMessage("palpate cervical spine");
  const key = match?.entry?.exam_key || "C-Spine";
  const value = match?.entry?.finding
    ? _normalizeExamFindingValue(key, match.entry.finding)
    : "Cervical spine palpated for midline tenderness, deformity, and step-off. No authored scenario-specific finding is available.";
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  await addPcrExam(key, value, "student_stated_exam");
  appendExamFindingInfo(key, value);
  appendLexiActionFeedback("focused_exam", LEXI_ACTION_FEEDBACK.focused_exam);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

async function _handleManualCspineCommand(message = "", chipId = null, isAction = false) {
  if (!_manualCspineCommandRequested(message)) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  await applyInterventionAndRecord("smr", "Spinal Motion Restriction — manual in-line stabilization", { source: "student_confirmed" });
  const display = "*Alex:* Copy — holding manual in-line cervical stabilization now.";
  appendAiMessage(display);
  speakText(display);
  return true;
}

function _popupQueuedDisplayText(queue = []) {
  if (!Array.isArray(queue) || queue.length === 0) return "";
  if (queue.length > 1) {
    return "*Alex:* I have multiple treatments ready. Choose which one to complete next in the popup.";
  }
  const iv = queue[0] || {};
  if (iv.popup_type === "oxygen") {
    return "*Alex:* Oxygen setup is ready. Confirm the delivery method in the popup.";
  }
  if (iv.popup_type === "medication") {
    return "*Alex:* Medication setup is ready. Complete the medication check in the popup.";
  }
  return "*Alex:* The intervention is ready. Confirm the details in the popup.";
}

function _historyPromptRequested(message = "") {
  const msg = String(message || "").toLowerCase();
  return /\b(history|medical history|pmh|past medical|past history|allerg(?:y|ies)|meds?|medications?|sample|ample|opqrst|hx|background|diabetic|diabetes|type\s*1|type\s*one|type\s*2|type\s*two|insulin|any history|what happened(?:\s+before)?|walk me through|walk us through|tell me what happened|talk me through|events?|timeline|onset|when did (?:this|it) start|before this|ever happen(?:ed)? before|first time|happened before|previous (?:episode|event|occurrence|time)|had this before|seen this before|recur(?:red|ring)?)\b/.test(msg);
}

function _volatileCurrentEventsOrientationQuestion(message = "") {
  const msg = _normalizeHistoryMapText(message);
  if (!msg) return false;
  const asksQuestion = /\b(?:who|what|when|where|which|do you know|can you tell me|tell me)\b/.test(msg);
  if (!asksQuestion) return false;
  return (
    /\b(?:president|governor|mayor|prime minister|senator|congress|election|news|current event|current events|recent event|recent events)\b/.test(msg)
    || /\b(?:what holiday|which holiday|holiday coming|coming up next week)\b/.test(msg)
  );
}

function _handleVolatileCurrentEventsOrientationQuestion(message = "") {
  if (!_volatileCurrentEventsOrientationQuestion(message)) return false;
  appendFtoGuidanceInfo(
    "Avoid volatile current-events orientation questions such as \"Who is the president?\" or upcoming-holiday prompts. They can depend on date, location, politics, culture, or news exposure and are less reliable for EMS mental-status assessment.\n\nUse person, place, time, and event instead: \"Can you tell me your name?\" \"Do you know where you are?\" \"What day, month, or year is it?\" \"Can you tell me what happened?\""
  );
  return true;
}

function _normalizeHistoryMapText(text = "") {
  return String(text || "")
    .toLowerCase()
    .replace(/[’]/g, "'")
    .replace(/\bwhat's\b/g, "what is")
    .replace(/\bwhats\b/g, "what is")
    .replace(/\bwho's\b/g, "who is")
    .replace(/\bwhos\b/g, "who is")
    .replace(/\bdoesn't\b/g, "does not")
    .replace(/\bisn't\b/g, "is not")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function _historyMapTriggerMatches(message = "", trigger = "") {
  const msg = _normalizeHistoryMapText(message);
  const trig = _normalizeHistoryMapText(trigger);
  if (!msg || !trig) return false;
  const msgPhrase = ` ${msg} `;
  const trigPhrase = ` ${trig} `;
  const messageTokens = msg.split(" ").filter(Boolean);
  if (messageTokens.length < 2 && msg !== trig) {
    return msgPhrase.includes(trigPhrase);
  }
  return msgPhrase.includes(trigPhrase) || trigPhrase.includes(msgPhrase) || _historyMapOrderedTokenMatch(msg, trig);
}

function _historyMapOrderedTokenMatch(messageText = "", triggerText = "") {
  const messageTokens = String(messageText || "").split(" ").filter(Boolean);
  const triggerTokens = String(triggerText || "").split(" ").filter(Boolean);
  if (messageTokens.length < 3 || triggerTokens.length < 3) return false;

  let cursor = 0;
  for (const token of triggerTokens) {
    cursor = messageTokens.indexOf(token, cursor);
    if (cursor === -1) return false;
    cursor += 1;
  }
  return true;
}

function _historyMapMessageRequestsCompoundSample(message = "") {
  const msg = _normalizeHistoryMapText(message);
  if (!msg) return false;
  if (/\bsample\b/.test(msg)) return true;
  const sampleComponentPatterns = [
    /\bsigns?\b|\bsymptoms?\b|\bassociated\b/,
    /\ballerg(?:y|ies)\b/,
    /\bmed(?:s|ication|ications)?\b|\bmedicine\b/,
    /\bpmh\b|\bpast medical\b|\bmedical history\b|\bmedical problems?\b/,
    /\blast oral\b|\boral intake\b|\bintake\b|\bfeeding\b|\bformula\b|\beat\b|\bdrink\b/,
    /\bevents?\b|\bleading up\b|\bwhat happened\b/,
  ];
  const componentCount = sampleComponentPatterns.filter((pattern) => pattern.test(msg)).length;
  return componentCount >= 3;
}

function _historyMapEntryMatchScore(entry = {}, message = "", originalIndex = 0) {
  if (!entry || typeof entry !== "object") return null;
  const triggers = Array.isArray(entry.triggers) ? entry.triggers : [];
  const matchingTriggers = triggers
    .map(trigger => _normalizeHistoryMapText(trigger))
    .filter(trigger => trigger && _historyMapTriggerMatches(message, trigger));
  if (!_historyMapEntryAllowedForContext(entry, message)) return null;

  const tags = Array.isArray(entry.tags) ? entry.tags : (entry.tag ? [entry.tag] : []);
  const notes = _normalizeHistoryMapText(entry.notes || "");
  const isCompleteSampleEntry = tags.some(tag => /\[\[\s*HISTORY:\s*Signs and Symptoms\s*[:=]/i.test(tag))
    && tags.some(tag => /\[\[\s*HISTORY:\s*(?:Last Oral Intake|LOI)\s*[:=]/i.test(tag))
    && tags.some(tag => /\[\[\s*HISTORY:\s*Events\s*[:=]/i.test(tag));
  if (isCompleteSampleEntry && !_historyMapMessageRequestsCompoundSample(message)) return null;
  if (!matchingTriggers.length && !(isCompleteSampleEntry && _historyMapMessageRequestsCompoundSample(message))) return null;
  const longestTriggerLength = matchingTriggers.reduce((max, trigger) => Math.max(max, trigger.length), 0);
  const longestTriggerTokens = matchingTriggers.reduce((max, trigger) => Math.max(max, trigger.split(" ").filter(Boolean).length), 0);
  const priorityBonus = /\bpriority entry\b/.test(notes) ? 100000 : 0;
  const completeSampleBonus = isCompleteSampleEntry ? 10000 : 0;
  const tagBreadthBonus = tags.length * 100;
  const triggerSpecificity = (longestTriggerTokens * 10) + longestTriggerLength;

  return {
    entry,
    score: priorityBonus + completeSampleBonus + tagBreadthBonus + triggerSpecificity,
    originalIndex,
  };
}

function _historyMapEntryLooksLikeMechanism(entry = {}, entryKey = "") {
  const tags = Array.isArray(entry.tags) ? entry.tags : (entry.tag ? [entry.tag] : []);
  const tagsBlob = tags.join(" ");
  const haystack = _normalizeHistoryMapText([
    entryKey,
    entry.label,
    Array.isArray(entry.triggers) ? entry.triggers.join(" ") : "",
    tagsBlob,
  ].filter(Boolean).join(" "));
  if (/\b(broad opener|chief concern|chief complaint)\b/.test(haystack)) return false;
  if (/\[\[\s*HISTORY:\s*Events\s*[:=]/i.test(tagsBlob)) return true;
  return /\b(mechanism|moi|events?)\b/.test(haystack);
}

function _eventsHistoryValueForMechanismEntry(entry = {}) {
  if (!entry || typeof entry !== "object" || !_historyMapEntryLooksLikeMechanism(entry)) return "";
  const tags = Array.isArray(entry.tags) ? entry.tags : (entry.tag ? [entry.tag] : []);
  for (const tag of tags) {
    const match = String(tag || "").match(/\[\[\s*HISTORY:\s*Events\s*[:=]\s*([^\]]+)\]\]/i);
    const value = match?.[1]?.replace(/[*_]/g, "").trim();
    if (value) return value;
  }
  return String(entry.answer || "").replace(/\[\[[^\]]+\]\]/g, "").trim();
}

function _messageIsBareMechanismHow(message = "") {
  const msg = _normalizeHistoryMapText(message);
  return ["how", "how did it happen", "how did that happen"].includes(msg);
}

function _bareHowMechanismHistoryEntry(responseMap = {}, message = "") {
  if (!_messageIsBareMechanismHow(message)) return null;
  const initial = [
    state.scenarioData?.initial_complaint?.lay_summary,
    state.scenarioData?.initial_complaint?.text,
    state.scenarioData?.dispatch,
  ].filter(Boolean).join(" ");
  if (!/\b(fall|fell|trip|tripped|hit|struck|land(?:ed)?|cut|injur(?:y|ed))\b/i.test(initial)) return null;
  for (const [key, entry] of Object.entries(responseMap)) {
    if (!entry || typeof entry !== "object" || !entry.answer) continue;
    if (_historyMapEntryLooksLikeMechanism(entry, key)) {
      return _narrowDemographicHistoryEntry(entry, message);
    }
  }
  return null;
}

function _applyHistoryResponseMapTag(tag = "") {
  const match = String(tag || "").match(/\[\[\s*(EXAM|HISTORY):\s*([^\]=:]+)\s*[:=]\s*([^\]]+)\]\]/i);
  if (!match) return false;
  const type = match[1].toUpperCase();
  const key = match[2].replace(/[*_]/g, "").trim();
  const val = match[3].replace(/[*_]/g, "").trim();
  if (!key || !val) return false;
  if (type === "EXAM") addPcrExam(key, val);
  if (type === "HISTORY") addPcrHistory(key, val);
  return true;
}

function _historyResponseTextMentionsTagValue(tag = "", responseText = "") {
  const match = String(tag || "").match(/\[\[\s*(EXAM|HISTORY):\s*([^\]=:]+)\s*[:=]\s*([^\]]+)\]\]/i);
  if (!match) return false;
  const key = _normalizeHistoryMapText(match[2]);
  const val = _normalizeHistoryMapText(match[3]);
  const response = _normalizeHistoryMapText(responseText);
  if (!response) return false;
  if (/date of birth|dob|birth date/.test(key)) {
    return /\b(born|birth|dob|date of birth)\b/.test(response);
  }
  if (/name/.test(key)) {
    const expected = _normalizeHistoryMapText(state.scenarioData?.patient?.name || "");
    return Boolean(expected && response.includes(expected));
  }
  if (/weight|broselow|broslow/.test(key)) {
    return /\b(weigh|weight|pounds?|lbs?|kilograms?|kg|broselow|broslow)\b/.test(response);
  }
  if (/chief complaint|chief concern|complaint/.test(key)) {
    return /\b(acting|strange|confused|breath|breathing|cough|complaint|called)\b/.test(response) || response.includes(val);
  }
  return val && response.includes(val);
}

function _historyMapTagAllowedForContext(tag = "", message = "", responseText = "") {
  const match = String(tag || "").match(/\[\[\s*(EXAM|HISTORY):\s*([^\]=:]+)\s*[:=]\s*([^\]]+)\]\]/i);
  if (!match) return false;
  const key = _normalizeHistoryMapText(match[2]);
  const msg = _normalizeHistoryMapText(message);
  const combined = `${msg} ${_normalizeHistoryMapText(responseText)}`;

  if (/date of birth|dob|birth date/.test(key)) {
    return /\b(date of birth|dob|birth date|birthday|born|birth)\b/.test(msg);
  }
  if (/name/.test(key)) {
    const expected = _normalizeHistoryMapText(state.scenarioData?.patient?.name || "");
    const response = _normalizeHistoryMapText(responseText);
    return _messageRequestsPatientName(message) || Boolean(expected && response.includes(expected));
  }
  if (/patient age/.test(key)) {
    return /\b(age|old|date of birth|dob|birth date|birthday|born|birth|demographics?)\b/.test(msg);
  }
  if (/weight|broselow|broslow/.test(key)) {
    return /\b(weigh|weight|pounds?|lbs?|kilograms?|kg|broselow|broslow|demographics?)\b/.test(msg);
  }
  return true;
}

function _messageRequestsPatientName(message = "") {
  const msg = String(message || "").toLowerCase();
  return /\b(?:what(?:'s| is)?|whats|who(?:'s| is)?|identify|id)\b.{0,40}\b(?:name|patient|pt|her|him|them|child|infant|baby)\b/i.test(msg)
    || /\b(?:patient|pt|her|his|their|child|infant|baby)\s+name\b/i.test(msg)
    || /\bname\s*(?:and|,|\/)\s*(?:age|dob|date of birth|birthday|weight)\b/i.test(msg);
}

function _historyMapEntryAllowedForContext(entry = {}, message = "") {
  const tags = Array.isArray(entry.tags) ? entry.tags : (entry.tag ? [entry.tag] : []);
  if (!tags.length) return true;
  return tags.some(tag => _historyMapTagAllowedForContext(tag, message, entry.answer || ""));
}

function _patientDemographicTagValues(entry = {}) {
  const tags = Array.isArray(entry.tags) ? entry.tags : (entry.tag ? [entry.tag] : []);
  const values = {};
  tags.forEach(tag => {
    const match = String(tag || "").match(/\[\[\s*HISTORY:\s*(Patient Name|Patient Age|Patient Date of Birth|Patient Weight)\s*[:=]\s*([^\]]+)\]\]/i);
    if (!match) return;
    const label = _normalizeHistoryMapText(match[1]);
    const key = {
      "patient name": "name",
      "patient age": "age",
      "patient date of birth": "dob",
      "patient weight": "weight",
    }[label];
    if (key) values[key] = match[2].trim();
  });
  return values;
}

function _requestedDemographicFields(message = "") {
  const msg = _normalizeHistoryMapText(message);
  const raw = String(message || "").toLowerCase();
  const fields = new Set();
  if (/\b(name|who is|identify|id)\b/.test(msg)) fields.add("name");
  if (/\b(age|old)\b/.test(msg)) fields.add("age");
  if (/\b(date\s+of\s+birth|dob|birth\s*date|birthday|born|birth)\b/.test(raw)) fields.add("dob");
  if (/\b(weigh|weight|pounds?|lbs?|kilograms?|kg|broselow|broslow)\b/.test(msg)) fields.add("weight");
  if (/\b(demographics?|identify him|identify her|identify them|id him|id her|id them)\b/.test(msg)) {
    ["name", "age", "dob", "weight"].forEach(field => fields.add(field));
  }
  return fields;
}

function _patientPronouns() {
  const sex = String(state.scenarioData?.patient?.sex || state.scenarioData?.patient?.gender || "").toLowerCase();
  if (sex.startsWith("m")) return { subject: "he", possessive: "his", be: "he's" };
  if (sex.startsWith("f")) return { subject: "she", possessive: "her", be: "she's" };
  return { subject: "they", possessive: "their", be: "they're" };
}

function _agePhrase(ageValue = "") {
  const text = String(ageValue || "").trim();
  const match = text.match(/^(\d+(?:\.\d+)?)\s*-\s*year\s*-\s*old\b/i);
  return match ? `${match[1]} years old` : text;
}

function _numberWordToDigits(word = "") {
  const key = String(word || "").toLowerCase().trim();
  return {
    zero: "0",
    one: "1",
    two: "2",
    three: "3",
    four: "4",
    five: "5",
    six: "6",
    seven: "7",
    eight: "8",
    nine: "9",
    ten: "10",
    eleven: "11",
    twelve: "12",
  }[key] || "";
}

function _narrowDemographicHistoryEntry(entry = {}, message = "") {
  const values = _patientDemographicTagValues(entry);
  const valueKeys = Object.keys(values);
  if (!valueKeys.length) return entry;
  const requested = _requestedDemographicFields(message);
  const requestedKeys = valueKeys.filter(key => requested.has(key));
  if (!requestedKeys.length || requestedKeys.length === valueKeys.length) return entry;

  const pronouns = _patientPronouns();
  const sentences = [];
  if (requested.has("name") && values.name) {
    const speaker = _normalizeHistoryMapText(entry.speaker || "");
    const patientName = _normalizeHistoryMapText(state.scenarioData?.patient?.name || "");
    sentences.push(speaker && patientName && speaker === patientName
      ? `My name is ${values.name}.`
      : `${pronouns.possessive.charAt(0).toUpperCase() + pronouns.possessive.slice(1)} name is ${values.name}.`);
  }
  if (requested.has("age") && values.age) {
    sentences.push(`${pronouns.be.charAt(0).toUpperCase() + pronouns.be.slice(1)} ${_agePhrase(values.age)}.`);
  }
  if (requested.has("dob") && values.dob) {
    sentences.push(/before today|born today/i.test(values.dob)
      ? `${pronouns.be.charAt(0).toUpperCase() + pronouns.be.slice(1)} ${values.dob}.`
      : `${pronouns.possessive.charAt(0).toUpperCase() + pronouns.possessive.slice(1)} birthday is ${values.dob}.`);
  }
  if (requested.has("weight") && values.weight) {
    sentences.push(`${pronouns.subject.charAt(0).toUpperCase() + pronouns.subject.slice(1)} weighs ${values.weight}.`);
  }

  const allowedLabels = {
    name: "Patient Name",
    age: "Patient Age",
    dob: "Patient Date of Birth",
    weight: "Patient Weight",
  };
  const filteredTags = (Array.isArray(entry.tags) ? entry.tags : (entry.tag ? [entry.tag] : []))
    .filter(tag => requestedKeys.some(key => new RegExp(`\\[\\[\\s*HISTORY:\\s*${allowedLabels[key]}\\s*[:=]`, "i").test(String(tag || ""))));

  const narrowed = { ...entry, answer: sentences.join(" "), tags: filteredTags };
  delete narrowed.tag;
  return narrowed;
}

function _scenarioPatientPersona() {
  const s = state.scenarioData || {};
  const personas = s.personas && typeof s.personas === "object" ? Object.values(s.personas) : [];
  return personas.find(persona => String(persona?.role || "").toLowerCase() === "patient") || null;
}

function _scenarioPatientCanAnswerDirectQuestions() {
  const s = state.scenarioData || {};
  const patient = s.patient || {};
  const persona = _scenarioPatientPersona() || {};
  const text = [
    patient.general_impression,
    patient.avpu_assessment?.value,
    patient.avpu_assessment?.description,
    patient.gcs_assessment?.rationale,
    persona.description,
    persona.speaking_style,
    persona.clinical_state_instructions,
  ].filter(Boolean).join(" ").toLowerCase();

  if (/\b(newborn|infant|non[-\s]?verbal|cannot speak|never speaks|unresponsive|apneic|does not respond|can't answer|cannot answer)\b/.test(text)) {
    return false;
  }
  const age = Number(patient.age ?? persona.age);
  if (Number.isFinite(age) && age < 3) return false;
  return /\b(alert|oriented|answers?|speaks?|verbal|responds?|crying|short answers?|communicates?)\b/.test(text);
}

function _messageDirectlyAddressesPatient(message = "") {
  const s = state.scenarioData || {};
  const patient = s.patient || {};
  const persona = _scenarioPatientPersona() || {};
  const aliases = new Set(["patient", "pt"]);
  if (patient.name) aliases.add(String(patient.name));
  if (persona.name) aliases.add(String(persona.name));
  if (Array.isArray(persona.aliases)) {
    persona.aliases.forEach(alias => {
      const normalized = _normalizeHistoryMapText(alias);
      if (!normalized || /^(he|him|his|she|her|hers|they|them|their|it|its|the child|the patient|the boy|the girl)$/.test(normalized)) return;
      aliases.add(alias);
    });
  }
  return [...aliases].some(alias => {
    const normalized = _normalizeHistoryMapText(alias);
    if (!normalized) return false;
    return new RegExp(`\\b${normalized.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i").test(_normalizeHistoryMapText(message));
  });
}

function _historyEntrySpeakerIsPatient(entry = {}) {
  const speaker = _normalizeHistoryMapText(entry.speaker || "");
  if (!speaker) return false;
  const s = state.scenarioData || {};
  const patient = s.patient || {};
  const persona = _scenarioPatientPersona() || {};
  const names = new Set([patient.name, persona.name].filter(Boolean).map(_normalizeHistoryMapText));
  if (Array.isArray(persona.aliases)) persona.aliases.map(_normalizeHistoryMapText).filter(Boolean).forEach(alias => names.add(alias));
  return names.has(speaker);
}

function _lastSceneSpeakerWasPatient() {
  if (!_lastNonPartnerSceneSpeaker) return false;
  return _speakerRoleHint(_lastNonPartnerSceneSpeaker) === "patient";
}

function _messageLooksLikeShortSceneFollowup(message = "") {
  const msg = _normalizeHistoryMapText(message);
  if (!msg) return false;
  if (/\b(alex|partner|crew|teammate)\b/i.test(msg)) return false;
  const words = msg.match(/[a-z0-9']+/g) || [];
  if (words.length > 10) return false;
  return /^(how|what|when|where|why|who|which|any|does|did|is|are|can|could|tell|describe)\b/i.test(msg)
    || /\b(how|what|when|where|why|who|which)\b/i.test(msg)
    || /\b(confused|worse|better|before|again|long|started|start|symptoms?|allerg(?:y|ies)|meds?|medications?|history|pain|hurt|name)\b/i.test(msg);
}

function _shouldBypassHistoryMapForDirectPatient(message = "", entry = {}) {
  const patientFollowup = _lastSceneSpeakerWasPatient() && _messageLooksLikeShortSceneFollowup(message);
  return (_messageDirectlyAddressesPatient(message) || patientFollowup)
    && _scenarioPatientCanAnswerDirectQuestions()
    && !_historyEntrySpeakerIsPatient(entry);
}

function _applyScenarioHistoryResponseMapTags(message = "", responseText = "") {
  const entry = _scenarioHistoryResponseMapEntry(message);
  if (!entry) return 0;
  return _applyHistoryResponseEntryTags(entry, message);
}

function _scenarioHistoryResponseMapEntry(message = "") {
  const responseMap = state.scenarioData?.history_response_map;
  if (!responseMap || typeof responseMap !== "object") return null;
  const bareHowMechanism = _bareHowMechanismHistoryEntry(responseMap, message);
  if (bareHowMechanism) return bareHowMechanism;
  const candidates = [];
  Object.values(responseMap).forEach((entry, originalIndex) => {
    if (!entry || typeof entry !== "object" || !entry.answer) return;
    if (_shouldBypassHistoryMapForDirectPatient(message, entry)) return;
    const candidate = _historyMapEntryMatchScore(entry, message, originalIndex);
    if (candidate) candidates.push(candidate);
  });
  if (!candidates.length) return null;
  candidates.sort((a, b) => (b.score - a.score) || (a.originalIndex - b.originalIndex));
  return _narrowDemographicHistoryEntry(candidates[0].entry, message);
}

function _applyHistoryResponseEntryTags(entry, message = "") {
  if (!entry || typeof entry !== "object") return 0;
  let applied = 0;
  let appliedEvents = false;
  const responseText = entry.answer || "";
  const tags = Array.isArray(entry.tags) ? entry.tags : (entry.tag ? [entry.tag] : []);
  tags.forEach(tag => {
    if (!_historyMapTagAllowedForContext(tag, message, responseText)) return;
    if (_applyHistoryResponseMapTag(tag)) {
      applied += 1;
      if (/\[\[\s*HISTORY:\s*Events\s*[:=]/i.test(String(tag || ""))) appliedEvents = true;
    }
  });
  if (!appliedEvents) {
    const eventsValue = _eventsHistoryValueForMechanismEntry(entry);
    if (eventsValue) {
      addPcrHistory("Events", eventsValue, "ai_roleplay_tag");
      applied += 1;
    }
  }
  _captureDeferredPcrHeaderFromPlainText(responseText);
  _captureKnownSceneNamesFromExchange(message, responseText);
  return applied;
}

function _speakerRoleBeforeIndex(text = "", index = 0) {
  const prefix = String(text || "").slice(0, Math.max(0, index));
  const speakerRegex = /(?:^|\n)\s*\*?([^:\n*]{1,80})\*?\s*:/g;
  let match;
  let speaker = "";
  while ((match = speakerRegex.exec(prefix)) !== null) {
    speaker = match[1].trim();
  }
  return speaker ? _speakerRoleHint(speaker) : "";
}

function _userMessageStatesSelfMeasuredVital(message = "") {
  const msg = String(message || "").toLowerCase();
  const vital = /\b(vitals?|vital signs?|blood pressure|bp|spo2|sp\s*o2|spo₂|sp\s*o₂|o2\s*sat|o₂\s*sat|oxygen saturation|pulse ox|heart rate|hr|pulse|respiratory rate|respirations?|rr|temperature|temp|blood glucose|bgl|blood sugar|glucose|gcs)\b/i;
  return /\b(i|we)\s+(?:am\s+|are\s+)?(?:checking|check|checked|obtaining|obtain|obtained|taking|take|took|assessing|assess|assessed|measuring|measure|measured)\b/i.test(msg)
    && vital.test(msg);
}

function _userMessageRequestsOnScenePartnerVital(message = "") {
  const msg = String(message || "").toLowerCase();
  if (/\b(last|prior|previous|home|before ems|before you|earlier|watch|smartwatch|fitbit|apple watch|cgm|pump|omnipod|reported)\b/i.test(msg)) {
    return false;
  }
  const addressedPartner = /\b(alex|partner|crew|teammate)\b/i.test(msg);
  const commandVerb = /\b(check|get|grab|obtain|take|reassess|repeat)\b/i.test(msg);
  return (addressedPartner || commandVerb) && _userExplicitlyRequestedVitals(message);
}

function _vitalTagSourceAllowed(text = "", tagIndex = 0) {
  const role = _speakerRoleBeforeIndex(text, tagIndex);
  if (role === "partner") return true;
  if (role && role !== "partner") return false;
  return _userMessageStatesSelfMeasuredVital(_lastUserChatMessage)
    || _userMessageRequestsOnScenePartnerVital(_lastUserChatMessage);
}

function _userMessageExplicitlyRequestsProvocation(message = "") {
  const msg = String(message || "").toLowerCase();
  return /\b(provok|provocation|palliat|palliation|better|worse|help|hurt|trigger|triggers|triggered|aggravat|reliev|relieve|affect)\b/i.test(msg)
    || /\bmakes?\b.{0,40}\b(?:better|worse)\b/i.test(msg);
}

function _examTagAllowedForUserContext(key = "", message = "") {
  const normalizedKey = String(key || "").replace(/[*_]/g, "").trim().toLowerCase();
  if (/^provocation(?:\s*\/\s*palliation)?$/.test(normalizedKey)) {
    return _userMessageExplicitlyRequestsProvocation(message);
  }
  return true;
}

function _normalizeExamFindingValue(key = "", value = "") {
  let clean = String(value || "").replace(/[*_]/g, "").trim();
  const normalizedKey = String(key || "").replace(/[*_]/g, "").trim().toLowerCase();
  if (/^dcap[-\s]?btls\b/i.test(normalizedKey)) {
    clean = clean
      .replace(/\babrasion\s*\(\s*laceration\s*\)/gi, "laceration")
      .replace(/\babrasions?\s*\/\s*lacerations?\b/gi, "laceration")
      .replace(/\blacerations?\s*\/\s*abrasions?\b/gi, "laceration");
  }
  return clean;
}

function _examKeyShouldRenderInfoBox(key = "") {
  const normalizedKey = String(key || "").replace(/[*_]/g, "").trim().toLowerCase();
  if (!normalizedKey) return false;
  // OPQRST/SAMPLE items are interview/history answers. They should stay in the
  // patient/caregiver dialogue while their tags populate PCR/scoring evidence.
  if (/^(?:onset|provocation(?:\s*\/\s*palliation)?|palliation|quality|region(?:\s*\/\s*radiation)?|radiation|severity|time|time\s*\/\s*course|course|signs(?:\s*and\s*symptoms)?|symptoms?|allergies?|medications?|pmh|past\s*(?:medical\s*)?history|pertinent\s*history|last\s*oral\s*intake|events?|recent\s*illness|fever|prior\s*(?:episodes?|seizures?)|seizure\s*(?:onset|duration|history|type)|trauma|choking(?:\s*\/\s*foreign\s*body)?|foreign\s*body|ingestion)$/i.test(normalizedKey)) {
    return false;
  }
  return true;
}

function _examFindingShouldRenderChatCallout(key = "", value = "") {
  if (!_examKeyShouldRenderInfoBox(key)) return false;
  const normalizedKey = String(key || "").replace(/[*_]/g, "").trim().toLowerCase();
  const text = String(value || "").toLowerCase();
  const isVitalLikeExam = /^(?:temp|temperature|blood\s*pressure|bp|heart\s*rate|hr|pulse|resp(?:iratory)?\s*rate|respirations?|spo2|sp\s*o2|oxygen\s*saturation|blood\s*glucose|bgl|glucose)$/i.test(normalizedKey);
  if (isVitalLikeExam && /\b(?:per|from|reported by|according to)\s+(?:parent|parents|mom|mother|dad|father|caregiver|guardian|family|bystander)\b/i.test(text)) {
    return false;
  }
  return true;
}

function _examTagKeys(text = "") {
  const keys = [];
  const re = /\[\[\s*EXAM:\s*([^\]=:]+)\s*[:=]\s*[^\]]+\]\]/gi;
  let match;
  while ((match = re.exec(String(text || ""))) !== null) {
    keys.push(match[1].replace(/[*_]/g, "").trim());
  }
  return keys;
}

function _allExamTagsRenderAsInfoBoxes(text = "") {
  const keys = _examTagKeys(text);
  return keys.length > 0 && keys.every(_examKeyShouldRenderInfoBox);
}

function _messageSideHint(message = "") {
  const msg = _normalizeHistoryMapText(message);
  const hasLeft = /\bleft\b/.test(msg);
  const hasRight = /\bright\b/.test(msg);
  if (hasLeft && !hasRight) return "left";
  if (hasRight && !hasLeft) return "right";
  return "";
}

function _standardExamEntrySide(entry = {}) {
  const text = [
    entry.label,
    entry.exam_key,
    ...(entry.aliases || []),
    entry.finding,
  ].filter(Boolean).join(" ");
  return _messageSideHint(text);
}

function _messageLooksLikeStandardExam(message = "") {
  const msg = String(message || "");
  return /\b(?:assess(?:ing)?|inspect(?:ing)?|palpat(?:e|ing)|check(?:ing)?|conduct(?:ing)?|evaluate|perform(?:ing)?|exam(?:ine|ining)?|reassess(?:ing)?|recheck(?:ing)?)\b/i.test(msg)
    && /\b(?:nexus|dcap|btls|cms|pms|pulse|pupils?|eyes?|perrla|radial|pedal|dorsalis|posterior tibial|cap(?:illary)? refill|sensation|sensory|motor|movement|move|wiggle|grip|hand|forearm|arm|leg|foot|toe|distal|abdomen|pelvis|neck|spine|face|chest|thorax)\b/i.test(msg);
}

function _standardExamAliasScore(message = "", entry = {}) {
  const msg = _normalizeHistoryMapText(message);
  if (!msg) return 0;
  const messageSide = _messageSideHint(message);
  const entrySide = _standardExamEntrySide(entry);
  if (messageSide && entrySide && messageSide !== entrySide && !/\b(?:injured|affected|distal)\b/.test(msg)) {
    return 0;
  }

  const aliases = [
    entry.exam_key,
    entry.label,
    ...(entry.aliases || []),
  ].filter(Boolean);
  let best = 0;
  aliases.forEach(alias => {
    const normalized = _normalizeHistoryMapText(alias);
    if (!normalized) return;
    if (msg.includes(normalized)) {
      best = Math.max(best, normalized.length + 20);
      return;
    }
    const words = normalized.split(/\s+/).filter(word => word.length > 2 && !/^(the|and|for|with|assessment|assess|checking|check)$/.test(word));
    if (!words.length) return;
    const hits = words.filter(word => new RegExp(`\\b${word.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`).test(msg)).length;
    if (hits >= Math.min(words.length, 2)) best = Math.max(best, hits * 5);
  });
  return best;
}

function _authoredStandardExamFindingForMessage(message = "") {
  const findings = state.scenarioData?.standard_exam_findings;
  if (!findings || typeof findings !== "object" || !_messageLooksLikeStandardExam(message)) return null;
  const matches = Object.entries(findings)
    .map(([id, entry]) => ({ id, entry, score: _standardExamAliasScore(message, entry) }))
    .filter(match => match.score > 0)
    .sort((a, b) => (b.score - a.score));
  return matches[0] || null;
}

function _defaultStandardExamFindingForMessage(message = "") {
  if (!_messageLooksLikeStandardExam(message)) return null;
  const msg = String(message || "").toLowerCase();
  if (/\b(head|scalp|ears?)\b/.test(msg) && /\b(dcap|btls|palpat|inspect|assess|check|examin)\b/.test(msg)) {
    return {
      exam_key: "DCAP-BTLS Head",
      finding: "Head/scalp DCAP-BTLS assessed for deformity, contusions, abrasions, punctures, burns, tenderness, lacerations, swelling, and skull step-off; no visible injury or external hemorrhage noted.",
    };
  }
  if (/\b(face|facial|mouth|nose)\b/.test(msg)) {
    return {
      exam_key: "Facial / Mouth / Nose Assessment",
      finding: "Face assessed for asymmetry, droop, and DCAP-BTLS: no facial droop, asymmetry, deformity, tenderness, swelling, or visible injury noted.",
    };
  }
  if (/\b(jvd|jugular|neck veins?)\b/.test(msg)) {
    return {
      exam_key: "Jugular Veins / JVD",
      finding: "Jugular veins assessed: no jugular vein distension noted.",
    };
  }
  if (/\b(trachea|tracheal)\b/.test(msg)) {
    return {
      exam_key: "Tracheal Position",
      finding: "Trachea assessed and found midline without deviation.",
    };
  }
  if (/\b(neck|cervical|c-?spine|spine)\b/.test(msg)) {
    return {
      exam_key: "Neck / Cervical Spine Assessment",
      finding: "Neck and cervical spine assessed for DCAP-BTLS, midline tenderness, deformity, and step-off; no abnormal finding noted.",
    };
  }
  if (/\b(chest|thorax)\b/.test(msg)) {
    return {
      exam_key: "Chest Assessment",
      finding: "Chest inspected and palpated for DCAP-BTLS: no chest wall deformity, tenderness, crepitus, instability, or visible trauma noted.",
    };
  }
  if (/\b(abdomen|belly)\b/.test(msg)) {
    return {
      exam_key: "Abdomen Assessment",
      finding: "Abdomen inspected and palpated: soft, non-distended, and non-tender; no visible trauma noted.",
    };
  }
  if (/\b(pelvis|pelvic)\b/.test(msg)) {
    return {
      exam_key: "Pelvis Assessment",
      finding: "Pelvis assessed: stable without tenderness, deformity, or visible trauma.",
    };
  }
  return null;
}

function _messageLooksLikeCmsAssessment(message = "") {
  return /\b(?:cms|pms|neurovascular|distal|radial|pedal|dorsalis|posterior tibial|cap(?:illary)? refill|sensation|sensory|motor|movement|move|wiggle|grip|pulse)\b/i.test(String(message || ""));
}

function _messageTargetsInjuredOrAffectedSide(message = "", examEntry = {}) {
  const msg = _normalizeHistoryMapText(message);
  const side = _messageSideHint(message);
  const entrySide = _standardExamEntrySide(examEntry);
  if (/\b(?:injured|affected|distal)\b/.test(msg)) return true;
  if (!side) return true;
  return !entrySide || side === entrySide;
}

function _scenarioCmsTargetMatchesMessage(message = "") {
  const findings = state.scenarioData?.standard_exam_findings;
  if (!findings || typeof findings !== "object") return false;
  const side = _messageSideHint(message);
  return Object.values(findings).some(entry => {
    const text = [
      entry?.label,
      entry?.exam_key,
      ...(entry?.aliases || []),
      entry?.notes,
    ].filter(Boolean).join(" ");
    if (!/\b(?:cms|pms|neurovascular|distal|affected|injured)\b/i.test(text)) return false;
    const entrySide = _standardExamEntrySide(entry);
    return !side || !entrySide || side === entrySide;
  });
}

function _hasAppliedOrRecordedIntervention(interventionId, labelPattern = null) {
  if (!interventionId) return false;
  if (state.interventionsApplied.includes(interventionId)) return true;
  if (state.detectedTreatmentIds.includes(interventionId)) return true;
  if (!labelPattern) return false;
  return state.detectedTreatmentLabels.some(label => labelPattern.test(String(label || "")));
}

async function _maybeRecordCmsAssessmentFromMessage(message = "", examEntry = null) {
  if (!_messageLooksLikeCmsAssessment(message)) return;
  const entryText = [
    examEntry?._id,
    examEntry?.label,
    examEntry?.exam_key,
    ...(examEntry?.aliases || []),
  ].filter(Boolean).join(" ");
  const isScenarioCmsTarget = /\b(?:cms|pms|neurovascular|injured|affected|distal)\b/i.test(entryText);
  const messageNamesInjuredTarget = /\b(?:cms|pms|neurovascular|injured|affected|distal)\b/i.test(String(message || ""));
  const messageMatchesAuthoredCmsTarget = _scenarioCmsTargetMatchesMessage(message);
  if (!isScenarioCmsTarget && !messageNamesInjuredTarget && !messageMatchesAuthoredCmsTarget) return;
  if (!_messageTargetsInjuredOrAffectedSide(message, examEntry || {})) return;
  const pre = _interventionById["assess_cms"];
  const post = _interventionById["assess_cms_post"];
  if (!pre && !post) return;
  const splinted = _hasAppliedOrRecordedIntervention("splinting", /\bsplint|immobili/i);
  if (splinted && post && !_hasAppliedOrRecordedIntervention("assess_cms_post", /\bCMS Re-Assessment\b/i)) {
    await applyInterventionAndRecord("assess_cms_post", post.label || "CMS Re-Assessment — Post-Splint", { source: "authored_exam" });
    return;
  }
  if (!splinted && pre && !_hasAppliedOrRecordedIntervention("assess_cms", /\bCMS Assessment\b/i)) {
    await applyInterventionAndRecord("assess_cms", pre.label || "CMS Assessment — Pre-Splint", { source: "authored_exam" });
  }
}

async function _handleAuthoredStandardExamAction(message, chipId = null, isAction = false) {
  const match = _authoredStandardExamFindingForMessage(message);
  const fallback = !match?.entry?.finding ? _defaultStandardExamFindingForMessage(message) : null;
  const entry = match?.entry?.finding ? match.entry : fallback;
  if (!entry?.finding) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  const key = entry.exam_key || entry.label || "Exam Finding";
  const value = _normalizeExamFindingValue(key, entry.finding);
  await addPcrExam(key, value, "student_stated_exam");
  if (_examFindingShouldRenderChatCallout(key, value)) appendExamFindingInfo(key, value);
  await _maybeRecordCmsAssessmentFromMessage(message, { ...entry, _id: match?.id || "default_standard_exam" });
  appendLexiActionFeedback("focused_exam", LEXI_ACTION_FEEDBACK.focused_exam);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

function _historyResponseMapSpeaker(entry = {}) {
  return entry.speaker || _preferredScenarioHistorySpeaker(state.scenarioData) || "Patient";
}

function _lastUserMessageRequestsPatientName() {
  return _messageRequestsPatientName(_lastUserChatMessage);
}

function _lastUserMessageRequestsPatientAge() {
  const msg = _normalizeHistoryMapText(_lastUserChatMessage);
  return /\b(?:age|old|years? old|months? old|demographics?)\b/.test(msg);
}

function _lastUserMessageRequestsPatientDob() {
  const msg = String(_lastUserChatMessage || "").toLowerCase();
  return /\b(?:date\s+of\s+birth|dob|birth\s*date|birthday|born)\b/i.test(msg);
}

function _lastUserMessageRequestsPatientWeight() {
  const msg = _normalizeHistoryMapText(_lastUserChatMessage);
  return /\b(?:weigh|weight|pounds?|lbs?|kilograms?|kg|broselow|broslow|demographics?)\b/.test(msg);
}

function _captureDeferredPcrHeaderFromPlainText(text = "") {
  if (!_pcrDemographicsDeferred()) return 0;
  const body = String(text || "").replace(/[\u00a0\u202f]/g, " ");
  let applied = 0;
  const ptName = state.scenarioData?.patient?.name || "";
  if (_lastUserMessageRequestsPatientName() && ptName && new RegExp(`\\b${ptName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i").test(body)) {
    _capturePcrHeaderFinding("Patient Name", ptName);
    applied += 1;
  }

  const agePhraseMatch = body.match(/\b(\d+(?:\.\d+)?)\s*(?:-| )?(?:year|yr|month|mo|day)s?\s*old\b/i)
    || body.match(/\b(zero|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)\s*(?:-| )?(?:year|yr|month|mo|day)s?\s*old\b/i)
    || body.match(/\b(?:age|aged)\s*(?:is|:)?\s*(\d+(?:\.\d+)?)\b/i);
  if (_lastUserMessageRequestsPatientAge() && agePhraseMatch) {
    const wordAge = _numberWordToDigits(agePhraseMatch[1]);
    const ageDisplay = _scenarioAgeDisplay(state.scenarioData) || (wordAge
      ? `${wordAge} years old`
      : agePhraseMatch[0].replace(/\s+/g, " ").trim());
    _capturePcrHeaderFinding("Patient Age", ageDisplay);
    applied += 1;
  }

  const bornMatch = body.match(/\b(?:born\s+(?:on\s+)?|date\s+of\s+birth\s*(?:is|:)?\s*|dob\s*(?:is|:)?\s*)([A-Z][a-z]+\.?\s+\d{1,2},?\s+\d{4}|\d{1,2}\/\d{1,2}\/\d{2,4})/i);
  if (_lastUserMessageRequestsPatientDob() && bornMatch?.[1]) {
    _capturePcrHeaderFinding("Patient Date of Birth", bornMatch[1].replace(/\s+/g, " ").trim());
    applied += 1;
  }
  return applied;
}

function processAiTags(text, options = {}) {
  const { persistAuthoritative = true } = options;
  const vitalRegex = /\[\[\s*VITAL:\s*([^\]=:]+)\s*[:=]\s*([^\]]+)\]\]/gi;
  const examRegex  = /\[\[\s*EXAM:\s*([^\]=:]+)\s*[:=]\s*([^\]]+)\]\]/gi;
  const histRegex  = /\[\[\s*HISTORY:\s*([^\]=:]+)\s*[:=]\s*([^\]]+)\]\]/gi;
  const intRegex   = /\[\[\s*INTERVENTION:\s*([^\]]+)\]\]/gi;

  _vitalsBatch = {};
  const vitalTagSources = {};
  _pendingPopupQueue = [];

  if (!persistAuthoritative) {
    return text.replace(/\[\[\s*(VITAL|EXAM|HISTORY|INTERVENTION):[^\]]+\]\]/gi, "").replace(/\n{3,}/g, "\n\n").trim();
  }

  let m;
  const explicitVitalRequested = _userExplicitlyRequestedVitals(_lastUserChatMessage);
  const explicitGcsRequested = _userRequestedGcs(_lastUserChatMessage);
  while ((m = vitalRegex.exec(text)) !== null) {
    if (!explicitVitalRequested) {
      console.warn("Ignoring unrequested VITAL tag from AI response:", m[1]);
      continue;
    }
    if (!_vitalTagSourceAllowed(text, m.index)) {
      console.warn("Ignoring VITAL tag from non-EMS/history source:", m[1]);
      continue;
    }
    const key = m[1].replace(/[*_]/g, '').trim();
    if (/^gcs$/i.test(key) && !explicitGcsRequested) continue;
    _vitalsBatch[key] = m[2].replace(/[*_]/g, '').trim();
    vitalTagSources[key] = /\b(?:blood\s*glucose|blood\s*sugar|bgl|glucose)\b/i.test(key)
      ? "glucometer_check"
      : "authored_vitals";
  }
  while ((m = examRegex.exec(text))  !== null) {
    const key = m[1].replace(/[*_]/g, '').trim();
    if (!_examTagAllowedForUserContext(key, _lastUserChatMessage)) {
      console.warn("Ignoring EXAM tag not requested by learner context:", key);
      continue;
    }
    if (/^gcs(?:\s+components?)?$/i.test(key) && !explicitGcsRequested) continue;
    if (/^(?:avpu|loc|level\s+of\s+consciousness)$/i.test(key)) {
      const assessment = _scenarioExpectedAvpu();
      addPcrExam("LOC", assessment.value);
      if (assessment.description) addPcrExam("Mental Status", assessment.description);
      appendExamFindingInfo("Level of Consciousness", assessment.description || assessment.value);
      // Persist AVPU as structured evidence without rendering it under vitals.
      _postFinding("vital", "AVPU", assessment.value, "ai_roleplay_tag");
      continue;
    }
    const val = _normalizeExamFindingValue(key, m[2]);
    addPcrExam(key, val);
    if (_examFindingShouldRenderChatCallout(key, val)) appendExamFindingInfo(key, val);
  }
  while ((m = histRegex.exec(text))  !== null) {
    const key = m[1].replace(/[*_]/g, '').trim();
    const val = m[2].replace(/[*_]/g, '').trim();
    // Avoid unsolicited PMH/AMPLE dumps, but keep history unlocked once user starts asking.
    const patientHeaderTag = _pcrDemographicsDeferred() && _pcrHeaderKeyIsPatientScoped(key);
    if (patientHeaderTag && !_historyMapTagAllowedForContext(`[[HISTORY: ${key}=${val}]]`, _lastUserChatMessage, text)) {
      console.warn("Ignoring deferred PCR demographic tag not supported by user/chat context:", key);
      continue;
    }
    if (patientHeaderTag || _historyCaptureUnlocked || _historyPromptRequested(_lastUserChatMessage)) addPcrHistory(key, val);
  }
  while ((m = intRegex.exec(text))   !== null) {
    const label = m[1].replace(/[*_]/g, '').trim();
    const iv = findInterventionByLabel(label);
    if (!iv) continue; // ignore tags for labels not in the scenario's defined interventions
    if (state.interventionsApplied.includes(iv.id)) continue; // already recorded — no re-popup, no duplicate PCR entry
    if (_showFtoGuidanceForIntervention(iv, label)) continue;
    if (iv.requires_popup && !_pendingPopupQueue.find(q => q.id === iv.id)) {
      _pendingPopupQueue.push(iv);
    } else if (!iv.requires_popup) {
      addPcrTreatment(label, iv.id);
    }
  }

  if (Object.keys(_vitalsBatch).length > 0) {
    flushVitalsBlock({ ...vitalTagSources, default: "authored_vitals" });
  }

  return text.replace(/\[\[\s*(VITAL|EXAM|HISTORY|INTERVENTION):[^\]]+\]\]/gi, "").replace(/\n{3,}/g, "\n\n").trim();
}

function _stripUnrequestedVitalLines(text, sourceText = "") {
  if (_userExplicitlyRequestedVitals(_lastUserChatMessage)) return text;
  if (!/\[\[\s*VITAL:/i.test(sourceText)) return text;
  const vitalLine = /\b(?:heart\s*rate|hr|pulse|resp(?:iratory)?\s*rate|rr|respirations?|spo2|sp\s*o2|spO₂|oxygen\s*saturation|blood\s*pressure|bp|temperature|temp|blood\s*glucose|bgl|glucose|gcs|capillary\s*refill|cap\s*refill)\b/i;
  return String(text || "")
    .split("\n")
    .filter(line => !vitalLine.test(line))
    .join("\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

// Transitional ingestion — persists a structured finding to the backend so the
// debrief pipeline has access to it. Errors are non-fatal, but final
// handoff/debrief submission waits briefly for pending writes so quick-action
// findings are not lost when the session closes.
// Source is frontend tag parsing; findings are NOT independently verified facts.
const _pendingFindingWrites = new Set();
const _pendingEventWrites = new Set();

function _postFinding(findingType, key, value, source = "ai_roleplay_tag") {
  if (!state.sessionId) return Promise.resolve(null);
  const write = authFetch(`${API}/api/sessions/${state.sessionId}/findings`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    authRedirectOn401: false,
    body: JSON.stringify({ finding_type: findingType, key, value, source }),
  }).then(res => {
    if (!res.ok) console.warn("PCR finding persistence failed:", findingType, key, res.status);
    return res;
  }).catch(err => {
    console.warn("PCR finding persistence failed:", findingType, key, err);
    return null;
  });
  _pendingFindingWrites.add(write);
  write.finally(() => _pendingFindingWrites.delete(write));
  return write;
}

async function _flushPendingFindingWrites(timeoutMs = 2000) {
  const writes = [..._pendingFindingWrites];
  if (!writes.length) return;
  let timeoutId = null;
  const timeout = new Promise(resolve => {
    timeoutId = setTimeout(resolve, timeoutMs);
  });
  await Promise.race([Promise.allSettled(writes), timeout]);
  if (timeoutId) clearTimeout(timeoutId);
}

function _postSessionEvent(eventType, eventKey, eventData = {}) {
  if (!state.sessionId) return Promise.resolve(null);
  const write = authFetch(`${API}/api/sessions/${state.sessionId}/events`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    authRedirectOn401: false,
    body: JSON.stringify({
      event_type: eventType,
      event_key: eventKey,
      event_data: eventData,
      source: "frontend_explicit",
    }),
  }).then(res => {
    if (!res.ok) console.warn("Session event persistence failed:", eventType, eventKey, res.status);
    return res;
  }).catch(err => {
    console.warn("Session event persistence failed:", eventType, eventKey, err);
    return null;
  });
  _pendingEventWrites.add(write);
  write.finally(() => _pendingEventWrites.delete(write));
  return write;
}

async function _flushPendingSessionEventWrites(timeoutMs = 2000) {
  const writes = [..._pendingEventWrites];
  if (!writes.length) return;
  let timeoutId = null;
  const timeout = new Promise(resolve => {
    timeoutId = setTimeout(resolve, timeoutMs);
  });
  await Promise.race([Promise.allSettled(writes), timeout]);
  if (timeoutId) clearTimeout(timeoutId);
}

function _ftoAttemptPenaltyCategory(interventionMeta = null, guidance = "") {
  const text = `${interventionMeta?.id || ""} ${interventionMeta?.label || ""} ${guidance || ""}`.toLowerCase();
  if (interventionMeta?.within_bls_scope === false || interventionMeta?.expansion_not_selected === true) return "scope_adherence";
  if (/\b(contraindicat|not indicated|not appropriate|should not|do not|avoid|protocol)\b/.test(text)) return "protocols_treatment";
  return "clinical_performance";
}

function _recordInappropriateInterventionAttempt({ category = "clinical_performance", attemptType = "inappropriate_intervention", label = "Inappropriate intervention", reason = "", penaltyPoints = 3 } = {}) {
  const safeCategory = ["clinical_performance", "protocols_treatment", "scope_adherence", "professionalism"].includes(category)
    ? category
    : "clinical_performance";
  return _postSessionEvent("clinical_decision", "inappropriate_intervention_attempted", {
    category: safeCategory,
    attempt_type: attemptType,
    label,
    reason,
    penalty_points: Math.max(1, Math.min(6, Number(penaltyPoints) || 3)),
  });
}

function _turnoverTreatmentPayload() {
  return {
    interventions_performed: _pcrTreatmentLabelsForSubmission(),
    transport_decision: true,
    transport_rationale: "Transport via ALS — non-transport BLS agency",
    als_intercept: true,
    als_rationale: "ALS co-dispatched",
    additional_notes: "",
  };
}

async function _submitTreatmentForTurnover() {
  if (!state.sessionId) return null;
  return authFetch(`${API}/api/sessions/${state.sessionId}/treatment`, {
    method: "POST",
    authRedirectOn401: false,
    body: JSON.stringify(_turnoverTreatmentPayload()),
  });
}

async function _ensureTreatmentSubmittedForDmist(timeoutMs = 2500) {
  let treatmentRes = null;
  if (_turnoverTreatmentPromise) {
    let timeoutId = null;
    const timeout = new Promise(resolve => {
      timeoutId = setTimeout(() => resolve(null), timeoutMs);
    });
    treatmentRes = await Promise.race([_turnoverTreatmentPromise, timeout]);
    if (timeoutId) clearTimeout(timeoutId);
  }
  if (!treatmentRes) {
    treatmentRes = await _submitTreatmentForTurnover();
  }
  _turnoverTreatmentPromise = null;
  return treatmentRes;
}

function flushVitalsBlock(source = "ai_roleplay_tag") {
  const container = el("pcr-vitals");
  hide("pcr-vitals-empty");
  const elapsed = state.startTime
    ? formatTime(Math.floor((Date.now() - state.startTime.getTime()) / 1000))
    : new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });

  const block = document.createElement("div");
  block.className = "pcr-vital-block";
  block.innerHTML = `<div class="pcr-vital-time">@ ${elapsed}</div>` +
    Object.entries(_vitalsBatch).map(([label, val]) =>
      `<div class="pcr-item"><span class="pcr-item-key">${escapeHTML(label)}:</span><span class="pcr-vital-val">${escapeHTML(val)}</span></div>`
    ).join("");
  container.appendChild(block);
  container.scrollTop = container.scrollHeight;
  const sourceForLabel = (label, val) => {
    if (typeof source === "function") return source(label, val) || "ai_roleplay_tag";
    if (source && typeof source === "object") return source[label] || source.default || "ai_roleplay_tag";
    return source;
  };
  const writes = Object.entries(_vitalsBatch).map(([label, val]) => _postFinding("vital", label, val, sourceForLabel(label, val)));
  _orientationQueueCue("after_first_vitals");
  checkReadiness();
  _orientationFlushQueuedCues();
  return writes;
}

function addPcrExam(key, value, source = "ai_roleplay_tag") {
  value = _normalizePcrHeaderValue(key, value);
  const headerCaptured = _capturePcrHeaderFinding(key, value);
  const blockedHeaderOnly = _pcrDemographicsDeferred()
    && _pcrFindingShouldRenderOnlyInHeader(key)
    && !headerCaptured
    && !_pcrHeaderOnlyFieldRequestedForCurrentMessage(key);
  if (blockedHeaderOnly) {
    _removePcrHeaderOnlyRows("pcr-exam", key);
    return null;
  }
  if (_pcrDemographicsDeferred() && (headerCaptured || _pcrFindingShouldRenderOnlyInHeader(key))) {
    _removePcrHeaderOnlyRows("pcr-exam", key);
    return _postFinding("exam", key, value, source);
  }
  const container = el("pcr-exam");
  hide("pcr-exam-empty");
  const dkey = _pcrDataKeyForDisplayKey(key);
  const existing = container.querySelector(`[data-key="${dkey}"]`);
  if (existing) {
    existing.querySelector(".pcr-item-val").textContent = value;
  } else {
    const item = document.createElement("div");
    item.className = "pcr-item";
    item.dataset.key = dkey;
    _pcrItemInsertSeq += 1;
    item.dataset.pcrInsertSeq = String(_pcrItemInsertSeq);
    item.innerHTML = `<span class="pcr-item-key">${escapeHTML(key)}:</span><span class="pcr-item-val">${escapeHTML(value)}</span>`;
    container.appendChild(item);
  }
  _sortPcrMnemonicItems("pcr-exam");
  _orientationQueueCue("after_first_exam");
  checkReadiness();
  _orientationFlushQueuedCues();
  return _postFinding("exam", key, value, source);
}

// Always appends a new entry — used for repeated findings like multiple lung sound sets
function addPcrExamRaw(label, value, source = "ai_roleplay_tag") {
  value = _normalizePcrHeaderValue(label, value);
  const headerCaptured = _capturePcrHeaderFinding(label, value);
  const blockedHeaderOnly = _pcrDemographicsDeferred()
    && _pcrFindingShouldRenderOnlyInHeader(label)
    && !headerCaptured
    && !_pcrHeaderOnlyFieldRequestedForCurrentMessage(label);
  if (blockedHeaderOnly) {
    _removePcrHeaderOnlyRows("pcr-exam", label);
    return null;
  }
  if (_pcrDemographicsDeferred() && (headerCaptured || _pcrFindingShouldRenderOnlyInHeader(label))) {
    _removePcrHeaderOnlyRows("pcr-exam", label);
    return _postFinding("exam", label, value, source);
  }
  const container = el("pcr-exam");
  hide("pcr-exam-empty");
  const item = document.createElement("div");
  item.className = "pcr-item";
  _pcrItemInsertSeq += 1;
  item.dataset.pcrInsertSeq = String(_pcrItemInsertSeq);
  item.innerHTML = `<span class="pcr-item-key">${escapeHTML(label)}:</span><span class="pcr-item-val">${escapeHTML(value)}</span>`;
  container.appendChild(item);
  _sortPcrMnemonicItems("pcr-exam");
  _orientationQueueCue("after_first_exam");
  checkReadiness();
  _orientationFlushQueuedCues();
  return _postFinding("exam", label, value, source);
}

function addPcrHistory(key, value, source = "ai_roleplay_tag") {
  const rawKey = key;
  const historyLabel = _pcrCanonicalHistoryLabel(key);
  key = historyLabel.label || key;
  value = _normalizePcrHeaderValue(key, value);
  const headerCaptured = _capturePcrHeaderFinding(rawKey, value);
  const blockedHeaderOnly = _pcrDemographicsDeferred()
    && _pcrFindingShouldRenderOnlyInHeader(rawKey)
    && !headerCaptured
    && !_pcrHeaderOnlyFieldRequestedForCurrentMessage(rawKey);
  if (blockedHeaderOnly) {
    _removePcrHeaderOnlyRows("pcr-history", rawKey);
    return null;
  }
  if (_pcrDemographicsDeferred() && (headerCaptured || _pcrFindingShouldRenderOnlyInHeader(rawKey))) {
    _removePcrHeaderOnlyRows("pcr-history", rawKey);
    return _postFinding("history", rawKey, value, source);
  }
  const container = el("pcr-history");
  hide("pcr-history-empty");
  const dkey = _pcrDataKeyForDisplayKey(key);
  const existing = container.querySelector(`[data-key="${dkey}"]`);
  if (existing) {
    const existingIsCanonical = existing.dataset.canonicalHistorySource === "canonical";
    const incomingIsCanonical = historyLabel.canonical || rawKey === key;
    if (!existingIsCanonical || incomingIsCanonical) {
      existing.querySelector(".pcr-item-val").textContent = value;
      existing.dataset.canonicalHistorySource = incomingIsCanonical ? "canonical" : "alias";
    }
  } else {
    const item = document.createElement("div");
    item.className = "pcr-item";
    item.dataset.key = dkey;
    item.dataset.canonicalHistorySource = (historyLabel.canonical || rawKey === key) ? "canonical" : "alias";
    _pcrItemInsertSeq += 1;
    item.dataset.pcrInsertSeq = String(_pcrItemInsertSeq);
    item.innerHTML = `<span class="pcr-item-key">${escapeHTML(key)}:</span><span class="pcr-item-val">${escapeHTML(value)}</span>`;
    container.appendChild(item);
  }
  _sortPcrMnemonicItems("pcr-history");
  return _postFinding("history", rawKey, value, source);
}

function addPcrTreatment(label, interventionId = null) {
  if (_isUnscoredCprCompletedTreatmentLabel(label)) return;
  const container = el("pcr-treatments");
  hide("pcr-treatments-empty");
  if (interventionId && state.detectedTreatmentIds.includes(interventionId)) {
    const existing = container.querySelector(`[data-intervention-id="${CSS.escape(interventionId)}"]`);
    const shouldPreferSpecificLabel = /manual|in-line|inline/i.test(String(label || ""));
    if (existing && shouldPreferSpecificLabel) {
      const oldLabel = existing.dataset.label || "";
      existing.dataset.label = label;
      const oldIdx = state.detectedTreatmentLabels.indexOf(oldLabel);
      if (oldIdx >= 0) state.detectedTreatmentLabels[oldIdx] = label;
      existing.querySelector(".pcr-treat-val").textContent = `${state._lexiGuidedMode ? "✓🦴" : "✓"} ${label}`;
    }
    return;
  }
  if (state.detectedTreatmentLabels.includes(label)) return;
  if (interventionId) state.detectedTreatmentIds.push(interventionId);
  state.detectedTreatmentLabels.push(label);

  const lexiAssisted = state._lexiGuidedMode;
  if (lexiAssisted && !state._lexiAssistedTreatments.includes(label)) {
    state._lexiAssistedTreatments.push(label);
  }

  const item = document.createElement("div");
  item.className = "pcr-item";
  if (interventionId) item.dataset.interventionId = interventionId;
  item.dataset.label = label;
  item.innerHTML = `<span class="pcr-treat-val">${lexiAssisted ? "✓🦴" : "✓"} ${escapeHTML(label)}</span>`;
  container.appendChild(item);
  if (!_treatmentIsReportedAsVital(interventionId, label)) {
    appendProcedureInfo(label, label, {
      icon: lexiAssisted ? "🦴" : _treatmentInfoIcon(interventionId, label),
      title: _treatmentInfoTitle(interventionId, label),
    });
  }
  _orientationQueueCue("after_first_treatment");
  checkReadiness();
  _orientationFlushQueuedCues();
}

function _isUnscoredCprCompletedTreatmentLabel(label) {
  return /^CPR Challenge completed\s+—.*\(\s*not scored\s*\)\s*$/i.test(String(label || "").trim());
}

function _pcrTreatmentLabelsForSubmission() {
  return state.detectedTreatmentLabels.filter(label => !_isUnscoredCprCompletedTreatmentLabel(label));
}

/* ═══════════════════════════════════════════════════════════════════
   CHAT
   ═══════════════════════════════════════════════════════════════════ */

/* ═══════════════════════════════════════════════════════════════════
   READINESS CHECK — unlocks ALS Turnover button
   ═══════════════════════════════════════════════════════════════════ */

// Map a typed check definition from the scenario JSON to a live check function.
// Supported types: message_count, vitals_logged, exam_logged, treatment_logged, history_logged, med_control_logged, lexi_logged
function _resolveCheck(chk) {
  switch (chk.type) {
    case "message_count":
      return () => msgCount >= (chk.min ?? 5);
    case "vitals_logged":
      return () => el("pcr-vitals") && el("pcr-vitals").children.length > 0;
    case "exam_logged":
      return () => el("pcr-exam") && el("pcr-exam").children.length > 0;
    case "history_logged":
      return () => el("pcr-history") && el("pcr-history").children.length > 0;
    case "treatment_logged":
      return () => state.detectedTreatmentLabels.length > 0;
    case "med_control_logged":
      return () => _orientationMedControlLogged();
    case "lexi_logged":
      return () => Array.isArray(state.lexiHistory)
        && state.lexiHistory.some(item => item?.role === "user" && String(item.content || "").trim());
    default:
      return () => true;   // unknown type — always passes so new types don't break the button
  }
}

function buildReadinessCriteria() {
  const rc = state.scenarioData?.readiness_criteria || {};
  const minMin = rc.min_minutes ?? 3;

  // Time criterion is first when configured. Orientation/training scenarios can
  // set min_minutes: 0 to unlock as soon as authored checks are met.
  const criteria = [];
  if (minMin > 0) {
    criteria.push({
      id: "time",
      label: `${minMin} min on scene`,
      check: () => state.startTime && (Date.now() - state.startTime.getTime()) >= minMin * 60 * 1000,
    });
  }

  // Additional typed checks defined per-scenario
  for (const chk of (rc.checks || [])) {
    criteria.push({ id: chk.id, label: chk.label, check: _resolveCheck(chk) });
  }

  return criteria;
}

function _applyCurrentVitalsSnapshot(vitals = {}) {
  if (!vitals || typeof vitals !== "object") return;
  state.currentVitals = vitals;
  const presentation = vitals.patient_presentation;
  if (presentation) {
    setText("pcr-presentation", presentation);
  }
}

async function startVitalsWs() {
  // Close any existing connection before opening a new one (e.g. scenario retry).
  if (state.vitalsWs) {
    state.vitalsWs.close();
    state.vitalsWs = null;
  }

  let ticket = "";
  try {
    const tr = await authFetch(`${API}/api/ws-ticket`, { method: "POST" });
    if (tr.ok) { const td = await tr.json(); ticket = td.ticket || ""; }
  } catch {}

  if (!ticket) {
    // Ticket fetch failed — retry via the normal reconnect path if session is still active.
    if (state.sessionId) setTimeout(startVitalsWs, 3000);
    return;
  }

  const wsProto = location.protocol === "https:" ? "wss:" : "ws:";
  const ws = new WebSocket(`${wsProto}//${location.host}/ws/vitals/${state.sessionId}?ticket=${encodeURIComponent(ticket)}`);
  state.vitalsWs = ws;

  ws.onmessage = (event) => {
    try {
      const data = JSON.parse(event.data);
      if (data.vitals && typeof data.vitals === "object") {
        _applyCurrentVitalsSnapshot(data.vitals);
      }

      // Sync interventions applied — picks up server-side auto-detected ones
      // that the client may not know about (detected from chat text, e.g. telling Sarah/family).
      if (Array.isArray(data.interventions_applied)) {
        const prevApplied = new Set(state.interventionsApplied);
        state.interventionsApplied = data.interventions_applied;
        for (const ivId of data.interventions_applied) {
          if (!prevApplied.has(ivId)) {
            const iv = _interventionById[ivId];
            if (iv && !iv.requires_popup && iv.label) {
              addPcrTreatment(iv.label, ivId);
            }
          }
        }
      }

      checkReadiness();
    } catch { /* malformed frame — ignore */ }
  };

  ws.onerror = () => {
    console.warn("Vitals WebSocket error — will reconnect if session is active.");
  };

  ws.onclose = () => {
    state.vitalsWs = null;
    // Reconnect only if the session is still active (sessionId is cleared by
    // resetSessionState before the close event fires from an intentional close).
    if (state.sessionId) {
      setTimeout(startVitalsWs, 3000);
    }
  };
}

// ═══════════════════════════════════════════════════════════════════
//  ORIENTATION GUIDANCE SYSTEM
//  Populated from scenario.orientation_guidance when is_orientation is true.
//  Cues are advisory (not locking). Fired once per trigger; consumed on fire.
// ═══════════════════════════════════════════════════════════════════

let _orientationPendingCues = [];
let _orientationReadinessFired = false;
let _orientationSessionStartTimer = null;
let _orientationQueuedCueTriggers = [];
const ORIENTATION_ORDERED_CUE_TRIGGERS = [
  "after_first_message",
  "after_first_vitals",
  "after_first_exam",
  "after_first_treatment",
  "after_first_med_control",
  "after_first_lexi",
];

function _orientationInit() {
  _orientationPendingCues = [];
  _orientationReadinessFired = false;
  _orientationQueuedCueTriggers = [];
  if (_orientationSessionStartTimer) clearTimeout(_orientationSessionStartTimer);
  _orientationSessionStartTimer = null;

  if (!state.scenarioData?.is_orientation) return;

  const cues = state.scenarioData.orientation_guidance || [];
  _orientationPendingCues = cues.map(c => ({ ...c, fired: false }));

  // Fire session_start cues immediately when configured with delay_seconds: 0.
  const startCue = _orientationPendingCues.find(c => c.trigger === "session_start");
  if (startCue) {
    const delay = Math.max(0, Number(startCue.delay_seconds ?? 8) * 1000);
    _orientationSessionStartTimer = setTimeout(() => _orientationFireCue("session_start"), delay);
  }
}

function _orientationFireCue(triggerKey) {
  if (!state.scenarioData?.is_orientation) return;
  const cue = _orientationPendingCues.find(c => c.trigger === triggerKey && !c.fired);
  if (!cue) return;
  cue.fired = true;
  _orientationInjectMessage(cue.message);
}

function _orientationCueFired(triggerKey) {
  return _orientationPendingCues.some(c => c.trigger === triggerKey && c.fired);
}

function _orientationMedControlLogged() {
  return Array.isArray(_mc?.history)
    && _mc.history.some(item => item?.role === "caller" && String(item.content || "").trim());
}

function _orientationRepeatCue(triggerKey) {
  if (!state.scenarioData?.is_orientation) return false;
  const cue = _orientationPendingCues.find(c => c.trigger === triggerKey);
  if (!cue?.message) return false;
  _orientationInjectMessage(cue.message);
  return true;
}

function _orientationPromptForMedControlIfNeeded() {
  if (_orientationMedControlLogged()) return false;
  if (!_orientationCueFired("after_first_exam")) {
    return _orientationRepeatCue(_orientationCueFired("after_first_vitals") ? "after_first_vitals" : "after_first_message");
  }
  return _orientationRepeatCue("after_first_treatment");
}

function _orientationRepeatCueToken(triggerKey) {
  return `repeat:${triggerKey}`;
}

function _orientationBlockedCueReminder(triggerKey) {
  if (triggerKey === "after_first_vitals" && !_orientationCueFired("after_first_message")) {
    return "after_first_message";
  }
  if (triggerKey === "after_first_exam" && !_orientationCueFired("after_first_vitals")) {
    return "after_first_message";
  }
  if (triggerKey === "after_first_treatment" && !_orientationCueFired("after_first_exam")) {
    return _orientationCueFired("after_first_vitals") ? "after_first_vitals" : "after_first_message";
  }
  if (triggerKey === "after_first_med_control" && !_orientationCueFired("after_first_treatment")) {
    if (_orientationCueFired("after_first_exam")) return "after_first_exam";
    return _orientationCueFired("after_first_vitals") ? "after_first_vitals" : "after_first_message";
  }
  if (triggerKey === "after_first_lexi" && !_orientationCueFired("after_first_med_control")) {
    if (_orientationCueFired("after_first_treatment")) return "after_first_treatment";
    if (_orientationCueFired("after_first_exam")) return "after_first_exam";
    return _orientationCueFired("after_first_vitals") ? "after_first_vitals" : "after_first_message";
  }
  return null;
}

function _orientationQueueCue(triggerKey) {
  if (!state.scenarioData?.is_orientation) return;
  const blockedReminder = _orientationBlockedCueReminder(triggerKey);
  const orderedTrigger = blockedReminder
    ? (_orientationCueFired(blockedReminder) ? _orientationRepeatCueToken(blockedReminder) : blockedReminder)
    : triggerKey;
  if (orderedTrigger.startsWith("repeat:")) {
    if (!_orientationQueuedCueTriggers.includes(orderedTrigger)) {
      _orientationQueuedCueTriggers.push(orderedTrigger);
    }
    return;
  }
  const cue = _orientationPendingCues.find(c => c.trigger === orderedTrigger && !c.fired);
  if (!cue) return;
  if (!_orientationQueuedCueTriggers.includes(orderedTrigger)) {
    _orientationQueuedCueTriggers.push(orderedTrigger);
  }
}

function _orientationFlushQueuedCues() {
  if (!state.scenarioData?.is_orientation || !_orientationQueuedCueTriggers.length) return;
  const triggers = [..._orientationQueuedCueTriggers];
  _orientationQueuedCueTriggers = [];
  triggers.forEach(trigger => {
    if (trigger.startsWith("repeat:")) _orientationRepeatCue(trigger.slice("repeat:".length));
    else _orientationFireCue(trigger);
  });
  _orientationMaybeQueueReadinessCue();
}

function _orientationFlushPreReadinessCues() {
  const preReadinessTriggers = new Set(ORIENTATION_ORDERED_CUE_TRIGGERS);
  _orientationPendingCues.forEach(c => {
    if (preReadinessTriggers.has(c.trigger) && !c.fired) c.fired = true;
  });
}

function _orientationHasQueuedPreReadinessCue() {
  const preReadinessTriggers = new Set(ORIENTATION_ORDERED_CUE_TRIGGERS);
  return _orientationQueuedCueTriggers.some(trigger => preReadinessTriggers.has(trigger));
}

function _orientationMaybeQueueReadinessCue() {
  if (!state.scenarioData?.is_orientation || _orientationReadinessFired) return;
  const btn = el("btn-open-treatment");
  if (!btn || btn.disabled) return;
  const cue = _orientationPendingCues.find(c => c.trigger === "on_readiness_ready" && !c.fired);
  if (!cue) return;
  _orientationReadinessFired = true;
  setTimeout(() => _orientationFireCue("on_readiness_ready"), 650);
}

function _orientationMarkLexiInteraction() {
  _orientationQueueCue("after_first_lexi");
  checkReadiness();
  _orientationFlushQueuedCues();
}

function _orientationInjectMessage(markdown) {
  const chatLog = el("chat-messages") || el("chat-log");
  if (!chatLog) return;
  const div = document.createElement("div");
  div.className = "orientation-cue-msg";
  div.innerHTML = `
    <div class="orientation-cue-header">
      <span class="orientation-cue-icon">🐾</span>
      <span class="orientation-cue-label">Lexi — Station Guide</span>
    </div>
    <div class="orientation-cue-body">${renderMarkdown(markdown)}</div>
  `;
  chatLog.appendChild(div);
  chatLog.scrollTop = chatLog.scrollHeight;
}

function _orientationGuideMessageForCriterion(result) {
  const id = result?.id || "";
  const label = result?.label || "the next orientation step";
  const messages = {
    time: "Stay on scene until the **1 minute on scene** timer is checked off. Use the extra moment to review your notes or ask Jake one more assessment question.",
    messages: "Start by introducing yourself to Jake in the main chat. Try: **Hi Jake, I'm [your name] with [agency]. I'll be doing your assessment today.**",
    vitals: "Next, assess and record Jake's vitals. Open **Vitals** and document the baseline set before moving on.",
    exam: "Next, practice an exam finding. Use **LOC**, **Breathing**, **Pulse**, or the **Exam** tools to document what you assess.",
    treatment: "Next, practice one treatment or procedure. Use a treatment/action control or type a clear action in chat so it appears in your treatment record.",
    med_control: "Next, call **Medical Control** and send a brief practice report. This is just to learn the workflow.",
    lexi: "Next, use the **Lexi** panel. Ask a question or tap a Lexi prompt so you know where instructor help lives.",
  };
  return messages[id] || `Next, complete **${label}**. Check the readiness row at the top for what is still open.`;
}

function _orientationShowNextMissingStep() {
  if (!state.scenarioData?.is_orientation) return false;
  const results = buildReadinessCriteria().map(c => ({ ...c, met: c.check() }));
  const nextMissing = results.find(r => !r.met);
  if (nextMissing) {
    _orientationInjectMessage(_orientationGuideMessageForCriterion(nextMissing));
  } else {
    _orientationInjectMessage("You're ready. Tap **Get Drill Feedback** to complete the Station Skills Drill, then continue the Station 1 orientation.");
  }
  return true;
}

function checkReadiness() {
  const btn = el("btn-open-treatment");
  const btnDrill = el("btn-drill-feedback");
  const btnNextStep = el("btn-orientation-next-step");
  const bar = el("readiness-bar");
  if (!bar) return;

  const results = buildReadinessCriteria().map(c => ({ ...c, met: c.check() }));
  const allMet = results.every(r => r.met);
  if (btnNextStep) {
    btnNextStep.classList.toggle("hidden", !state.scenarioData?.is_orientation);
  }

  bar.innerHTML = results.map(r =>
    `<span title="${r.label}" class="text-xs ${r.met ? "text-green-400" : "text-gray-600"}">
      ${r.met ? "✓" : "○"} ${r.label}
    </span>`
  ).join("<span class='text-gray-700 mx-0.5'>·</span>");

  if (btn && !state.drillMode) {
    const wasMet = !btn.disabled;
    if (allMet) {
      btn.disabled = false;
      btn.className = "bg-red-700 hover:bg-red-600 text-white text-sm font-semibold px-4 py-2 rounded-lg transition-colors";
      btn.title = "Ready — give your ALS turnover";
      if (!wasMet && !_orientationReadinessFired) {
        if (_orientationHasQueuedPreReadinessCue()) {
          // Let the just-earned step instruction land after the partner/chat
          // response; it already tells the learner what to do next.
        } else {
          _orientationFlushPreReadinessCues();
          _orientationReadinessFired = true;
          _orientationQueueCue("on_readiness_ready");
        }
      }
    } else {
      btn.disabled = true;
      btn.className = "bg-gray-700 text-gray-400 text-sm font-semibold px-4 py-2 rounded-lg transition-colors cursor-not-allowed";
      btn.title = "Complete your assessment first";
    }
  }

  if (btnDrill && state.drillMode) {
    if (allMet) {
      btnDrill.disabled = false;
      btnDrill.className = "bg-yellow-700 hover:bg-yellow-600 text-white text-sm font-semibold px-4 py-2 rounded-lg transition-colors";
      btnDrill.title = "Get drill feedback";
    } else {
      btnDrill.disabled = true;
      btnDrill.className = "bg-gray-700 text-gray-400 text-sm font-semibold px-4 py-2 rounded-lg transition-colors cursor-not-allowed";
      btnDrill.title = "Complete your assessment first";
    }
  }
}

// Re-check time criterion every 15 seconds while on scene
let _readinessTimer = null;
function startReadinessTimer() {
  if (_readinessTimer) clearInterval(_readinessTimer);
  _readinessTimer = setInterval(checkReadiness, 15000);
}

el("btn-send").addEventListener("click", sendMessage);

el("chat-input").addEventListener("keydown", e => {
  if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); }
});
el("chat-input").addEventListener("focus", () => setTimeout(_syncSimMobileOffsets, 0));
el("chat-input").addEventListener("blur", () => setTimeout(_syncSimMobileOffsets, 0));

const _CHAT_QUICK_ACTIONS = {
  "btn-chat-loc": "I am assessing AVPU and level of consciousness.",
  "btn-chat-breathing": "I am assessing airway and breathing, including work of breathing and whether the airway is patent or obstructed.",
  "btn-chat-pulse": "I am manually checking for a pulse and assessing pulse quality.",
};

Object.entries(_CHAT_QUICK_ACTIONS).forEach(([btnId, message]) => {
  el(btnId)?.addEventListener("click", async () => {
    if (btnId === "btn-chat-loc") {
      await _recordAvpuAssessment(message, { isAction: true, chipId: btnId });
    } else if (btnId === "btn-chat-breathing") {
      await _recordBreathingAssessment(message, { isAction: true, chipId: btnId });
    } else {
      sendMessage(message, { isAction: true, chipId: btnId });
    }
    if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
  });
});

el("btn-chat-start-cpr")?.addEventListener("click", () => {
  if (_scenarioHasCprChallenge()) {
    _openCprChallengeHud("cpr_ready");
  } else {
    sendMessage("I am starting CPR.", { isAction: true, chipId: "btn-chat-start-cpr" });
  }
  if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
});

el("btn-orientation-next-step")?.addEventListener("click", () => {
  _orientationShowNextMissingStep();
  if (el("screen-sim")?.classList.contains("sim-mobile-active")) _setSimMobileTab("chat");
});

let msgCount = 0;
let o2Applied = false;

async function sendMessage(overrideText = null, options = {}) {
  // Guard: event listeners pass Event objects as first arg — reject non-strings
  if (overrideText instanceof Event || typeof overrideText !== "string") overrideText = null;
  const { chipId = null, isAction = false, suppressAuthoritativeTags = false, suppressGcsChallenge = false } = options;

  const input = el("chat-input");
  const message = overrideText ?? input.value.trim();
  if (!message || !state.sessionId) return;

  if (await _handleSuctionReadyConfirmation(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handlePatAssessmentAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handlePrimarySurveyAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleFocusedSecondaryAssessmentAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleCspineExamAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleInappropriateCprAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleFtoBlockedInterventionAttempt(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleOrientationTrainingTreatmentAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleRecoveryPositionAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleSuctionAirwayAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleProtectFromInjuryAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  if (await _handleSuctionReadyAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }

  const authoredVitalsDefs = _authoredVitalsRequestedDefs(message);
  const mixedGcsWithOtherVitals = _userRequestedGcs(message) && authoredVitalsDefs.length > 0;
  if (!suppressGcsChallenge && mixedGcsWithOtherVitals) {
    if (!overrideText) input.value = "";
    await _recordAuthoredVitalsRequest(message, { chipId, isAction });
    _openGcsAssessmentModal();
    return;
  }

  if (!suppressGcsChallenge && _userRequestedGcs(message)) {
    if (!overrideText) input.value = "";
    _openGcsAssessmentModal();
    return;
  }

  if (_userRequestedAvpuOnly(message)) {
    if (!overrideText) input.value = "";
    await _recordAvpuAssessment(message, { isAction, chipId });
    return;
  }
  const requestedAvpuWithVitals = _userRequestedAvpu(message) && authoredVitalsDefs.length > 0;

  if (await _handleAuthoredStandardExamAction(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }
  await _maybeRecordCmsAssessmentFromMessage(
    message,
    _authoredStandardExamFindingForMessage(message)?.entry || null,
  );

  if (_isLikelyAuthoredVitalsRequest(message)) {
    if (!overrideText) input.value = "";
    const handled = await _recordAuthoredVitalsRequest(message, { isAction, chipId });
    if (handled) {
      if (requestedAvpuWithVitals) {
        await _recordAvpuAssessment(message, { appendUser: false });
      }
      el("btn-send").disabled = false;
      input.focus();
      return;
    }
  }

  if (!overrideText) input.value = "";
  el("btn-send").disabled = true;
  if (isAction) {
    appendUserAction(message, chipId);
  } else {
    appendUserMessage(message);
  }
  _lastUserChatMessage = message;
  if (_lungSoundClarificationPending) {
    _lungSoundClarificationPending = false;
    if (_isYesMessage(message)) {
      _openLungSoundChallengeFromChat();
      el("btn-send").disabled = false;
      input.focus();
      return;
    }
    if (_isNoMessage(message)) {
      const prompt = "*Alex:* Okay — tell me exactly what assessment you want.";
      appendAiMessage(prompt);
      speakText(prompt);
      el("btn-send").disabled = false;
      input.focus();
      return;
    }
  }
  if (_scenarioUsesLungSoundChallenge() && _userExplicitlyRequestedLungSounds(message)) {
    _openLungSoundChallengeFromChat();
    el("btn-send").disabled = false;
    input.focus();
    return;
  }
  if (_maybeAmbiguousLungSoundRequest(message)) {
    _lungSoundClarificationPending = true;
    const prompt = "*Alex:* Did you mean lung sounds?";
    appendAiMessage(prompt);
    speakText(prompt);
    el("btn-send").disabled = false;
    input.focus();
    return;
  }
  if (_handleVolatileCurrentEventsOrientationQuestion(message)) {
    el("btn-send").disabled = false;
    input.focus();
    return;
  }
  if (_historyPromptRequested(message)) _historyCaptureUnlocked = true;
  const mappedHistoryEntry = _scenarioHistoryResponseMapEntry(message);
  if (mappedHistoryEntry) {
    _historyCaptureUnlocked = true;
    _applyHistoryResponseEntryTags(mappedHistoryEntry, message);
    if (_messageIsBareMechanismHow(message)) {
      const eventsValue = _eventsHistoryValueForMechanismEntry(mappedHistoryEntry);
      if (eventsValue) addPcrHistory("Events", eventsValue, "ai_roleplay_tag");
    }
    _captureKnownSceneNamesFromExchange(message, mappedHistoryEntry.answer);
    const speaker = _historyResponseMapSpeaker(mappedHistoryEntry);
    const display = `*${speaker}:* ${mappedHistoryEntry.answer}`;
    appendAiMessage(display);
    speakText(display);
    el("btn-send").disabled = false;
    input.focus();
    return;
  }
  if (await _handleManualCspineCommand(message, chipId, isAction)) {
    if (!overrideText) input.value = "";
    el("btn-send").disabled = false;
    input.focus();
    return;
  }
  const vitalsClarify = _buildPartnerVitalsClarifier(message);
  if (vitalsClarify) {
    appendAiMessage(vitalsClarify);
    speakText(vitalsClarify);
    el("btn-send").disabled = false;
    input.focus();
    return;
  }
  const typingEl = appendTypingIndicator();
  const slowResponseTimer = setTimeout(() => {
    if (typingEl.isConnected) {
      appendSystemMessage("Still waiting on scene updates… this can take a few seconds.");
    }
  }, 9000);
  // Track O2 early for badge
  if (!o2Applied && /\b(nrb|nasal\s+cannula|o2|oxygen|15\s*lpm)\b/i.test(message)) {
    o2Applied = true;
    if (msgCount <= 3) state._o2Early = true;
  }

  try {
    const res = await authFetch(`${API}/api/chat`, {
      method: "POST",
      body: JSON.stringify({
        session_id: state.sessionId,
        message,
        last_scene_speaker: _lastNonPartnerSceneSpeaker || null,
      }),
    });

    if (!res.ok) {
      typingEl.remove();
      if (res.status === 429) {
        appendSystemMessage("🐾 Lexi says: Whoa, slow down! Even I can only fetch one stick at a time. Give it a second and try again.");
      } else {
        appendSystemMessage("🐾 Lexi lost the signal for a second. Try sending that again.");
      }
      return;
    }

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "", aiText = "", aiEl = null;

    const _lsExtract = /\[\[\s*EXAM:\s*(?:Lung\s*Sounds?|Breath\s*Sounds?|Auscultation)\s*[:=]\s*([^\]]+)\]\]/i;
    const _lsStrip   = /\[\[\s*EXAM:\s*(?:Lung\s*Sounds?|Breath\s*Sounds?|Auscultation)\s*[:=]\s*[^\]]+\]\]/gi;

    let doneSeen = false;
    let _pendingChallengeAvailable = null;
    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        buffer += decoder.decode();
      } else {
        buffer += decoder.decode(value, { stream: true });
      }
      const lines = buffer.split("\n");
      buffer = done ? "" : lines.pop();
      const dataLines = done
        ? _extractSseDataLines(lines.join("\n"))
        : lines.map(l => l.trim()).filter(l => l.startsWith("data: ")).map(l => l.slice(6));
      for (const data of dataLines) {
        if (data === "[DONE]") {
          doneSeen = true;
          // Check for lung sound challenge before processing tags
          if (_shouldTriggerLungSoundChallenge(aiText)) {
            // Extract the finding value from the tag, strip it from aiText before PCR
            const lsMatch = aiText.match(_lsExtract);
            const lsFinding = lsMatch ? lsMatch[1].trim() : null;
            const cleanedForPcr = aiText.replace(_lsStrip, "");
            processAiTags(cleanedForPcr, { persistAuthoritative: false });
            const nonRevealDisplay = _stripLungRevealText(processAiTagsForDisplay(cleanedForPcr))
              || "";
            if (!aiEl) {
              typingEl.remove();
              if (nonRevealDisplay) aiEl = appendAiMessage("");
            }
            if (aiEl && nonRevealDisplay) renderAiText(aiEl, nonRevealDisplay);
            appendAssessmentInfo("Lung Sounds", "Listen to the recording and identify what you hear.");
            openLungSoundChallenge(lsFinding);
          } else {
            const persistenceText = (!_userExplicitlyRequestedLungSounds(_lastUserChatMessage) && _LUNG_SOUND_TAG_RE.test(aiText))
              ? aiText.replace(_lsStrip, "")
              : aiText;
            processAiTags(persistenceText, { persistAuthoritative: !suppressAuthoritativeTags });
            if (!suppressAuthoritativeTags) {
              _applyScenarioHistoryResponseMapTags(_lastUserChatMessage, aiText);
              _captureDeferredPcrHeaderFromPlainText(aiText);
              _captureKnownSceneNamesFromExchange(_lastUserChatMessage, aiText);
            }
            let displayStr = _pendingPopupQueue.length > 0
              ? _popupQueuedDisplayText(_pendingPopupQueue)
              : processAiTagsForDisplay(aiText);
            displayStr = _stripUnrequestedVitalLines(displayStr, aiText);
            const hasExamOnlyFinding = _allExamTagsRenderAsInfoBoxes(aiText)
              && !/\[\[\s*(VITAL|HISTORY|INTERVENTION):/i.test(aiText)
              && _pendingPopupQueue.length === 0;
            if (!_userExplicitlyRequestedLungSounds(_lastUserChatMessage) && _LUNG_SOUND_TAG_RE.test(aiText)) {
              displayStr = _stripLungRevealText(processAiTagsForDisplay(aiText))
                || "*Alex:* I can auscultate lung sounds if you ask me to check them.";
              displayStr = _stripUnrequestedVitalLines(displayStr, aiText);
            }
            if (hasExamOnlyFinding) displayStr = "";

            // If the AI only output tags (and maybe a lonely *Alex:* header),
            // _parseAiDialogueChunks will yield 0 renderable chunks. Inject fallback!
            if (!hasExamOnlyFinding && _parseAiDialogueChunks(displayStr).length === 0) {
              displayStr = Object.keys(_vitalsBatch).length > 0
                ? "*Alex:* Here are the vitals you requested."
                : "*(Action completed)*";
            }
            if (hasExamOnlyFinding && aiEl) {
              aiEl.remove();
              aiEl = null;
            }
            if (displayStr) {
              if (!aiEl) { typingEl.remove(); aiEl = appendAiMessage(""); }
              if (aiEl) renderAiText(aiEl, displayStr);
            } else if (typingEl?.isConnected) {
              typingEl.remove();
            }
            // Check if we need to queue speech due to pending popups
            if (!displayStr) {
              // Exam findings render as info cards and are intentionally not voiced.
            } else if (_pendingPopupQueue.length > 0) {
              // Queue speech for after popup completion
              speakText(displayStr);
              setTimeout(advanceInterventionQueue, 400);
            } else {
              speakText(displayStr);  // Speak the full AI response after streaming
            }
          }
          break;
        }
        try {
          const parsed = JSON.parse(data);
          if (parsed.type === "provider_error") {
            typingEl.remove();
            const errEl = appendAiMessage("");
            errEl.innerHTML = `<div class="bubble provider-error-msg">AI is temporarily at capacity — your progress is saved. Try again in a moment.</div>`;
            break;
          } else if (parsed.text) {
            aiText += parsed.text;
            if (!aiEl) { typingEl.remove(); aiEl = appendAiMessage(""); }
            // Display with tags stripped
            renderAiText(aiEl, processAiTagsForDisplay(aiText));
          } else if (parsed.challenge_available) {
            // Primary survey milestone fired — queue impression challenge after [DONE]
            _pendingChallengeAvailable = parsed.challenge_available;
          }
        } catch { /* partial chunk */ }
      }
      if (done || doneSeen) break;
    }

    if (isAction) _orientationMarkTreatmentInteraction(message);
    checkReadiness();
    if (!isAction) _orientationFireCue("after_first_message");
    _orientationFlushQueuedCues();
    state._lexiGuidedMode = false;  // clear after main chat response processed

    if (_pendingChallengeAvailable) {
      _openOrQueueImpressionChallenge(_pendingChallengeAvailable);
      _pendingChallengeAvailable = null;
    }
    // Patient presentation is kept current by the vitals WebSocket — no poll needed.
  } finally {
    clearTimeout(slowResponseTimer);
    el("btn-send").disabled = false;
    input.focus();
    _syncSimMobileOffsets();
  }
}

// Strip tags for real-time display during streaming (fast path — no PCR update)
function processAiTagsForDisplay(text) {
  let display = text
    .replace(/\[\[\s*(VITAL|EXAM|HISTORY|INTERVENTION):[^\]]+\]\]/gi, "")
    .replace(/\[\[\s*EXAM:\s*(?:Lung\s*Sounds?|Breath\s*Sounds?|Auscultation)\s*[:=]\s*[^\]]+\]\]/gi, "")
    // Strip any [[TAG that was truncated mid-stream (no closing ]]).
    .replace(/\[\[(?![\s\S]*\]\])[\s\S]*$/, "")
    // Normalize single embedded newlines to spaces so multiline authored vital
    // values (e.g. "Work of Breathing\nModerate — subcostal retractions...") read
    // as a flat sentence. Double newlines (paragraph breaks) are preserved.
    .replace(/([^\n])\n([^\n])/g, "$1 $2")
    .replace(/\n{3,}/g, "\n\n").trim();
  if (!_userRequestedGcs(_lastUserChatMessage)) {
    display = display
      .replace(/\bGCS\s*(?:is|=|:)?\s*\d{1,2}(?:\s*\/\s*15)?(?:\s*\([^)]+\))?\.?/gi, "")
      .replace(/\bGlasgow\s+Coma\s+Scale\s*(?:is|=|:)?\s*\d{1,2}(?:\s*\/\s*15)?(?:\s*\([^)]+\))?\.?/gi, "")
      // Strip E/V/M component scores ("E4 V5 M6", "Eyes 4 Verbal 5 Motor 6")
      .replace(/\bE\s*[1-4]\s*V\s*[1-5]\s*M\s*[1-6]\b/gi, "")
      .replace(/\bEyes?\s+\d\s*[,/]?\s*Verbal\s+\d\s*[,/]?\s*Motor\s+\d\b/gi, "")
      .replace(/\bscore(?:\s+is|:)?\s+\d{1,2}\s*(?:out\s+of|\/)\s*15\b/gi, "")
      .replace(/\n{3,}/g, "\n\n")
      .trim();
  }
  if (_userRequestedAvpu(_lastUserChatMessage)) {
    const assessment = _scenarioExpectedAvpu();
    const locText = assessment.value || "alert";
    const detail = assessment.description || `Level of consciousness is ${locText}.`;
    display = display
      .replace(/\bPatient is alert\.?/gi, detail)
      .replace(/\bLevel of consciousness\s*(?:is|=|:)?\s*alert\.?/gi, `Level of consciousness is ${locText}.`)
      .replace(/\bLOC\s*(?:is|=|:)?\s*alert\.?/gi, `LOC is ${locText}.`)
      .replace(/\n{3,}/g, "\n\n")
      .trim();
  }
  return display;
}

function _stripLungRevealText(text) {
  return String(text || "")
    .split("\n")
    .filter(line => {
      const l = String(line || "");
      if (!l.trim()) return true;

      // Remove explicit auscultation/lung-sound reveal text, but preserve the
      // broader breathing assessment. A general breathing quick action may
      // legitimately report work of breathing, airway patency, retractions,
      // audible stridor/wheeze, etc. Those findings should not disappear just
      // because the model also emitted a lung-sound EXAM tag.
      if (/(lung\s*sounds?|breath\s*sounds?|auscultation|auscultat(?:e|ing|ion))/i.test(l)) return false;

      const mentionsAdventitious = /\b(wheez(?:e|ing|es)?|crackles?|rhonchi|stridor)\b/i.test(l);
      const isBreathingStatus = /\b(breath(?:ing)?|work\s+of\s+breath(?:ing)?|wob|airway|respiratory|respirations?|retractions?|accessory\s+muscles?|patent|obstruct(?:ed|ion)?)\b/i.test(l);
      return !mentionsAdventitious || isBreathingStatus;
    })
    .join("\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function _normalizeLungSoundIntentMessage(message = "") {
  return String(message || "")
    .toLowerCase()
    .replace(/\b(?:a|the)?\s*long\s+sounds?\b/g, "lung sounds")
    .replace(/\balong\s+sounds?\b/g, "lung sounds")
    .replace(/\b(?:one|won)\s+sounds?\b/g, "lung sounds")
    .replace(/\blung\s+sound\b/g, "lung sounds");
}

function _userExplicitlyRequestedLungSounds(message = "") {
  const msg = _normalizeLungSoundIntentMessage(message);
  return /\b(lungs?\s*sounds?|breath\s*sounds?|auscultat(?:e|ing|ion)|listen to (?:the )?(?:lungs|chest)|check (?:the )?(?:lungs|breath sounds)|(?:hear|check|get|listen to|auscultat(?:e|ing|ion))\s+(?:the\s+)?lungs?\s*sounds?)\b/.test(msg);
}

function appendUserMessage(text) {
  _markSimLearnerActivityForLexiIdle();
  const div = document.createElement("div");
  div.className = "msg-user";
  div.innerHTML = `<div class="bubble">${escapeHTML(text)}</div><div class="meta">${escapeHTML(state.firstName || state.studentName)} · now</div>`;
  el("chat-messages").appendChild(div);
  if (state.sessionId) msgCount++;
  scrollChat();
  return div;
}

// Immersive Mode: UI-injected action bubble (Jump Bag, chips, Body Map, FAB)
// Visually distinct from typed messages; LLM receives identical payload
function appendUserAction(text, chipId = null) {
  _markSimLearnerActivityForLexiIdle();
  const div = document.createElement("div");
  div.className = "msg-user msg-user-action";
  div.innerHTML = `<div class="bubble">${escapeHTML(text)}</div><div class="meta">🩺 Action · now</div>`;
  if (chipId) div.querySelector(".bubble").dataset.chipId = chipId;
  el("chat-messages").appendChild(div);
  if (state.sessionId) msgCount++;
  scrollChat();
  return div;
}

function appendAiMessage(text) {
  const div = document.createElement("div");
  div.className = "msg-ai-batch";
  div.innerHTML = "";
  el("chat-messages").appendChild(div);
  if (text) renderAiText(div, text);
  scrollChat();
  return div;
}

const _AI_SPEAKER_COLOR_CLASSES = [
  "ai-speaker-1",
  "ai-speaker-2",
  "ai-speaker-3",
  "ai-speaker-4",
  "ai-speaker-5",
];
const _SCENARIO_SPEAKER_COLOR_CLASSES = {
  patient: "ai-speaker-patient",
  partner: "ai-speaker-partner",
  als: "ai-speaker-als",
  edPhysician: "ai-speaker-ed-physician",
  primaryCaregiver: "ai-speaker-caregiver-primary",
  secondaryCaregiver: "ai-speaker-caregiver-secondary",
  bystander1: "ai-speaker-bystander-1",
  bystander2: "ai-speaker-bystander-2",
};
let _aiSpeakerColorMap = new Map();
let _aiSpeakerColorCursor = 0;
let _scenarioSpeakerAliasMap = new Map();
let _scenarioCanonicalSpeakerColorMap = new Map();
let _lastNonPartnerSceneSpeaker = "";

function _normalizeSpeakerName(name = "") {
  return String(name || "")
    .replace(/^(\*\*|\*|__|_)+\s*/g, "")
    .replace(/\s*(\*\*|\*|__|_)+$/g, "")
    .trim();
}

function _normalizeSpeakerKey(name = "") {
  return _normalizeSpeakerName(name).toLowerCase().replace(/\s+/g, " ").trim();
}

function _speakerLookupKeys(name = "") {
  const raw = _normalizeSpeakerName(name);
  const keys = new Set();
  if (!raw) return [];
  const full = _normalizeSpeakerKey(raw);
  if (full) keys.add(full);
  const fullFirst = full.split(" ")[0];
  if (fullFirst) keys.add(fullFirst);

  const noParen = _normalizeSpeakerKey(raw.replace(/\([^)]*\)/g, " "));
  if (noParen) keys.add(noParen);
  const noParenFirst = noParen.split(" ")[0];
  if (noParenFirst) keys.add(noParenFirst);

  const parenMatches = [...raw.matchAll(/\(([^)]{1,40})\)/g)];
  for (const match of parenMatches) {
    const parenKey = _normalizeSpeakerKey(match[1]);
    if (parenKey) keys.add(parenKey);
    const parenFirst = parenKey.split(" ")[0];
    if (parenFirst) keys.add(parenFirst);
  }

  if (noParen.includes("/")) {
    noParen.split("/").map(p => _normalizeSpeakerKey(p)).filter(Boolean).forEach(k => keys.add(k));
  }
  if (noParen.includes(" - ")) {
    noParen.split(" - ").map(p => _normalizeSpeakerKey(p)).filter(Boolean).forEach(k => keys.add(k));
  }
  return [...keys];
}

function _roleLabelFromActor(role = "", relation = "") {
  const r = String(role || "").toLowerCase();
  const rel = String(relation || "").toLowerCase();
  const combined = `${r} ${rel}`;
  if (/\b(als|advanced[_\s-]*life[_\s-]*support|paramedic|medic)\b/.test(combined)) return "als";
  if (/\b(ed|er|emergency|receiving|hospital)\b.*\b(physician|doctor|md)\b/.test(combined)
    || /\b(physician|doctor|md)\b.*\b(ed|er|emergency|receiving|hospital)\b/.test(combined)
    || /\b(ed|er)[_\s-]*(physician|doctor|md)\b/.test(combined)) return "ed physician";
  if (r.includes("ems_partner") || r.includes("partner") || r.includes("crew")) return "partner";
  if (r.includes("patient")) return "patient";
  if (rel.includes("mother") || rel === "mom") return "mom";
  if (rel.includes("father") || rel === "dad") return "dad";
  if (rel.includes("guardian")) return "guardian";
  if (r.includes("family") || rel) return rel || "family";
  if (r.includes("bystander")) return "bystander";
  return "";
}

function _registerSpeakerAlias(alias, roleLabel, canonical, profile = null, colorClass = null) {
  const k = _normalizeSpeakerKey(alias);
  if (!k || !roleLabel) return;
  const displayName = _normalizeSpeakerName(canonical || alias);
  const canonicalKey = _normalizeSpeakerKey(displayName || alias);
  const resolvedColor = colorClass || _scenarioCanonicalSpeakerColorMap.get(canonicalKey) || null;
  if (!_scenarioSpeakerAliasMap.has(k)) {
    _scenarioSpeakerAliasMap.set(k, {
      role: roleLabel,
      canonical: canonicalKey,
      displayName,
      profile,
      colorClass: resolvedColor,
    });
  } else if (resolvedColor && !_scenarioSpeakerAliasMap.get(k)?.colorClass) {
    _scenarioSpeakerAliasMap.get(k).colorClass = resolvedColor;
  }
  const first = k.split(" ")[0];
  if (first && !_scenarioSpeakerAliasMap.has(first)) {
    _scenarioSpeakerAliasMap.set(first, {
      role: roleLabel,
      canonical: canonicalKey,
      displayName,
      profile,
      colorClass: resolvedColor,
    });
  } else if (first && resolvedColor && !_scenarioSpeakerAliasMap.get(first)?.colorClass) {
    _scenarioSpeakerAliasMap.get(first).colorClass = resolvedColor;
  }
}

function _profileFromScenarioPersona(persona = {}) {
  const known = _profileForKnownName(persona.name);
  const tts = persona.tts && typeof persona.tts === "object" ? persona.tts : {};
  const personaText = [
    tts.gender,
    tts.voice_role,
    tts.age_band,
    persona.sex,
    persona.gender,
    persona.role,
    persona.relation,
    persona.name,
    ...(Array.isArray(persona.aliases) ? persona.aliases : []),
  ].join(" ").toLowerCase();
  const inferredGender = /\b(mom|mother|female|girl|woman|wife|grandma|grandmother)\b/.test(personaText)
    ? "female"
    : /\b(dad|father|male|boy|man|husband|grandpa|grandfather)\b/.test(personaText)
      ? "male"
      : null;
  const gender = _genderForTts(tts.gender || persona.sex || persona.gender) || inferredGender || known?.gender || null;
  const ageBand = String(tts.age_band || "").toLowerCase();
  const age = ageBand === "child" || ageBand === "infant" || ageBand === "toddler" || ageBand === "adolescent"
    ? "child"
    : ageBand === "elderly"
      ? "elderly"
      : _ageBandForTts(persona.age) || known?.age || null;
  const speechNotes = `${persona.speaking_style || ""} ${persona.description || ""}`.toLowerCase();
  const nonverbal = tts.enabled === false || /\bnon[-\s]?verbal\b|\bcannot speak\b|\bnever speaks\b/.test(speechNotes);
  const voiceRole = tts.voice_role || null;
  const providerVoice = tts.provider_voice || null;
  return {
    gender,
    age,
    nonverbal,
    voiceRole,
    providerVoice,
    demeanor: tts.demeanor || null,
    delivery: tts.delivery || null,
    avoid: tts.avoid || null,
    speed: Number.isFinite(Number(tts.speed)) ? Number(tts.speed) : null,
  };
}

function _scenarioPersonaColorClass(persona = {}) {
  const nameKey = _normalizeSpeakerKey(persona?.name || "");
  if (nameKey && _scenarioCanonicalSpeakerColorMap.has(nameKey)) {
    return _scenarioCanonicalSpeakerColorMap.get(nameKey);
  }
  const role = _roleLabelFromActor(persona?.role, persona?.relation);
  if (role === "patient") return _SCENARIO_SPEAKER_COLOR_CLASSES.patient;
  if (role === "partner") return _SCENARIO_SPEAKER_COLOR_CLASSES.partner;
  if (role === "als") return _SCENARIO_SPEAKER_COLOR_CLASSES.als;
  if (role === "ed physician") return _SCENARIO_SPEAKER_COLOR_CLASSES.edPhysician;
  return null;
}

function _assignScenarioCanonicalSpeakerColor(canonical, colorClass) {
  const key = _normalizeSpeakerKey(canonical || "");
  if (key && colorClass && !_scenarioCanonicalSpeakerColorMap.has(key)) {
    _scenarioCanonicalSpeakerColorMap.set(key, colorClass);
  }
}

function _orderedScenarioBystanders(s = {}) {
  if (Array.isArray(s.scene?.bystanders)) return s.scene.bystanders.filter(by => by?.name);
  return [];
}

function _scenarioHasAuthoredBystander(s = {}) {
  if (_orderedScenarioBystanders(s).length > 0) return true;
  const personas = s.personas && typeof s.personas === "object" ? Object.values(s.personas) : [];
  return personas.some(persona => String(persona?.role || "").toLowerCase() === "bystander");
}

function _preferredScenarioHistorySpeaker(s = {}) {
  const initialSpeaker = String(s?.initial_complaint?.speaker || "").trim();
  if (initialSpeaker) return initialSpeaker;

  const personas = s?.personas && typeof s.personas === "object" ? Object.values(s.personas) : [];
  const family = personas.find(persona => {
    const role = _roleLabelFromActor(persona?.role, persona?.relation);
    return persona?.name && role && !["patient", "partner", "als", "ed physician"].includes(role);
  });
  if (family?.name) return family.name;
  if (s?.patient?.name) return s.patient.name;
  const bystander = _orderedScenarioBystanders(s)[0];
  if (bystander?.name) return bystander.name;
  return "";
}

function _seedScenarioSpeakerColors(s = {}) {
  _scenarioCanonicalSpeakerColorMap = new Map();
  if (s.patient?.name) {
    _assignScenarioCanonicalSpeakerColor(s.patient.name, _SCENARIO_SPEAKER_COLOR_CLASSES.patient);
  }

  const personas = s.personas && typeof s.personas === "object" ? Object.values(s.personas) : [];
  personas.forEach(persona => {
    if (!persona?.name) return;
    const role = _roleLabelFromActor(persona.role, persona.relation);
    if (role === "patient") _assignScenarioCanonicalSpeakerColor(persona.name, _SCENARIO_SPEAKER_COLOR_CLASSES.patient);
    if (role === "partner") _assignScenarioCanonicalSpeakerColor(persona.name, _SCENARIO_SPEAKER_COLOR_CLASSES.partner);
    if (role === "als") _assignScenarioCanonicalSpeakerColor(persona.name, _SCENARIO_SPEAKER_COLOR_CLASSES.als);
    if (role === "ed physician") _assignScenarioCanonicalSpeakerColor(persona.name, _SCENARIO_SPEAKER_COLOR_CLASSES.edPhysician);
  });

  const bystanderColors = [
    _SCENARIO_SPEAKER_COLOR_CLASSES.primaryCaregiver,
    _SCENARIO_SPEAKER_COLOR_CLASSES.secondaryCaregiver,
    _SCENARIO_SPEAKER_COLOR_CLASSES.bystander1,
    _SCENARIO_SPEAKER_COLOR_CLASSES.bystander2,
  ];
  _orderedScenarioBystanders(s).forEach((bystander, index) => {
    _assignScenarioCanonicalSpeakerColor(
      bystander.name,
      bystanderColors[Math.min(index, bystanderColors.length - 1)]
    );
  });

  let extraFamilyIndex = _orderedScenarioBystanders(s).length;
  personas.forEach(persona => {
    if (!persona?.name) return;
    const role = _roleLabelFromActor(persona.role, persona.relation);
    if (!role || role === "patient" || role === "partner" || role === "als" || role === "ed physician") return;
    if (_scenarioCanonicalSpeakerColorMap.has(_normalizeSpeakerKey(persona.name))) return;
    _assignScenarioCanonicalSpeakerColor(
      persona.name,
      bystanderColors[Math.min(extraFamilyIndex, bystanderColors.length - 1)]
    );
    extraFamilyIndex += 1;
  });
}

function _seedScenarioSpeakerAliases(scenario) {
  _scenarioSpeakerAliasMap = new Map();
  _lastNonPartnerSceneSpeaker = "";
  _aiSpeakerColorMap = new Map();
  _aiSpeakerColorCursor = 0;
  const s = scenario || state.scenarioData;
  if (!s) return;
  _seedScenarioSpeakerColors(s);

  const personas = s.personas && typeof s.personas === "object" ? Object.values(s.personas) : [];
  for (const persona of personas) {
    if (!persona || typeof persona !== "object") continue;
    const actorName = persona.name || "";
    const roleLabel = _personaSceneRoleDisplay(persona) || _roleLabelFromActor(persona.role, persona.relation);
    const canonical = actorName || (persona.role || "");
    const profile = _profileFromScenarioPersona(persona);
    const colorClass = _scenarioPersonaColorClass(persona);
    if (actorName) _registerSpeakerAlias(actorName, roleLabel, canonical, profile, colorClass);
    if (Array.isArray(persona.aliases)) {
      for (const alias of persona.aliases) _registerSpeakerAlias(alias, roleLabel, canonical, profile, colorClass);
    }
    if (persona.relation) _registerSpeakerAlias(persona.relation, roleLabel, canonical, profile, colorClass);
  }

  if (s.patient?.name) {
    const patientPersona = personas.find(p => _normalizeSpeakerKey(p?.name) === _normalizeSpeakerKey(s.patient.name)) || {};
    const speechNotes = `${patientPersona.speaking_style || ""} ${patientPersona.description || ""}`.toLowerCase();
    const profile = {
      gender: _genderForTts(s.patient.sex || s.patient.gender),
      age: _ageBandForTts(s.patient.age),
      nonverbal: /\bnon[-\s]?verbal\b|\bcannot speak\b|\bnever speaks\b/.test(speechNotes),
    };
    _registerSpeakerAlias(s.patient.name, "patient", s.patient.name, profile, _SCENARIO_SPEAKER_COLOR_CLASSES.patient);
  }
  if (Array.isArray(s.scene?.bystanders)) {
    for (const by of s.scene.bystanders) {
      if (!by?.name) continue;
      const roleLabel = _roleLabelFromActor("family", by.relation);
      const profile = _profileFromScenarioPersona(by);
      const colorClass = _scenarioCanonicalSpeakerColorMap.get(_normalizeSpeakerKey(by.name)) || null;
      _registerSpeakerAlias(by.name, roleLabel || "family", by.name, profile, colorClass);
      if (by.relation) _registerSpeakerAlias(by.relation, roleLabel || "family", by.name, profile, colorClass);
    }
  }
}

function _scenarioSpeakerMeta(name = "") {
  for (const key of _speakerLookupKeys(name)) {
    const meta = _scenarioSpeakerAliasMap.get(key);
    if (meta) return meta;
  }
  return null;
}

function _canonicalSpeakerDisplayName(name = "") {
  const normalized = _normalizeSpeakerName(name);
  const s = state.scenarioData || {};
  if (_normalizeSpeakerKey(normalized) === "bystander" && !_scenarioHasAuthoredBystander(s)) {
    return _preferredScenarioHistorySpeaker(s) || "Patient";
  }
  const meta = _scenarioSpeakerMeta(normalized);
  if (meta?.displayName) return meta.displayName;
  return normalized.replace(/\s*\([^)]{1,40}\)\s*/g, " ").replace(/\s+/g, " ").trim();
}

function _speakerDisplayRole(name = "", role = "") {
  const normalized = _normalizeSpeakerName(name);
  const s = state.scenarioData || {};
  if (_normalizeSpeakerKey(normalized) === "bystander" && !_scenarioHasAuthoredBystander(s)) {
    const preferred = _preferredScenarioHistorySpeaker(s);
    return preferred ? _speakerRoleHint(preferred) : "";
  }
  const meta = _scenarioSpeakerMeta(name);
  return meta?.role || role || _speakerRoleHint(name);
}

function _speakerRoleHint(name = "") {
  const fromScenario = _scenarioSpeakerMeta(name);
  if (fromScenario?.role) return fromScenario.role;

  const n = _normalizeSpeakerName(name).toLowerCase();
  const patientName = (state.scenarioData?.patient?.name || "").toLowerCase();
  if (/\b(als|advanced life support|paramedic|medic)\b/.test(n)) return "als";
  if (/\b(ed|er|emergency|receiving|hospital)\b.*\b(physician|doctor|md|dr\.?)\b/.test(n)
    || /\b(physician|doctor|md|dr\.?)\b.*\b(ed|er|emergency|receiving|hospital)\b/.test(n)
    || /\b(ed|er)[\s-]*(physician|doctor|md)\b/.test(n)) return "ed physician";
  if (n.includes("alex") || n.includes("partner") || n.includes("crew")) return "partner";
  if (n.includes("mom") || n.includes("mother")) return "mom";
  if (n.includes("dad") || n.includes("father")) return "dad";
  if (n.includes("parent") || n.includes("guardian")) return "family";
  if (patientName && n.includes(patientName)) return "patient";
  return "";
}

function _speakerProfileForTts(name = "") {
  const fromScenario = _scenarioSpeakerMeta(name);
  if (fromScenario?.profile) return fromScenario.profile;
  return _profileForKnownName(name) || { gender: null, age: null };
}

function _scenarioPatientProfileForTts() {
  const patient = state.scenarioData?.patient || {};
  const persona = state.scenarioData?.personas && typeof state.scenarioData.personas === "object"
    ? Object.values(state.scenarioData.personas).find(p => _normalizeSpeakerKey(p?.name) === _normalizeSpeakerKey(patient.name))
    : null;
  const profile = persona ? _profileFromScenarioPersona(persona) : {};
  return {
    gender: _genderForTts(patient.sex || patient.gender) || profile.gender || null,
    age: _ageBandForTts(patient.age) || profile.age || null,
    nonverbal: Boolean(profile.nonverbal) || Number(patient.age) < 2,
    name: patient.name || "",
  };
}

function _shouldSkipTtsForNonverbalPatient(speaker = "", text = "") {
  const patient = _scenarioPatientProfileForTts();
  if (!patient.nonverbal) return false;
  const role = speaker ? _speakerRoleForTts(speaker) : "";
  const isPatientSpeaker = role === "patient"
    || (patient.name && _speakerLookupKeys(speaker).includes(_normalizeSpeakerKey(patient.name)));
  const body = _cleanSpeakerText(text).toLowerCase();
  if (isPatientSpeaker) return true;
  if (speaker) return false;
  const looksLikeInfantOnlyAction = body.length <= 120
    && /\b(whimper|cry|cries|crying|bark-like cough|scream|arch|reach|cling|fuss|sob|gurgle)\b/.test(body)
    && !/\b(i|we|copy|checking|assess|auscult|report|lungs?|airway|spo2|oxygen|pulse|pressure|rate)\b/.test(body);
  return looksLikeInfantOnlyAction;
}

function _speakerColorClass(name = "") {
  const fromScenario = _scenarioSpeakerMeta(name);
  if (fromScenario?.colorClass) return fromScenario.colorClass;
  const role = fromScenario?.role || _speakerRoleHint(name);
  if (role === "partner") return _SCENARIO_SPEAKER_COLOR_CLASSES.partner;
  if (role === "patient") return _SCENARIO_SPEAKER_COLOR_CLASSES.patient;
  if (role === "als") return _SCENARIO_SPEAKER_COLOR_CLASSES.als;
  if (role === "ed physician") return _SCENARIO_SPEAKER_COLOR_CLASSES.edPhysician;
  const key = fromScenario?.canonical || _normalizeSpeakerKey(name);
  if (!key) return "ai-speaker-default";
  if (_scenarioCanonicalSpeakerColorMap.has(key)) return _scenarioCanonicalSpeakerColorMap.get(key);
  if (_aiSpeakerColorMap.has(key)) return _aiSpeakerColorMap.get(key);
  const cls = _AI_SPEAKER_COLOR_CLASSES[_aiSpeakerColorCursor % _AI_SPEAKER_COLOR_CLASSES.length];
  _aiSpeakerColorMap.set(key, cls);
  _aiSpeakerColorCursor += 1;
  return cls;
}

function _rememberLastNonPartnerSceneSpeaker(text = "") {
  const chunks = _parseAiDialogueChunks(text);
  for (let i = chunks.length - 1; i >= 0; i -= 1) {
    const chunk = chunks[i];
    if (chunk.type !== "speaker" || !chunk.speaker) continue;
    const speakerName = _canonicalSpeakerDisplayName(chunk.speaker);
    const role = _speakerDisplayRole(chunk.speaker, chunk.role);
    const roleKey = String(role || "").toLowerCase();
    const speakerKey = _normalizeSpeakerKey(speakerName);
    if (!speakerKey) continue;
    if (roleKey === "partner" || roleKey === "als" || roleKey === "ed physician") continue;
    if (speakerKey.includes("alex") || speakerKey.includes("lexi")) continue;
    _lastNonPartnerSceneSpeaker = speakerName;
    return;
  }
}

function _looksLikeActionLine(line = "") {
  const t = line.trim();
  if (!t) return false;
  if (/^\*[^*]+\*$/i.test(t)) return true;
  if (/^\[[^\]]+\]$/i.test(t)) return true;
  if (/^\(.*\)$/i.test(t)) return true;
  if (/^(?:radio crackles|monitor beeps?|beeps?|bleeps?|sirens?|footsteps?|door opens?|phone rings?)\b/i.test(t)) return true;
  return false;
}

function _cleanActionText(line = "") {
  const t = String(line || "").trim();
  if (!t) return "";
  return t
    .replace(/^\*+/, "")
    .replace(/\*+$/, "")
    .replace(/^\[+/, "")
    .replace(/\]+$/, "")
    .replace(/^\(+/, "")
    .replace(/\)+$/, "")
    .trim();
}

function _normalizeAiDialogueText(text = "") {
  let out = String(text || "").replace(/\r/g, "");
  const speakerLabel = "(?:[A-Za-z][A-Za-z.'\\-]{0,20}(?:\\s+[A-Za-z][A-Za-z.'\\-]{0,20}){0,3}(?:\\s*\\([^\\)]{1,20}\\))?)";
  const splitSpeaker = (full, before, label, offset, source) => {
    const prefix = String(source || "").slice(0, offset + String(before || "").length);
    if (/\b(?:Mr|Mrs|Ms|Miss|Mx|Dr|Prof|Officer|Deputy|Capt|Lt|Sgt)\.$/i.test(prefix)) {
      return full;
    }
    return `${before}\n${label}`;
  };
  // Split compressed multi-speaker turns into separate lines:
  // e.g. "Alex: ... Diane: Yes" -> "Alex: ...\nDiane: Yes"
  const inlineSpeaker = new RegExp(`(\\S)[^\\S\\n]+((?:\\*\\*|\\*|__|_)?\\s*${speakerLabel}\\s*(?:\\*\\*|\\*|__|_)?\\s*:)`, "g");
  // Split action markers followed by a new speaker on the same line.
  const actionThenSpeaker = new RegExp(`(\\*[^*\\n]{2,120}\\*)[^\\S\\n]+((?:\\*\\*|\\*|__|_)?\\s*${speakerLabel}\\s*(?:\\*\\*|\\*|__|_)?\\s*:)`, "g");
  let prev = "";
  while (prev !== out) {
    prev = out;
    out = out.replace(inlineSpeaker, splitSpeaker);
    out = out.replace(actionThenSpeaker, splitSpeaker);
  }
  return out;
}

function _splitLeadingActionFromSpeech(content = "") {
  const t = String(content || "").trim();
  if (!t) return null;
  let m = t.match(/^(?:\*+\s*)?(\([^)]{2,180}\)|\[[^\]]{2,180}\]|\*[^*]{2,180}\*)\s*[,—-]?\s*(.+)$/);
  if (m) return { action: m[1].trim(), speech: m[2].trim() };
  m = t.match(/^(\*[^*]{2,180}\*)\s*[,—-]?\s*(.+)$/);
  if (m) return { action: m[1].trim(), speech: m[2].trim() };
  return null;
}

function _cleanSpeakerText(text = "") {
  return String(text || "")
    .replace(/\[\[.*?\]\]/g, "")
    .replace(/^(\*\*|\*|__|_)+\s*/g, "")
    .replace(/\s*(\*\*|\*|__|_)+$/g, "")
    .trim();
}

function _parseLeadingSpeakerLine(line = "") {
  const trimmed = String(line || "").trim();
  const parentheticalSpeaker = trimmed.match(/^\(([A-Za-z][A-Za-z.'\-\s]{1,40})\)\s*:?\s*(.*)$/);
  if (parentheticalSpeaker) {
    const speaker = _normalizeSpeakerName(parentheticalSpeaker[1]);
    if (_speakerRoleHint(speaker)) {
      return {
        speaker,
        content: _cleanSpeakerText(parentheticalSpeaker[2]),
      };
    }
  }
  const match = String(line || "").trim().match(
    /^(?:\*\*|\*|__|_)?\s*([A-Za-z][A-Za-z.'-]{0,20}(?:\s+[A-Za-z][A-Za-z.'-]{0,20}){0,3}(?:\s*\([^)]{1,30}\))?)\s*(?:\*\*|\*|__|_)?\s*:\s*(?:\*\*|\*|__|_)?\s*(.*)$/
  );
  const fallbackMatch = match || String(line || "").trim().match(
    /^(?:\*\*|\*|__|_)?\s*([A-Za-z][A-Za-z.'-]{0,20}(?:\s+[A-Za-z][A-Za-z.'-]{0,20}){0,3}(?:\s*\([^)]{1,30}\))?)\s*(?:\*\*|\*|__|_)+\s*:\s*(?:\*\*|\*|__|_)?\s*(.*)$/
  );
  if (!fallbackMatch) return null;
  if (_looksLikeHistorySectionLabel(fallbackMatch[1])) return null;
  return {
    speaker: _normalizeSpeakerName(fallbackMatch[1]),
    content: _cleanSpeakerText(fallbackMatch[2]),
  };
}

function _looksLikeHistorySectionLabel(label = "") {
  const normalized = String(label || "")
    .toLowerCase()
    .replace(/[*_]/g, "")
    .replace(/\s+/g, " ")
    .trim();
  if (!normalized) return false;
  return /^(?:onset|provocation|palliation|quality|radiation|region|severity|time|signs(?: and symptoms)?|symptoms|allergies|medications|meds|past medical history|medical history|pmh|last oral intake|oral intake|loi|events(?: leading up)?|events leading to|fever|temperature|prior episodes|prior seizures)$/.test(normalized);
}

function _parseAiDialogueChunks(text = "") {
  const raw = _normalizeAiDialogueText(text);
  const lines = raw.split("\n");
  const chunks = [];
  let pendingSpeaker = null;
  let lastSpeakerChunk = null;

  for (const sourceLine of lines) {
    const line = sourceLine.trim();
    if (!line) {
      pendingSpeaker = null;
      lastSpeakerChunk = null;
      continue;
    }

    const protocolMatch = line.match(/^\[PROTOCOL NOTE:(.+?)\]$/i);
    if (protocolMatch) {
      chunks.push({ type: "protocol", text: protocolMatch[1].trim() });
      pendingSpeaker = null;
      lastSpeakerChunk = null;
      continue;
    }

    const speakerMatch = _parseLeadingSpeakerLine(line);
    if (speakerMatch) {
      const speaker = speakerMatch.speaker;
      const content = speakerMatch.content;
      const role = _speakerRoleHint(speaker);
      pendingSpeaker = { speaker, role };
      if (content) {
        const split = _splitLeadingActionFromSpeech(content);
        if (split) {
          chunks.push({ type: "action", text: split.action });
          if (split.speech) {
            const chunk = { type: "speaker", speaker, role, text: _cleanSpeakerText(split.speech) };
            chunks.push(chunk);
            lastSpeakerChunk = chunk;
            pendingSpeaker = null;
          } else {
            lastSpeakerChunk = null;
          }
        } else if (_looksLikeActionLine(content)) {
          chunks.push({ type: "action", text: content });
          lastSpeakerChunk = null;
        } else {
          const chunk = { type: "speaker", speaker, role, text: _cleanSpeakerText(content) };
          chunks.push(chunk);
          lastSpeakerChunk = chunk;
          pendingSpeaker = null;
        }
      } else {
        lastSpeakerChunk = null;
      }
      continue;
    }

    if (_looksLikeActionLine(line)) {
      chunks.push({ type: "action", text: line });
      pendingSpeaker = null;
      lastSpeakerChunk = null;
      continue;
    }

    if (pendingSpeaker) {
      const chunk = { type: "speaker", speaker: pendingSpeaker.speaker, role: pendingSpeaker.role, text: _cleanSpeakerText(line) };
      chunks.push(chunk);
      lastSpeakerChunk = chunk;
      pendingSpeaker = null;
      continue;
    }

    if (lastSpeakerChunk) {
      lastSpeakerChunk.text += `\n${_cleanSpeakerText(line)}`;
      continue;
    }

    chunks.push({ type: "narration", text: line });
  }

  return chunks;
}

function renderAiText(div, text) {
  const chunks = _parseAiDialogueChunks(text);
  _rememberLastNonPartnerSceneSpeaker(text);
  div.className = "msg-ai-batch";
  div.innerHTML = chunks.map(chunk => {
    if (chunk.type === "speaker") {
      const speakerLabel = _chatSpeakerLabelForDisplay(chunk.speaker, chunk.role);
      return `<div class="msg-ai msg-ai-split ${_speakerColorClass(chunk.speaker)}">
        <div class="meta"><span class="speaker-name">${escapeHTML(speakerLabel)}</span></div>
        <div class="bubble">${escapeHTML(chunk.text)}</div>
      </div>`;
    }
    if (chunk.type === "protocol") {
      return `<div class="msg-ai msg-ai-split ai-speaker-default">
        <div class="bubble"><div class="protocol-note">⚠ Protocol Note: ${escapeHTML(chunk.text)}</div></div>
      </div>`;
    }
    if (chunk.type === "action") {
      return `<div class="msg-action">${escapeHTML(_cleanActionText(chunk.text))}</div>`;
    }
    return `<div class="msg-ai msg-ai-split ai-speaker-default">
      <div class="bubble">${escapeHTML(chunk.text)}</div>
    </div>`;
  }).join("");
  scrollChat();
}

function appendTypingIndicator() {
  const div = document.createElement("div");
  div.className = "msg-ai";
  div.innerHTML = `<div class="bubble"><div class="typing-dots"><span></span><span></span><span></span></div></div>`;
  el("chat-messages").appendChild(div);
  scrollChat();
  return div;
}

function appendSystemMessage(text) {
  const div = document.createElement("div");
  div.className = "msg-system";
  div.textContent = `— ${text} —`;
  el("chat-messages").appendChild(div);
  scrollChat();
}

function appendAssessmentInfo(title = "Assessment Note", markdown = "", options = {}) {
  const { icon = "🩺", iconHtml = "", variant = "" } = options;
  const chatLog = el("chat-messages");
  if (!chatLog) return null;
  const div = document.createElement("div");
  const variantClass = /^[a-z0-9_-]+$/i.test(variant) ? ` orientation-cue-msg--${variant}` : "";
  const renderedIcon = iconHtml || `<span class="orientation-cue-icon">${escapeHTML(icon)}</span>`;
  div.className = `orientation-cue-msg${variantClass}`;
  div.innerHTML = `
    <div class="orientation-cue-header">
      ${renderedIcon}
      <span class="orientation-cue-label">${escapeHTML(title)}</span>
    </div>
    <div class="orientation-cue-body">${renderMarkdown(markdown)}</div>
  `;
  chatLog.appendChild(div);
  chatLog.scrollTop = chatLog.scrollHeight;
  return div;
}

function appendExamFindingInfo(label = "Exam Finding", value = "") {
  const cleanLabel = String(label || "Exam Finding").replace(/[*_]/g, "").trim() || "Exam Finding";
  const cleanValue = String(value || "").replace(/[*_]/g, "").trim();
  if (!cleanValue) return null;
  return appendAssessmentInfo(cleanLabel, cleanValue);
}

function _currentSceneElapsedLabel() {
  if (!state.startTime) return new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  return formatTime(Math.floor((Date.now() - state.startTime.getTime()) / 1000));
}

function _treatmentInfoIcon(interventionId = null, label = "") {
  const meta = interventionId ? _interventionById[interventionId] : null;
  const text = `${meta?.popup_type || ""} ${meta?.label || ""} ${label || ""}`.toLowerCase();
  if (/\b(blood\s+glucose|blood\s+sugar|bgl|glucometer|finger\s*stick)\b/.test(text)) {
    return "📊";
  }
  if (/\b(transport|transporting|transported|depart(?:ing|ed)?|en\s*route|arrival|arrived|on\s+scene|als\s+(?:arrival|arrived|on\s+scene)|medic\s+\d+\s+(?:arrival|arrived|on\s+scene))\b/.test(text)) {
    return "🚑";
  }
  if (/\b(unresponsive|became\s+unresponsive|goes?\s+unresponsive|arrest|deteriorat(?:e|es|ed|ing)|worsen(?:s|ed|ing)?|decompensat(?:e|es|ed|ing)|condition\s+change|status\s+change|scene\s+change|patient\s+change)\b/.test(text)) {
    return "🚨";
  }
  if (/\b(scene\s+safety|safe|unsafe|hazard|ppe|bsi|body\s+substance\s+isolation|law\s+enforcement|police|pd|fire\s+department|traffic|perimeter|staging|stage|secure(?:d)?|danger)\b/.test(text)) {
    return "🦺";
  }
  if (/\b(warning|caution|alert|risk|contraindicat(?:ed|ion)?|do\s+not|avoid|concern|watch\s+for)\b/.test(text)) {
    return "⚠️";
  }
  if (/\b(page|paging|paged|pager|tones?|tone\s+out|dispatch\s+page)\b/.test(text)) {
    return "📟";
  }
  if (/\b(dispatch|radio|contact|call|notify|request|requested|additional\s+(?:units?|help|resources?)|als|intercept|rendezvous|hospital|receiving|ed|emergency\s+department|trauma\s+center|burn\s+center)\b/.test(text)) {
    return "📡";
  }
  if (/\b(message|messages|notification|notified|update|advised|informed|communication)\b/.test(text)) {
    return "💬";
  }
  if (meta?.popup_type === "medication" || /\b(medication|administer(?:ed)?|dose|mg|mcg|ml|epi(?:nephrine)?|albuterol|naloxone|glucose|dextrose|benzodiazepine|midazolam|ketamine)\b/.test(text)) {
    return "💊";
  }
  return "⚕️";
}

function _treatmentIsReportedAsVital(interventionId = null, label = "") {
  const meta = interventionId ? _interventionById[interventionId] : null;
  const text = `${interventionId || ""} ${meta?.label || ""} ${label || ""}`.toLowerCase();
  return /\b(blood_glucose_check|blood\s+glucose|blood\s+sugar|bgl|glucometer|finger\s*stick)\b/.test(text);
}

function _treatmentInfoTitle(interventionId = null, label = "") {
  const meta = interventionId ? _interventionById[interventionId] : null;
  const text = `${meta?.popup_type || ""} ${meta?.label || ""} ${label || ""}`.toLowerCase();
  if (/\b(blood\s+glucose|blood\s+sugar|bgl|glucometer|finger\s*stick)\b/.test(text)) return "Vital Sign";
  return "Procedure";
}

function _ftoGuidanceIconHtml() {
  return `<span class="orientation-cue-icon fto-guidance-icon" aria-hidden="true">
    <svg viewBox="0 0 24 24" focusable="false">
      <path d="M12 3.2 19 6v5.1c0 4.4-2.8 8.3-7 9.7-4.2-1.4-7-5.3-7-9.7V6l7-2.8Z"></path>
      <path d="M12 7v6"></path>
      <path d="M12 16.6v.1"></path>
    </svg>
  </span>`;
}

function appendFtoGuidanceInfo(markdown = "") {
  const cleanText = String(markdown || "").replace(/[*_]/g, "").trim();
  if (!cleanText) return null;
  return appendAssessmentInfo(`FTO Guidance @ ${_currentSceneElapsedLabel()}`, cleanText, {
    iconHtml: _ftoGuidanceIconHtml(),
    variant: "fto",
  });
}

function _ftoGuidanceForIntervention(interventionMeta = null, label = "") {
  if (!interventionMeta) return "";
  const reason = String(interventionMeta.fto_guidance || interventionMeta.unavailable_reason || "").trim();
  const unavailable = interventionMeta.unavailable === true || interventionMeta.unavailable_in_scenario === true;
  const expansionBlocked = interventionMeta.expansion_not_selected === true;
  const outOfScope = interventionMeta.within_bls_scope === false;
  if (!reason && !unavailable && !expansionBlocked && !outOfScope) return "";
  const displayLabel = String(interventionMeta.label || label || "that intervention").replace(/[*_]/g, "").trim();
  let why = reason;
  if (!why && expansionBlocked) {
    why = "This treatment requires an agency-specific protocol expansion that is not active for this session.";
  } else if (!why && outOfScope) {
    why = "This intervention is outside the current BLS/EMT scope for this session.";
  } else if (!why && unavailable) {
    why = "This intervention is not available or not appropriate in the current scenario state.";
  }
  return `Do not perform: **${displayLabel}**.\n\n${why}`;
}

function _showFtoGuidanceForIntervention(interventionMeta = null, label = "") {
  if (_isOrientationScenarioActive()) return false;
  const guidance = _ftoGuidanceForIntervention(interventionMeta, label);
  if (!guidance) return false;
  appendFtoGuidanceInfo(guidance);
  _recordInappropriateInterventionAttempt({
    category: _ftoAttemptPenaltyCategory(interventionMeta, guidance),
    attemptType: interventionMeta?.within_bls_scope === false ? "out_of_scope_intervention" : "inappropriate_intervention",
    label: interventionMeta?.label || label || "Inappropriate intervention",
    reason: guidance.replace(/[*_]/g, " ").replace(/\s+/g, " ").trim(),
    penaltyPoints: interventionMeta?.within_bls_scope === false ? 3 : 3,
  });
  return true;
}

function _orientationTreatmentActionRequested(message = "") {
  if (!_isOrientationScenarioActive()) return false;
  const msg = String(message || "").toLowerCase();
  if (!/\b(administer(?:ing|ed)?|apply|applying|applied|start|starting|started|perform|performing|performed|place|placing|placed|prepare|preparing|prepared|give|giving|given|treat|treatment)\b/.test(msg)) {
    return false;
  }
  return /\b(?:medication|medication administration|aspirin|nitro(?:glycerin)?|albuterol|epinephrine|epi\b|naloxone|narcan|glucose|dextrose|glucagon|midazolam|diazepam|lorazepam|ondansetron|fentanyl|morphine|ketamine|oxygen|o2|nrb|nasal cannula|bvm|cpap|nebulizer|suction|opa|npa|airway adjunct|cpr|compressions?|aed|c-?collar|cervical collar|splint|immobiliz|direct pressure|pressure bandage|tourniquet|hemostatic|wound packing|chest seal|dressing|bandage)\b/.test(msg);
}

function _orientationMarkTreatmentInteraction(message = "") {
  if (!_orientationTreatmentActionRequested(message)) return;
  _orientationQueueCue("after_first_treatment");
}

async function _handleOrientationTrainingTreatmentAction(message, chipId = null, isAction = false) {
  if (!_orientationTreatmentActionRequested(message)) return false;
  const shouldRepeatMedControlPrompt = _orientationCueFired("after_first_treatment") && !_orientationMedControlLogged();
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  const practiceLabel = String(message || "Training treatment/procedure practiced").replace(/\s+/g, " ").trim();
  addPcrTreatment(`Orientation practice: ${practiceLabel}`, null);
  const display = "*Alex:* Copy — training action recorded in Notes for the orientation drill. Keep exploring, or call Medical Control when you're ready.";
  appendAiMessage(display);
  speakText(display);
  checkReadiness();
  _orientationFlushQueuedCues();
  if (shouldRepeatMedControlPrompt) _orientationPromptForMedControlIfNeeded();
  return true;
}

function appendProcedureInfo(label = "Procedure", detail = "", options = {}) {
  const { icon = "⚕️", title = "Procedure" } = options;
  const cleanLabel = String(label || "Procedure").replace(/[*_]/g, "").trim() || "Procedure";
  const cleanDetail = String(detail || cleanLabel).replace(/[*_]/g, "").trim();
  if (!cleanDetail) return null;
  return appendAssessmentInfo(`${title} @ ${_currentSceneElapsedLabel()}`, cleanDetail, { icon });
}

function appendCprCodeLogInfo(stamp = "", text = "") {
  const cleanText = String(text || "").replace(/[*_]/g, "").trim();
  if (!cleanText) return null;
  const cleanStamp = String(stamp || "").trim();
  const title = cleanStamp ? `Code Log @ ${cleanStamp}` : "Code Log";
  return appendAssessmentInfo(title, cleanText, { icon: "❤️" });
}

function _summarizeMedicalControlGuidance(reply = "") {
  const text = String(reply || "")
    .replace(/\s+/g, " ")
    .replace(/^(?:this is )?dr\.\s+[a-z.'-]+,\s*(?:medical control\.?\s*)?/i, "")
    .replace(/^medical control[,.\s-]*/i, "")
    .trim();
  if (!text) return "";

  const sentences = text.match(/[^.!?]+[.!?]+|[^.!?]+$/g) || [text];
  const priority = sentences.filter(sentence =>
    /\b(approve|approved|authorize|authorized|order|orders?|continue|transport|administer|give|withhold|do not|stop|repeat|contact|call back|notify|destination|dose|protocol|permission)\b/i.test(sentence)
  );
  const chosen = (priority.length ? priority : sentences).slice(0, 3).map(s => s.trim()).filter(Boolean);
  return chosen.join(" ").trim();
}

function _recordMedicalControlTurn(request = "", reply = "") {
  const guidance = _summarizeMedicalControlGuidance(reply);
  if (!guidance) return;
  const cleanRequest = String(request || "").replace(/[*_]/g, "").replace(/\s+/g, " ").trim();
  _mc.summaryTurns.push({ request: cleanRequest, guidance });
  _mc.summaryLogged = false;
}

function appendMedicalControlSummaryInfo() {
  if (_mc.summaryLogged || !_mc.summaryTurns.length) return null;
  const lines = _mc.summaryTurns.map((turn, idx) => {
    const prefix = _mc.summaryTurns.length > 1 ? `Call ${idx + 1}: ` : "";
    return turn.request
      ? `${prefix}Request: ${turn.request}\nGuidance/approval: ${turn.guidance}`
      : `${prefix}Guidance/approval: ${turn.guidance}`;
  });
  _mc.summaryLogged = true;
  return appendAssessmentInfo(`Medical Control Summary @ ${_currentSceneElapsedLabel()}`, lines.join("\n\n"), { icon: "📞" });
}

function appendMedicalControlInfo(request = "", reply = "") {
  _recordMedicalControlTurn(request, reply);
  return null;
}

function scrollChat() { const c = el("chat-messages"); c.scrollTop = c.scrollHeight; }

/* ═══════════════════════════════════════════════════════════════════
   LUNG SOUND CHALLENGE
   ═══════════════════════════════════════════════════════════════════ */

let _lungSoundPendingFinding = null;   // finding text to add to PCR after challenge
let _lungSoundUsed = false;            // unused — kept for resetSessionState compat
let _lungSoundSetCount = 0;           // how many sets have been auscultated this session
let _lungSoundClarificationPending = false;
let _suctionReadyConfirmationPending = false;
let _lungSoundActiveConfig = null;
let _lungSoundSelectedChoice = null;

const _LUNG_SOUND_CHOICES = [
  { id: "clear", label: "Clear bilaterally" },
  { id: "expiratory_wheeze", label: "Expiratory wheeze" },
  { id: "inspiratory_stridor", label: "Inspiratory stridor" },
  { id: "upper_airway_gurgling", label: "Upper-airway gurgling" },
  { id: "crackles", label: "Crackles" },
  { id: "rhonchi", label: "Rhonchi" },
  { id: "diminished", label: "Diminished breath sounds" },
  { id: "absent", label: "Absent breath sounds" },
];

// Matches any lung sounds EXAM tag variant the AI might generate
const _LUNG_SOUND_TAG_RE = /\[\[\s*EXAM:\s*(?:Lung\s*Sounds?|Breath\s*Sounds?|Auscultation)\s*[:=]/i;

// Returns true if this AI response should trigger the lung sound challenge.
function _shouldTriggerLungSoundChallenge(aiText) {
  if (!_scenarioUsesLungSoundChallenge()) return false;
  return _LUNG_SOUND_TAG_RE.test(aiText) && _userExplicitlyRequestedLungSounds(_lastUserChatMessage);
}

function _scenarioUsesLungSoundChallenge() {
  return Boolean(state.scenarioData);
}

function _isYesMessage(message = "") {
  return /^(?:y|yes|yeah|yep|correct|right|please do|go ahead|do that)\b/i.test(String(message || "").trim());
}

function _isNoMessage(message = "") {
  return /^(?:n|no|nope|negative|not really|not exactly|never mind|cancel)\b/i.test(String(message || "").trim());
}

function _maybeAmbiguousLungSoundRequest(message = "") {
  if (!_scenarioUsesLungSoundChallenge()) return false;
  const msg = String(message || "").toLowerCase().trim();
  if (!msg || _userExplicitlyRequestedLungSounds(msg)) return false;
  const actionish = /\b(get|check|listen|hear|auscultat(?:e|ing|ion)|assess|do)\b/.test(msg);
  const maybeLungish =
    /\b(?:along|long|lung)\s+sounds?\b/.test(msg) ||
    /\bbreath\b/.test(msg) ||
    (/\b(?:lung|chest)\b/.test(msg) && /\bsounds?\b/.test(msg));
  return actionish && maybeLungish;
}

function _openLungSoundChallengeFromChat() {
  if (!openLungSoundChallenge()) return;
  appendAssessmentInfo("Lung Sounds", "Listen to the recording and identify what you hear.");
}

function _openScenarioLungSoundChallenge(actionMessage = "") {
  if (!openLungSoundChallenge()) return;
  appendUserAction(actionMessage || "I am auscultating bilateral lung sounds.", "lung-sound-challenge");
  appendAssessmentInfo("Lung Sounds", "Listen to the recording and identify what you hear.");
}

function _scenarioSuggestsRespiratoryOrCardiacArrest() {
  const s = state.scenarioData || {};
  const concepts = [
    ...(s.clinical_context?.concepts || []),
    ...(s.clinical_context?.protocol_focus || []),
  ].join(" ");
  const text = [
    s.id,
    s.title,
    s.display_title,
    s.subtitle,
    s.category,
    s.patient?.chief_complaint,
    s.patient?.general_impression,
    concepts,
  ].filter(Boolean).join(" ").toLowerCase();
  return /\b(?:cardiac|respiratory)[_\s-]*arrest\b|\bcpr\b|\bpulseless\b|\bapneic\b/.test(text);
}

function _inferLungSoundAudioFile(config = {}) {
  const text = _normalizeLungSoundText(config);
  if (/\bgurg|secretions?|death\s*rattle\b/.test(text)) return "/static/audio/lung sounds/DeathRattle.mp3";
  if (/\bstridor|croup\b/.test(text)) return "/static/audio/lung sounds/InspiratoryStridor.mp3";
  if (/\bwheez/.test(text)) return "/static/audio/lung sounds/AsthmaWheezing.mp3";
  if (/\bcrackles?|rales?|rhonchi|rhonchus\b/.test(text)) return "/static/audio/lung sounds/CoarseCrackles.mp3";
  if (/\bclear|normal|no adventitious\b/.test(text)) return "/static/audio/lung sounds/clear.mp3";
  return "";
}

function _defaultLungSoundChallengeConfig() {
  if (_scenarioSuggestsRespiratoryOrCardiacArrest()) {
    return {
      enabled: true,
      audio_file: "",
      prompt: "Auscultate bilateral lung sounds — what do you hear?",
      accepted_answers: ["absent", "no breath sounds", "no air movement"],
      finding: "Absent breath sounds bilaterally.",
      correct_choice_id: "absent",
      feedback_correct: "Correct — absent breath sounds documented.",
      feedback_incorrect: "Listen for whether air movement is present or absent.",
    };
  }
  return {
    enabled: true,
    audio_file: "/static/audio/lung sounds/clear.mp3",
    prompt: "Auscultate bilateral lung sounds — what do you hear?",
    accepted_answers: ["clear", "clear bilaterally", "normal", "no adventitious sounds"],
    finding: "Clear bilaterally.",
    correct_choice_id: "clear",
    feedback_correct: "Correct — clear bilateral lung sounds documented.",
    feedback_incorrect: "Listen again for adventitious sounds such as wheeze, stridor, crackles, or rhonchi.",
  };
}

function _activeScenarioLungSoundChallengeConfig() {
  const fallback = _defaultLungSoundChallengeConfig();
  const authored = state.scenarioData?.lung_sound_challenge;
  if (!authored || typeof authored !== "object") return fallback;
  const hasAuthoredContent = Boolean(
    authored.finding ||
    authored.prompt ||
    authored.audio_file ||
    authored.correct_choice_id ||
    (Array.isArray(authored.accepted_answers) && authored.accepted_answers.length)
  );
  if (!hasAuthoredContent) return fallback;
  const merged = {
    ...fallback,
    ...authored,
    enabled: true,
    accepted_answers: Array.isArray(authored.accepted_answers) && authored.accepted_answers.length
      ? authored.accepted_answers
      : fallback.accepted_answers,
  };
  merged.audio_file = _scormAssetUrl(authored.audio_file || _inferLungSoundAudioFile(merged) || fallback.audio_file || "");
  return merged;
}

function _lungSoundConfigForCurrentState() {
  const lsc = _activeScenarioLungSoundChallengeConfig();
  const pt = lsc.post_treatment;
  const requiredId = pt?.requires_intervention_id || pt?.requires_intervention;
  const requiredLabel = pt?.requires_treatment_label;
  const postTreatmentActive = Boolean(
    pt && (
      (requiredId && state.interventionsApplied.includes(requiredId)) ||
      (requiredLabel && state.detectedTreatmentLabels.some(l =>
        l.toLowerCase().includes(requiredLabel.toLowerCase())
      ))
    )
  );
  if (postTreatmentActive && _lungSoundSetCount > 1) {
    const mergedPostTreatment = { ...lsc, ...pt, enabled: true };
    mergedPostTreatment.audio_file = _scormAssetUrl(pt.audio_file || _inferLungSoundAudioFile(mergedPostTreatment) || lsc.audio_file || "");
    return mergedPostTreatment;
  }
  lsc.audio_file = _scormAssetUrl(lsc.audio_file || "");
  return lsc;
}

function _normalizeLungSoundText(config = {}) {
  return [
    config.finding,
    ...(config.accepted_answers || []),
  ].filter(Boolean).join(" ").toLowerCase();
}

function _lungSoundChoiceId(config = {}) {
  const authoredChoice = String(config.correct_choice_id || "").trim();
  if (_LUNG_SOUND_CHOICES.some(choice => choice.id === authoredChoice)) return authoredChoice;
  const text = _normalizeLungSoundText(config);
  if (/\bgurg|secretions?|death\s*rattle\b/.test(text)) return "upper_airway_gurgling";
  if (/\babsent\b|\bno\s+(?:breath|lung)\s+sounds?\b|\bno air movement\b/.test(text)) return "absent";
  if (/\bstridor|stridorous|upper airway|croup\b/.test(text)) return "inspiratory_stridor";
  if (/\b(improved|resolved|clearing|clear|no adventitious|normal|good air movement|no wheeze|absent wheeze)\b/.test(text)) return "clear";
  if (/\bwheez/.test(text)) return "expiratory_wheeze";
  if (/\bcrackles?|rales?\b/.test(text)) return "crackles";
  if (/\brhonchi|rhonchus\b/.test(text)) return "rhonchi";
  if (/\bdiminished|decreased\b/.test(text)) return "diminished";
  return null;
}

function _renderLungSoundChoices(config = {}) {
  const optionsEl = el("lung-sound-options");
  if (!optionsEl) return;
  const correctId = _lungSoundChoiceId(config);
  const preferred = ["clear", "expiratory_wheeze", "inspiratory_stridor", "upper_airway_gurgling", "crackles", "rhonchi", "diminished", "absent"];
  const ordered = preferred
    .map(id => _LUNG_SOUND_CHOICES.find(choice => choice.id === id))
    .filter(Boolean);
  optionsEl.innerHTML = ordered.map(choice => `
    <button type="button" class="lung-sound-option" data-choice-id="${escapeHTML(choice.id)}" role="radio" aria-checked="false">
      ${escapeHTML(choice.label)}
    </button>
  `).join("");
  optionsEl.querySelectorAll(".lung-sound-option").forEach(btn => {
    btn.addEventListener("click", () => {
      if (el("btn-submit-lung-sound")?.classList.contains("hidden")) return;
      _lungSoundSelectedChoice = btn.getAttribute("data-choice-id");
      optionsEl.querySelectorAll(".lung-sound-option").forEach(other => {
        const selected = other === btn;
        other.classList.toggle("selected", selected);
        other.classList.remove("wrong", "correct");
        other.disabled = false;
        other.setAttribute("aria-checked", selected ? "true" : "false");
      });
      const fb = el("lung-sound-feedback");
      fb?.classList.add("hidden");
    });
  });
  return correctId;
}

function _buildPartnerVitalsClarifier(message = "") {
  const msg = String(message || "").toLowerCase();
  const partnerAddressed = /\b(alex|partner|crew|teammate)\b/.test(msg);
  const asksVitals = /\b(vitals?|v\s*\/\s*s|vital signs)\b/.test(msg) || /\b(get|grab|check|obtain|take)\s+(the\s+)?vitals?\b/.test(msg);
  if (!partnerAddressed || !asksVitals) return null;
  if (/\b(full|complete|all)\s+(?:set\s+of\s+)?vitals?\b/i.test(message) || /\bcomplete\s+vital\s+signs\b/i.test(message)) return null;
  const hasSpecific = /\b(pulse|heart rate|hr|bp|blood pressure|respiratory|respirations?|rr|spo2|o2 sat|oxygen sat|temp|temperature|gcs|bgl|glucose|skin|capillary|pain|etco2|etco₂|capnography|work of breathing|wob|respiratory effort|cardiac monitor|4-lead|rhythm|12-lead|ecg|ekg|orthostatic|reassessment|repeat)\b/.test(msg);
  if (hasSpecific) return null;
  return "*Alex:* Which vitals do you want first? I can grab pulse, blood pressure, respirations, SpO2, temp, GCS, or blood glucose.";
}

const _AUTHORED_VITAL_DEFS = [
  { key: "bp", label: "Blood Pressure", type: "vital", patterns: [/\bbp\b/i, /\bblood\s+pressure\b/i] },
  { key: "spo2", label: "SpO2", type: "vital", patterns: [/\bspo2\b/i, /\bsp\s*o2\b/i, /\bspo₂\b/i, /\bsp\s*o₂\b/i, /\bo2\s*sat(?:uration)?\b/i, /\bo₂\s*sat(?:uration)?\b/i, /\boxygen\s*sat(?:uration)?\b/i, /\bpulse\s*ox(?:imetry)?\b/i] },
  { key: "hr", label: "Heart Rate", type: "vital", patterns: [/\bheart\s+rate\b/i, /\bhr\b/i] },
  { key: "pulse_quality", aliases: ["pulse"], label: "Pulse", type: "exam", patterns: [/\bpulse\s+quality\b/i, /\bmanual(?:ly)?\s+check(?:ing)?\s+(?:for\s+)?(?:a\s+)?pulse\b/i, /\bcheck(?:ing)?\s+(?:for\s+)?(?:a\s+)?pulse\b/i, /\bassess(?:ing)?\s+(?:the\s+)?(?:patient'?s\s+)?pulse\b/i] },
  { key: "rr", label: "Resp Rate", type: "vital", patterns: [/\bresp(?:iratory)?\s+rate\b/i, /\brespirations?\b/i, /\brr\b/i] },
  { key: "temp", aliases: ["temperature"], label: "Temperature", type: "vital", patterns: [/\btemp(?:erature)?\b/i] },
  { key: "blood_glucose", aliases: ["bgl"], label: "Blood Glucose", type: "vital", patterns: [/\bblood\s+glucose\b/i, /\bblood\s+sugar\b/i, /\bglucose\b/i, /\bbgl\b/i, /\bglucometer\b/i, /\bfinger\s*stick\b/i] },
  { key: "skin_color", label: "Skin", type: "exam", patterns: [/\bskin\b/i, /\bcolor,\s*temperature,\s*and\s*condition\b/i] },
  { key: "cap_refill", label: "Cap Refill", type: "exam", patterns: [/\bcap(?:illary)?\s+refill\b/i] },
  { key: "pain", aliases: ["pain_score", "severity"], label: "Pain", type: "exam", fallback: "Pain score is not authored for this scenario; ask the patient directly if pain is relevant.", patterns: [/\bpain(?:\s+scale)?\b/i, /\b0\s*(?:-|to)\s*10\b/i, /\bseverity\b/i] },
  { key: "pupils", label: "Pupils", type: "exam", patterns: [/\bpupils?\b/i, /\bperrl\b/i] },
  { key: "work_of_breathing", label: "WOB", type: "exam", patterns: [/\bwork\s+of\s+breath(?:ing)?\b/i, /\bwob\b/i, /\brespiratory\s+(?:quality|effort)\b/i] },
  { key: "etco2", aliases: ["etco₂", "end_tidal_co2", "capnography"], label: "ETCO2", type: "vital", fallback: "ETCO2 is not authored for this scenario.", patterns: [/\betco2\b/i, /\betco₂\b/i, /\bend[-\s]?tidal\b/i, /\bwaveform\s+capnography\b/i, /\bcapnography\b/i] },
  { key: "cardiac_rhythm", aliases: ["rhythm", "monitor_rhythm"], label: "Cardiac Rhythm", type: "exam", fallback: "Cardiac rhythm is not authored for this scenario.", patterns: [/\bcardiac\s+monitor\b/i, /\b4[-\s]?lead\b/i, /\b(?:cardiac|monitor)\s+rhythm\b/i] },
  { key: "twelve_lead", aliases: ["12_lead", "ecg_12_lead", "ecg", "ekg"], label: "12-Lead ECG", type: "exam", fallback: "A 12-lead ECG interpretation is not authored for this scenario.", patterns: [/\b12[-\s]?lead\b/i, /\becg\b/i, /\bekg\b/i] },
  { key: "orthostatic", aliases: ["orthostatic_vitals", "orthostatics"], label: "Orthostatic Vitals", type: "exam", fallback: "Orthostatic vitals are not authored for this scenario.", patterns: [/\borthostatic\b/i] },
];

function _authoredVitalsBaseline() {
  return state.scenarioData?.vitals?.baseline || {};
}

function _authoredVitalsValueFor(def, options = {}) {
  const { includeFallback = false } = options;
  const baseline = _authoredVitalsBaseline();
  const keys = [def.key, ...(def.aliases || [])];
  const key = keys.find(k => baseline[k]);
  if (!key && def.key === "pulse_quality") {
    const derived = _derivePulseQualityFromVitals();
    return {
      key: "pulse_quality",
      spec: { label: def.label, value: derived },
      rawValue: derived,
    };
  }
  if (!key) {
    if (!includeFallback || !def.fallback) return null;
    return {
      key: def.key,
      spec: { label: def.label, value: def.fallback },
      rawValue: def.fallback,
      unavailable: true,
    };
  }
  const spec = baseline[key] || {};
  const snapshot = state.currentVitals || {};
  const rawValue = snapshot[key] ?? keys.map(k => snapshot[k]).find(v => v !== undefined && v !== null) ?? spec.value;
  return { key, spec, rawValue };
}

function _derivePulseQualityFromVitals() {
  const baseline = _authoredVitalsBaseline();
  const snapshot = state.currentVitals || {};
  const hrRaw = snapshot.hr ?? baseline.hr?.value;
  const hrText = String(hrRaw ?? "").trim();
  const hr = Number(String(hrRaw ?? "").match(/\d+(?:\.\d+)?/)?.[0] || NaN);
  const bpText = String(snapshot.bp ?? baseline.bp?.value ?? "").trim();
  const skinText = String(snapshot.skin_color ?? baseline.skin_color?.value ?? "").toLowerCase();
  const capRaw = snapshot.cap_refill ?? baseline.cap_refill?.value;
  const cap = Number(String(capRaw ?? "").match(/\d+(?:\.\d+)?/)?.[0] || NaN);
  const tempRaw = snapshot.temp ?? baseline.temp?.value;
  const temp = Number(String(tempRaw ?? "").match(/\d+(?:\.\d+)?/)?.[0] || NaN);

  if (/\b(no pulse|pulseless|absent|0)\b/i.test(hrText) || hr === 0) return "no pulse palpated";

  const weakPerfusion = /\b(pale|cool|cold|mottled|cyanotic|ashen|diaphoretic|clammy)\b/i.test(skinText)
    || (!Number.isNaN(cap) && cap > 2)
    || /\b(?:[0-7]?\d|8[0-9])\s*\/\s*\d{2,3}\b/.test(bpText);
  if (weakPerfusion) return "present, weak and rapid";
  if (!Number.isNaN(temp) && temp >= 102 && !Number.isNaN(hr) && hr >= 150) return "present, bounding and rapid";
  if (!Number.isNaN(hr) && hr >= 160) return "present, strong and rapid";
  if (!Number.isNaN(hr) && hr >= 120) return "present, rapid and regular";
  if (!Number.isNaN(hr) && hr <= 50) return "present, slow";
  return "present, strong and regular";
}

function _formatAuthoredVitalValue(def, options = {}) {
  const { useDisplay = true } = options;
  const found = _authoredVitalsValueFor(def, { includeFallback: true });
  if (!found) return null;
  const { spec, rawValue, unavailable = false } = found;
  const unit = String(spec.unit || "").trim();
  const displayValue = useDisplay && spec.display && String(rawValue ?? "") === String(spec.value ?? "")
    ? spec.display
    : rawValue;
  const valueText = String(displayValue ?? "").trim();
  const _unitAlts = (u) => {
    const ul = u.toLowerCase();
    if (ul === "bpm") return ["/min", "per min", "per minute", "beats/min"];
    if (ul === "/min") return ["bpm", "per min", "per minute", "beats/min"];
    return [];
  };
  const hasUnit = unit && (
    valueText.toLowerCase().includes(unit.toLowerCase()) ||
    _unitAlts(unit).some(alt => valueText.toLowerCase().includes(alt))
  );
  const display = `${valueText}${unit && !hasUnit ? ` ${unit}` : ""}`.trim();
  return {
    label: spec.label || def.label,
    value: display,
    detail: spec.detail || "",
    unavailable,
  };
}

function _compactPartnerFindingText(value = "") {
  return String(value || "")
    // Authored vitals sometimes contain display-oriented line breaks inside a
    // single value. Flatten them for Alex's spoken/read chat response only.
    .replace(/\s*\n+\s*/g, " ")
    .replace(/\s*\((?:appropriate|normal|expected|borderline)[^)]+\)/gi, "")
    .replace(/\s{2,}/g, " ")
    .trim();
}

function _actionVitalsRequestedDefs(items = []) {
  const requested = [];
  const add = (def, options = {}) => {
    const { includeFallback = true } = options;
    if (!def) return;
    if (requested.some(existing => existing.key === def.key)) return;
    if (_authoredVitalsValueFor(def, { includeFallback })) requested.push(def);
  };
  items.forEach(item => {
    const keys = item?.vitalKeys || [];
    if (keys.includes("__repeat__")) {
      _AUTHORED_VITAL_DEFS.forEach(def => add(def, { includeFallback: false }));
      return;
    }
    keys.forEach(key => add(_AUTHORED_VITAL_DEFS.find(def => def.key === key)));
  });
  return requested;
}

function _authoredVitalsRequestedDefs(message = "") {
  const msg = String(message || "");
  const fullSet = /\b(full|complete|all)\s+(?:set\s+of\s+)?vitals?\b/i.test(msg) || /\bvital\s+signs\b/i.test(msg);
  if (fullSet) {
    return _AUTHORED_VITAL_DEFS.filter(def => _authoredVitalsValueFor(def));
  }
  const repeatSet = /\brepeat(?:ing)?\s+vital|\breassess(?:ing)?\s+response|\breassessment\b/i.test(msg);
  if (repeatSet) {
    return _AUTHORED_VITAL_DEFS.filter(def => _authoredVitalsValueFor(def));
  }

  const requested = [];
  const add = (def) => {
    if (!def) return;
    if (!requested.some(existing => existing.key === def.key) && _authoredVitalsValueFor(def, { includeFallback: true })) requested.push(def);
  };
  _AUTHORED_VITAL_DEFS.forEach(def => {
    if (def.patterns.some(pattern => pattern.test(msg))) add(def);
  });
  if (/\bpulse\b/i.test(msg) && !/\bpulse\s*ox(?:imeter|imetry)?\b/i.test(msg)) add(_AUTHORED_VITAL_DEFS.find(def => def.key === "pulse_quality"));
  if (/\brespiratory\s+rate,\s*(?:rhythm|work\s+of\s+breathing|effort),\s*and\s*(?:quality|respiratory\s+effort)\b/i.test(msg)) add(_AUTHORED_VITAL_DEFS.find(def => def.key === "work_of_breathing"));
  if (/\bheart\s+rate\s+and\s+pulse\s+quality\b/i.test(msg)) {
    add(_AUTHORED_VITAL_DEFS.find(def => def.key === "hr"));
    add(_AUTHORED_VITAL_DEFS.find(def => def.key === "pulse_quality"));
  }
  return requested.filter(Boolean);
}

function _isLikelyAuthoredVitalsRequest(message = "") {
  const msg = String(message || "");
  if (_userRequestedGcs(msg)) return false;
  // Treatment verbs indicate medication/procedure intent, not a vital-check request
  if (/\b(administer|give|apply|start|place|put\s+on|treat)\b/i.test(msg)) return false;
  // Past-tense or externally-sourced queries are history questions, not on-scene checks
  if (/\bwhat\s+was\b/i.test(msg)) return false;
  if (/\b(last|prior|previous|home|baseline|cgm)\s+\w*\s*(blood|glucose|sugar|bgl|spo2|o2|oxygen|bp|pressure|rate|reading|vital)\b/i.test(msg)) return false;
  if (_authoredVitalsRequestedDefs(msg).length === 0) return false;
  return _userExplicitlyRequestedVitals(msg);
}

function _userExplicitlyRequestedVitals(message = "") {
  const msg = String(message || "");
  if (_userRequestedGcs(msg)) return false;
  const asksForVitalAction = /\b(alex|partner|please report|obtain(?:ing)?|assess(?:ing)?|check(?:ing)?|take|get|grab|vitals?|vital signs?|blood pressure|bp|spo2|sp\s*o2|spo₂|sp\s*o₂|o2\s*sat|o₂\s*sat|oxygen\s*saturation|pulse\s*ox|heart rate|hr|pulse|respiratory rate|respirations?|rr|temperature|temp|glucose|bgl|blood\s*sugar|skin|capillary|pain|pupils?|etco2|etco₂|capnography|work of breathing|wob|respiratory effort|cardiac monitor|4-lead|rhythm|12-lead|ecg|ekg|orthostatic|reassessment|repeat)\b/i.test(msg);
  if (!asksForVitalAction) return false;
  const generalStatusOnly = /\b(how(?:'s| is)?\s+(?:she|he|they|the patient)\s+(?:doing|looking)|any better|improv(?:e|ed|ing)|worse|status|condition)\b/i.test(msg)
    && !/\b(vitals?|vital signs?|spo2|sp\s*o2|spo₂|sp\s*o₂|o2\s*sat|o₂\s*sat|oxygen\s*saturation|pulse\s*ox|heart rate|hr|pulse|respiratory rate|respirations?|rr|blood pressure|bp|temperature|temp|glucose|bgl|blood\s*sugar|gcs|avpu)\b/i.test(msg);
  return !generalStatusOnly;
}

function _userPreparingSuctionOnly(message = "") {
  return /\b(?:prepar(?:e|ing)|set(?:ting)?\s*up|ready(?:ing)?)\b.{0,40}\bsuction\b/i.test(String(message || ""));
}

function _userAsksPartnerToPrepareSuction(message = "") {
  const msg = String(message || "");
  return /\b(?:alex|partner|crew|teammate)\b.{0,60}\b(?:prepar(?:e|ing)|set(?:ting)?\s*up|ready(?:ing)?)\b.{0,40}\bsuction\b/i.test(msg)
    || /\b(?:prepar(?:e|ing)|set(?:ting)?\s*up|ready(?:ing)?)\b.{0,40}\bsuction\b.{0,60}\b(?:alex|partner|crew|teammate)\b/i.test(msg);
}

function _userRequestsSuctionAirway(message = "") {
  const msg = String(message || "");
  if (_userPreparingSuctionOnly(msg)) return false;
  return /\b(?:suction(?:ing)?|clear(?:ing)?)\b.{0,50}\b(?:airway|mouth|oral|secretions?|saliva|fluids?)\b/i.test(msg)
    || /\b(?:airway|mouth|oral|secretions?|saliva|fluids?)\b.{0,50}\b(?:suction|clear)\b/i.test(msg)
    || /\b(?:suction(?:ing|ed)?|use(?:d)?\s+suction)\b.{0,40}\b(?:her|him|them|patient|pt|child|infant|baby|chloe)\b/i.test(msg)
    || /\b(?:her|him|them|patient|pt|child|infant|baby|chloe)\b.{0,40}\b(?:suction(?:ing|ed)?|use(?:d)?\s+suction)\b/i.test(msg);
}

function _userRequestsProtectFromInjury(message = "") {
  const msg = String(message || "");
  return /\bprotect(?:ing|ed)?\b.{0,60}\b(?:injur|trauma|harm|hurt|seizure|patient|infant|baby|her|him|them)\b/i.test(msg)
    || /\bprevent(?:ing|ed)?\b.{0,50}\b(?:injur|trauma|harm|hurt)\b/i.test(msg)
    || /\bkeep(?:ing)?\b.{0,50}\b(?:safe|protected)\b.{0,50}\b(?:injur|trauma|harm|hurt|seizure)\b/i.test(msg)
    || /\bsafe\b.{0,40}\bfrom\b.{0,30}\b(?:injur|trauma|harm|hurt)\b/i.test(msg)
    || /\b(?:clear|move)(?:ing)?\b.{0,50}\b(?:area|objects?|hazards?|toys?|furniture)\b/i.test(msg)
    || /\b(?:do not|don't|nothing|no)\b.{0,40}\b(?:restrain|mouth)\b/i.test(msg)
    || /\bpad(?:ding)?\b.{0,40}\b(?:head|around|area)\b/i.test(msg);
}

function _userRequestsRecoveryPosition(message = "") {
  const msg = String(message || "");
  return /\brecovery\s+position\b/i.test(msg)
    || /\blateral\s+(?:position|recumbent)\b/i.test(msg)
    || /\b(?:roll|turn|place|put|position)(?:ing)?\b.{0,50}\b(?:her|him|them|patient|infant|baby)?\s*(?:on(?:to)?|to|in)?\s*(?:her|his|their)?\s*side\b/i.test(msg)
    || /\b(?:onto|on|to)\s+(?:her|his|their|the)\s+side\b/i.test(msg);
}

function _userRequestsPatAssessment(message = "") {
  return /\b(?:pediatric\s+assessment\s+triangle|perform(?:ing)?\s+(?:the\s+)?pat\b|\bpat\s+assessment\b)\b/i.test(String(message || ""));
}

function _userRequestsPrimarySurvey(message = "") {
  return /\bprimary\s+survey\b/i.test(String(message || ""))
    || /\baddress(?:ing)?\s+immediate\s+life\s+threats?\b/i.test(String(message || ""));
}

function _userRequestsFocusedSecondaryAssessment(message = "") {
  return /\b(?:focused\s+)?secondary\s+assessment\b/i.test(String(message || ""));
}

function _scenarioUsesTraumaAssessmentRubric() {
  const s = state.scenarioData || {};
  if (String(s.category || "").toLowerCase().includes("trauma")) return true;
  if (String(s.base_patient_care_rubric || "").toLowerCase() === "nremt_trauma_v1") return true;
  const additional = Array.isArray(s.additional_patient_care_rubrics)
    ? s.additional_patient_care_rubrics
    : [];
  return additional.map(x => String(x || "").toLowerCase()).includes("nremt_trauma_v1");
}

function _nremtTraumaSecondaryAssessmentText() {
  return [
    "Inspects and palpates scalp and ears.",
    "Assesses eyes and pupils.",
    "Inspects mouth, nose, and facial area.",
    "Checks trachea position, jugular veins/JVD, and palpates cervical spine.",
    "Inspects chest, palpates chest, and auscultates chest/lung sounds.",
    "Inspects and palpates abdomen.",
    "Assesses pelvis.",
    "Verbalizes genitalia/perineum assessment as needed.",
    "Inspects and palpates both legs with PMS/CMS, motor, sensory, and distal circulation.",
    "Inspects and palpates both arms with PMS/CMS, motor, sensory, and distal circulation.",
    "Log roll to inspect and palpate posterior thorax.",
    "Inspects and palpates lumbar and buttocks areas.",
    "Identifies secondary injuries and wounds for appropriate management.",
    "No other injuries are identified on this broad secondary assessment.",
  ].join(" ");
}

function _userAttemptsCpr(message = "") {
  return /\b(?:start(?:ing)?|begin(?:ning)?|initiat(?:e|ing)|perform(?:ing)?|do(?:ing)?|commenc(?:e|ing))\b.{0,40}\b(?:cpr|compressions?)\b/i.test(String(message || ""))
    || /\b(?:cpr|compressions?)\b.{0,40}\b(?:start(?:ing)?|begin(?:ning)?|initiat(?:e|ing)|perform(?:ing)?|do(?:ing)?|commenc(?:e|ing))\b/i.test(String(message || ""));
}

function _scenarioCprCurrentlyIndicated() {
  if (_scenarioHasCprChallenge()) return true;
  if (_scenarioSuggestsRespiratoryOrCardiacArrest()) return true;
  const text = [
    state.scenarioData?.patient?.general_impression,
    state.scenarioData?.patient?.avpu_assessment?.description,
    state.scenarioData?.patient?.airway_assessment?.description,
    state.scenarioData?.vitals?.baseline?.pulse_quality?.value,
    state.scenarioData?.vitals?.baseline?.respirations?.value,
    state.scenarioData?.vitals?.baseline?.rr?.value,
  ].filter(Boolean).join(" ").toLowerCase();
  return /\b(?:pulseless|no\s+(?:central\s+)?pulse|absent\s+pulse|apneic|not\s+breathing|cardiac\s+arrest|respiratory\s+arrest)\b/.test(text);
}

function _isOrientationScenarioActive() {
  return state.scenarioData?.id === "orientation_01" || state.scenarioData?.is_orientation === true;
}

async function _handleInappropriateCprAction(message, chipId = null, isAction = false) {
  if (_isOrientationScenarioActive()) return false;
  if (!_userAttemptsCpr(message) || _scenarioCprCurrentlyIndicated()) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  const guidance = "Do not start CPR. CPR is for a patient who is pulseless and not breathing normally. This patient is responsive, breathing, and has a pulse, so starting compressions would be harmful. Continue airway and breathing support appropriate to the presentation.";
  appendFtoGuidanceInfo(guidance);
  _recordInappropriateInterventionAttempt({
    category: "clinical_performance",
    attemptType: "cpr_not_indicated",
    label: "CPR attempted when not indicated",
    reason: guidance,
    penaltyPoints: 4,
  });
  const display = "*Alex:* CPR is not indicated — the patient is responsive, breathing, and has a pulse.";
  appendAiMessage(display);
  speakText(display);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

function _unsupportedProcedureFtoGuidance(message = "") {
  const msg = String(message || "");
  const scenarioText = [
    state.scenarioData?.id,
    state.scenarioData?.title,
    state.scenarioData?.display_title,
    state.scenarioData?.patient?.chief_complaint,
    state.scenarioData?.patient?.general_impression,
    ...(state.scenarioData?.available_interventions || []).map(iv => iv.label),
  ].filter(Boolean).join(" ").toLowerCase();

  if (/\b(?:traction\s+splint|femur\s+fracture|femoral\s+fracture)\b/i.test(msg)
      && !/\b(?:traction\s+splint|femur\s+fracture|femoral\s+fracture|femoral\s+shaft)\b/.test(scenarioText)) {
    return "Do not perform: **Traction splint**.\n\nA traction splint is for an indicated femur/femoral shaft fracture. This scenario does not have a femur fracture finding, so applying traction would be inappropriate and could harm the patient.";
  }

  if (/\b(?:cpap|continuous\s+positive\s+airway\s+pressure)\b/i.test(msg)
      && !/\b(?:cpap|continuous\s+positive\s+airway\s+pressure)\b/.test(scenarioText)) {
    return "Do not perform: **CPAP**.\n\nCPAP is for selected patients with respiratory distress or hypoxia who can tolerate the mask and meet protocol indications. This scenario does not have a CPAP indication, so applying CPAP would be inappropriate.";
  }

  return "";
}

function _unsupportedProcedureAttemptLabel(message = "") {
  if (/\b(?:cpap|continuous\s+positive\s+airway\s+pressure)\b/i.test(String(message || ""))) {
    return "CPAP attempted when not indicated";
  }
  return "Unsupported procedure attempted";
}

async function _handleFtoBlockedInterventionAttempt(message, chipId = null, isAction = false) {
  if (_isOrientationScenarioActive()) return false;
  const iv = findInterventionByLabel(message);
  const guidance = iv ? _ftoGuidanceForIntervention(iv, message) : _unsupportedProcedureFtoGuidance(message);
  if (!guidance) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  appendFtoGuidanceInfo(guidance);
  _recordInappropriateInterventionAttempt({
    category: iv ? _ftoAttemptPenaltyCategory(iv, guidance) : "clinical_performance",
    attemptType: iv?.within_bls_scope === false ? "out_of_scope_intervention" : "inappropriate_intervention",
    label: iv?.label || _unsupportedProcedureAttemptLabel(message),
    reason: guidance.replace(/[*_]/g, " ").replace(/\s+/g, " ").trim(),
    penaltyPoints: iv?.within_bls_scope === false ? 3 : 3,
  });
  const display = "*Alex:* Hold up — that is not appropriate for this patient. Check the FTO note before proceeding.";
  appendAiMessage(display);
  speakText(display);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

async function _handlePatAssessmentAction(message, chipId = null, isAction = false) {
  if (!_userRequestsPatAssessment(message)) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;

  const s = state.scenarioData;
  const isPeds = s?.category === "pediatric_medical" || s?.category === "pediatric_trauma";
  if (isPeds) {
    _showPatModal();
    const display = "*Alex:* PAT challenge reopened.";
    appendAiMessage(display);
    speakText(display);
  } else {
    const display = "*Alex:* PAT is a pediatric doorway assessment. For this patient, continue with general impression and primary survey.";
    appendAiMessage(display);
    speakText(display);
  }
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

function _scenarioAirwayAssessmentText() {
  const p = state.scenarioData?.patient || {};
  const authored = p.airway_assessment?.description || p.airway || p.airway_status;
  return _compactPartnerFindingText(authored || "Airway assessed.");
}

function _scenarioWorkOfBreathingText() {
  const p = state.scenarioData?.patient || {};
  const authored = p.work_of_breathing || p.wob || p.respiratory_effort || p.pat?.work_of_breathing;
  return _compactPartnerFindingText(authored || "Breathing assessed.");
}

async function _handlePrimarySurveyAction(message, chipId = null, isAction = false) {
  if (!_userRequestsPrimarySurvey(message)) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;

  const p = state.scenarioData?.patient || {};
  const observation = _compactPartnerFindingText(
    p.general_impression ||
    p.presentation ||
    "Initial observation completed. No additional focused findings are available from this broad command."
  );
  await addPcrExam("Initial Observation", observation, "structured_action");

  appendAssessmentInfo(
    "Initial Observation / Primary Survey",
    `${observation}\n\nUse the Exam menu for focused assessments like airway/breathing, pulse quality, lung sounds, skin, neuro, pupils, abdomen, or extremities.`
  );
  appendLexiActionFeedback("primary_survey", LEXI_ACTION_FEEDBACK.primary_survey);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

async function _handleFocusedSecondaryAssessmentAction(message, chipId = null, isAction = false) {
  if (!_userRequestsFocusedSecondaryAssessment(message)) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;

  if (_scenarioUsesTraumaAssessmentRubric()) {
    const assessment = _nremtTraumaSecondaryAssessmentText();
    await addPcrExam("Secondary Assessment", assessment, "structured_action");
    appendAssessmentInfo(
      "Secondary Assessment",
      `${assessment}\n\nNo other injuries are found on the broad secondary assessment. Use the Exam menu for a focused exam on the affected area and any abnormal body-region finding.`
    );
  } else {
    appendAssessmentInfo(
      "Secondary Assessment",
      "Use the Exam menu for a focused exam on the affected body system or chief complaint."
    );
  }
  appendLexiActionFeedback("secondary_assessment", LEXI_ACTION_FEEDBACK.secondary_assessment);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

async function _handleSuctionAirwayAction(message, chipId = null, isAction = false) {
  if (!_userRequestsSuctionAirway(message)) return false;
  _suctionReadyConfirmationPending = false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  const suction = _interventionById["suction_airway"];
  if (suction && !suction.requires_popup) {
    await applyInterventionAndRecord("suction_airway", suction.label || "Suction airway", { source: "partner_action" });
  }
  const display = "*Alex:* Copy — suctioning the airway now.";
  appendAiMessage(display);
  speakText(display);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

async function _applyProtectFromInjuryIntervention() {
  const protect = _interventionById["protect_from_injury"];
  if (protect && !protect.requires_popup) {
    await applyInterventionAndRecord("protect_from_injury", protect.label || "Protect from injury", { source: "partner_action" });
  }
}

async function _handleProtectFromInjuryAction(message, chipId = null, isAction = false) {
  if (!_userRequestsProtectFromInjury(message)) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  await _applyProtectFromInjuryIntervention();
  const display = "*Alex:* Copy — keeping the seizure area clear, protecting her from injury, not restraining her, and keeping objects out of her mouth.";
  appendAiMessage(display);
  speakText(display);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

async function _handleRecoveryPositionAction(message, chipId = null, isAction = false) {
  if (!_userRequestsRecoveryPosition(message)) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  const recovery = _interventionById["recovery_position"];
  if (recovery && !recovery.requires_popup) {
    await applyInterventionAndRecord("recovery_position", recovery.label || "Recovery position", { source: "partner_action" });
  }
  const shouldAlsoSuction = _userRequestsSuctionAirway(message);
  if (shouldAlsoSuction) {
    const suction = _interventionById["suction_airway"];
    if (suction && !suction.requires_popup) {
      await applyInterventionAndRecord("suction_airway", suction.label || "Suction airway", { source: "partner_action" });
    }
  }
  const shouldAlsoProtect = _userRequestsProtectFromInjury(message);
  if (shouldAlsoProtect) await _applyProtectFromInjuryIntervention();
  const selfPerformed = /\b(i|we)\s+(?:am|are|will|can)?\s*(?:placing|putting|turning|rolling|positioning|place|put|turn|roll|position)\b/i.test(message)
    && !/\b(alex|partner|crew|teammate)\b/i.test(message);
  if (selfPerformed && !shouldAlsoSuction && !shouldAlsoProtect) {
    checkReadiness();
    _orientationFlushQueuedCues();
    return true;
  }
  const actionParts = ["patient now in recovery position"];
  if (shouldAlsoSuction) actionParts.push("suctioning the airway now");
  if (shouldAlsoProtect) actionParts.push("protecting her from injury without restraint or anything in the mouth");
  const display = `*Alex:* Copy — ${actionParts.join(". ")}.`;
  appendAiMessage(display);
  speakText(display);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

async function _handleSuctionReadyAction(message, chipId = null, isAction = false) {
  if (!_userAsksPartnerToPrepareSuction(message)) return false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  _suctionReadyConfirmationPending = true;
  const display = "*Alex:* Suction is ready. Do you want me to suction the airway?";
  appendAiMessage(display);
  speakText(display);
  checkReadiness();
  _orientationFlushQueuedCues();
  return true;
}

async function _handleSuctionReadyConfirmation(message, chipId = null, isAction = false) {
  if (!_suctionReadyConfirmationPending) return false;
  if (!_isYesMessage(message) && !_isNoMessage(message)) return false;
  _suctionReadyConfirmationPending = false;
  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;
  if (!_isYesMessage(message)) {
    const display = "*Alex:* Copy — suction is ready if you need it.";
    appendAiMessage(display);
    speakText(display);
    return true;
  }
  const suction = _interventionById["suction_airway"];
  if (suction && !suction.requires_popup) {
    await applyInterventionAndRecord("suction_airway", suction.label || "Suction airway", { source: "partner_action" });
  }
  const display = "*Alex:* Copy — suctioning the airway now.";
  appendAiMessage(display);
  speakText(display);
  checkReadiness();
  return true;
}

async function _recordAuthoredVitalsRequest(message, options = {}) {
  const { chipId = null, isAction = false, requestedDefs = null, extraResponseLines = [] } = options;
  const defs = requestedDefs || _authoredVitalsRequestedDefs(message);
  if (!defs.length) return false;

  if (isAction) appendUserAction(message, chipId);
  else appendUserMessage(message);
  _lastUserChatMessage = message;

  const lines = [];
  const examLines = [];
  const vitals = {};
  const vitalSources = {};
  const findingWrites = [];
  const capturedVitalKeys = new Set();
  const hadPriorVitals = Boolean(el("pcr-vitals")?.querySelector(".pcr-item"));
  defs.forEach(def => {
    const formatted = _formatAuthoredVitalValue(def, { useDisplay: def.type !== "vital" });
    if (!formatted) return;
    const spokenValue = _compactPartnerFindingText(formatted.value);
    if (formatted.unavailable) {
      if (def.type === "exam") examLines.push({ label: formatted.label, value: formatted.value });
      else lines.push(`${formatted.label}: ${spokenValue}`);
      return;
    }
    if (def.type === "vital") {
      vitals[formatted.label] = formatted.value;
      vitalSources[formatted.label] = def.key === "blood_glucose" ? "glucometer_check" : "authored_vitals";
      capturedVitalKeys.add(def.key);
      lines.push(`${formatted.label} is ${spokenValue}.`);
    } else {
      findingWrites.push(addPcrExam(formatted.label, formatted.value, "partner_reported_exam"));
      examLines.push({ label: formatted.label, value: formatted.value });
    }
  });

  if (Object.keys(vitals).length) {
    _vitalsBatch = vitals;
    findingWrites.push(...(flushVitalsBlock({ ...vitalSources, default: "authored_vitals" }) || []));
  }

  // When blood_glucose is captured via authored path (bypassing AI), also log
  // the glucometer check intervention so the rubric can credit the assessment.
  if (capturedVitalKeys.has("blood_glucose")) {
    const bglCheck = _interventionById["blood_glucose_check"];
    if (bglCheck && !bglCheck.requires_popup) {
      applyInterventionAndRecord("blood_glucose_check", bglCheck.label, { source: "glucometer_check" }).catch(() => {});
    }
  }

  await Promise.allSettled(findingWrites.filter(Boolean));
  examLines.forEach(({ label, value }) => appendExamFindingInfo(label, value));

  if (capturedVitalKeys.has("pulse_quality")) {
    appendLexiActionFeedback("pulse_assessed", LEXI_ACTION_FEEDBACK.pulse_assessed);
  }
  if (Object.keys(vitals).length) {
    const key = hadPriorVitals ? "reassessment" : "vitals_obtained";
    appendLexiActionFeedback(key, LEXI_ACTION_FEEDBACK[key]);
  } else if (examLines.length) {
    appendLexiActionFeedback("focused_exam", LEXI_ACTION_FEEDBACK.focused_exam);
  }

  const responseLines = [
    ...lines,
    ...extraResponseLines.map(line => _compactPartnerFindingText(line)).filter(Boolean),
  ];
  if (responseLines.length) {
    const display = `*Alex:* ${responseLines.join(" ")}`;
    appendAiMessage(display);
    speakText(display);
  } else if (!examLines.length) {
    return false;
  }
  checkReadiness();
  if (!isAction) _orientationFireCue("after_first_message");
  _orientationFlushQueuedCues();
  return true;
}

function _cprAdditionalActionFindingSpec(action = {}) {
  const actionId = String(action.action_id || action.id || "").toLowerCase();
  const label = String(action.label || action.id || "");
  if (actionId === "blood_glucose_check" || /\b(?:bgl|blood\s+glucose|glucose)\b/i.test(label)) {
    return { type: "vital", vitalKey: "blood_glucose", source: "glucometer_check" };
  }
  if (actionId === "pupil_assessment" || /\bpupils?\b/i.test(label)) {
    return { type: "exam", key: "Pupils", vitalKey: "pupils", source: "partner_reported_exam" };
  }
  if (/\bairway|bvm|suction|supraglottic\b/i.test(`${actionId} ${label}`)) {
    return { type: "exam", key: "Airway", source: "partner_reported_exam" };
  }
  return { type: "exam", key: label || "CPR Action", source: "partner_reported_exam" };
}

async function _recordCprAdditionalScenarioEvidence(action = {}, section = {}) {
  const label = action.label || action.id || "Additional action";
  const actionId = action.action_id || action.id || "";
  const finding = action.finding || action.result_text || action.response || "";
  const spec = _cprAdditionalActionFindingSpec(action);
  const writes = [];

  if (spec.type === "vital" && spec.vitalKey) {
    const def = _AUTHORED_VITAL_DEFS.find(d => d.key === spec.vitalKey);
    const formatted = def ? _formatAuthoredVitalValue(def) : null;
    const value = formatted?.value || finding || "Assessed";
    const displayLabel = formatted?.label || label;
    _vitalsBatch = { [displayLabel]: value };
    writes.push(...(flushVitalsBlock({ [displayLabel]: spec.source || "authored_vitals", default: spec.source || "authored_vitals" }) || []));
  } else if (finding) {
    const def = spec.vitalKey ? _AUTHORED_VITAL_DEFS.find(d => d.key === spec.vitalKey) : null;
    const formatted = def ? _formatAuthoredVitalValue(def) : null;
    writes.push(addPcrExam(spec.key || formatted?.label || label, formatted?.value || finding, spec.source || "partner_reported_exam"));
  }

  if (actionId && _interventionById[actionId]) {
    await applyInterventionAndRecord(actionId, _interventionById[actionId].label || label, { source: "cpr_challenge_menu" });
  }

  if (state.sessionId && actionId) {
    writes.push(authFetch(`${API}/api/sessions/${state.sessionId}/events`, {
      method: "POST",
      authRedirectOn401: false,
      body: JSON.stringify({
        event_type: section.kind === "medication" ? "clinical_decision" : "explicit_assessment",
        event_key: actionId,
        source: "frontend_explicit",
        event_data: {
          cpr_challenge_menu: true,
          section_id: section.id || null,
          section_kind: section.kind || null,
          label,
          finding,
        },
      }),
    }).catch(() => null));
  }

  await Promise.allSettled(writes.filter(Boolean));
  checkReadiness();
}

function openLungSoundChallenge(finding) {
  if (!_scenarioUsesLungSoundChallenge()) {
    showToast("Lung sound challenge is not available until a scenario is active.", "info");
    return false;
  }
  const modal = el("modal-lung-sound");
  if (!modal) {
    console.error("Lung sound challenge modal is missing from the DOM.");
    showToast("Lung sound challenge could not open. Please refresh and try again.", "error");
    return false;
  }
  try {
    // Use post-treatment config if the required intervention has been given.
    _lungSoundSetCount++;
    const config = _lungSoundConfigForCurrentState();
    _lungSoundActiveConfig = config;
    _lungSoundSelectedChoice = null;
    _lungSoundPendingFinding = config.finding || finding;

    const audio = el("lung-sound-audio");
    if (audio) {
      audio.pause();
      audio.currentTime = 0;
      audio.src = config.audio_file || "";
    }
    setText("lung-sound-play-icon", "▶");
    setText("lung-sound-prompt", config.prompt || "Listen carefully — what lung sounds do you hear?");
    _renderLungSoundChoices(config);
    el("lung-sound-feedback")?.classList.add("hidden");
    el("btn-lung-sound-continue")?.classList.add("hidden");
    el("btn-submit-lung-sound")?.classList.remove("hidden");
    show("modal-lung-sound");
    isPopupOpen = true;  // Prevent TTS while popup is open
    return true;
  } catch (err) {
    console.error("Failed to open lung sound challenge:", err);
    isPopupOpen = false;
    showToast("Lung sound challenge could not open. Please try again.", "error");
    return false;
  }
}

el("btn-play-lung-sound")?.addEventListener("click", () => {
  const audio = el("lung-sound-audio");
  const icon = el("lung-sound-play-icon");
  if (!audio || !icon) return;
  if (audio.paused) {
    audio.play().catch(() => showToast("Could not play this audio clip.", "warning"));
    icon.textContent = "⏸";
    audio.onended = () => { icon.textContent = "▶"; };
  } else {
    audio.pause();
    audio.currentTime = 0;
    icon.textContent = "▶";
  }
});

el("btn-submit-lung-sound")?.addEventListener("click", () => {
  if (!_lungSoundSelectedChoice) {
    const fb = el("lung-sound-feedback");
    if (!fb) return;
    fb.className = "rounded-lg p-3 text-sm border bg-red-900/40 border-red-700 text-red-300";
    fb.textContent = "Choose the lung sound you hear before submitting.";
    return;
  }
  const config = _lungSoundActiveConfig || _lungSoundConfigForCurrentState();
  const correctChoice = _lungSoundChoiceId(config);
  const correct = Boolean(correctChoice && _lungSoundSelectedChoice === correctChoice);
  const selectedLabel = _LUNG_SOUND_CHOICES.find(choice => choice.id === _lungSoundSelectedChoice)?.label || "Selected answer";

  const fb = el("lung-sound-feedback");
  if (!fb) return;
  fb.classList.remove("hidden", "bg-green-900/40", "border-green-700", "bg-red-900/40", "border-red-700", "text-green-300", "text-red-300", "border");
  if (!correct) {
    el("lung-sound-options")?.querySelectorAll(".lung-sound-option").forEach(btn => {
      const id = btn.getAttribute("data-choice-id");
      btn.classList.toggle("wrong", id === _lungSoundSelectedChoice);
      btn.classList.remove("correct");
      btn.disabled = false;
    });
    fb.className = "rounded-lg p-3 text-sm border bg-red-900/40 border-red-700 text-red-300";
    fb.textContent = "Incorrect, try again.";
    return;
  }

  el("lung-sound-options")?.querySelectorAll(".lung-sound-option").forEach(btn => {
    const id = btn.getAttribute("data-choice-id");
    btn.classList.toggle("correct", id === correctChoice);
    btn.classList.remove("wrong");
    btn.disabled = true;
  });
  fb.className = "rounded-lg p-3 text-sm border bg-green-900/40 border-green-700 text-green-300";
  fb.textContent = config.feedback_correct || "Correct.";
  el("btn-submit-lung-sound")?.classList.add("hidden");
  el("btn-lung-sound-continue")?.classList.remove("hidden");
  appendUserAction(`Lung sounds: ${selectedLabel}`, "lung-sound-challenge");

  // Post the finding immediately on correct submission so the backend record
  // exists even if the student closes the modal without clicking Continue.
  const _lsFinding = _lungSoundPendingFinding || _lungSoundConfigForCurrentState()?.finding;
  if (_lsFinding) {
    const _lsElapsed = state.startTime
      ? formatTime(Math.floor((Date.now() - state.startTime.getTime()) / 1000))
      : "";
    const _lsLabel = `Lung Sounds${_lungSoundSetCount > 1 ? ` (set ${_lungSoundSetCount})` : ""}${_lsElapsed ? ` @ ${_lsElapsed}` : ""}`;
    addPcrExamRaw(_lsLabel, _lsFinding, "lung_sound_challenge");
    appendExamFindingInfo(_lsLabel, _lsFinding);
  }

  // Deterministic Lexi encouragement: canned, action-specific, and de-duped.
  if (correct) {
    const feedbackKey = _lungSoundSetCount > 1 ? "lung_sound_reassessment_correct" : "lung_sound_initial_correct";
    const feedbackText = _lungSoundSetCount > 1
      ? `Nice reassessment. You correctly identified ${selectedLabel.toLowerCase()} after the intervention.`
      : `Nice work. You correctly identified ${selectedLabel.toLowerCase()}.`;
    setTimeout(() => appendLexiActionFeedback(feedbackKey, feedbackText), 500);
  }
});

el("btn-lung-sound-continue")?.addEventListener("click", () => {
  hide("modal-lung-sound");
  isPopupOpen = false;  // Allow TTS now that popup is closed
  speakPendingIfAny();  // Speak any queued response
  _resumePendingImpressionChallengeAfterModal();
  // Finding is now posted on submit (correct answer), not here — Continue is UI closure only.
  const audio = el("lung-sound-audio");
  if (audio) {
    audio.pause();
    audio.currentTime = 0;
  }
  setText("lung-sound-play-icon", "▶");
});

