el("btn-new-session").addEventListener("click", () => {
  const { seconds, sessionId, isDrill } = _activeReviewTimer.stop();
  _submitDebriefCe(seconds, sessionId, isDrill, _sessionActiveTimer.stop());
  hide("modal-debrief");
  const returnDistrictId = _lastDebriefEntry?.returnDistrictId || _sessionReturnDistrictId || null;
  const catKey = state.scenarioData?.category;
  resetSessionState();
  if (_returnToScormStation1()) return;
  if (returnDistrictId === "station_1") {
    _categoryView = { mode: "district", districtId: "station_1" };
    _renderStation1Map();
  } else if (catKey && state.allScenarios.some(s => s.category === catKey)) {
    showCategoryScreen(catKey);
  } else {
    buildMenu();
    showScreen("menu");
  }
});

el("btn-retry-session").addEventListener("click", () => {
  const { seconds, sessionId, isDrill } = _activeReviewTimer.stop();
  _submitDebriefCe(seconds, sessionId, isDrill, _sessionActiveTimer.stop());
  hide("modal-debrief");
  const sid = state.scenarioId;
  resetSessionState();
  startScenario(sid);
});

