function resetSessionState() {
  _sessionReturnDistrictId = null;
  _setRefSubtab("conditions");
  if (state.timerInterval) clearInterval(state.timerInterval);
  if (state.alsArrivalTimer) clearTimeout(state.alsArrivalTimer);
  if (_readinessTimer) clearInterval(_readinessTimer);
  // Close the vitals WebSocket. sessionId is cleared below, so the onclose
  // handler will see no sessionId and will not attempt to reconnect.
  if (state.vitalsWs) { state.vitalsWs.close(); state.vitalsWs = null; }
  // Phase 3: stop cardiac monitor and close AudioContext
  window._immAudio?.teardown();
  state.sessionId    = null;
  state.scenarioId   = null;
  state.scenarioData = null;
  state.startTime    = null;
  state.timerInterval = null;
  state.simTimersStarted = false;
  state.alsArrivalTimer = null;
  state.alsArrived   = false;
  state.interventionsApplied    = [];
  state.detectedTreatmentIds     = [];
  state.detectedTreatmentLabels = [];
  state.lexiHistory             = [];
  state._o2Early                = false;
  state._lexiGuidedMode = false;
  state._lexiAssistedTreatments = [];
  state._lastSimLearnerActivityAt = null;
  state._lexiIdleCheckinShown = false;
  _clearLexiIdleCheckinTimer();
  state._sceneEntryPatAssessment = null;
  state._sceneEntryPersisted = false;
  state._sceneEntryPersistedSignature = null;
  state.drillMode = false;
  state.dispatchQuickDrillOnly = false;
  state.isRandomCall = false;
  state.currentVitals = null;
  state.pcrHeader = null;
  _aiSpeakerColorMap = new Map();
  _aiSpeakerColorCursor = 0;
  _scenarioSpeakerAliasMap = new Map();
  msgCount = 0;
  o2Applied = false;
  _lastUserChatMessage = "";
  _historyCaptureUnlocked = false;
  _pendingImpChallenge = null;
  _impressionChallengeCompleted = false;
  _turnoverTreatmentPromise = null;

  // Reset chat
  el("chat-messages").innerHTML = "";
  _resetSimComposerInputs();
  show("sim-instructions");

  // Reset PCR notes
  el("pcr-exam").innerHTML = "";
  el("pcr-history").innerHTML = "";
  el("pcr-vitals").innerHTML = "";
  el("pcr-treatments").innerHTML = "";
  show("pcr-exam-empty");
  show("pcr-history-empty");
  show("pcr-vitals-empty");
  show("pcr-treatments-empty");
  setText("pcr-patient-id", "");
  setText("pcr-complaint", "");
  setText("pcr-dispatch", "Awaiting dispatch info…");
  setText("pcr-presentation", "Assess the patient…");

  // Reset sidebar tabs to default (PCR Notes)
  document.querySelectorAll(".sidebar-tab").forEach(b => b.classList.remove("active"));
  document.querySelectorAll(".tab-content").forEach(t => t.classList.add("hidden"));
  document.querySelector(".sidebar-tab[data-tab='notes']")?.classList.add("active");
  el("tab-notes")?.classList.remove("hidden");

  // Reset patient photo
  const photo = el("pt-photo");
  if (photo) { photo.src = ""; photo.classList.add("hidden"); }
  const placeholder = el("pt-photo-placeholder");
  if (placeholder) placeholder.classList.remove("hidden");
  hide("scene-image-container");
  const sceneImage = el("scene-image");
  if (sceneImage) sceneImage.src = "";

  // Reset Lexi panel
  el("lexi-messages").innerHTML = "";

  // Reset forms
  el("dmist-input").value = "";
  el("narrative-input").value = "";
  // Reset character counters to their max values
  const _dmistChars = el("dmist-chars");   if (_dmistChars)  { _dmistChars.textContent  = "1500"; _dmistChars.style.color  = ""; }
  const _narrChars = el("narrative-chars"); if (_narrChars)   { _narrChars.textContent   = "2000"; _narrChars.style.color   = ""; }
  el("debrief-xp-badge").classList.add("hidden");
  el("debrief-bonus-xp-badge")?.classList.add("hidden");
  el("new-badges-row").classList.add("hidden");

  // Reset lung sound challenge
  _lungSoundUsed = false;
  _lungSoundPendingFinding = null;
  _lungSoundSetCount = 0;
  _lungSoundClarificationPending = false;

  // Reset popup/TTS state so a prior incomplete attempt doesn't bleed through
  _pendingPopupQueue = [];
  _vitalsBatch = {};
  isPopupOpen = false;
  _clearTtsAudioQueue();

  // Reset drill mode UI
  const drillBadge = el("drill-mode-badge");
  const btnDrillFb = el("btn-drill-feedback");
  const btnTreatment = el("btn-open-treatment");
  if (drillBadge) drillBadge.classList.add("hidden");
  if (btnDrillFb) { btnDrillFb.classList.add("hidden"); btnDrillFb.disabled = true; }
  if (btnTreatment) btnTreatment.classList.remove("hidden");

  // Hide any modals that might be open from a prior attempt
  hide("modal-intervention-queue");
  hide("modal-o2-admin");
  hide("modal-med-admin");
  hide("modal-treat-confirm");
  hide("modal-lung-sound");
}

