function openLightbox(src, caption, details = null) {
  const img = el("lightbox-img");
  img.src = src;
  setText("lightbox-caption-title", caption || "");
  const detailsWrap = el("lightbox-caption-details");
  const sceneSection = el("lightbox-scene-section");
  const presentationSection = el("lightbox-presentation-section");
  const sceneDesc = (details?.sceneDescription || "").trim();
  const presentation = (details?.presentation || "").trim();
  if (sceneDesc || presentation) {
    setText("lightbox-scene-desc", sceneDesc);
    setText("lightbox-presentation", presentation);
    if (sceneDesc) sceneSection?.classList.remove("hidden");
    else sceneSection?.classList.add("hidden");
    if (presentation) presentationSection?.classList.remove("hidden");
    else presentationSection?.classList.add("hidden");
    detailsWrap?.classList.remove("hidden");
  } else {
    setText("lightbox-scene-desc", "");
    setText("lightbox-presentation", "");
    sceneSection?.classList.add("hidden");
    presentationSection?.classList.add("hidden");
    detailsWrap?.classList.add("hidden");
  }
  show("modal-lightbox");
}

function _currentScenarioLightboxDetails() {
  return {
    sceneDescription: el("scene-description")?.textContent?.trim() || "",
    presentation: "",
  };
}

function _openArrivalImageLightbox() {
  const arrImg = el("arrival-image");
  if (arrImg?.src) {
    openLightbox(arrImg.src, el("pcr-patient-id")?.textContent || "Patient");
    return true;
  }
  const ptImg = el("pt-photo");
  if (ptImg && !ptImg.classList.contains("hidden") && ptImg.src) {
    openLightbox(ptImg.src, el("pcr-patient-id")?.textContent || "Patient");
    return true;
  }
  return false;
}

el("modal-lightbox").addEventListener("click", e => {
  if (e.target === el("modal-lightbox") || e.target === el("btn-lightbox-close")) {
    hide("modal-lightbox");
    el("lightbox-img").src = "";
    setText("lightbox-caption-title", "");
    setText("lightbox-scene-desc", "");
    setText("lightbox-presentation", "");
    el("lightbox-scene-section")?.classList.add("hidden");
    el("lightbox-presentation-section")?.classList.add("hidden");
    el("lightbox-caption-details")?.classList.add("hidden");
  }
});
