// ── Analytics tab ─────────────────────────────────────────────────────────────

el("btn-analytics-refresh")?.addEventListener("click", _loadDashboardAnalytics);

async function _loadDashboardAnalytics() {
  const scenariosEl  = el("analytics-scenarios");
  const categoriesEl = el("analytics-categories");
  const categoriesSection = el("analytics-categories-section");
  const practiceEl   = el("analytics-practice");
  const missedEl     = el("analytics-missed");
  const emptyEl      = el("analytics-empty");
  scenariosEl.innerHTML = "<p class='text-gray-500 text-sm'>Loading…</p>";
  if (categoriesEl) categoriesEl.innerHTML = "";
  if (categoriesSection) categoriesSection.classList.add("hidden");

  try {
    const r = await authFetch(`${API}/api/admin/analytics`);
    if (!r.ok) { scenariosEl.innerHTML = "<p class='text-red-400 text-sm'>Could not load agency insights.</p>"; return; }
    const data = await r.json();
    const practiceOps = data.practice_opportunities || data.at_risk || [];
    const overallOnTrack = (data.on_track_rate_overall ?? data.pass_rate_overall);

    // Summary
    el("analytics-total-sessions").textContent = data.total_sessions ?? "—";
    el("analytics-pass-rate").textContent = data.total_sessions ? `${overallOnTrack}%` : "—";
    el("analytics-practice-count").textContent = practiceOps.length ?? 0;

    if (!data.total_sessions) {
      emptyEl.classList.remove("hidden");
      scenariosEl.innerHTML = "";
      return;
    }
    emptyEl.classList.add("hidden");

    // Scenario performance cards
    scenariosEl.innerHTML = (data.scenario_stats || []).map(s => {
      const barColor = s.avg_score >= 85 ? "bg-green-500" : s.avg_score >= 65 ? "bg-blue-500" : s.avg_score >= 50 ? "bg-yellow-500" : "bg-red-500";
      const onTrackRate = (s.on_track_rate ?? s.pass_rate ?? 0);
      const passColor = onTrackRate >= 80 ? "text-green-400" : onTrackRate >= 60 ? "text-yellow-400" : "text-red-400";
      return `<div class="bg-gray-800 border border-gray-700 rounded-lg p-3">
        <div class="flex items-center justify-between mb-1.5">
          <span class="text-sm text-gray-200 font-medium">${escapeHTML(s.title)}</span>
          <span class="text-xs text-gray-500">${s.attempts} attempt${s.attempts !== 1 ? "s" : ""}</span>
        </div>
        <div class="flex items-center gap-3">
          <div class="flex-1 h-2 bg-gray-700 rounded-full overflow-hidden">
            <div class="${barColor} h-full rounded-full" style="width:${s.avg_score}%"></div>
          </div>
          <span class="text-xs text-gray-300 w-16 shrink-0">Avg: ${s.avg_score}/100</span>
          <span class="text-xs ${passColor} w-20 shrink-0 text-right">On Track: ${onTrackRate}%</span>
        </div>
      </div>`;
    }).join("");

    // Category practice opportunities
    if (categoriesEl && categoriesSection && Array.isArray(data.category_stats) && data.category_stats.length > 0) {
      const top = data.category_stats.slice(0, 6);
      categoriesEl.innerHTML = top.map(c => {
        const onTrackRate = (c.on_track_rate ?? c.pass_rate ?? 0);
        const barColor = c.avg_score >= 85 ? "bg-green-500" : c.avg_score >= 65 ? "bg-blue-500" : c.avg_score >= 50 ? "bg-yellow-500" : "bg-red-500";
        const rateColor = onTrackRate >= 80 ? "text-green-400" : onTrackRate >= 60 ? "text-yellow-400" : "text-red-400";
        const label = String(c.category || "uncategorized")
          .replace(/[_-]+/g, " ")
          .replace(/\b\w/g, (m) => m.toUpperCase());
        return `<div class="bg-gray-800 border border-gray-700 rounded-lg p-3">
          <div class="flex items-center justify-between mb-1.5">
            <span class="text-sm text-gray-200 font-medium">${escapeHTML(label)}</span>
            <span class="text-xs text-gray-500">${c.attempts} reps · ${c.scenario_count} scenarios</span>
          </div>
          <div class="flex items-center gap-3">
            <div class="flex-1 h-2 bg-gray-700 rounded-full overflow-hidden">
              <div class="${barColor} h-full rounded-full" style="width:${c.avg_score}%"></div>
            </div>
            <span class="text-xs text-gray-300 w-16 shrink-0">Avg: ${c.avg_score}/100</span>
            <span class="text-xs ${rateColor} w-20 shrink-0 text-right">On Track: ${onTrackRate}%</span>
          </div>
        </div>`;
      }).join("");
      categoriesSection.classList.remove("hidden");
    } else if (categoriesSection) {
      categoriesSection.classList.add("hidden");
    }

    // Practice opportunity responders
    const practiceSection = el("analytics-practice-section");
    if (practiceOps.length > 0) {
      practiceEl.innerHTML = practiceOps.map(u => `<div class="bg-red-950/30 border border-red-800/40 rounded-lg p-3 text-sm">
        <div class="font-semibold text-red-300">${escapeHTML(u.name)} <span class="text-xs text-gray-500">@${escapeHTML(u.username)}</span></div>
        <div class="text-xs text-gray-400 mt-0.5">More reps suggested for: ${u.weak_scenarios.map(s => escapeHTML(s)).join(", ")}</div>
      </div>`).join("");
      practiceSection.classList.remove("hidden");
    } else {
      practiceSection.classList.add("hidden");
    }

    // Top missed actions
    const missedSection = el("analytics-missed-section");
    if (data.top_missed_actions?.length > 0) {
      const maxCount = data.top_missed_actions[0].missed_count;
      missedEl.innerHTML = data.top_missed_actions.map(item => {
        const pct = Math.round((item.missed_count / maxCount) * 100);
        return `<div class="flex items-center gap-2 text-xs">
          <div class="flex-1 min-w-0">
            <div class="text-gray-300 truncate" title="${escapeHTML(item.action)}">${escapeHTML(item.action)}</div>
            <div class="h-1 bg-gray-700 rounded-full mt-1 overflow-hidden"><div class="bg-orange-500 h-full rounded-full" style="width:${pct}%"></div></div>
          </div>
          <span class="text-gray-500 shrink-0">${item.missed_count}x</span>
        </div>`;
      }).join("");
      missedSection.classList.remove("hidden");
    } else {
      missedSection.classList.add("hidden");
    }

  } catch {
    scenariosEl.innerHTML = "<p class='text-red-400 text-sm'>Connection error loading analytics.</p>";
  }
}

