// Create challenge form (instructor/admin)
el("form-create-challenge")?.addEventListener("submit", async e => {
  e.preventDefault();
  const msgEl  = el("ch-create-msg");
  const btn    = e.target.querySelector("button[type=submit]");
  msgEl.className = "text-xs hidden";

  const name = (el("ch-name")?.value || "").trim();
  if (!name) {
    msgEl.textContent = "Challenge name is required.";
    msgEl.className = "text-xs text-red-400";
    return;
  }

  const requirements = _chGetRequirements("ch-requirements-list");
  if (!requirements.length) {
    msgEl.textContent = "Add at least one requirement.";
    msgEl.className = "text-xs text-red-400";
    return;
  }

  const body = {
    name,
    icon:              (el("ch-icon")?.value || "").trim() || null,
    description:       (el("ch-desc")?.value || "").trim() || null,
    requirements,
    time_goal_minutes: parseInt(el("ch-time-goal")?.value || "0", 10) || null,
    repeatable:        !!el("ch-repeatable")?.checked,
  };

  btn.disabled = true;
  btn.textContent = "Creating…";

  try {
    const r = await authFetch(`${API}/api/admin/challenges`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });
    if (!r.ok) {
      const err = await r.json().catch(() => ({}));
      throw new Error(err.detail || r.statusText);
    }
    e.target.reset();
    el("ch-requirements-list").innerHTML = "";
    el("ch-prereq-warning")?.classList.add("hidden");
    msgEl.textContent = "Challenge created!";
    msgEl.className = "text-xs text-emerald-400";
    _loadDashboardChallenges();
    await _loadChallenges();
    buildMenu();
    setTimeout(() => hide("modal-create-challenge"), 800);
  } catch (err) {
    msgEl.textContent = "Error: " + err.message;
    msgEl.className = "text-xs text-red-400";
  } finally {
    btn.disabled = false;
    btn.textContent = "Create Challenge";
  }
});

// Agency settings form (admin)
el("form-agency-settings")?.addEventListener("submit", async e => {
  e.preventDefault();
  const msgEl = el("agency-settings-msg");
  msgEl.className = "text-xs hidden";

  const body = {
    name:             el("agency-setting-name").value.trim()  || undefined,
    agency_join_code: el("agency-setting-code").value.trim()  || undefined,
  };

  const submitBtn = e.target.querySelector("button[type=submit]");
  submitBtn.disabled = true;
  submitBtn.textContent = "Saving…";

  try {
    const r = await authFetch(`${API}/api/agency`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });
    if (!r.ok) {
      const err = await r.json().catch(() => ({ detail: "Unknown error" }));
      msgEl.textContent = err.detail || "Failed to save settings";
      msgEl.className = "text-xs text-red-400";
      return;
    }
    const updated = await r.json();
    // Update local state agency name if it changed
    if (body.name) state.agency = updated.name;
    setText("dash-agency-label", state.agency || "");
    msgEl.textContent = "Settings saved.";
    msgEl.className = "text-xs text-green-400";
    setTimeout(() => msgEl.classList.add("hidden"), 3000);
  } catch (err) {
    msgEl.textContent = "Network error: " + err;
    msgEl.className = "text-xs text-red-400";
  } finally {
    submitBtn.disabled = false;
    submitBtn.textContent = "Save Settings";
  }
});

// Clinical config form (admin)
el("form-agency-config")?.addEventListener("submit", async e => {
  e.preventDefault();
  const msgEl = el("config-save-msg");
  msgEl.className = "text-xs hidden";

  const providerLevel = el("cfg-provider-level")?.value || "EMT";
  const availMcas = Array.from(el("cfg-available-mcas")?.selectedOptions ?? []).map(o => o.value);

  const body = {
    display_name:      el("cfg-display-name")?.value.trim()       || undefined,
    unit_designator:   el("cfg-unit-designator")?.value.trim()    || undefined,
    mca:               el("cfg-mca")?.value                       || undefined,
    available_mcas:    availMcas,
    provider_levels:   { primary: providerLevel },
    service_type:      {
      transport: el("cfg-transport")?.checked ?? true,
      notes:     el("cfg-service-notes")?.value.trim() || "",
    },
    ai_prompt_context: el("cfg-ai-prompt-context")?.value.trim()  || undefined,
    equipment:         _cfgGetEquipmentPayload(),
    training_and_certifications: { completed: _cfgGetListValues("cfg-training-list") },
    sops:              _cfgGetSops(),
  };

  const submitBtn = e.target.querySelector("button[type=submit]");
  submitBtn.disabled = true;
  submitBtn.textContent = "Saving…";

  try {
    const r = await authFetch(`${API}/api/agency/config`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });
    if (!r.ok) {
      const err = await r.json().catch(() => ({ detail: "Unknown error" }));
      msgEl.textContent = err.detail || "Failed to save config";
      msgEl.className = "text-xs text-red-400";
      return;
    }
    msgEl.textContent = "Clinical config saved.";
    msgEl.className = "text-xs text-green-400";
    setTimeout(() => msgEl.classList.add("hidden"), 3000);
  } catch (err) {
    msgEl.textContent = "Network error: " + err;
    msgEl.className = "text-xs text-red-400";
  } finally {
    submitBtn.disabled = false;
    submitBtn.textContent = "Save Clinical Config";
  }
});

